}
# ── Hidden boss (v1.5): per-dungeon flags used to gate spawn ──
$script:UsedPotionsThisDungeon = $false
$script:TookDamageThisDungeon  = $false
$script:HiddenBossDefeated     = $false   # lifetime achievement
# ── New Game Plus (v1.5 Pass 2): incremented each time the player
# ascends. Currently saved/loaded but not yet wired into enemy scaling
# (that's a Pass 2 feature).
$script:NGPlusLevel            = 0
# ── Dungeon Mutators (v1.5 Pass 2): chosen at dungeon entry, cleared
# on dungeon end. $script:DungeonMutator is $null (no mutator) or
# @{Id, Name, Desc, RewardMul} where RewardMul is the gold/XP bonus
# multiplier applied at the end-of-dungeon clear.
$script:DungeonMutator         = $null
# ── Talent Tree (v1.5 Pass 2): 1 talent point per player level. Spent
# at the Stats page. Each class has 9 talents in 3 tiers of 3 (Tier 1
# requires Lv1, Tier 2 requires Lv5, Tier 3 requires Lv10). Stored as
# a hashtable: talent ID -> 1 (purchased). Talent points are calculated
# as max(0, PlayerLevel - sum-of-purchased-talents). Reset on ascend
# and on new char.
$script:Talents = @{}            # @{ "Knight_T1_A" = 1; ... }
# Per-dungeon one-shot talent flags. Cleared on Enter-Dungeon.
$script:LastStandUsed    = $false   # Knight Last Stand
$script:ResurrectionUsed = $false   # Cleric Resurrection
$script:FinalStandUsed   = $false   # Berserker Final Stand
$script:LayOnHandsUsed   = 0       # Cleric Lay on Hands counter (T4 allows 2)
# Berserker Final Stand: stores the delta applied at proc time so
# Reset-MutatorOnEnd can revert it at dungeon end. Without this, the
# +50% stats would compound across dungeons.
$script:FinalStandBuffs  = $null    # @{ATK; DEF; SPD; MAG} or $null

# ── Settings (saved inside the save code, not on disk) ──
# Difficulty: "Easy" -25% enemy HP/ATK, "Medium" baseline, "Hard" +25%.
# AutoLoot: when $true the loot screen auto-takes everything that fits.
# AutoResize: when $true the game tries to resize the console window on start.
# These are persisted as part of $script:Settings inside the v8 save
# format (see Save-Game / Load-Game). Defaults below are applied to a
# fresh character; loading a save overwrites them with the saved values.
$script:Settings = @{
    Difficulty = "Medium"
    AutoLoot   = $false
    AutoResize = $false
    Renderer   = "Auto"   # Auto / Classic / Raycast — Auto picks Raycast where VT (ANSI) is detected, Classic on bare conhost
    ShowFPS    = $true    # raycast HUD FPS counter — ON by default, toggle in Options
    RotSpeed   = 100      # raycast turn speed percent — 50/75/100/125/150 preset cycle
    ZoneTheme  = $true    # zone-tinted dungeon visuals — OFF = plain stone everywhere
}

# ── PHASE 1 FOUNDATIONS (save format v9) ─────────────────────────
# Persistent state plumbing for the v1.5 roadmap. All of these travel
# inside the save code's extensible key-value field (see Save-Game
# field [45]) so future systems never need another format bump.

# In-game day counter. Advances on dungeon clears and Inn rests today;
# world-map travel will advance it later. Drives radiant events and
# story pacing down the line.
$script:GameDay = 1

# Global Corruption meter 0-100 (Cat 8). Phase 1 stores it; Phase 4
# wires effects (composition-based hostility, never raw stats).
$script:Corruption = 0

# Marn's Journal (Cat 7): page# -> $true once collected. Permanent per
# character, persists via save key JN. The physical note items are only
# transient pickups (the whole bag liquidates to gold on save) — these
# flags are the real collection. JournalCharm = the all-15 reward
# (Marn's Lucky Byte, +2% crit), persists via save key JC.
$script:JournalPages = @{}
$script:JournalCharm = $false

# Town upgrades (Phase 4e): permanent per character, bought with
# high-tier trinkets. Keys: "Forge" (repairs -25%), "Inn" (paid rests
# grant Well Rested +2 DEF when no food buff is active). Save key TU.
$script:TownUpgrades = @{}
$script:Companion = ""             # faction follower: "" / "rp" (Orphan, +1 SPD) / "dm" (Cursor, +2% crit); key CM

# Nap-spam cap (Phase 5 prep): the GameDay value of the last rest that
# advanced the day. Rests always heal, but only the first paid rest per
# day passes time — so future radiant events cannot be slept past.
# Persists via save key RD (save/load cycling cannot bypass it).
$script:RestedOnDay = 0

# Deepest floor reached (Phase 5): per-character personal best. No
# shared leaderboard is possible (no file/network I/O by design), so
# the record travels in the save code via key DF.
$script:DeepestFloor = 0

# Nemesis (Phase 5): Root, the Usurped Admin — one bespoke, scripted
# rival (locked decision). Stage: 0=unmet, 1=beaten once (escaped),
# 2=beaten twice (escaped), 3=terminated (reward claimed). Fled flag
# flavors his taunts. Persist via key NM; Pending is session-only.
$script:NemesisStage   = 0
$script:NemesisFled    = $false
$script:NemesisPending = $false
# Act III finale (session-only): the Lich King waits below floor 16
# while story quest 10 is active. Same loop-head contract as Root.
$script:MigrationPending = $false

# World map (Phase 6): id of the location the player is at. "helpdesk"
# is the hub (the only known Depths entrance). Persists via key WL.
$script:CurrentLocation = "helpdesk"

# Fishing (Phase 6): 3 casts per game-day, tracked per session.
$script:FishCastDay    = -1
$script:FishCastsToday = 0
# Lifetime successful hauls (quest objective backing). Key FC.
$script:TotalFishCaught = 0

# Themed raid excursions (Phase 6): $null, or the active theme config
# (cloned from Get-RaidThemes, carrying SavedLevel for restore).
# Transient — never persisted; cleared by Reset-MutatorOnEnd.
$script:RaidTheme = $null

# Factions (Phase 6, canonical names from the original doc): rep
# -100..100 per faction, 0 = unknown to them. Key FR. Effects:
# <= -20 HUNTED (assassin road ambushes), >= +25 HONORED (perks).
$script:FactionRep = @{ RogueProcesses = 0; DataMiners = 0 }

# Guild membership (Phase 6): "" or sysadmins/datathieves/cabal.
# Switchable with penalty (locked decision): defecting forfeits 100g
# in dues and resets that guild's questline. Key GM.
$script:GuildMembership = ""

# Appearance (creator Phase 1): build/gender, skin tone, hair style,
# hair color — indexes into the creator palette tables. Key AP.
$script:Appearance = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 }

# Story / multi-stage quest flags (Cat 13, Cat 10). Hashtable of
# questId -> integer stage. 0 or missing = not started. Town Board
# quests deliberately do NOT live here — they stay ephemeral per the
# design doc. Ids must be alphanumeric+underscore (sanitized on save).
$script:StoryFlags = @{}

# Skill XP tracking (Cat 11). Fixed skill order — the save format
# serializes XP as a positional comma list, so NEVER reorder or
# remove entries; append only.
function Get-SkillList {
    @("Swords","Bows","Destruction","Restoration","HeavyArmor",
      "LightArmor","Lockpicking","Blacksmithing","Alchemy",
      "Fishing")   # appended Phase 6 (append-only, never reorder)
}
$script:SkillXP = @{}
foreach($__sk in (Get-SkillList)){ $script:SkillXP[$__sk] = 0 }

# Skill level curve: level N requires N*100 cumulative XP, so
# Lv1=100, Lv5=1500, Lv10=5500 (triangular). Cheap to compute and
# naturally slows growth at higher levels.
# ── ROADMAP DESIGN DECISIONS (do not delete — survives session resets) ──
# RAYCASTER (integrate AFTER Phase 3; engine in uploads/raycaster.ps1):
#   * FULL FREE-FLOAT movement (user choice): float px/py + radian angle.
#     Tile-entry triggers become: enemies/exit = proximity (~0.6 tile
#     collision radius); chests/NPCs/doors = [E] interact key w/ facing
#     check; random-encounter step rolls = accumulated distance.
#   * Layout: raycast view + RIGHT side panel (minimap/stats), as now.
#   * VT detection: SetConsoleMode 0x4 probe (env sniff fallback) + Options toggle
#     "Renderer: Classic/Raycaster"; classic stays as fallback.
#   * Port fix: fisheye-correct sprite dist for z-buffer comparison.
#   * Zone palettes: Get-ShadedColor families get per-zone variants.
# WORLD MAP (Phase 6):
#   * Skyrim-scale breadth, data-driven locations, PS-humor names.
#   * Per-location AMENITIES (camps: campfire only; cities: full set)
#     and location-EXCLUSIVE shop stock (unique items/potions).
# BALANCE LEVERS: AoE splash 65%. Spawn baselines (corruption-scaled,
#   Phase 4): variant 30%+CR/4, group 28%+CR/5, support 40%+CR/5.
function Get-SkillLevel {
    param([string]$Skill)
    $xp = 0
    if($script:SkillXP -and $script:SkillXP.ContainsKey($Skill)){
        $xp = [int]$script:SkillXP[$Skill]
    }
    $lvl = 0
    $need = 100
    while($xp -ge $need -and $lvl -lt 50){   # hard cap Lv 50
        $xp -= $need
        $lvl++
        $need = ($lvl + 1) * 100
    }
    return $lvl
}

# Grants XP to a skill. Safe no-op for unknown skill names so callers
# never need guards. Bonuses from skill levels arrive in Phase 4 and
# will be capped low per design (skills are seasoning, not the meal).
function Add-SkillXP {
    param([string]$Skill, [int]$Amount = 1)
    if(-not $script:SkillXP){ return }
    if(-not $script:SkillXP.ContainsKey($Skill)){ return }
    if($Amount -le 0){ return }
    $before = Get-SkillLevel $Skill
    $script:SkillXP[$Skill] = [int]$script:SkillXP[$Skill] + $Amount
    $after = Get-SkillLevel $Skill
    if($after -gt $before){
        $script:StatusMsg = "Skill up! $Skill is now level $after."
    }
}


# ── Phase 4: skill bonus helpers ──────────────────────────────────
# Uniform tier: +1 effect step per 10 skill levels (max 5 at cap 50).
# Skills are seasoning, not the meal (locked design decision).
function Get-SkillTier {
    param([string]$Skill)
    return [math]::Floor((Get-SkillLevel $Skill) / 10)
}

# Armor weight classes (Phase 4): explicit name map, locked decision
# 'classify by name tier'. Amulets are jewelry — excluded from weight
# classification entirely. Mythril is classified LIGHT (canonically
# so), which gives both classes a low- and high-tier option in every
# slot. Unknown/future pieces default to Heavy.
function Get-ArmorWeightClass {
    param($Item)
    if(-not $Item -or -not $Item.Name){ return "" }
    if($Item.Slot -eq "Amulet"){ return "" }
    switch($Item.Name){
        "Leather Cap"        { "Light" }
        "Mythril Crown"      { "Light" }
        "Archon's Diadem"    { "Light" }
        "Leather Vest"       { "Light" }
        "Mythril Cuirass"    { "Light" }
        "Wooden Shield"      { "Light" }
        "Enchanted Ward"     { "Light" }
        "Starlight Aegis"    { "Light" }
        "Leather Boots"      { "Light" }
        "Windstrider Boots"  { "Light" }
        "Boots of Legends"   { "Light" }
        "Mythril Treads"     { "Light" }
        "Cachewoven Cap"     { "Light" }
        "Longshore Greaves"  { "Light" }
        "Whisperstep Boots"  { "Light" }
        "Orphan's Cloak"     { "Light" }
        "Indexer's Visor"    { "Light" }
        default              { "Heavy" }
    }
}

# Compact listing tag (v1.6.1): " [H]" heavy / " [L]" light / "" for
# jewelry — the weight class is finally VISIBLE wherever armor is
# listed (shops, equip screens, crafting, character sheet).
function Get-ArmorClassTag {
    param($Item)
    switch(Get-ArmorWeightClass $Item){
        "Heavy" { " [H]" }
        "Light" { " [L]" }
        default { "" }
    }
}

# Majority weight class across equipped non-amulet armor (4 slots).
# Strict majority required; ties or nothing equipped return "".
function Get-EquippedArmorMajority {
    $heavy = 0; $light = 0
    foreach($slot in @("Helmet","Chest","Shield","Boots")){
        $piece = $script:EquippedArmor[$slot]
        if(-not $piece){ continue }
        switch(Get-ArmorWeightClass $piece){
            "Heavy" { $heavy++ }
            "Light" { $light++ }
        }
    }
    if($heavy -gt $light){ return "Heavy" }
    if($light -gt $heavy){ return "Light" }
    return ""
}

# +1 DEF per 10 HeavyArmor levels while heavy-majority (max +5).
# v1.6.2: a MATCHING wardrobe (3+ pieces, every one the same class)
# pays a flat class bonus on top of the skill tiers — Heavy sets
# +2 DEF, Light sets +2 SPD.
function Get-ArmorClassSetBonus {
    param([string]$Cls)
    $n = 0
    foreach($apc in $script:EquippedArmor.Values){
        if(-not $apc){ continue }
        if((Get-ArmorWeightClass $apc) -ne $Cls){ return 0 }
        $n++
    }
    if($n -ge 3){ return 2 }
    return 0
}
function Get-ArmorSkillDEF {
    $b = 0
    if((Get-EquippedArmorMajority) -eq "Heavy"){ $b += Get-SkillTier "HeavyArmor" }
    $b += Get-ArmorClassSetBonus "Heavy"
    return $b
}
# +1 SPD per 10 LightArmor levels while light-majority (max +5).
function Get-ArmorSkillSPD {
    $b = 0
    if((Get-EquippedArmorMajority) -eq "Light"){ $b += Get-SkillTier "LightArmor" }
    $b += Get-ArmorClassSetBonus "Light"
    return $b
}

# ── Phase 4: Corruption (Cat 8) ────────────────────────────────
# World-state meter 0-100. Sources (locked decision): rises on player
# death (+15) and successful flees (+3); falls on boss kills (dungeon
# boss -10, miniboss -4, hidden boss -15). Effects are COMPOSITION-
# based only — nastier spawn mixes, a cutpurse instead of the lost
# merchant, stingier altars — never raw stat scaling (that would
# double-stack with the Difficulty setting). Persists via save key CR
# and through 'Play Again (Same Character)'; a new character resets it.
function Add-Corruption {
    param([int]$Delta)
    if($Delta -eq 0){ return }
    $old = [int]$script:Corruption
    $script:Corruption = [math]::Max(0, [math]::Min(100, $old + $Delta))
    if($script:Corruption -eq $old){ return }
    if($Delta -gt 0){
        $script:StatusMsg = "The Depths grow darker... (Corruption $($script:Corruption))"
    } else {
        $script:StatusMsg = "The Depths breathe a little easier. (Corruption $($script:Corruption))"
    }
}

# Spawn-composition chances, corruption-scaled from the Phase 2/3
# baselines (variant 30%, group 28%, support-in-group 40%).
function Get-CorruptionVariantChance {
    $ch = 30 + [math]::Floor($script:Corruption / 4)   # 30-55%
    # Radiant events (Phase 5): nastier variants stir.
    switch(Get-ActiveRadiantEvent){
        "BloodMoon" { $ch += 25 }
        "Plague"    { $ch += 15 }
    }
    return $ch
}
function Get-CorruptionGroupChance {
    # v1.6.2 retune: 18% base, gentler corruption slope (18-30%).
    $ch = 18 + [math]::Floor($script:Corruption / 8)
    switch(Get-ActiveRadiantEvent){
        "GoblinHorde" { $ch += 15 }
        "BloodMoon"   { $ch += 10 }
    }
    return $ch
}
function Get-CorruptionSupportChance {
    $ch = 40 + [math]::Floor($script:Corruption / 5)   # 40-60%
    if((Get-ActiveRadiantEvent) -eq "BloodMoon"){ $ch += 20 }
    return $ch
}

# ── Phase 5: RADIANT EVENTS ────────────────────────────────────────
# Stateless by design: the active event derives PURELY from the
# GameDay counter (modulo windows, priority-ordered), so there is
# nothing to save, reset, or desync — and the nap-spam cap means days
# cannot be fast-forwarded past them. Never wall-clock (no background
# scheduling is possible without file/process access, by design).
#   Blood Moon      — every 13th day (1 day): elites and packs surge,
#                     supports muster, kills grant +25% XP
#   Goblin Horde    — days = 4,5 (mod 9), from day 8: goblins flood
#                     the spawn table, packs form more often
#   Blighted Plague — days = 7,8 (mod 11), from day 9: the dead walk
#                     in numbers, nastier variants stir
function Get-ActiveRadiantEvent {
    $d = [int]$script:GameDay
    if($d -ge 13 -and ($d % 13) -eq 0){ return "BloodMoon" }
    if($d -ge 8  -and (($d % 9) -eq 4 -or ($d % 9) -eq 5)){ return "GoblinHorde" }
    if($d -ge 9  -and (($d % 11) -eq 7 -or ($d % 11) -eq 8)){ return "Plague" }
    return ""
}

function Get-RadiantEventInfo {
    switch(Get-ActiveRadiantEvent){
        "BloodMoon"   { @{ Name="BLOOD MOON";      Color="Red";       Line="The moon hangs red over the Depths. Everything below is bolder — and worth more." } }
        "GoblinHorde" { @{ Name="GOBLIN HORDE";    Color="Green";     Line="Goblin drums echo up the stairwells. The little terrors are everywhere." } }
        "Plague"      { @{ Name="BLIGHTED PLAGUE"; Color="DarkGreen"; Line="A blight seeps through the halls. The dead are walking in numbers." } }
        default       { $null }
    }
}

# Spawn-table bias during events: 60% of regular rolls become the
# event's signature type. Both bias targets are base-table types.
function Get-EventBiasedType {
    param($Pool)
    switch(Get-ActiveRadiantEvent){
        "GoblinHorde" { if((Get-Random -Max 100) -lt 60){ return "Goblin" } }
        "Plague"      { if((Get-Random -Max 100) -lt 60){ return "Zombie" } }
        "BloodMoon"   { if((Get-Random -Max 100) -lt 50){ return (@("Zombie","Skeleton") | Get-Random) } }
    }
    return ($Pool | Get-Random)
}

function Announce-RadiantEvent {
    # v1.6.2: event windows can CHAIN (a day-13 Blood Moon rolls
    # straight into a day-14 Goblin Horde), and the banner used to
    # flip silently — reading like a bug. Transitions are now
    # called out, including endings.
    $ev = Get-RadiantEventInfo
    $cur = if($ev){ [string]$ev.Name } else { "" }
    if($null -eq $script:LastSeenEvent){ $script:LastSeenEvent = "" }
    if($cur -ne $script:LastSeenEvent -and $script:LastSeenEvent -ne ""){
        Write-CL "  ... the $($script:LastSeenEvent) has passed." "DarkGray"
    }
    if($ev){
        Write-CL "  *** $($ev.Name) ***" $ev.Color
        Write-CL "  $($ev.Line)" "DarkGray"
    }
    $script:LastSeenEvent = $cur
}

# Permanent shop discount granted by defeating the Orphaned Process.
# Applied multiplicatively to all shop purchase prices.
function Get-ShopDiscount {
    $mul = 1.0
    if($script:HiddenBossDefeated){ $mul *= 0.85 }   # 15% off
    # Phase 4: a calm world trades kindly — 5% off below 25 Corruption.
    if($script:Corruption -lt 25){ $mul *= 0.95 }
    return $mul
}
# v1.6.2: names the ACTIVE discount sources. Fresh characters start
# at 0 Corruption and rightly get the calm-world 5% — but every
# receipt used to credit it to a "Guild SysAdmin discount" the
# player never earned. SysAdmin favor is the hidden-boss 15%.
function Get-ShopDiscountLabel {
    $parts = @()
    if($script:HiddenBossDefeated){ $parts += "SysAdmin favor" }
    if($script:Corruption -lt 25){ $parts += "calm world" }
    if($parts.Count -eq 0){ return "discount" }
    return (($parts -join " + ") + " discount")
}

# Difficulty -> enemy stat multiplier. Easy = 0.75, Medium = 1.0, Hard = 1.25.
# Applied to enemy HP/MaxHP and ATK in Start-Combat (see scaling block).
function Get-DifficultyMul {
    switch($script:Settings.Difficulty){
        "Easy" { return 0.75 }
        "Hard" { return 1.25 }
        default { return 1.0 }
    }
}

# Best-effort terminal resize. PS5.1 has [Console]::SetWindowSize and
# [Console]::SetBufferSize natively; both are safe and don't shell out.
# Failures (window manager refusing the resize, sandboxed host, etc.)
# are swallowed silently.
function Try-AutoResizeTerminal {
    if(-not $script:Settings.AutoResize){ return }
    try {
        $targetW = 100
        $targetH = 40
        $maxW = [Console]::LargestWindowWidth
        $maxH = [Console]::LargestWindowHeight
        if($targetW -gt $maxW){ $targetW = $maxW }
        if($targetH -gt $maxH){ $targetH = $maxH }
        # Buffer must be >= window dimensions. The trick: when shrinking
        # the window, you must shrink the WINDOW first so the buffer
        # shrink doesn't fail (buffer can't be smaller than window).
        # When growing, grow the BUFFER first so the window grow doesn't
        # fail (window can't be larger than buffer).
        $curW = [Console]::WindowWidth
        $curH = [Console]::WindowHeight
        $curBufH = [Console]::BufferHeight
        $newBufH = [Math]::Max($curBufH, $targetH + 100)
        if($targetW -le $curW -and $targetH -le $curH){
            # Shrink path: window first, then buffer.
            [Console]::SetWindowSize($targetW, $targetH)
            [Console]::SetBufferSize($targetW, $newBufH)
        } else {
            # Grow (or mixed) path: buffer first, then window. We grow
            # buffer width up to target without shrinking buffer height.
            [Console]::SetBufferSize([Math]::Max($targetW, [Console]::BufferWidth), $newBufH)
            [Console]::SetWindowSize($targetW, $targetH)
            # Snap buffer width down to the window width for a clean
            # no-horizontal-scroll experience.
            try { [Console]::SetBufferSize($targetW, $newBufH) } catch {}
        }
    } catch {
        # Some hosts (ConPTY in some terminal apps, Windows Terminal at
        # certain settings) don't permit window resize. That's fine —
        # we just leave the user's existing window.
    }
}
# ── Pet (v1.5): one of "Hound", "Raven", "Falcon" or $null. ──
# Pets are bought at the Guild Hall and provide a single passive perk:
#   Hound  — chests show on minimap regardless of fog of war
#   Raven  — +5% gold from all sources
#   Falcon — minimap window radius 5 -> 8
$script:Pet = $null
# ── Cooking (v1.5): ingredients drop from enemies; combine at the Inn
# into buff foods that last the entire dungeon run. Active buff cleared
# on dungeon end (clear or death).
$script:Ingredients     = @{}      # e.g. @{Mushroom=2; Herb=0; Meat=1; Bone=3}
$script:ActiveFoodBuff  = $null    # @{Name; Effect; Value} or $null



# ─── HELPERS ──────────────────────────────────────────────────────

# ── FRAME BUFFER (for flicker-free dungeon redraws) ─────────────────
# When $script:Buffered is $true, Write-C / Write-CL append to an
# in-memory frame buffer instead of writing directly to the host.
# Calling Flush-Frame compares the new buffer to the previous frame
# and only writes the cells that changed, by cursor-positioning. This
# eliminates the screen flash from Clear-Host on every dungeon turn.
#
# Hosts that don't support cursor positioning fall back to Clear-Host
# + full-paint automatically.
$script:Buffered    = $false       # is buffered output active?
$script:FrameBuf    = $null        # array of @{Text;Fg;Bg} cells, indexed [row,col]
# Buffer dimensions are sized to the actual console window so that
# cursor positioning never overflows (which would scroll the terminal
# and invalidate every other absolute position we wrote).
# We reserve ZERO rows for "below buffer" content — controls bar and
# prompt go INTO the buffer and get diff-painted with the rest.
$script:FrameRows   = 36
$script:FrameCols   = 100
try {
    $ws = $Host.UI.RawUI.WindowSize
    if($ws.Width  -ge 60){
        if($ws.Width -le 120){ $script:FrameCols = $ws.Width }
        else { $script:FrameCols = 120 }
    }
    if($ws.Height -ge 24){
        # Reserve 1 trailing row so the cursor parking spot doesn't trigger scroll.
        $script:FrameRows = [math]::Min($ws.Height - 1, 50)
    }
} catch {}
$script:FrameRow    = 0            # current write row
$script:FrameCol    = 0            # current write col
$script:PrevFrame   = $null        # previous frame for diff
$script:CursorPosOK = $null        # null=untested, $true=works, $false=fallback to Clear-Host
$script:BufferedFirstFrame = $true # full-paint on first frame after Begin-Frame

function Test-CursorPositionOK {
    if($null -ne $script:CursorPosOK){ return $script:CursorPosOK }
    try {
        $null = $Host.UI.RawUI.CursorPosition
        $script:CursorPosOK = $true
    } catch {
        $script:CursorPosOK = $false
    }
    return $script:CursorPosOK
}

function Begin-Frame {
    # Detect window-size changes since the last frame. If the size has
    # changed (or this is the first frame), resize the buffer to match
    # the new window and force a full repaint to avoid stale-cell
    # mismatches against the previous frame.
    #
    # The dungeon view needs ~30 rows: ~27 for the 3D viewport + minimap
    # + HUD + status, plus 2 controls bar lines + 1 prompt. We require
    # 32 rows of headroom to enable buffered rendering. Smaller windows
    # fall back to Clear-Host + full-paint each frame (slower but
    # correct — no scroll-induced tearing).
    $script:BufferedDisabled = $false
    try {
        $ws = $Host.UI.RawUI.WindowSize
        if($ws.Width -lt 80 -or $ws.Height -lt 32){
            # Too small for buffered rendering. Fall back to clear-and-redraw.
            $script:BufferedDisabled = $true
            $script:Buffered = $false
            $script:PrevFrame = $null
            $script:BufferedFirstFrame = $true
            return
        }
        $newCols = $script:FrameCols
        $newRows = $script:FrameRows
        if($ws.Width -le 120){ $newCols = $ws.Width }
        else { $newCols = 120 }
        # Buffer height: leave 2 rows of safety margin under the window
        # so the cursor never hits the bottom and triggers terminal scroll.
        $newRows = [math]::Min($ws.Height - 2, 50)
        if($newCols -ne $script:FrameCols -or $newRows -ne $script:FrameRows){
            $script:FrameCols = $newCols
            $script:FrameRows = $newRows
            $script:PrevFrame = $null
            $script:BufferedFirstFrame = $true
        }
    } catch {
        $script:BufferedDisabled = $true
        $script:Buffered = $false
        return
    }

    # Allocate a fresh buffer of empty cells. Mark cursor pos at home.
    $script:FrameBuf = New-Object 'object[,]' $script:FrameRows, $script:FrameCols
    for($r=0; $r -lt $script:FrameRows; $r++){
        for($c=0; $c -lt $script:FrameCols; $c++){
            $script:FrameBuf[$r,$c] = @{Text=' '; Fg='Gray'; Bg=''}
        }
    }
    $script:FrameRow = 0
    $script:FrameCol = 0
    $script:Buffered = $true
}

function Buf-Write {
    param([string]$Text, [string]$Fg='Gray', [string]$Bg='')
    if(-not $script:FrameBuf){ return }
    if($null -eq $Text){ return }
    foreach($ch in $Text.ToCharArray()){
        if($ch -eq "`n"){
            $script:FrameRow++
            $script:FrameCol = 0
            continue
        }
        if($script:FrameRow -ge $script:FrameRows){ return }
        if($script:FrameCol -ge $script:FrameCols){
            # truncate rather than wrapping
            continue
        }
        $script:FrameBuf[$script:FrameRow, $script:FrameCol] = @{Text=[string]$ch; Fg=$Fg; Bg=$Bg}
        $script:FrameCol++
    }
}

function Buf-Newline {
    if(-not $script:FrameBuf){ return }
    $script:FrameRow++
    $script:FrameCol = 0
}

# Diff current frame vs previous and paint only changed cells.
# On hosts without cursor positioning, fall back to Clear-Host + full
# repaint (which is identical to the pre-buffer behavior).
function Flush-Frame {
    if(-not $script:FrameBuf){ return }
    $script:Buffered = $false   # writes after this go directly to host

    if(-not (Test-CursorPositionOK)){
        # Fallback path: dump entire buffer with regular writes
        Clear-Host
        for($r=0; $r -lt $script:FrameRows; $r++){
            $hasContent = $false
            for($c=0; $c -lt $script:FrameCols; $c++){
                if($script:FrameBuf[$r,$c].Text -ne ' '){ $hasContent = $true; break }
            }
            if(-not $hasContent){ Write-Host ""; continue }
            $line = ""
            $curFg = $null; $curBg = $null
            for($c=0; $c -lt $script:FrameCols; $c++){
                $cell = $script:FrameBuf[$r,$c]
                if($cell.Fg -ne $curFg -or $cell.Bg -ne $curBg){
                    if($line.Length -gt 0){
                        if($curBg){ Write-Host $line -ForegroundColor $curFg -BackgroundColor $curBg -NoNewline }
                        else      { Write-Host $line -ForegroundColor $curFg -NoNewline }
                        $line = ""
                    }
                    $curFg = $cell.Fg; $curBg = $cell.Bg
                }
                $line += $cell.Text
            }
            if($line.Length -gt 0){
                if($curBg){ Write-Host $line -ForegroundColor $curFg -BackgroundColor $curBg }
                else      { Write-Host $line -ForegroundColor $curFg }
            } else {
                Write-Host ""
            }
        }
        $script:PrevFrame = $script:FrameBuf
        $script:FrameBuf = $null
        return
    }

    # Hide cursor during paint to avoid blink flicker
    $cursorWasVisible = $true
    try { $cursorWasVisible = [Console]::CursorVisible } catch {}
    try { [Console]::CursorVisible = $false } catch {}

    if($script:BufferedFirstFrame -or -not $script:PrevFrame){
        # First frame: full clear and paint
        Clear-Host
        for($r=0; $r -lt $script:FrameRows; $r++){
            try {
                $pos = New-Object System.Management.Automation.Host.Coordinates 0, $r
                $Host.UI.RawUI.CursorPosition = $pos
            } catch { break }
            # Find last non-blank col on this row to avoid trailing spaces
            $lastCol = -1
            for($c=$script:FrameCols - 1; $c -ge 0; $c--){
                if($script:FrameBuf[$r,$c].Text -ne ' '){ $lastCol = $c; break }
            }
            if($lastCol -lt 0){ continue }
            $line = ""
            $curFg = $null; $curBg = $null
            for($c=0; $c -le $lastCol; $c++){
                $cell = $script:FrameBuf[$r,$c]
                if($cell.Fg -ne $curFg -or $cell.Bg -ne $curBg){
                    if($line.Length -gt 0){
                        if($curBg){ Write-Host $line -ForegroundColor $curFg -BackgroundColor $curBg -NoNewline }
                        else      { Write-Host $line -ForegroundColor $curFg -NoNewline }
                        $line = ""
                    }
                    $curFg = $cell.Fg; $curBg = $cell.Bg
                }
                $line += $cell.Text
            }
            if($line.Length -gt 0){
                if($curBg){ Write-Host $line -ForegroundColor $curFg -BackgroundColor $curBg -NoNewline }
                else      { Write-Host $line -ForegroundColor $curFg -NoNewline }
            }
        }
        $script:BufferedFirstFrame = $false
    } else {
        # Diff and paint only changed runs of cells
        for($r=0; $r -lt $script:FrameRows; $r++){
            $c = 0
            while($c -lt $script:FrameCols){
                $newCell = $script:FrameBuf[$r,$c]
                $oldCell = $script:PrevFrame[$r,$c]
                if($newCell.Text -ne $oldCell.Text -or $newCell.Fg -ne $oldCell.Fg -or $newCell.Bg -ne $oldCell.Bg){
                    # Found a changed cell — find run of consecutive changes with same fg/bg
                    $runStart = $c
                    $runFg = $newCell.Fg
                    $runBg = $newCell.Bg
                    $runText = $newCell.Text
                    $c++
                    while($c -lt $script:FrameCols){
                        $nc = $script:FrameBuf[$r,$c]
                        $oc = $script:PrevFrame[$r,$c]
                        $changed = ($nc.Text -ne $oc.Text -or $nc.Fg -ne $oc.Fg -or $nc.Bg -ne $oc.Bg)
                        if(-not $changed -or $nc.Fg -ne $runFg -or $nc.Bg -ne $runBg){ break }
                        $runText += $nc.Text
                        $c++
                    }
                    try {
                        $pos = New-Object System.Management.Automation.Host.Coordinates $runStart, $r
                        $Host.UI.RawUI.CursorPosition = $pos
                        if($runBg){ Write-Host $runText -ForegroundColor $runFg -BackgroundColor $runBg -NoNewline }
                        else      { Write-Host $runText -ForegroundColor $runFg -NoNewline }
                    } catch {
                        # If positioning fails, abandon partial-redraw and full-paint next time
                        $script:BufferedFirstFrame = $true
                        break
                    }
                } else {
                    $c++
                }
            }
        }
    }

    # Restore cursor visibility. The CALLER is responsible for parking the
    # cursor wherever it should appear (e.g. at a prompt) — Flush-Frame
    # leaves it wherever the last paint write put it.
    try { [Console]::CursorVisible = $cursorWasVisible } catch {}

    $script:PrevFrame = $script:FrameBuf
    $script:FrameBuf = $null
}

# Reset buffered mode — call when leaving the dungeon to force full paint next time.
function Reset-FrameBuffer {
    $script:Buffered = $false
    $script:FrameBuf = $null
    $script:PrevFrame = $null
    $script:BufferedFirstFrame = $true
}

function Write-C { param([string]$Text,[string]$Color="White",[string]$BG="")
    if($script:Buffered){
        Buf-Write $Text $Color $BG
        return
    }
    if($BG){
        Write-Host $Text -ForegroundColor $Color -BackgroundColor $BG -NoNewline
    } else {
        Write-Host $Text -ForegroundColor $Color -NoNewline
    }
}
function Write-CL { param([string]$Text,[string]$Color="White",[string]$BG="")
    if($script:Buffered){
        Buf-Write $Text $Color $BG
        Buf-Newline
        return
    }
    if($BG){
        Write-Host $Text -ForegroundColor $Color -BackgroundColor $BG
    } else {
        Write-Host $Text -ForegroundColor $Color
    }
}
function Wait-Key { Write-Host ""; Write-C "[Press any key]" "DarkGray"; $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown") }
# Like Wait-Key but specifically waits for Enter. Used in screens where
# the player is expected to read text and press Enter to dismiss — feels
# more deliberate than tapping any key.
function Wait-Enter {
    Write-Host ""
    Write-C "[Press Enter]" "DarkGray"
    $null = Read-Host
}
function clr {
    Clear-Host
    # Any non-dungeon clear invalidates the buffered dungeon state, so the
    # next dungeon render starts with a full paint instead of a partial diff.
    $script:BufferedFirstFrame = $true
    $script:PrevFrame = $null
}

# Drains ALL pending console input WITHOUT ever blocking (v1.6.2).
# The trap: RawUI.KeyAvailable counts key-UP events, but ReadKey with
# only IncludeKeyDown discards ups and then BLOCKS for the next
# keydown — so a drain running right as the player releases a key
# hangs until they press another (the [Q] black-screen bug). Console
# path first ([Console]::KeyAvailable is keydown-filtered at the .NET
# level), RawUI with BOTH filters as fallback, hard-capped like the
# fishing minigame's fish-Drain, which documented this trap first.
# v1.6.2: boxed notice panel — shared style for the display checks
# and the quit screen (color-coded per purpose).
function Show-NoticePanel {
    param([string]$Title, [string[]]$Lines, [string]$Color = "Yellow", [string]$EdgeColor = "DarkYellow")
    $bar = "═" * 62
    Write-Host ""
    Write-CL "  ╔$bar╗" $EdgeColor
    Write-CL ("  ║ " + $Title.PadRight(60) + " ║") $Color
    Write-CL "  ╚$bar╝" $EdgeColor
    Write-Host ""
    foreach($nl in $Lines){ Write-CL "  $nl" "Gray" }
    Write-Host ""
}

# Display checks (v1.6.2): unique panels per renderer. The 3D view
# resizes the window itself now, so its warning is about ART — on a
# cramped or odd host, loot banners and encounter art can shear.
# Classic keeps the original size guidance.
# v1.6.2: cosmetic 'carving the floor' animation between the entry
# text screens and the first frame. Pure random noise — it reveals
# NOTHING of the real layout (fresh symbols every phase).
function Show-GenerationVisual {
    try {
        clr
        $phases = @("Carving corridors","Raising walls","Wiring the torches","Hiding the loot","Sealing the boss room","Waking the residents")
        for($gp = 0; $gp -lt $phases.Count; $gp++){
            try { [Console]::SetCursorPosition(0,1) } catch {}
            Write-CL "   G E N E R A T I N G   F L O O R   $($script:DungeonLevel)" "Cyan"
            Write-Host ""
            for($gy = 0; $gy -lt 10; $gy++){
                $row = ""
                for($gx = 0; $gx -lt 44; $gx++){
                    $gr = Get-Random -Max 10
                    $row += if($gr -lt 3){"█"} elseif($gr -lt 5){"▓"} elseif($gr -lt 7){"░"} else {" "}
                }
                Write-CL "   $row" "DarkGray"
            }
            Write-Host ""
            Write-CL ("   " + $phases[$gp] + "..." + (" " * 30)) "Yellow"
            Start-Sleep -Milliseconds 320
        }
    } catch {}
    clr
}

function Show-DisplayCheck {
    if(Test-RaycastActive){
        Show-NoticePanel -Title "D I S P L A Y   C H E C K  —  3 D   V I E W" -Color "Cyan" -EdgeColor "DarkCyan" -Lines @(
            "The 3D view manages its own window size. If your terminal",
            "fights the resize, expect visual glitches: sheared loot",
            "banners, broken encounter art, or torn frames.",
            "",
            "If art looks broken, enlarge the window — everything",
            "heals on the next screen."
        )
    } else {
        Show-NoticePanel -Title "D I S P L A Y   C H E C K  —  C L A S S I C   V I E W" -Color "Yellow" -EdgeColor "DarkYellow" -Lines @(
            "The classic view wants at least 80 columns and 30 rows.",
            "On a smaller window, screens can wrap and art — loot",
            "banners, encounters, the map — may come out broken.",
            "",
            "Maximize the terminal for the intended experience."
        )
    }
    Wait-Key
}

function Drain-Keys {
    for($dk = 0; $dk -lt 60; $dk++){
        $any = $false
        try { if([Console]::KeyAvailable){ $null = [Console]::ReadKey($true); $any = $true } } catch {}
        if(-not $any){
            try {
                if($Host.UI.RawUI.KeyAvailable){
                    $null = $Host.UI.RawUI.ReadKey('NoEcho,IncludeKeyDown,IncludeKeyUp')
                    $any = $true
                }
            } catch {}
        }
        if(-not $any){ break }
    }
}

# Safely parse a string into an integer. Returns $Default (0 by default) for
# any non-numeric input — including empty strings, letters, spaces, etc.
# Use this everywhere the user types a number into a Read-Host menu so a
# stray keystroke can't crash the game with a casting exception.
function ConvertTo-SafeInt {
    param(
        [string]$Value,
        [int]$Default = 0
    )
    if([string]::IsNullOrWhiteSpace($Value)){ return $Default }
    $trimmed = $Value.Trim()
    $val = 0
    if([int]::TryParse($trimmed, [ref]$val)){ return $val }
    return $Default
}

# ─── ABILITY SCALING ─────────────────────────────────────────────
# Player abilities evolve at levels 5, 10, 15. Each tier adds power.
# Capped at 3 upgrades (max tier reached at level 15).
#
# Returns the current ability tier index (0 = base, 1, 2, or 3).
function Get-AbilityTier {
    param([int]$Level)
    if($Level -ge 15){ return 3 }
    if($Level -ge 10){ return 2 }
    if($Level -ge 5){  return 1 }
    return 0
}

# Returns a roman-numeral suffix for the ability name based on tier.
# Base tier (0) returns empty string so the base name is unchanged.
function Get-TierSuffix {
    param([int]$Tier)
    switch($Tier){
        1 { " II" }
        2 { " III" }
        3 { " IV" }
        default { "" }
    }
}

# Returns a scaled copy of an ability with its Power upgraded by tier
# and its Name appended with " II / III / IV".
# Heals scale more (the player's MaxHP grows fast); buffs are also scaled.
function Get-ScaledAbility {
    param($Ability, [int]$Level)
    $tier = Get-AbilityTier $Level
    if($tier -le 0){ return $Ability }
    $copy = @{}
    foreach($k in $Ability.Keys){ $copy[$k] = $Ability[$k] }
    # +25% power per tier (rounded up). Healing scales the same way.
    if($Ability.Power -gt 0){
        $copy.Power = [int][math]::Ceiling($Ability.Power * (1 + 0.25 * $tier))
    }
    $copy.Name = $Ability.Name + (Get-TierSuffix $tier)
    return $copy
}

# Returns total DEF bonus from all equipped armor pieces
function Get-TotalArmorDEF {
    $total = 0
    foreach($slot in $script:EquippedArmor.Keys){
        $piece = $script:EquippedArmor[$slot]
        if($piece -and -not (Test-ItemBroken $piece)){
            $total += $piece.DEF
        }
    }
    return $total
}

# Returns bonus ATK if equipped weapon matches player class
# Helper used by shop tables: pads a string to $Width with a leading space,
# truncating if the text is longer than the column. Renders text exactly
# inside a cell of the given width, lining up with border dashes.
function Pad-Cell {
    param([string]$Text, [int]$Width)
    $s = " $Text"
    if($s.Length -ge $Width){ return $s.Substring(0, $Width) }
    return $s.PadRight($Width)
}

# ─── DURABILITY SYSTEM ────────────────────────────────────────────
# Weapons and armor have a durability pool. Broken items stay equipped
# but contribute 0 stat bonus. Repairs happen at the blacksmith.
#
# Max durability formulas:
#   Weapons: max(20, ATK * 2)     — tier scales linearly with hits
#   Armor:   max(15, DEF * 3)     — tier scales with hits absorbed
#
# Returns the computed max durability for a given item.
# ─── INVENTORY WEIGHT SYSTEM ─────────────────────────────────────
# Carry capacity: 100 + (avg(ATK,DEF) * 5). Updates whenever stats change.
# Equipped gear is FREE. Gold, lockpicks, repair kits, ESPs, potions weigh 0.
# Loot weight = ceil(value/30). Equipment in inventory has fixed slot/type weight.
function Get-MaxCarryWeight {
    param($Player)
    # Hard cap: 90. No longer scales with player stats — keeps inventory
    # decisions meaningful at every level (you can't just train ATK/DEF
    # to carry more loot).
    return 90
}

# Returns the weight an inventory item contributes when carried (NOT equipped).
function Get-ItemWeight {
    param($Item)
    if(-not $Item){ return 0 }
    if($Item.ContainsKey("Weight")){ return [int]$Item.Weight }
    # Fallback: classify by Kind / Slot / WeaponType
    if($Item.Kind -eq "Weapon" -or $Item.WeaponType){
        $wt = switch($Item.WeaponType){
            "Dagger"     { 4 }
            "Staff"      { 4 }
            "Wand"       { 4 }
            "Sword"      { 5 }
            "Mace"       { 5 }
            "Bow"        { 5 }
            "Greatsword" { 6 }
            "Scythe"     { 6 }
            "Hammer"     { 6 }
            default      { 5 }
        }
        return $wt
    }
    if($Item.Kind -eq "Armor" -or $Item.Slot){
        $wt = switch($Item.Slot){
            "Helmet" { 2 }
            "Chest"  { 4 }
            "Shield" { 3 }
            "Amulet" { 1 }
            "Boots"  { 2 }
            default  { 2 }
        }
        return $wt
    }
    # Potions all weigh 1 — small but not free
    if($Item.Kind -eq "Potion" -or $Item.Type -in @("Heal","Mana","ATKBuff","DEFBuff","Luck","Throw","ThrowPoison","ThrowSlow")){
        return 1
    }
    # Loot fallback: ceil(value / 30)
    if($Item.Value){
        return [math]::Max(1, [math]::Ceiling([int]$Item.Value / 30.0))
    }
    return 1
}

# Sums weight across the inventory bag.
function Get-CurrentCarryWeight {
    $w = 0
    foreach($it in $script:Inventory){
        $w += (Get-ItemWeight $it)
    }
    # Lockpicks weigh 1 each
    $w += [int]$script:Lockpicks
    # Potions and throwables in their respective bags weigh 1 each
    if($script:Potions){
        $w += $script:Potions.Count
    }
    if($script:ThrowablePotions){
        $w += $script:ThrowablePotions.Count
    }
    # Equipped armor counts toward carry weight. Slot-based defaults:
    #   Helmet 3, Chest 5, Shield 4, Amulet 1, Boots 2  (= 15 if fully geared)
    # Items that store an explicit Weight field use that instead.
    if($script:EquippedArmor){
        foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
            $piece = $script:EquippedArmor[$slot]
            if($piece){
                if($piece.Weight){
                    $w += [int]$piece.Weight
                } else {
                    $defaultWt = switch($slot){
                        "Helmet" { 3 }
                        "Chest"  { 5 }
                        "Shield" { 4 }
                        "Amulet" { 1 }
                        "Boots"  { 2 }
                        default  { 0 }
                    }
                    $w += $defaultWt
                }
            }
        }
    }
    # Equipped weapon contributes weight too. Default 4 wt unless the weapon
    # stores an explicit Weight field.
    if($script:EquippedWeapon){
        if($script:EquippedWeapon.Weight){
            $w += [int]$script:EquippedWeapon.Weight
        } else {
            $w += 4
        }
    }
    # Cooking ingredients: 1 wt each. They live in $script:Ingredients
    # (not the bag), so we sum the counter values.
    if($script:Ingredients){
        foreach($k in $script:Ingredients.Keys){
            $w += [int]$script:Ingredients[$k]
        }
    }
    return $w
}

# Computes a unified sell value for any inventory item.
# - Loot:    its Value field
# - Weapons: 50% of shop Price (rounded down)
# - Armor:   50% of shop Price (rounded down)
# - Other:   Value field if present, else 0
function Get-ItemSellValue {
    param($Item)
    if(-not $Item){ return 0 }
    if($Item.Kind -eq "Weapon" -or $Item.WeaponType){
        if($Item.Price){ return [math]::Max([int][math]::Floor([int]$Item.Price * 0.5), 1) }
    }
    if($Item.Kind -eq "Armor" -or $Item.Slot){
        if($Item.Price){ return [math]::Max([int][math]::Floor([int]$Item.Price * 0.5), 1) }
    }
    # Potions and throwables (Category="Potion"/"Throwable") sell at 50% Price.
    # Extra-Strong (Category="Special") have Price=0 in shop data; use 250g notional.
    if($Item.Category -eq "Potion" -or $Item.Category -eq "Throwable"){
        if($Item.Price){ return [math]::Max([int][math]::Floor([int]$Item.Price * 0.5), 1) }
    }
    if($Item.Category -eq "Special"){ return 250 }
    if($Item.Value){
        # Honored Data Miners (Phase 6): they buy your loot at +10% —
        # every trinket is data to somebody.
        if($Item.Kind -eq "Loot" -and (Get-FactionRep "DataMiners") -ge 25){
            return [int][math]::Floor([int]$Item.Value * 1.10)
        }
        return [int]$Item.Value
    }
    if($Item.Price){ return [math]::Max([int][math]::Floor([int]$Item.Price * 0.5), 1) }
    return 0
}

# True if the player is at or over their carry cap.
function Test-Encumbered {
    $cur = Get-CurrentCarryWeight
    $max = Get-MaxCarryWeight $script:Player
    return ($cur -gt $max)
}

# Stamps Weight + Kind onto a loot item. Idempotent.
function Init-ItemWeight {
    param($Item, [string]$Kind = "Loot")
    if(-not $Item){ return $null }
    if(-not $Item.Kind){ $Item.Kind = $Kind }
    if(-not $Item.ContainsKey("Weight")){ $Item.Weight = (Get-ItemWeight $Item) }
    return $Item
}

# ─── GEAR ACQUISITION HELPERS ────────────────────────────────────
# Unified flow for "I just got a weapon/armor — should I equip it now,
# or stow it in my inventory?" Used by all gear sources (shop, merchant,
# encounters, drops). The user picks each time.
#
# If the target slot is empty, auto-equip with no prompt — there's no
# meaningful choice (equipping vs. carrying a useless item with weight).
# Returns gold multiplier from pet effects. Currently only Raven contributes.
function Get-PetGoldMul {
    if($script:Pet -and $script:Pet.Type -eq "Raven"){ return 1.05 }
    return 1.0
}

function Invoke-GearAcquired {
    param(
        $Item,                    # the new item (hashtable)
        [string]$Kind             # "Weapon" or "Armor"
    )
    if(-not $Item){ return }

    if($Kind -eq "Weapon"){
        # 2H exclusivity: if the incoming weapon is 2H, we'll need to
        # stow the shield (if any) when the player accepts the equip.
        $needShieldStow = ($Item.TwoHanded -and $script:EquippedArmor.Shield)
        $currentEquipped = $script:EquippedWeapon
        if(-not $currentEquipped){
            # Slot empty — auto-equip with no prompt
            if($needShieldStow){
                $shield = $script:EquippedArmor.Shield
                if(-not $shield.Kind){ $shield.Kind = "Armor" }
                [void]$script:Inventory.Add($shield)
                $script:EquippedArmor.Shield = $null
                Write-CL "  $($Item.Name) is two-handed — stowed your $($shield.Name)." "DarkYellow"
            }
            $script:EquippedWeapon = $Item
            Write-CL "  Equipped: $($Item.Name)" "Green"
            return
        }
        Write-Host ""
        Write-CL "  You already have $($currentEquipped.Name) equipped." "DarkGray"
        Write-CL "  New item: $($Item.Name)$(if($Item.TwoHanded){' (Two-Handed)'}else{''})" "Yellow"
        if($needShieldStow){
            Write-CL "  NOTE: Equipping this two-handed weapon will stow your shield." "DarkYellow"
        }
        Write-Host ""
        Write-CL "    [1] Equip $($Item.Name) now (old goes to inventory)" "Cyan"
        Write-CL "    [2] Stow $($Item.Name) in inventory" "DarkCyan"
        Write-Host ""
        Write-C "    > " "Yellow"
        $c = Read-Host
        if($c -eq "1"){
            if($needShieldStow){
                $shield = $script:EquippedArmor.Shield
                if(-not $shield.Kind){ $shield.Kind = "Armor" }
                [void]$script:Inventory.Add($shield)
                $script:EquippedArmor.Shield = $null
                Write-CL "  Stowed your $($shield.Name) (two-handed weapon needs both hands)." "DarkYellow"
            }
            if(-not $currentEquipped.Kind){ $currentEquipped.Kind = "Weapon" }
            [void]$script:Inventory.Add($currentEquipped)
            $script:EquippedWeapon = $Item
            Write-CL "  Equipped $($Item.Name); $($currentEquipped.Name) stowed in bag." "Green"
        } else {
            if(-not $Item.Kind){ $Item.Kind = "Weapon" }
            [void]$script:Inventory.Add($Item)
            Write-CL "  Stowed $($Item.Name) in your bag." "DarkCyan"
        }
        if(Test-Encumbered){
            Write-CL "  -- OVER ENCUMBERED -- you cannot enter dungeons or move on the dungeon grid." "Red"
        }
        return
    }

    if($Kind -eq "Armor"){
        $slot = $Item.Slot
        if(-not $slot){
            # Defensive: shouldn't happen, but fall back to stow
            if(-not $Item.Kind){ $Item.Kind = "Armor" }
            [void]$script:Inventory.Add($Item)
            Write-CL "  Stowed $($Item.Name) in your bag." "DarkCyan"
            return
        }
        # Shield + 2H exclusivity: if equipping a Shield while wielding a
        # two-handed weapon, the player must consent to stowing the weapon.
        $needWeaponStow = ($slot -eq "Shield" -and $script:EquippedWeapon -and $script:EquippedWeapon.TwoHanded)
        $currentEquipped = $script:EquippedArmor[$slot]
        if(-not $currentEquipped){
            if($needWeaponStow){
                # Auto-equip with note that weapon was stowed
                $wep = $script:EquippedWeapon
                if(-not $wep.Kind){ $wep.Kind = "Weapon" }
                [void]$script:Inventory.Add($wep)
                $script:EquippedWeapon = $null
                Write-CL "  Stowed $($wep.Name) (two-handed) to make room for the shield." "DarkYellow"
            }
            $script:EquippedArmor[$slot] = $Item
            Write-CL "  Equipped: $($Item.Name) ($slot)" "Green"
            return
        }
        Write-Host ""
        Write-CL "  You already have $($currentEquipped.Name) equipped in $slot slot." "DarkGray"
        Write-CL "  New item: $($Item.Name)" "Yellow"
        if($needWeaponStow){
            Write-CL "  NOTE: Equipping this shield will stow your two-handed weapon." "DarkYellow"
        }
        Write-Host ""
        Write-CL "    [1] Equip $($Item.Name) now (old goes to inventory)" "Cyan"
        Write-CL "    [2] Stow $($Item.Name) in inventory" "DarkCyan"
        Write-Host ""
        Write-C "    > " "Yellow"
        $c = Read-Host
        if($c -eq "1"){
            if($needWeaponStow){
                $wep = $script:EquippedWeapon
                if(-not $wep.Kind){ $wep.Kind = "Weapon" }
                [void]$script:Inventory.Add($wep)
                $script:EquippedWeapon = $null
                Write-CL "  Stowed $($wep.Name) (two-handed)." "DarkYellow"
            }
            if(-not $currentEquipped.Kind){ $currentEquipped.Kind = "Armor" }
            [void]$script:Inventory.Add($currentEquipped)
            $script:EquippedArmor[$slot] = $Item
            Write-CL "  Equipped $($Item.Name); $($currentEquipped.Name) stowed in bag." "Green"
        } else {
            if(-not $Item.Kind){ $Item.Kind = "Armor" }
            [void]$script:Inventory.Add($Item)
            Write-CL "  Stowed $($Item.Name) in your bag." "DarkCyan"
        }
        if(Test-Encumbered){
            Write-CL "  -- OVER ENCUMBERED -- you cannot enter dungeons or move on the dungeon grid." "Red"
        }
        return
    }
}

# Equip an item already in $script:Inventory by index. The currently
# equipped piece (if any) goes back to inventory. Returns $true on
# success, $false if the index is invalid or the item kind is wrong.
function Invoke-EquipFromInventory {
    param([int]$InvIndex)
    if($InvIndex -lt 0 -or $InvIndex -ge $script:Inventory.Count){
        Write-CL "  Invalid inventory index." "Red"
        return $false
    }
    $item = $script:Inventory[$InvIndex]
    $kind = $item.Kind

    if($kind -eq "Weapon" -or $item.WeaponType){
        # 2H weapons can't coexist with a shield. If the new weapon is 2H
        # AND a shield is equipped, auto-stow the shield first. If the bag
        # would overflow, abort the equip.
        if($item.TwoHanded -and $script:EquippedArmor.Shield){
            $shield = $script:EquippedArmor.Shield
            if(-not $shield.Kind){ $shield.Kind = "Armor" }
            [void]$script:Inventory.Add($shield)
            $script:EquippedArmor.Shield = $null
            Write-CL "  $($item.Name) requires both hands. Stowed your $($shield.Name)." "DarkYellow"
        }
        $oldWep = $script:EquippedWeapon
        $script:Inventory.RemoveAt($InvIndex)
        if($oldWep){
            if(-not $oldWep.Kind){ $oldWep.Kind = "Weapon" }
            [void]$script:Inventory.Add($oldWep)
            Write-CL "  Equipped $($item.Name); $($oldWep.Name) goes to bag." "Green"
        } else {
            Write-CL "  Equipped $($item.Name)." "Green"
        }
        $script:EquippedWeapon = $item
        return $true
    }
    elseif($kind -eq "Armor" -or $item.Slot){
        $slot = $item.Slot
        if(-not $slot){
            Write-CL "  This item has no armor slot — cannot equip." "Red"
            return $false
        }
        # Block shield equip while wielding a 2H weapon — stow the weapon
        # first, then equip the shield. Player gives explicit consent in
        # the gear-acquisition flow; here we just auto-resolve it since
        # this path is always a deliberate equip from the inventory.
        if($slot -eq "Shield" -and $script:EquippedWeapon -and $script:EquippedWeapon.TwoHanded){
            $wep = $script:EquippedWeapon
            if(-not $wep.Kind){ $wep.Kind = "Weapon" }
            [void]$script:Inventory.Add($wep)
            $script:EquippedWeapon = $null
            Write-CL "  Stowed $($wep.Name) (two-handed) to make room for the shield." "DarkYellow"
        }
        $oldArm = $script:EquippedArmor[$slot]
        $script:Inventory.RemoveAt($InvIndex)
        if($oldArm){
            if(-not $oldArm.Kind){ $oldArm.Kind = "Armor" }
            [void]$script:Inventory.Add($oldArm)
            Write-CL "  Equipped $($item.Name) ($slot); $($oldArm.Name) goes to bag." "Green"
        } else {
            Write-CL "  Equipped $($item.Name) ($slot)." "Green"
        }
        $script:EquippedArmor[$slot] = $item
        return $true
    }
    else {
        Write-CL "  This isn't a weapon or armor — cannot equip." "DarkGray"
        return $false
    }
}

# ─── COMBAT STANCE ───────────────────────────────────────────────
# Aggressive: ATK x1.30 / DEF x0.70 — more damage out, more in
# Balanced  : ATK x1.00 / DEF x1.00 — neutral
# Defensive : ATK x0.70 / DEF x1.30 — less damage out, less in
# Switching is a free action during any combat turn.
function Get-StanceATKMult {
    switch($script:Stance){
        "Aggressive" { 1.30 }
        "Defensive"  { 0.70 }
        default      { 1.00 }
    }
}
function Get-StanceDEFMult {
    switch($script:Stance){
        "Aggressive" { 0.70 }
        "Defensive"  { 1.30 }
        default      { 1.00 }
    }
}
function Get-StanceColor {
    switch($script:Stance){
        "Aggressive" { "Red" }
        "Defensive"  { "Cyan" }
        default      { "Yellow" }
    }
}
function Get-StanceShortLabel {
    switch($script:Stance){
        "Aggressive" { "AGG" }
        "Defensive"  { "DEF" }
        default      { "BAL" }
    }
}

function Get-MaxDurability {
    param($Item)
    if(-not $Item){ return 0 }
    # Dutchman's Blade is cursed — never breaks
    if($Item.Name -eq "Dutchman's Blade"){ return -1 }
    if($Item.ATK){
        return [math]::Max(20, [int]$Item.ATK * 2)
    } elseif($Item.DEF){
        return [math]::Max(15, [int]$Item.DEF * 3)
    }
    return 20
}

# When the player buys or equips a new item, stamp durability fields onto it.
# We clone the hashtable so the shop catalog entries aren't mutated.
function Init-ItemDurability {
    param($Item)
    if(-not $Item){ return $null }
    $max = Get-MaxDurability $Item
    $copy = @{}
    foreach($k in $Item.Keys){ $copy[$k] = $Item[$k] }
    $copy.MaxDurability = $max
    $copy.Durability    = $max  # full on pickup
    # Cursed Loot mutator: gear drops are cursed — start at 50% durability
    # but grant +50% to ATK / DEF / MAGBonus. Indestructible items
    # (Dutchman's Blade, MaxDurability=-1) are unaffected by the
    # durability part but still get the stat boost.
    if(Has-Mutator "CursedLoot" -and ($copy.WeaponType -or $copy.Slot)){
        if($max -gt 0){
            $copy.Durability = [math]::Max(1, [math]::Floor($max * 0.5))
        }
        if($copy.ATK){
            $copy.ATK = [math]::Floor($copy.ATK * 1.5)
        }
        if($copy.DEF){
            $copy.DEF = [math]::Floor($copy.DEF * 1.5)
        }
        if($copy.MAGBonus){
            $copy.MAGBonus = [math]::Floor($copy.MAGBonus * 1.5)
        }
        # Mark for inventory display flair
        $copy.Cursed = $true
    }
    return $copy
}

# True if an item is broken (has finite durability and is at 0).
# Dutchman's Blade (MaxDurability = -1) is NEVER broken.
function Test-ItemBroken {
    param($Item)
    if(-not $Item){ return $false }
    if($Item.MaxDurability -lt 0){ return $false }  # indestructible
    if(-not $Item.ContainsKey("Durability")){ return $false }
    return ($Item.Durability -le 0)
}

# Returns a damage-to-durability color for display.
function Get-DurabilityColor {
    param($Item)
    if(-not $Item){ return "DarkGray" }
    if($Item.MaxDurability -lt 0){ return "Magenta" }  # cursed / immortal
    $cur = $Item.Durability
    $max = $Item.MaxDurability
    if($max -le 0){ return "DarkGray" }
    $pct = $cur / $max
    if($cur -le 0)    { return "Red" }
    elseif($pct -le 0.25) { return "DarkRed" }
    elseif($pct -le 0.5)  { return "DarkYellow" }
    else                  { return "Green" }
}

# Build a short durability label like "[42/60]" or "[BROKEN]" or "[∞]".
function Format-Durability {
    param($Item)
    if(-not $Item){ return "" }
    if($Item.MaxDurability -lt 0){ return "[INDESTRUCTIBLE]" }
    if(-not $Item.ContainsKey("Durability")){ return "" }
    if($Item.Durability -le 0){ return "[BROKEN]" }
    return "[$($Item.Durability)/$($Item.MaxDurability)]"
}

# Repair cost: (missing / max) * Price. Dutchman's Blade is never damaged.
function Get-RepairCost {
    param($Item)
    if(-not $Item){ return 0 }
    if($Item.MaxDurability -lt 0){ return 0 }
    $missing = $Item.MaxDurability - $Item.Durability
    if($missing -le 0){ return 0 }
    $price = if($Item.Price){ [int]$Item.Price } else { 50 }
    $cost = [math]::Floor(($missing / $Item.MaxDurability) * $price)
    # Skill (Phase 4): Blacksmithing trims repair costs, -3% per tier (max -15%).
    $cost = [math]::Floor($cost * (1.0 - 0.03 * (Get-SkillTier "Blacksmithing")))
    # Town upgrade (Phase 4e): Reinforced Forge trims another 25%.
    if($script:TownUpgrades["Forge"]){ $cost = [math]::Floor($cost * 0.75) }
    if($cost -lt 1){ $cost = 1 }
    return $cost
}

function Get-WeaponClassBonus {
    if(-not $script:EquippedWeapon){ return 0 }
    if(Test-ItemBroken $script:EquippedWeapon){ return 0 }
    $w = $script:EquippedWeapon
    # Ranger bow buff: when a Ranger wields a Bow weapon, the affinity
    # bonus is increased by 1 ATK (a small flat buff to reinforce the
    # class fantasy without overshadowing other classes' weapons).
    $rangerBowBonus = 0
    if($script:PlayerClass -eq "Ranger" -and $w.WeaponType -eq "Bow"){
        $rangerBowBonus = 1
    }
    # Direct class match (Knight+Knight-affinity sword, Mage+Mage-affinity staff, etc.)
    if($w.ClassAffinity -eq $script:PlayerClass){
        return [int]$w.AffinityBonus + $rangerBowBonus
    }
    # Shared-affinity fallbacks: new classes inherit bonuses from a related class
    # because the shop doesn't carry "Berserker"/"Warlock" tagged weapons.
    #   Berserker -> shares sword affinity with Knight
    #   Warlock   -> shares staff affinity with Mage
    $sharedAffinity = switch($script:PlayerClass){
        "Berserker" { "Knight" }
        "Warlock"   { "Mage" }
        default     { $null }
    }
    if($sharedAffinity -and $w.ClassAffinity -eq $sharedAffinity){
        return [int]$w.AffinityBonus + $rangerBowBonus
    }
    # Ranger gets the bow bonus even on bows they don't have direct affinity with
    return $rangerBowBonus
}

# True if a weapon's affinity matches the player's class (directly or via shared).
# Used by shop UIs to show "MATCH" / green highlights.
function Test-WeaponClassMatch {
    param($Weapon)
    if(-not $Weapon){ return $false }
    if($Weapon.ClassAffinity -eq $script:PlayerClass){ return $true }
    $sharedAffinity = switch($script:PlayerClass){
        "Berserker" { "Knight" }
        "Warlock"   { "Mage" }
        default     { $null }
    }
    if($sharedAffinity -and $Weapon.ClassAffinity -eq $sharedAffinity){ return $true }
    return $false
}

# Returns total effective weapon ATK (base + class bonus) — 0 if broken
function Get-TotalWeaponATK {
    if(-not $script:EquippedWeapon){ return 0 }
    if(Test-ItemBroken $script:EquippedWeapon){ return 0 }
    return $script:EquippedWeapon.ATK + (Get-WeaponClassBonus)
}

# Returns MAG bonus from weapon (staves grant MAG) — 0 if broken
function Get-WeaponMAGBonus {
    if(-not $script:EquippedWeapon){ return 0 }
    if(Test-ItemBroken $script:EquippedWeapon){ return 0 }
    if($script:EquippedWeapon.MAGBonus){
        return $script:EquippedWeapon.MAGBonus
    }
    return 0
}

# ─── REAL-TIME INPUT (dungeon only) ──────────────────────────────
# All keys (W/A/S/D, P, Q, arrows, etc.) register instantly — no Enter
# required. On each call the queue is drained up front so auto-repeat
# from a previously-held key doesn't cause runaway movement or menu
# double-fire.
#
# Returns an uppercase ASCII character.
function Read-DungeonKey {
    # Discard queued-up keys (stale pre-dungeon input or auto-repeat leftovers).
    Drain-Keys
    while($true){
        if($Host.UI.RawUI.KeyAvailable){
            $k = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
            # Arrow keys map to WASD
            switch($k.VirtualKeyCode){
                37 { return 'A' }
                38 { return 'W' }
                39 { return 'D' }
                40 { return 'S' }
            }
            if($k.Character -and $k.Character -ne [char]0){
                $c = [string]$k.Character
                if($c -match '^[A-Za-z0-9]$'){
                    return $c.ToUpper()
                }
            }
        }
        Start-Sleep -Milliseconds 25
    }
}

# Briefly flash a status line (used for animations without a full redraw)
function Flash-Line {
    param([int]$Row,[string]$Text,[string]$Color="White",[int]$Ms=120)
    try {
        $prevPos = $Host.UI.RawUI.CursorPosition
        $pos = New-Object System.Management.Automation.Host.Coordinates 0, $Row
        $Host.UI.RawUI.CursorPosition = $pos
        Write-Host (" " * 70) -NoNewline
        $Host.UI.RawUI.CursorPosition = $pos
        Write-Host $Text -ForegroundColor $Color -NoNewline
        Start-Sleep -Milliseconds $Ms
        $Host.UI.RawUI.CursorPosition = $prevPos
    } catch {
        # Fallback for hosts without cursor positioning
    }
}

