        @{Id="IronFist";       Name="Iron Fist";           Desc="Defeat 10 enemies bare-handed";        Gold=400; XP=300; Req="barehands:10"}
        @{Id="UntouchedRun";   Name="Untouched";           Desc="Reach a boss room above 75% HP";       Gold=200; XP=200; Req="untouched:1"}
        @{Id="StanceShifter";  Name="Stance Shifter";      Desc="Switch combat stance 25 times";        Gold=150; XP=150; Req="stanceswaps:25"}
        @{Id="TrueScholar";    Name="True Scholar";        Desc="Complete 25 quests";                   Gold=500; XP=500; Req="quests:25"}
        @{Id="GearGuru";       Name="Gear Guru";           Desc="Repair gear at the blacksmith 10 times"; Gold=150; XP=150; Req="repairs:10"}
        @{Id="HighRoller";     Name="High Roller";         Desc="Accumulate 10000 gold";                Gold=0;   XP=1000; Req="gold:10000"}
        @{Id="DeepestDive";    Name="Tireless Adventurer"; Desc="Clear 20 dungeons";                    Gold=2000; XP=1500; Req="cleared:20"}
    )
}

function Try-UnlockAchievement {
    param([string]$Id)
    if($script:Achievements.ContainsKey($Id)){ return } # already unlocked
    $list = Get-AchievementList
    $ach = $list | Where-Object { $_.Id -eq $Id } | Select-Object -First 1
    if(-not $ach){ return }
    $script:Achievements[$Id] = $true
    $script:Gold += $ach.Gold
    $script:XP   += $ach.XP
    # Queue a status message; caller will display it next redraw
    $script:StatusMsg = "ACHIEVEMENT: $($ach.Name) (+$($ach.Gold)g, +$($ach.XP)xp)"
    # Flash immediately too, so combat screens see it
    Write-Host ""
    Write-CL "  ★ ACHIEVEMENT UNLOCKED ★" "Yellow"
    Write-CL "  $($ach.Name) — $($ach.Desc)" "Yellow"
    if($ach.Gold -gt 0){ Write-CL "  +$($ach.Gold) Gold" "DarkYellow" }
    if($ach.XP   -gt 0){ Write-CL "  +$($ach.XP) XP"   "DarkCyan" }
    Start-Sleep -Milliseconds 500
}

# Called in many places to check every achievement's criteria
function Check-Achievements {
    $stats = @{
        kills        = $script:TotalKills
        bosses       = $script:BossesDefeated
        dungeon      = $script:DungeonLevel
        cleared      = $script:DungeonsCleared
        gold         = $script:Gold
        weapons      = $script:WeaponsOwned.Count
        streak       = $script:BestStreak
        training     = 0  # filled below
        quests       = $script:CompletedQuests
        daily        = if($script:DailyDungeonDone){1}else{0}
        # New v1.3 stats
        crits        = $script:TotalCrits
        lockspicked  = $script:TotalLocksPicked
        carry        = (Get-CurrentCarryWeight)
        barehands    = $script:TotalBareKills
        untouched    = $script:TotalUntouched
        stanceswaps  = $script:TotalStanceSwaps
        repairs      = $script:TotalRepairs
        encumbered   = $script:TotalEncumbered
    }
    # Training total spent is tracked as sum of TrainingPoints * baseline (approx)
    $trSum = 0
    foreach($k in $script:TrainingPoints.Keys){ $trSum += $script:TrainingPoints[$k] }
    $stats.training = $trSum * 100  # each point roughly cost 100g+

    # Armor completion
    $fullArmor = $true
    foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
        if(-not $script:EquippedArmor[$slot]){ $fullArmor = $false; break }
    }

    foreach($ach in (Get-AchievementList)){
        if($script:Achievements.ContainsKey($ach.Id)){ continue }
        $parts = $ach.Req -split ":"
        $key = $parts[0]; $val = $parts[1]
        $unlock = $false
        if($key -eq "armor" -and $val -eq "all" -and $fullArmor){ $unlock = $true }
        elseif($key -eq "event"){ continue }  # event achievements unlock explicitly
        elseif($stats.ContainsKey($key)){
            $num = [int]$val
            if($stats[$key] -ge $num){ $unlock = $true }
        }
        if($unlock){ Try-UnlockAchievement $ach.Id }
    }
}

function Get-TrainingCost {
    param([string]$Stat)
    # Each level of training costs more than the last. Caps at +10.
    $current = $script:TrainingPoints[$Stat]
    if($current -ge 10){ return -1 }  # maxed
    return 100 + ($current * 50)
}



# ─── LOOT GENERATION ─────────────────────────────────────────────
# ─── MARN'S JOURNAL (Cat 7, v2.0) ─────────────────────────────────
# The 15 found notes, rewritten as one out-of-order journal kept by
# Marn, a Guild of SysAdmins fieldwalker sent into the Depths. Pages
# 1-3, 13 and 15 are Marn's own entries; the rest are documents Marn
# pasted in, each with a margin comment. Drops (18% per chest) only
# ever offer UNCOLLECTED pages, so the set is completable. Collection
# is flag-based ($script:JournalPages, save key JN) and permanent per
# character; the paper items are just mementos. Collecting all 15
# awards Marn's Lucky Byte (+2% crit, $script:JournalCharm, key JC).
function Get-JournalPages {
    @(
        @{ Page=1; Title="Page 1 — Day 1"; Body="Day 1. The Guild handed me a map and a whetstone. Neither had documentation. I drew my own diagrams in the dirt with a stick. The stick broke. I am choosing not to read anything into that. For the record: Marn, fieldwalker third-class, Guild of SysAdmins. Tickets stopped coming back up from the Depths. Someone has to go down and close them." }
        @{ Page=2; Title="Page 2 — Day 3"; Body="Day 3. Encountered a sealed chamber. Five tumblers. The mechanism gave me an obscure error code on every failed pick. Tier 3 support told me to file a ticket. I am tier 3 support. I filed a ticket against myself. It was closed as duplicate." }
        @{ Page=3; Title="Page 3 — Day 7"; Body="Day 7. The walls down here weren't built. They were instantiated. I leaned against one and felt it allocate memory under my hand. I have not leaned against a wall since." }
        @{ Page=4; Title="Page 4 — A Pasted Contract"; Body="By descending past this point you agree to: (1) the Guild of SysAdmins is not liable for soul loss, (2) durability is not guaranteed in caustic environments, (3) the Dutchman's blade comes AS-IS with no warranty. Continue? [Y/N]. The forest does not show this prompt twice.`n`n[In the margin, Marn's hand]: I clicked Y. Obviously. Keeping this in case Legal asks." }
        @{ Page=5; Title="Page 5 — A Cleric's Prayer Card"; Body="Light eternal, hold our pointers steady. Bless our crit rolls and our retry logic. Forgive us our null references, as we forgive those who null-ref against us. May our potions be unbroken and our mana never throw OutOfMemory. Amen.`n`n[In the margin]: Found in a dead cleric's pack. It works about as often as retry logic does. I say it anyway." }
        @{ Page=6; Title="Page 6 — A Smith's Invoice"; Body="WORK ORDER #00471. Customer: Wenna of the Eastern Hills. Repair: chainmail, full set. Status: paid in advance. Customer did not return for pickup. Item stored 90 days per policy. Note: name matched grave in family plot. Refund issued to next of kin: also Wenna. We did not ask follow-up questions.`n`n[In the margin]: Pulled off a workbench on floor four. I have started checking whether people I meet down here cast shadows." }
        @{ Page=7; Title="Page 7 — A Rubbing of a Carved Tablet"; Body="HE WHO DEPLOYS TO PRODUCTION THRICE OPENS THE DOOR. We do not know which door. We have lost five climbers searching. The carving is older than the language it is written in, which sysadmins find professionally upsetting.`n`n[In the margin]: Took this rubbing on Day 16. Deploys to production. THRICE. I have deployed twice in my life and both times required counseling." }
        @{ Page=8; Title="Page 8 — A Riddle Card"; Body="I have three tongues but no mouth. Six faces but no eyes. Walk through me with nothing equipped, and I dress you. Walk through me wearing armor, and I strip you. (Answer scratched out and replaced with: 'a corrupted character creation screen.')`n`n[In the margin]: The scratched-out answer is wrong. I think the real answer is a Mimic. I am not testing this theory unequipped." }
        @{ Page=9; Title="Page 9 — A Brewmaster's Manifest"; Body="Extra Strong reds: triple the moonpetal, halve the mandrake, add a single tear shed in honest grief over a deleted production database. The grief is the active ingredient. Without it you brew colored water. With it you brew miracles. Backups not included.`n`n[In the margin]: Grief as an active ingredient. That explains why my potions taste like the night we lost the prod database." }
        @{ Page=10; Title="Page 10 — A Necromancer's TODO List"; Body="// FIXME: figure out why the dead remember their old job titles`n// FIXME: bones keep reassembling on respawn — memory leak?`n// TODO: ask Lich King about garbage collection`n// TODO: don't ask Lich King about anything ever`n`n[In the margin]: Found nailed to a door. Whoever wrote this has my exact job and worse coworkers." }
        @{ Page=11; Title="Page 11 — Halix's Map (.bak)"; Body="...third fork past the segfault, beneath the twin pillars (load-balanced), behind the stone with the chipped corner. The floor in that room runs on a tick counter. Every fifth tile is a trap. I learned the hard way. — Halix the Lost (deceased)`n`n[In the margin]: Halix mapped the tick-counter floor and it killed him anyway. Keeping the map. Deceased documentation is still documentation." }
        @{ Page=12; Title="Page 12 — The Architect's Footnote"; Body="The Depths are not a place. They are a process tree. Each floor is a child spawned by the one above. The Lich King is not at the bottom because he is the deepest. He is at the bottom because nothing has terminated him yet.`n`n[In the margin]: Found loose in an empty archive, Day 31. If the floors are a process tree, then I am not descending. I am being forked. I did not sleep after reading this one." }
        @{ Page=13; Title="Page 13 — Day 33"; Body="Day 33. Met the Flying Dutchman. Lost a coin toss because I assumed Get-Random was uniform. It is uniform. I was just unlucky. He took my falcon. I miss the falcon more than the gold. The gold I can earn back." }
        @{ Page=14; Title="Page 14 — A Letter, Returned Unopened"; Body="Aldric — DO NOT MERGE the cursed blade branch. The Dutchman's repo is forked from a deleted commit. I traced it. The commit message reads: 'fixed bug, also kills you.' Burn the map. Squash this branch. — M.`n`n[In the margin]: My own letter, back in my hands with the seal intact. Aldric never read it. I hope he burned the map anyway. I did not burn mine." }
        @{ Page=15; Title="Page 15 — The Last Entry"; Body="Day 40. I swore to keep the systems up. I did not swear to descend into the Server Halls and duel a man whose CV is older than the kingdom. But here we are. The king is on PTO. The realm is a crashed VM. A whetstone is a whetstone. If you are reading this, the journal outlived me. Good. Documentation should. Check the spine — my luck is sewn in there. It compiled more often than it had any right to. Close my tickets. — Marn" }
    )
}

# Marks a journal page as permanently collected (1-based page number).
# Returns $true if the page was NEW to the collection.
function Add-JournalPage {
    param([int]$Page)
    if(-not $script:JournalPages){ $script:JournalPages = @{} }
    if($script:JournalPages.ContainsKey($Page)){ return $false }
    $script:JournalPages[$Page] = $true
    return $true
}

# Fires the one-time completion ceremony when all pages are collected:
# the journal binds and Marn's Lucky Byte falls out of the spine.
# The charm is a pure flag (+2% crit wired into Get-PlayerCrit), never
# a bag item — so it can't be sold, dropped, or liquidated on save.
function Test-JournalComplete {
    if($script:JournalCharm){ return }
    $total = @(Get-JournalPages).Count
    if(-not $script:JournalPages -or $script:JournalPages.Count -lt $total){ return }
    $script:JournalCharm = $true
    clr
    Write-Host ""
    Write-CL "  ╔════════════════════════════════════════════════════════════╗" "DarkYellow"
    Write-CL "  ║             T H E   J O U R N A L   B I N D S              ║" "Yellow"
    Write-CL "  ╚════════════════════════════════════════════════════════════╝" "DarkYellow"
    Write-Host ""
    Write-CL "  The fifteenth page slides into place, and the loose stack" "Gray"
    Write-CL "  pulls itself together — stitching along a spine that was" "Gray"
    Write-CL "  never there before. Marn's journal is whole." "Gray"
    Write-Host ""
    Write-CL "  Something small drops out of the binding:" "Gray"
    Write-Host ""
    Write-CL "      MARN'S LUCKY BYTE" "Yellow"
    Write-CL "      A copper charm shaped like a semicolon." "DarkGray"
    Write-CL "      +2% critical hit chance, always. Weighs nothing." "Green"
    Write-CL "      It compiled more often than it had any right to." "DarkGray"
    Write-Host ""
    Wait-Enter
}

function New-RandomLoot {
    param([int]$Tier)
    $types = @("Rusty Dagger","Old Ring","Gem Shard","Goblin Ear","Bone Fragment",
               "Silver Pendant","Enchanted Dust","Wyvern Scale","Dark Shard","Ruby Chunk",
               "Golden Idol","Ancient Rune","Dragon Tooth","Shadow Gem","Demon Horn")
    $item = $types | Get-Random
    $value = (Get-Random -Min (5*$Tier) -Max (25*$Tier))
    # Per-item weight overrides — gems/rings are realistically valuable but light;
    # tooth/scale/horn/idol are bulky regardless of value.
    # NOTE: All loot items receive a +2 weight surcharge to make the
    # 90-weight hard cap meaningful — collecting many loot items
    # forces real bag-management choices.
    $baseWeight = switch($item){
        "Old Ring"        { 1 }
        "Gem Shard"       { 1 }
        "Silver Pendant"  { 1 }
        "Enchanted Dust"  { 1 }
        "Ruby Chunk"      { 2 }
        "Shadow Gem"      { 1 }
        "Ancient Rune"    { 2 }
        "Goblin Ear"      { 1 }
        "Bone Fragment"   { 2 }
        "Demon Horn"      { 4 }
        "Dragon Tooth"    { 5 }
        "Wyvern Scale"    { 4 }
        "Dark Shard"      { 2 }
        "Golden Idol"     { 6 }
        "Rusty Dagger"    { 4 }
        default           { [math]::Max(1, [math]::Ceiling($value / 30.0)) }
    }
    $weight = $baseWeight + 2
    @{ Name=$item; Value=$value; Tier=$Tier; Kind="Loot"; Weight=[int]$weight }
}

# ─── ENEMY FACTORIES ─────────────────────────────────────────────
# ─── DUNGEON SCALING ─────────────────────────────────────────────
# Enemy levels are now relative to the player's level, with floor/ceiling
# rules that vary by role and dungeon mode.
#
#   Normal dungeon, regular enemy : [PL - 4, PL + 2]
#   Normal dungeon, miniboss/boss : [PL,     PL + 2]   (never below player)
#   Daily dungeon, ALL enemies     : [PL,     PL + 2]   (always at least PL — hard mode)
#
# This makes raw "Dungeon Level" (the floor counter) only matter for ambient
# difficulty backdrop and reward scaling; combat level is anchored to the
# player so a level-15 player isn't farming level-1 dungeons trivially.
function Get-ScaledEnemyLevel {
    param(
        [int]$PlayerLevel,
        [string]$Role = "Regular",   # "Regular", "MiniBoss", "Boss"
        [bool]$IsDaily = $false
    )
    if($IsDaily){
        $minL = $PlayerLevel
        $maxL = $PlayerLevel + 2
    } elseif($Role -eq "MiniBoss" -or $Role -eq "Boss"){
        $minL = $PlayerLevel
        $maxL = $PlayerLevel + 2
    } else {
        $minL = $PlayerLevel - 4
        $maxL = $PlayerLevel + 2
    }
    if($minL -lt 1){ $minL = 1 }
    if($maxL -lt $minL){ $maxL = $minL }
    return Get-Random -Min $minL -Max ($maxL + 1)  # inclusive of $maxL
}

function New-Enemy {
    param([string]$Type,[int]$Lvl)
    # Special case: Mimic mirrors player stats and abilities
    if($Type -eq "Mimic"){
        return New-MimicEnemy $Lvl
    }
    # Base stats — slightly buffed in v1.4 so normal enemies pose a real
    # threat (was push-overs at mid/late dungeon levels).
    $b = switch ($Type) {
        "Goblin"   {@{HP=36;ATK=10;DEF=4; SPD=11;MAG=3; XP=22; G=Get-Random -Min 5  -Max 22}}
        "Zombie"   {@{HP=54;ATK=12;DEF=8; SPD=4; MAG=2; XP=33; G=Get-Random -Min 8  -Max 28}}
        "Thief"    {@{HP=30;ATK=14;DEF=5; SPD=15;MAG=4; XP=28; G=Get-Random -Min 15 -Max 45}}
        "Wizard"   {@{HP=40;ATK=6; DEF=5; SPD=9; MAG=18;XP=38; G=Get-Random -Min 10 -Max 38}}
        "Troll"    {@{HP=72;ATK=16;DEF=10;SPD=6; MAG=3; XP=50; G=Get-Random -Min 12 -Max 33}}
        "Skeleton" {@{HP=46;ATK=13;DEF=7; SPD=9; MAG=4; XP=36; G=Get-Random -Min 10 -Max 33}}
        # Themed-raid natives (Phase 6): Frostfang / Sys-V / the Woods
        "Frost Troll" {@{HP=60;ATK=14;DEF=10;SPD=3; MAG=4; XP=40; G=Get-Random -Min 12 -Max 34}}
        "Golem"       {@{HP=70;ATK=13;DEF=14;SPD=2; MAG=0; XP=44; G=Get-Random -Min 14 -Max 40}}
        "Spore Beast" {@{HP=46;ATK=12;DEF=6; SPD=6; MAG=8; XP=34; G=Get-Random -Min 8  -Max 26}}
    }
    # Per-level scale: was 0.32 in v1.3, softened to 0.28 in v1.4 — players
    # were getting walled at mid dungeons. Combat math still rewards higher
    # depth runs, just with a gentler curve.
    $s = 1+($Lvl-1)*0.28
    # Build ability list with cooldowns. Type-specific abilities now include
    # heals or self-buffs at higher levels for variety.
    $abilities = @(
        @{Name="Attack"; Power=0; Type="Normal"; Cooldown=0}
    )
    switch($Type){
        "Wizard"   {
            $abilities += @{Name="Dark Bolt"; Power=12; Type="Magic"; Cooldown=2}
            if($Lvl -ge 3){
                $abilities += @{Name="Arcane Barrier"; Power=0; Type="Buff"; Effect="DEF+4"; Cooldown=4}
            }
        }
        "Troll"    {
            $abilities += @{Name="Smash"; Power=8; Type="Physical"; Cooldown=2}
            if($Lvl -ge 4){
                $abilities += @{Name="Regenerate"; Power=15; Type="Heal"; Cooldown=5}
            }
        }
        "Thief"    {
            $abilities += @{Name="Backstab"; Power=10; Type="Physical"; Cooldown=2}
            if($Lvl -ge 3){
                $abilities += @{Name="Sharpen Blade"; Power=0; Type="Buff"; Effect="ATK+3"; Cooldown=4}
            }
        }
        "Skeleton" {
            $abilities += @{Name="Bone Throw"; Power=9; Type="Physical"; Cooldown=2}
            if($Lvl -ge 5){
                $abilities += @{Name="Marrow Knit"; Power=12; Type="Heal"; Cooldown=5}
            }
        }
        "Zombie"   {
            $abilities += @{Name="Bite"; Power=4; Type="Physical"; Cooldown=2}
            if($Lvl -ge 4){
                $abilities += @{Name="Festering Wound"; Power=0; Type="Buff"; Effect="ATK+2"; Cooldown=4}
            }
        }
        default    {
            $abilities += @{Name="Bite"; Power=4; Type="Physical"; Cooldown=2}
        }
    }
    # ── Procedural variants (v1.5) ──
    # Each enemy spawn has a 22% chance to roll a variant — a flavor name
    # plus a small stat-tweak profile. Variants don't change abilities or
    # XP value; they just nudge the feel of each fight. The Bestiary
    # tracks kills per (Type, Variant) combo so completionists can hunt
    # them down.
    $variantName = ""
    $variant = $null
    if((Get-Random -Max 100) -lt 22){
        $variants = @(
            @{Name="Frenzied"; AtkMul=1.30; DefMul=0.75; HpMul=1.00; SpdMul=1.10; Color="Red"   }
            @{Name="Armored";  AtkMul=0.85; DefMul=1.50; HpMul=1.10; SpdMul=0.90; Color="DarkGray"}
            @{Name="Hulking";  AtkMul=1.10; DefMul=1.00; HpMul=1.40; SpdMul=0.80; Color="DarkYellow"}
            @{Name="Swift";    AtkMul=0.95; DefMul=0.80; HpMul=0.85; SpdMul=1.50; Color="Cyan"  }
            @{Name="Sickly";   AtkMul=0.80; DefMul=0.80; HpMul=0.70; SpdMul=0.95; Color="DarkGreen"}
            @{Name="Brutal";   AtkMul=1.20; DefMul=0.95; HpMul=1.05; SpdMul=1.00; Color="Magenta"}
        )
        $variant = $variants | Get-Random
        $variantName = $variant.Name
    }
    $hpFinal  = [math]::Max([math]::Floor($b.HP * $s * $(if($variant){$variant.HpMul}else{1.0})), 1)
    $atkFinal = [math]::Max([math]::Floor($b.ATK * $s * $(if($variant){$variant.AtkMul}else{1.0})), 1)
    $defFinal = [math]::Max([math]::Floor($b.DEF * $s * $(if($variant){$variant.DefMul}else{1.0})), 0)
    $spdFinal = [math]::Max([math]::Floor($b.SPD * $s * $(if($variant){$variant.SpdMul}else{1.0})), 1)
    $magFinal = [math]::Max([math]::Floor($b.MAG * $s), 0)
    $displayName = if($variantName){"$variantName $Type (Lv$Lvl)"}else{"$Type (Lv$Lvl)"}

    @{ Name="$Type";DisplayName=$displayName;HP=$hpFinal;MaxHP=$hpFinal
       ATK=$atkFinal;DEF=$defFinal;SPD=$spdFinal
       MAG=$magFinal;XP=[math]::Floor($b.XP*$s);Gold=$b.G
       IsBoss=$false;IsMiniBoss=$false;Loot=(New-RandomLoot $Lvl);Stunned=$false;DropsKey=$false
       Abilities=$abilities
       Variant=$variantName
    }
}

# Mimic copies the player's class, HP, ATK/DEF/SPD/MAG and hits
# for scaled damage using the player's signature abilities.
# Displays different sprites per class via the "MimicX" keys in Get-EnemyArt.
function New-MimicEnemy {
    param([int]$Lvl)
    $p = $script:Player
    $pc = $script:PlayerClass
    # Scale slightly based on player stats — roughly 85% to feel evenly matched
    $scale = 0.85 + ($Lvl - 1) * 0.05
    if($scale -gt 1.2){ $scale = 1.2 }
    $mimicHP  = [math]::Floor($p.MaxHP * 0.85 * $scale)
    $mimicATK = [math]::Floor(($p.ATK + (Get-TotalWeaponATK)) * 0.9 * $scale)
    $mimicDEF = [math]::Floor(($p.DEF + (Get-TotalArmorDEF)) * 0.85 * $scale)
    $mimicSPD = [math]::Floor($p.SPD * 0.9)
    $mimicMAG = [math]::Floor($p.MAG * 0.9 * $scale)
    if($mimicATK -lt 5){ $mimicATK = 5 }
    if($mimicDEF -lt 3){ $mimicDEF = 3 }
    # Class-specific ability set
    $mimicAbilities = @(@{Name="Attack";Power=0;Type="Normal"})
    switch($pc){
        "Knight"      { $mimicAbilities += @{Name="Shield Bash";Power=12;Type="Physical"} }
        "Mage"        { $mimicAbilities += @{Name="Fireball";   Power=14;Type="Magic"} }
        "Brawler"     { $mimicAbilities += @{Name="Flurry";     Power=11;Type="Physical"} }
        "Ranger"      { $mimicAbilities += @{Name="Piercing Shot";Power=13;Type="Physical"} }
        "Cleric"      { $mimicAbilities += @{Name="Holy Smite"; Power=13;Type="Magic"} }
        "Necromancer" { $mimicAbilities += @{Name="Life Drain"; Power=12;Type="Magic"} }
        "Berserker"   { $mimicAbilities += @{Name="Savage Cleave";Power=16;Type="Physical"} }
        "Warlock"     { $mimicAbilities += @{Name="Eldritch Blast";Power=15;Type="Magic"} }
        default       { $mimicAbilities += @{Name="Mirror Strike";Power=10;Type="Physical"} }
    }
    # Sprite key: "MimicKnight", "MimicMage", etc. If unknown, falls back to "Mimic".
    $mimicSpriteName = "Mimic$pc"
    @{ Name=$mimicSpriteName
       DisplayName="Mimic (masquerading as $pc)"
       HP=$mimicHP; MaxHP=$mimicHP
       ATK=$mimicATK; DEF=$mimicDEF; SPD=$mimicSPD; MAG=$mimicMAG
       XP=[math]::Floor(80 * $scale)
       Gold=(Get-Random -Min 40 -Max 100)
       IsBoss=$false; IsMiniBoss=$false
       Loot=(New-RandomLoot ($Lvl+1))
       Stunned=$false; DropsKey=$false
       Revealed=$false
       Abilities=$mimicAbilities
    }
}

# Disguise check (v1.6.2): a mimic that has not yet sprung its ambush
# presents as a CHEST everywhere — world sprite, [E] label, both maps.
# $Val is a $d.Enemies value: a single enemy hashtable or a group array
# (mimics never spawn in groups, so arrays are never disguised). The
# Revealed flag flips ON FIRST CONTACT and the con is blown for good.
function Test-MimicDisguised {
    param($Val)
    if(-not $Val){ return $false }
    if($Val -is [array]){ return $false }
    if(-not $Val.Name){ return $false }
    if([string]$Val.Name -notlike "Mimic*"){ return $false }
    return (-not $Val.Revealed)
}

function New-MiniBoss {
    param([int]$Lvl)
    $names=@("Shadow Knight","Dark Shaman","Iron Golem","Venom Queen","Flame Warden","Bone Colossus","Frost Wyrm","Void Sentinel")
    $n=$names|Get-Random
    # Mini-boss base stats: slightly bumped in v1.4 so they remain a
    # threat as the player gears up. Scale rate softened from 0.32 to 0.28
    # to match normal enemies and prevent mid-game walls.
    $s = 1 + ($Lvl - 1) * 0.28
    # Equipment drops: 30% weapon, 30% armor (independent rolls). Tier scales with level.
    $weaponDrop = $null; $armorDrop = $null
    if((Get-Random -Max 100) -lt 30){
        $tierMin = [math]::Max(1, $Lvl * 30)
        $tierMax = [math]::Max(150, $Lvl * 70)
        $pool = Get-WeaponShop | Where-Object { $_.Price -ge $tierMin -and $_.Price -le $tierMax }
        if($pool.Count -gt 0){ $weaponDrop = $pool | Get-Random }
    }
    if((Get-Random -Max 100) -lt 30){
        $tierMin = [math]::Max(1, $Lvl * 25)
        $tierMax = [math]::Max(120, $Lvl * 60)
        $pool = Get-ArmorShop | Where-Object { $_.Price -ge $tierMin -and $_.Price -le $tierMax }
        if($pool.Count -gt 0){ $armorDrop = $pool | Get-Random }
    }
    @{ Name=$n;DisplayName="$n [MINI-BOSS]";HP=[math]::Floor(160*$s);MaxHP=[math]::Floor(160*$s)
       ATK=[math]::Floor(20*$s);DEF=[math]::Floor(14*$s);SPD=[math]::Floor(10*$s);MAG=[math]::Floor(13*$s)
       XP=[math]::Floor(150*$s);Gold=(Get-Random -Min 50 -Max 120)
       IsBoss=$false;IsMiniBoss=$true;Loot=(New-RandomLoot ($Lvl+1));Stunned=$false;DropsKey=$true
       WeaponDrop=$weaponDrop; ArmorDrop=$armorDrop
       Abilities=@(
           @{Name="Attack";       Power=0;  Type="Normal";   Cooldown=0}
           @{Name="Power Strike"; Power=15; Type="Physical"; Cooldown=2}
           @{Name="Dark Wave";    Power=12; Type="Magic";    Cooldown=3}
           @{Name="Iron Skin";    Power=0;  Type="Buff";     Effect="DEF+5"; Cooldown=5}
           @{Name="Blood Mend";   Power=20; Type="Heal";                    Cooldown=6}
       )
    }
}

function New-Boss {
    param([int]$Lvl)
    $names=@("Lich King","Dragon Wyrm","Demon Lord","Abyssal Horror","Undead Titan","Shadow Emperor","Plague Bringer","World Eater")
    $n=$names|Get-Random
    # Themed raid (Phase 6): the raid has ONE boss, and this is them.
    if($script:RaidTheme){ $n = $script:RaidTheme.Boss }
    # Boss tuning v1.4: substantially toned down. Was overtuned at high
    # player levels — combined with player-gear contribution at fight
    # start, bosses were dealing one-shot damage and had bullet-sponge HP.
    # Reduced base HP/ATK and softened scaling. v1.4 follow-up: scaling
    # softened further (0.28->0.24 HP, 0.24->0.20 ATK) after play feedback.
    $hpScale  = 1 + ($Lvl - 1) * 0.24
    $atkScale = 1 + ($Lvl - 1) * 0.20
    # Boss drops: 50% weapon, 50% armor — bigger tier range
    $weaponDrop = $null; $armorDrop = $null
    if((Get-Random -Max 100) -lt 50){
        $tierMin = [math]::Max(50, $Lvl * 50)
        $tierMax = [math]::Max(300, $Lvl * 120)
        $pool = Get-WeaponShop | Where-Object { $_.Price -ge $tierMin -and $_.Price -le $tierMax }
        if($pool.Count -gt 0){ $weaponDrop = $pool | Get-Random }
    }
    if((Get-Random -Max 100) -lt 50){
        $tierMin = [math]::Max(40, $Lvl * 40)
        $tierMax = [math]::Max(250, $Lvl * 100)
        $pool = Get-ArmorShop | Where-Object { $_.Price -ge $tierMin -and $_.Price -le $tierMax }
        if($pool.Count -gt 0){ $armorDrop = $pool | Get-Random }
    }
    @{ Name=$n;DisplayName=">>> $n [DUNGEON BOSS] <<<";HP=[math]::Floor(231*$hpScale);MaxHP=[math]::Floor(231*$hpScale)
       ATK=[math]::Floor(22*$atkScale);DEF=[math]::Floor(14*$hpScale);SPD=[math]::Floor(11*$atkScale);MAG=[math]::Floor(14*$atkScale)
       XP=[math]::Floor(400*$hpScale);Gold=(Get-Random -Min 100 -Max 250) + $Lvl * 40
       IsBoss=$true;IsMiniBoss=$false;Loot=(New-RandomLoot ($Lvl+2));Stunned=$false;DropsKey=$false
       WeaponDrop=$weaponDrop; ArmorDrop=$armorDrop
       # Telegraph: $TelegraphNext flags that next turn a big move is coming, giving player a chance to defend.
       TelegraphNext=$false
       Abilities=@(
           @{Name="Attack";        Power=0;  Type="Normal";   Cooldown=0}
           @{Name="Devastate";     Power=20; Type="Physical"; Cooldown=3}
           @{Name="Soul Drain";    Power=18; Type="Magic";    Cooldown=3}
           @{Name="Inferno";       Power=25; Type="Magic";    Cooldown=4}
           @{Name="Boss Roar";     Power=0;  Type="Buff";     Effect="ATK+6"; Cooldown=5}
           @{Name="Dark Mending";  Power=30; Type="Heal";                    Cooldown=7}
       )
    }
}

# ─── DUNGEON GENERATION ──────────────────────────────────────────
# ── Support enemies (Phase 2): group-only specialists ──
# Built on a regular enemy chassis, then specialized. Shamans heal the
# most-wounded group member; Commanders buff the whole pack's DEF.
# Both are squishier than their base type — killing the support first
# is the intended tactical answer. Only spawned inside groups.
function New-SupportEnemy {
    param([int]$Lvl)
    if((Get-Random -Max 2) -eq 0){
        $s = New-Enemy "Goblin" $Lvl
        $s.Name        = "Goblin Shaman"
        $s.DisplayName = "Goblin Shaman"
        $s.ArtType     = "Goblin"
        $s.Role        = "Shaman"
        $s.MAG         = [int]$s.MAG + 6
        $s.HP          = [math]::Max([math]::Floor($s.HP * 0.75), 1)
        $s.MaxHP       = [math]::Max([math]::Floor($s.MaxHP * 0.75), 1)
        $s.Abilities   = @(
            @{Name="Attack";     Power=0;  Type="Normal"; Cooldown=0}
            @{Name="Mend Kin";   Power=16; Type="Heal";   Cooldown=2}
            @{Name="Hex Spark";  Power=10; Type="Magic";  Cooldown=2}
        )
        return $s
    } else {
        $s = New-Enemy "Skeleton" $Lvl
        $s.Name        = "Skeleton Commander"
        $s.DisplayName = "Skeleton Commander"
        $s.ArtType     = "Skeleton"
        $s.Role        = "Commander"
        $s.HP          = [math]::Max([math]::Floor($s.HP * 0.85), 1)
        $s.MaxHP       = [math]::Max([math]::Floor($s.MaxHP * 0.85), 1)
        $s.Abilities   = @(
            @{Name="Attack";      Power=0; Type="Normal"; Cooldown=0}
            @{Name="Bone Rally";  Power=0; Type="Buff"; Effect="DEF+5"; Cooldown=3}
            @{Name="Bone Throw";  Power=9; Type="Physical"; Cooldown=2}
        )
        return $s
    }
}

# ── THEMED ZONES (Phase 3, Cat 4) ─────────────────────────────────
# The Depths tell the story of a system falling into chaos as the
# player descends. Every 5 dungeon levels is a distinct zone with its
# own look, ambient quirk, and enemy variants.
function Get-DungeonZone {
    param([int]$Level)
    if($Level -le 5){
        return @{
            Id="ServerHalls"; Name="The Server Halls"
            Color="Gray"; EdgeColor="White"
            Desc1="Clean, cold stone. Faint fluorescent hum overhead."
            Desc2="The upper level of the system. Everything still (mostly) works."
            VariantPool=@()   # baseline zone — no zone variants
        }
    } elseif($Level -le 10){
        return @{
            Id="Flooded"; Name="The Flooded Data-Center"
            Color="Cyan"; EdgeColor="Cyan"
            Desc1="Ankle-deep glowing coolant. The air hums with failing pumps."
            Desc2="Somewhere below, something big is leaking."
            VariantPool=@("Corroded","Short-Circuited","Waterlogged")
        }
    } elseif($Level -le 15){
        return @{
            Id="Archives"; Name="The Overgrown Archives"
            Color="DarkGreen"; EdgeColor="DarkGreen"
            Desc1="Thick pulsating cables hang like vines. The air is thick with spores."
            Desc2="Biology has opinions about your presence here."
            VariantPool=@("Fungal","Sporeback","Parasitic")
        }
    } else {
        return @{
            Id="Core"; Name="The Core Meltdown"
            Color="Red"; EdgeColor="DarkRed"
            Desc1="Oppressive heat. Glowing cracks vein the floor."
            Desc2="A constant low hum you feel in your teeth. The heart of the failure."
            VariantPool=@("Molten","Overclocked","Irradiated")
        }
    }
}

# Applies a zone-flavored variant to a freshly spawned REGULAR enemy:
# ~30% chance to prefix the name (feeding the existing bestiary
# Name~Variant dimension) with a small stat nudge per zone family.
# Bosses/mini-bosses/supports are exempt — they have their own identity.
function Apply-ZoneVariant {
    param($Enemy, $Zone)
    if(-not $Enemy -or -not $Zone){ return $Enemy }
    if($Enemy.IsBoss -or $Enemy.IsMiniBoss -or $Enemy.Role){ return $Enemy }
    if(-not $Zone.VariantPool -or $Zone.VariantPool.Count -eq 0){ return $Enemy }
    if((Get-Random -Max 100) -ge (Get-CorruptionVariantChance)){ return $Enemy }
    # Don't stack zone variants on top of a procedural variant — one
    # adjective per goblin is plenty.
    if($Enemy.Variant){ return $Enemy }
    $zv = $Zone.VariantPool | Get-Random
    $Enemy.Variant     = $zv
    $Enemy.DisplayName = "$zv $($Enemy.Name)"
    switch($zv){
        "Corroded"        { $Enemy.DEF = [math]::Max($Enemy.DEF - 2, 1); $Enemy.HP += 8; $Enemy.MaxHP += 8 }
        "Short-Circuited" { $Enemy.SPD += 3 }
        "Waterlogged"     { $Enemy.SPD = [math]::Max($Enemy.SPD - 2, 1); $Enemy.HP += 12; $Enemy.MaxHP += 12 }
        "Fungal"          { $Enemy.HP += 10; $Enemy.MaxHP += 10 }
        "Sporeback"       { $Enemy.MAG += 4 }
        "Parasitic"       { $Enemy.ATK += 2 }
        "Molten"          { $Enemy.ATK += 3 }
        "Overclocked"     { $Enemy.SPD += 4 }
        "Irradiated"      { $Enemy.MAG += 5; $Enemy.DEF = [math]::Max($Enemy.DEF - 1, 1) }
    }
    return $Enemy
}

# ── Phase 3: room-effect + lore helpers ──────────────────────────
# Returns the ambient effect of the room the player currently stands
# in ("Flooded" / "Charged"), or $null in corridors / plain rooms.
function Get-ActiveRoomEffect {
    param($d)
    if(-not $d -or -not $d.Rooms){ return $null }
    foreach($r in $d.Rooms){
        if($r.Effect -and $d.PX -ge $r.X -and $d.PX -lt ($r.X + $r.W) -and
           $d.PY -ge $r.Y -and $d.PY -lt ($r.Y + $r.H)){
            return $r.Effect
        }
    }
    return $null
}

# Lore text pools for interactive objects (Cat 5). Terminals and
# bookshelves are pure SysAdmin-humor flavor; Effigies whisper cryptic
# but TRUE hints about real game systems.
function Get-LoreText {
    param([string]$Type)
    switch($Type){
        "Terminal" {
            @(
                "LOG 4471: backup job 'FINAL_BACKUP_v2_REALFINAL' failed. Retrying forever."
                "MOTD: The dungeon is a flat circle. Have you tried turning it off and on again?"
                "ALERT: 99,847 unread tickets. Estimated resolution: heat death of the universe."
                "> whoami`n  root. Everything down here answers to root. Except the boss."
                "uptime: 11,842 days. Nobody has patched me. Nobody will."
            ) | Get-Random
        }
        "Bookshelf" {
            @(
                "'Networking for Necromancers' — spine cracked at the chapter on dead links."
                "'The Art of the Graceful Shutdown' — clearly never read."
                "'1001 Uses For A Broken Keyboard' — someone underlined 'weapon.'"
                "'Error Handling: A Memoir' — every page just says try/catch in shaky ink."
                "'Recursion for Beginners' — the whole text reads: see Recursion for Beginners."
            ) | Get-Random
        }
        "Effigy" {
            @(
                "'Some chests bite. Watch for the ones that breathe.'"
                "'The deepest doors open to those who clear five-and-twenty halls.'"
                "'A process with no parent wanders these depths, hunting the streak-blessed.'"
                "'Feed the pot at the lantern. Strength comes from strange soup.'"
                "'The Dutchman's dice favor no one. His blade remembers its price.'"
            ) | Get-Random
        }
        default { "Dust. Just dust." }
    }
}

# ─── SYSADMIN VOICE (Cat 6, v2.0) ──────────────────────────────────
# Light-touch humor pass, per the locked design decision: NEW one-line
# quips at the four highest-visibility moments only (fight start,
# victory, player death, boss defeat). No existing text was rewritten.
# All lines render DarkGray so they season the moment, not steal it.
function Get-EnemyIntroQuip {
    param($En)
    # Support specialists get their own lines (Role checked first);
    # everything else keys on Name, which stays stable under variants.
    if($En.Role -eq "Shaman"){
        return @(
            "A healer. Kill the healer first. Everyone knows this."
            "It keeps the pack's uptime at five nines."
        ) | Get-Random
    }
    if($En.Role -eq "Commander"){
        return @(
            "Middle management, but with a sword."
            "It buffs the team and contributes nothing itself."
        ) | Get-Random
    }
    # Mimics are named "Mimic<Class>" (e.g. MimicKnight) — prefix match.
    if($En.Name -like "Mimic*"){
        return @(
            "The chest was a phishing attempt."
            "Always verify before you click, adventurer."
        ) | Get-Random
    }
    # Regular enemies store their type in Name ("Goblin", "Zombie"...);
    # zone/procedural variants only change DisplayName, so Name is a
    # stable key here.
    switch($En.Name){
        "Goblin"   { @(
            "It has the energy of an unread ticket queue."
            "Small, loud, and multiplying — like alerts at 3 AM."
        ) | Get-Random }
        "Zombie"   { @(
            "A process that should have terminated long ago."
            "It shambles like a service stuck in 'stopping'."
        ) | Get-Random }
        "Thief"    { @(
            "It's here for your credentials."
            "Somewhere, a security audit just failed."
        ) | Get-Random }
        "Wizard"   { @(
            "It knows regex. Be careful."
            "It casts from documentation you've never read."
        ) | Get-Random }
        "Troll"    { @(
            "Do not feed it. Do not reply to it."
            "It has opinions about your uptime."
        ) | Get-Random }
        "Skeleton" { @(
            "Legacy hardware. Still in production."
            "No flesh, no fear, no patch schedule."
        ) | Get-Random }
        "Frost Troll" { @(
            "Cold storage, but it walks."
            "It has been buffering since the Second Age."
        ) | Get-Random }
        "Golem"       { @(
            "It never got the shutdown order. It never will."
            "Hardware from before warranties. Or mercy."
        ) | Get-Random }
        "Spore Beast" { @(
            "It spreads faster than a bad config."
            "Do not inhale the release notes."
        ) | Get-Random }
        default    { "It does not appear in any documentation." }
    }
}

function Get-PackIntroQuip {
    @(
        "A whole incident response team, but for the other side."
        "Multiple alerts firing at once. Classic."
        "They've formed a standup. You are the blocker."
    ) | Get-Random
}

function Get-VictoryQuip {
    @(
        "Ticket closed."
        "Resolved: will not fix. (Fixed with sword.)"
        "Uptime restored."
        "Process terminated. Gracefully is a strong word."
        "Incident post-mortemed. Literally."
        "Marked as duplicate of a previous corpse."
        "Rollback successful."
        "The queue is one shorter."
    ) | Get-Random
}

function Get-DeathQuip {
    @(
        "Have you tried turning yourself off and on again?"
        "Root cause analysis: sword-shaped."
        "Your session has expired."
        "Fatal error. In the traditional sense."
        "The Guild will file this under 'known issues'."
    ) | Get-Random
}

function Get-BossDefeatQuip {
    @(
        "The parent process has been terminated."
        "Change approved. Deployed. Permanent."
        "Escalation complete. There is no tier above you here."
    ) | Get-Random
}

function New-Dungeon {
    param([int]$Level, [int]$GenTry = 0)
    # Themed zone for this dungeon (Phase 3) — drives banner, renderer
    # tint, ambient effects, and enemy variants below.
    $zone = Get-DungeonZone $Level
    # Themed raid (Phase 6): the theme supplies the zone identity —
    # a non-Core Id also keeps the Meltdown heat tick out of raids.
    if($script:RaidTheme){
        $zone = @{ Id=$script:RaidTheme.Id; Name=$script:RaidTheme.DName; Color=$script:RaidTheme.Color
                   Desc1=$script:RaidTheme.Desc1; Desc2=$script:RaidTheme.Desc2 }
    }
    $w=41; $h=41
    $grid = New-Object 'int[,]' $h,$w
    for($y=0;$y -lt $h;$y++){for($x=0;$x -lt $w;$x++){$grid[$y,$x]=1}}

    # Generate rooms
    $rooms=[System.Collections.ArrayList]@()
    $att=0; $target=14+[math]::Min($Level,6)
    while($rooms.Count -lt $target -and $att -lt 800){
        $att++
        $rw=Get-Random -Min 3 -Max 9; $rh=Get-Random -Min 3 -Max 7
        $rx=Get-Random -Min 1 -Max ($w-$rw-1); $ry=Get-Random -Min 1 -Max ($h-$rh-1)
        $ok=$true
        foreach($r in $rooms){
            if($rx -lt ($r.X+$r.W+1) -and ($rx+$rw) -gt ($r.X-1) -and
               $ry -lt ($r.Y+$r.H+1) -and ($ry+$rh) -gt ($r.Y-1)){$ok=$false;break}
        }
        if(-not $ok){continue}
        for($y=$ry;$y -lt ($ry+$rh);$y++){for($x=$rx;$x -lt ($rx+$rw);$x++){$grid[$y,$x]=0}}
        [void]$rooms.Add(@{X=$rx;Y=$ry;W=$rw;H=$rh;CX=[math]::Floor($rx+$rw/2);CY=[math]::Floor($ry+$rh/2)})
    }

    # Connect rooms with corridors
    for($i=0;$i -lt $rooms.Count-1;$i++){
        $a=$rooms[$i];$b=$rooms[$i+1]
        $cx=$a.CX;$cy=$a.CY;$tx=$b.CX;$ty=$b.CY
        if((Get-Random -Max 2)-eq 0){
            while($cx-ne $tx){$grid[$cy,$cx]=0;$cx+=if($tx-gt $cx){1}else{-1}}
            while($cy-ne $ty){$grid[$cy,$cx]=0;$cy+=if($ty-gt $cy){1}else{-1}}
        }else{
            while($cy-ne $ty){$grid[$cy,$cx]=0;$cy+=if($ty-gt $cy){1}else{-1}}
            while($cx-ne $tx){$grid[$cy,$cx]=0;$cx+=if($tx-gt $cx){1}else{-1}}
        }
        $grid[$ty,$tx]=0
    }
    # Loop corridors (v1.6): the 41x41 floors are too big to stay a
    # single chain — punch 2-3 extra connections between random
    # non-adjacent rooms. The BOSS room (last) is never an endpoint,
    # so its ring stays a controlled, door-sealed border.
    if($rooms.Count -ge 5){
        $loops = Get-Random -Min 2 -Max 4
        for($lc=0; $lc -lt $loops; $lc++){
            $ia = Get-Random -Min 0 -Max ($rooms.Count-1)
            $ib = Get-Random -Min 0 -Max ($rooms.Count-1)
            if($ia -eq $ib -or [math]::Abs($ia-$ib) -eq 1){ continue }
            $a=$rooms[$ia];$b=$rooms[$ib]
            $cx=$a.CX;$cy=$a.CY;$tx=$b.CX;$ty=$b.CY
            if((Get-Random -Max 2)-eq 0){
                while($cx-ne $tx){$grid[$cy,$cx]=0;$cx+=if($tx-gt $cx){1}else{-1}}
                while($cy-ne $ty){$grid[$cy,$cx]=0;$cy+=if($ty-gt $cy){1}else{-1}}
            }else{
                while($cy-ne $ty){$grid[$cy,$cx]=0;$cy+=if($ty-gt $cy){1}else{-1}}
                while($cx-ne $tx){$grid[$cy,$cx]=0;$cx+=if($tx-gt $cx){1}else{-1}}
            }
            $grid[$ty,$tx]=0
        }
    }

    # Place entities  (0=floor,1=wall,2=enemy,3=miniboss,4=boss door,
    # 5=exit,6=treasure,10=sliding door,11=BOSS)
    # Weighted enemy pool: Skeleton is mid-rare, Mimic is rare (shows up ~once per dungeon)
    $eTypes=@("Goblin","Goblin","Zombie","Zombie","Thief","Wizard","Troll","Skeleton","Skeleton")
    # Themed raid (Phase 6): the natives own the spawn table.
    if($script:RaidTheme){ $eTypes = @($script:RaidTheme.Types) }
    # Mimic has a chance to spawn per dungeon (small), added separately below
    $enemies=@{}
    for($i=1;$i -lt [math]::Max($rooms.Count-2,1);$i++){
        $r=$rooms[$i]; $ne=Get-Random -Min 1 -Max 4
        for($e=0;$e -lt $ne;$e++){
            $ex=Get-Random -Min $r.X -Max ($r.X+$r.W)
            $ey=Get-Random -Min $r.Y -Max ($r.Y+$r.H)
            if($grid[$ey,$ex]-eq 0){
                $grid[$ey,$ex]=2
                # Use scaled level relative to player, not raw dungeon floor
                $spawnLvl = Get-ScaledEnemyLevel -PlayerLevel $script:PlayerLevel -Role "Regular" -IsDaily $script:DailyDungeonActive
                # ~5% chance this slot is a Mimic instead of a regular enemy
                if((Get-Random -Max 100) -lt 5){
                    $enemies["$ex,$ey"]=New-Enemy "Mimic" $spawnLvl
                } elseif((Get-Random -Max 100) -lt (Get-CorruptionGroupChance)){
                    # ── Group spawn (Phase 2): 2-3 enemies on one tile ──
                    # 40%+ (corruption-scaled) include a support specialist (Shaman
                    # or Commander) as the final member — the tactical
                    # "kill the healer first" puzzle from the design doc.
                    $groupSize = Get-Random -Min 2 -Max 4     # 2 or 3 (Max exclusive)
                    # v1.6.2: packs of FOUR exist only in a deeply
                    # corrupted world (70+), and even then rarely.
                    if($script:Corruption -ge 70 -and (Get-Random -Max 100) -lt 25){ $groupSize = 4 }
                    $pack = @()
                    for($gm = 0; $gm -lt $groupSize; $gm++){
                        $isLast = ($gm -eq ($groupSize - 1))
                        if($isLast -and (Get-Random -Max 100) -lt (Get-CorruptionSupportChance)){
                            $pack += (New-SupportEnemy $spawnLvl)
                        } else {
                            $pack += (Apply-ZoneVariant (New-Enemy (Get-EventBiasedType $eTypes) $spawnLvl) $zone)
                        }
                    }
                    $enemies["$ex,$ey"] = $pack
                } else {
                    $enemies["$ex,$ey"] = Apply-ZoneVariant (New-Enemy (Get-EventBiasedType $eTypes) $spawnLvl) $zone
                }
            }
        }
        if((Get-Random -Max 100)-lt 40){
            $tx2=Get-Random -Min $r.X -Max ($r.X+$r.W)
            $ty2=Get-Random -Min $r.Y -Max ($r.Y+$r.H)
            if($grid[$ty2,$tx2]-eq 0){$grid[$ty2,$tx2]=6}
        }
    }

    # ── Phase 3: hazard/boon rooms, Ancient Altar, lore objects ──
    # Room effects: up to 2 middle rooms get an ambient effect that the
    # player feels while standing anywhere inside the room.
    #   Flooded — SPD -3 in combat (slog through coolant)
    #   Charged — magic damage +20% BOTH ways, +1 MP per step
    $fxAssigned = 0
    for($ri=1; $ri -lt [math]::Max($rooms.Count-2,1) -and $fxAssigned -lt 3; $ri++){
        if((Get-Random -Max 100) -lt 25){
            $rooms[$ri].Effect = @("Flooded","Charged") | Get-Random
            $fxAssigned++
        }
    }
    # Ancient Altar: 35% of dungeons hide one in a middle room (cell 8).
    # One prayer per altar — blessing, silence, or a toll.
    $loreObjects = @{}
    if($rooms.Count -ge 4 -and (Get-Random -Max 100) -lt 35){
        $ar = $rooms[(Get-Random -Min 1 -Max ($rooms.Count-2))]
        for($atry=0;$atry -lt 8;$atry++){
            $ax=Get-Random -Min $ar.X -Max ($ar.X+$ar.W)
            $ay=Get-Random -Min $ar.Y -Max ($ar.Y+$ar.H)
            if($grid[$ay,$ax] -eq 0){ $grid[$ay,$ax]=8; break }
        }
    }
    # Lore objects: 1-2 per dungeon (cell 9) — Terminal / Bookshelf /
    # Effigy. Read once, then they crumble (cell reverts to floor).
    $loreCount = Get-Random -Min 2 -Max 4
    for($li=0;$li -lt $loreCount;$li++){
        if($rooms.Count -lt 4){ break }
        $lr = $rooms[(Get-Random -Min 1 -Max ($rooms.Count-2))]
        for($ltry=0;$ltry -lt 8;$ltry++){
            $lox=Get-Random -Min $lr.X -Max ($lr.X+$lr.W)
            $loy=Get-Random -Min $lr.Y -Max ($lr.Y+$lr.H)
            if($grid[$loy,$lox] -eq 0){
                $grid[$loy,$lox]=9
                $loreObjects["$lox,$loy"] = @{ Type = (@("Terminal","Bookshelf","Effigy") | Get-Random) }
                break
            }
        }
    }

    # Mini-boss in second-to-last room
    if($rooms.Count -ge 3){
        $mbR=$rooms[$rooms.Count-2]; $grid[$mbR.CY,$mbR.CX]=3
        $mbLvl = Get-ScaledEnemyLevel -PlayerLevel $script:PlayerLevel -Role "MiniBoss" -IsDaily $script:DailyDungeonActive
        $mbSpawn = New-MiniBoss $mbLvl
        # Goblin Horde (Cat 12): the WARCHIEF leads from the front —
        # this floor's miniboss is him, +15% stats, 200g bounty riding
        # the corpse. Not in themed raids (the Horde is a Depths thing).
        if((Get-ActiveRadiantEvent) -eq "GoblinHorde" -and -not $script:RaidTheme){
            $mbSpawn.Name  = "Goblin Warchief"
            $mbSpawn.HP    = [math]::Floor($mbSpawn.HP * 1.15)
            $mbSpawn.MaxHP = $mbSpawn.HP
            $mbSpawn.ATK   = [math]::Floor($mbSpawn.ATK * 1.15)
            $mbSpawn.Gold  = [int]$mbSpawn.Gold + 200
        }
        $enemies["$($mbR.CX),$($mbR.CY)"]=$mbSpawn
    }
    # Boss room (v1.6): the last room is SEALED. The boss itself is a
    # tile of its own (cell 11) at the room's center; every carved
    # floor tile on the one-tile ring around the room rectangle is an
    # entrance and becomes a locked RED boss door (cell 4).
    $bR=$rooms[$rooms.Count-1]; $grid[$bR.CY,$bR.CX]=11
    $bossLvl = Get-ScaledEnemyLevel -PlayerLevel $script:PlayerLevel -Role "Boss" -IsDaily $script:DailyDungeonActive
    $enemies["$($bR.CX),$($bR.CY)"]=New-Boss $bossLvl
    for($bdy=$bR.Y-1; $bdy -le ($bR.Y+$bR.H); $bdy++){
        for($bdx=$bR.X-1; $bdx -le ($bR.X+$bR.W); $bdx++){
            $onRing = ($bdy -eq ($bR.Y-1) -or $bdy -eq ($bR.Y+$bR.H) -or $bdx -eq ($bR.X-1) -or $bdx -eq ($bR.X+$bR.W))
            if(-not $onRing){ continue }
            if($bdx -lt 0 -or $bdx -ge $w -or $bdy -lt 0 -or $bdy -ge $h){ continue }
            if($grid[$bdy,$bdx] -ne 0){ continue }
            # Genuine entrance only (v1.6.1): the tile must touch the
            # room interior ORTHOGONALLY. Ring corners are diagonal —
            # a corridor clipping a corner is not a way in, and both
            # movement modes are 4-directional at the tile level, so
            # skipping corners cannot breach the seal.
            $bInRoom = $false
            foreach($nb in @(@(0,-1),@(0,1),@(-1,0),@(1,0))){
                $nbx = $bdx + $nb[0]; $nby = $bdy + $nb[1]
                if($nbx -ge $bR.X -and $nbx -lt ($bR.X+$bR.W) -and $nby -ge $bR.Y -and $nby -lt ($bR.Y+$bR.H)){ $bInRoom = $true; break }
            }
            if($bInRoom){ $grid[$bdy,$bdx] = 4 }
        }
    }
    # Door-run collapse (v1.6.2): a corridor carved flush along the
    # ring makes EVERY tile of that segment a genuine entrance — the
    # map ends up with a picket line of 4-5 red doors. A locked boss
    # door blocks movement exactly like wall (Get-Cell treats 4 as 1),
    # so thinning the line changes nothing pre-key: each run of
    # adjacent doors keeps ONE (preferring a tile that still touches
    # passable floor OUTSIDE the room, so the survivor stays
    # approachable) and the rest become wall. A run with no such tile
    # is left alone — current behavior, provably safe.
    $bdSides = @(
        @{ Fixed=($bR.Y-1);     FMin=$bR.X; FMax=($bR.X+$bR.W-1); Horiz=$true  },
        @{ Fixed=($bR.Y+$bR.H); FMin=$bR.X; FMax=($bR.X+$bR.W-1); Horiz=$true  },
        @{ Fixed=($bR.X-1);     FMin=$bR.Y; FMax=($bR.Y+$bR.H-1); Horiz=$false },
        @{ Fixed=($bR.X+$bR.W); FMin=$bR.Y; FMax=($bR.Y+$bR.H-1); Horiz=$false }
    )
    foreach($sd in $bdSides){
        $bdRun = [System.Collections.ArrayList]@()
        for($fi=$sd.FMin; $fi -le ($sd.FMax+1); $fi++){
            $isDoor = $false
            $rcx = 0; $rcy = 0
            if($fi -le $sd.FMax){
                if($sd.Horiz){ $rcx = $fi; $rcy = $sd.Fixed } else { $rcx = $sd.Fixed; $rcy = $fi }
                if($rcx -ge 0 -and $rcx -lt $w -and $rcy -ge 0 -and $rcy -lt $h){
                    if($grid[$rcy,$rcx] -eq 4){ $isDoor = $true }
                }
            }
            if($isDoor){
                [void]$bdRun.Add(@($rcx,$rcy))
                continue
            }
            if($bdRun.Count -ge 2){
                # Keeper preference: run ENDS first (a continuing
                # corridor keeps feeding them), then interior tiles.
                $order = @(0, ($bdRun.Count-1)) + @(1..($bdRun.Count-2))
                $keep = -1
                foreach($oi in $order){
                    $kx = [int]$bdRun[$oi][0]; $ky = [int]$bdRun[$oi][1]
                    foreach($nb in @(@(0,-1),@(0,1),@(-1,0),@(1,0))){
                        $nbx = $kx + $nb[0]; $nby = $ky + $nb[1]
                        if($nbx -lt 0 -or $nbx -ge $w -or $nby -lt 0 -or $nby -ge $h){ continue }
                        # Must touch passable floor OUTSIDE the room
                        # (not wall, not another sealed door, not the
                        # interior it opens into).
                        if($nbx -ge $bR.X -and $nbx -lt ($bR.X+$bR.W) -and $nby -ge $bR.Y -and $nby -lt ($bR.Y+$bR.H)){ continue }
                        $nbv = $grid[$nby,$nbx]
                        if($nbv -ne 1 -and $nbv -ne 4){ $keep = $oi; break }
                    }
                    if($keep -ge 0){ break }
                }
                if($keep -ge 0){
                    for($ri=0; $ri -lt $bdRun.Count; $ri++){
                        if($ri -eq $keep){ continue }
                        $wx = [int]$bdRun[$ri][0]; $wy = [int]$bdRun[$ri][1]
                        $grid[$wy,$wx] = 1
                    }
                }
            }
            if($bdRun.Count -gt 0){ $bdRun = [System.Collections.ArrayList]@() }
        }
    }
    # Exit
    $placed=$false
    for($y=$bR.Y;$y -lt $bR.Y+$bR.H -and !$placed;$y++){
        for($x=$bR.X;$x -lt $bR.X+$bR.W -and !$placed;$x++){
            if($grid[$y,$x]-eq 0){$grid[$y,$x]=5;$placed=$true}
        }
    }

        # Place rescue NPC if player has an active Rescue quest
    $hasRescueQuest = $false
    foreach($q in $script:Quests){
        if($q.Type -eq "Rescue" -and -not $q.Complete -and -not $q.TurnedIn){
            $hasRescueQuest = $true; break
        }
    }
    if($hasRescueQuest -and $rooms.Count -ge 3){
        $rescueRoom = $rooms[(Get-Random -Min 1 -Max ($rooms.Count - 2))]
        $rx2 = Get-Random -Min $rescueRoom.X -Max ($rescueRoom.X + $rescueRoom.W)
        $ry2 = Get-Random -Min $rescueRoom.Y -Max ($rescueRoom.Y + $rescueRoom.H)
        if($grid[$ry2,$rx2] -eq 0){
            $grid[$ry2,$rx2] = 7
        }
    }

    # Sliding doors (v1.6.1 rework): doors are GATES, not decoration.
    # Pick 2-3 rooms that actually HOLD something (enemies, chest,
    # survivor, altar, lore) and seal every genuine entrance of those
    # rooms — opening a door reveals a meaningful pocket of the
    # dungeon (an idol and its guards, a hoard, a captive). The start
    # room and the boss room (which has its own RED seal) are never
    # gated, and a door is only placed on a tile that touches the
    # room interior orthogonally — no doors to nowhere.
    $gateTarget = Get-Random -Min 2 -Max 4
    $gateCandidates = [System.Collections.ArrayList]@()
    for($gri=1; $gri -lt ($rooms.Count-1); $gri++){
        $gr = $rooms[$gri]
        $hasStuff = $false
        for($gy=$gr.Y; $gy -lt ($gr.Y+$gr.H) -and -not $hasStuff; $gy++){
            for($gx=$gr.X; $gx -lt ($gr.X+$gr.W) -and -not $hasStuff; $gx++){
                $gv = $grid[$gy,$gx]
                if($gv -eq 2 -or $gv -eq 3 -or $gv -eq 6 -or $gv -eq 7 -or $gv -eq 8 -or $gv -eq 9){ $hasStuff = $true }
            }
        }
        if($hasStuff){ [void]$gateCandidates.Add($gri) }
    }
    $gatePicks = @($gateCandidates | Sort-Object { Get-Random } | Select-Object -First $gateTarget)
    foreach($gpi in $gatePicks){
        $dr = $rooms[$gpi]
        for($ddy=$dr.Y-1; $ddy -le ($dr.Y+$dr.H); $ddy++){
            for($ddx=$dr.X-1; $ddx -le ($dr.X+$dr.W); $ddx++){
                $onRing = ($ddy -eq ($dr.Y-1) -or $ddy -eq ($dr.Y+$dr.H) -or $ddx -eq ($dr.X-1) -or $ddx -eq ($dr.X+$dr.W))
                if(-not $onRing){ continue }
                if($ddx -lt 0 -or $ddx -ge $w -or $ddy -lt 0 -or $ddy -ge $h){ continue }
                if($grid[$ddy,$ddx] -ne 0){ continue }
                $dInRoom = $false
                foreach($nb in @(@(0,-1),@(0,1),@(-1,0),@(1,0))){
                    $nbx = $ddx + $nb[0]; $nby = $ddy + $nb[1]
                    if($nbx -ge $dr.X -and $nbx -lt ($dr.X+$dr.W) -and $nby -ge $dr.Y -and $nby -lt ($dr.Y+$dr.H)){ $dInRoom = $true; break }
                }
                if(-not $dInRoom){ continue }
                $adjDoor = $false
                foreach($nb in @(@(0,-1),@(0,1),@(-1,0),@(1,0))){
                    $nbx = $ddx + $nb[0]; $nby = $ddy + $nb[1]
                    if($nbx -lt 0 -or $nbx -ge $w -or $nby -lt 0 -or $nby -ge $h){ continue }
                    $nbv = $grid[$nby,$nbx]
                    if($nbv -eq 10 -or $nbv -eq 4){ $adjDoor = $true; break }
                }
                if(-not $adjDoor){ $grid[$ddy,$ddx] = 10 }
            }
        }
    }

    # ── Doorway sanity sweep (v1.6.2) ── a gate door must BE a
    # doorway: exactly two passable orthogonal neighbors, on
    # OPPOSITE sides (room on one, approach on the other).
    # Corridors carved along a ring produce door-gap-door runs and
    # doors whose far side is bare wall ("doors to nothing"), and
    # rooms one tile apart can leave a door standing in what reads
    # as open floor. Any brown door failing the shape test reverts
    # to floor — always safe, brown doors are freely passable.
    for($sy=0; $sy -lt $h; $sy++){
        for($sx=0; $sx -lt $w; $sx++){
            if($grid[$sy,$sx] -ne 10){ continue }
            $pN = ($sy -gt 0      -and $grid[($sy-1),$sx] -ne 1 -and $grid[($sy-1),$sx] -ne 4)
            $pS = ($sy -lt ($h-1) -and $grid[($sy+1),$sx] -ne 1 -and $grid[($sy+1),$sx] -ne 4)
            $pW = ($sx -gt 0      -and $grid[$sy,($sx-1)] -ne 1 -and $grid[$sy,($sx-1)] -ne 4)
            $pE = ($sx -lt ($w-1) -and $grid[$sy,($sx+1)] -ne 1 -and $grid[$sy,($sx+1)] -ne 4)
            $pCount = 0
            foreach($pv in @($pN,$pS,$pW,$pE)){ if($pv){ $pCount++ } }
            if(-not ($pCount -eq 2 -and (($pN -and $pS) -or ($pW -and $pE)))){
                $grid[$sy,$sx] = 0
            }
        }
    }

    $startR=$rooms[0]
    # ── Connectivity guarantee (v1.6.2) ── corridors are carved
    # center to center and can cut straight THROUGH the boss room;
    # the seal then turns both crossing points into locked doors,
    # and any region whose only route ran through that room is
    # boxed in — including, rarely, the START room (the reported
    # spawn-next-to-a-boss-door softlock). Flood from the spawn
    # over everything a determined player can pass (walls and
    # locked boss doors block; enemies die; brown doors slide) and
    # demand (a) the mini-boss that carries the key is reachable
    # and (b) some boss door is approachable from outside. A bad
    # layout rerolls with fresh randomness; after 8 rolls the seal
    # downgrades to sliding doors — an ugly floor beats an
    # unwinnable one (never expected in practice).
    $genOk = $true
    $flood = New-Object 'bool[,]' $h,$w
    $fq = New-Object System.Collections.Queue
    $fq.Enqueue(@([int]$startR.CX,[int]$startR.CY))
    $flood[$startR.CY,$startR.CX] = $true
    $sawMini = $false; $sawBossDoor = $false; $miniExists = $false
    for($fy=0;$fy -lt $h;$fy++){ for($fx=0;$fx -lt $w;$fx++){ if($grid[$fy,$fx] -eq 3){ $miniExists = $true } } }
    if($grid[$startR.CY,$startR.CX] -eq 3){ $sawMini = $true }
    while($fq.Count -gt 0){
        $fc = $fq.Dequeue()
        $fcx = [int]$fc[0]; $fcy = [int]$fc[1]
        foreach($nb in @(@(0,-1),@(0,1),@(-1,0),@(1,0))){
            $nx = $fcx + $nb[0]; $ny = $fcy + $nb[1]
            if($nx -lt 0 -or $nx -ge $w -or $ny -lt 0 -or $ny -ge $h){ continue }
            if($flood[$ny,$nx]){ continue }
            $nv = $grid[$ny,$nx]
            if($nv -eq 4){ $sawBossDoor = $true; continue }
            if($nv -eq 1 -or $nv -eq 11){ continue }
            if($nv -eq 3){ $sawMini = $true }
            $flood[$ny,$nx] = $true
            $fq.Enqueue(@($nx,$ny))
        }
    }
    if($miniExists -and -not $sawMini){ $genOk = $false }
    if(-not $sawBossDoor){ $genOk = $false }
    if(-not $genOk){
        if($GenTry -lt 8){ return (New-Dungeon $Level ($GenTry + 1)) }
        for($fy=0;$fy -lt $h;$fy++){ for($fx=0;$fx -lt $w;$fx++){ if($grid[$fy,$fx] -eq 4){ $grid[$fy,$fx] = 10 } } }
    }
    # Fog of war: 2D bool array tracking which tiles the player has seen.
    # All false initially. Render-Screen reveals tiles around the player each turn.
    $seen = New-Object 'bool[,]' $h, $w
    @{Grid=$grid;W=$w;H=$h;Rooms=$rooms;Enemies=$enemies;Zone=$zone;LoreObjects=$loreObjects
      PX=$startR.CX;PY=$startR.CY;PDir=0;HasBossKey=$false;BossDefeated=$false
      Seen=$seen}
}
function Get-Cell {
    param($d,$dx,$dy)
    if($dx -lt 0 -or $dx -ge $d.W -or $dy -lt 0 -or $dy -ge $d.H){return 1}
    $v=$d.Grid[$dy,$dx]
    if($v -eq 1 -or $v -eq 10 -or $v -eq 4){return 1}else{return 0}
}

function Get-Forward {
    param($dir,$dist)
    switch($dir){
        0{@(0,-$dist)}
        1{@($dist,0)}
        2{@(0,$dist)}
        3{@(-$dist,0)}
    }
}

function Get-Left {
    param($dir,$dist)
    switch($dir){
        0{@(-$dist,0)}
        1{@(0,-$dist)}
        2{@($dist,0)}
        3{@(0,$dist)}
    }
}

# ─── 3D RENDERER ─────────────────────────────────────────────────
function Render-Screen {
    $d=$script:Dungeon; $px=$d.PX; $py=$d.PY; $pdir=$d.PDir
    $p=$script:Player
    # Expanded viewport: was 42x21, now 56x24 (+33% area)
    $vw=56; $vh=24

    # ── Box-drawing chars ──
    $chVLine = [char]0x2502
    $chHLine = [char]0x2500
    $chTL    = [char]0x250C
    $chTR    = [char]0x2510
    $chBL    = [char]0x2514
    $chBR    = [char]0x2518
    $chCross = [char]0x256C
    $chHalfU = [char]0x2580  # ▀  upper half block  (top cell lit, bottom dark)
    $chHalfL = [char]0x2584  # ▄  lower half block  (bottom cell lit, top dark)
    $chFull  = [char]0x2588  # █  full block
    $chShadeL= [char]0x2591  # ░  light shade
    $chShadeM= [char]0x2592  # ▒  medium shade
    $chShadeD= [char]0x2593  # ▓  dark shade
    $chDot   = [char]0x00B7  # ·  middle dot (floor texture)

    # ── Build 3D view buffer ──
    $buf   = New-Object 'char[,]'   $vh,$vw
    $fgbuf = New-Object 'string[,]' $vh,$vw
    $bgbuf = New-Object 'string[,]' $vh,$vw

    $halfY = [math]::Floor($vh/2)
    for($y=0;$y -lt $vh;$y++){for($x=0;$x -lt $vw;$x++){
        $buf[$y,$x]   = ' '
        $fgbuf[$y,$x] = "White"
        if($y -lt $halfY){ $bgbuf[$y,$x] = "Black" }         # ceiling: black
        else             { $bgbuf[$y,$x] = "DarkGray" }      # floor: dark gray
    }}

    # ── Floor checkerboard texture ──
    # Adds depth cues on the floor using middle-dots spaced by distance
    # from camera. Dot color comes from the zone (Phase 3): coolant-cyan
    # in the Flooded Data-Center, sickly green in the Archives, ember-red
    # in the Core Meltdown. Server Halls keep the classic dark-gold.
    $zoneFloorFG = "DarkYellow"
    if($d.Zone){
        $zoneFloorFG = switch($d.Zone.Id){
            "Flooded"  { "DarkCyan" }
            "Archives" { "DarkGreen" }
            "Core"     { "DarkRed" }
            default    { "DarkYellow" }
        }
    }
    for($y=$halfY;$y -lt $vh;$y++){
        # rows closer to bottom = nearer = denser pattern
        $closeness = $y - $halfY
        # Use alternating pattern per player position so walking feels like scrolling
        $phase = ($px + $py + $pdir) % 4
        for($x=0;$x -lt $vw;$x++){
            if((($x + $closeness + $phase) % 6) -eq 0){
                $buf[$y,$x] = $chDot
                $fgbuf[$y,$x] = $zoneFloorFG
            }
        }
    }
    # Ceiling speckle (faint stars / stone bits)
    for($y=0;$y -lt $halfY;$y++){
        for($x=0;$x -lt $vw;$x++){
            if((($x * 7 + $y * 3 + $px * 2 + $py) % 37) -eq 0){
                $buf[$y,$x] = $chDot
                $fgbuf[$y,$x] = "DarkGray"
            }
        }
    }

    # 5 depth layers (same count, but wider/taller to fit larger viewport)
    $bounds = @(
        @{L=0; R=55;T=0; B=23},
        @{L=7; R=48;T=3; B=20},
        @{L=14;R=41;T=6; B=17},
        @{L=20;R=35;T=9; B=14},
        @{L=24;R=31;T=10;B=13}
    )

    # Background fog per depth (near -> far)
    $shadeBG    = @("DarkCyan","DarkBlue","DarkBlue","Black","Black")
    # Edge foreground per depth (gradient for fog effect)
    # Edge tint follows the dungeon's themed zone (Phase 3): the nearest
    # depth edge picks up the zone's signature color so the Flooded
    # Data-Center reads blue, the Archives green, the Core red.
    $zoneEdge = if($d.Zone -and $d.Zone.EdgeColor){$d.Zone.EdgeColor}else{"Cyan"}
    $shadeEdgeFG = @("White",$zoneEdge,"Gray","DarkGray","DarkGray")
    # Wall fill shade character per depth (near is full, far is stippled for fog)
    $shadeFill   = @(' ',' ',$chShadeL,$chShadeM,$chShadeD)

    for($depth=4;$depth -ge 1;$depth--){
        $fwd=Get-Forward $pdir $depth
        $fdx=$px+$fwd[0]; $fdy=$py+$fwd[1]
        $leftOff=Get-Left $pdir 1
        $lx=$fdx+$leftOff[0]; $ly=$fdy+$leftOff[1]
        $rx=$fdx-$leftOff[0]; $ry=$fdy-$leftOff[1]
        $wallAhead=(Get-Cell $d $fdx $fdy)-eq 1
        $wallLeft =(Get-Cell $d $lx $ly)-eq 1
        $wallRight=(Get-Cell $d $rx $ry)-eq 1
        $outer=$bounds[$depth-1]; $inner=$bounds[$depth]
        $bg  = $shadeBG[$depth]
        $efg = $shadeEdgeFG[$depth]
        $fillCh = $shadeFill[$depth]

        if($wallAhead){
            # Fill wall face
            for($y=$inner.T;$y -le $inner.B;$y++){
                for($x=$inner.L;$x -le $inner.R;$x++){
                    $buf[$y,$x]=$fillCh; $fgbuf[$y,$x]=$efg; $bgbuf[$y,$x]=$bg
                }
            }
            # Stone block texture lines (horizontal brick effect)
            $brickRow1 = $inner.T + [math]::Floor(($inner.B-$inner.T)/3)
            $brickRow2 = $inner.T + [math]::Floor(($inner.B-$inner.T)*2/3)
            if($depth -le 2){
                for($x=$inner.L+1;$x -lt $inner.R;$x++){
                    $buf[$brickRow1,$x]=[char]0x2500
                    $fgbuf[$brickRow1,$x]="DarkGray"
                    $bgbuf[$brickRow1,$x]=$bg
                    $buf[$brickRow2,$x]=[char]0x2500
                    $fgbuf[$brickRow2,$x]="DarkGray"
                    $bgbuf[$brickRow2,$x]=$bg
                }
            }
            # Door handle
            $midX=[math]::Floor(($inner.L+$inner.R)/2)
            $midY=[math]::Floor(($inner.T+$inner.B)/2)
            if(($inner.R-$inner.L)-gt 4){
                $buf[$midY,$midX]=$chCross; $fgbuf[$midY,$midX]="White"; $bgbuf[$midY,$midX]=$bg
            }
            # Horizontal edges
            for($x=$inner.L;$x -le $inner.R;$x++){
                $buf[$inner.T,$x]=$chHLine; $fgbuf[$inner.T,$x]="White"; $bgbuf[$inner.T,$x]=$bg
                $buf[$inner.B,$x]=$chHLine; $fgbuf[$inner.B,$x]="White"; $bgbuf[$inner.B,$x]=$bg
            }
            # Corners
            $buf[$inner.T,$inner.L]=$chTL; $fgbuf[$inner.T,$inner.L]="White"; $bgbuf[$inner.T,$inner.L]=$bg
            $buf[$inner.T,$inner.R]=$chTR; $fgbuf[$inner.T,$inner.R]="White"; $bgbuf[$inner.T,$inner.R]=$bg
            $buf[$inner.B,$inner.L]=$chBL; $fgbuf[$inner.B,$inner.L]="White"; $bgbuf[$inner.B,$inner.L]=$bg
            $buf[$inner.B,$inner.R]=$chBR; $fgbuf[$inner.B,$inner.R]="White"; $bgbuf[$inner.B,$inner.R]=$bg
        }

        if($wallLeft){
            # Fill left side wall
            for($y=$inner.T;$y -le $inner.B;$y++){
                for($x=$outer.L;$x -lt $inner.L;$x++){
                    $buf[$y,$x]=$fillCh; $fgbuf[$y,$x]=$efg; $bgbuf[$y,$x]=$bg
                }
            }
            # Diagonal top fill
            $dT=$inner.T-$outer.T; $dX=$inner.L-$outer.L
            if($dT -gt 0){
                for($row=$outer.T;$row -lt $inner.T;$row++){
                    $frac=($row-$outer.T)/$dT
                    $xEnd=[math]::Floor($outer.L+$frac*$dX)
                    for($x=$outer.L;$x -le $xEnd;$x++){
                        $buf[$row,$x]=$fillCh; $fgbuf[$row,$x]=$efg; $bgbuf[$row,$x]=$bg
                    }
                }
                # Diagonal bottom fill
                $dB=$outer.B-$inner.B
                if($dB -gt 0){
                    for($row=($inner.B+1);$row -le $outer.B;$row++){
                        $frac=($outer.B-$row)/$dB
                        $xEnd=[math]::Floor($outer.L+$frac*$dX)
                        for($x=$outer.L;$x -le $xEnd;$x++){
                            $buf[$row,$x]=$fillCh; $fgbuf[$row,$x]=$efg; $bgbuf[$row,$x]=$bg
                        }
                    }
                }
            }
            # Left vertical edge
            for($y=$inner.T;$y -le $inner.B;$y++){
                $buf[$y,$inner.L]=$chVLine; $fgbuf[$y,$inner.L]="White"; $bgbuf[$y,$inner.L]=$bg
            }
            # Torch on left wall (only nearest layer, only sometimes)
            if($depth -eq 1 -and (($px + $py + $pdir * 3) % 3) -eq 0){
                $torchRow = $inner.T + 2
                $torchCol = [math]::Floor(($outer.L + $inner.L) / 2)
                if($torchRow -lt $inner.B -and $torchCol -lt $inner.L){
                    # Flicker between two chars based on player position for cheap animation
                    $flicker = if((($px + $py) % 2) -eq 0){"*"}else{"^"}
                    $buf[$torchRow,$torchCol] = [char]$flicker
                    $fgbuf[$torchRow,$torchCol] = "Yellow"
                    # Glow above
                    if($torchRow-1 -ge 0){
                        $buf[($torchRow-1),$torchCol] = [char]0x00B0
                        $fgbuf[($torchRow-1),$torchCol] = "DarkYellow"
                    }
                }
            }
        }

        if($wallRight){
            # Fill right side wall
            for($y=$inner.T;$y -le $inner.B;$y++){
                for($x=($inner.R+1);$x -le $outer.R;$x++){
                    $buf[$y,$x]=$fillCh; $fgbuf[$y,$x]=$efg; $bgbuf[$y,$x]=$bg
                }
            }
            # Diagonal top fill
            $dT=$inner.T-$outer.T; $dX=$outer.R-$inner.R
            if($dT -gt 0){
                for($row=$outer.T;$row -lt $inner.T;$row++){
                    $frac=($row-$outer.T)/$dT
                    $xStart=[math]::Floor($outer.R-$frac*$dX)
                    for($x=$xStart;$x -le $outer.R;$x++){
                        $buf[$row,$x]=$fillCh; $fgbuf[$row,$x]=$efg; $bgbuf[$row,$x]=$bg
                    }
                }
                # Diagonal bottom fill
                $dB=$outer.B-$inner.B
                if($dB -gt 0){
                    for($row=($inner.B+1);$row -le $outer.B;$row++){
                        $frac=($outer.B-$row)/$dB
                        $xStart=[math]::Floor($outer.R-$frac*$dX)
                        for($x=$xStart;$x -le $outer.R;$x++){
                            $buf[$row,$x]=$fillCh; $fgbuf[$row,$x]=$efg; $bgbuf[$row,$x]=$bg
                        }
                    }
                }
            }
            # Right vertical edge
            for($y=$inner.T;$y -le $inner.B;$y++){
                $buf[$y,$inner.R]=$chVLine; $fgbuf[$y,$inner.R]="White"; $bgbuf[$y,$inner.R]=$bg
            }
            # Right-wall torch
            if($depth -eq 1 -and (($px * 2 + $py + $pdir) % 3) -eq 0){
                $torchRow = $inner.T + 2
                $torchCol = [math]::Floor(($outer.R + $inner.R) / 2)
                if($torchRow -lt $inner.B -and $torchCol -gt $inner.R){
                    $flicker = if((($px + $py) % 2) -eq 0){"^"}else{"*"}
                    $buf[$torchRow,$torchCol] = [char]$flicker
                    $fgbuf[$torchRow,$torchCol] = "Yellow"
                    if($torchRow-1 -ge 0){
                        $buf[($torchRow-1),$torchCol] = [char]0x00B0
                        $fgbuf[($torchRow-1),$torchCol] = "DarkYellow"
                    }
                }
            }
        }
    }
        # ── Entity sprite (bigger, more detailed) ──
    $fwd1=Get-Forward $pdir 1; $ax=$px+$fwd1[0]; $ay=$py+$fwd1[1]
    $cellAhead=if($ax -ge 0 -and $ax -lt $d.W -and $ay -ge 0 -and $ay -lt $d.H){$d.Grid[$ay,$ax]}else{1}
    if(($cellAhead -ge 2 -and $cellAhead -le 11) -and ($cellAhead -eq 4 -or $cellAhead -eq 10 -or (Get-Cell $d $ax $ay) -eq 0)){
        $eColor=switch($cellAhead){2{"Red"}3{"Magenta"}4{"DarkRed"}5{"Green"}6{"Yellow"}7{"Yellow"}8{"White"}9{"DarkCyan"}10{"DarkYellow"}11{"Red"}default{"White"}}
        # New larger sprites (10w x 7h) with more detail
        $sprites=@{
            8=@(
                "    __    ",
                "   |  |   ",
                "  _|##|_  ",
                " | #### | ",
                " |______| ",
                " /######\ ",
                "/________\"
            )
            9=@(
                " ________ ",
                " |~~~~~~| ",
                " |> run_| ",
                " |______| ",
                "   |__|   ",
                "  /____\  ",
                "          "
            )
            2=@(
                "   .--.   ",
                "  /o  o\  ",
                " | (>>) | ",
                "  \ ^^ /  ",
                "  /|__|\  ",
                " d |  | b ",
                "   /  \   "
            )
            3=@(
                "  [____]  ",
                "  [XMBX]  ",
                " {|OOOO|} ",
                "  |****|  ",
                "  /|==|\  ",
                " // || \\ ",
                "  /    \  "
            )
            4=@(
                "  ______  ",
                " /######\ ",
                " |##||##| ",
                " |##||##| ",
                " |#=()=#| ",
                " |##||##| ",
                " \######/ "
            )
            5=@(
                "  ______  ",
                " |DDDDDD| ",
                " |D EXIT D| ",
                " |D >>>> D| ",
                " |DDDDDDD| ",
                " |______| ",
                "  ||__||  "
            )
            6=@(
                "  ._____________. ",
                " /    .-===-.    \",
                "/___| |###| |___\ ",
                "|   | '---' |   | ",
                "|   '-------'   | ",
                "|_______________| ",
                "\_______________/ "
            )
            7=@(
                "   /\     ",
                "  /  \    ",
                " | ?? |   ",
                " | HELP|  ",
                "  \__/    ",
                "  /||\    ",
                " / || \   "
            )
            10=@(
                "  ______  ",
                " /######\ ",
                " |##||##| ",
                " |##||##| ",
                " |#=()=#| ",
                " |##||##| ",
                " \######/ "
            )
            11=@(
                " \^----^/ ",
                " ( @  @ ) ",
                "  |vVVv|  ",
                " /|####|\ ",
                "/ |####| \",
                "  d|  |b  ",
                " _/    \_ "
            )
        }
        # Disguised mimic (v1.6.2): sell the con in classic too — chest
        # art, chest gold. Blown disguises fall through to the enemy face.
        $spriteKey=$cellAhead
        if($cellAhead -eq 2 -and (Test-MimicDisguised $d.Enemies["$ax,$ay"])){ $spriteKey=6; $eColor="Yellow" }
        $sprite=$sprites[$spriteKey]
        if($sprite){
            $midX=[math]::Floor($vw/2); $midY=[math]::Floor($vh/2)
            $sy=$midY-[math]::Floor($sprite.Count/2)
            foreach($line in $sprite){
                $sx=$midX-[math]::Floor($line.Length/2)
                for($ci=0;$ci -lt $line.Length;$ci++){
                    $col=$sx+$ci
                    $inBounds = ($col -ge 0 -and $col -lt $vw -and $sy -ge 0 -and $sy -lt $vh)
                    if(-not $inBounds){ continue }
                    if($line[$ci] -ne ' '){
                        # Draw this sprite glyph (wall-face chars under it are overwritten)
                        $buf[$sy,$col]=$line[$ci]
                        $fgbuf[$sy,$col]=$eColor
                    } else {
                        # Space in the sprite: also clear any wall-face chars (│ ─ etc.)
                        # from the buffer so the dungeon wall's outline doesn't bleed
                        # through the sprite's negative space. Background stays as-is
                        # (so depth fog / wall fill still shows through transparently).
                        $under = $buf[$sy,$col]
                        if($under -ne ' '){
                            $buf[$sy,$col] = ' '
                        }
                    }
                }
                $sy++
            }
        }
    }

    # ── Fog of war: reveal tiles within sight radius around player ──
    # Lazy-init Seen for any dungeons that pre-date the field (loaded saves)
    if(-not $d.Seen){
        $d.Seen = New-Object 'bool[,]' $d.H, $d.W
    }
    $sightR = 3   # reveal a 7x7 area around the player each render
    # Falcon pet: expands the per-step fog reveal radius from 3 to 5,
    # giving the player better situational awareness on the minimap.
    if($script:Pet -and $script:Pet.Type -eq "Falcon"){
        $sightR = 5
    }
    for($dy=-$sightR;$dy -le $sightR;$dy++){
        for($dx=-$sightR;$dx -le $sightR;$dx++){
            $mx = $d.PX + $dx; $my = $d.PY + $dy
            if($mx -ge 0 -and $mx -lt $d.W -and $my -ge 0 -and $my -lt $d.H){
                $d.Seen[$my, $mx] = $true
            }
        }
    }

    # ── Build minimap lines: windowed view centered on player, with fog ──
    # 11x21 window keeps the right panel within the 3D viewport's 24 rows.
    $dirChar = switch($d.PDir){0{'^'}1{'>'}2{'v'}3{'<'}}
    # Hound pet: chest cells inside the minimap window are always visible
    # even through fog, helping the player spot loot from a distance.
    $houndOwned = ($script:Pet -and $script:Pet.Type -eq "Hound")
    $mapLines = [System.Collections.ArrayList]@()
    [void]$mapLines.Add("  MAP ")
    $mapR = 5    # half-radius (window is (2R+1) tall)
    $mapW = 10   # half-width (window is (2W+1) wide)
    for($dy=-$mapR; $dy -le $mapR; $dy++){
        $ml = ""
        for($dx=-$mapW; $dx -le $mapW; $dx++){
            $mx = $d.PX + $dx
            $my = $d.PY + $dy
            if($mx -lt 0 -or $mx -ge $d.W -or $my -lt 0 -or $my -ge $d.H){
                $ml += " "  # outside dungeon bounds
            } elseif($mx -eq $d.PX -and $my -eq $d.PY){
                $ml += $dirChar
            } elseif(-not $d.Seen[$my, $mx]){
                # Hound: chest cells visible through fog so player can plan routes
                if($houndOwned -and $d.Grid[$my, $mx] -eq 6){
                    $ml += "$"
                } else {
                    $ml += "·"  # fog
                }
            } else {
                $c = $d.Grid[$my, $mx]
                $ml += switch($c){1{"#"} 0{"."} 2{ if(Test-MimicDisguised $d.Enemies["$mx,$my"]){'$'}else{'!'} } 3{"M"} 4{"D"} 5{">"} 6{"$"} 7{"?"} 8{"A"} 9{"i"} 10{"+"} 11{"B"} default{" "}}
            }
        }
        [void]$mapLines.Add($ml)
    }
    # ── Build HUD lines ──
    $dirNames=@("North","East","South","West")
    $wAtk = Get-TotalWeaponATK
    $aDef = Get-TotalArmorDEF
    $mBonus = Get-WeaponMAGBonus
    $hpPct=$p.HP/$p.MaxHP
    $hpBar="+" * [math]::Max([math]::Floor($hpPct*15),0)
    $hpBar+="-" * (15 - $hpBar.Length)
    $mpBar="+" * [math]::Max([math]::Floor(($p.MP/$p.MaxMP)*15),0)
    $mpBar+="-" * (15 - $mpBar.Length)

    $wepName = if($script:EquippedWeapon){$script:EquippedWeapon.Name}else{"Bare Hands"}
    $wepPerk = if($script:EquippedWeapon -and $script:EquippedWeapon.Perk){" [$($script:EquippedWeapon.Perk)]"}else{""}

    $hudCurW = Get-CurrentCarryWeight
    $hudMaxW = Get-MaxCarryWeight $p
    $hudLines = @(
        "",
        " $($p.Name) Lv$($script:PlayerLevel)",
        " HP[$hpBar] $($p.HP)/$($p.MaxHP)",
        " MP[$mpBar] $($p.MP)/$($p.MaxMP)",
        " ATK:$($p.ATK+$wAtk) DEF:$($p.DEF+$aDef) SPD:$($p.SPD)",
        " MAG:$($p.MAG+$mBonus) Gold:$($script:Gold)",
        " Facing: $($dirNames[$d.PDir])",
        " XP: $($script:XP)/$($script:XPToNext)",
        " Wpn: $wepName$wepPerk",
        " Armor DEF: +$aDef",
        " Lockpicks: $($script:Lockpicks)",
        " Carry: $hudCurW/$hudMaxW"
    )
    # Note: streak no longer displayed in dungeon HUD — it crowded the boss key
    # indicator. Streak is still tracked and shown on the stats page.
    if($script:HasBossKey){ $hudLines += " >> BOSS KEY <<" }
    if($script:Partner){ $hudLines += " Ally: $($script:Partner.Name)" }
    if($script:Pet){ $hudLines += " Pet: $($script:Pet.Type)" }
    if($script:DungeonMutator){ $hudLines += " Mut: $($script:DungeonMutator.Name)" }
    if($script:ActiveFoodBuff){ $hudLines += " Food: $($script:ActiveFoodBuff.Name)" }
    if($script:NGPlusLevel -gt 0){ $hudLines += " NG+$($script:NGPlusLevel)" }
    if($d.Zone){ $hudLines += " $($d.Zone.Name)" }
    $rfHud = Get-ActiveRoomEffect $d
    if($rfHud -eq "Flooded"){ $hudLines += " ~ Flooded (SPD-3)" }
    elseif($rfHud -eq "Charged"){ $hudLines += " * Charged (MAG+20%)" }
    # Active quests are no longer shown inline. Press [J] in dungeon to view
    # the full quest log with progress bars.

    # ── Combine: right panel = minimap then HUD ──
    $rightLines = [System.Collections.ArrayList]@()
    foreach($ml in $mapLines){ [void]$rightLines.Add($ml) }
    foreach($hl in $hudLines){ [void]$rightLines.Add($hl) }
    # ── Render combined output (uses frame buffer if Buffered mode is on) ──
    # When buffered, calls go to Buf-Write and Flush-Frame paints only changes.
    # Otherwise they fall through to direct host writes via Write-C/Write-CL.
    $separator = "  | "
    $maxY = $vh
    if($rightLines.Count -gt $maxY){ $maxY = $rightLines.Count }
    for($y=0;$y -lt $maxY;$y++){
        if($y -lt $vh){
            for($x=0;$x -lt $vw;$x++){
                Write-C ([string]$buf[$y,$x]) $fgbuf[$y,$x] $bgbuf[$y,$x]
            }
        } else {
            # Pad blank where the 3D view has ended but the right panel continues
            Write-C (' ' * $vw) "Gray"
        }
        Write-C $separator "DarkGray"
        if($y -lt $rightLines.Count){
            $rl = $rightLines[$y]
            if($y -eq 0){
                Write-C $rl "DarkYellow"
            }
            elseif($y -ge 1 -and $y -lt $mapLines.Count){
                # Per-character coloring of the minimap row
                for($ci=0;$ci -lt $rl.Length;$ci++){
                    $ch = $rl[$ci]
                    $cc = switch($ch){
                        '#' {"DarkBlue"}
                        '.' {"DarkGray"}
                        '!' {"Red"}
                        'M' {"Magenta"}
                        'B' {"DarkRed"}
                        '$' {"Yellow"}
                        '?' {"Yellow"}
                        '^' {"Green"}
                        'v' {"Green"}
                        '<' {"Green"}
                        '>' {"Green"}
                        '·' {"DarkGray"}    # fog of war
                        default {"DarkGray"}
                    }
                    Write-C ([string]$ch) $cc
                }
            }
            elseif($rl -match "HP\["){
                for($ci=0;$ci -lt $rl.Length;$ci++){
                    $ch=$rl[$ci]
                    if($ch -eq '+'){
                        $hpC = if($hpPct -gt 0.5){"Green"}elseif($hpPct -gt 0.25){"Yellow"}else{"Red"}
                        Write-C "+" $hpC
                    }
                    elseif($ch -eq '-'){ Write-C "-" "DarkGray" }
                    else{ Write-C ([string]$ch) "White" }
                }
            }
            elseif($rl -match "MP\["){
                for($ci=0;$ci -lt $rl.Length;$ci++){
                    $ch=$rl[$ci]
                    if($ch -eq '+'){ Write-C "+" "Cyan" }
                    elseif($ch -eq '-'){ Write-C "-" "DarkGray" }
                    else{ Write-C ([string]$ch) "White" }
                }
            }
            elseif($rl -match "BOSS KEY"){ Write-C $rl "Magenta" }
            elseif($rl -match "Quest:"){ Write-C $rl "Cyan" }
            elseif($rl -match "Carry:"){
                $carryColor = if(Test-Encumbered){"Red"}else{"DarkGray"}
                Write-C $rl $carryColor
            }
            elseif($rl -match "Facing:|Gold:|ATK:|MAG:|XP:|Wpn:|Armor DEF:|Hit:|Ally:|Lockpicks:"){
                Write-C $rl "DarkGray"
            }
            else{ Write-C $rl "Gray" }
        }
        Write-CL "" "Gray"
    }
    Write-CL ("="*80) "DarkYellow"
    if($script:StatusMsg){
        Write-CL "  $($script:StatusMsg)" "Yellow"
        $script:StatusMsg = ""
    }
}




# ─── COMBAT SYSTEM ───────────────────────────────────────────────
