        )}
        "Thief" { @(
            "      .-==~==-.      ",
            "     /  ..  ..  \    ",
            "    |   (0)(0)   |   ",
            "    |    \_/\_   |   ",
            "     \  '----'  /    ",
            "      \_.-..-._/     ",
