            "   | [] [] [] |      ",
            "    \  belt  /       ",
            "     /\    /\        ",
            "    /  \__/  \       "
        )}
        "Wizard" { @(
            "       ▄▄▄       ",
            "      ╱   ╲      ",
            "     ╱ ✦   ╲     ",
            "    ╱   ✦   ╲    ",
            "   ╱_________╲   ",
            "   █▓ ◉   ◉ ▓█   ",
            "   █▓   ╲_╱  ▓█   ",
            "    ▀█▓▓▓▓▓█▀    ",
            "    ║▓▓▓▓▓▓║    ",
            "   ═╝▓▓▓▓▓▓╚═   ",
            "    ║║▓▓▓▓║║    ",
            "   ══╩╩══╩╩══   "
        )}
        "Troll" { @(
            "    ▄▄██████▄▄    ",
            "  ▄██▒▒▒▒▒▒▒▒██▄  ",
            " ██▒▒ ◎    ◎ ▒▒██ ",
            " █▒▒▒   ▲▲   ▒▒▒█ ",
            " █▒▒▒ ┌────┐ ▒▒▒█ ",
            " █▒▒▒ │ ▼▼ │ ▒▒▒█ ",
            "  ▀█▒▒└────┘▒▒█▀  ",
            "   ║▒▓▓▓▓▓▓▓▒║   ",
            "  ═╝▒▓██████▓▒╚═  ",
            "   ║▓▒▒▒▒▒▒▒▓║   ",
            "   ║▓▓▒▒▒▒▓▓▓║   ",
            "  ══╩╩═══════╩╩══ "
        )}
        "MiniBoss" { @(
            "    ▄▄▀▀██▀▀▄▄    ",
            "   ▄╱▓▓▓▓▓▓▓▓╲▄   ",
            "  ██▓▓ {X}  {X}▓▓██  ",
            " █▓▓▓  ╲──╱  ▓▓▓█ ",
            " █▓▓▓ ═══>═══ ▓▓▓█ ",
            "  ██▓▓▓█████▓▓▓██  ",
            "   ▀▓╱═╤═╤═╤═╲▓▀   ",
            "    ║▓║ ║ ║ ║▓║    ",
            "   ═╝▓╚═╧═╧═╧╝▓╚═  ",
            "    ▓║▓▓▓▓▓▓║▓    ",
            "   ╱▓║██████║▓╲   ",
            "  ══╩╩═══════╩╩══ "
        )}
        "Boss" { @(
            "    ╔═══╗   ╔═══╗   ",
            "    ║▲▼▲║   ║▲▼▲║   ",
            "  ▄▄╚═══╝═══╚═══╝▄▄  ",
            " ▄█▓ ✦    ╱╲    ✦ ▓█▄ ",
            " █▓▓▓█{X}╱  ╲{X}█▓▓▓█ ",
            " █▓▓▓╱═════════╲▓▓▓█ ",
            "  █▓╱<===HATE===>╲▓█  ",
            "   ║▓▓▓▓▓▓▓▓▓▓▓▓▓║   ",
            "   ║▓╔═╤═╤═╤═╤═╗▓║   ",
            "  ╔╝▓║ ║ ║ ║ ║ ║▓╚╗  ",
            "  ║▓▓╚═╧═╧═╧═╧═╝▓▓║  ",
            "  ║▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓║  ",
            "  ╚═╩╩═════════╩╩═╝  "
        )}
        "Skeleton" { @(
            '       .-"""-.      ',
            '      /  __  \      ',
            '     | (oo)| |      ',
            '     |  ==  ||      ',
            '      \____/        ',
            '       ||||         ',
            '      /|||||\       ',
            '     |\\|||/|       ',
            '     |  |||   |     ',
            '      \ |||  /      ',
            '       \|||/        ',
            '        |||         ',
            '       /| |\        ',
            '      /_| |_\       '
        )}
        "Mimic" { @(
            "     _,---.---._     ",
            "    /   /   \   \    ",
            "   |  GRRR   AH  |   ",
            "   | >@<====>@<  |   ",
