# Returns a "hit flash" variant of the art — with background briefly red
# Used during combat damage animation. Returns same lines; caller handles color.
function Get-EnemyHitFrame {
    param([string]$Type)
    $base = Get-EnemyArt $Type
    # Return as-is; caller colors differently
    return $base
}

function Draw-CombatHPBar {
    param([int]$Current,[int]$Max,[int]$Width,[string]$Color)
    $filled = [math]::Max([math]::Floor(($Current/$Max)*$Width),0)
    $empty = $Width - $filled
    Write-C "[" "White"
    Write-C ("=" * $filled) $Color
    Write-C ("-" * $empty) "DarkGray"
    Write-C "]" "White"
}

# ── Per-kill crediting (Phase 2 group combat) ──
# Credits counters/quests/bestiary for ONE slain enemy, exactly once
# (guarded by the KillCredited flag on the enemy). Called from the
# mid-fight kill sweep so AoE and poison kills in group fights credit
# at the moment of death, and again defensively from the victory block.
function Credit-EnemyKill {
    param($en)
    if(-not $en){ return }
    if($en.KillCredited){ return }
    $en.KillCredited = $true
    $script:KillCount++
    $script:TotalKills++
    $script:RunStats.KillsThisRun++
    Update-QuestProgress "Kill"
    if($en.IsMiniBoss){
        Update-QuestProgress "MiniBoss"; Add-Corruption -4
        if($en.Name -eq "Goblin Warchief"){
            Write-CL "  *** THE WARCHIEF FALLS. The Horde's drums miss a beat. ***" "Green"
            Write-CL "  (The 200g bounty is in its warchest.)" "Yellow"
        }
    }
    if($en.IsBoss){
        Update-QuestProgress "Boss"
        $script:BossesDefeated++
        Add-Corruption -10
        # Story flag (Act II): the Rehearsal ends when its Warden does.
        if($en.Name -eq "Warden Prime"){ Set-QuestStage "wp_down" 999999 }
    }
    # Bare-handed quest: credit only if no weapon was equipped.
    if(-not $script:EquippedWeapon){
        Update-QuestProgress "BareHands"; $script:TotalBareKills++
    }
    # Bestiary key format: "Category~Name" or "Name~Variant". '~' is
    # save-grammar-safe (see Save-Game bestiary encoding).
    $bestKey = if($en.IsBoss){"Boss~$($en.Name)"}
               elseif($en.IsMiniBoss){"MiniBoss~$($en.Name)"}
               elseif($en.Variant){"$($en.Name)~$($en.Variant)"}
               else{"$($en.Name)~"}
    if(-not $script:Bestiary.ContainsKey($bestKey)){
        $script:Bestiary[$bestKey] = @{ Kills = 0; FirstSeen = $true }
    }
    $script:Bestiary[$bestKey].Kills++
}

# ── Phase 6: GRANT-XP (extracted from Start-Combat's victory block) ─
# THE one leveling routine. Kills accrue XP per-kill and Start-Combat
# resolves through this; quests and story beats award through it too,
# so there is exactly one level-up code path. Amount 0 = just resolve.
function Grant-XP {
    param([int]$Amount = 0)
    if($Amount -gt 0){
        $script:XP += $Amount
        Write-CL "  +$Amount XP" "Cyan"
    }
    $p = $script:Player
    while($script:XP -ge $script:XPToNext){
        $script:XP -= $script:XPToNext
        $script:PlayerLevel++
        $script:XPToNext = [math]::Floor($script:XPToNext * 1.5)
        $p.MaxHP += 10; $p.HP = $p.MaxHP; $p.MaxMP += 5; $p.MP = $p.MaxMP
        $p.ATK += 2; $p.DEF += 2; $p.SPD += 1; $p.MAG += 2
        Write-Host ""
        Write-CL "  *** LEVEL UP! Now Level $($script:PlayerLevel)! ***" "Yellow"
        Write-CL "  All stats increased! HP & MP fully restored!" "Yellow"
        Write-CL "  *** +1 TALENT POINT — spend at the Stats page ***" "Cyan"
        # Tier-2 / Tier-3 talent unlock prompts
        if($script:PlayerLevel -eq 5){
            Write-CL "  *** TALENT TIER 2 UNLOCKED! ***" "Magenta"
        }
        if($script:PlayerLevel -eq 10){
            Write-CL "  *** TALENT TIER 3 UNLOCKED! ***" "Magenta"
        }
        # Ability tier upgrade notification at milestone levels
        if($script:PlayerLevel -in @(5,10,15)){
            $newTier = Get-AbilityTier $script:PlayerLevel
            Write-CL "  *** ABILITIES UPGRADED TO TIER $newTier! ***" "Magenta"
            Write-CL "  Your abilities now hit harder. (+25% Pwr per tier)" "Magenta"
        }
    }
}

function Start-Combat {
    param($Enemy)
    # ── Group combat support (Phase 2) ──
    # $Enemy may be a single enemy hashtable (all legacy callers) or an
    # array of 1-3 enemies. Combat runs on $combatEnemies; $e is the
    # player's CURRENT TARGET, re-pointed automatically when the target
    # dies. During each enemy's own turn, $e is temporarily set to the
    # acting enemy (the 1v1-era attack code reads attacker stats from
    # $e), then restored to the player's target afterward.
    $combatEnemies = @($Enemy)
    $p = $script:Player
    $fled = $false; $won = $false

    # Equipment bonuses
    $bonusATK  = Get-TotalWeaponATK
    $armorDEF  = Get-TotalArmorDEF
    $magBonus  = Get-WeaponMAGBonus

    # ── Player-gear contribution to enemy stats ──
    # The user's gear shouldn't trivialize content, but the contribution is
    # also intentionally MILD so the player can still feel the benefit of
    # better gear. Training point boosts (ATK/DEF/SPD/MAG/HP/MP from the
    # Training Grounds) are NOT factored in — those are the player's reward
    # for spending gold and should give a real combat advantage.
    # Locked at fight start so swapping gear mid-dungeon doesn't matter.
    # Applied PER ENEMY so groups scale each member identically.
    $gearAtk = $bonusATK + $magBonus
    $gearDef = $armorDEF
    foreach($e in $combatEnemies){
    if($e.IsBoss){
        # Bosses are already strong from base stats + level scaling. Light gear bump.
        $bossAtkBump = [math]::Floor($gearAtk * 0.12)
        $bossDefBump = [math]::Floor($gearDef * 0.12)
        $e.ATK += $bossAtkBump
        $e.DEF += $bossDefBump
    } elseif($e.IsMiniBoss){
        $miniAtkBump = [math]::Floor($gearAtk * 0.18)
        $miniDefBump = [math]::Floor($gearDef * 0.18)
        $e.ATK += $miniAtkBump
        $e.DEF += $miniDefBump
        # Mini-bosses get a small HP bump scaled to player's gear too
        $e.MaxHP += [math]::Floor($gearAtk * 0.4)
        $e.HP    += [math]::Floor($gearAtk * 0.4)
    } else {
        $normAtkBump = [math]::Floor($gearAtk * 0.18)
        $normDefBump = [math]::Floor($gearDef * 0.18)
        $e.ATK += $normAtkBump
        $e.DEF += $normDefBump
        # Normals get a tiny HP bump so they don't die in 1 shot to a high-ATK player
        $e.MaxHP += [math]::Floor($gearAtk * 0.20)
        $e.HP    += [math]::Floor($gearAtk * 0.20)
    }

    # ── Mutator-driven stat overlays ──
    if(Has-Mutator "Speedrun"){
        # Enemies +25% SPD on this run
        $e.SPD = [math]::Floor($e.SPD * 1.25)
    }
    # ── New Game Plus scaling ──
    # Each NG+ level multiplies enemy HP and ATK by an additional 20%.
    # Stacks multiplicatively on top of the existing dungeon scaling.
    if($script:NGPlusLevel -gt 0){
        $ngMul = 1.0 + ($script:NGPlusLevel * 0.20)
        $e.HP    = [math]::Floor($e.HP * $ngMul)
        $e.MaxHP = [math]::Floor($e.MaxHP * $ngMul)
        $e.ATK   = [math]::Floor($e.ATK * $ngMul)
    }
    # ── Difficulty scaling (Settings) ──
    # Easy 0.75, Medium 1.0, Hard 1.25. Stacks multiplicatively. Floors
    # to 1 so Easy never produces 0-HP/0-ATK enemies.
    $diffMul = Get-DifficultyMul
    if($diffMul -ne 1.0){
        $e.HP    = [math]::Max([math]::Floor($e.HP    * $diffMul), 1)
        $e.MaxHP = [math]::Max([math]::Floor($e.MaxHP * $diffMul), 1)
        $e.ATK   = [math]::Max([math]::Floor($e.ATK   * $diffMul), 1)
    }
    }
    # Player's initial target: the first enemy in the group.
    $e = $combatEnemies[0]
    # $playerTarget mirrors the player's CHOSEN target so it can be
    # restored after each enemy's initiative slot borrows $e.
    $playerTarget = $e
    # ── Initiative queue (Phase 2, Step 3) ──
    # Combat is a sequence of actor slots, refilled each round from all
    # living combatants sorted by SPD descending; ties go to the player.
    # The player's slot renders the screen and takes the menu; enemy
    # slots resolve attacks whose log lines appear at the next render.
    # An enemy FASTER than the player strikes first each round FROM
    # ROUND TWO onward. The fight OPENER is dice-gated (user tuning):
    # see the first-round adjustment in the refill block below. Declared outside the revive-resume do/until so a mid-round
    # revival lets the remaining (slower) enemies finish their slots:
    # you rise at 1 HP with the round still in motion.
    $initQueue = [System.Collections.ArrayList]@()
    $firstRoundDone = $false   # opening-strike dice rule fires once

    $defBuff   = 0; $atkBuff = 0
    $defendCooldown = 0   # turns until Defend can be used again (0 = ready)
    # Per-ability cooldown tracker: name -> remaining turns. Cleared at the
    # start of each combat so cooldowns don't carry between fights.
    $abilityCooldowns = @{}
    # Enemy ability cooldowns and self-buff state now live PER ENEMY on
    # the enemy hashtable ($en.AbilityCD, $en.BonusATK, $en.BonusDEF,
    # $en.BuffTurns) — initialized in the per-enemy loop below. Two
    # goblins must not share one buff timer.
    $combatLog = [System.Collections.ArrayList]@()
    # ── SysAdmin voice (Cat 6): one dry line to open the fight. ──
    # Bosses are exempt — their telegraphs carry their own drama.
    if($combatEnemies.Count -gt 1){
        [void]$combatLog.Add(@{Text="   $(Get-PackIntroQuip)";Color="DarkGray"})
    } elseif(-not $combatEnemies[0].IsBoss){
        [void]$combatLog.Add(@{Text="   $(Get-EnemyIntroQuip $combatEnemies[0])";Color="DarkGray"})
    }

    # ── Start-of-fight talent procs ──
    # Knight Holy Vigil: heal 5 HP at start of every fight.
    if(Has-Talent "Knight_T2_C"){
        $heal = [math]::Min(5, $script:Player.MaxHP - $script:Player.HP)
        if($heal -gt 0){
            $script:Player.HP += $heal
            [void]$combatLog.Add(@{Text=">> Holy Vigil grants $heal HP.";Color="Green"})
        }
    }
    # Ranger Quickdraw: first attack of the fight is a guaranteed crit.
    # Cleared after first hit lands.
    $quickdrawArmed = (Has-Talent "Ranger_T2_C")
    # Berserker Reckless Charge: first attack deals +50%.
    $recklessChargeArmed = (Has-Talent "Berserker_T2_C")
    # Knight Last Stand / Cleric Resurrection / Berserker Final Stand:
    # one-time per dungeon proc flags. Cleared on dungeon entry, not here.
    # (See Enter-Dungeon for the per-run reset.)
    # Cleric Lay on Hands: one free full heal per dungeon (used flag).
    # Necromancer Death Pact / Berserker Rampage: stacking ATK buffs from
    # killing blows. Stacks persist within a fight; reset between fights.
    # Caps: Death Pact 5, Rampage 3 (or 6 with Berserker T4 Eternal Rage).
    $rampageStacks  = 0
    $deathPactStacks = 0
    # Per-enemy status effects (Poisoned/Slowed/PoisonDmg) are initialized
    # in the per-enemy loop below, after the hit/crit helpers are defined.

    # ── NEW HIT CHANCE SYSTEM ──
    # Player base 70%, enemy base 65%. Hard cap at 90%, floor at 20%.
    # Adjusted by level, SPD, status effects.
    #
    #   Player hit = 70 + min(level-1, 15) + floor(SPD * 0.3)  (capped 90, floored 20)
    #   Enemy  hit = 65 + DungeonLevel * 1.5                   (capped 90, floored 20)
    #
    # Slow drops target's hit% by 25; Stun sets 0 for one turn.
    # Luck potion previously added to hit chance — now it boosts CRIT CHANCE
    # via Get-PlayerCrit. Hit chance no longer takes a luck argument.
    function Get-PlayerHit {
        param($level,$spd)
        $h = 70 + [math]::Min($level - 1, 15) + [math]::Floor($spd * 0.3)
        if($h -gt 90){ $h = 90 }
        if($h -lt 20){ $h = 20 }
        return $h
    }
    # Player crit chance: 5% base, +1% per 4 SPD, plus active Luck buff.
    # Capped at 60% so the game never feels deterministic.
    function Get-PlayerCrit {
        param($spd, $luckBonus)
        $c = 5 + [math]::Floor($spd / 4) + $luckBonus
        # Marn's Lucky Byte (journal completion reward): +2% crit, always
        if($script:JournalCharm){ $c += 2 }
        # Cursor, the Data Miners' query sprite (faction companion): +2% crit
        if($script:Companion -eq "dm"){ $c += 2 }
        # Shadow Gem sockets (Phase 4c): +1% crit each
        $c += Get-SocketBonus "CRIT"
        # Armor set bonus (Phase 4d): Mythril 2pc grants +1% crit
        $c += Get-SetBonus "CRIT"
        # Ranger Eagle Eye: +5% crit
        if(Has-Talent "Ranger_T1_A"){ $c += 5 }
        # Brawler Berserk: +40% crit when below 25% HP
        if(Has-Talent "Brawler_T3_A" -and $script:Player.HP -lt ($script:Player.MaxHP * 0.25)){
            $c += 40
        }
        if($c -gt 95){ $c = 95 }
        if($c -lt 0){ $c = 0 }
        return $c
    }
    function Get-EnemyHit {
        param($dungeonLvl,$isMini,$isBoss)
        $h = 65 + [math]::Floor($dungeonLvl * 1.5)
        if($isMini){ $h += 3 }
        if($isBoss){ $h += 5 }
        if($h -gt 90){ $h = 90 }
        if($h -lt 20){ $h = 20 }
        return $h
    }
    # Enemy crit chance: 4% base + scales mildly with dungeon level.
    # Mini-bosses get +3, bosses +6. Capped at 30% so it can't snowball.
    function Get-EnemyCrit {
        param($dungeonLvl,$isMini,$isBoss)
        $c = 4 + [math]::Floor($dungeonLvl / 3)
        if($isMini){ $c += 3 }
        if($isBoss){ $c += 6 }
        if($c -gt 30){ $c = 30 }
        if($c -lt 0){ $c = 0 }
        return $c
    }

    $playerHitChance = Get-PlayerHit $script:PlayerLevel $p.SPD
    # ── Per-enemy runtime state init ──
    # Every group member gets its own hit/crit, status effects, self-buff
    # tracking, and ability-cooldown table. Statuses reset here on every
    # combat entry so a fled-and-re-engaged enemy starts clean (same
    # behavior the old fight-local variables had).
    foreach($en in $combatEnemies){
        $en.HitChance  = Get-EnemyHit $script:DungeonLevel $en.IsMiniBoss $en.IsBoss
        $en.CritChance = Get-EnemyCrit $script:DungeonLevel $en.IsMiniBoss $en.IsBoss
        $en.Poisoned   = $false
        $en.Slowed     = $false
        $en.PoisonDmg  = 0
        $en.BonusATK   = 0
        $en.BonusDEF   = 0
        $en.BuffTurns  = 0
        $en.AbilityCD  = @{}
    }
    # ── Room effects (Phase 3): read once at fight start ──
    # Flooded rooms slog the player: SPD -3 for initiative, flee, and
    # crit math. Charged rooms boost Magic damage 20% BOTH ways (see
    # the ability blocks). Uses the player's tile at engage time.
    $roomFx = Get-ActiveRoomEffect $script:Dungeon
    $effSPD = [int]$p.SPD
    $effSPD += Get-ArmorSkillSPD   # LightArmor skill (Phase 4)
    $effSPD += Get-SetBonus "SPD"  # armor set bonus (Phase 4d)
    if($script:Companion -eq "rp"){ $effSPD += 1 }  # Orphan, the Rogue Processes' stray (faction companion)
    $spdTag = ""
    if($roomFx -eq "Flooded"){ $effSPD = [math]::Max($effSPD - 3, 1); $spdTag = ", slowed by coolant" }
    $playerCritChance = Get-PlayerCrit $effSPD $script:LuckBonus

    # Enemy art — refreshed each player render too, because in group
    # fights the target (and therefore the portrait) can change.
    $artType  = if($e.IsMiniBoss){"MiniBoss"}elseif($e.IsBoss){"Boss"}elseif($e.ArtType){$e.ArtType}else{$e.Name}
    $enemyArt = Get-EnemyArt $artType

    # ── Animation helpers (closures so they share $combatLog/$e) ──
    function Show-AttackAnim {
        param([string]$Type,[int]$Damage,[string]$Color="Yellow")
        # Short animated burst - player side
        $frames = switch($Type){
            "sword"  { @("  ╱","  ╱╱"," ╱╱╱","╱╱╱>","══>═"," ══>"," > ","    ") }
            "magic"  { @("  *","  **","  ***"," ****","*****","  ✦","  .","    ") }
            "ranged" { @("  .","  .-","  .->"," .-->",".--->","  ->","  >"," .") }
            "fist"   { @("  o","  oo"," o<<","o<<<","<<<!"," <!","  !","   ") }
            default  { @("  !","  !!","  !!!"," !!!!","!!!!!","  !!","  !","   ") }
        }
        foreach($f in $frames){
            Write-C "    " "Black"
            Write-CL $f $Color
            Start-Sleep -Milliseconds 35
            # Cursor up one line & clear
            try {
                $pos = $Host.UI.RawUI.CursorPosition
                $newY = $pos.Y - 1
                if($newY -ge 0){
                    $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                    Write-Host (" " * 20) -NoNewline
                    $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                }
            } catch {}
        }
        # Damage popup
        Write-C "    " "Black"
        Write-CL " -$Damage! " "Red"
        Start-Sleep -Milliseconds 150
        try {
            $pos = $Host.UI.RawUI.CursorPosition
            $newY = $pos.Y - 1
            if($newY -ge 0){
                $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                Write-Host (" " * 20) -NoNewline
                $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
            }
        } catch {}
    }

    function Show-EnemyAttackAnim {
        param([int]$Damage)
        # Reversed direction for enemy attacks
        $frames = @("<   ","<<  ","<<< ","<<<<","<<< "," << ","  < ","    ")
        foreach($f in $frames){
            Write-C "    " "Black"
            Write-CL $f "Red"
            Start-Sleep -Milliseconds 30
            try {
                $pos = $Host.UI.RawUI.CursorPosition
                $newY = $pos.Y - 1
                if($newY -ge 0){
                    $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                    Write-Host (" " * 20) -NoNewline
                    $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                }
            } catch {}
        }
        Write-C "    " "Black"
        Write-CL " YOU -$Damage! " "DarkRed"
        Start-Sleep -Milliseconds 200
        try {
            $pos = $Host.UI.RawUI.CursorPosition
            $newY = $pos.Y - 1
            if($newY -ge 0){
                $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                Write-Host (" " * 20) -NoNewline
                $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
            }
        } catch {}
    }

    # Decide animation type from equipped weapon
    $animType = "default"
    if($script:EquippedWeapon){
        switch($script:EquippedWeapon.WeaponType){
            "Sword"  { $animType = "sword" }
            "Staff"  { $animType = "magic" }
            "Bow"    { $animType = "ranged" }
            "Fist"   { $animType = "fist" }
            "Mace"   { $animType = "sword" }
            "Scythe" { $animType = "sword" }
            "Dagger" { $animType = "sword" }
            "Hammer" { $animType = "fist" }
            default  { $animType = "default" }
        }
    }

    # ── Main combat loop, wrapped in a revive-resume shell ──
    # If a lethal-save talent (Last Stand / Resurrection / Final Stand)
    # procs while the enemy is still alive, $reviveResume re-enters the
    # combat loop instead of exiting the fight. Previously the proc
    # returned Result="Fled", which silently teleported the player out
    # of combat — turning every revive into a free escape and making
    # the Cleric effectively unkillable (revive, walk away, repeat next
    # dungeon). Now the enemy that dropped you is still standing there.
    # No infinite-loop risk: each talent sets its once-per-dungeon flag
    # at proc time, so at most one resume can occur per dungeon.
    do {
    $reviveResume = $false
    while($p.HP -gt 0 -and @($combatEnemies | Where-Object { $_.HP -gt 0 }).Count -gt 0 -and !$fled){
        # Target auto-advance: if the player's current target died last
        # round but others remain, re-point $e at the next living enemy.
        if($playerTarget.HP -le 0){
            $nextTarget = @($combatEnemies | Where-Object { $_.HP -gt 0 }) | Select-Object -First 1
            if($nextTarget){
                $playerTarget = $nextTarget
                [void]$combatLog.Add(@{Text=">> You turn to face $($playerTarget.DisplayName)!";Color="Yellow"})
            }
        }
        $e = $playerTarget

        # ── Initiative: refill the queue when a new round begins ──
        if($initQueue.Count -eq 0){
            $roundActors = [System.Collections.ArrayList]@()
            # +0.5 tie-break: the player wins SPD ties.
            [void]$roundActors.Add(@{IsPlayer=$true; SortSPD=([double]$effSPD + 0.5)})
            foreach($qe in $combatEnemies){
                if($qe.HP -gt 0){
                    [void]$roundActors.Add(@{IsPlayer=$false; En=$qe; SortSPD=[double]$qe.SPD})
                }
            }
            # Scriptblock sort (v1.6.2): -Property NAME does not bind
            # hashtable keys in Windows PowerShell 5.1 — the old line
            # compared nulls, so turn order was effectively RANDOM
            # (and the opener could claim a slower enemy was faster).
            # { $_.Key } evaluates in the language engine, which DOES
            # fall back to dictionary lookup. Same fix applied to the
            # boss telegraph, both shop lists, and the world map.
            foreach($qa in @($roundActors | Sort-Object { [double]$_.SortSPD } -Descending)){
                [void]$initQueue.Add($qa)
            }
            # ── Opening strike (user tuning): the FIRST round is no
            # longer pure SPD order. A faster enemy must WIN a dice
            # roll to seize the opener — 30% + 4% per point of SPD
            # gap, capped at 75% — otherwise the player reacts in
            # time and acts first. Rounds after the first keep the
            # deterministic SPD order (ties still favor the player).
            if(-not $firstRoundDone){
                $firstRoundDone = $true
                $pIdx = -1
                for($qi = 0; $qi -lt $initQueue.Count; $qi++){
                    if($initQueue[$qi].IsPlayer){ $pIdx = $qi; break }
                }
                if($pIdx -gt 0){
                    $topSPD = [double]$initQueue[0].SortSPD
                    $spdGap = [math]::Max([int]($topSPD - $effSPD), 1)
                    $jumpChance = [math]::Min(30 + ($spdGap * 4), 75)
                    if((Get-Random -Max 100) -lt $jumpChance){
                        [void]$combatLog.Add(@{Text=">> $($initQueue[0].En.DisplayName) is faster (SPD $([int]$topSPD) vs your $effSPD$spdTag) — it wins the rush ($jumpChance% chance)!";Color="Red"})
                    } else {
                        $pSlot = $initQueue[$pIdx]
                        $initQueue.RemoveAt($pIdx)
                        $initQueue.Insert(0, $pSlot)
                        [void]$combatLog.Add(@{Text=">> You react before it can close the distance!";Color="Green"})
                    }
                }
            }
        }
        $actor = $initQueue[0]
        $initQueue.RemoveAt(0)
        # Enemy slot whose owner died earlier this round: skip it.
        if(-not $actor.IsPlayer -and $actor.En.HP -le 0){ continue }

        if($actor.IsPlayer){
        # Recompute crit chance every player turn (bug fix): Brawler
        # Berserk (+40% below 25% HP) reads live HP, so a once-per-fight
        # snapshot went stale — dropping below 25% mid-fight gave no
        # buff, and healing out of it kept the buff all fight.
        $playerCritChance = Get-PlayerCrit $effSPD $script:LuckBonus
        # Refresh the portrait for the current target (group fights).
        $artType  = if($e.IsMiniBoss){"MiniBoss"}elseif($e.IsBoss){"Boss"}elseif($e.ArtType){$e.ArtType}else{$e.Name}
        $enemyArt = Get-EnemyArt $artType
        clr

        # ── Broken-gear warnings (once per turn, to keep pressure on) ──
        if($script:EquippedWeapon -and (Test-ItemBroken $script:EquippedWeapon)){
            [void]$combatLog.Add(@{Text=">> WARNING: $($script:EquippedWeapon.Name) is BROKEN — no ATK bonus!";Color="Red"})
        }
        foreach($armorSlot in @("Helmet","Chest","Shield","Amulet","Boots")){
            $armorPiece = $script:EquippedArmor[$armorSlot]
            if($armorPiece -and (Test-ItemBroken $armorPiece)){
                [void]$combatLog.Add(@{Text=">> WARNING: $($armorPiece.Name) is BROKEN — no DEF!";Color="Red"})
            }
        }

        # ── Header ──
        Write-CL ("=" * 70) "DarkRed"
        Write-C "  " "Red"
        if($e.IsBoss){Write-CL $e.DisplayName "DarkRed"}
        elseif($e.IsMiniBoss){Write-CL $e.DisplayName "Magenta"}
        else{Write-CL $e.DisplayName "Red"}
        Write-CL ("=" * 70) "DarkRed"
        Write-Host ""

        # ── Enemy art + stats ──
        $eHPPct = [math]::Max($e.HP / $e.MaxHP, 0)
        $statusStr = ""
        if($e.Poisoned){ $statusStr += " [POISON]" }
        if($e.Slowed){ $statusStr += " [SLOW]" }
        if($e.Stunned){ $statusStr += " [STUN]" }
        if($e.IsBoss -and $e.TelegraphNext){ $statusStr += " [CHARGING!]" }

        $statsLines = @(
            "",
            "  $($e.DisplayName)",
            "$statusStr",
            $null,
            "  $($e.HP) / $($e.MaxHP) HP",
            "",
            "  ATK: $($e.ATK)  DEF: $($e.DEF)",
            "  SPD: $($e.SPD)  MAG: $($e.MAG)",
            ""
        )

        $maxLines = [math]::Max($enemyArt.Count, $statsLines.Count)
        for($i=0;$i -lt $maxLines;$i++){
            if($i -lt $enemyArt.Count){
                $artColor = if($e.IsBoss){"DarkRed"}elseif($e.IsMiniBoss){"Magenta"}else{"Red"}
                Write-C "  $($enemyArt[$i])" $artColor
                $pad = 24 - $enemyArt[$i].Length
                if($pad -gt 0){Write-C (" " * $pad) "Black"}
            } else {
                Write-C ("  " + " " * 22) "Black"
            }
            Write-C "  " "Black"
            if($i -lt $statsLines.Count){
                if($null -eq $statsLines[$i]){
                    Write-C "  " "White"
                    Draw-CombatHPBar $e.HP $e.MaxHP 30 $(if($eHPPct -gt 0.5){"Red"}elseif($eHPPct -gt 0.25){"DarkYellow"}else{"DarkRed"})
                } elseif($statsLines[$i] -match "\[POISON\]|\[SLOW\]|\[STUN\]|\[CHARGING") {
                    Write-C $statsLines[$i] "Yellow"
                } else {
                    Write-C $statsLines[$i] "Gray"
                }
            }
            Write-Host ""
        }

        Write-Host ""

        # ── Group roster (Phase 2) ──
        # Shown only when facing 2+ enemies: every group member with a
        # slot number, HP, and condensed statuses. '>' marks the player's
        # current target (the big art above is always the target).
        if($combatEnemies.Count -gt 1){
            for($gi = 0; $gi -lt $combatEnemies.Count; $gi++){
                $ge = $combatEnemies[$gi]
                $marker = if($ge -eq $e){">"}else{" "}
                if($ge.HP -le 0){
                    Write-CL "  $marker [$($gi+1)] $($ge.DisplayName) — slain" "DarkGray"
                } else {
                    $gStatus = ""
                    if($ge.Poisoned){ $gStatus += " [PSN]" }
                    if($ge.Slowed){   $gStatus += " [SLW]" }
                    if($ge.Stunned){  $gStatus += " [STN]" }
                    if($ge.IsBoss -and $ge.TelegraphNext){ $gStatus += " [CHG!]" }
                    $gColor = if($ge -eq $e){"Yellow"}else{"Gray"}
                    Write-CL "  $marker [$($gi+1)] $($ge.DisplayName)  $($ge.HP)/$($ge.MaxHP) HP$gStatus" $gColor
                }
            }
            Write-Host ""
        }

        Write-CL ("  " + "-" * 66) "DarkGray"
        Write-Host ""

        # ── Player stats (with stance applied) ──
        $stanceATK = Get-StanceATKMult
        $stanceDEF = Get-StanceDEFMult
        # Cooking food buffs: ATKBoost adds flat ATK; DEFBoost adds flat DEF.
        # Applied BEFORE stance multiplier so it scales with stance.
        $foodATK = 0; $foodDEF = 0
        if($script:ActiveFoodBuff){
            switch($script:ActiveFoodBuff.Effect){
                "ATKBoost" { $foodATK = [int]$script:ActiveFoodBuff.Value }
                "DEFBoost" { $foodDEF = [int]$script:ActiveFoodBuff.Value }
            }
        }
        # Talent stat bonuses (passive, always-on flat stats)
        $talATK = Get-TalentStatBonus "ATK"
        $talDEF = Get-TalentStatBonus "DEF"
        $talMAG = Get-TalentStatBonus "MAG"
        # Class-specific weapon-type bonuses (e.g. Sword Discipline)
        $wepBonus = 0
        if($script:EquippedWeapon){
            $wt = $script:EquippedWeapon.WeaponType
            if(Has-Talent "Knight_T1_C"   -and $wt -eq "Sword"){ $wepBonus += 2 }
            if(Has-Talent "Berserker_T1_C" -and $wt -eq "Sword"){ $wepBonus += 3 }
            if(Has-Talent "Cleric_T1_C"   -and $wt -eq "Mace"){  $wepBonus += 2 }
            if(Has-Talent "Brawler_T1_B"  -and $wt -eq "Fist"){  $wepBonus += 3 }
            # Skill (Phase 4): Swords covers all melee weapon types;
            # Bows covers Bow. +1 dmg per 10 levels (max +5).
            $wepBonus += Get-SkillTier $(if($wt -eq "Bow"){"Bows"}else{"Swords"})
        }
        $totalDEF = [int][math]::Floor(($p.DEF + $armorDEF + $defBuff + $foodDEF + $talDEF + (Get-ArmorSkillDEF) + (Get-SocketBonus "DEF") + (Get-SetBonus "DEF")) * $stanceDEF)
        $totalATK = [int][math]::Floor(($p.ATK + $bonusATK + $atkBuff + $foodATK + $talATK + $wepBonus + (Get-SocketBonus "ATK") + (Get-SetBonus "ATK")) * $stanceATK)
        $totalMAG = [int][math]::Floor(($p.MAG + $magBonus + $talMAG + (Get-SocketBonus "MAG")) * $stanceATK)  # MAG scales with ATK multiplier
        $pHPPct = [math]::Max($p.HP / $p.MaxHP, 0)
        $wep = if($script:EquippedWeapon){$script:EquippedWeapon.Name}else{"Bare Hands"}

        Write-C "  $($p.Name)" "Green"
        Write-CL "  (Lv$($script:PlayerLevel))  Weapon: $wep" "DarkGray"

        Write-C "  HP " "White"
        Draw-CombatHPBar $p.HP $p.MaxHP 25 $(if($pHPPct -gt 0.5){"Green"}elseif($pHPPct -gt 0.25){"Yellow"}else{"Red"})
        Write-CL " $($p.HP)/$($p.MaxHP)" "White"

        Write-C "  MP " "White"
        Draw-CombatHPBar $p.MP $p.MaxMP 25 "Cyan"
        Write-CL " $($p.MP)/$($p.MaxMP)" "White"

        # v1.6.1: SPD shown is the EFFECTIVE speed (base + LightArmor
        # skill + set bonus + companion, -3 in Flooded rooms) — the
        # exact number the initiative queue compares. ATK/DEF already
        # showed totals; SPD showing raw base made correct “enemy is
        # faster” openers look like a bug.
        $spdShown = if($roomFx -eq "Flooded"){"$effSPD (Flooded)"}else{"$effSPD"}
        Write-CL "  ATK:$totalATK DEF:$totalDEF SPD:$spdShown MAG:$totalMAG" "DarkGray"
        $luckStr = if($script:LuckTurnsLeft -gt 0){" | LUCK +$($script:LuckBonus)% crit ($($script:LuckTurnsLeft)t)"}else{""}
        Write-CL "  Hit:$($playerHitChance)% Crit:$($playerCritChance)%$luckStr | Enemy Hit:$($e.HitChance)% Crit:$($e.CritChance)%" "DarkGray"
        Write-C "  Stance: " "DarkGray"; Write-CL "[$(Get-StanceShortLabel)] $($script:Stance)" (Get-StanceColor)

        # ── Combat log ──
        if($combatLog.Count -gt 0){
            Write-Host ""
            $logStart = [math]::Max($combatLog.Count - 5, 0)
            for($li=$logStart;$li -lt $combatLog.Count;$li++){
                $entry = $combatLog[$li]
                Write-CL "  $($entry.Text)" $entry.Color
            }
        }

        # ── Action menu ──
        Write-Host ""
        Write-CL ("  " + "-" * 66) "DarkGray"
        $throwCount = $script:ThrowablePotions.Count
        $defLabel = if($defendCooldown -gt 0){"Defend(${defendCooldown}t)"}else{"Defend"}
        Write-CL "   [1] Attack  [2] Ability  [3] Potion  [4] Throw($throwCount)  [5] $defLabel  [6] Flee" "White"
        $extraOptions = @()
        if(Has-Talent "Cleric_T3_B"){
            # T4 Holy Fury allows 2 uses per dungeon, baseline allows 1.
            $maxLoH = if(Has-Talent "Cleric_T4_A"){2}else{1}
            if([int]$script:LayOnHandsUsed -lt $maxLoH){
                $remaining = $maxLoH - [int]$script:LayOnHandsUsed
                $extraOptions += "[L] Lay on Hands ($remaining left)"
            }
        }
        if(Has-Talent "Warlock_T2_B"){
            $extraOptions += "[O] Soul Tap"
        }
        if($extraOptions.Count -gt 0){
            Write-CL ("   " + ($extraOptions -join "  ")) "Magenta"
        }
        Write-CL "   [T] Stance (free action)" "DarkCyan"
        if(@($combatEnemies | Where-Object { $_.HP -gt 0 }).Count -gt 1){
            Write-CL "   [V] Switch Target (free action)" "DarkCyan"
        }
        Write-CL ("  " + "-" * 66) "DarkGray"
        Write-C "  > " "Yellow"
        $choice = Read-Host

        $acted = $true
        $playerDefending = $false
        $wasFleeAttempt = $false   # set by the Flee handler; gates poison tick
        # Track enemy HP before this action so on-kill talents can know the
        # pre-strike HP for threshold checks (e.g., Eternal Bargain).
        $script:LastEnemyHpBeforeAction = [int]$e.HP

        switch($choice){
            "1" {
                # Necromancer Reaper: enemies below threshold HP are killed
                # automatically by basic attack. Skips hit roll, perks,
                # crits, and all damage math. T4 Lord of the Dead bumps
                # the threshold from 25% to 40% AND heals the player for
                # 15 HP per Reaper kill.
                $reaperThresh = 0
                if(Has-Talent "Necromancer_T4_A"){
                    $reaperThresh = 0.40
                } elseif(Has-Talent "Necromancer_T3_C"){
                    $reaperThresh = 0.25
                }
                if($reaperThresh -gt 0 -and $e.HP -le ($e.MaxHP * $reaperThresh) -and $e.HP -gt 0){
                    [void]$combatLog.Add(@{Text=">> REAPER. Their thread is harvested.";Color="DarkMagenta"})
                    $script:RunStats.DamageDealt += $e.HP
                    $e.HP = 0
                    if(Has-Talent "Necromancer_T4_A"){
                        $heal = [math]::Min(15, $script:Player.MaxHP - $script:Player.HP)
                        if($heal -gt 0){
                            $script:Player.HP += $heal
                            [void]$combatLog.Add(@{Text="   Lord of the Dead — drained $heal HP.";Color="Magenta"})
                        }
                    }
                }
                elseif((Get-Random -Max 100) -ge $playerHitChance){
                    [void]$combatLog.Add(@{Text=">> You attack but MISS!";Color="DarkGray"})
                } else {
                    # Skill XP (Phase 4): landed weapon hits train Swords/Bows.
                    if($script:EquippedWeapon){
                        Add-SkillXP $(if($script:EquippedWeapon.WeaponType -eq "Bow"){"Bows"}else{"Swords"}) 2
                    }
                    $raw = $totalATK - [math]::Floor(($e.DEF + [int]$e.BonusDEF) * 0.5)
                    $playerDmg = [math]::Max($raw + (Get-Random -Min -2 -Max 4), 1)
                    # Glass Cannon mutator: +50% damage dealt
                    if(Has-Mutator "GlassCannon"){
                        $playerDmg = [math]::Floor($playerDmg * 1.5)
                    }
                    # ── Talent damage modifiers (apply BEFORE crit doubling) ──
                    if($e.IsBoss -and (Has-Talent "Knight_T3_A")){
                        $playerDmg = [math]::Floor($playerDmg * 1.25)
                    }
                    if(Has-Talent "Ranger_T2_A" -and ($e.HP -ge ($e.MaxHP * 0.75))){
                        $playerDmg = [math]::Floor($playerDmg * 1.15)
                    }
                    # Brawler T2_A Pugilist (was 20%) and T4 Iron Avalanche
                    # share the "below 50% HP" condition. T4 supersedes T2_A
                    # by going to 50% bonus instead of 20%.
                    if($script:Player.HP -lt ($script:Player.MaxHP * 0.50)){
                        if(Has-Talent "Brawler_T4_A"){
                            $playerDmg = [math]::Floor($playerDmg * 1.50)
                        }
                        elseif(Has-Talent "Brawler_T2_A"){
                            $playerDmg = [math]::Floor($playerDmg * 1.20)
                        }
                    }
                    if(Has-Talent "Berserker_T2_A" -and $script:Player.HP -lt ($script:Player.MaxHP * 0.40)){
                        $playerDmg = [math]::Floor($playerDmg * 1.30)
                    }
                    # Knight Avatar of Light (T4): +15% damage dealt
                    if(Has-Talent "Knight_T4_A"){
                        $playerDmg = [math]::Floor($playerDmg * 1.15)
                    }
                    # Weapon-type +% mastery talents
                    if($script:EquippedWeapon){
                        $wt = $script:EquippedWeapon.WeaponType
                        if(Has-Talent "Mage_T1_C"        -and $wt -eq "Staff"){  $playerDmg = [math]::Floor($playerDmg * 1.10) }
                        if(Has-Talent "Warlock_T1_C"     -and $wt -eq "Staff"){  $playerDmg = [math]::Floor($playerDmg * 1.10) }
                        if(Has-Talent "Ranger_T1_C"      -and $wt -eq "Bow"){    $playerDmg = [math]::Floor($playerDmg * 1.10) }
                        if(Has-Talent "Necromancer_T1_C" -and $wt -eq "Scythe"){ $playerDmg = [math]::Floor($playerDmg * 1.10) }
                    }
                    # Cleric Smiter: +25% to undead enemy types
                    if(Has-Talent "Cleric_T2_B" -and ($e.Name -eq "Skeleton" -or $e.Name -eq "Zombie")){
                        $playerDmg = [math]::Floor($playerDmg * 1.25)
                    }
                    # Berserker Reckless Charge: first attack +50%
                    if($recklessChargeArmed){
                        $playerDmg = [math]::Floor($playerDmg * 1.50)
                    }
                    # Necromancer Lich's Pact: +30% damage (HP penalty already
                    # applied at purchase). Note: T3_A already used for Lich
                    # in our talent table for Necromancer.
                    if(Has-Talent "Necromancer_T3_A"){
                        $playerDmg = [math]::Floor($playerDmg * 1.30)
                    }
                    # Stacking ATK buffs from kills: each stack = +5 flat
                    # damage, applied as a multiplier-equivalent boost.
                    if($rampageStacks -gt 0){
                        $playerDmg += (5 * $rampageStacks)
                    }
                    if($deathPactStacks -gt 0){
                        $bump = [math]::Floor($playerDmg * (0.05 * $deathPactStacks))
                        $playerDmg += $bump
                    }
                    # Crit roll: 2x damage if it lands. Quickdraw forces crit
                    # on the first attack of the fight if owned.
                    $isCrit = ((Get-Random -Max 100) -lt $playerCritChance)
                    if($quickdrawArmed){
                        $isCrit = $true
                        $quickdrawArmed = $false
                    }
                    # Reckless Charge consumed on first hit
                    $recklessChargeArmed = $false
                    if($isCrit){
                        # Ranger Deadshot: crits deal 3x instead of 2x
                        if(Has-Talent "Ranger_T3_A"){ $playerDmg *= 3 }
                        else { $playerDmg *= 2 }
                    }
                    Show-AttackAnim $animType $playerDmg "Yellow"
                    $e.HP -= $playerDmg
                    $script:RunStats.DamageDealt += $playerDmg
                    if($isCrit){
                        [void]$combatLog.Add(@{Text=">> CRITICAL HIT! $playerDmg damage!";Color="Yellow"})
                        Update-QuestProgress "Crit"; $script:TotalCrits++; $script:RunStats.CritsThisRun++
                        # ── On-crit talent procs ──
                        # Brawler Combo Strike: heal 8 HP
                        if(Has-Talent "Brawler_T2_C"){
                            $heal = [math]::Min(8, $script:Player.MaxHP - $script:Player.HP)
                            if($heal -gt 0){
                                $script:Player.HP += $heal
                                [void]$combatLog.Add(@{Text="   Combo Strike: +$heal HP";Color="Green"})
                            }
                        }
                        # Mage Mana Surge: restore 10 MP
                        if(Has-Talent "Mage_T3_B"){
                            $manaR = [math]::Min(10, $script:Player.MaxMP - $script:Player.MP)
                            if($manaR -gt 0){
                                $script:Player.MP += $manaR
                                [void]$combatLog.Add(@{Text="   Mana Surge: +$manaR MP";Color="Cyan"})
                            }
                        }
                        # Brawler Knockout: 30% chance to stun on crit
                        if(Has-Talent "Brawler_T3_C" -and (Get-Random -Max 100) -lt 30){
                            $e.Stunned = $true
                            [void]$combatLog.Add(@{Text="   KNOCKOUT! Enemy is stunned!";Color="Yellow"})
                        }
                    } else {
                        [void]$combatLog.Add(@{Text=">> You attack for $playerDmg damage!";Color="Green"})
                    }

                    # Weapon durability: successful hit consumes 1 point (unless indestructible)
                    if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0 -and $script:EquippedWeapon.Durability -gt 0){
                        $script:EquippedWeapon.Durability--
                        if($script:EquippedWeapon.Durability -le 0){
                            [void]$combatLog.Add(@{Text="   *CRACK* $($script:EquippedWeapon.Name) SHATTERS — 0 ATK bonus!";Color="Red"})
                        } elseif($script:EquippedWeapon.Durability -eq [int]($script:EquippedWeapon.MaxDurability * 0.25)){
                            [void]$combatLog.Add(@{Text="   Your $($script:EquippedWeapon.Name) groans — durability low!";Color="DarkYellow"})
                        }
                    }

                    # Ranger Multishot: 25% chance to attack a second time.
                    # Half damage, no perk procs, no durability loss to keep
                    # the proc cheap and the combat log readable.
                    # Volley (T4) supersedes: 50% chance, FULL damage.
                    if($e.HP -gt 0){
                        $msChance = 0
                        $msMul    = 0.5
                        if(Has-Talent "Ranger_T4_A"){
                            $msChance = 50; $msMul = 1.0
                        } elseif(Has-Talent "Ranger_T3_B"){
                            $msChance = 25; $msMul = 0.5
                        }
                        if($msChance -gt 0 -and (Get-Random -Max 100) -lt $msChance){
                            $extraDmg = [math]::Max([math]::Floor($playerDmg * $msMul), 1)
                            $e.HP -= $extraDmg
                            $script:RunStats.DamageDealt += $extraDmg
                            $tag = if(Has-Talent "Ranger_T4_A"){"Volley"}else{"Multishot"}
                            [void]$combatLog.Add(@{Text="   $tag! Second arrow flies for $extraDmg.";Color="Green"})
                        }
                    }

                    # Weapon perk proc. Some talents bump the perk chance
                    # (Toxic Tips, Hexweave) — apply those before the roll.
                    if($script:EquippedWeapon -and $script:EquippedWeapon.Perk){
                        $perkChance = [int]$script:EquippedWeapon.PerkChance
                        if(Has-Talent "Ranger_T2_B" -and $script:EquippedWeapon.Perk -eq "Poison"){
                            $perkChance = [math]::Floor($perkChance * 1.25)
                        }
                        if(Has-Talent "Warlock_T2_A" -and $script:EquippedWeapon.Perk -eq "Drain"){
                            $perkChance = [math]::Floor($perkChance * 1.25)
                        }
                        if((Get-Random -Max 100) -lt $perkChance){
                            switch($script:EquippedWeapon.Perk){
                                "Bleed" {
                                    $bleedDmg = Get-Random -Min 3 -Max 9
                                    # Berserker Bleed Mastery: doubled
                                    if(Has-Talent "Berserker_T2_B"){ $bleedDmg *= 2 }
                                    $e.HP -= $bleedDmg
                                    [void]$combatLog.Add(@{Text="   BLEED! $bleedDmg extra damage!";Color="DarkRed"})
                                }
                                "Burn" {
                                    $burnDmg = Get-Random -Min 3 -Max 8
                                    # Mage Burnsight: doubled
                                    if(Has-Talent "Mage_T2_C"){ $burnDmg *= 2 }
                                    $e.HP -= $burnDmg
                                    [void]$combatLog.Add(@{Text="   BURN! $burnDmg extra damage!";Color="DarkYellow"})
                                }
                                "Poison" {
                                    $e.Poisoned = $true
                                    $e.PoisonDmg = Get-Random -Min 4 -Max 8
                                    [void]$combatLog.Add(@{Text="   Enemy is POISONED! ($($e.PoisonDmg)/turn)";Color="DarkGreen"})
                                }
                                "Drain" {
                                    $drainAmt = [math]::Floor($playerDmg * 0.25)
                                    # Necromancer Drain Mastery: heal doubled
                                    if(Has-Talent "Necromancer_T2_A"){ $drainAmt *= 2 }
                                    $p.HP = [math]::Min($p.HP + $drainAmt, $p.MaxHP)
                                    [void]$combatLog.Add(@{Text="   DRAIN! Restored $drainAmt HP!";Color="Magenta"})
                                }
                                "Stun" {
                                    $e.Stunned = $true
                                    [void]$combatLog.Add(@{Text="   STUN! Enemy stunned!";Color="Yellow"})
                                }
                            }
                        }
                    }
                }
            }
            "2" {
                Write-Host ""
                Write-CL "  ── Abilities ──" "Cyan"
                for($ai=0;$ai -lt $p.Abilities.Count;$ai++){
                    $ab = Get-ScaledAbility $p.Abilities[$ai] $script:PlayerLevel
                    $costStr = if($ab.Type -eq "Sacrifice"){"HP:$([math]::Floor($p.MaxHP * 0.15))"}else{"MP:$($ab.Cost)"}
                    $effStr = if($ab.Effect -and $ab.Effect -ne "None" -and $ab.Effect -ne "SacrificeHP"){" [$($ab.Effect)]"}else{""}
                    # Show cooldown state per ability
                    $cdLeft = 0
                    if($abilityCooldowns.ContainsKey($ab.Name)){ $cdLeft = $abilityCooldowns[$ab.Name] }
                    if($cdLeft -gt 0){
                        Write-CL "    [$($ai+1)] $($ab.Name)  ($costStr)  [$($ab.Type)] Pwr:$($ab.Power)$effStr  -- COOLDOWN ${cdLeft}t --" "DarkGray"
                    } else {
                        Write-CL "    [$($ai+1)] $($ab.Name)  ($costStr)  [$($ab.Type)] Pwr:$($ab.Power)$effStr" "Cyan"
                    }
                }
                Write-C "    > " "Yellow"; $ac = Read-Host
                $idx = (ConvertTo-SafeInt -Value $ac) - 1
                if($idx -ge 0 -and $idx -lt $p.Abilities.Count){
                    $ab = Get-ScaledAbility $p.Abilities[$idx] $script:PlayerLevel

                    # Check cooldown FIRST
                    $cdLeft = 0
                    if($abilityCooldowns.ContainsKey($ab.Name)){ $cdLeft = $abilityCooldowns[$ab.Name] }
                    if($cdLeft -gt 0){
                        [void]$combatLog.Add(@{Text=">> $($ab.Name) is still on cooldown ($cdLeft turns)!";Color="DarkGray"})
                        $acted = $false
                        # break out of switch case — need to continue to next iteration
                    } else {
                    # Check cost
                    $canUse = $true
                    if($ab.Type -eq "Sacrifice"){
                        $hpCost = [math]::Floor($p.MaxHP * 0.15)
                        if($p.HP -le $hpCost){
                            [void]$combatLog.Add(@{Text=">> Not enough HP to sacrifice!";Color="Red"})
                            $canUse = $false; $acted = $false
                        }
                    } else {
                        if($p.MP -lt $ab.Cost){
                            [void]$combatLog.Add(@{Text=">> Not enough MP!";Color="Red"})
                            $canUse = $false; $acted = $false
                        }
                    }

                    if($canUse){
                        # Pay cost
                        if($ab.Type -eq "Sacrifice"){
                            $hpCost = [math]::Floor($p.MaxHP * 0.15)
                            $p.HP -= $hpCost
                            [void]$combatLog.Add(@{Text=">> Sacrificed $hpCost HP!";Color="DarkMagenta"})
                        } else {
                            # Mage Archmage Ascendant (T4): MP cost halved.
                            $mpCost = [int]$ab.Cost
                            if(Has-Talent "Mage_T4_A"){
                                $mpCost = [math]::Max([math]::Floor($mpCost * 0.5), 1)
                            }
                            # Warlock Bound to Eternity (T4): Soul Tap is free.
                            # Soul Tap is handled separately as the [O] action,
                            # so here we only need to handle ability MP cost
                            # — Soul Tap doesn't go through this path.
                            $p.MP -= $mpCost
                        }

                        # Set this ability's cooldown. Use the CD field from the
                        # base ability template (default 2 if missing). The cooldown
                        # decrements at end of turn, so a Cooldown=2 ability skips
                        # the next 2 turns then is ready again.
                        $cdVal = if($p.Abilities[$idx].Cooldown){[int]$p.Abilities[$idx].Cooldown}else{2}
                        # Mage Time Slip: ability cooldowns -1 turn (min 1)
                        if(Has-Talent "Mage_T3_C"){ $cdVal = [math]::Max($cdVal - 1, 1) }
                        $abilityCooldowns[$ab.Name] = $cdVal

                        if($ab.Type -eq "Buff"){
                            switch -Wildcard ($ab.Effect){
                                "DEF*" {
                                    $val = [int]($ab.Effect -replace '[^0-9]','')
                                    $defBuff += $val
                                    [void]$combatLog.Add(@{Text=">> Defense raised by $val!";Color="Cyan"})
                                }
                                "ATK*" {
                                    $val = [int]($ab.Effect -replace '[^0-9]','')
                                    $atkBuff += $val
                                    [void]$combatLog.Add(@{Text=">> Attack raised by $val!";Color="Cyan"})
                                }
                                "SPD*" {
                                    $val = [int]($ab.Effect -replace '[^0-9]','')
                                    # Under new system: SPD buff directly increases hit%
                                    $playerHitChance = [math]::Min($playerHitChance + ($val * 2), 90)
                                    [void]$combatLog.Add(@{Text=">> Speed raised! Hit chance improved!";Color="Cyan"})
                                }
                            }
                        }
                        elseif($ab.Type -eq "Heal"){
                            $healAmt = $ab.Power + [math]::Floor(($p.MAG + $magBonus) * 0.5)
                            $healAmt += 2 * (Get-SkillTier "Restoration")   # skill (Phase 4)
                            Add-SkillXP "Restoration" 3
                            $healed = [math]::Min($healAmt, $p.MaxHP - $p.HP)
                            $p.HP += $healed
                            [void]$combatLog.Add(@{Text=">> $($ab.Name) restores $healed HP!";Color="Green"})
                        }
                        else {
                            # Damage ability
                            if((Get-Random -Max 100) -ge $playerHitChance){
                                [void]$combatLog.Add(@{Text=">> $($ab.Name) MISSES!";Color="DarkGray"})
                            } else {
                                $base = if($ab.Type -eq "Magic" -or $ab.Type -eq "Sacrifice"){$p.MAG + $magBonus}else{$p.ATK + $bonusATK + $atkBuff}
                                # Apply stance multiplier (same scaler for ATK and MAG)
                                $base = [int][math]::Floor($base * (Get-StanceATKMult))
                                $raw = $base + $ab.Power - [math]::Floor(($e.DEF + [int]$e.BonusDEF) * 0.4)
                                $playerDmg = [math]::Max($raw + (Get-Random -Min -2 -Max 5), 1)
                                # Skill (Phase 4): Destruction — magic-school abilities only.
                                if($ab.Type -eq "Magic" -or $ab.Type -eq "Sacrifice"){
                                    $playerDmg += Get-SkillTier "Destruction"
                                    Add-SkillXP "Destruction" 3
                                }
                                # Glass Cannon mutator: +50% ability damage
                                if(Has-Mutator "GlassCannon"){
                                    $playerDmg = [math]::Floor($playerDmg * 1.5)
                                }
                                # Crit roll on abilities too. Quickdraw/Reckless apply too.
                                $isCrit = ((Get-Random -Max 100) -lt $playerCritChance)
                                if($quickdrawArmed){ $isCrit = $true; $quickdrawArmed = $false }
                                if($recklessChargeArmed){
                                    $playerDmg = [math]::Floor($playerDmg * 1.50)
                                    $recklessChargeArmed = $false
                                }
                                # Necromancer Lich's Pact: +30% damage
                                if(Has-Talent "Necromancer_T3_A"){
                                    $playerDmg = [math]::Floor($playerDmg * 1.30)
                                }
                                # Mage Archmage: +30% damage on Magic abilities
                                if(Has-Talent "Mage_T3_A" -and $ab.Type -eq "Magic"){
                                    $playerDmg = [math]::Floor($playerDmg * 1.30)
                                }
                                # Mage Archmage Ascendant (T4): +40% on Magic
                                if(Has-Talent "Mage_T4_A" -and $ab.Type -eq "Magic"){
                                    $playerDmg = [math]::Floor($playerDmg * 1.40)
                                }
                                # Magically-Charged room (Phase 3): +20%
                                # on Magic — the same boost enemies get.
                                if($roomFx -eq "Charged" -and $ab.Type -eq "Magic"){
                                    $playerDmg = [math]::Floor($playerDmg * 1.20)
                                }
                                # Stacking buffs from kills
                                if($rampageStacks -gt 0){ $playerDmg += (5 * $rampageStacks) }
                                if($deathPactStacks -gt 0){
                                    $playerDmg += [math]::Floor($playerDmg * (0.05 * $deathPactStacks))
                                }
                                if($isCrit){
                                    if(Has-Talent "Ranger_T3_A"){ $playerDmg *= 3 }
                                    else { $playerDmg *= 2 }
                                }
                                $abAnim = if($ab.Type -eq "Magic" -or $ab.Type -eq "Sacrifice"){"magic"}else{$animType}
                                Show-AttackAnim $abAnim $playerDmg "Cyan"
                                $e.HP -= $playerDmg
                                $script:RunStats.DamageDealt += $playerDmg
                                if($isCrit){
                                    [void]$combatLog.Add(@{Text=">> CRITICAL $($ab.Name) hits for $playerDmg!";Color="Yellow"})
                                    Update-QuestProgress "Crit"; $script:TotalCrits++; $script:RunStats.CritsThisRun++
                                    # On-crit talent procs (apply for ability crits too)
                                    if(Has-Talent "Brawler_T2_C"){
                                        $h = [math]::Min(8, $p.MaxHP - $p.HP)
                                        if($h -gt 0){ $p.HP += $h; [void]$combatLog.Add(@{Text="   Combo Strike: +$h HP";Color="Green"}) }
                                    }
                                    if(Has-Talent "Mage_T3_B"){
                                        $m = [math]::Min(10, $p.MaxMP - $p.MP)
                                        if($m -gt 0){ $p.MP += $m; [void]$combatLog.Add(@{Text="   Mana Surge: +$m MP";Color="Cyan"}) }
                                    }
                                    if(Has-Talent "Brawler_T3_C" -and (Get-Random -Max 100) -lt 30){
                                        $e.Stunned = $true
                                        [void]$combatLog.Add(@{Text="   KNOCKOUT! Enemy is stunned!";Color="Yellow"})
                                    }
                                } else {
                                    [void]$combatLog.Add(@{Text=">> $($ab.Name) hits for $playerDmg!";Color="Cyan"})
                                }

                                # ── AoE splash (Phase 2) ──
                                # Abilities flagged AoE=$true strike EVERY
                                # living enemy: the primary target takes the
                                # full computed damage above; all others take
                                # 65% of it (floored at 1). Splash reuses the
                                # primary's fully-multiplied damage rather
                                # than re-running the talent chain per enemy
                                # — cheaper, and the 65% factor is the
                                # balance lever. Kill crediting for splash
                                # kills happens in the kill sweep.
                                if($ab.AoE){
                                    foreach($sp in $combatEnemies){
                                        if($sp -eq $e -or $sp.HP -le 0){ continue }
                                        $splash = [math]::Max([math]::Floor($playerDmg * 0.65), 1)
                                        $sp.HP -= $splash
                                        $script:RunStats.DamageDealt += $splash
                                        [void]$combatLog.Add(@{Text="   ...arcs to $($sp.DisplayName) for $splash!";Color="Cyan"})
                                    }
                                }

                                # Mage Spell Echo: 15% chance for the ability
                                # to refund its MP cost (applied AFTER spend).
                                if(Has-Talent "Mage_T2_B" -and (Get-Random -Max 100) -lt 15 -and $ab.Cost -gt 0){
                                    $refund = [math]::Min($ab.Cost, $p.MaxMP - $p.MP)
                                    if($refund -gt 0){
                                        $p.MP += $refund
                                        [void]$combatLog.Add(@{Text="   Spell Echo: $refund MP refunded";Color="Cyan"})
                                    }
                                }
                                # Warlock Soul Drain: ability damage heals
                                # for 30% (T3) or 60% (T4 Bound to Eternity).
                                if(Has-Talent "Warlock_T3_B"){
                                    $drainMul = if(Has-Talent "Warlock_T4_A"){0.60}else{0.30}
                                    $drain = [math]::Floor($playerDmg * $drainMul)
                                    $drain = [math]::Min($drain, $p.MaxHP - $p.HP)
                                    if($drain -gt 0){
                                        $p.HP += $drain
                                        [void]$combatLog.Add(@{Text="   Soul Drain: +$drain HP";Color="DarkMagenta"})
                                    }
                                }

                                # Weapon durability: ability hits also wear the weapon (counts for magic/physical)
                                if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0 -and $script:EquippedWeapon.Durability -gt 0){
                                    $script:EquippedWeapon.Durability--
                                    if($script:EquippedWeapon.Durability -le 0){
                                        [void]$combatLog.Add(@{Text="   *CRACK* $($script:EquippedWeapon.Name) SHATTERS — 0 ATK bonus!";Color="Red"})
                                    }
                                }

                                # Status-inflicting effects now rework Slow to drop enemy hit chance
                                if($ab.Effect -eq "Stun" -and (Get-Random -Max 100) -lt 40){
                                    $e.Stunned = $true
                                    [void]$combatLog.Add(@{Text="   Enemy is STUNNED!";Color="Yellow"})
                                }
                                if($ab.Effect -eq "Burn" -and (Get-Random -Max 100) -lt 50){
                                    $burnDmg = Get-Random -Min 3 -Max 8
                                    $e.HP -= $burnDmg
                                    [void]$combatLog.Add(@{Text="   BURN deals $burnDmg extra!";Color="DarkYellow"})
                                }
                                if($ab.Effect -eq "Bleed" -and (Get-Random -Max 100) -lt 45){
                                    $bleedDmg = Get-Random -Min 4 -Max 10
                                    $e.HP -= $bleedDmg
                                    [void]$combatLog.Add(@{Text="   BLEED deals $bleedDmg extra!";Color="DarkRed"})
                                }
                                if($ab.Effect -eq "Poison" -and (Get-Random -Max 100) -lt 50){
                                    $e.Poisoned = $true
                                    $e.PoisonDmg = Get-Random -Min 4 -Max 8
                                    [void]$combatLog.Add(@{Text="   Enemy POISONED! ($($e.PoisonDmg)/turn)";Color="DarkGreen"})
                                }
                                if($ab.Effect -eq "Slow" -and (Get-Random -Max 100) -lt 60){
                                    $e.Slowed = $true
                                    # NEW: Slow lowers enemy's hit chance by 25 (floored at 20)
                                    $e.HitChance = [math]::Max($e.HitChance - 25, 20)
                                    [void]$combatLog.Add(@{Text="   Enemy SLOWED! -25% hit chance!";Color="DarkCyan"})
                                }
                                if($ab.Effect -eq "Drain"){
                                    $drainAmt = [math]::Floor($playerDmg * 0.3)
                                    $p.HP = [math]::Min($p.HP + $drainAmt, $p.MaxHP)
                                    [void]$combatLog.Add(@{Text="   DRAIN! Restored $drainAmt HP!";Color="Magenta"})
                                }
                                if($ab.Effect -eq "Weaken" -and (Get-Random -Max 100) -lt 50){
                                    $weakenAmt = [math]::Max([math]::Floor($e.ATK * 0.15), 1)
                                    $e.ATK -= $weakenAmt
                                    [void]$combatLog.Add(@{Text="   CURSE! Enemy ATK -$weakenAmt!";Color="DarkMagenta"})
                                }
                            }
                        }
                    }
                    }   # close: } else { (cooldown branch) — runs ability when not on CD
                } else { $acted = $false }
            }
            "3" {
                if($script:Potions.Count -eq 0){
                    [void]$combatLog.Add(@{Text=">> No potions!";Color="Red"}); $acted = $false
                } else {
                    Write-Host ""
                    Write-CL "  ── Potions ──" "Green"
                    for($pi=0;$pi -lt $script:Potions.Count;$pi++){
                        $pot = $script:Potions[$pi]
                        $col = if($pot.Category -eq "Special"){"Magenta"}else{"Green"}
                        Write-CL "    [$($pi+1)] $($pot.Name) - $($pot.Desc)" $col
                    }
                    Write-C "    > " "Yellow"; $pc = Read-Host
                    $pidx = (ConvertTo-SafeInt -Value $pc) - 1
                    if($pidx -ge 0 -and $pidx -lt $script:Potions.Count){
                            $pot = $script:Potions[$pidx]
                            switch($pot.Type){
                                "Heal" {
                                    $power = [int]$pot.Power + [math]::Floor([int]$pot.Power * 0.04 * (Get-SkillTier "Alchemy"))
                                    # Cleric Healer's Touch: heal potions +30%
                                    if(Has-Talent "Cleric_T2_A"){
                                        $power = [math]::Floor($power * 1.30)
                                    }
                                    # Cleric Holy Fury (T4): +50% on top
                                    if(Has-Talent "Cleric_T4_A"){
                                        $power = [math]::Floor($power * 1.50)
                                    }
                                    $healed = [math]::Min($power, $p.MaxHP - $p.HP)
                                    $p.HP += $healed
                                    [void]$combatLog.Add(@{Text=">> Healed for $healed HP!";Color="Green"})
                                }
                                "Mana" {
                                    $restored = [math]::Min($pot.Power, $p.MaxMP - $p.MP)
                                    $p.MP += $restored
                                    [void]$combatLog.Add(@{Text=">> Restored $restored MP!";Color="Cyan"})
                                }
                                "ATKBuff" {
                                    $atkBuff += $pot.Power
                                    [void]$combatLog.Add(@{Text=">> Attack boosted by $($pot.Power)!";Color="Yellow"})
                                }
                            "DEFBuff" {
                                $defBuff += $pot.Power
                                [void]$combatLog.Add(@{Text=">> Defense boosted by $($pot.Power)!";Color="Yellow"})
                            }
                            "Luck" {
                                # Luck potion boosts CRIT chance for several turns.
                                # Special-tier (Extra Strong) lasts longer.
                                $turns = if($pot.Category -eq "Special"){5}else{3}
                                $script:LuckBonus = $pot.Power
                                $script:LuckTurnsLeft = $turns
                                $playerCritChance = Get-PlayerCrit $effSPD $script:LuckBonus
                                [void]$combatLog.Add(@{Text=">> LUCK +$($pot.Power)% crit for $turns turns!";Color="Yellow"})
                            }
                        }
                        $script:Potions.RemoveAt($pidx)
                        $script:RunStats.PotionsUsed++; Add-SkillXP "Alchemy" 8
                        $script:UsedPotionsThisDungeon = $true
                        } else { $acted = $false }
                }
            }

            "4" {
                if($script:ThrowablePotions.Count -eq 0){
                    [void]$combatLog.Add(@{Text=">> No throwables!";Color="Red"}); $acted=$false
                } else {
                    Write-Host ""
                    Write-CL "  ── Throwables ──" "DarkYellow"
                    for($ti=0;$ti -lt $script:ThrowablePotions.Count;$ti++){
                        $tp = $script:ThrowablePotions[$ti]
                        Write-CL "    [$($ti+1)] $($tp.Name) - $($tp.Desc)" "DarkYellow"
                    }
                    Write-C "    > " "Yellow"; $tc = Read-Host
                    $tidx = (ConvertTo-SafeInt -Value $tc) - 1
                    if($tidx -ge 0 -and $tidx -lt $script:ThrowablePotions.Count){
                        $tp = $script:ThrowablePotions[$tidx]
                        $throwDmg = $tp.Power + (Get-Random -Min -3 -Max 4)
                        $throwDmg = [math]::Max($throwDmg, 1)
                        Show-AttackAnim "ranged" $throwDmg "DarkYellow"
                        $e.HP -= $throwDmg
                        [void]$combatLog.Add(@{Text=">> Threw $($tp.Name) for $throwDmg damage!";Color="DarkYellow"})

                        if($tp.Type -eq "ThrowPoison"){
                            $e.Poisoned = $true
                            $e.PoisonDmg = Get-Random -Min 4 -Max 8
                            [void]$combatLog.Add(@{Text="   Enemy is POISONED! ($($e.PoisonDmg)/turn)";Color="DarkGreen"})
                        }
                        if($tp.Type -eq "ThrowSlow"){
                            $e.Slowed = $true
                            $e.HitChance = [math]::Max($e.HitChance - 25, 20)
                            [void]$combatLog.Add(@{Text="   Enemy SLOWED! -25% hit chance!";Color="DarkCyan"})
                        }
                        $script:ThrowablePotions.RemoveAt($tidx)
                    } else { $acted = $false }
                }
            }
            "5" {
                # Defend: halves incoming damage. Has a 2-turn cooldown after use
                # so it's a tactical commitment, not a spam button.
                if($defendCooldown -gt 0){
                    [void]$combatLog.Add(@{Text=">> Defend is recovering. ($defendCooldown more turn(s))";Color="DarkGray"})
                    $acted = $false
                } else {
                    $playerDefending = $true
                    $defendCooldown = 3   # decrements at end of THIS turn -> 2 actual turns of cooldown
                    [void]$combatLog.Add(@{Text=">> You brace for impact. DEF doubled this turn.";Color="Cyan"})
                }
            }
            "6" {
                # Flee attempt. Both outcomes (escape or fail) mark this
                # turn as a flee attempt so the poison tick below skips —
                # players were cheesing fights by throwing poison then
                # spamming Flee: each failed attempt ticked poison damage
                # with zero player risk beyond one enemy swing.
                $wasFleeAttempt = $true
                if($e.IsBoss -or $e.IsMiniBoss){
                    [void]$combatLog.Add(@{Text=">> Cannot flee from this enemy!";Color="Red"})
                    $acted = $false
                    $wasFleeAttempt = $false   # rejected outright; normal turn rules
                } elseif((Get-Random -Max 100) -lt (40 + $effSPD + (Get-FactionFleeBonus))){
                    [void]$combatLog.Add(@{Text=">> You escaped!";Color="Yellow"}); $fled = $true; Add-Corruption 3
                } else {
                    [void]$combatLog.Add(@{Text=">> Failed to flee!";Color="Red"})
                }
            }
            "T" {
                # Stance switch — FREE ACTION, doesn't consume turn.
                # PowerShell switch is case-insensitive by default, so 'T' or 't' both match.
                Write-Host ""
                Write-CL "  ── Switch Stance ──" "Cyan"
                $curLabel = "[CURRENT: $($script:Stance)]"
                Write-CL "  $curLabel" (Get-StanceColor)
                Write-Host ""
                Write-CL "    [1] Aggressive  ATK +30% / DEF -30%" "Red"
                Write-CL "    [2] Balanced    no change (neutral)" "Yellow"
                Write-CL "    [3] Defensive   ATK -30% / DEF +30%" "Cyan"
                Write-CL "    [0] Cancel" "DarkGray"
                Write-Host ""
                Write-C "    > " "Yellow"
                $sChoice = Read-Host
                $newStance = switch($sChoice){
                    "1" { "Aggressive" }
                    "2" { "Balanced" }
                    "3" { "Defensive" }
                    default { $null }
                }
                if($newStance -and $newStance -ne $script:Stance){
                    $script:Stance = $newStance
                    $script:TotalStanceSwaps++
                    [void]$combatLog.Add(@{Text=">> Stance: $newStance.";Color=(Get-StanceColor)})
                }
                # Free action — does NOT cost a turn
                $acted = $false
            }
            "V" {
                # Switch target — FREE ACTION, only meaningful with 2+
                # living enemies. Sets BOTH $playerTarget (the durable
                # choice restored after every enemy slot) and $e (what
                # this turn's attack code aims at).
                $livingT = @($combatEnemies | Where-Object { $_.HP -gt 0 })
                if($livingT.Count -le 1){
                    [void]$combatLog.Add(@{Text=">> Only one enemy stands — no target to switch to.";Color="DarkGray"})
                } else {
                    Write-Host ""
                    Write-CL "  ── Choose Target ──" "Yellow"
                    for($ti = 0; $ti -lt $combatEnemies.Count; $ti++){
                        $te = $combatEnemies[$ti]
                        if($te.HP -gt 0){
                            $curTag = if($te -eq $e){"  (current)"}else{""}
                            Write-CL "    [$($ti+1)] $($te.DisplayName)  $($te.HP)/$($te.MaxHP) HP$curTag" "White"
                        } else {
                            Write-CL "    [$($ti+1)] $($te.DisplayName) — slain" "DarkGray"
                        }
                    }
                    Write-CL "    [0] Cancel" "DarkGray"
                    Write-Host ""
                    Write-C "    > " "Yellow"
                    $tSel = Read-Host
                    $tIdx = 0
                    if([int]::TryParse([string]$tSel, [ref]$tIdx) -and $tIdx -ge 1 -and $tIdx -le $combatEnemies.Count){
                        $picked = $combatEnemies[$tIdx - 1]
                        if($picked.HP -gt 0){
                            $playerTarget = $picked
                            $e = $picked
                            [void]$combatLog.Add(@{Text=">> New target: $($e.DisplayName)!";Color="Yellow"})
                        } else {
                            [void]$combatLog.Add(@{Text=">> That one is already dead.";Color="DarkGray"})
                        }
                    }
                }
                # Free action — does NOT cost a turn
                $acted = $false
            }
            "L" {
                # Cleric Lay on Hands: full heal, once per dungeon (or
                # twice with Holy Fury T4). Costs the player's turn but
                # full HP recovery is worth it.
                if(-not (Has-Talent "Cleric_T3_B")){
                    [void]$combatLog.Add(@{Text=">> You don't have that talent.";Color="DarkGray"})
                    $acted = $false
                } else {
                    $maxLoH = if(Has-Talent "Cleric_T4_A"){2}else{1}
                    if([int]$script:LayOnHandsUsed -ge $maxLoH){
                        [void]$combatLog.Add(@{Text=">> Lay on Hands exhausted for this dungeon.";Color="DarkGray"})
                        $acted = $false
                    } else {
                        $heal = $p.MaxHP - $p.HP
                        $p.HP = $p.MaxHP
                        $script:LayOnHandsUsed = [int]$script:LayOnHandsUsed + 1
                        [void]$combatLog.Add(@{Text=">> LAY ON HANDS — restored $heal HP.";Color="Green"})
                    }
                }
            }
            "O" {
                # Warlock Soul Tap: spend 5 HP to deal +10 damage on this
                # turn's basic attack. Sets a flag the basic attack reads.
                # T4 Bound to Eternity makes Soul Tap free (no HP cost).
                if(-not (Has-Talent "Warlock_T2_B")){
                    [void]$combatLog.Add(@{Text=">> You don't have that talent.";Color="DarkGray"})
                    $acted = $false
                } else {
                    $tapCost = if(Has-Talent "Warlock_T4_A"){0}else{5}
                    if($tapCost -gt 0 -and $p.HP -le $tapCost){
                        [void]$combatLog.Add(@{Text=">> Not enough HP to Soul Tap (need >$tapCost).";Color="Red"})
                        $acted = $false
                    } else {
                        # Deduct HP, deal direct damage with hit roll
                        if($tapCost -gt 0){ $p.HP -= $tapCost }
                        if((Get-Random -Max 100) -ge $playerHitChance){
                            $missMsg = if($tapCost -gt 0){">> Soul Tap MISSES! Lost $tapCost HP for nothing."}else{">> Soul Tap MISSES!"}
                            [void]$combatLog.Add(@{Text=$missMsg;Color="DarkGray"})
                        } else {
                            $rawTap = $totalATK + 10 - [math]::Floor(($e.DEF + [int]$e.BonusDEF) * 0.5)
                            $tapDmg = [math]::Max($rawTap + (Get-Random -Min -2 -Max 4), 1)
                            # Crit roll
                            $tapCrit = ((Get-Random -Max 100) -lt $playerCritChance)
                            if($tapCrit){
                                if(Has-Talent "Ranger_T3_A"){ $tapDmg *= 3 } else { $tapDmg *= 2 }
                            }
                            $e.HP -= $tapDmg
                            $script:RunStats.DamageDealt += $tapDmg
                            $costTag = if($tapCost -gt 0){" (-$tapCost HP)"}else{" (free!)"}
                            if($tapCrit){
                                [void]$combatLog.Add(@{Text=">> SOUL TAP CRIT! $tapDmg damage.$costTag";Color="Yellow"})
                            } else {
                                [void]$combatLog.Add(@{Text=">> Soul Tap: $tapDmg damage.$costTag";Color="DarkMagenta"})
                            }
                        }
                    }
                }
            }
            default { $acted = $false }
        }

        # ── On-kill talent procs ──
        # Fired when the player's action this turn brought the enemy
        # to 0 HP. We check just once before the poison tick so we don't
        # double-fire on the same kill.
        if($acted -and $e.HP -le 0){
            # Berserker Rampage: +1 stack — adds to $rampageStacks which
            # the next basic/ability attack will read. Baseline cap is 3,
            # T4 Eternal Rage doubles cap to 6 AND prevents end-of-turn
            # decay (handled separately below).
            if(Has-Talent "Berserker_T3_A"){
                $rampageMax = if(Has-Talent "Berserker_T4_A"){6}else{3}
                if($rampageStacks -lt $rampageMax){
                    $rampageStacks++
                    [void]$combatLog.Add(@{Text="   Rampage: stack $rampageStacks/$rampageMax";Color="DarkRed"})
                }
            }
            # Necromancer Death Pact: +1 stack (max 5)
            if(Has-Talent "Necromancer_T3_B" -and $deathPactStacks -lt 5){
                $deathPactStacks++
                [void]$combatLog.Add(@{Text="   Death Pact: stack $deathPactStacks/5";Color="DarkMagenta"})
            }
            # Necromancer Soul Harvest: +5 MP per kill
            if(Has-Talent "Necromancer_T2_C"){
                $sM = [math]::Min(5, $p.MaxMP - $p.MP)
                if($sM -gt 0){
                    $p.MP += $sM
                    [void]$combatLog.Add(@{Text="   Soul Harvest: +$sM MP";Color="Cyan"})
                }
            }
            # Warlock Eternal Bargain: kill below 20% HP restores 25 HP / 15 MP.
            # Approximation: any kill below the 20% threshold counts. Since the
            # killing blow drives HP to or below 0 from some prior value, we use
            # the fact that the enemy is now dead AND this kill happened. If the
            # PRE-action HP was already below 20% MaxHP, Eternal Bargain procs.
            if(Has-Talent "Warlock_T3_C" -and $script:LastEnemyHpBeforeAction -le ($e.MaxHP * 0.20)){
                $eH = [math]::Min(25, $p.MaxHP - $p.HP)
                $eM = [math]::Min(15, $p.MaxMP - $p.MP)
                if($eH -gt 0){ $p.HP += $eH }
                if($eM -gt 0){ $p.MP += $eM }
                if($eH -gt 0 -or $eM -gt 0){
                    [void]$combatLog.Add(@{Text="   Eternal Bargain: +$eH HP, +$eM MP";Color="DarkMagenta"})
                }
            }
        }

        # Invalid/cancelled input: the player KEEPS their initiative slot
        # and simply retries — enemies do not get free extra turns. All
        # downstream round effects (poison, cooldowns, luck) are gated
        # on $acted, so falling through is safe.
        if(-not $acted){
            $initQueue.Insert(0, $actor)
        }

        # ── Poison tick on ALL poisoned enemies (after player acts) ──
        # Gated on $wasFleeAttempt (flee attempts don't tick — closes the
        # throw-poison-then-spam-Flee cheese) AND on $acted (invalid menu
        # inputs don't tick either — the same exploit through a different
        # door, spotted during the group-combat rework).
        if($acted -and !$fled -and -not $wasFleeAttempt){
            foreach($pe in $combatEnemies){
                if($pe.Poisoned -and $pe.HP -gt 0){
                    $pe.HP -= $pe.PoisonDmg
                    [void]$combatLog.Add(@{Text="   POISON ticks $($pe.DisplayName) for $($pe.PoisonDmg)!";Color="DarkGreen"})
                }
            }
        }

        # ── Kill sweep: credit every enemy that died this action ──
        # Covers target kills, AoE kills, and poison-tick kills alike.
        foreach($ke in $combatEnemies){
            if($ke.HP -le 0 -and -not $ke.KillCredited){
                Credit-EnemyKill $ke
            }
        }

        # ── Player slot ends; enemy slots resolve one at a time ──
        # In the initiative-queue model each enemy occupies its own slot,
        # so the else branch below handles exactly ONE acting enemy. $e
        # is temporarily re-pointed at the actor — the 1v1-era attack
        # code reads attacker state from $e — and restored afterward.
        } else {
            $actingEnemy = $actor.En
            $e = $actingEnemy

        # ── Boss telegraph handling ──
        # If a boss fired its telegraph last turn, this turn it unleashes Inferno.
        # Also: bosses will randomly telegraph 25% of the time their turn starts,
        # giving the player a defensive opening.
        $forcedBossAbility = $null
        if($e.IsBoss){
            if($e.TelegraphNext){
                # Execute the telegraphed move. Bug fix: pull the boss's
                # own strongest damaging ability instead of conjuring a
                # hardcoded Inferno it may not even have — custom bosses
                # telegraph THEIR big move now. Falls back to a generic
                # blast only if the boss somehow has no damage abilities.
                $bigAbil = @($e.Abilities | Where-Object {
                    ($_.Type -eq "Magic" -or $_.Type -eq "Physical") -and [int]$_.Power -gt 0
                } | Sort-Object { [int]$_.Power } -Descending | Select-Object -First 1)
                if($bigAbil.Count -gt 0){
                    $forcedBossAbility = $bigAbil[0]
                } else {
                    $forcedBossAbility = @{Name="Charged Blast";Power=25;Type="Magic"}
                }
                $e.TelegraphNext = $false
                [void]$combatLog.Add(@{Text="<< $($e.DisplayName) UNLEASHES its charged attack!";Color="DarkRed"})
            }
        }

        # ── Enemy turn ──
        # NOTE: the old "$acted" gate is gone — in the initiative-queue
        # model an enemy slot only ever runs after a COMPLETED player
        # action (invalid inputs requeue the player at the front), and a
        # faster-than-player enemy legitimately acts before the player's
        # first action of the fight.
        if($e.HP -gt 0 -and !$fled){
            # Slow no longer makes the enemy lose turns — it reduced their hit% instead
            if($e.Stunned){
                [void]$combatLog.Add(@{Text="<< $($e.DisplayName) is stunned!";Color="Yellow"})
                $e.Stunned = $false
            } else {
                # ── Choose the enemy's action ──
                # Decision tree:
                #   1. Forced boss telegraphed move (always wins)
                #   2. Below 30% HP AND a Heal is off-cooldown -> Heal
                #   3. No buff active AND a Buff is off-cooldown AND 30% chance -> Buff
                #   4. 35% chance to use a damage ability (random off-cooldown one) — caps spam
                #   5. Otherwise: basic Attack
                $eAbility = $null
                if($forcedBossAbility){
                    $eAbility = $forcedBossAbility
                }
                else {
                    $hpPctE = $e.HP / [math]::Max($e.MaxHP, 1)
                    # Support role (Shaman): triggers healing when ANY
                    # living group member is wounded below 60%, not just
                    # itself below 30%. The heal execution below targets
                    # the most-wounded ally.
                    if($e.Role -eq "Shaman"){
                        $woundedAlly = @($combatEnemies | Where-Object {
                            $_.HP -gt 0 -and ($_.HP / [math]::Max($_.MaxHP,1)) -lt 0.60
                        })
                        if($woundedAlly.Count -gt 0){ $hpPctE = 0.1 }
                    }
                    # Filter abilities by category and off-cooldown
                    $allAbil = @($e.Abilities)
                    $healAbil = @($allAbil | Where-Object {
                        $_.Type -eq "Heal" -and (-not $e.AbilityCD.ContainsKey($_.Name) -or $e.AbilityCD[$_.Name] -le 0)
                    })
                    $buffAbil = @($allAbil | Where-Object {
                        $_.Type -eq "Buff" -and (-not $e.AbilityCD.ContainsKey($_.Name) -or $e.AbilityCD[$_.Name] -le 0)
                    })
                    $dmgAbil = @($allAbil | Where-Object {
                        ($_.Type -eq "Physical" -or $_.Type -eq "Magic") -and (-not $e.AbilityCD.ContainsKey($_.Name) -or $e.AbilityCD[$_.Name] -le 0)
                    })
                    $basicAtk = @($allAbil | Where-Object { $_.Type -eq "Normal" })

                    if($hpPctE -lt 0.3 -and $healAbil.Count -gt 0){
                        $eAbility = $healAbil | Get-Random
                    }
                    elseif($e.BuffTurns -le 0 -and $buffAbil.Count -gt 0 -and (Get-Random -Max 100) -lt 30){
                        $eAbility = $buffAbil | Get-Random
                    }
                    elseif($dmgAbil.Count -gt 0 -and (Get-Random -Max 100) -lt 35){
                        $eAbility = $dmgAbil | Get-Random
                    }
                    else {
                        # Fall back to basic Attack (always available, never on cooldown)
                        if($basicAtk.Count -gt 0){
                            $eAbility = $basicAtk[0]
                        } else {
                            $eAbility = @{Name="Attack"; Power=0; Type="Normal"; Cooldown=0}
                        }
                    }
                }

                # ── Resolve the chosen ability ──
                if($eAbility.Type -eq "Heal"){
                    # Heal: no hit roll, no damage. Default target is the
                    # caster itself; a Shaman instead targets the MOST
                    # WOUNDED living group member (by HP ratio) — which
                    # can still be itself.
                    $healTarget = $e
                    if($e.Role -eq "Shaman"){
                        $mostWounded = $null; $worstPct = 2.0
                        foreach($ally in $combatEnemies){
                            if($ally.HP -le 0){ continue }
                            $allyPct = $ally.HP / [math]::Max($ally.MaxHP, 1)
                            if($allyPct -lt $worstPct){ $worstPct = $allyPct; $mostWounded = $ally }
                        }
                        if($mostWounded){ $healTarget = $mostWounded }
                    }
                    $healAmt = $eAbility.Power + [math]::Floor($e.MAG * 0.4)
                    $actualHeal = [math]::Min($healAmt, $healTarget.MaxHP - $healTarget.HP)
                    $healTarget.HP += $actualHeal
                    if($healTarget -eq $e){
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) uses $($eAbility.Name) — restores $actualHeal HP!";Color="Green"})
                    } else {
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) uses $($eAbility.Name) on $($healTarget.DisplayName) — restores $actualHeal HP!";Color="Green"})
                    }
                    # Set cooldown
                    $cd = if($eAbility.Cooldown){[int]$eAbility.Cooldown}else{4}
                    $e.AbilityCD[$eAbility.Name] = $cd
                }
                elseif($eAbility.Type -eq "Buff"){
                    # Buff (ATK+N or DEF+N) for ~3 turns. Default: self.
                    # A Commander instead buffs EVERY living group member
                    # — this is what makes support enemies priority
                    # targets in group fights.
                    $effectStr = "$($eAbility.Effect)"
                    $val = [int]($effectStr -replace '[^0-9]','')
                    $buffTargets = @($e)
                    if($e.Role -eq "Commander"){
                        $buffTargets = @($combatEnemies | Where-Object { $_.HP -gt 0 })
                    }
                    foreach($bt in $buffTargets){
                        if($effectStr -match 'ATK'){ $bt.BonusATK += $val }
                        elseif($effectStr -match 'DEF'){ $bt.BonusDEF += $val }
                        $bt.BuffTurns = 3
                    }
                    $buffStat = if($effectStr -match 'ATK'){"ATK"}else{"DEF"}
                    if($e.Role -eq "Commander" -and $buffTargets.Count -gt 1){
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) uses $($eAbility.Name) — the whole pack gains $buffStat +$val!";Color="DarkCyan"})
                    } else {
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) uses $($eAbility.Name) — $buffStat +$val!";Color="DarkCyan"})
                    }
                    $cd = if($eAbility.Cooldown){[int]$eAbility.Cooldown}else{4}
                    $e.AbilityCD[$eAbility.Name] = $cd
                }
                else {
                    # Damaging ability or basic attack
                    if((Get-Random -Max 100) -ge $e.HitChance){
                        $aName = if($eAbility.Name -eq "Attack"){"attacks"}else{"uses $($eAbility.Name)"}
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) $aName but MISSES!";Color="DarkGray"})
                    } else {
                        # Stance multiplier applies to player DEF before incoming damage calc
                        $totalPlayerDEF = [int][math]::Floor(($p.DEF + $armorDEF + $defBuff + (Get-ArmorSkillDEF) + (Get-SocketBonus "DEF") + (Get-SetBonus "DEF")) * (Get-StanceDEFMult))
                        # Defending DOUBLES the (already-stance-modified) DEF this turn
                        if($playerDefending){ $totalPlayerDEF = $totalPlayerDEF * 2 }

                        $effATK = $e.ATK + $e.BonusATK
                        $effMAG = $e.MAG + $e.BonusATK   # buff helps both
                        # Magically-Charged room: enemy magic +20% too.
                        if($roomFx -eq "Charged"){ $effMAG = [math]::Floor($effMAG * 1.20) }

                        if($eAbility.Type -eq "Normal"){
                            $eRaw = $effATK - [math]::Floor($totalPlayerDEF * 0.5)
                            $eDmg = [math]::Max($eRaw + (Get-Random -Min -2 -Max 3), 1)
                        } else {
                            $eBase = if($eAbility.Type -eq "Magic"){$effMAG}else{$effATK}
                            $eRaw = $eBase + $eAbility.Power - [math]::Floor($totalPlayerDEF * 0.4)
                            $eDmg = [math]::Max($eRaw + (Get-Random -Min -1 -Max 4), 1)
                        }
                        # Enemy crit roll: 2x damage if it lands
                        $eIsCrit = ((Get-Random -Max 100) -lt $e.CritChance)
                        if($eIsCrit){
                            $eDmg *= 2
                            # Brawler Iron Chin: -30% on crits taken
                            if(Has-Talent "Brawler_T2_B"){
                                $eDmg = [math]::Floor($eDmg * 0.70)
                            }
                        }
                        # Glass Cannon mutator: +50% damage taken
                        if(Has-Mutator "GlassCannon"){
                            $eDmg = [math]::Floor($eDmg * 1.5)
                        }
                        # ── Talent damage reductions ──
                        # Brawler Unbreakable: -15% always
                        if(Has-Talent "Brawler_T3_B"){
                            $eDmg = [math]::Floor($eDmg * 0.85)
                        }
                        # Necromancer Bone Shield: -10% always
                        if(Has-Talent "Necromancer_T2_B"){
                            $eDmg = [math]::Floor($eDmg * 0.90)
                        }
                        # Knight Stalwart: -15% when below 30% HP
                        if(Has-Talent "Knight_T2_A" -and $p.HP -lt ($p.MaxHP * 0.30)){
                            $eDmg = [math]::Floor($eDmg * 0.85)
                        }
                        # Knight Guardian: -10% when shield equipped
                        if(Has-Talent "Knight_T3_C" -and $script:EquippedArmor.Shield){
                            $eDmg = [math]::Floor($eDmg * 0.90)
                        }
                        # Mage Mana Shield: -20% if MP > 50%
                        if(Has-Talent "Mage_T2_A" -and $p.MP -gt ($p.MaxMP * 0.50)){
                            $eDmg = [math]::Floor($eDmg * 0.80)
                        }
                        # Cleric Divine Aegis: -20% from magic
                        if(Has-Talent "Cleric_T3_A" -and $eAbility.Type -eq "Magic"){
                            $eDmg = [math]::Floor($eDmg * 0.80)
                        }
                        # Warlock Fiendish Pact: -15% from physical
                        if(Has-Talent "Warlock_T2_C" -and $eAbility.Type -eq "Physical"){
                            $eDmg = [math]::Floor($eDmg * 0.85)
                        }
                        # Warlock Doompact: +25% damage taken (was applied as ATK boost in same tier)
                        if(Has-Talent "Warlock_T3_A"){
                            $eDmg = [math]::Floor($eDmg * 1.25)
                        }
                        # Knight Avatar of Light (T4): -25% all damage taken.
                        # Stacks multiplicatively with other reductions.
                        if(Has-Talent "Knight_T4_A"){
                            $eDmg = [math]::Floor($eDmg * 0.75)
                        }
                        # Ensure damage doesn't drop below 1
                        if($eDmg -lt 1){ $eDmg = 1 }
                        Show-EnemyAttackAnim $eDmg
                        $p.HP -= $eDmg
                        # Skill XP (Phase 4): taking hits trains the majority armor class.
                        # v1.6.2: a MIXED wardrobe used to train nothing
                        # (no majority -> no grant). Mixed now trains
                        # each worn class at half rate.
                        switch(Get-EquippedArmorMajority){
                            "Heavy" { Add-SkillXP "HeavyArmor" 2 }
                            "Light" { Add-SkillXP "LightArmor" 2 }
                            default {
                                $wornCls = @{}
                                foreach($apc in $script:EquippedArmor.Values){
                                    if($apc){ $wornCls[(Get-ArmorWeightClass $apc)] = $true }
                                }
                                if($wornCls["Heavy"]){ Add-SkillXP "HeavyArmor" 1 }
                                if($wornCls["Light"]){ Add-SkillXP "LightArmor" 1 }
                            }
                        }
                        $script:RunStats.DamageTaken += $eDmg
                        $script:TookDamageThisDungeon = $true
                        $aName = if($eAbility.Name -eq "Attack"){"attacks"}else{"uses $($eAbility.Name)"}
                        $defNote = if($playerDefending){" (defended!)"}else{""}
                        if($eIsCrit){
                            [void]$combatLog.Add(@{Text="<< CRITICAL! $($e.DisplayName) $aName for $eDmg!$defNote";Color="Red"})
                        } else {
                            [void]$combatLog.Add(@{Text="<< $($e.DisplayName) $aName for $eDmg!$defNote";Color="Red"})
                        }
                        # Knight Counter-Strike: 20% chance to retaliate after
                        # taking a hit while defending. Damage is half of the
                        # player's totalATK, no perks or crits.
                        if($playerDefending -and (Has-Talent "Knight_T2_B") -and (Get-Random -Max 100) -lt 20 -and $e.HP -gt 0){
                            $cDmg = [math]::Max([math]::Floor($totalATK * 0.5), 1)
                            $e.HP -= $cDmg
                            $script:RunStats.DamageDealt += $cDmg
                            [void]$combatLog.Add(@{Text=">> Counter-Strike! You retaliate for $cDmg!";Color="Yellow"})
                        }
                        # Berserker Pain Tolerance: 25% of damage taken
                        # converts to a 1-turn ATK buff.
                        if(Has-Talent "Berserker_T3_B" -and $eDmg -gt 0){
                            $bumpAmt = [math]::Floor($eDmg * 0.25)
                            if($bumpAmt -gt 0){
                                $atkBuff += $bumpAmt
                                [void]$combatLog.Add(@{Text="   Pain Tolerance: +$bumpAmt ATK next turn";Color="DarkRed"})
                            }
                        }

                        # Armor durability: 50% chance a random equipped piece loses 1
                        if((Get-Random -Max 100) -lt 50){
                            $armorSlots = @("Helmet","Chest","Shield","Amulet","Boots")
                            $wornSlots = @($armorSlots | Where-Object { $script:EquippedArmor[$_] -and $script:EquippedArmor[$_].Durability -gt 0 })
                            if($wornSlots.Count -gt 0){
                                $hitSlot = $wornSlots | Get-Random
                                $piece = $script:EquippedArmor[$hitSlot]
                                $piece.Durability--
                                if($piece.Durability -le 0){
                                    [void]$combatLog.Add(@{Text="   *SNAP* Your $($piece.Name) is DESTROYED — 0 DEF!";Color="Red"})
                                } elseif($piece.Durability -eq [int]($piece.MaxDurability * 0.25)){
                                    [void]$combatLog.Add(@{Text="   Your $($piece.Name) is battered — durability low!";Color="DarkYellow"})
                                }
                            }
                        }
                    }
                    # Set cooldown for ability (basic Attack always has cd=0)
                    if($eAbility.Cooldown -and [int]$eAbility.Cooldown -gt 0){
                        $e.AbilityCD[$eAbility.Name] = [int]$eAbility.Cooldown
                    }

                    # Boss telegraph for next turn (25% chance, if healthy enough)
                    if($e.IsBoss -and -not $e.TelegraphNext -and -not $forcedBossAbility -and (Get-Random -Max 100) -lt 25){
                        $e.TelegraphNext = $true
                        [void]$combatLog.Add(@{Text="<< $($e.DisplayName) begins CHARGING a devastating attack! DEFEND!";Color="DarkYellow"})
                    }
                }
            }

            # Tick down enemy ability cooldowns at end of enemy turn
            if($e.AbilityCD.Count -gt 0){
                $cdKeys = @($e.AbilityCD.Keys)
                foreach($cdN in $cdKeys){
                    if($e.AbilityCD[$cdN] -gt 0){ $e.AbilityCD[$cdN]-- }
                }
            }
            # Tick down enemy buff timer
            if($e.BuffTurns -gt 0){
                $e.BuffTurns--
                if($e.BuffTurns -le 0 -and ($e.BonusATK -gt 0 -or $e.BonusDEF -gt 0)){
                    [void]$combatLog.Add(@{Text="<< $($e.DisplayName)'s buff fades.";Color="DarkGray"})
                    $e.BonusATK = 0
                    $e.BonusDEF = 0
                }
            }
        }
        # Restore the player's chosen target after this enemy's slot.
        $e = $playerTarget
        }

        # ── Player-slot tail: partner assist + round bookkeeping ──
        # These fire once per PLAYER turn (= once per round), never on
        # enemy slots — otherwise luck/cooldowns would tick per enemy.
        if($actor.IsPlayer){
        # ── Partner: Healer ──
        if($script:Partner -and $script:Partner.Class -eq "Healer" -and $p.HP -gt 0 -and !$fled){
            $hpPctCheck = $p.HP / $p.MaxHP
            if($hpPctCheck -lt 0.5 -and (Get-Random -Max 100) -lt 30){
                $partnerHeal = Get-Random -Min 15 -Max 26
                $actualHeal = [math]::Min($partnerHeal, $p.MaxHP - $p.HP)
                $p.HP += $actualHeal
                [void]$combatLog.Add(@{Text="<< $($script:Partner.Name) heals you for $actualHeal HP!";Color="Green"})
            }
        }

        # Decrement Defend cooldown
        if($defendCooldown -gt 0 -and $acted){
            $defendCooldown--
        }

        # Tick down per-ability cooldowns (each acted turn).
        if($acted -and $abilityCooldowns.Count -gt 0){
            $cdKeys = @($abilityCooldowns.Keys)
            foreach($cdName in $cdKeys){
                if($abilityCooldowns[$cdName] -gt 0){
                    $abilityCooldowns[$cdName]--
                }
            }
        }

        # Decrement Luck
        if($script:LuckTurnsLeft -gt 0 -and $acted){
            $script:LuckTurnsLeft--
            if($script:LuckTurnsLeft -le 0){
                $script:LuckBonus = 0
                $playerCritChance = Get-PlayerCrit $effSPD 0
                [void]$combatLog.Add(@{Text="   Luck potion wears off.";Color="DarkGray"})
            }
        }
        }

    }

    # ── Outcome ──
    if($p.HP -le 0){
        # Knight Last Stand: survive lethal damage with 1 HP, once per dungeon.
        if(Has-Talent "Knight_T3_B" -and -not $script:LastStandUsed){
            $p.HP = 1
            $script:LastStandUsed = $true
            [void]$combatLog.Add(@{Text=">> LAST STAND! You refuse to fall — 1 HP remains.";Color="Yellow"})
            if($e.HP -le 0){
                # Enemy also died this turn — fall through to victory.
            } else {
                # The fight continues: the enemy that dropped you is
                # still standing. Re-enter the combat loop at 1 HP.
                [void]$combatLog.Add(@{Text="   The fight is NOT over. Steel yourself!";Color="DarkYellow"})
                $reviveResume = $true
            }
        }
        # Cleric Resurrection: revive at 50% HP, once per dungeon.
        elseif(Has-Talent "Cleric_T3_C" -and -not $script:ResurrectionUsed){
            $p.HP = [math]::Floor($p.MaxHP * 0.50)
            $script:ResurrectionUsed = $true
            [void]$combatLog.Add(@{Text=">> RESURRECTION! Divine light restores you to half HP.";Color="Cyan"})
            if($e.HP -le 0){
                # Enemy also died — victory.
            } else {
                [void]$combatLog.Add(@{Text="   Your killer still stands. The fight continues!";Color="DarkYellow"})
                $reviveResume = $true
            }
        }
        # Berserker Final Stand: at 1 HP grants +50% all stats for the
        # rest of the dungeon, once per dungeon. We store the per-stat
        # deltas in $script:FinalStandBuffs so Reset-MutatorOnEnd can
        # revert them at dungeon end. Without this, the +50% would
        # compound permanently each dungeon (exponential stat growth).
        elseif(Has-Talent "Berserker_T3_C" -and -not $script:FinalStandUsed){
            $p.HP = 1
            $script:FinalStandUsed = $true
            $atkDelta = [math]::Floor($p.ATK * 0.5)
            $defDelta = [math]::Floor($p.DEF * 0.5)
            $spdDelta = [math]::Floor($p.SPD * 0.5)
            $magDelta = [math]::Floor($p.MAG * 0.5)
            $p.ATK += $atkDelta
            $p.DEF += $defDelta
            $p.SPD += $spdDelta
            $p.MAG += $magDelta
            $script:FinalStandBuffs = @{
                ATK = $atkDelta; DEF = $defDelta; SPD = $spdDelta; MAG = $magDelta
            }
            [void]$combatLog.Add(@{Text=">> FINAL STAND! +50% all stats. You will not yield.";Color="Red"})
            if($e.HP -le 0){
                # Continue to victory
            } else {
                # This is the Berserker fantasy: rise at 1 HP, empowered,
                # and finish the fight that nearly finished you.
                [void]$combatLog.Add(@{Text="   Rise. Rage. FINISH IT.";Color="DarkYellow"})
                $reviveResume = $true
            }
        }
        else {
            $p.HP = 0
            # Streak reset
            $script:Streak = 0
            # Clear luck
            $script:LuckTurnsLeft = 0; $script:LuckBonus = 0
            return @{Result="Death"}
        }
    }
    } until(-not $reviveResume)
    if($fled){
        $script:LuckTurnsLeft = 0; $script:LuckBonus = 0
        return @{Result="Fled"}
    }

    # ── Victory ──
    # Per-kill crediting (counters/quests/bestiary) normally fires in
    # the mid-fight kill sweep the moment each enemy dies; this final
    # pass is a defensive net so nothing slips through.
    foreach($ke in $combatEnemies){ Credit-EnemyKill $ke }

    # Ingredient drops are now built into the post-victory loot pile
    # (see "Build loot pile" below) so the player consciously takes them
    # and sees what they got. The previous silent auto-add to
    # $script:Ingredients was confusing — players never saw the drop.

    clr
    Write-CL ("=" * 70) "Green"
    Write-CL "  V I C T O R Y" "Green"
    Write-CL ("=" * 70) "Green"
    Write-Host ""

    # Death dissolve animation on the enemy
    for($fade=0;$fade -lt 3;$fade++){
        clr
        Write-CL ("=" * 70) "Green"
        Write-CL "  V I C T O R Y" "Green"
        Write-CL ("=" * 70) "Green"
        Write-Host ""
        $fadeColor = switch($fade){0{"DarkGray"}1{"DarkBlue"}2{"Black"}}
        foreach($line in $enemyArt){
            Write-CL "  $line" $fadeColor
        }
        Start-Sleep -Milliseconds 140
    }
    clr
    Write-CL ("=" * 70) "Green"
    Write-CL "  V I C T O R Y" "Green"
    Write-CL ("=" * 70) "Green"
    Write-Host ""
    if($combatEnemies.Count -gt 1){
        foreach($ve in $combatEnemies){ Write-CL "  $($ve.DisplayName) defeated!" "Green" }
    } else {
        Write-CL "  $($e.DisplayName) defeated!" "Green"
    }
    Write-CL "  $(Get-VictoryQuip)" "DarkGray"
    Write-Host ""

    # ── Group rewards: XP and gold are summed across every slain
    # member; the multiplier chain (Bard, food, streak, Raven) applies
    # to the group total exactly as it did to a single kill. ──
    $groupXP = 0
    foreach($ve in $combatEnemies){
        $veXP = [int]$ve.XP
        # Blood Moon (Cat 12): the undead are worth DOUBLE tonight.
        if((Get-ActiveRadiantEvent) -eq "BloodMoon" -and $ve.Name -match "Zombie|Skeleton"){
            $veXP = $veXP * 2
        }
        $groupXP += $veXP
    }

    # Apply Bard XP bonus
    $xpGain = $groupXP
    if($script:Partner -and $script:Partner.Class -eq "Bard"){
        $xpBonus = [math]::Floor($groupXP * 0.25)
        $xpGain += $xpBonus
    }
    # Cooking XPBoost: +X% XP from kills
    if($script:ActiveFoodBuff -and $script:ActiveFoodBuff.Effect -eq "XPBoost"){
        $foodMul = [int]$script:ActiveFoodBuff.Value / 100.0
        $foodXP = [math]::Floor($groupXP * $foodMul)
        if($foodXP -gt 0){
            $xpGain += $foodXP
        }
    }
    # Pacifist's Path mutator: kills grant zero XP. Quests completed
    # while this mutator is active have their XP reward tripled at the
    # moment of completion (see Update-QuestProgress); the turn-in
    # screen pays out the boosted reward when the player visits the
    # Quest Board in town.
    if(Has-Mutator "Pacifist"){
        $xpGain = 0
    }
    # Hardcore mutator XP bonus used to fire per-kill, but mutator
    # reward bonuses now apply ONLY at end-of-dungeon clear via the
    # Get-MutatorRewardMul multiplier. Per-kill XP is baseline so a
    # quit-forfeiture rollback maps cleanly to actual earned XP.
    # Blood Moon (Cat 12 rework): undead already doubled at the
    # per-enemy accumulation; the general night bonus softens to +10%.
    if($xpGain -gt 0 -and (Get-ActiveRadiantEvent) -eq "BloodMoon"){
        $xpGain = [math]::Floor($xpGain * 1.10)
    }
    $script:XP += $xpGain
    $script:RunStats.XPEarned += $xpGain
    if($xpGain -gt 0){
        Write-CL "  + $xpGain XP" "Cyan"
    } else {
        Write-CL "  + 0 XP (Pacifist's Path)" "DarkGray"
    }
    if($script:Partner -and $script:Partner.Class -eq "Bard"){
        Write-CL "    ($($script:Partner.Name): +$xpBonus bonus XP)" "DarkCyan"
    }

    # Apply Thief gold bonus, plus streak multiplier
    $groupGold = 0
    foreach($ve in $combatEnemies){ $groupGold += [int]$ve.Gold }
    $goldGain = $groupGold
    if($script:Partner -and $script:Partner.Class -eq "Thief"){
        $goldBonus = [math]::Floor($groupGold * 0.15)
        $goldGain += $goldBonus
    }
    if($script:Streak -ge 2){
        $streakBonus = [math]::Floor($goldGain * 0.15 * [math]::Min($script:Streak, 6))
        $goldGain += $streakBonus
        Write-CL "  + $streakBonus Gold (streak bonus x$($script:Streak))" "Yellow"
    }
    # Raven pet: +5% to combat gold (rounded down)
    $petMul = Get-PetGoldMul
    if($petMul -gt 1.0){
        $petBonus = [math]::Floor($goldGain * ($petMul - 1.0))
        if($petBonus -gt 0){
            $goldGain += $petBonus
            Write-CL "  + $petBonus Gold (Raven's eye)" "DarkYellow"
        }
    }
    # Cooking GoldBoost: +X% gold from kills (stacks with Raven)
    if($script:ActiveFoodBuff -and $script:ActiveFoodBuff.Effect -eq "GoldBoost"){
        $foodMul = [int]$script:ActiveFoodBuff.Value / 100.0
        $foodGold = [math]::Floor($goldGain * $foodMul)
        if($foodGold -gt 0){
            $goldGain += $foodGold
            Write-CL "  + $foodGold Gold (well-fed)" "DarkYellow"
        }
    }
    # Mutator gold modifiers used to fire per-kill, but that put padded
    # gold in the player's bag before they reached the end of the run —
    # which then conflicted with the mutator-active quit-forfeiture rule.
    # Mutator reward bonuses now apply ONLY at the end-of-dungeon clear
    # multiplier (Get-MutatorRewardMul). Per-kill drops are baseline.

    # Gold goes through the loot screen now — flows better visually with the
    # rest of the drops. Always free weight, but listed alongside loot items.

    # ── Build loot pile from this enemy ──
    $lootPile = @()
    if($goldGain -gt 0){
        $lootPile += @{
            Name     = "Gold ($goldGain)"
            Kind     = "Gold"
            Quantity = $goldGain
            Weight   = 0
            Value    = $goldGain
        }
    }
    # ── Per-enemy drops: every slain group member rolls its own loot,
    # gear drops, potion chance, ES roll, ingredients, and key/boss
    # flags. Reuses $e as the loop variable (all enemies are dead at
    # this point); the player's target pointer is restored after.
    foreach($e in @($combatEnemies)){
    if($e.Loot){
        $lootPile += (Init-ItemWeight $e.Loot "Loot")
    }
    # Mini-boss / boss may drop weapon and/or armor (set on enemy by factory)
    # NG+ feature: 20% chance per drop is "Ascended" — +30% ATK/DEF/MAGBonus,
    # marked with the Ascended flag for inventory display.
    if($e.WeaponDrop){
        $w = $e.WeaponDrop
        # Make a defensive copy so we don't mutate the shop template
        if($script:NGPlusLevel -gt 0 -and (Get-Random -Max 100) -lt 20){
            $copy = @{}
            foreach($k in $w.Keys){ $copy[$k] = $w[$k] }
            if($copy.ATK){ $copy.ATK = [math]::Floor($copy.ATK * 1.30) }
            if($copy.MAGBonus){ $copy.MAGBonus = [math]::Floor($copy.MAGBonus * 1.30) }
            $copy.Name = "Ascended " + $copy.Name
            $copy.Ascended = $true
            $copy.Perk = if($copy.Perk){$copy.Perk}else{"Soulbound"}
            $w = $copy
        }
        $lootPile += (Init-ItemWeight $w "Weapon")
    }
    if($e.ArmorDrop){
        $a = $e.ArmorDrop
        if($script:NGPlusLevel -gt 0 -and (Get-Random -Max 100) -lt 20){
            $copy = @{}
            foreach($k in $a.Keys){ $copy[$k] = $a[$k] }
            if($copy.DEF){ $copy.DEF = [math]::Floor($copy.DEF * 1.30) }
            if($copy.MAGBonus){ $copy.MAGBonus = [math]::Floor($copy.MAGBonus * 1.30) }
            $copy.Name = "Ascended " + $copy.Name
            $copy.Ascended = $true
            $a = $copy
        }
        $lootPile += (Init-ItemWeight $a "Armor")
    }
    # Potion drop: regular 12%, mini-boss 25%, boss 40%.
    # Extra Strong potions (Category="Special") are EXCLUDED here — they
    # only drop from end-of-dungeon loot rolls (see the exit-tile handler)
    # and from boss-kills via a separate roll below. Normal enemies
    # cannot drop Extra Strong potions on death.
    $potionDropChance = if($e.IsBoss){40}elseif($e.IsMiniBoss){25}else{12}
    if((Get-Random -Max 100) -lt $potionDropChance){
        $potShop = @(Get-PotionShop | Where-Object { $_.Category -ne "Special" })
        if($potShop -and $potShop.Count -gt 0){
            $potTemplate = $potShop | Get-Random
            $potCopy = @{}
            foreach($k in $potTemplate.Keys){ $potCopy[$k] = $potTemplate[$k] }
            # Determine kind by Type field
            if($potCopy.Type -in @("Throw","ThrowPoison","ThrowSlow")){
                $potCopy.Kind = "Throwable"
            } else {
                $potCopy.Kind = "Potion"
            }
            $potCopy.Weight = 1
            $lootPile += $potCopy
        }
    }
    # Boss-only Extra Strong drop: 35% chance for the slain boss to leave
    # behind a single Extra Strong potion, in addition to the normal loot.
    # This is the second valid spawn point per design (the first being
    # end-of-dungeon clear roll); normal enemies don't roll for ES potions.
    if($e.IsBoss -and (Get-Random -Max 100) -lt 35){
        $espShop = @(Get-PotionShop | Where-Object { $_.Category -eq "Special" })
        if($espShop -and $espShop.Count -gt 0){
            $espTemplate = $espShop | Get-Random
            $espCopy = @{}
            foreach($k in $espTemplate.Keys){ $espCopy[$k] = $espTemplate[$k] }
            $espCopy.Kind   = "Potion"
            $espCopy.Weight = 1
            $lootPile += $espCopy
        }
    }
    # Cooking ingredients: 12% chance per kill, bosses guaranteed.
    # Routed through the loot screen so the player sees the drop and
    # consciously takes it. The take-handler in Show-LootScreen routes
    # Kind="Ingredient" into the $script:Ingredients hashtable.
    if($e.IsBoss -or (Get-Random -Max 100) -lt 12){
        $ingTypes = @("Mushroom","Herb","Meat","Bone")
        $ingType  = $ingTypes | Get-Random
        $ingIcon  = switch($ingType){
            "Mushroom" { "[Mush]" }
            "Herb"     { "[Herb]" }
            "Meat"     { "[Meat]" }
            "Bone"     { "[Bone]" }
            default    { "[Ing]"  }
        }
        $lootPile += @{
            Name           = "$ingType"
            Kind           = "Ingredient"
            IngredientType = $ingType
            Weight         = 1
            Value          = 5
            Icon           = $ingIcon
            Desc           = "A cooking ingredient. Take it to the Inn's pot."
        }
    }
    if($e.DropsKey){
        $script:HasBossKey = $true; $script:Dungeon.HasBossKey = $true
        Write-Host ""
        Write-CL "  *** BOSS KEY ACQUIRED! ***" "Magenta"
        Write-CL "  You can now unlock the Boss Room!" "Magenta"
    }
    if($e.IsBoss){
        $script:BossDefeated = $true; $script:Dungeon.BossDefeated = $true
        Write-Host ""
        Write-CL "  *** DUNGEON BOSS DEFEATED! ***" "Yellow"
        Write-CL "  Find the exit to complete the dungeon!" "Yellow"
        Write-CL "  $(Get-BossDefeatQuip)" "DarkGray"
    }
    }
    # Restore the target pointer after borrowing $e for the drop loop.
    $e = $playerTarget

    # Show loot screen if there's anything droppable
    if($lootPile.Count -gt 0){
        Wait-Key
        $lootTitle = if($combatEnemies.Count -gt 1){"THE SLAIN DROPPED"}else{"$($e.Name) DROPPED"}
        $taken = Show-LootScreen -Title $lootTitle -Items $lootPile
        if($taken.Count -gt 0){
            clr
            Write-Host ""
            Write-CL "  Loot stowed:" "Magenta"
            foreach($t in $taken){
                $kindTag = switch($t.Kind){"Weapon"{"[Wpn]"}"Armor"{"[Arm]"}"Ingredient"{"[Ing]"}"Note"{"[Note]"}default{""}}
                Write-CL "    + $($t.Name) $kindTag" "Magenta"
            }
            Write-Host ""
        } else {
            Write-CL "  Nothing taken." "DarkGray"
            Write-Host ""
        }
    }
    # Level-ups resolve through Grant-XP (Phase 6 extraction) — the
    # ONE leveling routine shared with quest and story rewards.
    Grant-XP

    # Check for achievements after each victory
    Check-Achievements

    Wait-Key
    return @{Result="Won"}
}


# ─── COOKING STATION (v1.5) ───────────────────────────────────────
# Inn-side cooking pot. Combines ingredients (Mushroom/Herb/Meat/Bone)
# dropped from enemies into buff foods that last one full dungeon run.
# The active food buff is cleared on dungeon clear or death. Only ONE
# food buff can be active at a time — eating a new food replaces the
# previous one.
function Show-CookingStation {
    $cookLoop = $true
    while($cookLoop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
        Write-CL "  ║                  T H E   C O O K I N G   P O T          ║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
        Write-Host ""
        # Cooking pot ASCII
        Write-CL "                  ___       ___" "DarkGray"
        Write-CL "                 (   )_____(   )" "DarkGray"
        Write-CL "                  \\___________/" "DarkGray"
        Write-CL "                   |  ~~~~~  |" "DarkRed"
        Write-CL "                   |   ~~~   |" "Red"
        Write-CL "                   \\_________/" "DarkGray"
        Write-CL "                    /       \\" "DarkGray"
        Write-Host ""

        # ── Ingredient inventory ──
        if(-not $script:Ingredients){ $script:Ingredients = @{} }
        $mush = if($script:Ingredients.Mushroom){[int]$script:Ingredients.Mushroom}else{0}
        $herb = if($script:Ingredients.Herb)    {[int]$script:Ingredients.Herb}    else{0}
        $meat = if($script:Ingredients.Meat)    {[int]$script:Ingredients.Meat}    else{0}
        $bone = if($script:Ingredients.Bone)    {[int]$script:Ingredients.Bone}    else{0}

        Write-CL "  ── Ingredients ──" "Yellow"
        Write-CL "    Mushroom: $mush     Herb: $herb     Meat: $meat     Bone: $bone" "DarkGray"
        Write-Host ""

        # ── Active buff status ──
        if($script:ActiveFoodBuff){
            Write-CL "  Active food buff: $($script:ActiveFoodBuff.Name)" "Cyan"
            Write-CL "    $($script:ActiveFoodBuff.Desc)" "DarkCyan"
            Write-CL "    (Wears off when this dungeon ends)" "DarkGray"
        } else {
            Write-CL "  No active food buff." "DarkGray"
        }
        Write-Host ""

        # ── Recipes ──
        # Each recipe consumes specific ingredients and grants a run-long
        # buff. Effects map to flags read by combat / drop code:
        #   "ATKBoost"  — +5 ATK on all attacks (combat math)
        #   "DEFBoost"  — +3 DEF on all damage taken (combat math)
        #   "GoldBoost" — +10% gold from all sources (stacks with Raven)
        #   "XPBoost"   — +15% XP from kills
        $recipes = @(
            @{ Name="Hearty Stew";        Mush=1; Herb=0; Meat=2; Bone=0; Effect="ATKBoost";  Value=5;  Desc="+5 ATK for the run"; Color="Red" }
            @{ Name="Bone Broth";         Mush=0; Herb=2; Meat=0; Bone=2; Effect="DEFBoost";  Value=3;  Desc="+3 DEF for the run"; Color="DarkGray" }
            @{ Name="Forager's Plate";    Mush=2; Herb=2; Meat=0; Bone=0; Effect="GoldBoost"; Value=10; Desc="+10% gold for the run"; Color="Yellow" }
            @{ Name="Hunter's Skewer";    Mush=0; Herb=1; Meat=2; Bone=1; Effect="XPBoost";   Value=15; Desc="+15% XP for the run"; Color="Cyan" }
        )

        Write-CL "  ── Recipes ──" "Yellow"
        for($ri=0; $ri -lt $recipes.Count; $ri++){
            $r = $recipes[$ri]
            $canMake = ($mush -ge $r.Mush -and $herb -ge $r.Herb -and $meat -ge $r.Meat -and $bone -ge $r.Bone)
            $col = if($canMake){$r.Color}else{"DarkGray"}
            $reqParts = @()
            if($r.Mush -gt 0){ $reqParts += "$($r.Mush) Mush" }
            if($r.Herb -gt 0){ $reqParts += "$($r.Herb) Herb" }
            if($r.Meat -gt 0){ $reqParts += "$($r.Meat) Meat" }
            if($r.Bone -gt 0){ $reqParts += "$($r.Bone) Bone" }
            $req = $reqParts -join ", "
            Write-CL "    [$($ri+1)] $($r.Name)" $col
            Write-CL "         Recipe: $req" "DarkGray"
            Write-CL "         Effect: $($r.Desc)" "DarkGray"
        }
        Write-Host ""
        Write-CL "    [0] Leave" "White"
        Write-Host ""
        Write-C "  > " "Yellow"; $cCh = Read-Host

        if($cCh -eq "0"){ $cookLoop = $false; continue }
        $idx = (ConvertTo-SafeInt -Value $cCh) - 1
        if($idx -lt 0 -or $idx -ge $recipes.Count){
            continue
        }
        $r = $recipes[$idx]
        if($mush -lt $r.Mush -or $herb -lt $r.Herb -or $meat -lt $r.Meat -or $bone -lt $r.Bone){
            Write-CL "  Not enough ingredients for $($r.Name)." "Red"
            Wait-Key
            continue
        }
        if($script:ActiveFoodBuff){
            Write-Host ""
            Write-CL "  You already have a food buff active: $($script:ActiveFoodBuff.Name)" "Yellow"
            Write-CL "  Eating $($r.Name) will replace it." "DarkYellow"
            Write-C "  Continue? (y/n): " "White"; $cf = Read-Host
            if($cf -ne 'y' -and $cf -ne 'Y'){ continue }
        }
        # Consume ingredients
        $script:Ingredients.Mushroom = $mush - $r.Mush
        $script:Ingredients.Herb     = $herb - $r.Herb
        $script:Ingredients.Meat     = $meat - $r.Meat
        $script:Ingredients.Bone     = $bone - $r.Bone
        # Set active buff
        $script:ActiveFoodBuff = @{
            Name   = $r.Name
            Effect = $r.Effect
            Value  = $r.Value
            Desc   = $r.Desc
        }
        Write-Host ""
        Write-CL "  You eat $($r.Name). $($r.Desc)" $r.Color
        Write-CL "  This buff persists until your next dungeon ends." "DarkGray"
        Wait-Key
    }
}

# ─── PET KENNEL (v1.5) ────────────────────────────────────────────
# Sub-shop accessed from the Guild Hall. Exactly 3 pets — Hound, Raven,
# Falcon — each with one passive perk. Player can own ONE pet at a time.
# Buying a new pet refunds 50% of the prior pet's cost.
function Show-PetKennel {
    $kennelLoop = $true
    while($kennelLoop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkMagenta"
        Write-CL "  ║                    T H E   K E N N E L                   ║" "Magenta"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkMagenta"
        Write-Host ""
        # Kennel ASCII (small)
        Write-CL "             /\___/\           //\          " "DarkYellow"
        Write-CL "            (  o.o  )         /  \      ___ " "Yellow"
        Write-CL "             >  v  <         (    )    /(*)\\" "DarkYellow"
        Write-CL "          /\/  HOUND  \/\   /  RAVEN  \/  FALCON" "DarkGray"
        Write-Host ""

        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-Host ""

        if($script:Pet){
            Write-CL "  Current Pet: $($script:Pet.Type)" "Cyan"
            Write-CL "    $($script:Pet.Desc)" "DarkGray"
            Write-Host ""
        } else {
            Write-CL "  You have no pet." "DarkGray"
            Write-Host ""
        }

        $pets = @(
            @{ Type="Hound";  Price=500; Desc="Reveals chests on the minimap regardless of fog" }
            @{ Type="Raven";  Price=650; Desc="+5% gold from all sources" }
            @{ Type="Falcon"; Price=600; Desc="Minimap reveal radius increased (5 -> 8)"      }
        )

        Write-CL "  ── Available Pets ──" "Yellow"
        for($pi=0; $pi -lt $pets.Count; $pi++){
            $p = $pets[$pi]
            $owned = ($script:Pet -and $script:Pet.Type -eq $p.Type)
            $afford = ($script:Gold -ge $p.Price)
            $col = if($owned){"DarkGray"}elseif($afford){"Green"}else{"Red"}
            $tag = if($owned){" [OWNED]"}else{""}
            Write-CL "    [$($pi+1)] $($p.Type)  ($($p.Price)g)$tag" $col
            Write-CL "         $($p.Desc)" "DarkGray"
        }
        Write-Host ""
        if($script:Pet){
            Write-CL "    [R] Release current pet (50% refund)" "DarkYellow"
        }
        Write-CL "    [0] Back" "White"
        Write-Host ""
        Write-C "  > " "Yellow"; $kCh = Read-Host

        switch($kCh.ToUpper()){
            {$_ -in @("1","2","3")} {
                $pIdx = [int]$_ - 1
                $newPet = $pets[$pIdx]
                if($script:Pet -and $script:Pet.Type -eq $newPet.Type){
                    Write-CL "  You already have a $($newPet.Type)." "DarkGray"
                    Wait-Key
                } elseif($script:Gold -lt $newPet.Price){
                    Write-CL "  Not enough gold! Need $($newPet.Price)g." "Red"
                    Wait-Key
                } else {
                    if($script:Pet){
                        # Find the old pet's price for refund
                        $oldPrice = ($pets | Where-Object { $_.Type -eq $script:Pet.Type } | Select-Object -First 1).Price
                        $refund = [math]::Floor($oldPrice * 0.5)
                        $script:Gold += $refund
                        Write-CL "  Released your $($script:Pet.Type) for ${refund}g refund." "DarkYellow"
                    }
                    $script:Gold -= $newPet.Price
                    $script:Pet = @{ Type = $newPet.Type; Desc = $newPet.Desc }
                    Write-Host ""
                    Write-CL "  $($newPet.Type) bonded with you!" "Green"
                    Wait-Key
                }
            }
            "R" {
                if($script:Pet){
                    Write-C "  Release your $($script:Pet.Type)? (y/n): " "Red"
                    $confirm = Read-Host
                    if($confirm -eq 'y'){
                        $oldPrice = ($pets | Where-Object { $_.Type -eq $script:Pet.Type } | Select-Object -First 1).Price
                        $refund = [math]::Floor($oldPrice * 0.5)
                        $script:Gold += $refund
                        Write-CL "  Your $($script:Pet.Type) wanders off. Refunded ${refund}g." "DarkGray"
                        $script:Pet = $null
                        Wait-Key
                    }
                }
            }
            "0" { $kennelLoop = $false }
        }
    }
}

# ── Phase 6: THE MAIN STORY — "THE FINAL MIGRATION" (Cat 13.1) ─────
# Persistence: SF ids "msq" (stage = quest# * 10 + phase; phase 0 =
# cutscene pending, 1 = active) and "msqa" (aux/baseline for the
# current quest). Story rows appear in town and at bound locations.
# NG+ gate swaps to story completion when the finale ships (locked).
function Get-MainStage { Get-QuestStage "msq" }
function Get-MainAux   { Get-QuestStage "msqa" }

# Paced cutscene helper: lines of @{T;C}, gentle sleep, Enter to end.
function Show-Cutscene {
    param($Lines, [string]$Title = "")
    clr
    Write-Host ""
    if($Title){
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
        $ctPad = [math]::Max([math]::Floor((60 - $Title.Length) / 2), 0)
        Write-C  "  ║" "DarkYellow"
        Write-C ((" " * $ctPad) + $Title + (" " * (60 - $ctPad - $Title.Length))) "Yellow"
        Write-CL "║" "DarkYellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""
    }
    foreach($cl in $Lines){
        Write-CL "  $($cl.T)" $cl.C
        Start-Sleep -Milliseconds 350
    }
    Write-Host ""
    Wait-Enter
}

# The quest table. Where: "town" or a location id. Types reuse the
# established delta/threshold objective mechanics.
function Get-MainQuests {
    @(
        @{ N=1; Id="unreturned"; Title="The Unreturned"; Where="town"; Type="Clear"; Need=1;
           Hint="Clear one full dungeon — boss down, exit reached." }
        @{ N=2; Id="margins"; Title="Marn's Margins"; Where="town"; Type="Journal"; Need=3;
           Hint="Recover 3 pages of Marn's journal from the Depths' chests." }
        @{ N=3; Id="courier"; Title="The Courier Who Blinked"; Where="syslogxing"; Type="Depth"; Need=8;
           Hint="Descend to floor 8 of the Depths and see it yourself." }
        @{ N=4; Id="rootcause"; Title="Root Cause"; Where="town"; Type="Nemesis"; Need=1;
           Hint="Bring Root down once. He will not stay down. Do it anyway." }
        # ── ACT II ──
        @{ N=5; Id="registry"; Title="The Registry Remembers"; Where="registry"; Type="Collect"; ItemName="Dark Shard"; Need=2;
           Hint="Bring 2 Dark Shards — index keys to unseal the Migration file." }
        @{ N=6; Id="rehearsal"; Title="The Rehearsal"; Where="sysv"; Type="Warden"; Need=1;
           Hint="Defeat WARDEN PRIME in the Patrol Vaults beneath Sys-V." }
        @{ N=7; Id="lens"; Title="A Lens of Shadow"; Where="town"; Type="Collect"; ItemName="Shadow Gem"; Need=1;
           Hint="The Cabal reads schedules through shadow. Bring 1 Shadow Gem." }
        @{ N=8; Id="schedule"; Title="The Schedule"; Where="cronmarch"; Type="Depth"; Need=14;
           Hint="Verify the deep route: reach floor 14 of the Depths." }
        # ── ACT III ──
        @{ N=9; Id="sweeper"; Title="Sever the Sweeper"; Where="town"; Type="Nemesis"; Need=3;
           Hint="End Root — terminate him on the deep floors, for good." }
        @{ N=10; Id="migration"; Title="The Final Migration"; Where="town"; Type="Migration"; Need=1;
           Hint="Descend past floor 16. Be there before the Blood Moon is." }
    )
}

function Get-CurrentMainQuest {
    $st = Get-MainStage
    if($st -eq 0){ return (Get-MainQuests)[0] }   # story not started: quest 1 pending
    $qn = [math]::Floor($st / 10)
    foreach($mq in (Get-MainQuests)){ if($mq.N -eq $qn){ return $mq } }
    return $null   # beyond authored content (act break)
}

function Get-MainQuestProgress {
    param($MQ)
    $aux = Get-MainAux
    switch($MQ.Type){
        "Clear"   { [int]$script:DungeonsCleared - $aux }
        "Journal" { @($script:JournalPages.Keys).Count }
        "Depth"   { [int]$script:DeepestFloor }
        "Nemesis" { [int]$script:NemesisStage }
        "Warden"  { if((Get-QuestStage "wp_down") -eq 999999){ 1 } else { 0 } }
        "Migration" { if((Get-QuestStage "lk_down") -eq 999999){ 1 } else { 0 } }
        "Collect" { Get-NamedItemCount $MQ.ItemName }
        default   { 0 }
    }
}

# The story driver: cutscene phase plays the beat, active phase shows
# progress and advances on completion. One quest at a time, in order.
function Show-StoryQuest {
    param([string]$Context = "town")
    $st = Get-MainStage
    $mq = Get-CurrentMainQuest
    if(-not $mq){
        clr; Write-Host ""
        Write-CL "  ── THE FINAL MIGRATION ──" "Yellow"
        Write-Host ""
        if($st -ge 999){
            Write-CL "  The board's UP side fills a little more every day now." "Gray"
            Write-CL "  Tickets go down. Tickets come back. The Migration is" "Gray"
            Write-CL "  CANCELLED — stamped, filed, and initialed by you." "Yellow"
            Write-Host ""
            Write-CL "  (New Game+ is open at the town's [N] mark.)" "Magenta"
        } else {
            Write-CL "  The trail has gone quiet — for now. The story continues" "Gray"
            Write-CL "  in a coming update." "DarkGray"
        }
        Write-Host ""; Wait-Enter; return
    }
    $phase = $st % 10
    if($st -eq 0 -or $phase -eq 0){
        # ── Cutscene phase — but only where the trail actually IS.
        # Elsewhere, point the player at it (quests send you around
        # the map — user requirement).
        if($mq.Where -ne $Context){
            clr; Write-Host ""
            Write-CL "  ── STORY: $($mq.Title) ──" "Yellow"
            $whereName = if($mq.Where -eq "town"){"Helpdesk"}else{ (Get-WorldLocation $mq.Where).Name }
            Write-CL "  The trail leads to $whereName." "Red"
            Write-CL "  (Travel there and look for the [!] mark.)" "DarkGray"
            Write-Host ""; Wait-Enter; return
        }
        # ── Cutscene phase ──
        switch($mq.N){
            1 {
                Show-Cutscene -Title "THE FINAL MIGRATION — I" -Lines @(
                    @{T="The Helpdesk ticket board has two sides.";                      C="Gray"}
                    @{T="DOWN: requests sent into the Depths. Sealing jobs.";            C="DarkGray"}
                    @{T="Retrieval jobs. The occasional exorcism, misfiled.";            C="DarkGray"}
                    @{T="UP: the completions. The board's other side.";                  C="DarkGray"}
                    @{T="";                                                             C="Gray"}
                    @{T="The UP side has been empty for nineteen days.";                 C="Yellow"}
                    @{T="";                                                             C="Gray"}
                    @{T="The clerk stamps your form without looking at it.";             C="Gray"}
                    @{T="'Go down. Finish something. Come BACK. That last part";         C="Red"}
                    @{T=" is the part nobody has managed lately.'";                      C="Red"}
                )
                Set-QuestStage "msqa" ([int]$script:DungeonsCleared)
                Set-QuestStage "msq" 11
            }
            9 {
                Show-Cutscene -Title "THE FINAL MIGRATION — IX" -Lines @(
                    @{T="The clerk stands. The whole Guild hall stands with her.";       C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'ROOT.'";                                                    C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="The name lands like a dropped tray. Nobody breathes.";          C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'He is sweeping the Migration's road from below. Every";      C="Yellow"}
                    @{T=" floor he clears is a floor THEY do not have to fight";         C="Yellow"}
                    @{T=" for. Sever the sweeper. TERMINATE him. Then we talk";          C="Yellow"}
                    @{T=" about what is behind him.'";                                  C="Red"}
                )
                Set-QuestStage "msq" 91
            }
            10 {
                Show-Cutscene -Title "THE FINAL MIGRATION — X" -Lines @(
                    @{T="The town is quiet the way servers are quiet before a";          C="Gray"}
                    @{T="deploy: everything held, nothing resting.";                     C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'The sweeper is severed. The route is floor sixteen";          C="Yellow"}
                    @{T=" and falling, and the next Blood Moon is close enough";         C="Yellow"}
                    @{T=" to read by.'";                                                C="Yellow"}
                    @{T="";                                                             C="Gray"}
                    @{T="The clerk hands you a ticket. The form is blank except";        C="Gray"}
                    @{T="for the priority field, which says only: LAST.";                C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="'Go down past sixteen. Be there FIRST. Close it.'";           C="Red"}
                )
                Set-QuestStage "msq" 101
            }
            5 {
                Show-Cutscene -Title "THE FINAL MIGRATION — V" -Lines @(
                    @{T="The Registry's reading room smells of dust and policy.";       C="Gray"}
                    @{T="An archivist descends a ladder holding a file at arm's";       C="Gray"}
                    @{T="length, the way one carries a wasp.";                           C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="MIGRATION PLAN: FINAL.";                                        C="Red"}
                    @{T="AUTHOR: [REDACTED]. STATUS: SCHEDULED.";                        C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="'The body of the file is index-sealed. Old craft. It";        C="Yellow"}
                    @{T=" wants two Dark Shards to open, and I want to be in";           C="Yellow"}
                    @{T=" another wing when it does.'";                                 C="Yellow"}
                )
                Set-QuestStage "msq" 51
            }
            6 {
                Show-Cutscene -Title "THE FINAL MIGRATION — VI" -Lines @(
                    @{T="The unsealed file is short. That is the worst part.";           C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="PHASE 0: REHEARSAL — SITE: SYS-V. RESULT: SEE SITE.";           C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="Sys-V. The Ruined City. Its defenses still patrol";              C="Gray"}
                    @{T="streets nobody lives on — because the Migration was";            C="Gray"}
                    @{T="TESTED there, and the wardens never stood down.";                C="Yellow"}
                    @{T="";                                                             C="Gray"}
                    @{T="End the rehearsal. Bring down WARDEN PRIME in the";              C="Red"}
                    @{T="Patrol Vaults, and read what it was guarding.";                  C="Red"}
                )
                Set-QuestStage "msq" 61
            }
            7 {
                Show-Cutscene -Title "THE FINAL MIGRATION — VII" -Lines @(
                    @{T="Warden Prime's core held one line of orders:";                  C="Gray"}
                    @{T="HOLD SITE UNTIL PROD CUTOVER.";                                  C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="Cutover. A DATE exists. The Guild's clerks cannot read";        C="Gray"}
                    @{T="it — the schedule is written in shadow-notation.";               C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="A Cabal envoy materializes near your elbow, which is";           C="Gray"}
                    @{T="rude, and offers, which is worse:";                              C="Gray"}
                    @{T="'Bring a Shadow Gem. We will grind it to a lens and";           C="Yellow"}
                    @{T=" READ the thing. Corruption is a feature, remember.'";          C="Yellow"}
                )
                Set-QuestStage "msq" 71
            }
            8 {
                Show-Cutscene -Title "THE FINAL MIGRATION — VIII" -Lines @(
                    @{T="Cronmarch. Where everything happens on schedule.";               C="Gray"}
                    @{T="The Scheduler sets the shadow-lens on the decoded page";         C="Gray"}
                    @{T="and goes very, very still.";                                    C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'CUTOVER WINDOW: NEXT SUITABLE BLOOD MOON.";                   C="Red"}
                    @{T=" SOURCE ENVIRONMENT: THE DEPTHS.";                              C="Red"}
                    @{T=" TARGET ENVIRONMENT: ...everything else.'";                    C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="'The deep route runs through floor fourteen. VERIFY it.";      C="Yellow"}
                    @{T=" If the way is open for you, it is open for THEM.'";            C="Yellow"}
                )
                Set-QuestStage "msq" 81
            }
            4 {
                Show-Cutscene -Title "THE FINAL MIGRATION — IV" -Lines @(
                    @{T="You describe the badge. The clerk stops writing.";              C="Gray"}
                    @{T="She pulls a roster so old its cover is soft as cloth,";         C="Gray"}
                    @{T="and turns to a page that has been turned to before.";           C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'ROOT. Field administrator, first class. Descended";           C="Yellow"}
                    @{T=" before Marn. Never filed a resignation.'";                    C="Yellow"}
                    @{T="";                                                             C="Gray"}
                    @{T="'The Guild does not say his name. It stamps his file";         C="Red"}
                    @{T=" UNRESOLVED and files it under the floor.'";                   C="Red"}
                    @{T="";                                                             C="Gray"}
                    @{T="She slides the roster across the counter.";                     C="Gray"}
                    @{T="'Resolve it. Once will do — for now. He is not the";           C="Yellow"}
                    @{T=" disease. But he is the fever, and fevers get MEASURED.'";     C="Yellow"}
                )
                Set-QuestStage "msq" 41
            }
            3 {
                Show-Cutscene -Title "THE FINAL MIGRATION — III" -Lines @(
                    @{T="The Crossing's log-keeper flips back nineteen days";          C="Gray"}
                    @{T="without being asked. Everyone has been counting.";             C="Gray"}
                    @{T="";                                                            C="Gray"}
                    @{T="'One courier came up. ONE. He crossed at night, paid";        C="Yellow"}
                    @{T=" double to be unlisted, and his hands would not stop.'";      C="Yellow"}
                    @{T="";                                                            C="Gray"}
                    @{T="'He said below floor eight, the tickets are STACKED.";        C="Yellow"}
                    @{T=" Sorted. Filed. And something wearing a Guild badge";          C="Yellow"}
                    @{T=" is doing the filing, in the dark, alone.'";                  C="Red"}
                    @{T="";                                                            C="Gray"}
                    @{T="The log-keeper closes the book.";                              C="Gray"}
                    @{T="'Floor eight. See it yourself. Then tell SOMEBODY.'";        C="Red"}
                )
                Set-QuestStage "msq" 31
            }
            2 {
                Show-Cutscene -Title "THE FINAL MIGRATION — II" -Lines @(
                    @{T="You came back. The clerk stares like you are a rounding";       C="Gray"}
                    @{T="error that walked in and ordered lunch.";                        C="Gray"}
                    @{T="";                                                             C="Gray"}
                    @{T="'One return in nineteen days. And the one before you —'";       C="Yellow"}
                    @{T="She checks a ledger. Her finger stops.";                        C="Gray"}
                    @{T="'MARN. Field sysadmin. Never clocked out. His journal";         C="Yellow"}
                    @{T=" is still down there, page by page. Company property,";         C="Yellow"}
                    @{T=" technically. And the margins... Marn NOTICED things.'";        C="Yellow"}
                )
                Set-QuestStage "msq" 21
            }
        }
        return
    }
    # ── Active phase ──
    clr; Write-Host ""
    Write-CL "  ── STORY: $($mq.Title) ──" "Yellow"
    Write-CL "  $($mq.Hint)" "Gray"
    $prog = Get-MainQuestProgress $mq
    if($prog -lt 0){ $prog = 0 }
    Write-CL "  Progress: $prog / $($mq.Need)" "Cyan"
    if($prog -ge $mq.Need){
        Write-Host ""
        switch($mq.N){
            1 {
                Write-CL "  You slap the completed ticket on the UP side of the" "Gray"
                Write-CL "  board. The whole room exhales." "Gray"
                $script:Gold += 150
                Grant-XP 120
                Write-CL "  *** Story quest complete: The Unreturned! (+150g) ***" "Magenta"
                Set-QuestStage "msq" 20   # quest 2, cutscene pending
            }
            2 {
                Write-CL "  Three pages, pressed flat. The clerk reads the margins" "Gray"
                Write-CL "  twice, then locks the door before reading them again." "Gray"
                Write-CL "  'Marn was tracking something with a BADGE...'" "Yellow"
                $script:Gold += 200
                Grant-XP 180
                Write-CL "  *** Story quest complete: Marn's Margins! (+200g) ***" "Magenta"
                Write-CL "  'A badge... ask at SYSLOG CROSSING. They log everyone.'" "Red"
                Set-QuestStage "msq" 30   # quest 3: cutscene waits at the Crossing
            }
            3 {
                Write-CL "  Floor eight. You saw the stacked tickets. You saw the" "Gray"
                Write-CL "  badge in the dark — and it saw you." "Gray"
                $script:Gold += 250
                Grant-XP 200
                Write-CL "  *** Story quest complete: The Courier Who Blinked! (+250g) ***" "Magenta"
                Write-CL "  The thing with the badge has a name. You will hear it" "Red"
                Write-CL "  again, deeper down." "Red"
                Set-QuestStage "msq" 40   # quest 4: the name gets said
            }
            4 {
                Write-CL "  You put the roster back on the counter, and next to it," "Gray"
                Write-CL "  your report: ENCOUNTERED. ENGAGED. DRIVEN OFF." "Gray"
                Write-CL "  The clerk stamps the file RESOLVED (PARTIAL), which is" "Gray"
                Write-CL "  the most optimistic stamp the Guild owns." "Gray"
                $script:Gold += 300
                Grant-XP 250
                Write-CL "  *** Story quest complete: Root Cause! (+300g) ***" "Magenta"
                Write-CL "  *** ACT I COMPLETE. The fever is measured. The disease" "Red"
                Write-CL "  is still scheduling something, far below. ***" "Red"
                Set-QuestStage "msq" 50   # Act II opens at the Registry
            }
            5 {
                Remove-Gems "Dark Shard" 2
                Write-CL "  The shards click into the file's index-locks. The seal" "Gray"
                Write-CL "  releases with a sound like a held breath, twenty years old." "Gray"
                $script:Gold += 220
                Grant-XP 200
                Write-CL "  *** Story quest complete: The Registry Remembers! (+220g) ***" "Magenta"
                Set-QuestStage "msq" 60   # the rehearsal site: Sys-V
            }
            6 {
                Write-CL "  The Patrol Vaults stand down, one servo at a time. In" "Gray"
                Write-CL "  the sudden quiet, Sys-V sounds like a city again. Almost." "Gray"
                $script:Gold += 300
                Grant-XP 260
                Write-CL "  *** Story quest complete: The Rehearsal! (+300g) ***" "Magenta"
                Set-QuestStage "msq" 70   # the Cabal's offer, in town
            }
            7 {
                Remove-Gems "Shadow Gem" 1
                Write-CL "  The Cabal grinds the gem between two words you did not" "Gray"
                Write-CL "  catch. The lens they hand back is heavier than it looks." "Gray"
                $script:Gold += 180
                Grant-XP 200
                Write-CL "  *** Story quest complete: A Lens of Shadow! (+180g) ***" "Magenta"
                Write-CL "  'Take it to a Scheduler. We suggest CRONMARCH. Politely.'" "Red"
                Set-QuestStage "msq" 80   # the schedule, at Cronmarch
            }
            8 {
                Write-CL "  Floor fourteen, verified. The route is open — a road" "Gray"
                Write-CL "  someone has been sweeping from the OTHER end." "Gray"
                $script:Gold += 350
                Grant-XP 300
                Write-CL "  *** Story quest complete: The Schedule! (+350g) ***" "Magenta"
                Write-CL "  *** ACT II COMPLETE. The date is a Blood Moon. The route" "Red"
                Write-CL "  is floor fourteen and falling. ***" "Red"
                Set-QuestStage "msq" 90   # Act III: the name gets shouted
            }
            9 {
                Write-CL "  You lay Root's badge on the counter. The clerk does not" "Gray"
                Write-CL "  reach for a stamp. She writes it out by hand:" "Gray"
                Write-CL "  RESOLVED. FULL." "Yellow"
                $script:Gold += 400
                Grant-XP 350
                Write-CL "  *** Story quest complete: Sever the Sweeper! (+400g) ***" "Magenta"
                Set-QuestStage "msq" 100   # the LAST ticket
            }
        }
        Write-Host ""; Wait-Enter
    } else {
        Write-Host ""; Wait-Enter
    }
}

# ── Phase 6: GUILD CHARTERS (Cat 10) ───────────────────────────────
# Three formal guilds inside the Adventurers' Guild Hall. Questlines
# are 3 sequential stages on the town-quest SF encoding (per-stage
# ids), objectives ride existing lifetime counters. Defection resets
# the questline and forfeits 100g (switchable-with-penalty lock).
function Get-GuildDefs {
    @(
        @{ Id="sysadmins";   Name="The SysAdmins' Guild";          Color="Cyan";
           Motto="Purify. Patch. Persist.";
           Blurb="Sealing anomalies and recovering what the Depths swallowed.";
           Stages=@(
               @{ Sid="gq_sys1"; Label="Cleanse the shallows";   Type="Kill";    Need=8;  Text="'Eight hostile processes, terminated cleanly. Show us your uptime.'" }
               @{ Sid="gq_sys2"; Label="Recover the artifact";   Type="Collect"; ItemName="Golden Idol"; Need=1; Text="'A Golden Idol was lost below. Guild property. Bring it home.'" }
               @{ Sid="gq_sys3"; Label="Seal an anomaly";        Type="Clear";   Need=1;  Text="'Take a dungeon to its end and CLOSE it. Boss down, exit reached.'" }
           );
           RewardText="the FIREWALL PLATE (DEF+17) and 100g" }
        @{ Id="datathieves"; Name="The Data-Thieves' Collective"; Color="DarkMagenta";
           Motto="Everything is readable. Eventually.";
           Blurb="Espionage, acquisitions, and doors that were never locked, officially.";
           Stages=@(
               @{ Sid="gq_dt1"; Label="Prove your touch";        Type="Locks";   Need=3;  Text="'Three locks, opened, not broken. We can hear the difference.'" }
               @{ Sid="gq_dt2"; Label="A discreet acquisition";  Type="Collect"; ItemName="Shadow Gem"; Need=2; Text="'Two Shadow Gems. Do not ask what for. That is lesson one.'" }
               @{ Sid="gq_dt3"; Label="Quiet eliminations";      Type="Kill";    Need=10; Text="'Ten problems, solved. The kind that used to walk around.'" }
           );
           RewardText="the WHISPERSTEP BOOTS (DEF+8, light) and 5 lockpicks" }
        @{ Id="cabal";       Name="The Cabal of Forgotten Code";  Color="Red";
           Motto="Corruption is a feature.";
           Blurb="Warlocks who read the Depths' rot like release notes.";
           Stages=@(
               @{ Sid="gq_cab1"; Label="Let it in";              Type="Corrupt"; Need=40; Text="'Let the world's corruption reach 40. Feel it. Do not flinch.'" }
               @{ Sid="gq_cab2"; Label="Tribute of horn";        Type="Collect"; ItemName="Demon Horn"; Need=2; Text="'Two Demon Horns. The old code answers to old currencies.'" }
               @{ Sid="gq_cab3"; Label="Unmake a king";          Type="Boss";    Need=1;  Text="'Bring down one of the crowned things below. Any of them.'" }
           );
           RewardText="the GRIMOIRE OF FORGOTTEN CODE (amulet, DEF+6) and +2 MAG, permanent" }
    )
}

function Get-GuildDef {
    param([string]$Id)
    foreach($gd in (Get-GuildDefs)){ if($gd.Id -eq $Id){ return $gd } }
    return $null
}

function Show-GuildCharters {
    $gcLoop = $true
    while($gcLoop){
        clr
        Write-Host ""
        Write-CL "  ── G U I L D   C H A R T E R S ──" "Yellow"
        Write-Host ""
        if(-not $script:GuildMembership){
            Write-CL "  Three charters hang behind the counter. The clerk waits." "Gray"
            Write-Host ""
            $gds = Get-GuildDefs
            for($gi = 0; $gi -lt $gds.Count; $gi++){
                Write-C  "  [$($gi + 1)] " "White"
                Write-CL "$($gds[$gi].Name)" $gds[$gi].Color
                Write-CL "      '$($gds[$gi].Motto)' — $($gds[$gi].Blurb)" "DarkGray"
            }
            Write-CL "  [0] Not today" "DarkGray"
            Write-C  "  > " "Yellow"
            $gc = Read-Host
            if($gc -in @("1","2","3")){
                $joined = (Get-GuildDefs)[[int]$gc - 1]
                $script:GuildMembership = $joined.Id
                Write-Host ""
                Write-CL "  You sign the charter of $($joined.Name)." $joined.Color
                Write-CL "  '$($joined.Motto)'" "DarkGray"
                Write-Host ""
                Wait-Enter
            } else { $gcLoop = $false }
            continue
        }
        # ── Member view ──
        $gd = Get-GuildDef $script:GuildMembership
        Write-C  "  Member of " "Gray"
        Write-CL "$($gd.Name)" $gd.Color
        Write-CL "  '$($gd.Motto)'" "DarkGray"
        Write-Host ""
        # Find the current stage (first not-done)
        $curStage = $null; $stageNum = 0
        for($si = 0; $si -lt $gd.Stages.Count; $si++){
            if((Get-QuestStage $gd.Stages[$si].Sid) -ne 999999){ $curStage = $gd.Stages[$si]; $stageNum = $si + 1; break }
        }
        if(-not $curStage){
            Write-CL "  Your questline is COMPLETE. The charter remembers." "Yellow"
            Write-Host ""
            Write-CL "  [X] Defect (forfeit 100g dues; questline resets)   [0] Back" "DarkGray"
        } else {
            $st = Get-QuestStage $curStage.Sid
            Write-CL "  Stage ${stageNum}/3: $($curStage.Label)" "Cyan"
            if($st -eq 0){
                Write-CL "  $($curStage.Text)" "Yellow"
                Write-Host ""
                Write-CL "  [1] Accept the work   [X] Defect (100g penalty)   [0] Back" "White"
            } else {
                $aux = $st - 100000
                $prog = switch($curStage.Type){
                    "Kill"    { [int]$script:TotalKills - $aux }
                    "Locks"   { [int]$script:TotalLocksPicked - $aux }
                    "Clear"   { [int]$script:DungeonsCleared - $aux }
                    "Boss"    { [int]$script:BossesDefeated - $aux }
                    "Corrupt" { [int]$script:Corruption }
                    "Collect" { Get-NamedItemCount $curStage.ItemName }
                }
                if($prog -lt 0){ $prog = 0 }
                Write-CL "  Progress: $prog / $($curStage.Need)" "White"
                if($prog -ge $curStage.Need){
                    Write-CL "  READY TO TURN IN." "Green"
                    Write-Host ""
                    Write-CL "  [1] Turn in   [X] Defect (100g penalty)   [0] Back" "White"
                } else {
                    Write-Host ""
                    Write-CL "  [X] Defect (100g penalty)   [0] Back" "DarkGray"
                }
            }
        }
        Write-C  "  > " "Yellow"
        $gc = Read-Host
        switch($gc.ToUpper()){
            "1" {
                if(-not $curStage){ continue }
                $st = Get-QuestStage $curStage.Sid
                if($st -eq 0){
                    $aux = switch($curStage.Type){
                        "Kill"    { [int]$script:TotalKills }
                        "Locks"   { [int]$script:TotalLocksPicked }
                        "Clear"   { [int]$script:DungeonsCleared }
                        "Boss"    { [int]$script:BossesDefeated }
                        default   { 0 }
                    }
                    Set-QuestStage $curStage.Sid (100000 + $aux)
                    Write-Host ""
                    Write-CL "  *** Stage accepted: $($curStage.Label) ***" $gd.Color
                    Write-Host ""; Wait-Enter
                } else {
                    $aux = $st - 100000
                    $prog = switch($curStage.Type){
                        "Kill"    { [int]$script:TotalKills - $aux }
                        "Locks"   { [int]$script:TotalLocksPicked - $aux }
                        "Clear"   { [int]$script:DungeonsCleared - $aux }
                        "Boss"    { [int]$script:BossesDefeated - $aux }
                        "Corrupt" { [int]$script:Corruption }
                        "Collect" { Get-NamedItemCount $curStage.ItemName }
                    }
                    if($prog -ge $curStage.Need){
                        if($curStage.Type -eq "Collect"){ Remove-Gems $curStage.ItemName $curStage.Need }
                        Set-QuestStage $curStage.Sid 999999
                        Write-Host ""
                        Write-CL "  *** Stage complete: $($curStage.Label) ***" $gd.Color
                        if($stageNum -eq 3){
                            # ── Questline finale: the signature reward ──
                            Write-Host ""
                            Write-CL "  The charter-master rises. The hall goes quiet." "Gray"
                            $exName = switch($gd.Id){
                                "sysadmins"   { "Firewall Plate" }
                                "datathieves" { "Whisperstep Boots" }
                                default       { "Grimoire of Forgotten Code" }
                            }
                            foreach($ex in (Get-ExclusiveStock)){
                                if($ex.Loc -eq "__guild" -and $ex.Item.Name -eq $exName){
                                    $gItem = @{}
                                    foreach($k in $ex.Item.Keys){ $gItem[$k] = $ex.Item[$k] }
                                    $gItem.Kind = "Armor"
                                    $gItem = Init-ItemDurability $gItem
                                    [void]$script:Inventory.Add($gItem)
                                    break
                                }
                            }
                            Write-CL "  *** You receive $($gd.RewardText)! ***" "Magenta"
                            switch($gd.Id){
                                "sysadmins"   { $script:Gold += 100 }
                                "datathieves" { $script:Lockpicks += 5 }
                                default       { $script:Player.MAG += 2 }
                            }
                        }
                        Write-Host ""; Wait-Enter
                    }
                }
            }
            "X" {
                Write-Host ""
                Write-CL "  Defect from $($gd.Name)? Dues are forfeit (100g) and" "Red"
                Write-CL "  the questline resets. (y/n)" "Red"
                Write-C  "  > " "Yellow"
                if((Read-Host) -match '^[Yy]$'){
                    $script:Gold = [math]::Max(0, $script:Gold - 100)
                    foreach($sg in $gd.Stages){ Set-QuestStage $sg.Sid 0 }
                    $script:GuildMembership = ""
                    Write-CL "  Your name is scraped from the charter. Politely." "DarkGray"
                    Write-Host ""; Wait-Enter
                }
            }
            "0" { $gcLoop = $false }
        }
    }
}

function Show-GuildHall {
    $ghLoop = $true
    while($ghLoop){
        clr
        Write-Host ""
        # 60-char-wide banner (interior 56)
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
        Write-CL "  ║                    G U I L D   H A L L                   ║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""
        # Guild house ASCII (roughly 30 wide)
        Write-CL "          _______|__________|_______          " "DarkGray"
        Write-CL "         |  __   __   __   __  |         " "DarkGray"
        Write-CL "         | |  | |  | |  | |  | |         " "DarkYellow"
        Write-CL "         | |__| |__| |__| |__| |         " "DarkGray"
        Write-CL "         |                     |         " "DarkGray"
        Write-CL "         |  ADVENTURERS GUILD  |         " "Yellow"
        Write-CL "         |       _______       |         " "DarkGray"
        Write-CL "         |      |       |      |         " "DarkYellow"
        Write-CL "         |______|       |______|         " "DarkGray"
        Write-Host ""

        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-Host ""

        # ── Current Ally box (60 char wide, interior 56) ──
        $bar = "═" * 56
        if($script:Partner){
            Write-CL "  ╔$bar╗" "DarkCyan"
            Write-C "  ║ " "DarkCyan"; Write-C "C U R R E N T   A L L Y" "Cyan"
            $hdr = "C U R R E N T   A L L Y"
            $hpad = 55 - $hdr.Length
            Write-CL ("$(' ' * $hpad)║") "DarkCyan"
            Write-CL "  ╠$bar╣" "DarkCyan"

            $allyLine = "$($script:Partner.Name)  ($($script:Partner.Class))"
            Write-C "  ║ " "DarkCyan"
            Write-C "$($script:Partner.Name)" "Green"
            Write-C "  ($($script:Partner.Class))" "Cyan"
            $allyPad = 55 - $allyLine.Length
            if($allyPad -lt 0){$allyPad=0}
            Write-CL "$(' ' * $allyPad)║" "DarkCyan"

            Write-C "  ║ " "DarkCyan"
            Write-C $script:Partner.Desc "DarkGray"
            $dPad = 55 - $script:Partner.Desc.Length
            if($dPad -lt 0){$dPad=0}
            Write-CL "$(' ' * $dPad)║" "DarkCyan"

            Write-CL "  ╚$bar╝" "DarkCyan"
            Write-Host ""
        } else {
            Write-CL "  You have no ally. Recruit one below!" "DarkGray"
            Write-Host ""
        }

        $followers = @(
            @{
                Name="Sister Maren"; Class="Healer"; Price=200
                Desc="Heals you when HP drops below 50%"
                Detail="30% chance to heal 15-25 HP after each combat turn"
                Color="Green"
            }
            @{
                Name="Fingers McGee"; Class="Thief"; Price=250
                Desc="+15% gold from enemy defeats"
                Detail="Flat 15% bonus gold added to all combat rewards"
                Color="Yellow"
            }
            @{
                Name="Lyric the Wise"; Class="Bard"; Price=225
                Desc="+25% XP from all sources"
                Detail="25% bonus XP from combat victories and quests"
                Color="Cyan"
            }
        )

        # Recruits box (same 60/56 width)
        Write-CL "  ╔$bar╗" "DarkGreen"
        Write-C "  ║ " "DarkGreen"
        Write-C "A V A I L A B L E   R E C R U I T S" "Green"
        $rhdr = "A V A I L A B L E   R E C R U I T S"
        $rhpad = 55 - $rhdr.Length
        Write-CL ("$(' ' * $rhpad)║") "DarkGreen"
        Write-CL "  ╠$bar╣" "DarkGreen"

        for($i=0;$i -lt $followers.Count;$i++){
            $f = $followers[$i]
            $affordable = if($script:Gold -ge $f.Price){"Green"}else{"DarkGray"}
            $recruited = if($script:Partner -and $script:Partner.Class -eq $f.Class){" [RECRUITED]"}else{""}

            # Line 1: "[N] Name  (Class) [RECRUITED]"
            $line1 = "[$($i+1)] $($f.Name)  ($($f.Class))$recruited"
            Write-C "  ║ " "DarkGreen"
            Write-C "[$($i+1)] " $affordable
            Write-C "$($f.Name)" $f.Color
            Write-C "  ($($f.Class))" "DarkGray"
            if($recruited){Write-C $recruited "Green"}
            $pad1 = 55 - $line1.Length
            if($pad1 -lt 0){$pad1=0}
            Write-CL "$(' ' * $pad1)║" "DarkGreen"

            # Line 2: indented Desc
            $line2 = "     $($f.Desc)"
            Write-C "  ║ " "DarkGreen"
            Write-C $line2 "White"
            $pad2 = 55 - $line2.Length
            if($pad2 -lt 0){$pad2=0}
            Write-CL "$(' ' * $pad2)║" "DarkGreen"

            # Line 3: indented Detail
            $line3 = "     $($f.Detail)"
            Write-C "  ║ " "DarkGreen"
            Write-C $line3 "DarkGray"
            $pad3 = 55 - $line3.Length
            if($pad3 -lt 0){$pad3=0}
            Write-CL "$(' ' * $pad3)║" "DarkGreen"

            # Line 4: indented Cost
            $line4 = "     Cost: $($f.Price)g"
            Write-C "  ║ " "DarkGreen"
            Write-C $line4 $affordable
            $pad4 = 55 - $line4.Length
            if($pad4 -lt 0){$pad4=0}
            Write-CL "$(' ' * $pad4)║" "DarkGreen"

            if($i -lt ($followers.Count - 1)){
                Write-CL "  ║$(' ' * 56)║" "DarkGreen"
            }
        }
        Write-CL "  ╚$bar╝" "DarkGreen"
        Write-Host ""

        # Bottom action menu (interior width 44 chars)
        $mBar = "─" * 44
        Write-CL "  ┌$mBar┐" "DarkGray"
        $row1 = " [1-3] Recruit an ally"
        $pad1 = 42 - $row1.Length
        Write-C "  │" "DarkGray"; Write-C " [1-3]" "White"; Write-C " Recruit an ally" "White"
        Write-CL ("$(' ' * $pad1) │") "DarkGray"
        if($script:Partner){
            $row2 = " [D]   Dismiss current ally"
            $pad2 = 42 - $row2.Length
            Write-C "  │" "DarkGray"; Write-C " [D]" "Red"; Write-C "   Dismiss current ally" "White"
            Write-CL ("$(' ' * $pad2) │") "DarkGray"
        }
        $rowP = " [P]   Visit the kennel (pets)"
        $padP = 42 - $rowP.Length
        Write-C "  │" "DarkGray"; Write-C " [P]" "Magenta"; Write-C "   Visit the kennel (pets)" "White"
        Write-CL ("$(' ' * $padP) │") "DarkGray"
        $rowG = " [G]   Guild charters (join/quests)"
        $padG = 42 - $rowG.Length
        Write-C "  │" "DarkGray"; Write-C " [G]" "Yellow"; Write-C "   Guild charters (join/quests)" "White"
        Write-CL ("$(' ' * $padG) │") "DarkGray"
        $row3 = " [0]   Back"
        $pad3 = 42 - $row3.Length
        Write-C "  │" "DarkGray"; Write-C " [0]" "White"; Write-C "   Back" "White"
        Write-CL ("$(' ' * $pad3) │") "DarkGray"
        Write-CL "  └$mBar┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $gCh = Read-Host

        switch($gCh.ToUpper()){
            {$_ -in @("1","2","3")} {
                $fIdx = [int]$_ - 1
                $f = $followers[$fIdx]
                if($script:Partner -and $script:Partner.Class -eq $f.Class){
                    Write-CL "  You've already recruited $($f.Name)!" "DarkGray"
                    Wait-Key
                }
                elseif($script:Gold -lt $f.Price){
                    Write-CL "  Not enough gold! Need $($f.Price)g." "Red"
                    Wait-Key
                } else {
                    if($script:Partner){
                        Write-CL "  $($script:Partner.Name) has been dismissed." "DarkGray"
                        Write-CL "  (No refund for previous ally)" "DarkGray"
                    }
                    $script:Gold -= $f.Price
                    $script:Partner = @{
                        Name  = $f.Name
                        Class = $f.Class
                        Desc  = $f.Desc
                    }
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════╗" "Green"
                    Write-CL "  ║     ALLY RECRUITED!                   ║" "Green"
                    Write-CL "  ╚══════════════════════════════════════╝" "Green"
                    Write-CL "  $($f.Name) joins your party!" "Green"
                    Write-CL "  $($f.Detail)" "DarkGray"
                    Wait-Key
                }
            }
            "D" {
                if($script:Partner){
                    Write-C "  Dismiss $($script:Partner.Name)? (y/n): " "Red"
                    $confirm = Read-Host
                    if($confirm -eq 'y'){
                        Write-CL "  $($script:Partner.Name) leaves your party." "DarkGray"
                        $script:Partner = $null
                        Wait-Key
                    }
                } else {
                    Write-CL "  No ally to dismiss." "DarkGray"
                    Wait-Key
                }
            }
            "P" { Show-PetKennel }
            "G" { Show-GuildCharters }
            "0" { $ghLoop = $false }
        }
    }
}


