        Write-C  "||             " "Green"
        Write-CL "|| FAIR PRICES!|" "Magenta"
        Write-CL " |___________ ||________||___||_____________||_____________|" "DarkGray"
        Write-CL " |_||_||_||_||_||_||_||_||_||_||_||_||_||_||_||_||_||_||_|" "DarkGray"
        Write-Host ""

        # ── Gold pouch (26 wide) + Merchant Says (36 wide) side-by-side ──
        # Top borders
        Write-C  "  ┌─ Coin Pouch ───────────┐  " "Yellow"
        Write-CL "┌─ Merchant Says ──────────────────┐"  "DarkYellow"
        # Content line
        $goldText = "Gold: $($script:Gold)g"
        $goldInner = 24  # interior width of pouch (26 minus 2 walls)
        $goldPad = $goldInner - 1 - $goldText.Length  # -1 for the leading space
        if($goldPad -lt 0){$goldPad = 0}
        Write-C "  │ " "Yellow"
        Write-C $goldText "Yellow"
        Write-C (" " * $goldPad) "Black"
        Write-C "│  " "Yellow"

        $tip = switch(Get-Random -Max 5){
            0 { "'Fresh steel, barely used!'" }
            1 { "'A scythe for shadow-touched souls?'" }
            2 { "'These potions brew by moonlight.'" }
            3 { "'Your loot, my coin. Fair trade.'" }
            4 { "'Dragon-scale armor, fitted to you.'" }
        }
        $tipInner = 34
        $tipPad = $tipInner - 1 - $tip.Length
        if($tipPad -lt 0){$tipPad = 0}
        Write-C "│ " "DarkYellow"
        Write-C $tip "DarkYellow"
        Write-C (" " * $tipPad) "Black"
        Write-CL "│" "DarkYellow"

        # Bottom borders
        Write-C  "  └─────────────────────────┘  " "Yellow"
        Write-CL "└──────────────────────────────────┘"  "DarkYellow"
        Write-Host ""

        # ── Action menu: single clean 2-column box ──
        # Column interior width = 30, total box = 2*(30)+3 = 63 between ┌ and ┐
        $colW = 30
        $bar = "─" * $colW
        Write-CL "  ┌$bar┬$bar┐" "DarkGray"

        $actions = @(
            @( @{N="[1]";L="Weapons Stall";      C="Yellow"},
               @{N="[2]";L="Armor Stall";        C="Cyan"} ),
            @( @{N="[3]";L="Potions & Elixirs";  C="Green"},
               @{N="[4]";L="Sell Your Loot";     C="Magenta"} ),
            @( @{N="[5]";L="Locksmith (picks)";  C="DarkCyan"},
               @{N="[6]";L="Blacksmith (repair)";C="DarkRed"} ),
            @( @{N="[7]";L="Leave the bazaar";   C="DarkGray"},
               @{N="[8]";L="The Enchanter";      C="Magenta"} )
        )
        foreach($r in $actions){
            $lCell = " $($r[0].N) $($r[0].L)"
            $rCell = if($r[1].N){ " $($r[1].N) $($r[1].L)" } else { "" }
            $lPad = $colW - $lCell.Length
            if($lPad -lt 0){$lPad = 0}
            $rPad = $colW - $rCell.Length
            if($rPad -lt 0){$rPad = 0}

            Write-C "  │" "DarkGray"
            if($r[0].N){
                Write-C " $($r[0].N)" $r[0].C
                Write-C " $($r[0].L)" "White"
            }
            Write-C (" " * $lPad) "Black"
            Write-C "│" "DarkGray"

            if($r[1].N){
                Write-C " $($r[1].N)" $r[1].C
                Write-C " $($r[1].L)" "White"
            }
            Write-C (" " * $rPad) "Black"
            Write-CL "│" "DarkGray"
        }
        Write-CL "  └$bar┴$bar┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $ch=Read-Host

        switch($ch){
            # ═══════════════════════════════════════════
            #  WEAPON SHOP
            # ═══════════════════════════════════════════
            "1" {
                $wepLoop = $true
                while($wepLoop){
                    clr
                    Write-CL "  ╔════════════════════════════════════════════════════════╗" "DarkCyan"
                    Write-CL "  ║                  W E A P O N S                         ║" "Cyan"
                    Write-CL "  ╚════════════════════════════════════════════════════════╝" "DarkCyan"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-C "  Class: " "DarkGray"; Write-CL "$($script:PlayerClass)" "Cyan"
                    Write-C "  Equipped: " "DarkGray"
                    if($script:EquippedWeapon){
                        $wb = Get-WeaponClassBonus
                        $wbStr = if($wb -gt 0){" [+$wb class bonus]"}else{""}
                        Write-CL "$($script:EquippedWeapon.Name) (ATK+$($script:EquippedWeapon.ATK)$wbStr)" "Cyan"
                    } else { Write-CL "Bare Hands" "DarkGray" }
                    Write-Host ""

                    Write-CL "  Select weapon category:" "White"
                    Write-Host ""
                    $catData = @(
                        @{Key="Sword";  Label="Swords";  Classes=@("Knight","Berserker"); Color="Yellow"}
                        @{Key="Staff";  Label="Staves";  Classes=@("Mage","Warlock");     Color="Cyan"}
                        @{Key="Fist";   Label="Fists";   Classes=@("Brawler");            Color="Red"}
                        @{Key="Bow";    Label="Bows";    Classes=@("Ranger");             Color="Green"}
                        @{Key="Mace";   Label="Maces";   Classes=@("Cleric");             Color="White"}
                        @{Key="Scythe"; Label="Scythes"; Classes=@("Necromancer");        Color="Magenta"}
                    )
                    for($ci=0;$ci -lt $catData.Count;$ci++){
                        $cat = $catData[$ci]
                        $match = if($cat.Classes -contains $script:PlayerClass){" << YOUR CLASS"}else{""}
                        $classList = ($cat.Classes -join "/") + " affinity"
                        Write-C "  [$($ci+1)] " "White"
                        Write-C "$($cat.Label.PadRight(10))" $cat.Color
                        Write-C "($classList)" "DarkGray"
                        Write-CL $match "Green"
                    }
                    Write-CL "  [7] Other Weapons" "DarkGray"
                    Write-CL "  [0] Back to Market" "DarkGray"
                    Write-Host ""
                    Write-C "  > " "Yellow"; $wCat = Read-Host

                    if($wCat -eq "0"){ $wepLoop = $false; continue }

                    # Determine filter
                    $allWeapons = Get-WeaponShopHere
                    $typeFilter = switch($wCat){
                        "1"{"Sword"} "2"{"Staff"} "3"{"Fist"} "4"{"Bow"}
                        "5"{"Mace"} "6"{"Scythe"} "7"{"Other"} default{$null}
                    }
                    if(-not $typeFilter){ continue }

                    if($typeFilter -eq "Other"){
                        $filtered = $allWeapons | Where-Object { $_.WeaponType -notin @("Sword","Staff","Fist","Bow","Mace","Scythe") }
                    } else {
                        $filtered = $allWeapons | Where-Object { $_.WeaponType -eq $typeFilter }
                    }
                    $filtered = @($filtered)
                    if($filtered.Count -eq 0){
                        Write-CL "  No weapons in this category." "DarkGray"
                        Wait-Key; continue
                    }

                    clr
                    Write-CL "  ╔════════════════════════════════════════════════════════╗" "DarkCyan"
                    $catLabel = if($typeFilter -eq "Other"){"OTHER WEAPONS"}else{$typeFilter.ToUpper() + "S"}
                    Write-CL "  ║  $($catLabel.PadRight(52))║" "Cyan"
                    Write-CL "  ╚════════════════════════════════════════════════════════╝" "DarkCyan"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-Host ""

                    # Column widths (interior — dashes in border = spaces in data)
                    # Row = "│" + cw1 + "│" + cw2 + "│" + cw3 + "│" + cw4 + "│" + cw5 + "│" + cw6 + "│"
                    $cw1 = 5   # #
                    $cw2 = 22  # Weapon (room for " [2H]" suffix on 2-handed weapons)
                    $cw3 = 8   # ATK
                    $cw4 = 9   # Price
                    $cw5 = 10  # Perk
                    $cw6 = 10  # Bonus

                    $top = "  ┌$('─'*$cw1)┬$('─'*$cw2)┬$('─'*$cw3)┬$('─'*$cw4)┬$('─'*$cw5)┬$('─'*$cw6)┐"
                    $mid = "  ├$('─'*$cw1)┼$('─'*$cw2)┼$('─'*$cw3)┼$('─'*$cw4)┼$('─'*$cw5)┼$('─'*$cw6)┤"
                    $bot = "  └$('─'*$cw1)┴$('─'*$cw2)┴$('─'*$cw3)┴$('─'*$cw4)┴$('─'*$cw5)┴$('─'*$cw6)┘"

                    $headerRow = "  │" + (Pad-Cell "#" $cw1) + "│" + (Pad-Cell "Weapon" $cw2) + "│" + (Pad-Cell "ATK" $cw3) + "│" + (Pad-Cell "Price" $cw4) + "│" + (Pad-Cell "Perk" $cw5) + "│" + (Pad-Cell "Bonus" $cw6) + "│"

                    Write-CL $top "DarkGray"
                    Write-CL $headerRow "DarkGray"
                    Write-CL $mid "DarkGray"

                    # Split into 1H and 2H sections, sort each section by
                    # ascending price. The 2H section gets a small banner
                    # row so it's visually obvious. Each weapon name in
                    # the 2H section is suffixed with [2H] to reinforce.
                    $oneHand = @($filtered | Where-Object { -not $_.TwoHanded } | Sort-Object { [int]$_.Price })
                    $twoHand = @($filtered | Where-Object { $_.TwoHanded }      | Sort-Object { [int]$_.Price })
                    # Concatenate so indices in the displayed list match the
                    # buy-by-number flow. Keep the divider as a non-purchasable
                    # marker — handle the "skip divider" logic below.
                    $rendered = New-Object System.Collections.ArrayList
                    foreach($w in $oneHand){ [void]$rendered.Add(@{Item=$w; Divider=$false}) }
                    if($twoHand.Count -gt 0){
                        [void]$rendered.Add(@{Item=$null; Divider=$true})
                        foreach($w in $twoHand){ [void]$rendered.Add(@{Item=$w; Divider=$false}) }
                    }

                    # Track per-row buy index (skipping divider) so the
                    # number column matches what the player types.
                    $buyNum = 0
                    # We also build a flat lookup so [#] -> weapon resolves quickly.
                    $buyMap = @{}
                    for($i=0;$i -lt $rendered.Count;$i++){
                        $row = $rendered[$i]
                        if($row.Divider){
                            # Render divider row spanning all 6 columns.
                            $bannerInner = "── TWO-HANDED ──"
                            $totalInner  = $cw1 + $cw2 + $cw3 + $cw4 + $cw5 + $cw6 + 5  # 5 internal pipes
                            $bPad = $totalInner - $bannerInner.Length
                            if($bPad -lt 0){$bPad = 0}
                            $leftP  = [math]::Floor($bPad / 2)
                            $rightP = $bPad - $leftP
                            Write-C "  │" "DarkGray"
                            Write-C ((' ' * $leftP) + $bannerInner + (' ' * $rightP)) "DarkYellow"
                            Write-CL "│" "DarkGray"
                            continue
                        }
                        $w = $row.Item
                        $buyNum++
                        $buyMap[$buyNum] = $w
                        $idxCell   = Pad-Cell ("$buyNum") $cw1
                        # Tag 2H weapons inline for instant scan-ability.
                        $displayName = if($w.TwoHanded){"$($w.Name) [2H]"}else{$w.Name}
                        if($w.Exclusive){ $displayName = "$displayName†" }
                        $nameCell  = Pad-Cell $displayName $cw2
                        $atkCell   = Pad-Cell ("+$($w.ATK)") $cw3
                        $priceCell = Pad-Cell ("$($w.Price)g") $cw4

                        $perkText   = if($w.Perk){"$($w.Perk)"}else{"---"}
                        $perkCell   = Pad-Cell $perkText $cw5

                        $magStr = if($w.MAGBonus){"M+$($w.MAGBonus)"}else{""}
                        $isMatch = Test-WeaponClassMatch $w
                        $bonusText = if($isMatch){"ATK+$($w.AffinityBonus)"}else{"---"}
                        if($magStr -and $bonusText -ne "---"){ $bonusText = "$bonusText $magStr" }
                        elseif($magStr){ $bonusText = $magStr }
                        $bonusCell = Pad-Cell $bonusText $cw6

                        $affordable = if($script:Gold -ge $w.Price){"Green"}else{"DarkGray"}
                        $perkColor  = switch($w.Perk){"Bleed"{"DarkRed"}"Burn"{"DarkYellow"}"Poison"{"DarkGreen"}"Drain"{"Magenta"}"Stun"{"Yellow"}default{"DarkGray"}}
                        $bonusColor = if($isMatch){"Green"}else{"DarkGray"}
                        # 2H weapon names use a slightly different shade
                        # so they pop visually even at a glance.
                        $nameColor  = if($w.TwoHanded){"Yellow"}else{"Cyan"}

                        Write-C "  │" "DarkGray"
                        Write-C $idxCell $affordable
                        Write-C "│" "DarkGray"
                        Write-C $nameCell $nameColor
                        Write-C "│" "DarkGray"
                        Write-C $atkCell "White"
                        Write-C "│" "DarkGray"
                        Write-C $priceCell $affordable
                        Write-C "│" "DarkGray"
                        Write-C $perkCell $perkColor
                        Write-C "│" "DarkGray"
                        Write-C $bonusCell $bonusColor
                        Write-CL "│" "DarkGray"
                    }
                    Write-CL $bot "DarkGray"
                    Write-Host ""
                    Write-CL "  Bonus column shows extra ATK when YOUR class matches." "DarkGray"
                    Write-CL "  Perks trigger randomly on basic attacks." "DarkGray"
                    Write-CL "  [2H] weapons block the Shield slot when equipped." "DarkGray"
                    Write-Host ""
                    Write-C "  Buy # (0=back): " "Yellow"; $bi=Read-Host
                    $widx = 0
                    [int]::TryParse([string]$bi, [ref]$widx) | Out-Null
                    if($widx -ge 1 -and $buyMap.ContainsKey($widx)){
                        $w = $buyMap[$widx]
                        $effPrice = [int][math]::Ceiling($w.Price * (Get-ShopDiscount))
                        if($script:Gold -ge $effPrice){
                            $script:Gold -= $effPrice
                            $newWeapon = Init-ItemDurability $w
                            if(-not $newWeapon.Kind){ $newWeapon.Kind = "Weapon" }
                            $script:WeaponsOwned[$w.Name] = $true
                            Invoke-GearAcquired -Item $newWeapon -Kind "Weapon"
                            if($effPrice -lt $w.Price){
                                Write-CL "  ($(Get-ShopDiscountLabel): $($w.Price)g -> ${effPrice}g)" "Cyan"
                            }
                            $cb = Get-WeaponClassBonus
                            if($cb -gt 0 -and $script:EquippedWeapon -eq $newWeapon){
                                Write-CL "  Class bonus active! +$cb ATK" "Green"
                            }
                            if($w.Perk -and $script:EquippedWeapon -eq $newWeapon){
                                Write-CL "  Weapon perk: $($w.Perk) ($($w.PerkChance)% chance on attack)" "DarkYellow"
                            }
                            Check-Achievements
                        } else { Write-CL "  Not enough gold!" "Red" }
                        Wait-Key
                    }
                }
            }

            # ═══════════════════════════════════════════
            #  ARMOR SHOP
            # ═══════════════════════════════════════════
            "2" {
                $armorLoop = $true
                while($armorLoop){
                    clr
                    Write-CL "  ╔════════════════════════════════════════════════════════╗" "DarkCyan"
                    Write-CL "  ║                    A R M O R                           ║" "Cyan"
                    Write-CL "  ╚════════════════════════════════════════════════════════╝" "DarkCyan"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-C "  Total Armor DEF: " "DarkGray"; Write-CL "+$(Get-TotalArmorDEF)" "Cyan"
                    Write-Host ""
                    Write-CL "  ── Armor Sets ── (pieces marked * in listings)" "DarkGray"
                    Write-CL "  Leather 2pc +1 SPD, 3pc +3 · Iron 2pc +1 DEF, 3pc +3" "DarkGray"
                    Write-CL "  Steel 2pc +2 DEF · Dragon 2pc +2 ATK, 3pc +2 DEF" "DarkGray"
                    Write-CL "  Mythril 2pc +1 SPD, +1% crit" "DarkGray"
                    Write-Host ""

                    # Show current equipment
                    Write-CL "  ── Currently Equipped ──" "DarkGray"
                    $slots = @("Helmet","Chest","Shield","Amulet","Boots")
                    for($si=0;$si -lt $slots.Count;$si++){
                        $slot = $slots[$si]
                        $piece = $script:EquippedArmor[$slot]
                        $slotStr = "$($slot):".PadRight(9)
                        Write-C "  [$($si+1)] $slotStr" "White"
                        if($piece){
                            $setTag = if(Get-ItemSet $piece.Name){" [$(Get-ItemSet $piece.Name) set]"}else{""}
                            Write-CL "$($piece.Name) (DEF+$($piece.DEF))$(Get-ArmorClassTag $piece)$setTag" "Cyan"
                        } else {
                            Write-CL "(empty)" "DarkGray"
                        }
                    }
                    Write-Host ""
                    Write-CL "  [0] Back to Market" "DarkGray"
                    Write-Host ""
                    Write-C "  Select slot to browse: " "Yellow"; $slotPick = Read-Host

                    if($slotPick -eq "0"){ $armorLoop = $false; continue }
                    $sIdx = (ConvertTo-SafeInt -Value $slotPick) - 1
                    if($sIdx -lt 0 -or $sIdx -ge $slots.Count){ continue }
                    $chosenSlot = $slots[$sIdx]

                    # Show armor for that slot, sorted by price ascending so
                    # the cheapest options are at the top — matches the
                    # weapon shop ordering and the player's expectation.
                    $allArmor = Get-ArmorShopHere
                    $slotArmor = @($allArmor | Where-Object { $_.Slot -eq $chosenSlot } | Sort-Object { [int]$_.Price })

                    clr
                    Write-CL "  ╔════════════════════════════════════════════════════════╗" "DarkCyan"
                    Write-CL "  ║  $($chosenSlot.ToUpper().PadRight(52))║" "Cyan"
                    Write-CL "  ╚════════════════════════════════════════════════════════╝" "DarkCyan"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    $current = $script:EquippedArmor[$chosenSlot]
                    Write-C "  Current: " "DarkGray"
                    if($current){ Write-CL "$($current.Name) (DEF+$($current.DEF))$(Get-ArmorClassTag $current)" "Cyan" }
                    else { Write-CL "(empty)" "DarkGray" }
                    Write-Host ""

                    # Column widths
                    $cw1 = 5   # #
                    $cw2 = 18  # Armor name
                    $cw3 = 8   # DEF
                    $cw4 = 9   # Price
                    $cw5 = 6   # Equipped marker

                    $top = "  ┌$('─'*$cw1)┬$('─'*$cw2)┬$('─'*$cw3)┬$('─'*$cw4)┬$('─'*$cw5)┐"
                    $mid = "  ├$('─'*$cw1)┼$('─'*$cw2)┼$('─'*$cw3)┼$('─'*$cw4)┼$('─'*$cw5)┤"
                    $bot = "  └$('─'*$cw1)┴$('─'*$cw2)┴$('─'*$cw3)┴$('─'*$cw4)┴$('─'*$cw5)┘"

                    $headerRow = "  │" + (Pad-Cell "#" $cw1) + "│" + (Pad-Cell "Armor" $cw2) + "│" + (Pad-Cell "DEF" $cw3) + "│" + (Pad-Cell "Price" $cw4) + "│" + (Pad-Cell "" $cw5) + "│"

                    Write-CL $top "DarkGray"
                    Write-CL $headerRow "DarkGray"
                    Write-CL $mid "DarkGray"

                    for($i=0;$i -lt $slotArmor.Count;$i++){
                        $a = $slotArmor[$i]
                        $idxCell   = Pad-Cell ("$($i+1)") $cw1
                        $nameCell  = Pad-Cell ("$($a.Name)$(if(Get-ItemSet $a.Name){'*'})$(if($a.Exclusive){'†'})") $cw2
                        $defCell   = Pad-Cell ("+$($a.DEF)$(Get-ArmorClassTag $a)") $cw3
                        $priceCell = Pad-Cell ("$($a.Price)g") $cw4
                        $equipped = if($current -and $current.Name -eq $a.Name){"[ON]"}else{""}
                        $eqCell    = Pad-Cell $equipped $cw5

                        $affordable = if($script:Gold -ge $a.Price){"Green"}else{"DarkGray"}

                        Write-C "  │" "DarkGray"
                        Write-C $idxCell $affordable
                        Write-C "│" "DarkGray"
                        Write-C $nameCell "Cyan"
                        Write-C "│" "DarkGray"
                        Write-C $defCell "White"
                        Write-C "│" "DarkGray"
                        Write-C $priceCell $affordable
                        Write-C "│" "DarkGray"
                        Write-C $eqCell "Yellow"
                        Write-CL "│" "DarkGray"
                    }
                    Write-CL $bot "DarkGray"
                    Write-CL "  [H] = Heavy armor  [L] = Light armor — wearing a class trains its skill" "DarkGray"
                    Write-Host ""
                    Write-C "  Buy # (0=back): " "Yellow"; $aPick = Read-Host
                    $aIdx = (ConvertTo-SafeInt -Value $aPick) - 1
                    if($aIdx -ge 0 -and $aIdx -lt $slotArmor.Count){
                        $a = $slotArmor[$aIdx]
                        $effPrice = [int][math]::Ceiling($a.Price * (Get-ShopDiscount))
                        if($script:Gold -ge $effPrice){
                            $script:Gold -= $effPrice
                            $newArmor = Init-ItemDurability $a
                            if(-not $newArmor.Kind){ $newArmor.Kind = "Armor" }
                            if(-not $newArmor.Slot){ $newArmor.Slot = $chosenSlot }
                            $script:ArmorOwned[$a.Name] = $true
                            Invoke-GearAcquired -Item $newArmor -Kind "Armor"
                            if($effPrice -lt $a.Price){
                                Write-CL "  ($(Get-ShopDiscountLabel): $($a.Price)g -> ${effPrice}g)" "Cyan"
                            }
                            Write-CL "  Total Armor DEF: +$(Get-TotalArmorDEF)" "Cyan"
                            Check-Achievements
                        } else { Write-CL "  Not enough gold!" "Red" }
                        Wait-Key
                    }
                }
            }

            # ═══════════════════════════════════════════
            #  POTION SHOP  (loops on purchase — player exits explicitly with 0)
            # ═══════════════════════════════════════════
            "3" {
                $potLoop = $true
                while($potLoop){
                    clr
                    Write-CL "" "Green"
                    Write-CL "  ╔════════════════════════════════════════════╗" "DarkGreen"
                    Write-CL "  ║            P O T I O N S                   ║" "Green"
                    Write-CL "  ╚════════════════════════════════════════════╝" "DarkGreen"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-C "  Potions: " "DarkGray"; Write-CL "$($script:Potions.Count) / 10" "Green"
                    Write-C "  Throwables: " "DarkGray"; Write-CL "$($script:ThrowablePotions.Count) / 5" "DarkYellow"
                    Write-Host ""

                    # Potions and throwables, each section sorted by price
                    # ascending. The split between sections is at index 7
                    # (the first Throwable entry). Order matters for the
                    # divider rendering below — keep the seven Potions
                    # first, then the four Throwables.
                    $potionShop = @(
                        @{Name="Small Health Potion"; Type="Heal";    Power=30; Price=25;  Desc="Restore 30 HP";     Icon="[HP+]";  Category="Potion"}
                        @{Name="Mana Potion";         Type="Mana";    Power=30; Price=30;  Desc="Restore 30 MP";     Icon="[MP+]";  Category="Potion"}
                        @{Name="Large Mana Potion";   Type="Mana";    Power=60; Price=55;  Desc="Restore 60 MP";     Icon="[MP++]"; Category="Potion"}
                        @{Name="Large Health Potion"; Type="Heal";    Power=70; Price=60;  Desc="Restore 70 HP";     Icon="[HP++]"; Category="Potion"}
                        @{Name="Strength Elixir";     Type="ATKBuff"; Power=8;  Price=75;  Desc="ATK+8 in battle";   Icon="[ATK]";  Category="Potion"}
                        @{Name="Iron Skin Elixir";    Type="DEFBuff"; Power=8;  Price=75;  Desc="DEF+8 in battle";   Icon="[DEF]";  Category="Potion"}
                        @{Name="Potion of Luck";      Type="Luck";    Power=20; Price=90;  Desc="+20% crit, 3 turns"; Icon="[LCK]";  Category="Potion"}
                        @{Name="Frost Bomb";          Type="ThrowSlow";  Power=20; Price=55; Desc="20 dmg + Slow";   Icon="[SLW]"; Category="Throwable"}
                        @{Name="Acid Flask";          Type="Throw";   Power=40; Price=60;  Desc="Deal 40 damage";    Icon="[DMG]";  Category="Throwable"}
                        @{Name="Poison Flask";        Type="ThrowPoison"; Power=25; Price=70; Desc="25 dmg + Poison"; Icon="[PSN]"; Category="Throwable"}
                        @{Name="Bomb";                Type="Throw";   Power=75; Price=140; Desc="Deal 75 damage";    Icon="[BMB]";  Category="Throwable"}
                    )

                    # Column widths — match borders exactly using Pad-Cell
                    $cw1 = 5   # #
                    $cw2 = 22  # Potion name
                    $cw3 = 20  # Effect
                    $cw4 = 9   # Price

                    $top = "  ┌$('─'*$cw1)┬$('─'*$cw2)┬$('─'*$cw3)┬$('─'*$cw4)┐"
                    $mid = "  ├$('─'*$cw1)┼$('─'*$cw2)┼$('─'*$cw3)┼$('─'*$cw4)┤"
                    $bot = "  └$('─'*$cw1)┴$('─'*$cw2)┴$('─'*$cw3)┴$('─'*$cw4)┘"
                    $headerRow = "  │" + (Pad-Cell "#" $cw1) + "│" + (Pad-Cell "Potion" $cw2) + "│" + (Pad-Cell "Effect" $cw3) + "│" + (Pad-Cell "Price" $cw4) + "│"

                    Write-CL "  ── Healing & Buff Potions ──" "Green"
                    Write-CL $top "DarkGray"
                    Write-CL $headerRow "DarkGray"
                    Write-CL $mid "DarkGray"

                    for($i=0;$i -lt $potionShop.Count;$i++){
                        $pt=$potionShop[$i]
                        $affordable = if($script:Gold -ge $pt.Price){"Green"}else{"DarkGray"}
                        $typeColor = switch($pt.Type){
                            "Heal"{"Green"} "Mana"{"Cyan"} "ATKBuff"{"Yellow"} "DEFBuff"{"Yellow"}
                            "Luck"{"Magenta"} "Throw"{"DarkRed"} "ThrowPoison"{"DarkGreen"} "ThrowSlow"{"DarkCyan"}
                            default{"White"}
                        }
                        if($i -eq 7){
                            # Mid-divider and THROWABLES label — width-matched to the table
                            Write-CL $mid "DarkGray"
                            $thLabel = "  │" + (Pad-Cell "" $cw1) + "│" + (Pad-Cell "-- THROWABLES --" $cw2) + "│" + (Pad-Cell "" $cw3) + "│" + (Pad-Cell "" $cw4) + "│"
                            Write-CL $thLabel "DarkYellow"
                            Write-CL $mid "DarkGray"
                        }
                        $idxCell   = Pad-Cell ("$($i+1)") $cw1
                        $nameCell  = Pad-Cell $pt.Name $cw2
                        $descCell  = Pad-Cell $pt.Desc $cw3
                        $priceCell = Pad-Cell ("$($pt.Price)g") $cw4

                        Write-C "  │" "DarkGray"
                        Write-C $idxCell $affordable
                        Write-C "│" "DarkGray"
                        Write-C $nameCell $typeColor
                        Write-C "│" "DarkGray"
                        Write-C $descCell "White"
                        Write-C "│" "DarkGray"
                        Write-C $priceCell $affordable
                        Write-CL "│" "DarkGray"
                    }
                    Write-CL $bot "DarkGray"
                    Write-Host ""
                    # The Master's Still (Cat 11): Alchemy 50 distills gems
                    # into Extra Strong potions (otherwise clear/boss-only).
                    $alLvl = Get-SkillLevel "Alchemy"
                    if($alLvl -ge 50){
                        Write-CL "  [B] The Master's Still — distill a gem into a miracle" "Magenta"
                    } else {
                        Write-CL "  [B] The Master's Still (locked — Alchemy 50; now $alLvl)" "DarkGray"
                    }
                    Write-Host ""
                    Write-C "  Buy # (B=still, 0=leave shop): " "Yellow"; $pi2=Read-Host
                    if($pi2 -eq "0"){ $potLoop = $false; continue }
                    if($pi2 -match '^[Bb]$'){
                        if($alLvl -lt 50){
                            Write-CL "  The stall-keeper shakes her head. 'Fifty. The still is picky.'" "DarkGray"
                            Start-Sleep -Milliseconds 900; continue
                        }
                        Show-MastersStill
                        continue
                    }
                    $pidx2=[int]$pi2 - 1
                    if($pidx2 -ge 0 -and $pidx2 -lt $potionShop.Count){
                        $pt=$potionShop[$pidx2]
                        $effPrice = [int][math]::Ceiling($pt.Price * (Get-ShopDiscount))
                        # Blighted Plague (Cat 12): potion prices spike +50%.
                        if((Get-ActiveRadiantEvent) -eq "Plague"){
                            $effPrice = [int][math]::Ceiling($effPrice * 1.5)
                        }
                        if($pt.Category -eq "Throwable"){
                            if($script:ThrowablePotions.Count -ge 5){
                                Write-CL "  Throwable inventory full! (5/5)" "Red"
                            }
                            elseif($script:Gold -ge $effPrice){
                                $script:Gold -= $effPrice
                                [void]$script:ThrowablePotions.Add($pt)
                                if($effPrice -lt $pt.Price){
                                    Write-CL "  Bought $($pt.Name)! ($(Get-ShopDiscountLabel): ${effPrice}g)" "Green"
                                } else {
                                    Write-CL "  Bought $($pt.Name)!" "Green"
                                }
                            } else { Write-CL "  Not enough gold!" "Red" }
                        } else {
                            if($script:Potions.Count -ge 10){
                                Write-CL "  Potion inventory full! (10/10)" "Red"
                            }
                            elseif($script:Gold -ge $effPrice){
                                $script:Gold -= $effPrice
                                [void]$script:Potions.Add($pt)
                                if($effPrice -lt $pt.Price){
                                    Write-CL "  Bought $($pt.Name)! ($(Get-ShopDiscountLabel): ${effPrice}g)" "Green"
                                } else {
                                    Write-CL "  Bought $($pt.Name)!" "Green"
                                }
                            } else { Write-CL "  Not enough gold!" "Red" }
                        }
                        Start-Sleep -Milliseconds 800  # brief feedback instead of Wait-Key; loops back for another purchase
                    }
                }
            }

            # ═══════════════════════════════════════════
            #  SELL LOOT
            # ═══════════════════════════════════════════
            "4" {
                # Loop until the player explicitly exits with [0] Back.
                # Previously each sale dropped them back to the market
                # root, which made multi-item liquidation tedious.
                $sellLoop = $true
                while($sellLoop){
                    clr
                    Write-CL "" "Magenta"
                    Write-CL "  ╔════════════════════════════════════════════╗" "DarkMagenta"
                    Write-CL "  ║           S E L L   L O O T                ║" "Magenta"
                    Write-CL "  ╚════════════════════════════════════════════╝" "DarkMagenta"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-Host ""

                    # Build a unified sellable list. Each entry tracks Source
                    # ("Inv", "Pot", "Throw") and SourceIdx so we can remove from
                    # the correct backing list when a sale completes.
                    # v1.6.2: items an ACTIVE Collect quest still needs
                    # cannot be sold out from under the quest.
                    $qNeedNames = @{}
                    foreach($qloc in @("backupvale","nullhaven","cachegrove","registry","sysv","foreachfalls","bashford","cronmarch","firewallkeep","syslogxing","kernelhold","terminus")){
                        $qq = Get-TownQuest $qloc
                        if($qq -and $qq.Type -eq "Collect" -and $qq.ItemName){
                            $qst = Get-QuestStage $qq.Id
                            if($qst -ge 100000 -and $qst -ne 999999){ $qNeedNames[[string]$qq.ItemName] = $true }
                        }
                    }
                    $sellList = New-Object System.Collections.ArrayList
                    for($i=0; $i -lt $script:Inventory.Count; $i++){
                        if($qNeedNames[[string]$script:Inventory[$i].Name]){ continue }
                        [void]$sellList.Add(@{ Item=$script:Inventory[$i]; Source="Inv"; SourceIdx=$i })
                    }
                    for($i=0; $i -lt $script:Potions.Count; $i++){
                        [void]$sellList.Add(@{ Item=$script:Potions[$i]; Source="Pot"; SourceIdx=$i })
                    }
                    for($i=0; $i -lt $script:ThrowablePotions.Count; $i++){
                        [void]$sellList.Add(@{ Item=$script:ThrowablePotions[$i]; Source="Throw"; SourceIdx=$i })
                    }

                    if($sellList.Count -eq 0){
                        Write-CL "  ┌─────────────────────────────────┐" "DarkGray"
                        Write-CL "  │  Your bags are empty...         │" "DarkGray"
                        Write-CL "  └─────────────────────────────────┘" "DarkGray"
                        Wait-Key
                        $sellLoop = $false
                        continue
                    }

                    Write-CL "  ┌─────┬──────────────────────┬──────────┐" "DarkGray"
                    Write-CL "  │  #  │ Item                 │ Value    │" "DarkGray"
                    Write-CL "  ├─────┼──────────────────────┼──────────┤" "DarkGray"
                    $totalVal = 0
                    for($i=0;$i -lt $sellList.Count;$i++){
                        $entry = $sellList[$i]
                        $it = $entry.Item
                        $sv = Get-ItemSellValue $it
                        $totalVal += $sv
                        $idxStr  = (" $($i+1) ").PadRight(3)
                        $nameStr = $it.Name
                        if($nameStr.Length -gt 20){ $nameStr = $nameStr.Substring(0,20) }
                        $nameStr = $nameStr.PadRight(20)
                        $valStr  = ("${sv}g").PadRight(8)
                        # Color by source for visual hint
                        $nameC = switch($entry.Source){
                            "Pot"   { "Green" }
                            "Throw" { "Cyan" }
                            default { "Magenta" }
                        }
                        Write-C "  │ " "DarkGray"
                        Write-C $idxStr "White"
                        Write-C " │ " "DarkGray"
                        Write-C $nameStr $nameC
                        Write-C " │ " "DarkGray"
                        Write-C $valStr "Yellow"
                        Write-CL " │" "DarkGray"
                    }
                    Write-CL "  └─────┴──────────────────────┴──────────┘" "DarkGray"
                    Write-Host ""
                    Write-CL "  Total sell value: ${totalVal}g" "Yellow"
                    Write-Host ""
                    Write-CL "  [A] Sell ALL          [#] Sell one item by number" "White"
                    Write-CL "  [L] Sell All Loot     [0] Back" "White"
                    Write-CL "      Sell All Loot option keeps weapons, armor, potions," "Green"
                    Write-CL "      throwables, notes, and ingredients — sells the rest." "Green"
                    Write-C "  > " "Yellow"; $si=Read-Host

                    if($si -eq 'A' -or $si -eq 'a'){
                        $script:Gold += $totalVal
                        $script:Inventory.Clear()
                        $script:Potions.Clear()
                        $script:ThrowablePotions.Clear()
                        Write-CL "  Sold everything for ${totalVal}g!" "Green"
                        Write-CL "  Gold: $($script:Gold)g" "Yellow"
                        Wait-Key
                    }
                    elseif($si -eq 'L' -or $si -eq 'l'){
                        # Sell-all-loot: liquidate generic loot items only.
                        # We KEEP: weapons, armor (might want to equip),
                        # potions/throwables (consumables), notes (lore),
                        # ingredients (cooking). Anything in $script:Inventory
                        # whose Kind is not in {Weapon, Armor, Note,
                        # Ingredient, Potion, Throwable} is sold.
                        # Potions and throwables live in their own bags so
                        # they're untouched by definition. Ingredients live
                        # in $script:Ingredients (not the bag) so they're
                        # also untouched.
                        $protectedKinds = @("Weapon","Armor","Note","Ingredient","Potion","Throwable")
                        $lootGold = 0
                        $lootCount = 0
                        # Iterate from the back so RemoveAt indices stay valid.
                        for($i = $script:Inventory.Count - 1; $i -ge 0; $i--){
                            $it = $script:Inventory[$i]
                            $kind = if($it.Kind){[string]$it.Kind}else{"Loot"}
                            if($protectedKinds -notcontains $kind){
                                $lootGold += (Get-ItemSellValue $it)
                                $script:Inventory.RemoveAt($i)
                                $lootCount++
                            }
                        }
                        if($lootCount -eq 0){
                            Write-CL "  No generic loot to sell — all your bag items are protected." "DarkYellow"
                            Write-CL "  (Weapons, armor, potions, notes, and ingredients are kept.)" "DarkGray"
                        } else {
                            $script:Gold += $lootGold
                            $itemWord = if($lootCount -eq 1){"item"}else{"items"}
                            Write-CL "  Sold $lootCount loot $itemWord for ${lootGold}g." "Green"
                            Write-CL "  (Weapons, armor, potions, notes, and ingredients kept.)" "DarkGray"
                            Write-CL "  Gold: $($script:Gold)g" "Yellow"
                        }
                        Wait-Key
                    }
                    elseif($si -eq '0'){
                        $sellLoop = $false
                    }
                    else {
                        $sidx=[int]$si - 1
                        if($sidx -ge 0 -and $sidx -lt $sellList.Count){
                            $entry = $sellList[$sidx]
                            $it = $entry.Item
                            # Dutchman's Blade is a unique encounter drop
                            # that can't be re-acquired in a normal run.
                            # Confirm before letting the player sell it
                            # — easy to misclick on a sorted bag.
                            $isUniqueSword = ($it.Name -eq "Dutchman's Blade")
                            if($isUniqueSword){
                                Write-Host ""
                                Write-CL "  ! WARNING: Dutchman's Blade is unique and CANNOT be" "DarkYellow"
                                Write-CL "    re-acquired. Once sold, it's gone for this run." "DarkYellow"
                                Write-Host ""
                                Write-C "  Sell anyway? (y/n): " "Yellow"
                                $duConfirm = Read-Host
                                if($duConfirm -ne 'y' -and $duConfirm -ne 'Y'){
                                    Write-CL "  Cancelled." "DarkGray"
                                    Wait-Key
                                    continue
                                }
                            }
                            $sv = Get-ItemSellValue $it
                            $script:Gold += $sv
                            Write-CL "  Sold $($it.Name) for ${sv}g!" "Green"
                            Write-CL "  Gold: $($script:Gold)g" "Yellow"
                            switch($entry.Source){
                                "Inv"   { $script:Inventory.RemoveAt($entry.SourceIdx) }
                                "Pot"   { $script:Potions.RemoveAt($entry.SourceIdx) }
                                "Throw" { $script:ThrowablePotions.RemoveAt($entry.SourceIdx) }
                            }
                            Wait-Key
                        }
                    }
                } # end while sellLoop
            }

            # ═══════════════════════════════════════════
            #  LOCKSMITH (lockpicks)
            # ═══════════════════════════════════════════
            "5" {
                $locksmithLoop = $true
                while($locksmithLoop){
                    clr
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkCyan"
                    Write-CL "  ║                    T H E   L O C K S M I T H             ║" "Cyan"
                    Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkCyan"
                    Write-Host ""
                    # Small locksmith stall art
                    Write-CL "          _____________" "DarkGray"
                    Write-CL "         |  _________  |" "DarkGray"
                    Write-CL "         | |  PICKS  | |" "DarkCyan"
                    Write-CL "         | |  25g ea | |" "Cyan"
                    Write-CL "         | |_________| |" "DarkGray"
                    Write-CL "         |  o=    =o   |" "DarkCyan"
                    Write-CL "         |_____________|" "DarkGray"
                    Write-Host ""
                    Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
                    Write-C "  Current lockpicks: " "DarkGray"; Write-CL "$($script:Lockpicks)" "Cyan"
                    Write-Host ""
                    Write-CL "  The locksmith adjusts her monocle:" "DarkGray"
                    Write-CL "  'Need picks? 25 gold each. Say how many.'" "White"
                    Write-Host ""
                    Write-CL "  ┌──────────────────────────────────────────┐" "DarkGray"
                    Write-CL "  │  Enter quantity (0 to leave)             │" "DarkGray"
                    Write-CL "  └──────────────────────────────────────────┘" "DarkGray"
                    Write-Host ""
                    Write-C "  > " "Yellow"; $qtyStr = Read-Host
                    $qty = 0
                    if([int]::TryParse($qtyStr, [ref]$qty) -and $qty -gt 0){
                        $rawCost = 25 * $qty
                        $cost = [int][math]::Ceiling($rawCost * (Get-ShopDiscount))
                        if($script:Gold -ge $cost){
                            $script:Gold -= $cost
                            $script:Lockpicks += $qty
                            if($cost -lt $rawCost){
                                Write-CL "  She slides $qty pick(s) across the counter for ${cost}g (Guild discount)." "Green"
                            } else {
                                Write-CL "  She slides $qty pick(s) across the counter for ${cost}g." "Green"
                            }
                            Wait-Key
                        } else {
                            Write-CL "  'That'll be $cost gold — come back when you have it.'" "Red"
                            Wait-Key
                        }
                    } else {
                        $locksmithLoop = $false
                    }
                }
            }

            # ═══════════════════════════════════════════
            #  BLACKSMITH (repair gear)
            # ═══════════════════════════════════════════
            "6" { Show-Blacksmith }
            "8" { Show-EnchanterScreen }

            # ═══════════════════════════════════════════
            #  LEAVE MARKET
            # ═══════════════════════════════════════════
            "7" { $loop=$false }
        }
    }
}




# ─── BLACKSMITH ──────────────────────────────────────────────────
# Repair equipped weapon and/or armor pieces. Cost = (missing/max) * Price.
# Lists individually with a "Repair All" bulk option (10% discount).
# Dutchman's Blade can't be repaired (never breaks).
# ─── LOOT SCREEN (arrow-key navigation) ───────────────────────────
# Presents a list of items. Player navigates with Up/Down (or W/S),
# toggles selection with Space, views item details with V, takes all
# with A, confirms with Enter, cancels (takes nothing) with Esc.
#
# Items must be initialized with Kind/Weight before being passed in
# (use Init-ItemWeight or pass items from New-RandomLoot).
#
# Returns the list of items taken (which the caller does NOT need to
# add to inventory — this function routes them itself based on Kind).
function Show-LootScreen {
    param(
        [string]$Title = "LOOT FOUND",
        $Items = @()
    )
    # Defensive: coerce to array. PS unwraps single-element arrays in some hosts.
    if($Items -isnot [array]){ $Items = @($Items) }
    if(-not $Items -or $Items.Count -eq 0){ return @() }

    $itemCount = $Items.Count
    $marked = New-Object 'bool[]' $itemCount   # default false; user opts in
    $cursor = 0                                # which row is highlighted
    function _LootRouteAndStow {
        param($Items, $marked)
        $taken = @()
        $rejected = @()
        for($i=0; $i -lt $Items.Count; $i++){
            if(-not $marked[$i]){ continue }
            $it = $Items[$i]
            $kindKnown = $it.Kind
            # Gold pile → add to $script:Gold (always, no cap, no weight)
            if($kindKnown -eq "Gold"){
                $qty = if($it.Quantity){[int]$it.Quantity}else{0}
                $script:Gold += $qty
                $script:RunStats.GoldEarned += $qty
                $taken += $it
            }
            # Lockpicks bundle → increment $script:Lockpicks counter
            elseif($kindKnown -eq "Lockpicks"){
                $qty = if($it.Quantity){[int]$it.Quantity}else{1}
                $script:Lockpicks += $qty
                $taken += $it
            }
            # Throwables → throwable bag (max 5)
            elseif($it.Type -in @("Throw","ThrowPoison","ThrowSlow") -or $kindKnown -eq "Throwable"){
                if($script:ThrowablePotions.Count -lt 5){
                    [void]$script:ThrowablePotions.Add($it)
                    $taken += $it
                } else {
                    $rejected += $it
                }
            }
            # Regular potions → potion belt (max 10)
            elseif($kindKnown -eq "Potion" -or $it.Type -in @("Heal","Mana","ATKBuff","DEFBuff","Luck")){
                if($script:Potions.Count -lt 10){
                    [void]$script:Potions.Add($it)
                    $taken += $it
                } else {
                    $rejected += $it
                }
            }
            # Cooking ingredients → $script:Ingredients hashtable (no inventory slot).
            # The carry-weight check is handled by the loot screen's mark-toggle
            # logic itself (you can only mark items the bag can fit), so by the
            # time we get here the weight has already been validated.
            elseif($kindKnown -eq "Ingredient"){
                if(-not $script:Ingredients){ $script:Ingredients = @{} }
                $iType = if($it.IngredientType){[string]$it.IngredientType}else{$it.Name}
                if(-not $script:Ingredients.ContainsKey($iType)){
                    $script:Ingredients[$iType] = 0
                }
                $script:Ingredients[$iType]++
                $taken += $it
            }
            # Journal pages (Cat 7): flag ONLY, no bag copy. The [V]
            # journal is the collection; a duplicate paper item was
            # clutter (user). Pages were already 0 wt and never saved
            # as items, so in-bag legacy copies die on save/load.
            elseif($it.IsNote -and $it.Page){
                [void](Add-JournalPage ([int]$it.Page))
                $taken += $it
            }
            # Loot, weapons, armor → main inventory bag
            else {
                [void]$script:Inventory.Add($it)
                $taken += $it
                # Track for LootHunter quest (any non-Gold/Lockpick/Potion/Throw item)
                if($it.Kind -eq "Loot" -or $it.Kind -eq "Weapon" -or $it.Kind -eq "Armor"){
                    Update-QuestProgress "LootHunter"
                }
            }
        }
        return @{ Taken = $taken; Rejected = $rejected }
    }

    function _LootShowDetailCard {
        param($Item)
        clr
        Write-Host ""
        $boxW = 56
        $bar = "═" * $boxW
        Write-CL ("  ╔" + $bar + "╗") "DarkCyan"
        $title = " " + $Item.Name
        if($title.Length -gt $boxW){ $title = $title.Substring(0, $boxW) }
        $title = $title.PadRight($boxW)
        Write-C "  ║" "DarkCyan"; Write-C $title "Yellow"; Write-CL "║" "DarkCyan"
        Write-CL ("  ╠" + ("─" * $boxW) + "╣") "DarkCyan"
        $rows = @()
        $kindStr = if($Item.Kind){ $Item.Kind } else { "Item" }
        $rows += "  Type:       $kindStr"
        if($Item.WeaponType){ $rows += "  WeaponType: $($Item.WeaponType)" }
        if($Item.Slot){       $rows += "  Slot:       $($Item.Slot)" }
        if($Item.ATK){        $rows += "  ATK:        +$($Item.ATK)" }
        if($Item.DEF){        $rows += "  DEF:        +$($Item.DEF)" }
        if($Item.MAGBonus){   $rows += "  MAG:        +$($Item.MAGBonus)" }
        if($Item.MaxDurability){
            $dCur = if($Item.Durability){ $Item.Durability } else { $Item.MaxDurability }
            $rows += "  Durability: $dCur/$($Item.MaxDurability)"
        }
        if($Item.Value){      $rows += "  Value:      $($Item.Value)g" }
        if($Item.Price){      $rows += "  Price:      $($Item.Price)g" }
        $weightV = Get-ItemWeight $Item
        $rows += "  Weight:     $weightV"
        if($Item.ClassAffinity){
            $bonusStr = if($Item.AffinityBonus){"+$($Item.AffinityBonus) ATK"}else{""}
            $rows += "  Affinity:   $($Item.ClassAffinity) $bonusStr"
        }
        if($Item.Perk){
            $perkChance = if($Item.PerkChance){"$($Item.PerkChance)%"}else{""}
            $rows += "  Perk:       $($Item.Perk) $perkChance"
        }
        if($Item.Effect -and $Item.Effect -ne "None"){
            $rows += "  Effect:     $($Item.Effect)"
        }
        if($Item.Power){
            $rows += "  Power:      $($Item.Power)"
        }
        if($Item.Desc){
            # Wrap description if too long
            $desc = $Item.Desc
            if($desc.Length -gt ($boxW - 4)){
                $desc = $desc.Substring(0, $boxW - 7) + "..."
            }
            $rows += "  Desc:       $desc"
        }
        # Notes (v1.5): if this is a found note, append the wrapped Body text
        # below the standard fields. Multi-line wrap at boxW-4 chars.
        if($Item.IsNote -and $Item.Body){
            $rows += "  ─── Contents ───"
            $bodyLeft = $Item.Body
            $wrapW = $boxW - 4
            while($bodyLeft.Length -gt 0){
                if($bodyLeft.Length -le $wrapW){
                    $rows += "  $bodyLeft"
                    $bodyLeft = ""
                } else {
                    # Find the last space within the window so we wrap on words
                    $cut = $wrapW
                    $space = $bodyLeft.Substring(0, $wrapW).LastIndexOf(' ')
                    if($space -gt 20){ $cut = $space }
                    $rows += "  $($bodyLeft.Substring(0, $cut))"
                    $bodyLeft = $bodyLeft.Substring($cut).TrimStart()
                }
            }
        }
        foreach($r in $rows){
            $padded = $r
            if($padded.Length -gt $boxW){ $padded = $padded.Substring(0, $boxW) }
            $padded = $padded.PadRight($boxW)
            Write-C "  ║" "DarkCyan"; Write-C $padded "Gray"; Write-CL "║" "DarkCyan"
        }
        Write-CL ("  ╚" + $bar + "╝") "DarkCyan"
        Write-Host ""
        Write-CL "  [Press any key to return to loot screen]" "DarkGray"
        # Drain any held keys then wait for one fresh press
        Drain-Keys
        $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
    }

    # Drain any leftover keys before entering the loop
    Drain-Keys

    # ── Auto-Loot setting bypass ──
    # When the player has Auto-Loot ON, this screen auto-marks every
    # item that fits within the carry-weight cap and routes them
    # directly. Items are picked in their natural order until adding
    # the next would exceed max weight; remaining items are left.
    # Potion-belt and throwable-bag overflow follows the same rules
    # as the manual flow.
    if($script:Settings -and $script:Settings.AutoLoot){
        $maxW = Get-MaxCarryWeight $script:Player
        $curW = Get-CurrentCarryWeight
        $room = $maxW - $curW
        if($room -lt 0){ $room = 0 }
        $autoMarked = New-Object 'bool[]' $itemCount
        for($i=0; $i -lt $itemCount; $i++){
            $iw = Get-ItemWeight $Items[$i]
            if($iw -le $room){
                $autoMarked[$i] = $true
                $room -= $iw
            }
        }
        $autoResult = _LootRouteAndStow $Items $autoMarked
        if($autoResult.Rejected.Count -gt 0){
            Write-Host ""
            Write-CL "  Auto-loot took what fit. These didn't make it:" "Yellow"
            foreach($r in $autoResult.Rejected){
                Write-CL "    ! $($r.Name)" "DarkYellow"
            }
            Wait-Key
        }
        return $autoResult.Taken
    }

    while($true){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
        $titleStr = $Title
        if($titleStr.Length -gt 56){ $titleStr = $titleStr.Substring(0, 56) }
        $titlePadded = $titleStr.PadLeft(($titleStr.Length + 56) / 2).PadRight(56)
        Write-C "  ║" "DarkYellow"; Write-C $titlePadded "Yellow"; Write-CL "║" "DarkYellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""

        $maxW = Get-MaxCarryWeight $script:Player
        $curW = Get-CurrentCarryWeight
        $selectedW = 0
        for($i=0; $i -lt $itemCount; $i++){
            if($marked[$i]){ $selectedW += (Get-ItemWeight $Items[$i]) }
        }
        $afterW = $curW + $selectedW
        $weightColor = if($afterW -gt $maxW){"Red"}elseif($afterW -gt ($maxW * 0.85)){"Yellow"}else{"Green"}

        Write-C "  Carry: " "DarkGray"
        Write-C "$curW" "White"
        Write-C " / $maxW" "White"
        Write-C "                       [Selected: " "DarkGray"
        Write-C "+$selectedW" $weightColor
        Write-CL "]" "DarkGray"
        if($afterW -gt $maxW){
            Write-CL "  -- selection will OVER-ENCUMBER you (you can still take it) --" "DarkYellow"
        }
        Write-Host ""

        # Item rows
        for($i=0; $i -lt $itemCount; $i++){
            $it = $Items[$i]
            $isCursor = ($i -eq $cursor)
            $box = if($marked[$i]){"[X]"}else{"[ ]"}
            $kindTag = switch($it.Kind){
                "Weapon"     { "[Wpn]" }
                "Armor"      { "[Arm]" }
                "Potion"     { "[Pot]" }
                "Throwable"  { "[Thr]" }
                "Lockpicks"  { "[Pck]" }
                "Gold"       { "[Gld]" }
                "Ingredient" { "[Ing]" }
                "Note"       { "[Note]" }
                default      { "[Loot]" }
            }
            $name = $it.Name
            if($name.Length -gt 24){ $name = $name.Substring(0,24) }
            $w = Get-ItemWeight $it
            $valStr = if($it.Value){"$($it.Value)g"}elseif($it.Price){"$($it.Price)g"}else{"---"}

            # Cursor arrow
            if($isCursor){ Write-C "  > " "Yellow" }
            else { Write-C "    " "DarkGray" }

            # Checkbox
            $boxColor = if($marked[$i]){"Green"}else{"DarkGray"}
            Write-C $box $boxColor

            # Name (highlighted if cursor on it)
            $nameColor = if($isCursor){"White"}elseif($marked[$i]){"White"}else{"Gray"}
            Write-C " " $nameColor
            Write-C $name.PadRight(24) $nameColor

            # Kind tag
            $tagColor = switch($it.Kind){
                "Weapon"    { "Yellow" }
                "Armor"     { "DarkCyan" }
                "Potion"    { "Green" }
                "Throwable" { "DarkYellow" }
                "Lockpicks" { "Cyan" }
                "Gold"      { "Yellow" }
                default     { "Magenta" }
            }
            Write-C " " "DarkGray"
            Write-C $kindTag.PadRight(7) $tagColor

            # Weight
            Write-C "  " "DarkGray"
            $wColor = if(($curW + $w) -gt $maxW){"Red"}else{"DarkGray"}
            Write-C "${w}wt".PadRight(5) $wColor

            # Value
            Write-C "  " "DarkGray"
            Write-CL $valStr.PadLeft(6) "DarkGray"
        }

        Write-Host ""
        Write-CL "  ──────────────────────────────────────────────────" "DarkGray"
        Write-CL "  [Up/Down] move    [Space] toggle    [V] details" "DarkCyan"
        Write-CL "  [A] take all      [Enter] confirm   [Esc] none" "DarkCyan"

        # Wait for a key
        $key = $null
        while(-not $key){
            if($Host.UI.RawUI.KeyAvailable){
                $k = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
                # Map virtual keys
                switch($k.VirtualKeyCode){
                    38 { $key = "UP" }       # Up arrow
                    40 { $key = "DOWN" }     # Down arrow
                    32 { $key = "SPACE" }    # Space
                    13 { $key = "ENTER" }    # Enter
                    27 { $key = "ESC" }      # Escape
                }
                if(-not $key -and $k.Character -and $k.Character -ne [char]0){
                    $c = [string]$k.Character
                    switch -Regex ($c){
                        '^[Ww]$' { $key = "UP" }
                        '^[Ss]$' { $key = "DOWN" }
                        '^[Aa]$' { $key = "ALL" }
                        '^[Vv]$' { $key = "VIEW" }
                        ' '      { $key = "SPACE" }
                    }
                }
            }
            Start-Sleep -Milliseconds 25
        }
        # A held arrow floods the input buffer; without a drain every
        # buffered repeat replays after release — forever-scroll (user).
        Drain-Keys

        switch($key){
            "UP" {
                $cursor--
                if($cursor -lt 0){ $cursor = $itemCount - 1 }
            }
            "DOWN" {
                $cursor++
                if($cursor -ge $itemCount){ $cursor = 0 }
            }
            "SPACE" {
                $marked[$cursor] = -not $marked[$cursor]
            }
            "ALL" {
                # Smart take-all: mark items greedily until weight cap reached
                $tentativeW = $curW
                for($i=0; $i -lt $itemCount; $i++){
                    $w = Get-ItemWeight $Items[$i]
                    if(($tentativeW + $w) -le $maxW){
                        $marked[$i] = $true
                        $tentativeW += $w
                    } else {
                        $marked[$i] = $false
                    }
                }
            }
            "VIEW" {
                _LootShowDetailCard $Items[$cursor]
            }
            "ENTER" {
                # Over-weight selections are now ALLOWED — the player may
                # voluntarily over-encumber themselves to keep precious
                # loot. We warn once, then proceed if they confirm. The
                # over-encumbered penalty (movement + stat) applies as
                # normal afterward.
                $finalAfter = $curW + $selectedW
                if($finalAfter -gt $maxW){
                    Write-Host ""
                    Write-CL "  ! Warning: selection puts you OVER the carry cap." "DarkYellow"
                    Write-CL "    Current $curW + selected $selectedW = $finalAfter (max $maxW)." "DarkGray"
                    Write-CL "    You will be ENCUMBERED — movement blocked in dungeons until you drop weight." "DarkYellow"
                    Write-Host ""
                    Write-C "  Take anyway? (y/n): " "Yellow"
                    Drain-Keys
                    $confirm = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
                    Write-Host ""
                    if($confirm.Character -ne 'y' -and $confirm.Character -ne 'Y'){
                        # Treat as a cancel — return to picker so the
                        # player can unmark items.
                        continue
                    }
                    # Else fall through to route + stow.
                }
                # Route + stow
                $result = _LootRouteAndStow $Items $marked
                if($result.Rejected.Count -gt 0){
                    Write-Host ""
                    Write-CL "  Some potions/throwables couldnt fit:" "Yellow"
                    foreach($r in $result.Rejected){
                        Write-CL "    ! $($r.Name) — your belt is full" "DarkYellow"
                    }
                    Wait-Key
                }
                return $result.Taken
            }
            "ESC" {
                return @()
            }
        }
    }
}


# ─── DROP SCREEN (arrow-key navigation) ───────────────────────────
# Mark items in inventory + potions + throwables, set lockpick drop
# quantity, then confirm to destroy. Equipped weapon/armor are shown
# at the top as a visual reminder — they are NOT droppable here (use
# the [U] Unequip option in the inventory screen for that).
function Show-DropScreen {
    $invCount = $script:Inventory.Count
    $potCount = $script:Potions.Count
    $thrCount = $script:ThrowablePotions.Count
    $hasPicks = ($script:Lockpicks -gt 0)
    # (user) Cooking ingredients are droppable now: 1 wt each, qty
    # rows like the lockpick control below.
    $ingKeys = @()
    if($script:Ingredients){
        foreach($ingK in ($script:Ingredients.Keys | Sort-Object)){
            if([int]$script:Ingredients[$ingK] -gt 0){ $ingKeys += [string]$ingK }
        }
    }
    $ingCount = $ingKeys.Count

    if($invCount -eq 0 -and $potCount -eq 0 -and $thrCount -eq 0 -and $ingCount -eq 0 -and -not $hasPicks){
        Write-CL "  Nothing droppable." "DarkGray"
        Wait-Key
        return
    }

    # Virtual row layout (in display order):
    #   row 0..invCount-1                            -> $script:Inventory[i]
    #   row invCount..invCount+potCount-1            -> $script:Potions[i - invCount]
    #   row invCount+potCount..potEnd+thrCount-1     -> $script:ThrowablePotions[...]
    #   row picksRow (if hasPicks)                   -> lockpick quantity control
    $potStart = $invCount
    $thrStart = $invCount + $potCount
    $ingStart = $invCount + $potCount + $thrCount
    $picksRow = $ingStart + $ingCount
    $totalRows = $picksRow
    if($hasPicks){ $totalRows++ }
    $ingDropQty = New-Object 'int[]' ([math]::Max($ingCount, 1))

    $invMarked = New-Object 'bool[]' ([math]::Max($invCount, 1))
    $potMarked = New-Object 'bool[]' ([math]::Max($potCount, 1))
    $thrMarked = New-Object 'bool[]' ([math]::Max($thrCount, 1))
    $picksDropQty = 0
    $cursor = 0

    # Drain leftover keys
    Drain-Keys

    while($true){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
        Write-CL "  ║              D R O P   I T E M S                         ║" "Red"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
        Write-Host ""

        $maxW = Get-MaxCarryWeight $script:Player
        $curW = Get-CurrentCarryWeight
        $shedW = $picksDropQty
        for($i=0; $i -lt $invCount; $i++){
            if($invMarked[$i]){ $shedW += (Get-ItemWeight $script:Inventory[$i]) }
        }
        for($i=0; $i -lt $potCount; $i++){
            if($potMarked[$i]){ $shedW += 1 }
        }
        for($i=0; $i -lt $thrCount; $i++){
            if($thrMarked[$i]){ $shedW += 1 }
        }
        for($i=0; $i -lt $ingCount; $i++){ $shedW += $ingDropQty[$i] }
        $afterW = $curW - $shedW
        $afterColor = if($afterW -gt $maxW){"Red"}else{"Green"}

        Write-C "  Carry: " "DarkGray"
        Write-C "$curW" "White"
        Write-C " (-$shedW dropped) = " "DarkGray"
        Write-C "$afterW" $afterColor
        Write-CL " / $maxW max" "DarkGray"
        Write-Host ""
        if($afterW -gt $maxW){
            Write-CL "  Still over weight - mark more items." "Red"
            Write-Host ""
        }

        # ─── Equipped reminder (NOT droppable) ───
        $hasEquipped = ($script:EquippedWeapon -ne $null)
        foreach($s in @("Helmet","Chest","Shield","Amulet","Boots")){
            if($script:EquippedArmor[$s]){ $hasEquipped = $true; break }
        }
        if($hasEquipped){
            Write-CL "  EQUIPPED (use Unequip in inventory to drop):" "DarkCyan"
            if($script:EquippedWeapon){
                Write-CL "    [E] $($script:EquippedWeapon.Name) [Wpn]" "Cyan"
            }
            foreach($s in @("Helmet","Chest","Shield","Amulet","Boots")){
                $piece = $script:EquippedArmor[$s]
                if($piece){
                    Write-CL "    [E] $($piece.Name) [$s]" "Cyan"
                }
            }
            Write-Host ""
        }

        # Helper: render a row
        # Inventory items
        for($i=0; $i -lt $invCount; $i++){
            $rowIdx = $i
            $isCursor = ($cursor -eq $rowIdx)
            $it = $script:Inventory[$i]
            if($isCursor){ Write-C "  > " "Yellow" } else { Write-C "    " "DarkGray" }
            $box = if($invMarked[$i]){"[X]"}else{"[ ]"}
            $boxColor = if($invMarked[$i]){"Red"}else{"DarkGray"}
            Write-C $box $boxColor
            $name = $it.Name
            if($name.Length -gt 24){ $name = $name.Substring(0,24) }
            $nameColor = if($isCursor){"White"}elseif($invMarked[$i]){"Red"}else{"White"}
            Write-C " " $nameColor
            Write-C $name.PadRight(24) $nameColor
            $kindTag = switch($it.Kind){
                "Weapon" { "[Wpn]" }
                "Armor"  { "[Arm]" }
                "Potion" { "[Pot]" }
                "Note"   { "[Note]" }
                default  { "[Loot]" }
            }
            $tagColor = switch($it.Kind){
                "Weapon" { "Yellow" }
                "Armor"  { "DarkCyan" }
                "Potion" { "Green" }
                "Note"   { "DarkMagenta" }
                default  { "Magenta" }
            }
            Write-C " " "DarkGray"
            Write-C $kindTag.PadRight(7) $tagColor
            $w = Get-ItemWeight $it
            Write-C "  " "DarkGray"
            Write-C "${w}wt".PadRight(5) "DarkGray"
            Write-C "  " "DarkGray"
            $valStr = if($it.Value){"$($it.Value)g"}else{"---"}
            Write-CL $valStr.PadLeft(6) "DarkGray"
        }

        # Potions
        for($i=0; $i -lt $potCount; $i++){
            $rowIdx = $potStart + $i
            $isCursor = ($cursor -eq $rowIdx)
            $pot = $script:Potions[$i]
            if($isCursor){ Write-C "  > " "Yellow" } else { Write-C "    " "DarkGray" }
            $box = if($potMarked[$i]){"[X]"}else{"[ ]"}
            $boxColor = if($potMarked[$i]){"Red"}else{"DarkGray"}
            Write-C $box $boxColor
            $name = $pot.Name
            if($name.Length -gt 24){ $name = $name.Substring(0,24) }
            $nameColor = if($isCursor){"White"}elseif($potMarked[$i]){"Red"}else{"White"}
            Write-C " " $nameColor
            Write-C $name.PadRight(24) $nameColor
            Write-C " " "DarkGray"
            Write-C "[Pot]".PadRight(7) "Green"
            Write-C "  " "DarkGray"
            Write-C "1wt".PadRight(5) "DarkGray"
            Write-C "  " "DarkGray"
            $valStr = if($pot.Price){"$($pot.Price)g"}else{"---"}
            Write-CL $valStr.PadLeft(6) "DarkGray"
        }

        # Throwables
        for($i=0; $i -lt $thrCount; $i++){
            $rowIdx = $thrStart + $i
            $isCursor = ($cursor -eq $rowIdx)
            $thr = $script:ThrowablePotions[$i]
            if($isCursor){ Write-C "  > " "Yellow" } else { Write-C "    " "DarkGray" }
            $box = if($thrMarked[$i]){"[X]"}else{"[ ]"}
            $boxColor = if($thrMarked[$i]){"Red"}else{"DarkGray"}
            Write-C $box $boxColor
            $name = $thr.Name
            if($name.Length -gt 24){ $name = $name.Substring(0,24) }
            $nameColor = if($isCursor){"White"}elseif($thrMarked[$i]){"Red"}else{"White"}
            Write-C " " $nameColor
            Write-C $name.PadRight(24) $nameColor
            Write-C " " "DarkGray"
            Write-C "[Thr]".PadRight(7) "DarkYellow"
            Write-C "  " "DarkGray"
            Write-C "1wt".PadRight(5) "DarkGray"
            Write-C "  " "DarkGray"
            $valStr = if($thr.Price){"$($thr.Price)g"}else{"---"}
            Write-CL $valStr.PadLeft(6) "DarkGray"
        }

        # Ingredient rows (qty control like lockpicks)
        for($i=0; $i -lt $ingCount; $i++){
            $rowIdx = $ingStart + $i
            $isCursor = ($cursor -eq $rowIdx)
            if($isCursor){ Write-C "  > " "Yellow" } else { Write-C "    " "DarkGray" }
            $dq = [int]$ingDropQty[$i]
            $boxColor = if($dq -gt 0){"Red"}else{"DarkGray"}
            Write-C "[~]" $boxColor
            $iName = [string]$ingKeys[$i]
            if($iName.Length -gt 24){ $iName = $iName.Substring(0,24) }
            Write-C " " "White"
            Write-C $iName.PadRight(24) "White"
            Write-C " " "DarkGray"
            Write-C "[Ing]".PadRight(7) "Green"
            Write-C "  " "DarkGray"
            Write-C "${dq}wt".PadRight(5) "DarkGray"
            Write-C "  " "DarkGray"
            $iHave = [int]$script:Ingredients[$ingKeys[$i]]
            $iQtyDisplay = if($dq -gt 0){"DROP $dq / $iHave"}else{"keep all $iHave"}
            Write-CL $iQtyDisplay.PadLeft(16) "DarkGray"
        }

        # Lockpicks row
        if($hasPicks){
            $isCursor = ($cursor -eq $picksRow)
            if($isCursor){ Write-C "  > " "Yellow" } else { Write-C "    " "DarkGray" }
            $boxColor = if($picksDropQty -gt 0){"Red"}else{"DarkGray"}
            Write-C "[~]" $boxColor
            $nameColor = if($isCursor){"White"}else{"Gray"}
            Write-C " " $nameColor
            Write-C "Lockpicks".PadRight(24) $nameColor
            Write-C " " "DarkGray"
            Write-C "[Pck]".PadRight(7) "Cyan"
            Write-C "  " "DarkGray"
            Write-C "${picksDropQty}wt".PadRight(5) "DarkGray"
            Write-C "  " "DarkGray"
            $qtyDisplay = if($picksDropQty -gt 0){"DROP $picksDropQty / $($script:Lockpicks)"}else{"keep all $($script:Lockpicks)"}
            Write-CL $qtyDisplay.PadLeft(16) "DarkGray"
        }

        Write-Host ""
        Write-CL "  --------------------------------------------------" "DarkGray"
        Write-CL "  [Up/Down] move    [Space] toggle    [+/-] pick qty" "DarkCyan"
        Write-CL "  [D] drop marked   [Esc] cancel" "DarkCyan"

        # Read key
        $key = $null
        while(-not $key){
            if($Host.UI.RawUI.KeyAvailable){
                $k = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
                switch($k.VirtualKeyCode){
                    38 { $key = "UP" }
                    40 { $key = "DOWN" }
                    32 { $key = "SPACE" }
                    13 { $key = "ENTER" }
                    27 { $key = "ESC" }
                    187 { $key = "PLUS" }
                    189 { $key = "MINUS" }
                    107 { $key = "PLUS" }
                    109 { $key = "MINUS" }
                }
                if(-not $key -and $k.Character -and $k.Character -ne [char]0){
                    $c = [string]$k.Character
                    switch -Regex ($c){
                        '^[Ww]$' { $key = "UP" }
                        '^[Ss]$' { $key = "DOWN" }
                        '^[Dd]$' { $key = "DROP" }
                        '^\+$'  { $key = "PLUS" }
                        '^=$'    { $key = "PLUS" }
                        '^-$'    { $key = "MINUS" }
                        ' '      { $key = "SPACE" }
                    }
                }
            }
            Start-Sleep -Milliseconds 25
        }
        # A held arrow floods the input buffer; without a drain every
        # buffered repeat replays after release — forever-scroll (user).
        Drain-Keys

        switch($key){
            "UP" {
                $cursor--
                if($cursor -lt 0){ $cursor = $totalRows - 1 }
            }
            "DOWN" {
                $cursor++
                if($cursor -ge $totalRows){ $cursor = 0 }
            }
            "SPACE" {
                # Determine which list the cursor is on
                if($hasPicks -and $cursor -eq $picksRow){
                    if($picksDropQty -eq 0){ $picksDropQty = $script:Lockpicks }
                    else { $picksDropQty = 0 }
                } elseif($cursor -ge $ingStart){
                    $i = $cursor - $ingStart
                    if($i -ge 0 -and $i -lt $ingCount){
                        if($ingDropQty[$i] -eq 0){ $ingDropQty[$i] = [int]$script:Ingredients[$ingKeys[$i]] }
                        else { $ingDropQty[$i] = 0 }
                    }
                } elseif($cursor -ge $thrStart){
                    $i = $cursor - $thrStart
                    if($i -ge 0 -and $i -lt $thrCount){ $thrMarked[$i] = -not $thrMarked[$i] }
                } elseif($cursor -ge $potStart){
                    $i = $cursor - $potStart
                    if($i -ge 0 -and $i -lt $potCount){ $potMarked[$i] = -not $potMarked[$i] }
                } else {
                    $i = $cursor
                    if($i -ge 0 -and $i -lt $invCount){ $invMarked[$i] = -not $invMarked[$i] }
                }
            }
            "PLUS" {
                if($hasPicks -and $cursor -eq $picksRow){
                    if($picksDropQty -lt $script:Lockpicks){ $picksDropQty++ }
                } elseif($cursor -ge $ingStart -and $cursor -lt $picksRow){
                    $i = $cursor - $ingStart
                    if($ingDropQty[$i] -lt [int]$script:Ingredients[$ingKeys[$i]]){ $ingDropQty[$i]++ }
                }
            }
            "MINUS" {
                if($hasPicks -and $cursor -eq $picksRow){
                    if($picksDropQty -gt 0){ $picksDropQty-- }
                } elseif($cursor -ge $ingStart -and $cursor -lt $picksRow){
                    $i = $cursor - $ingStart
                    if($ingDropQty[$i] -gt 0){ $ingDropQty[$i]-- }
                }
            }
            { $_ -eq "DROP" -or $_ -eq "ENTER" } {
                $invDropCount = 0
                for($i=0; $i -lt $invCount; $i++){ if($invMarked[$i]){ $invDropCount++ } }
                $potDropCount = 0
                for($i=0; $i -lt $potCount; $i++){ if($potMarked[$i]){ $potDropCount++ } }
                $thrDropCount = 0
                for($i=0; $i -lt $thrCount; $i++){ if($thrMarked[$i]){ $thrDropCount++ } }
                $ingDropTotal = 0
                for($i=0; $i -lt $ingCount; $i++){ $ingDropTotal += [int]$ingDropQty[$i] }
                $totalDrops = $invDropCount + $potDropCount + $thrDropCount + $picksDropQty + $ingDropTotal
                if($totalDrops -eq 0){
                    if($key -eq "DROP"){
                        Write-Host ""
                        Write-CL "  Nothing marked to drop." "DarkGray"
                        Wait-Key
                    }
                    continue
                }
                Write-Host ""
                $parts = @()
                if($invDropCount -gt 0){ $parts += "$invDropCount item(s)" }
                if($potDropCount -gt 0){ $parts += "$potDropCount potion(s)" }
                if($thrDropCount -gt 0){ $parts += "$thrDropCount throwable(s)" }
                if($ingDropTotal -gt 0){ $parts += "$ingDropTotal ingredient(s)" }
                if($picksDropQty -gt 0){ $parts += "$picksDropQty lockpick(s)" }
                $msg = "Drop " + ($parts -join " + ") + "?"
                Write-C "  $msg (y/n): " "Yellow"
                $confirm = Read-Host
                if($confirm -eq 'y' -or $confirm -eq 'Y'){
                    # Reverse-iterate each list
                    for($i = $invCount - 1; $i -ge 0; $i--){
                        if($invMarked[$i]){ $script:Inventory.RemoveAt($i) }
                    }
                    for($i = $potCount - 1; $i -ge 0; $i--){
                        if($potMarked[$i]){ $script:Potions.RemoveAt($i) }
                    }
                    for($i = $thrCount - 1; $i -ge 0; $i--){
                        if($thrMarked[$i]){ $script:ThrowablePotions.RemoveAt($i) }
                    }
                    for($i = 0; $i -lt $ingCount; $i++){
                        if($ingDropQty[$i] -gt 0){
                            $script:Ingredients[$ingKeys[$i]] = [math]::Max(0, [int]$script:Ingredients[$ingKeys[$i]] - [int]$ingDropQty[$i])
                        }
                    }
                    if($picksDropQty -gt 0){
                        $script:Lockpicks -= $picksDropQty
                        if($script:Lockpicks -lt 0){ $script:Lockpicks = 0 }
                    }
                    Write-CL "  Dropped: $($parts -join ', ')." "Red"
                    Wait-Key
                    return
                }
            }
            "ESC" { return }
        }
    }
}




# ─── MASTER CRAFTING (Cat 11): Blacksmithing 50 milestone ─────────
# The forge's back room. Unlocked at Blacksmithing Lv50; recipes
# consume gems + gold and produce "__craft" exclusives (append-only
# rows in Get-ExclusiveStock — the 1000+ name scan persists them
# once equipped, like every other exclusive). One forging each:
# WeaponsOwned/ArmorOwned gate repeat crafts.
function Show-MasterCrafting {
    $mcLoop = $true
    while($mcLoop){
        clr
        Write-Host ""
        Write-CL "  ── T H E   B A C K   R O O M ──" "Red"
        Write-CL "  The smith unhooks a chain. 'Fifty years at an anvil" "DarkGray"
        Write-CL "  or fifty levels — same door either way. In.'" "White"
        Write-Host ""
        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-Host ""
        $recipes = @(
            @{ Name="Hotpatch";           Cost=600; Gems=@(@{N="Dragon Tooth";Q=2}, @{N="Ancient Rune";Q=1}) }
            @{ Name="Nullforged Bulwark"; Cost=450; Gems=@(@{N="Ruby Chunk";Q=2},   @{N="Demon Horn";Q=1}) }
        )
        $stock = @{}
        foreach($ex in (Get-ExclusiveStock)){ if($ex.Loc -eq "__craft"){ $stock[$ex.Item.Name] = $ex.Item } }
        $n = 0
        foreach($r in $recipes){
            $n++
            $it = $stock[$r.Name]
            $owned = if($it.WeaponType){ $script:WeaponsOwned[$it.Name] } else { $script:ArmorOwned[$it.Name] }
            $statTxt = if($it.WeaponType){ "ATK+$($it.ATK), $($it.WeaponType), $($it.Perk) $($it.PerkChance)%" } else { "$($it.Slot), DEF+$($it.DEF)$(Get-ArmorClassTag $it)" }
            $gemTxt = @(); foreach($g in $r.Gems){ $gemTxt += "$($g.Q) $($g.N)" }
            if($owned){
                Write-CL "  [$n] $($it.Name)  ($statTxt) — FORGED" "DarkGray"
            } else {
                Write-CL "  [$n] $($it.Name)  ($statTxt)" "Cyan"
                Write-CL "      $($gemTxt -join ' + ') + $($r.Cost)g" "DarkGray"
            }
        }
        Write-Host ""
        Write-CL "  ('Forge-work, not shop-work. Each leaves this anvil once.')" "DarkGray"
        Write-CL "  [0] Back" "White"
        Write-Host ""
        Write-C "  Forge #: " "Yellow"
        $pick = Read-Host
        if($pick -eq "0" -or $pick -eq ""){ return }
        $rIdx = 0
        [int]::TryParse([string]$pick, [ref]$rIdx) | Out-Null
        if($rIdx -ge 1 -and $rIdx -le $recipes.Count){
            $r = $recipes[$rIdx-1]
            $it = $stock[$r.Name]
            $owned = if($it.WeaponType){ $script:WeaponsOwned[$it.Name] } else { $script:ArmorOwned[$it.Name] }
            if($owned){ Write-CL "  'Already made ye one. The anvil remembers.'" "DarkGray"; Wait-Key; continue }
            $short = @()
            foreach($g in $r.Gems){ if((Get-GemCount $g.N) -lt $g.Q){ $short += "$($g.Q) $($g.N)" } }
            if($short.Count -gt 0){
                Write-CL "  'Short on materials: $($short -join ', '). No shortcuts here.'" "Red"
                Wait-Key; continue
            }
            if($script:Gold -lt $r.Cost){ Write-CL "  'And the coin? Forges eat coal, coal eats coin.'" "Red"; Wait-Key; continue }
            $script:Gold -= $r.Cost
            foreach($g in $r.Gems){ Remove-Gems $g.N $g.Q }
            $copy = @{}
            foreach($k in $it.Keys){ $copy[$k] = $it[$k] }
            $copy.Exclusive = $true
            $newIt = Init-ItemDurability $copy
            Write-Host ""
            Write-CL "  Sparks. Swearing. Quench-hiss. Then silence." "Yellow"
            Write-CL "  *** The $($newIt.Name) leaves the anvil. ***" "Magenta"
            if($newIt.WeaponType){
                if(-not $newIt.Kind){ $newIt.Kind = "Weapon" }
                $script:WeaponsOwned[$it.Name] = $true
                Invoke-GearAcquired -Item $newIt -Kind "Weapon"
            } else {
                if(-not $newIt.Kind){ $newIt.Kind = "Armor" }
                $script:ArmorOwned[$it.Name] = $true
                Invoke-GearAcquired -Item $newIt -Kind "Armor"
            }
            Add-SkillXP "Blacksmithing" 50
            Check-Achievements
            Wait-Key
        }
    }
}

# ─── THE MASTER'S STILL (Cat 11): Alchemy 50 milestone ────────────
# Distills one gem + gold into an Extra Strong potion — the Special
# category that otherwise only drops from dungeon clears and bosses.
# Repeatable: consumables never survive a save, so nothing persists;
# the v6 save already carries ES potion counts by name (slots 11-14).
function Show-MastersStill {
    $msLoop = $true
    while($msLoop){
        clr
        Write-Host ""
        Write-CL "  ── T H E   M A S T E R ' S   S T I L L ──" "Magenta"
        Write-CL "  Copper coils, low flame, and a stall-keeper who only" "DarkGray"
        Write-CL "  now admits the good shelf exists. 'Gems in. Miracles out.'" "White"
        Write-Host ""
        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-C "  Potions: " "DarkGray"; Write-CL "$($script:Potions.Count) / 10" "Green"
        Write-Host ""
        $brews = @(
            @{ Name="Extra Strong Health Potion";   Gem="Ruby Chunk";  Cost=90;  Desc="Restore 200 HP" }
            @{ Name="Extra Strong Mana Potion";     Gem="Gem Shard";   Cost=80;  Desc="Restore 150 MP" }
            @{ Name="Extra Strong Strength Elixir"; Gem="Demon Horn";  Cost=110; Desc="ATK+20 in battle" }
            @{ Name="Extra Strong Luck Potion";     Gem="Shadow Gem";  Cost=110; Desc="+50% crit, 5 turns" }
        )
        $n = 0
        foreach($b in $brews){
            $n++
            $have = Get-GemCount $b.Gem
            $ok = ($have -ge 1 -and $script:Gold -ge $b.Cost)
            $col = if($ok){"Green"}else{"DarkGray"}
            Write-CL "  [$n] $($b.Name)  ($($b.Desc))" $col
            Write-CL "      1 $($b.Gem) (have $have) + $($b.Cost)g" "DarkGray"
        }
        Write-Host ""
        Write-CL "  [0] Back" "White"
        Write-C "  Distill #: " "Yellow"
        $pick = Read-Host
        if($pick -eq "0" -or $pick -eq ""){ return }
        $bIdx = 0
        [int]::TryParse([string]$pick, [ref]$bIdx) | Out-Null
        if($bIdx -ge 1 -and $bIdx -le $brews.Count){
            $b = $brews[$bIdx-1]
            if($script:Potions.Count -ge 10){ Write-CL "  Potion inventory full! (10/10)" "Red"; Wait-Key; continue }
            if((Get-GemCount $b.Gem) -lt 1){ Write-CL "  'No $($b.Gem), no miracle.'" "Red"; Wait-Key; continue }
            if($script:Gold -lt $b.Cost){ Write-CL "  Not enough gold!" "Red"; Wait-Key; continue }
            $script:Gold -= $b.Cost
            Remove-Gems $b.Gem 1
            $tmpl = $null
            foreach($p in (Get-PotionShop)){ if($p.Name -eq $b.Name){ $tmpl = $p; break } }
            if($tmpl){
                $potCopy = @{}
                foreach($k in $tmpl.Keys){ $potCopy[$k] = $tmpl[$k] }
                $potCopy.Kind = "Potion"
                $potCopy.Weight = 1
                [void]$script:Potions.Add($potCopy)
                Write-CL "  The still shudders, drips once, and delivers." "Magenta"
                Write-CL "  Brewed: $($b.Name)" "Green"
                Add-SkillXP "Alchemy" 25
            }
            Wait-Key
        }
    }
}

function Show-Blacksmith {
    $smithLoop = $true
    while($smithLoop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
        Write-CL "  ║                  T H E   B L A C K S M I T H             ║" "Red"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
        Write-Host ""
        # Forge art
        Write-CL "           _______________" "DarkGray"
        Write-CL "          /   _________   \" "DarkGray"
        Write-CL "         |   /    ^    \   |" "Red"
        Write-CL "         |  /    ( )    \  |" "DarkYellow"
        Write-CL "         | |    ~~~~~    | |" "DarkYellow"
        Write-CL "         | |   ~ FIRE ~  | |" "Yellow"
        Write-CL "         | |   ~~~~~~~   | |" "DarkYellow"
        Write-CL "          \|_____________|/" "DarkGray"
        Write-CL "         ///  |  ANVIL  |  \\\\\\" "DarkGray"
        Write-Host ""
        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-Host ""

        # Gather all damaged items
        $damaged = @()  # list of @{ Kind=Weapon/Armor; Slot=...; Item=...; Cost=... }
        if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0){
            $wCost = Get-RepairCost $script:EquippedWeapon
            if($wCost -gt 0){
                $damaged += @{ Kind="Weapon"; Slot="Weapon"; Item=$script:EquippedWeapon; Cost=$wCost }
            }
        }
        foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
            $piece = $script:EquippedArmor[$slot]
            if($piece -and $piece.MaxDurability -ge 0){
                $cost = Get-RepairCost $piece
                if($cost -gt 0){
                    $damaged += @{ Kind="Armor"; Slot=$slot; Item=$piece; Cost=$cost }
                }
            }
        }

        if($damaged.Count -eq 0){
            Write-CL "  The smith looks over your gear." "DarkGray"
            Write-CL "  'Everything's in fine shape. Off with ye.'" "White"
            Write-Host ""
            # Town upgrade (Phase 4e) stays buyable with pristine gear.
            # Master Crafting (Cat 11): Blacksmithing 50 opens the back room.
            $bsLvl = Get-SkillLevel "Blacksmithing"
            if($bsLvl -ge 50){
                Write-CL "  [C] Master Crafting — the back room is open" "Red"
            } else {
                Write-CL "  [C] Master Crafting (locked — Blacksmithing 50; now $bsLvl)" "DarkGray"
            }
            if(-not $script:TownUpgrades["Forge"]){
                Write-CL "  [U] Reinforce the Forge — 2 Dragon Tooth + 1 Demon Horn" "Magenta"
                Write-CL "      (all repairs -25%, permanent)" "DarkGray"
                Write-C  "  [C], [U] or Enter to leave: " "Yellow"
                $chIdle = Read-Host
                if($chIdle -match '^[Uu]$'){ Buy-ForgeUpgrade; continue }
                if($chIdle -match '^[Cc]$'){ if($bsLvl -ge 50){ Show-MasterCrafting } else { Write-CL "  'Fifty. Not a level less.'" "DarkGray"; Wait-Key }; continue }
            } else {
                Write-C  "  [C] or Enter to leave: " "Yellow"
                $chIdle = Read-Host
                if($chIdle -match '^[Cc]$'){ if($bsLvl -ge 50){ Show-MasterCrafting } else { Write-CL "  'Fifty. Not a level less.'" "DarkGray"; Wait-Key }; continue }
            }
            return
        }

        Write-CL "  The smith squints at your gear:" "DarkGray"
        Write-CL "  'Let's see what needs mending...'" "White"
        Write-Host ""

        # Table of damaged items
        $cw1 = 5; $cw2 = 10; $cw3 = 24; $cw4 = 13; $cw5 = 10
        $top = "  ┌$('─'*$cw1)┬$('─'*$cw2)┬$('─'*$cw3)┬$('─'*$cw4)┬$('─'*$cw5)┐"
        $mid = "  ├$('─'*$cw1)┼$('─'*$cw2)┼$('─'*$cw3)┼$('─'*$cw4)┼$('─'*$cw5)┤"
        $bot = "  └$('─'*$cw1)┴$('─'*$cw2)┴$('─'*$cw3)┴$('─'*$cw4)┴$('─'*$cw5)┘"
        $headerRow = "  │" + (Pad-Cell "#" $cw1) + "│" + (Pad-Cell "Slot" $cw2) + "│" + (Pad-Cell "Item" $cw3) + "│" + (Pad-Cell "Durability" $cw4) + "│" + (Pad-Cell "Cost" $cw5) + "│"

        Write-CL $top "DarkGray"
        Write-CL $headerRow "DarkGray"
        Write-CL $mid "DarkGray"

        $totalCost = 0
        for($i=0; $i -lt $damaged.Count; $i++){
            $d = $damaged[$i]
            $it = $d.Item
            $idxCell   = Pad-Cell ("$($i+1)") $cw1
            $slotCell  = Pad-Cell $d.Slot $cw2
            $nameCell  = Pad-Cell $it.Name $cw3
            $durCell   = Pad-Cell "$($it.Durability)/$($it.MaxDurability)" $cw4
            $costCell  = Pad-Cell ("$($d.Cost)g") $cw5
            $affordable = if($script:Gold -ge $d.Cost){"Green"}else{"DarkGray"}
            $durColor   = Get-DurabilityColor $it
            $totalCost += $d.Cost

            Write-C "  │" "DarkGray"
            Write-C $idxCell $affordable
            Write-C "│" "DarkGray"
            Write-C $slotCell "White"
            Write-C "│" "DarkGray"
            Write-C $nameCell "Cyan"
            Write-C "│" "DarkGray"
            Write-C $durCell $durColor
            Write-C "│" "DarkGray"
            Write-C $costCell $affordable
            Write-CL "│" "DarkGray"
        }
        Write-CL $bot "DarkGray"
        Write-Host ""

        # Repair All bundle (10% discount)
        $bulkCost = [math]::Floor($totalCost * 0.9)
        $bulkAffordable = if($script:Gold -ge $bulkCost){"Green"}else{"DarkGray"}

        Write-C "  [A] " "Yellow"
        Write-C "Repair All — " "White"
        Write-C "${bulkCost}g" $bulkAffordable
        Write-CL "  (10% bulk discount)" "DarkGray"
        if(-not $script:TownUpgrades["Forge"]){
            Write-CL "  [U] Reinforce the Forge — 2 Dragon Tooth + 1 Demon Horn (-25% repairs)" "Magenta"
        }
        # Master Crafting (Cat 11): Blacksmithing 50 opens the back room.
        $bsLvl = Get-SkillLevel "Blacksmithing"
        if($bsLvl -ge 50){
            Write-CL "  [C] Master Crafting — the back room is open" "Red"
        } else {
            Write-CL "  [C] Master Crafting (locked — Blacksmithing 50; now $bsLvl)" "DarkGray"
        }
        Write-CL "  [0] Leave" "White"
        Write-Host ""
        Write-C "  Repair which? (number / A / C / U / 0): " "Yellow"
        $ch = Read-Host

        if($ch -eq "0" -or $ch -eq ""){ return }

        if($ch -match '^[Uu]$'){ Buy-ForgeUpgrade; continue }

        if($ch -match '^[Cc]$'){ if($bsLvl -ge 50){ Show-MasterCrafting } else { Write-CL "  'Fifty. Not a level less.'" "DarkGray"; Wait-Key }; continue }

        if($ch -match '^[Aa]$'){
            # Repair all
            if($script:Gold -ge $bulkCost){
                $script:Gold -= $bulkCost
                foreach($d in $damaged){
                    $d.Item.Durability = $d.Item.MaxDurability
                }
                Write-Host ""
                Write-CL "  The smith works through the pile. Sparks fly." "Yellow"
                Write-CL "  All gear fully repaired for ${bulkCost}g." "Green"
                Update-QuestProgress "Repair"; $script:TotalRepairs++; Add-SkillXP "Blacksmithing" 20
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
            } else {
                Write-CL "  'Not enough gold for the lot. Try one at a time.'" "Red"
                Wait-Key
            }
        } else {
            $pick = 0
            if([int]::TryParse($ch, [ref]$pick) -and $pick -ge 1 -and $pick -le $damaged.Count){
                $d = $damaged[$pick - 1]
                if($script:Gold -ge $d.Cost){
                    $script:Gold -= $d.Cost
                    $d.Item.Durability = $d.Item.MaxDurability
                    Write-Host ""
                    Write-CL "  The smith hammers away at your $($d.Item.Name)." "Yellow"
                    Write-CL "  Repaired for $($d.Cost)g." "Green"
                    Update-QuestProgress "Repair"; $script:TotalRepairs++; Add-SkillXP "Blacksmithing" 20
                    Write-Host ""
                    Read-Host "  [Press Enter to continue]" | Out-Null
                } else {
                    Write-CL "  'Come back with more gold, adventurer.'" "Red"
                    Wait-Key
                }
            } else {
                Write-CL "  'I don't know which one ye mean.'" "DarkGray"
                Wait-Key
            }
        }
    }
}


# ─── RANDOM ENCOUNTERS ───────────────────────────────────────────
# Triggered during dungeon movement. Pulls player out of navigation
# briefly to present a choice. Dutchman is rare and unlocks the
# best weapon in the game (or demotes the player by 2 levels).
# ─── BLACKJACK MINI-GAME ──────────────────────────────────────────
# Self-contained 21 game used by the Underground Gambler encounter.
# Standard rules:
#   - Deck is a fresh single 52-card deck per session (no shoe across hands)
#   - Player can Hit, Stand, Double Down (if first action), Split (if first
#     action and pair), and use Insurance? — keeping it simple: NO insurance
#   - Dealer stands on all 17 (including soft)
#   - Blackjack (natural 21 on first two cards) pays 3:2
#   - Push (tie) returns the bet
#   - Player bust = immediate loss
#   - Doubling doubles the bet, adds exactly one more card, then stands
#   - Split creates two hands from a pair, each gets one new card; bet doubled
#   - Splits resolve sequentially. No re-splitting (max 2 hands).
# Returns the NET gold change (negative for loss, 0 for push, positive for
# win). The caller deducts/adds gold based on the return value.
function Start-Blackjack {
    param([int]$Bet)

    # ── Deck ──────────────────────────────────────────────────────
    # Build and shuffle a fresh 52-card deck. Cards are hashtables with
    # Suit (♠♥♦♣ as text), Rank (2-10, J, Q, K, A), and Value (numeric).
    $suits = @("S","H","D","C")
    $ranks = @(
        @{R="2"; V=2},@{R="3"; V=3},@{R="4"; V=4},@{R="5"; V=5},@{R="6"; V=6},
        @{R="7"; V=7},@{R="8"; V=8},@{R="9"; V=9},@{R="10";V=10},
        @{R="J"; V=10},@{R="Q"; V=10},@{R="K"; V=10},@{R="A"; V=11}
    )
    $deck = New-Object System.Collections.ArrayList
    foreach($s in $suits){
        foreach($r in $ranks){
            [void]$deck.Add(@{Suit=$s; Rank=$r.R; Value=$r.V})
        }
    }
    # Fisher-Yates shuffle
    $rng = [System.Random]::new()
    for($i=$deck.Count-1; $i -gt 0; $i--){
        $j = $rng.Next(0, $i+1)
        $tmp = $deck[$i]; $deck[$i] = $deck[$j]; $deck[$j] = $tmp
    }
    $deckIdx = 0
    $drawCard = {
        if($deckIdx -ge $deck.Count){ return $null }
        $c = $deck[$deckIdx]
        $script:bjDeckIdx = $deckIdx + 1
        return $c
    }

    # ── Hand value calc (handles aces as 1 or 11) ─────────────────
    function _BJ-HandValue {
        param($Hand)
        $total = 0; $aces = 0
        foreach($c in $Hand){
            $total += $c.Value
            if($c.Rank -eq "A"){ $aces++ }
        }
        # Demote aces from 11 to 1 while busting
        while($total -gt 21 -and $aces -gt 0){
            $total -= 10
            $aces--
        }
        return $total
    }

    # ── Card art (compact ASCII, 5 rows tall, 7 cols wide) ────────
    function _BJ-CardLines {
        param($Card,[switch]$Hidden)
        if($Hidden){
            return @(
                "┌─────┐",
                "│░░░░░│",
                "│░ ? ░│",
                "│░░░░░│",
                "└─────┘"
            )
        }
        $r = $Card.Rank
        $s = switch($Card.Suit){
            "S" { [char]0x2660 }   # ♠
            "H" { [char]0x2665 }   # ♥
            "D" { [char]0x2666 }   # ♦
            "C" { [char]0x2663 }   # ♣
        }
        # Pad rank to 2 chars (so "10" fits, others get a space)
        $rL = if($r.Length -eq 1){"$r "}else{"$r"}
        $rR = if($r.Length -eq 1){" $r"}else{"$r"}
        return @(
            "┌─────┐",
            "│$rL   │",
            "│  $s  │",
            "│   $rR│",
            "└─────┘"
        )
    }

    # ── Render a hand horizontally ────────────────────────────────
    function _BJ-DrawHand {
        param($Hand,$Label,[switch]$HideHole,$ColorRank="White",$ColorBorder="DarkGray")
        $rows = @("","","","","")
        for($ci=0; $ci -lt $Hand.Count; $ci++){
            $hide = ($HideHole.IsPresent -and $ci -eq 1)
            $lines = _BJ-CardLines -Card $Hand[$ci] -Hidden:$hide
            for($li=0; $li -lt 5; $li++){
                $rows[$li] += $lines[$li] + " "
            }
        }
        $val = if($HideHole.IsPresent){ "?" } else { _BJ-HandValue $Hand }
        Write-CL "  $Label  ($val)" $ColorRank
        foreach($row in $rows){
            Write-C "  " "Black"
            $isRed = $false
            # Color suits red for hearts/diamonds when visible
            for($ci=0; $ci -lt $row.Length; $ci++){
                $ch = $row[$ci]
                $col = $ColorBorder
                if($ch -eq [char]0x2665 -or $ch -eq [char]0x2666){ $col = "Red" }
                elseif($ch -eq [char]0x2660 -or $ch -eq [char]0x2663){ $col = "White" }
                elseif($ch -eq '░'){ $col = "DarkBlue" }
                elseif([char]::IsLetterOrDigit($ch)){ $col = "White" }
                Write-C ([string]$ch) $col
            }
            Write-Host ""
        }
    }

    # ── Deal opening hand ─────────────────────────────────────────
    $playerHands = @()
    $playerBets  = @()
    $h = New-Object System.Collections.ArrayList
    [void]$h.Add($deck[$deckIdx]); $deckIdx++
    [void]$h.Add($deck[$deckIdx]); $deckIdx++
    $playerHands += ,$h
    $playerBets  += $Bet

    $dealerHand = New-Object System.Collections.ArrayList
    [void]$dealerHand.Add($deck[$deckIdx]); $deckIdx++
    [void]$dealerHand.Add($deck[$deckIdx]); $deckIdx++

    # ── Dealing animation ─────────────────────────────────────────
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
    Write-CL "  ║          U N D E R G R O U N D   2 1            ║" "Yellow"
    Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
    Write-Host ""
    Write-CL "  Bet: ${Bet}g" "Yellow"
    Write-Host ""
    Write-CL "  Dealing..." "DarkGray"
    Start-Sleep -Milliseconds 600

    # ── Player turn loop (handles split as second hand) ───────────
    $handIdx = 0
    while($handIdx -lt $playerHands.Count){
        $hand = $playerHands[$handIdx]
        $playerStanding = $false
        $firstAction = $true
        $doubled = $false

        while(-not $playerStanding){
            clr
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
            Write-CL "  ║          U N D E R G R O U N D   2 1            ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
            Write-Host ""
            $betLabel = "Bet"
            if($playerHands.Count -gt 1){ $betLabel = "Hand $($handIdx+1) Bet" }
            Write-CL "  $betLabel`: $($playerBets[$handIdx])g       Your Gold: $($script:Gold)g" "Yellow"
            Write-Host ""
            _BJ-DrawHand -Hand $dealerHand -Label "DEALER" -HideHole -ColorRank "Magenta"
            Write-Host ""
            $playerLabel = if($playerHands.Count -gt 1){"YOU (Hand $($handIdx+1) of $($playerHands.Count))"}else{"YOU"}
            _BJ-DrawHand -Hand $hand -Label $playerLabel -ColorRank "Cyan"
            Write-Host ""

            $pVal = _BJ-HandValue $hand
            if($pVal -eq 21 -and $hand.Count -eq 2){
                # Natural blackjack — auto-stand
                Write-CL "  *** BLACKJACK! ***" "Yellow"
                Start-Sleep -Milliseconds 1200
                $playerStanding = $true
                break
            }
            if($pVal -gt 21){
                Write-CL "  BUST!" "Red"
                Write-Host ""
                # Wait for the player to press Enter so they can read the
                # bust before the dealer turn starts. Replaces the 1.2s
                # auto-advance, which was too fast to register.
                Read-Host "  [Press Enter to continue]" | Out-Null
                $playerStanding = $true
                break
            }

            # Build action menu
            $opts = "[H]it  [S]tand"
            $canDouble = ($firstAction -and $script:Gold -ge $playerBets[$handIdx])
            if($canDouble){ $opts += "  [D]ouble" }
            $canSplit = ($firstAction -and $hand.Count -eq 2 -and $hand[0].Value -eq $hand[1].Value -and $playerHands.Count -lt 2 -and $script:Gold -ge $Bet)
            if($canSplit){ $opts += "  [P] Split" }
            Write-CL "  $opts" "White"
            Write-C  "  > " "Yellow"
            $action = Read-Host
            if(-not $action){ continue }
            $action = $action.ToUpper().Substring(0,1)

            if($action -eq "H"){
                [void]$hand.Add($deck[$deckIdx]); $deckIdx++
                $firstAction = $false
            }
            elseif($action -eq "S"){
                $playerStanding = $true
            }
            elseif($action -eq "D" -and $canDouble){
                # Double the bet for THIS hand (gold is already on the line — we tracked
                # it as deducted upfront. Add the additional bet to script:Gold-going-out.
                $script:Gold -= $playerBets[$handIdx]   # extra wager
                $playerBets[$handIdx] *= 2
                [void]$hand.Add($deck[$deckIdx]); $deckIdx++
                $doubled = $true
                $playerStanding = $true
                # Bug fix: the turn ends immediately on a double-down, so
                # the loop-top BUST banner never showed. Give the player
                # their moment of pain right here.
                $ddVal = _BJ-HandValue $hand
                if($ddVal -gt 21){
                    Write-Host ""
                    Write-CL "  Doubled down and drew... BUST! ($ddVal)" "Red"
                    Start-Sleep -Milliseconds 900
                }
            }
            elseif($action -eq "P" -and $canSplit){
                # Split: take the second card off into a new hand. Each hand
                # gets one fresh card. Bet for the new hand equals original.
                $script:Gold -= $Bet  # extra wager for the new hand
                $secondCard = $hand[1]
                $hand.RemoveAt(1)
                [void]$hand.Add($deck[$deckIdx]); $deckIdx++
                $newHand = New-Object System.Collections.ArrayList
                [void]$newHand.Add($secondCard)
                [void]$newHand.Add($deck[$deckIdx]); $deckIdx++
                $playerHands += ,$newHand
                $playerBets  += $Bet
                $firstAction = $false
                # Continue with current hand (don't break loop)
            }
        }
        $handIdx++
    }

    # ── Dealer turn ───────────────────────────────────────────────
    # Dealer reveals hole, then hits until 17 or higher (stands on all 17).
    # Skip dealer turn if all player hands busted (saves time).
    $allBust = $true
    foreach($ph in $playerHands){
        if((_BJ-HandValue $ph) -le 21){ $allBust = $false; break }
    }

    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
    Write-CL "  ║          U N D E R G R O U N D   2 1            ║" "Yellow"
    Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
    Write-Host ""
    _BJ-DrawHand -Hand $dealerHand -Label "DEALER" -ColorRank "Magenta"
    Write-Host ""
    for($pi=0; $pi -lt $playerHands.Count; $pi++){
        $lbl = if($playerHands.Count -gt 1){"YOU (Hand $($pi+1))"}else{"YOU"}
        _BJ-DrawHand -Hand $playerHands[$pi] -Label $lbl -ColorRank "Cyan"
        Write-Host ""
    }
    Start-Sleep -Milliseconds 800

    if(-not $allBust){
        $dVal = _BJ-HandValue $dealerHand
        while($dVal -lt 17){
            Write-CL "  Dealer hits..." "DarkGray"
            Start-Sleep -Milliseconds 700
            [void]$dealerHand.Add($deck[$deckIdx]); $deckIdx++
            $dVal = _BJ-HandValue $dealerHand
            clr
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
            Write-CL "  ║          U N D E R G R O U N D   2 1            ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
            Write-Host ""
            _BJ-DrawHand -Hand $dealerHand -Label "DEALER" -ColorRank "Magenta"
            Write-Host ""
            for($pi=0; $pi -lt $playerHands.Count; $pi++){
                $lbl = if($playerHands.Count -gt 1){"YOU (Hand $($pi+1))"}else{"YOU"}
                _BJ-DrawHand -Hand $playerHands[$pi] -Label $lbl -ColorRank "Cyan"
                Write-Host ""
            }
        }
        if($dVal -gt 21){
            Write-CL "  Dealer BUSTS!" "Green"
        } else {
            Write-CL "  Dealer stands on $dVal." "DarkGray"
        }
        Start-Sleep -Milliseconds 1000
    } else {
        Write-CL "  Dealer doesn't need to play." "DarkGray"
        Start-Sleep -Milliseconds 800
    }

    # ── Resolve each hand ─────────────────────────────────────────
    # Bet accounting: the initial $Bet was already deducted by the caller
    # before calling this function. Any ADDITIONAL bets from doubling or
    # splitting were also deducted live above. So at this point all wagers
    # are "off the table". We now credit $script:Gold based on results:
    #   - Win:        credit 2x the hand's bet (return + winnings)
    #   - Blackjack:  credit 2.5x the original bet (3:2 payout)
    #   - Push:       credit 1x the hand's bet (bet returned)
    #   - Loss/Bust:  credit 0 (already gone)
    # netChange is the net delta from PRE-bet gold (informational only).
    $dealerVal = _BJ-HandValue $dealerHand
    $netChange = -$Bet   # initial bet
    # Account for additional wagers from double/split
    foreach($pb in $playerBets){
        if($pb -ne $Bet){
            # bet was doubled (or split made an extra entry of $Bet — that
            # added bet was already counted). Track total wagered.
            $netChange -= ($pb - $Bet)
        }
    }
    # For splits, each hand has its own $Bet entry so the loop above only
    # catches doubled hands. The extra split wager was deducted live.
    if($playerHands.Count -gt 1){
        $netChange -= $Bet * ($playerHands.Count - 1)
    }

    Write-Host ""
    Write-CL "  ── Results ──" "Yellow"
    for($pi=0; $pi -lt $playerHands.Count; $pi++){
        $ph = $playerHands[$pi]
        $pv = _BJ-HandValue $ph
        $pBet = $playerBets[$pi]
        $isNatural = ($ph.Count -eq 2 -and $pv -eq 21 -and $playerHands.Count -eq 1)
        $label = if($playerHands.Count -gt 1){"Hand $($pi+1)"}else{"Hand"}
        if($pv -gt 21){
            Write-CL "    $label`: BUST. Lost ${pBet}g." "Red"
            # No credit — wager already gone.
        }
        elseif($isNatural -and $dealerVal -ne 21){
            # 3:2 payout — get bet back PLUS 1.5x bet winnings
            $payout = $pBet + [int][math]::Floor($pBet * 1.5)
            $script:Gold += $payout
            $netChange += $payout
            $winAmt = [int][math]::Floor($pBet * 1.5)
            Write-CL "    $label`: BLACKJACK! Won ${winAmt}g (3:2)." "Yellow"
        }
        elseif($dealerVal -gt 21){
            # Dealer bust — get bet back plus 1x bet winnings
            $script:Gold += ($pBet * 2)
            $netChange += ($pBet * 2)
            Write-CL "    $label`: Dealer bust. Won ${pBet}g." "Green"
        }
        elseif($pv -gt $dealerVal){
            $script:Gold += ($pBet * 2)
            $netChange += ($pBet * 2)
            Write-CL "    $label`: WIN. Won ${pBet}g." "Green"
        }
        elseif($pv -lt $dealerVal){
            Write-CL "    $label`: LOSE. Lost ${pBet}g." "Red"
        }
        else {
            # Push — return bet
            $script:Gold += $pBet
            $netChange += $pBet
            Write-CL "    $label`: PUSH. Bet returned." "DarkGray"
        }
    }
    Write-Host ""
    Write-CL "  Net change: $(if($netChange -ge 0){'+'}else{''})${netChange}g" $(if($netChange -gt 0){"Green"}elseif($netChange -lt 0){"Red"}else{"DarkGray"})
    return $netChange
}

function Start-RandomEncounter {
    param([string]$Type = "")
    # If the player was holding a movement key when the encounter triggered,
    # the OS keeps queueing keystrokes. The first Read-Host or Wait-Key in
    # the encounter would immediately consume those as the player's answer,
    # making the encounter flash by unseen. Drain the buffer first, and also
    # pause briefly so the "encountering something" moment feels deliberate.
    Drain-Keys
    Start-Sleep -Milliseconds 150
    # Second drain in case new auto-repeats arrived during the pause
    Drain-Keys

    $p = $script:Player
    if(-not $Type){
        # Pick from available options.
        # - Alchemist can't spawn if potion bag is full (trade would be wasted).
        # - Bard can't spawn if HP and MP are both already full (heal would be wasted).
        # - Gambler needs at least 50g to bet meaningfully.
        # Phase 4: at high Corruption the kindly merchant does not
        # wander these halls — something else does.
        $options = @(if($script:Corruption -ge 60){"Thief"}else{"Merchant"})
        if($p.HP -lt $p.MaxHP -or $p.MP -lt $p.MaxMP){
            $options += "Bard"
        }
        if($script:Potions.Count -lt 10){
            $options += "Alchemist"
        }
        if($script:Gold -ge 50){
            $options += "Gambler"
        }
        $Type = $options | Get-Random
    }

    clr
    switch($Type){
        "Bard" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkMagenta"
            Write-CL "  ║             T H E   H E A L I N G   B A R D             ║" "Magenta"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkMagenta"
            Write-Host ""
            Write-CL "           ♪    ♫        ♪         ♫      ♪" "Yellow"
            Write-CL "               ▄▄▄▄               " "Magenta"
            Write-CL "             ▄█▓▓▓▓█▄             " "Magenta"
            Write-CL "            █▓▓ o o ▓▓█           " "Magenta"
            Write-CL "            █▓▓  □  ▓▓█           " "Magenta"
            Write-CL "             ▀█▓▓▓▓█▀             " "Magenta"
            Write-CL "               ║║                   ║│═─═│║" "DarkMagenta"
            Write-CL "              ═╩╩═               │═─═│" "DarkMagenta"
            Write-CL "              ║▓▓║                ║── ║" "DarkMagenta"
            Write-CL "              ╝▓▓╚               ╚═══╝" "DarkMagenta"
            Write-Host ""
            Write-CL "  A cheerful bard strums a lute in a forgotten alcove." "Gray"
            Write-CL "  'Traveler! Let my song mend your weary soul.'" "Yellow"
            Write-Host ""
            $hpRestore = [math]::Floor($p.MaxHP * (Get-Random -Min 30 -Max 61) / 100)
            $mpRestore = [math]::Floor($p.MaxMP * (Get-Random -Min 30 -Max 61) / 100)
            $p.HP = [math]::Min($p.HP + $hpRestore, $p.MaxHP)
            $p.MP = [math]::Min($p.MP + $mpRestore, $p.MaxMP)
            Write-CL "  You feel refreshed! +$hpRestore HP, +$mpRestore MP" "Green"
            Write-CL "  HP: $($p.HP)/$($p.MaxHP)  MP: $($p.MP)/$($p.MaxMP)" "White"
            Try-UnlockAchievement "Bard"
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
        "Thief" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
            Write-CL "  ║         C U T P U R S E   I N   T H E   D A R K          ║" "Red"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
            Write-Host ""
            Write-CL "  A hooded figure melts out of the corridor shadows," "Gray"
            Write-CL "  knife already drifting toward your coin purse." "Gray"
            Write-CL "  'The Depths are hungry, friend. Feed them - or feed me.'" "Red"
            Write-Host ""
            if($script:Gold -lt 20){
                Write-CL "  He eyes your purse, scoffs, and melts back into the dark." "DarkGray"
                Write-CL "  'Not worth the knife.'" "DarkGray"
            } else {
                $demand = [math]::Max(20, [math]::Floor($script:Gold * 0.10))
                Write-CL "  [1] Hand over ${demand}g" "Yellow"
                Write-CL "  [2] Refuse and stand your ground" "Red"
                Write-C  "  > " "Yellow"
                $tc = Read-Host
                if($tc -eq "1"){
                    $script:Gold -= $demand
                    Write-Host ""
                    Write-CL "  He weighs the coin, nods once, and is gone." "DarkGray"
                    Write-CL "  (-${demand}g)" "Red"
                } else {
                    # SPD contest: quick adventurers drive him off clean.
                    $chance = [math]::Min(45 + ($script:Player.SPD * 2), 90)
                    if((Get-Random -Max 100) -lt $chance){
                        Write-Host ""
                        Write-CL "  You catch his wrist mid-reach. He wrenches free" "Gray"
                        Write-CL "  and bolts, cursing. Your purse stays yours." "Green"
                    } else {
                        $cut  = [math]::Floor($script:Gold * 0.15)
                        $nick = Get-Random -Min 5 -Max 11
                        $script:Gold = [math]::Max(0, $script:Gold - $cut)
                        $script:Player.HP = [math]::Max(1, $script:Player.HP - $nick)
                        Write-Host ""
                        Write-CL "  A flash of steel - he is faster. The purse strings" "Gray"
                        Write-CL "  part, and so does the skin of your forearm." "Red"
                        Write-CL "  (-${cut}g, -${nick} HP)" "Red"
                    }
                }
            }
            Write-Host ""
            Wait-Enter
        }
        "Merchant" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
            Write-CL "  ║             T H E   L O S T   M E R C H A N T          ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
            Write-Host ""
            Write-CL "              ▄▄▄▄▄▄▄▄▄▄▄▄▄▄              " "DarkYellow"
            Write-CL "             █▓CART   GOODS▓█            " "Yellow"
            Write-CL "             █▓  ▀▄▄▄▄▄▄▀  ▓█            " "Yellow"
            Write-CL "              ▀▄▄████████▄▄▀             " "DarkYellow"
            Write-CL "                ◎        ◎                " "DarkYellow"
            Write-Host ""
            Write-CL "  A disheveled merchant emerges from the shadows." "Gray"
            Write-CL "  'Lost for weeks! Please — take anything! 60% off!'" "Yellow"
            Write-Host ""
            # Pick one random high-tier item
            $allWpn = Get-WeaponShop | Where-Object { $_.Price -ge 300 }
            $allArm = Get-ArmorShop | Where-Object { $_.Price -ge 200 }
            $allPot = Get-PotionShop | Where-Object { $_.Category -eq "Potion" }

            $offerKind = Get-Random -Min 0 -Max 3
            $item = $null; $itemKind = "None"; $origPrice = 0
            switch($offerKind){
                0 {
                    if($allWpn.Count -gt 0){ $item = $allWpn | Get-Random; $itemKind = "Weapon"; $origPrice = $item.Price }
                }
                1 {
                    if($allArm.Count -gt 0){ $item = $allArm | Get-Random; $itemKind = "Armor"; $origPrice = $item.Price }
                }
                2 {
                    if($allPot.Count -gt 0){ $item = $allPot | Get-Random; $itemKind = "Potion"; $origPrice = $item.Price }
                }
            }
            if(-not $item){
                Write-CL "  The merchant's cart is empty. He apologizes and vanishes." "DarkGray"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            $salePrice = [math]::Floor($origPrice * 0.4)
            Write-CL "  Offer: $($item.Name) [$itemKind]" "Cyan"

            # ── Compare against currently equipped gear ──
            # For weapons: compare ATK + AffinityBonus (when class matches).
            # For armor: compare DEF for the same slot.
            # Potions don't compare — there's no equipped potion to weigh.
            $cmpTag  = ""
            $cmpClr  = "DarkGray"
            if($itemKind -eq "Weapon"){
                $offerAtk   = [int]$item.ATK
                if(Test-WeaponClassMatch $item){
                    $offerAtk += [int]$item.AffinityBonus
                }
                $currentAtk = 0
                if($script:EquippedWeapon){
                    $currentAtk = [int]$script:EquippedWeapon.ATK
                    if(Test-WeaponClassMatch $script:EquippedWeapon){
                        $currentAtk += [int]$script:EquippedWeapon.AffinityBonus
                    }
                }
                if($currentAtk -eq 0){
                    $cmpTag = " (you have no weapon equipped)"
                    $cmpClr = "Yellow"
                } elseif($offerAtk -gt $currentAtk){
                    $cmpTag = "  ▲ better than current ATK $currentAtk -> $offerAtk"
                    $cmpClr = "Green"
                } elseif($offerAtk -lt $currentAtk){
                    $cmpTag = "  ▼ worse than current ATK $currentAtk -> $offerAtk"
                    $cmpClr = "Red"
                } else {
                    $cmpTag = "  = same ATK as current ($currentAtk)"
                    $cmpClr = "DarkGray"
                }
            }
            elseif($itemKind -eq "Armor"){
                $slot = [string]$item.Slot
                $offerDef   = [int]$item.DEF
                $current = $null
                if($slot -and $script:EquippedArmor -and $script:EquippedArmor.ContainsKey($slot)){
                    $current = $script:EquippedArmor[$slot]
                }
                $currentDef = if($current){[int]$current.DEF}else{0}
                if(-not $current){
                    $cmpTag = " (you have no $slot equipped)"
                    $cmpClr = "Yellow"
                } elseif($offerDef -gt $currentDef){
                    $cmpTag = "  ▲ better than current DEF $currentDef -> $offerDef"
                    $cmpClr = "Green"
                } elseif($offerDef -lt $currentDef){
                    $cmpTag = "  ▼ worse than current DEF $currentDef -> $offerDef"
                    $cmpClr = "Red"
                } else {
                    $cmpTag = "  = same DEF as current ($currentDef)"
                    $cmpClr = "DarkGray"
                }
            }
            if($cmpTag){
                Write-CL $cmpTag $cmpClr
            }

            Write-C "  Normal price: " "DarkGray"; Write-CL "$($origPrice)g" "DarkYellow"
            Write-C "  Today's price: " "DarkGray"; Write-CL "$($salePrice)g (60% off!)" "Yellow"
            Write-Host ""
            Write-C "  Buy? (y/n): " "Yellow"; $ans = Read-Host
            if($ans -eq 'y' -or $ans -eq 'Y'){
                if($script:Gold -ge $salePrice){
                    $script:Gold -= $salePrice
                    switch($itemKind){
                        "Weapon" {
                            $newWeapon = Init-ItemDurability $item
                            if(-not $newWeapon.Kind){ $newWeapon.Kind = "Weapon" }
                            $script:WeaponsOwned[$item.Name] = $true
                            Invoke-GearAcquired -Item $newWeapon -Kind "Weapon"
                        }
                        "Armor" {
                            if(-not $item.Slot){
                                Write-CL "  The merchant fumbles. The piece slips and is lost." "Red"
                                Write-CL "  (No slot info — refunding ${salePrice}g)" "DarkGray"
                                $script:Gold += $salePrice
                            } else {
                                $newArmor = Init-ItemDurability $item
                                if(-not $newArmor.Kind){ $newArmor.Kind = "Armor" }
                                $script:ArmorOwned[$item.Name] = $true
                                Invoke-GearAcquired -Item $newArmor -Kind "Armor"
                            }
                        }
                        "Potion" {
                            if($script:Potions.Count -ge 10){
                                Write-CL "  Your potion bag is full! The merchant frowns." "Red"
                                Write-CL "  (Refunded ${salePrice}g)" "DarkGray"
                                $script:Gold += $salePrice
                            } else {
                                [void]$script:Potions.Add($item)
                                Write-CL "  Added $($item.Name) to your potion bag." "Green"
                            }
                        }
                    }
                    Try-UnlockAchievement "Merchant"
                    Check-Achievements
                } else {
                    Write-CL "  'Ah... no gold. Such a shame.'" "Red"
                }
            } else {
                Write-CL "  'Suit yourself, friend.'" "DarkGray"
            }
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
        "Alchemist" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkGreen"
            Write-CL "  ║          T H E   W A N D E R I N G   A L C H E M I S T  ║" "Green"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkGreen"
            Write-Host ""
            Write-CL "                ░░░░░▄▄▄▄░░░░░               " "DarkGreen"
            Write-CL "              ▄▀ BUBBLE BUBBLE▀▄            " "Green"
            Write-CL "              ║~~~~~~~~~~~~~~~║            " "Green"
            Write-CL "              ║    POTIONS    ║            " "DarkGreen"
            Write-CL "               ▀▄▄▄▄▄▄▄▄▄▄▄▄▀             " "DarkGreen"
            Write-Host ""
            Write-CL "  A bent-backed alchemist stirs a cauldron." "Gray"
            Write-CL "  'Trade me 2 loot trinkets — I'll brew you something useful.'" "Green"
            Write-Host ""
            if($script:Inventory.Count -lt 2){
                Write-CL "  'Alas, you carry too little to trade. Come back when you loot more.'" "DarkGray"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            if($script:Potions.Count -ge 10){
                Write-CL "  The alchemist glances at your bulging potion bag." "DarkGray"
                Write-CL "  'Your satchel overflows already. Drink one, then return.'" "Green"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            Write-C "  Trade 2 loot items for a random potion? (y/n): " "Yellow"
            $ans = Read-Host
            if($ans -eq 'y' -or $ans -eq 'Y'){
                for($i=0; $i -lt 2; $i++){
                    $rmIdx = Get-Random -Min 0 -Max $script:Inventory.Count
                    $lost = $script:Inventory[$rmIdx]
                    $script:Inventory.RemoveAt($rmIdx)
                    Write-CL "  Traded: $($lost.Name)" "DarkGray"
                }
                $availablePotions = Get-PotionShop | Where-Object { $_.Category -eq "Potion" }
                $got = $availablePotions | Get-Random
                [void]$script:Potions.Add($got)
                Write-CL "  The alchemist hands you: $($got.Name)" "Green"
            } else {
                Write-CL "  'Wise to hoard, perhaps. Be gone.'" "DarkGray"
            }
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
        "RepairSmith" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
            Write-CL "  ║          A   W A N D E R I N G   M E T A L S M I T H    ║" "Red"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
            Write-Host ""
            # Small forge-on-cart art
            Write-CL "             ___________ " "DarkGray"
            Write-CL "            /  ___      \" "DarkGray"
            Write-CL "           |  /  ^  \   |" "Red"
            Write-CL "           | |  ( ) | _|" "Yellow"
            Write-CL "           | | ~~~  || /" "DarkYellow"
            Write-CL "            \|______|//" "DarkGray"
            Write-CL "            o^o^^^^o^o" "DarkGray"
            Write-Host ""
            Write-CL "  An old smith with a portable forge nods at your gear." "Gray"
            Write-CL "  'Aye, lemme set that right. No charge — pay it forward.'" "Yellow"
            Write-Host ""

            # Repair every damaged piece to full
            $totalPointsRestored = 0
            $itemsTouched = 0

            if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0){
                $missing = $script:EquippedWeapon.MaxDurability - $script:EquippedWeapon.Durability
                if($missing -gt 0){
                    $script:EquippedWeapon.Durability = $script:EquippedWeapon.MaxDurability
                    $totalPointsRestored += $missing
                    $itemsTouched++
                    Write-CL "  ✓ $($script:EquippedWeapon.Name) repaired (+$missing)" "Green"
                }
            }
            foreach($slotN in @("Helmet","Chest","Shield","Amulet","Boots")){
                $piece = $script:EquippedArmor[$slotN]
                if($piece -and $piece.MaxDurability -ge 0){
                    $missing = $piece.MaxDurability - $piece.Durability
                    if($missing -gt 0){
                        $piece.Durability = $piece.MaxDurability
                        $totalPointsRestored += $missing
                        $itemsTouched++
                        Write-CL "  ✓ $($piece.Name) repaired (+$missing)" "Green"
                    }
                }
            }

            Write-Host ""
            if($itemsTouched -eq 0){
                Write-CL "  Your gear is already in fine shape. The smith shrugs and moves on." "DarkGray"
            } else {
                Write-CL "  $itemsTouched item(s) restored. $totalPointsRestored durability points returned." "Yellow"
                Write-CL "  'Be safe down there, friend.'" "Cyan"
            }
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
        "Dutchman" {
            # Only trigger once per game if already owned
            if($script:OwnsDutchmanBlade){
                Write-CL "  A phantom ship drifts by, but the captain nods and vanishes." "DarkGray"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkCyan"
            Write-CL "  ║           T H E   F L Y I N G   D U T C H M A N         ║" "Cyan"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkCyan"
            Write-Host ""
            # User-provided ghost ship art (single-quoted to avoid interpolation)
            Write-CL '                             |    |    |              ' "White"
            Write-CL '                            )_)  )_)  )_)              ' "DarkCyan"
            Write-CL '                           )___))___))___)\           ' "DarkCyan"
            Write-CL '                          )____)____)_____)\\         ' "DarkCyan"
            Write-CL '                        _____|____|____|____\\\__     ' "Cyan"
            Write-CL '               ---------\                   /---------' "Cyan"
            Write-CL '                 ^^^^^ ^^^^^^^^^^^^^^^^^^^^^            ' "Blue"
            Write-CL '                   ^^^^      ^^^^     ^^^    ^^        ' "Blue"
            Write-CL '                        ^^^^      ^^^                  ' "DarkBlue"
            Write-Host ""
            Write-CL "  The Flying Dutchman materializes before you, its spectral" "Gray"
            Write-CL "  captain stepping through stone walls. He holds out a blade" "Gray"
            Write-CL "  that crackles with dark energy — and a coin." "Gray"
            Write-Host ""
            Write-CL "  'A wager, mortal. Call heads or tails.'" "Cyan"
            Write-CL "  'WIN — and take my blade: the DUTCHMAN'S BLADE." "DarkCyan"
            Write-CL "         ATK+100, worth 10,000 gold, steals life on hit.'" "DarkCyan"
            Write-CL "  'LOSE — and forfeit TWO levels of your experience.'" "DarkRed"
            Write-Host ""
            Write-C "  Accept the wager? (y/n): " "Yellow"; $ans = Read-Host
            if($ans -ne 'y' -and $ans -ne 'Y'){
                Write-CL "  The Dutchman chuckles and fades. Perhaps you were wise." "DarkGray"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            Write-Host ""
            Write-C "  Call it! (h)eads or (t)ails: " "Yellow"; $call = Read-Host
            $call = $call.ToLower()
            if($call -ne 'h' -and $call -ne 't'){
                Write-CL "  The Dutchman scowls. 'Choose, coward!'" "Red"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                return
            }
            # Coin flip
            Write-Host ""
            Write-CL "  The coin spins in the air..." "DarkGray"
            for($i=0; $i -lt 6; $i++){
                $face = if(($i % 2) -eq 0){"( H )"}else{"( T )"}
                Write-C "    " "Black"; Write-CL $face "Yellow"
                Start-Sleep -Milliseconds 140
                try {
                    $pos = $Host.UI.RawUI.CursorPosition
                    $newY = $pos.Y - 1
                    if($newY -ge 0){
                        $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                        Write-Host (" " * 20) -NoNewline
                        $Host.UI.RawUI.CursorPosition = New-Object System.Management.Automation.Host.Coordinates 0, $newY
                    }
                } catch {}
            }
            # Use a freshly-seeded Random for the actual coin flip. Get-Random's
            # default RNG should be fair, but a player reported tails winning
            # 100% of the time — likely just sample noise, but switching to an
            # explicit seeded RNG removes any doubt about distribution.
            $coinRng = [System.Random]::new()
            $coinVal = $coinRng.Next(0, 2)   # 0 or 1, evenly distributed
            $result = if($coinVal -eq 0){"h"}else{"t"}
            $resFace = if($result -eq 'h'){"( H )"}else{"( T )"}
            Write-CL "  Result: $resFace" "Yellow"
            Write-Host ""
            # Case-insensitive comparison just in case input had odd casing
            if($call.Trim().ToLower() -eq $result){
                Write-CL "  The Dutchman bows solemnly." "Cyan"
                Write-CL "  'The blade is yours. Use it well, mortal.'" "DarkCyan"
                # Add the blade
                $dutchBlade = @{
                    Name="Dutchman's Blade"; ATK=100; Price=10000; WeaponType="Sword"
                    ClassAffinity="None"; AffinityBonus=0; Perk="Drain"; PerkChance=40
                }
                $newBlade = Init-ItemDurability $dutchBlade
                if(-not $newBlade.Kind){ $newBlade.Kind = "Weapon" }
                $script:OwnsDutchmanBlade = $true
                $script:WeaponsOwned["Dutchman's Blade"] = $true
                Invoke-GearAcquired -Item $newBlade -Kind "Weapon"
                Try-UnlockAchievement "Lucky"
                Check-Achievements
            } else {
                Write-CL "  The Dutchman laughs, cold and hollow." "DarkRed"
                Write-CL "  'Your soul grows dimmer, mortal.'" "Red"
                $oldLvl = $script:PlayerLevel
                $script:PlayerLevel = [math]::Max($script:PlayerLevel - 2, 1)
                $lost = $oldLvl - $script:PlayerLevel
                # Roll back EXACTLY what levels grant (bug fix): level-ups
                # award +10 MaxHP and +5 MaxMP only — ATK/DEF/SPD/MAG come
                # from training points, talents, and gear. The old rollback
                # subtracted combat stats the levels never granted,
                # permanently robbing the player.
                $p.MaxHP = [math]::Max($p.MaxHP - (10 * $lost), 50)
                $p.MaxMP = [math]::Max($p.MaxMP - (5 * $lost), 20)
                if($p.HP -gt $p.MaxHP){ $p.HP = $p.MaxHP }
                if($p.MP -gt $p.MaxMP){ $p.MP = $p.MaxMP }
                Write-CL "  You lost $lost levels. (Now level $($script:PlayerLevel))" "Red"
            }
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
        "Gambler" {
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
            Write-CL "  ║          T H E   U N D E R G R O U N D   G A M B L E R         ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
            Write-Host ""
            # Quick ASCII portrait — shady figure at a card table
            Write-CL "                ___" "DarkGray"
            Write-CL "              .'   '." "DarkGray"
            Write-CL "             | () () |" "Yellow"
            Write-CL "             | ' ▔ ' |" "Yellow"
            Write-CL "             |  \=/  |" "DarkYellow"
            Write-CL "            /│       │\\" "DarkGray"
            Write-CL "           ░░│  ♠ ♥  │░░" "DarkRed"
            Write-CL "          ░░░│  ♦ ♣  │░░░" "Red"
            Write-CL "         ░░░░├───────┤░░░░" "DarkGray"
            Write-Host ""
            Write-CL "  A hooded figure waves you over to a candlelit table." "Gray"
            Write-CL "  'A hand of twenty-one, traveler? Just one. Your bet.'" "Yellow"
            Write-Host ""
            Write-C "  You have " "DarkGray"
            Write-CL "$($script:Gold)g" "Yellow"
            Write-Host ""
            Write-CL "  [P]lay   [L]eave" "White"
            Write-C "  > " "Yellow"; $gAns = Read-Host
            if($gAns -ne 'P' -and $gAns -ne 'p'){
                Write-CL "  The gambler shrugs. 'Another time, then.'" "DarkGray"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                break
            }
            # Bet entry
            Write-Host ""
            Write-CL "  Enter your bet (1-$($script:Gold), or 'A' for ALL-IN):" "Yellow"
            Write-C "  > " "Yellow"; $bAns = Read-Host
            $bet = 0
            if($bAns -eq 'A' -or $bAns -eq 'a'){
                $bet = $script:Gold
            } else {
                $parsed = 0
                if([int]::TryParse($bAns, [ref]$parsed)){
                    $bet = $parsed
                }
            }
            if($bet -lt 1 -or $bet -gt $script:Gold){
                Write-CL "  'That's not a real wager. Walk on.'" "Red"
                Write-Host ""
                Read-Host "  [Press Enter to continue]" | Out-Null
                break
            }
            # Deduct upfront. Start-Blackjack credits gold internally on win/push.
            $script:Gold -= $bet
            $netChange = Start-Blackjack -Bet $bet
            Write-CL "  Your gold: $($script:Gold)g" "Yellow"
            Write-Host ""
            Read-Host "  [Press Enter to continue]" | Out-Null
        }
    }
}

# ─── DUNGEON EXPLORATION LOOP ────────────────────────────────────
# ─── LOCKPICKING MINIGAME ─────────────────────────────────────────
# Adapted from the standalone lockpicking.ps1. Wrapped as a function that:
#   - Takes number of tumblers (difficulty) scaled by dungeon level
#   - Uses actual $script:Lockpicks count (displayed as a number)
#   - Returns @{ Success; Aborted; PicksUsed }
#   - Uses $script:lp* names so it doesn't clobber main game state
function Start-Lockpicking {
    param(
        [int]$Tumblers = 4,      # 3 (easy), 4 (normal), 5 (hard)
        [int]$AvailablePicks = 5
    )

    # Drain stale keys so a held movement key doesn't auto-break a pick
    Drain-Keys

    # Snapshot screen state so we can restore after
    $wasVisible = $true
    try { $wasVisible = [Console]::CursorVisible } catch {}
    try { [Console]::CursorVisible = $false } catch {}

    # Input mode detection (same as original)
    $script:lpInputMode = 'none'
    try { $null = [Console]::KeyAvailable; $script:lpInputMode = 'console' } catch {
        try { $null = $Host.UI.RawUI.KeyAvailable; $script:lpInputMode = 'rawui' } catch {}
    }
    if($script:lpInputMode -eq 'none'){
        Write-CL "  Lockpicking unavailable in this host (needs key input)." "Red"
        Wait-Key
        return @{ Success=$false; Aborted=$true; PicksUsed=0 }
    }

    # Config - scaled difficulty
    $TC    = $Tumblers       # tumblers
    $GH    = 8               # grid rows
    # Sweet-zone width: cell counts as in-zone when (row - center) is in
    # the half-open range [-SZ_BELOW, SZ_ABOVE). With SZ_BELOW=0 and
    # SZ_ABOVE=2, that's a 2-row band — the center row and the row above.
    # Slightly more forgiving than a single-row exact match without being
    # as loose as the previous 3-row band.
    $SZ_BELOW = 0
    # Skill (Phase 4): Lockpicking Lv15+ widens the sweet band by one row.
    if((Get-SkillLevel "Lockpicking") -ge 15){ $SZ_BELOW = 1 }
    $SZ_ABOVE = 2
    $CW    = 6               # column width
    $FMS   = 50              # frame ms
    $IW    = $TC * $CW + ($TC - 1)

    # State (all lp-prefixed)
    $script:lpLocked = @()
    for($i=0;$i -lt $TC;$i++){ $script:lpLocked += $false }
    $script:lpCur     = 0
    $script:lpPicks   = $AvailablePicks
    $script:lpPicksUsed = 0
    $script:lpT       = 0.0
    $script:lpRun     = $true
    $script:lpWon     = $false
    $script:lpAborted = $false
    $script:lpMsg     = ''
    $script:lpMsgC    = 'Gray'
    $script:lpMsgT    = 0
    $script:lpAnim    = 'none'
    $script:lpAnimF   = 0
    $script:lpAnimPin = 0

    # Rhythm — a bit faster as more tumblers, plus per-tumbler random sweet center
    $script:lpRng = [System.Random]::new()
    $script:lpFrq = @()
    $script:lpPhs = @()
    $script:lpSweet = @()  # one sweet center row per tumbler (random per lock)
    for($i=0;$i -lt $TC;$i++){
        $script:lpFrq += 2.0 + $i * 0.22 + ($script:lpRng.NextDouble() - 0.5) * 0.3
        $script:lpPhs += $i * 1.3 + $script:lpRng.NextDouble() * 0.5
        $script:lpSweet += $script:lpRng.Next(0, $GH)
    }

    $H  = [string]([char]0x2550); $V  = [string]([char]0x2551)
    $TL = [string]([char]0x2554); $TR = [string]([char]0x2557)
    $BL = [string]([char]0x255A); $BR = [string]([char]0x255D)
    $ML = [string]([char]0x2560); $MR = [string]([char]0x2563)
    $TJ = [string]([char]0x2564); $BJ = [string]([char]0x2567)
    $TV = [string]([char]0x2502)
    $FK = [string]([char]0x2588); $LB = [string]([char]0x2591)

    $LINE_W = 80

    function lp-Pad([string]$s){
        if($s.Length -ge $LINE_W){ return $s.Substring(0, $LINE_W) }
        return $s + (' ' * ($LINE_W - $s.Length))
    }
    function lp-ResetScreen {
        try {
            $z = New-Object System.Management.Automation.Host.Coordinates(0,0)
            $Host.UI.RawUI.CursorPosition = $z
        } catch {
            try { [Console]::SetCursorPosition(0,0) } catch { Clear-Host }
        }
    }
    function lp-GetKey {
        if($script:lpInputMode -eq 'console'){
            try { if([Console]::KeyAvailable){ return [Console]::ReadKey($true).Key.ToString() } } catch {}
        } elseif($script:lpInputMode -eq 'rawui'){
            # Release-proof (v1.6.2): skip key-ups instead of blocking
            # on them — a rawui host used to stutter on every release.
            try {
                while($Host.UI.RawUI.KeyAvailable){
                    $rkk = $Host.UI.RawUI.ReadKey('NoEcho,IncludeKeyDown,IncludeKeyUp')
                    if($rkk.KeyDown){ return [string]$rkk.VirtualKeyCode }
                }
            } catch {}
        }
        return $null
    }
    function lp-GetPinRow([int]$i){
        if($script:lpLocked[$i]){ return 0 }
        $v = [Math]::Sin($script:lpT * $script:lpFrq[$i] + $script:lpPhs[$i])
        return [int][Math]::Round(($v + 1) / 2 * ($GH - 1))
    }
    function lp-TestSweet([int]$i){
        $row = lp-GetPinRow $i
        $center = $script:lpSweet[$i]
        $delta = $row - $center
        # In-zone: row is the center row OR up to SZ_ABOVE-1 rows above it.
        return ($delta -ge -$SZ_BELOW -and $delta -lt $SZ_ABOVE)
    }

    Clear-Host

    # Render frame — drawn from scratch each tick
    $renderFrame = {
        lp-ResetScreen
        $sx = 0
        if($script:lpAnim -eq 'fail' -and $script:lpAnimF -lt 6){
            $sa = @(2,-2,1,-1,1,0); $sx = $sa[$script:lpAnimF]
        }
        $cp = ' ' * [Math]::Max(0, 9 + $sx)
        $lp = ' ' * [Math]::Max(0, 5 + $sx)

        # Chest
        Write-Host (lp-Pad "$cp   ._______________.")     -ForegroundColor Yellow
        Write-Host (lp-Pad "$cp  /   .--=====--.   \")    -ForegroundColor Yellow
        Write-Host "$cp /___| |" -NoNewline -ForegroundColor DarkYellow
        if($script:lpWon){ Write-Host " OPEN! " -NoNewline -ForegroundColor Green }
        else { Write-Host "LOCKED!" -NoNewline -ForegroundColor Red }
        $endStr = "| |___\"
        $used   = "$cp /___| |".Length + 7 + $endStr.Length
        $trail  = $LINE_W - $used
        if($trail -lt 0){ $trail = 0 }
        Write-Host "$endStr$(' ' * $trail)" -ForegroundColor DarkYellow
        Write-Host (lp-Pad "$cp |   | '-------' |   |")   -ForegroundColor DarkYellow
        Write-Host (lp-Pad "$cp |   '-----------'   |")   -ForegroundColor DarkYellow
        Write-Host (lp-Pad "$cp |_____________________|") -ForegroundColor DarkYellow
        Write-Host (lp-Pad "$cp  \___________________/")  -ForegroundColor DarkYellow

        # Top border
        Write-Host (lp-Pad "$lp$TL$($H * $IW)$TR") -ForegroundColor Cyan

        # Title row (shows PICK COUNT AS NUMBER)
        $pkC = 'Green'
        if($script:lpPicks -le 1){ $pkC = 'Red' }
        elseif($script:lpPicks -le 2){ $pkC = 'Yellow' }
        $pickStr = "Picks: $($script:lpPicks)"
        $gap = $IW - 13 - $pickStr.Length - 1
        if($gap -lt 1){ $gap = 1 }
        Write-Host "$lp$V" -NoNewline -ForegroundColor Cyan
        Write-Host " LOCKPICKING" -NoNewline -ForegroundColor White
        Write-Host "$(' ' * $gap) " -NoNewline
        Write-Host $pickStr -NoNewline -ForegroundColor $pkC
        $titleUsed  = "$lp$V".Length + 12 + $gap + 1 + $pickStr.Length + 1
        $titleTrail = $LINE_W - $titleUsed
        if($titleTrail -lt 0){ $titleTrail = 0 }
        Write-Host "$V$(' ' * $titleTrail)" -ForegroundColor Cyan

        # Grid top separator
        $sep = $ML
        for($c=0;$c -lt $TC;$c++){
            if($c -gt 0){ $sep += $TJ }
            $sep += $H * $CW
        }
        $sep += $MR
        Write-Host (lp-Pad "$lp$sep") -ForegroundColor Cyan

        # Grid rows
        for($r=0;$r -lt $GH;$r++){
            Write-Host "$lp$V" -NoNewline -ForegroundColor Cyan
            for($c=0;$c -lt $TC;$c++){
                # Per-tumbler sweet check: cell is "in sweet" if this column's
                # row is in the 2-row band relative to the sweet center.
                $delta = $r - $script:lpSweet[$c]
                $cellSweet = ($delta -ge -$SZ_BELOW -and $delta -lt $SZ_ABOVE)

                if($c -gt 0){
                    $sepC = 'DarkGray'
                    if($cellSweet){ $sepC = 'DarkGreen' }
                    Write-Host "$TV" -NoNewline -ForegroundColor $sepC
                }
                $pinR  = lp-GetPinRow $c
                $isCur = ($c -eq $script:lpCur)
                $isLck = $script:lpLocked[$c]
                $isAn  = ($script:lpAnim -ne 'none' -and $c -eq $script:lpAnimPin)
                if($pinR -eq $r){
                    if($isLck){
                        $cc = 'Green'
                        if($isAn -and $script:lpAnim -eq 'success' -and ($script:lpAnimF % 4 -lt 2)){ $cc = 'Yellow' }
                        Write-Host " [##] " -NoNewline -ForegroundColor $cc
                    } elseif($isCur){
                        if($isAn -and $script:lpAnim -eq 'fail' -and ($script:lpAnimF % 3 -lt 2)){
                            Write-Host " >XX< " -NoNewline -ForegroundColor Red
                        } elseif($cellSweet){
                            Write-Host " >##< " -NoNewline -ForegroundColor Yellow
                        } else {
                            Write-Host " >##< " -NoNewline -ForegroundColor White
                        }
                    } else {
                        Write-Host " [##] " -NoNewline -ForegroundColor Gray
                    }
                } else {
                    if($cellSweet){ Write-Host "  ~~  " -NoNewline -ForegroundColor DarkGreen }
                    else { Write-Host "      " -NoNewline }
                }
            }
            $rowUsed  = "$lp$V".Length + ($TC * $CW) + ($TC - 1) + 1
            $rowTrail = $LINE_W - $rowUsed
            if($rowTrail -lt 0){ $rowTrail = 0 }
            Write-Host "$V$(' ' * $rowTrail)" -ForegroundColor Cyan
        }

        # Bottom separator
        $sep2 = $ML
        for($c=0;$c -lt $TC;$c++){
            if($c -gt 0){ $sep2 += $BJ }
            $sep2 += $H * $CW
        }
        $sep2 += $MR
        Write-Host (lp-Pad "$lp$sep2") -ForegroundColor Cyan

        # Selector arrow
        Write-Host "$lp$V" -NoNewline -ForegroundColor Cyan
        for($c=0;$c -lt $TC;$c++){
            if($c -gt 0){ Write-Host " " -NoNewline }
            if($c -eq $script:lpCur -and -not $script:lpLocked[$c]){
                Write-Host "  /\  " -NoNewline -ForegroundColor Yellow
            } else { Write-Host "      " -NoNewline }
        }
        $arrowTrail = $LINE_W - ("$lp$V".Length + ($TC * $CW) + ($TC - 1) + 1)
        if($arrowTrail -lt 0){ $arrowTrail = 0 }
        Write-Host "$V$(' ' * $arrowTrail)" -ForegroundColor Cyan

        Write-Host (lp-Pad "$lp$BL$($H * $IW)$BR") -ForegroundColor Cyan

        # Timing bar — reflects the ACTIVE pin's distance from its sweet center.
        # Closer to center = fuller bar / greener color. When in sweet zone
        # (within SZ of center), bar shows ">>> NOW! <<<".
        $curPin = $script:lpCur
        $pinRow = lp-GetPinRow $curPin
        $sweetCenter = $script:lpSweet[$curPin]
        $rowDist = [math]::Abs($pinRow - $sweetCenter)
        # Distance maps to 0..1 closeness (0 = far, 1 = on sweet)
        $closeness = 1.0 - ([double]$rowDist / [double]($GH - 1))
        if($closeness -lt 0){ $closeness = 0 }

        $barLen = 20
        $fill = [int][Math]::Round($closeness * $barLen)
        if($fill -lt 0){ $fill = 0 }
        if($fill -gt $barLen){ $fill = $barLen }
        $remain = $barLen - $fill

        $inSweet = (lp-TestSweet $curPin)
        $barC = 'DarkGray'
        if($inSweet){ $barC = 'Green' }
        elseif($closeness -gt 0.7){ $barC = 'DarkGreen' }
        elseif($closeness -gt 0.4){ $barC = 'Yellow' }

        Write-Host "$lp Timing:[" -NoNewline -ForegroundColor DarkGray
        if($fill -gt 0){ Write-Host "$($FK * $fill)" -NoNewline -ForegroundColor $barC }
        if($remain -gt 0){ Write-Host "$($LB * $remain)" -NoNewline -ForegroundColor DarkGray }
        Write-Host "] " -NoNewline -ForegroundColor DarkGray
        $nowStr = if($inSweet){ ">>> NOW! <<<" } else { "            " }
        $barUsed = "$lp Timing:[".Length + $barLen + 2 + $nowStr.Length
        $barTrail = $LINE_W - $barUsed
        if($barTrail -lt 0){ $barTrail = 0 }
        if($inSweet){ Write-Host "$nowStr$(' ' * $barTrail)" -ForegroundColor Green }
        else { Write-Host "$nowStr$(' ' * $barTrail)" }

        # Message line
        if($script:lpMsg -ne ''){
            Write-Host (lp-Pad "  $($script:lpMsg)") -ForegroundColor $script:lpMsgC
        } else {
            Write-Host (lp-Pad "")
        }
        Write-Host (lp-Pad "  [SPACE] Pick  [< >] Select  [ESC] Walk Away") -ForegroundColor DarkCyan
    }

    # ── Fast renderer (v1.6.2) ── the original frame above is
    # ~100 Write-Host calls, every one a console round-trip; that is
    # why the minigame crawled until PowerShell's 16-call scriptblock
    # compilation warmed it up. On VT hosts the frame is built as ONE
    # string with ANSI colors and emitted with a single write — the
    # same technique the raycaster uses. Non-VT hosts keep the old
    # path (identical layout, both lines pad to LINE_W).
    $lpAnsi = @{ Black=30;DarkRed=31;DarkGreen=32;DarkYellow=33;DarkBlue=34;DarkMagenta=35;DarkCyan=36;Gray=37
                 DarkGray=90;Red=91;Green=92;Yellow=93;Blue=94;Magenta=95;Cyan=96;White=97 }
    $lpE = [string][char]0x1b
    $lpSB = New-Object System.Text.StringBuilder 8192
    $renderFrameFast = {
        $b = $lpSB
        [void]$b.Clear()
        [void]$b.Append($lpE).Append('[H')
        $sx = 0
        if($script:lpAnim -eq 'fail' -and $script:lpAnimF -lt 6){
            $sa = @(2,-2,1,-1,1,0); $sx = $sa[$script:lpAnimF]
        }
        $cp = ' ' * [Math]::Max(0, 9 + $sx)
        $lp = ' ' * [Math]::Max(0, 5 + $sx)
        $NL = "`n"
        # Chest art (colors mirror the Write-Host path exactly)
        [void]$b.Append($lpE).Append('[93m').Append((lp-Pad "$cp   ._______________.")).Append($NL)
        [void]$b.Append((lp-Pad "$cp  /   .--=====--.   \")).Append($NL)
        [void]$b.Append($lpE).Append('[33m').Append("$cp /___| |")
        if($script:lpWon){ [void]$b.Append($lpE).Append('[92m').Append(' OPEN! ') }
        else { [void]$b.Append($lpE).Append('[91m').Append('LOCKED!') }
        $endStr = "| |___\"
        $used   = "$cp /___| |".Length + 7 + $endStr.Length
        $trail  = $LINE_W - $used
        if($trail -lt 0){ $trail = 0 }
        [void]$b.Append($lpE).Append('[33m').Append($endStr).Append(' ' * $trail).Append($NL)
        [void]$b.Append((lp-Pad "$cp |   | '-------' |   |")).Append($NL)
        [void]$b.Append((lp-Pad "$cp |   '-----------'   |")).Append($NL)
        [void]$b.Append((lp-Pad "$cp |_____________________|")).Append($NL)
        [void]$b.Append((lp-Pad "$cp  \___________________/")).Append($NL)
        [void]$b.Append($lpE).Append('[96m').Append((lp-Pad "$lp$TL$($H * $IW)$TR")).Append($NL)
        # Title row
        $pkC = '[92m'
        if($script:lpPicks -le 1){ $pkC = '[91m' } elseif($script:lpPicks -le 2){ $pkC = '[93m' }
        $pickStr = "Picks: $($script:lpPicks)"
        $gap = $IW - 13 - $pickStr.Length - 1
        if($gap -lt 1){ $gap = 1 }
        [void]$b.Append("$lp$V").Append($lpE).Append('[97m').Append(' LOCKPICKING').Append(' ' * $gap).Append(' ')
        [void]$b.Append($lpE).Append($pkC).Append($pickStr)
        $titleTrail = $LINE_W - ("$lp$V".Length + 12 + $gap + 1 + $pickStr.Length + 1)
        if($titleTrail -lt 0){ $titleTrail = 0 }
        [void]$b.Append($lpE).Append('[96m').Append($V).Append(' ' * $titleTrail).Append($NL)
        # Grid top separator
        $sep = $ML
        for($c=0;$c -lt $TC;$c++){ if($c -gt 0){ $sep += $TJ }; $sep += $H * $CW }
        $sep += $MR
        [void]$b.Append((lp-Pad "$lp$sep")).Append($NL)
        # Pin rows once per frame (the old path recomputed per CELL)
        $pinRows = New-Object 'int[]' $TC
        for($c=0;$c -lt $TC;$c++){ $pinRows[$c] = lp-GetPinRow $c }
        for($r=0;$r -lt $GH;$r++){
            [void]$b.Append($lpE).Append('[96m').Append("$lp$V")
            for($c=0;$c -lt $TC;$c++){
                $delta = $r - $script:lpSweet[$c]
                $cellSweet = ($delta -ge -$SZ_BELOW -and $delta -lt $SZ_ABOVE)
                if($c -gt 0){
                    if($cellSweet){ [void]$b.Append($lpE).Append('[32m').Append($TV) }
                    else { [void]$b.Append($lpE).Append('[90m').Append($TV) }
                }
                $isCur = ($c -eq $script:lpCur)
                $isLck = $script:lpLocked[$c]
                $isAn  = ($script:lpAnim -ne 'none' -and $c -eq $script:lpAnimPin)
                if($pinRows[$c] -eq $r){
                    if($isLck){
                        if($isAn -and $script:lpAnim -eq 'success' -and ($script:lpAnimF % 4 -lt 2)){ [void]$b.Append($lpE).Append('[93m').Append(' [##] ') }
                        else { [void]$b.Append($lpE).Append('[92m').Append(' [##] ') }
                    } elseif($isCur){
                        if($isAn -and $script:lpAnim -eq 'fail' -and ($script:lpAnimF % 3 -lt 2)){ [void]$b.Append($lpE).Append('[91m').Append(' >XX< ') }
                        elseif($cellSweet){ [void]$b.Append($lpE).Append('[93m').Append(' >##< ') }
                        else { [void]$b.Append($lpE).Append('[97m').Append(' >##< ') }
                    } else {
                        [void]$b.Append($lpE).Append('[37m').Append(' [##] ')
                    }
                } else {
                    if($cellSweet){ [void]$b.Append($lpE).Append('[32m').Append('  ~~  ') }
                    else { [void]$b.Append('      ') }
                }
            }
            $rowTrail = $LINE_W - ("$lp$V".Length + ($TC * $CW) + ($TC - 1) + 1)
            if($rowTrail -lt 0){ $rowTrail = 0 }
            [void]$b.Append($lpE).Append('[96m').Append($V).Append(' ' * $rowTrail).Append($NL)
        }
        # Bottom separator
        $sep2 = $ML
        for($c=0;$c -lt $TC;$c++){ if($c -gt 0){ $sep2 += $BJ }; $sep2 += $H * $CW }
        $sep2 += $MR
        [void]$b.Append((lp-Pad "$lp$sep2")).Append($NL)
        # Selector arrow
        [void]$b.Append("$lp$V")
        for($c=0;$c -lt $TC;$c++){
            if($c -gt 0){ [void]$b.Append(' ') }
            if($c -eq $script:lpCur -and -not $script:lpLocked[$c]){ [void]$b.Append($lpE).Append('[93m').Append('  /\  ').Append($lpE).Append('[96m') }
            else { [void]$b.Append('      ') }
        }
        $arrowTrail = $LINE_W - ("$lp$V".Length + ($TC * $CW) + ($TC - 1) + 1)
        if($arrowTrail -lt 0){ $arrowTrail = 0 }
        [void]$b.Append($V).Append(' ' * $arrowTrail).Append($NL)
        [void]$b.Append((lp-Pad "$lp$BL$($H * $IW)$BR")).Append($NL)
        # Timing bar
        $curPin = $script:lpCur
        $pinRow = $pinRows[$curPin]
        $rowDist = [math]::Abs($pinRow - $script:lpSweet[$curPin])
        $closeness = 1.0 - ([double]$rowDist / [double]($GH - 1))
        if($closeness -lt 0){ $closeness = 0 }
        $barLen = 20
        $fill = [int][Math]::Round($closeness * $barLen)
        if($fill -lt 0){ $fill = 0 }
        if($fill -gt $barLen){ $fill = $barLen }
        $remain = $barLen - $fill
        $inSweet = (lp-TestSweet $curPin)
        $barC = '[90m'
        if($inSweet){ $barC = '[92m' }
        elseif($closeness -gt 0.7){ $barC = '[32m' }
        elseif($closeness -gt 0.4){ $barC = '[93m' }
        [void]$b.Append($lpE).Append('[90m').Append("$lp Timing:[")
        if($fill -gt 0){ [void]$b.Append($lpE).Append($barC).Append($FK * $fill) }
        if($remain -gt 0){ [void]$b.Append($lpE).Append('[90m').Append($LB * $remain) }
        [void]$b.Append($lpE).Append('[90m').Append('] ')
        $nowStr = if($inSweet){ '>>> NOW! <<<' } else { '            ' }
        $barTrail = $LINE_W - ("$lp Timing:[".Length + $barLen + 2 + $nowStr.Length)
        if($barTrail -lt 0){ $barTrail = 0 }
        if($inSweet){ [void]$b.Append($lpE).Append('[92m').Append($nowStr).Append(' ' * $barTrail).Append($NL) }
        else { [void]$b.Append($lpE).Append('[0m').Append($nowStr).Append(' ' * $barTrail).Append($NL) }
        # Message + help lines
        if($script:lpMsg -ne ''){
            $mc = 37
            if($lpAnsi.ContainsKey([string]$script:lpMsgC)){ $mc = $lpAnsi[[string]$script:lpMsgC] }
            [void]$b.Append($lpE).Append("[${mc}m").Append((lp-Pad "  $($script:lpMsg)")).Append($NL)
        } else {
            [void]$b.Append((lp-Pad "")).Append($NL)
        }
        [void]$b.Append($lpE).Append('[36m').Append((lp-Pad "  [SPACE] Pick  [< >] Select  [ESC] Walk Away"))
        [void]$b.Append($lpE).Append('[0m')
        try { [Console]::Write($b.ToString()) } catch { Write-Host $b.ToString() -NoNewline }
    }
    $doRender = if(Test-VTSupport){ $renderFrameFast } else { $renderFrame }

    # Input handler
    $handleInput = {
        $key = lp-GetKey
        while($key -ne $null){
            if($script:lpAnim -ne 'none'){ $key = lp-GetKey; continue }
            $isSpace = ($key -eq 'Spacebar' -or $key -eq '32')
            $isLeft  = ($key -eq 'LeftArrow' -or $key -eq 'Left' -or $key -eq '37')
            $isRight = ($key -eq 'RightArrow' -or $key -eq 'Right' -or $key -eq '39')
            $isEsc   = ($key -eq 'Escape' -or $key -eq '27')

            if($isSpace -and -not $script:lpLocked[$script:lpCur]){
                if(lp-TestSweet $script:lpCur){
                    $script:lpLocked[$script:lpCur] = $true
                    $script:lpAnim = 'success'
                    $script:lpAnimF = 0
                    $script:lpAnimPin = $script:lpCur
                    $script:lpMsg = "* CLICK * Tumbler $($script:lpCur + 1) is set!"
                    $script:lpMsgC = 'Green'
                    $script:lpMsgT = 35
                    $allDone = $true
                    for($j=0;$j -lt $TC;$j++){
                        if(-not $script:lpLocked[$j]){ $allDone = $false; break }
                    }
                    if($allDone){
                        $script:lpWon = $true
                        $script:lpMsg = "** LOCK OPENED! The chest is yours! **"
                        $script:lpMsgC = 'Yellow'
                        $script:lpMsgT = 999
                    } else {
                        for($j=1;$j -le $TC;$j++){
                            $nx = ($script:lpCur + $j) % $TC
                            if(-not $script:lpLocked[$nx]){ $script:lpCur = $nx; break }
                        }
                    }
                } else {
                    $script:lpPicks--
                    $script:lpPicksUsed++
                    $script:lpAnim = 'fail'
                    $script:lpAnimF = 0
                    $script:lpAnimPin = $script:lpCur
                    if($script:lpPicks -le 0){
                        $script:lpMsg = "All lockpicks broken... the lock wins."
                        $script:lpMsgC = 'DarkRed'
                        $script:lpMsgT = 999
                        $script:lpRun = $false
                    } else {
                        $script:lpMsg = "SNAP! Pick broke! ($($script:lpPicks) left)"
                        $script:lpMsgC = 'Red'
                        $script:lpMsgT = 40
                        for($j=0;$j -lt $TC;$j++){
                            if($script:lpLocked[$j] -and ($script:lpRng.NextDouble() -lt 0.25)){
                                $script:lpLocked[$j] = $false
                                $script:lpMsg += " [T$($j+1) fell!]"
                            }
                        }
                    }
                }
            } elseif($isLeft){
                $ul = @()
                for($j=0;$j -lt $TC;$j++){ if(-not $script:lpLocked[$j]){ $ul += $j } }
                if($ul.Count -gt 0){
                    $idx = [Array]::IndexOf($ul, $script:lpCur)
                    if($idx -le 0){ $script:lpCur = $ul[$ul.Count - 1] }
                    else { $script:lpCur = $ul[$idx - 1] }
                }
            } elseif($isRight){
                $ul = @()
                for($j=0;$j -lt $TC;$j++){ if(-not $script:lpLocked[$j]){ $ul += $j } }
                if($ul.Count -gt 0){
                    $idx = [Array]::IndexOf($ul, $script:lpCur)
                    if($idx -ge ($ul.Count - 1) -or $idx -lt 0){ $script:lpCur = $ul[0] }
                    else { $script:lpCur = $ul[$idx + 1] }
                }
            } elseif($isEsc){
                $script:lpRun = $false
                $script:lpAborted = $true
                $script:lpMsg = "You step away. The lock remains, disturbed."
                $script:lpMsgC = 'DarkGray'
                $script:lpMsgT = 999
            }
            $key = lp-GetKey
        }
    }

    # Main loop
    $clock = [System.Diagnostics.Stopwatch]::StartNew()
    $lastMs = $clock.ElapsedMilliseconds
    try {
        while($script:lpRun){
            $nowMs = $clock.ElapsedMilliseconds
            if(($nowMs - $lastMs) -lt $FMS){
                Start-Sleep -Milliseconds 5
                continue
            }
            $dt = ($nowMs - $lastMs) / 1000.0
            $lastMs = $nowMs
            $script:lpT += $dt

            if($script:lpMsgT -gt 0){
                $script:lpMsgT--
                if($script:lpMsgT -eq 0 -and $script:lpRun){ $script:lpMsg = '' }
            }
            if($script:lpAnim -ne 'none'){
                $script:lpAnimF++
                if($script:lpAnim -eq 'success' -and $script:lpAnimF -ge 10){ $script:lpAnim = 'none' }
                if($script:lpAnim -eq 'fail' -and $script:lpAnimF -ge 8){ $script:lpAnim = 'none' }
            }

            & $handleInput

            if($script:lpWon -and $script:lpAnim -eq 'none'){
                & $doRender
                Start-Sleep -Milliseconds 1500
                $script:lpRun = $false
                break
            }
            & $doRender
        }
        & $doRender
        # Holding the screen briefly with Start-Sleep used to flash the
        # final message past too fast — players reported screen tearing
        # and trouble reading what happened. If the player ran out of
        # picks (vs winning or aborting), give them an explicit prompt
        # so they can dismiss the result on their own time.
        if(-not $script:lpWon -and -not $script:lpAborted){
            # All picks broken path — print the final status line below
            # the rendered frame and wait for Enter.
            Write-Host ""
            Write-CL "  All your picks are broken. The lock stays shut." "DarkRed"
            Wait-Enter
        } else {
            Start-Sleep -Seconds 1
        }
    } finally {
        try { [Console]::CursorVisible = $wasVisible } catch {}
        # Drain any queued keys from the minigame so they don't leak into the dungeon loop
        Drain-Keys
    }

    return @{
        Success    = $script:lpWon
        Aborted    = $script:lpAborted
        PicksUsed  = $script:lpPicksUsed
    }
}



# ─── TALENT TREE (v1.5 Pass 2) ────────────────────────────────────
# 1 talent point per player level, spent at the Stats page. Each class
# has 9 talents in 3 tiers (3 talents per tier). Tiers gate on player
# level: T1 from level 1, T2 from 5, T3 from 10.
#
# Effects are read by various combat/loot/town code via Has-Talent.
# All effects are PASSIVE (no active triggers). Talents are kept simple
# and additive so they compose cleanly with potions, gear, and pets.
function Get-TalentsForClass {
    param([string]$Class)
    # Each talent: Id (unique per class), Name, Tier (1/2/3), Desc
    $base = switch($Class){
        "Knight" {
            @(
                @{ Id="Knight_T1_A"; Name="Iron Resolve";    Tier=1; Desc="+5 max HP per player level" }
                @{ Id="Knight_T1_B"; Name="Steady Stance";   Tier=1; Desc="+3 DEF (passive)" }
                @{ Id="Knight_T1_C"; Name="Sword Discipline";Tier=1; Desc="+2 ATK with sword weapons" }
                @{ Id="Knight_T2_A"; Name="Stalwart";        Tier=2; Desc="-15% damage taken below 30% HP" }
                @{ Id="Knight_T2_B"; Name="Counter-Strike";  Tier=2; Desc="20% chance to counter when defending" }
                @{ Id="Knight_T2_C"; Name="Holy Vigil";      Tier=2; Desc="+5 HP regen at start of every fight" }
                @{ Id="Knight_T3_A"; Name="Crusader";        Tier=3; Desc="+25% damage to bosses" }
                @{ Id="Knight_T3_B"; Name="Last Stand";      Tier=3; Desc="Survive lethal damage with 1 HP (once per dungeon)" }
                @{ Id="Knight_T3_C"; Name="Guardian";        Tier=3; Desc="-10% damage taken when shield is equipped" }
                @{ Id="Knight_T4_A"; Name="Avatar of Light";  Tier=4; Desc="ULT: -25% all damage taken, +15% all damage dealt" }
            )
        }
        "Mage" {
            @(
                @{ Id="Mage_T1_A"; Name="Arcane Focus";    Tier=1; Desc="+5 max MP per player level" }
                @{ Id="Mage_T1_B"; Name="Mystic Insight";  Tier=1; Desc="+3 MAG (passive)" }
                @{ Id="Mage_T1_C"; Name="Staff Mastery";   Tier=1; Desc="+10% damage with staff weapons" }
                @{ Id="Mage_T2_A"; Name="Mana Shield";     Tier=2; Desc="-20% damage taken if MP > 50%" }
                @{ Id="Mage_T2_B"; Name="Spell Echo";      Tier=2; Desc="15% chance for abilities to refund MP" }
                @{ Id="Mage_T2_C"; Name="Burnsight";       Tier=2; Desc="Burn perk damage doubled" }
                @{ Id="Mage_T3_A"; Name="Archmage";        Tier=3; Desc="+30% magic damage" }
                @{ Id="Mage_T3_B"; Name="Mana Surge";      Tier=3; Desc="Crit hits restore 10 MP" }
                @{ Id="Mage_T3_C"; Name="Time Slip";       Tier=3; Desc="Ability cooldowns -1 turn" }
                @{ Id="Mage_T4_A"; Name="Archmage Ascendant"; Tier=4; Desc="ULT: All abilities cost 50% MP, +40% magic damage" }
            )
        }
        "Brawler" {
            @(
                @{ Id="Brawler_T1_A"; Name="Tough Hide";    Tier=1; Desc="+5 DEF (passive)" }
                @{ Id="Brawler_T1_B"; Name="Bigger Fists";  Tier=1; Desc="+3 ATK with fist weapons" }
                @{ Id="Brawler_T1_C"; Name="Lung Capacity"; Tier=1; Desc="+8 max HP per player level" }
                @{ Id="Brawler_T2_A"; Name="Adrenaline";    Tier=2; Desc="+20% damage when below 50% HP" }
                @{ Id="Brawler_T2_B"; Name="Iron Chin";     Tier=2; Desc="-30% damage from enemy critical hits" }
                @{ Id="Brawler_T2_C"; Name="Combo Strike";  Tier=2; Desc="Crits restore 8 HP" }
                @{ Id="Brawler_T3_A"; Name="Berserk";       Tier=3; Desc="+40% crit chance below 25% HP" }
                @{ Id="Brawler_T3_B"; Name="Unbreakable";   Tier=3; Desc="-15% damage taken (always)" }
                @{ Id="Brawler_T3_C"; Name="Knockout";      Tier=3; Desc="Crits have 30% chance to stun" }
                @{ Id="Brawler_T4_A"; Name="Iron Avalanche"; Tier=4; Desc="ULT: +50% damage below 50% HP (was +20%)" }
            )
        }
        "Ranger" {
            @(
                @{ Id="Ranger_T1_A"; Name="Eagle Eye";      Tier=1; Desc="+5% crit chance" }
                @{ Id="Ranger_T1_B"; Name="Light Step";     Tier=1; Desc="+3 SPD (passive)" }
                @{ Id="Ranger_T1_C"; Name="Bow Mastery";    Tier=1; Desc="+10% damage with bow weapons" }
                @{ Id="Ranger_T2_A"; Name="Hunter's Mark";  Tier=2; Desc="+15% damage to enemies above 75% HP" }
                @{ Id="Ranger_T2_B"; Name="Toxic Tips";     Tier=2; Desc="Poison perk procs +25% more often" }
                @{ Id="Ranger_T2_C"; Name="Quickdraw";      Tier=2; Desc="First attack each fight is a guaranteed crit" }
                @{ Id="Ranger_T3_A"; Name="Deadshot";       Tier=3; Desc="Crits deal 3x damage (was 2x)" }
                @{ Id="Ranger_T3_B"; Name="Multishot";      Tier=3; Desc="25% chance to attack twice" }
                @{ Id="Ranger_T3_C"; Name="Trapfinder";     Tier=3; Desc="+1 free lockpick on dungeon entry" }
                @{ Id="Ranger_T4_A"; Name="Volley";          Tier=4; Desc="ULT: Multishot procs at 50% (was 25%) and full damage" }
            )
        }
        "Cleric" {
            @(
                @{ Id="Cleric_T1_A"; Name="Devout";         Tier=1; Desc="+4 max HP and +4 max MP per level" }
                @{ Id="Cleric_T1_B"; Name="Faithful";       Tier=1; Desc="+3 DEF (passive)" }
                @{ Id="Cleric_T1_C"; Name="Mace Discipline";Tier=1; Desc="+2 ATK with mace weapons" }
                @{ Id="Cleric_T2_A"; Name="Healer's Touch"; Tier=2; Desc="Healing potions restore +30%" }
                @{ Id="Cleric_T2_B"; Name="Smiter";         Tier=2; Desc="+25% damage to undead (Skeleton, Zombie)" }
                @{ Id="Cleric_T2_C"; Name="Sanctuary";      Tier=2; Desc="Regenerate 3 HP per dungeon step" }
                @{ Id="Cleric_T3_A"; Name="Divine Aegis";   Tier=3; Desc="-20% damage taken from magic" }
                @{ Id="Cleric_T3_B"; Name="Lay on Hands";   Tier=3; Desc="One free full heal per dungeon" }
                @{ Id="Cleric_T3_C"; Name="Resurrection";   Tier=3; Desc="On death, revive at 50% HP (once per dungeon)" }
                @{ Id="Cleric_T4_A"; Name="Holy Fury";       Tier=4; Desc="ULT: All healing +50%, Lay on Hands twice/dungeon" }
            )
        }
        "Necromancer" {
            @(
                @{ Id="Necromancer_T1_A"; Name="Soul Pool";    Tier=1; Desc="+5 max MP per player level" }
                @{ Id="Necromancer_T1_B"; Name="Death's Grip"; Tier=1; Desc="+3 MAG (passive)" }
                @{ Id="Necromancer_T1_C"; Name="Scythe Mastery"; Tier=1; Desc="+10% damage with scythe weapons" }
                @{ Id="Necromancer_T2_A"; Name="Drain Mastery"; Tier=2; Desc="Drain perk heals double" }
                @{ Id="Necromancer_T2_B"; Name="Bone Shield";  Tier=2; Desc="-10% damage taken (always)" }
                @{ Id="Necromancer_T2_C"; Name="Soul Harvest"; Tier=2; Desc="Kills restore 5 MP" }
                @{ Id="Necromancer_T3_A"; Name="Lich's Pact";  Tier=3; Desc="+30% damage but -20% max HP" }
                @{ Id="Necromancer_T3_B"; Name="Death Pact";   Tier=3; Desc="On killing blow, +5% damage next fight (stacking, max 5)" }
                @{ Id="Necromancer_T3_C"; Name="Reaper";       Tier=3; Desc="Killing an enemy below 25% HP is automatic" }
                @{ Id="Necromancer_T4_A"; Name="Lord of the Dead"; Tier=4; Desc="ULT: Reaper threshold 40% (was 25%), kills heal 15 HP" }
            )
        }
        "Berserker" {
            @(
                @{ Id="Berserker_T1_A"; Name="Reckless Strike";Tier=1; Desc="+4 ATK (passive)" }
                @{ Id="Berserker_T1_B"; Name="Battle Hunger";  Tier=1; Desc="+5 max HP per player level" }
                @{ Id="Berserker_T1_C"; Name="Sword Fury";     Tier=1; Desc="+3 ATK with sword weapons" }
                @{ Id="Berserker_T2_A"; Name="Bloodlust";      Tier=2; Desc="+30% damage when below 40% HP" }
                @{ Id="Berserker_T2_B"; Name="Bleed Mastery";  Tier=2; Desc="Bleed perk damage doubled" }
                @{ Id="Berserker_T2_C"; Name="Reckless Charge";Tier=2; Desc="First attack each fight deals +50%" }
                @{ Id="Berserker_T3_A"; Name="Rampage";        Tier=3; Desc="Kills grant +5 ATK for 3 turns (stacking, max 3)" }
                @{ Id="Berserker_T3_B"; Name="Pain Tolerance"; Tier=3; Desc="Damage taken converts 25% to ATK buff next turn" }
                @{ Id="Berserker_T3_C"; Name="Final Stand";    Tier=3; Desc="At 1 HP, +50% all stats (once per dungeon)" }
                @{ Id="Berserker_T4_A"; Name="Eternal Rage";    Tier=4; Desc="ULT: Rampage stacks max 6 (was 3)" }
            )
        }
        "Warlock" {
            @(
                @{ Id="Warlock_T1_A"; Name="Cursed Mind";    Tier=1; Desc="+3 MAG (passive)" }
                @{ Id="Warlock_T1_B"; Name="Pact's Vigor";   Tier=1; Desc="+5 max HP per player level" }
                @{ Id="Warlock_T1_C"; Name="Staff Discipline";Tier=1; Desc="+10% damage with staff weapons" }
                @{ Id="Warlock_T2_A"; Name="Hexweave";       Tier=2; Desc="Drain perk procs +25% more often" }
                @{ Id="Warlock_T2_B"; Name="Soul Tap";       Tier=2; Desc="Spend 5 HP to deal +10 damage on basic attack" }
                @{ Id="Warlock_T2_C"; Name="Fiendish Pact";  Tier=2; Desc="-15% damage taken from physical attacks" }
                @{ Id="Warlock_T3_A"; Name="Doompact";       Tier=3; Desc="+25% damage but +25% damage taken" }
                @{ Id="Warlock_T3_B"; Name="Soul Drain";     Tier=3; Desc="All abilities heal you for 30% damage dealt" }
                @{ Id="Warlock_T3_C"; Name="Eternal Bargain";Tier=3; Desc="Kills below 20% HP restore 25 HP and 15 MP" }
                @{ Id="Warlock_T4_A"; Name="Bound to Eternity"; Tier=4; Desc="ULT: Soul Drain heals 60% (was 30%), Soul Tap free" }
            )
        }
        default { @() }
    }
    return $base
}

# Returns 1 if the player has purchased the given talent, else 0.
# Returns flat stat bonuses from purchased talents. Used by combat
# stats display, level-up logic, and gear math. Each return key maps
# to one stat. Multiplicative effects (e.g. +X% damage to bosses) are
# applied inline at the relevant call site.
function Get-TalentStatBonus {
    param([string]$Stat)
    # Returns flat stat bonuses from purchased talents that apply to
    # ATK/DEF/SPD/MAG every combat tick. MaxHP and MaxMP talents do NOT
    # flow through this helper — they're applied as one-shot deltas at
    # talent-purchase time (see Show-TalentTree) and reapplied on ascend
    # (see the [N] handler in the town menu). Keeping HP/MP out of here
    # avoids any ambiguity about whether HP totals are dynamic.
    $b = 0
    $lvl = [int]$script:PlayerLevel
    switch($Stat){
        "ATK" {
            if(Has-Talent "Berserker_T1_A")  { $b += 4 }
        }
        "DEF" {
            if(Has-Talent "Knight_T1_B")     { $b += 3 }
            if(Has-Talent "Brawler_T1_A")    { $b += 5 }
            if(Has-Talent "Cleric_T1_B")     { $b += 3 }
        }
        "SPD" {
            if(Has-Talent "Ranger_T1_B")     { $b += 3 }
        }
        "MAG" {
            if(Has-Talent "Mage_T1_B")          { $b += 3 }
            if(Has-Talent "Necromancer_T1_B")   { $b += 3 }
            if(Has-Talent "Warlock_T1_A")       { $b += 3 }
        }
    }
    return $b
}

# Returns 1 if the player has purchased the given talent, else 0.
function Has-Talent {
    param([string]$Id)
    if(-not $script:Talents){ return $false }
    return ($script:Talents.ContainsKey($Id) -and $script:Talents[$Id] -eq 1)
}

# How many talent points the player has unspent.
# Total = PlayerLevel; Spent = count of purchased talents.
# After all class talents are owned, available drops to 0 even if the
# player has continued levelling — there's nothing left to buy.
function Get-AvailableTalentPoints {
    $total = [int]$script:PlayerLevel
    $spent = if($script:Talents){$script:Talents.Count}else{0}
    $avail = $total - $spent
    if($avail -lt 0){ $avail = 0 }
    # Class-specific cap: count talents available for the current class
    # and subtract what's already owned. The result is the max number
    # of points the player can ever spend, so cap $avail to that.
    $classTalents = @(Get-TalentsForClass $script:PlayerClass)
    $totalSlots   = $classTalents.Count
    $ownedForClass = 0
    if($script:Talents){
        foreach($t in $classTalents){
            if($script:Talents.ContainsKey($t.Id)){ $ownedForClass++ }
        }
    }
    $remainingSlots = $totalSlots - $ownedForClass
    if($remainingSlots -lt 0){ $remainingSlots = 0 }
    if($avail -gt $remainingSlots){ $avail = $remainingSlots }
    return $avail
}

# Tier gating: returns the minimum player level required to spend in
# this tier. Tier 1 = level 1; Tier 2 = level 5; Tier 3 = level 10;
# Tier 4 (capstone ultimates) = level 15.
function Get-TalentTierMinLevel {
    param([int]$Tier)
    switch($Tier){
        1 { return 1 }
        2 { return 5 }
        3 { return 10 }
        4 { return 15 }
        default { return 1 }
    }
}

# Talent screen — shown from the Stats page when the player presses [T].
# Lets the player browse their class's tree and spend points.
function Show-TalentTree {
    if(-not $script:Talents){ $script:Talents = @{} }
    $loop = $true
    while($loop){
        $talents = Get-TalentsForClass $script:PlayerClass
        $avail   = Get-AvailableTalentPoints
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkCyan"
        $tt = "  T A L E N T   T R E E   —   $($script:PlayerClass)"
        $padT = 66 - $tt.Length
        if($padT -lt 0){ $padT = 0 }
        Write-C  "  ║" "DarkCyan"; Write-C $tt "Cyan"; Write-CL "$(' ' * $padT)║" "DarkCyan"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""
        Write-C  "  Player Level: " "DarkGray"; Write-C "$($script:PlayerLevel)" "White"
        Write-C  "    Available Talent Points: " "DarkGray"; Write-CL "$avail" "Yellow"
        Write-Host ""
        Write-CL "  Tier gates: T1 @ Lv1   T2 @ Lv5   T3 @ Lv10   T4 @ Lv15" "DarkGray"
        Write-Host ""

        # Group talents by tier (4 tiers; Tier 4 is a single capstone
        # ULT per class with id pattern Class_T4_A, key "41").
        for($tier=1; $tier -le 4; $tier++){
            $tierMin = Get-TalentTierMinLevel $tier
            $tierLabel = if($tier -eq 4){"── Tier 4 ULT (Lv $tierMin+) ──"}else{"── Tier $tier (Lv $tierMin+) ──"}
            $tierColor = if($script:PlayerLevel -ge $tierMin){if($tier -eq 4){"Magenta"}else{"Yellow"}}else{"DarkGray"}
            Write-CL "  $tierLabel" $tierColor
            $idx = 0
            $tierHadAny = $false
            foreach($t in $talents){
                if($t.Tier -ne $tier){ continue }
                $tierHadAny = $true
                $idx++
                $owned = Has-Talent $t.Id
                $unlocked = ($script:PlayerLevel -ge $tierMin)
                $key = "$tier$idx"   # e.g. "1A" -> 11, 12, 13, 21, ..., "41"
                $status = if($owned){"[X]"}elseif($unlocked -and $avail -gt 0){"[ ]"}else{"[-]"}
                $col = if($owned){"Green"}elseif($unlocked -and $avail -gt 0){if($tier -eq 4){"Magenta"}else{"White"}}else{"DarkGray"}
                Write-C "    [$key] " $col
                Write-C $status $col
                Write-C "  $($t.Name)" $col
                $padN = 24 - $t.Name.Length
                if($padN -lt 1){ $padN = 1 }
                Write-CL ("$(' ' * $padN) — $($t.Desc)") "DarkGray"
            }
            if(-not $tierHadAny){
                Write-CL "    (no talents in this tier for this class)" "DarkGray"
            }
            Write-Host ""
        }

        Write-CL "    [0] Back" "White"
        Write-Host ""
        Write-CL "  Spend points by entering the talent code (e.g., 11 = Tier1 first, 41 = ULT)." "DarkGray"
        Write-Host ""
        Write-C  "  > " "Yellow"
        $sel = Read-Host

        if($sel -eq "0" -or [string]::IsNullOrWhiteSpace($sel)){
            $loop = $false
            continue
        }
        # Parse two-digit code: tier then index
        if($sel.Length -ne 2){
            continue
        }
        $tierChar = $sel.Substring(0,1)
        $idxChar  = $sel.Substring(1,1)
        $tierN    = 0
        $idxN     = 0
        if(-not [int]::TryParse($tierChar, [ref]$tierN)){ continue }
        if(-not [int]::TryParse($idxChar,  [ref]$idxN )){ continue }
        # Tier 1-3 have 3 talents each; Tier 4 has 1 capstone.
        if($tierN -lt 1 -or $tierN -gt 4){ continue }
        if($tierN -le 3 -and ($idxN -lt 1 -or $idxN -gt 3)){ continue }
        if($tierN -eq 4 -and $idxN -ne 1){ continue }

        # Find the talent
        $tierTalents = @($talents | Where-Object { $_.Tier -eq $tierN })
        if($idxN -gt $tierTalents.Count){ continue }
        $picked = $tierTalents[$idxN - 1]

        if(Has-Talent $picked.Id){
            Write-CL "  $($picked.Name) is already purchased." "DarkGray"
            Wait-Key
            continue
        }
        if($script:PlayerLevel -lt (Get-TalentTierMinLevel $tierN)){
            Write-CL "  Locked: requires level $(Get-TalentTierMinLevel $tierN)." "Red"
            Wait-Key
            continue
        }
        if($avail -lt 1){
            Write-CL "  No talent points to spend." "Red"
            Wait-Key
            continue
        }
        # Confirm purchase
        Write-Host ""
        Write-CL "  Confirm: spend 1 point on $($picked.Name)?" "Yellow"
        Write-CL "    $($picked.Desc)" "DarkGray"
        Write-C  "  [y/n]: " "White"
        $cf = Read-Host
        if($cf -ne 'y' -and $cf -ne 'Y'){ continue }
        $script:Talents[$picked.Id] = 1
        # Some talents grant immediate stat boosts. The combat code
        # already reads talent bonuses dynamically for ATK/DEF/MAG/SPD,
        # but MaxHP/MaxMP are stored on the player object — apply the
        # delta directly so the current pool benefits right away.
        $p = $script:Player
        $hpDelta = 0; $mpDelta = 0
        switch($picked.Id){
            "Knight_T1_A"     { $hpDelta = (5 * $script:PlayerLevel) }
            "Brawler_T1_C"    { $hpDelta = (8 * $script:PlayerLevel) }
            "Cleric_T1_A"     { $hpDelta = (4 * $script:PlayerLevel); $mpDelta = (4 * $script:PlayerLevel) }
            "Berserker_T1_B"  { $hpDelta = (5 * $script:PlayerLevel) }
            "Warlock_T1_B"    { $hpDelta = (5 * $script:PlayerLevel) }
            "Mage_T1_A"       { $mpDelta = (5 * $script:PlayerLevel) }
            "Necromancer_T1_A"{ $mpDelta = (5 * $script:PlayerLevel) }
        }
        # Lich's Pact: -20% max HP at purchase. (One-shot, doesn't
        # re-apply on level up — keeps the math simple.)
        if($picked.Id -eq "Necromancer_T3_A"){
            $reduction = [math]::Floor($p.MaxHP * 0.20)
            $p.MaxHP = [math]::Max($p.MaxHP - $reduction, 30)
            if($p.HP -gt $p.MaxHP){ $p.HP = $p.MaxHP }
        }
        if($hpDelta -gt 0){
            $p.MaxHP += $hpDelta
            $p.HP    += $hpDelta
        }
        if($mpDelta -gt 0){
            $p.MaxMP += $mpDelta
            $p.MP    += $mpDelta
        }
        Write-CL "  $($picked.Name) acquired!" "Green"
        if($hpDelta -gt 0){ Write-CL "  +$hpDelta Max HP" "Green" }
        if($mpDelta -gt 0){ Write-CL "  +$mpDelta Max MP" "Cyan" }
        Wait-Key
    }
}

# ─── HIDDEN BOSS: THE ORPHANED PROCESS (v1.5 Pass 2) ──────────────
# Secret super-boss. Spawn condition is gated to Daily Dungeon clears
# at 100% HP with zero potions used. On defeat: permanent "Guild of
# SysAdmin Favor" buff (+5 to all stats) and a 15% shop discount flag.
# Sysadmin lore: an Orphaned Process is one whose parent has terminated
# but the process itself never died — a perfect monster for a dungeon
# built atop deprecated infrastructure.
# ── Phase 6: THE FINAL MIGRATION — THE LICH KING OF LEGACY CODE ────
# The story's scripted finale (quest 10). Queued at descend past 16,
# fired from the loop head. Victory CANCELS the Migration: msq=999,
# lk_down flag, permanent +2 all stats, and New Game+ opens (the NG+
# gate is story completion now, per the locked decision).
function New-LichKing {
    $lvl = [math]::Max($script:DungeonLevel, 16)
    $hpScale  = 1 + ($lvl - 1) * 0.20
    $atkScale = 1 + ($lvl - 1) * 0.14
    @{
        Name        = "Lich King"
        DisplayName = "*** THE LICH KING OF LEGACY CODE ***"
        HP          = [math]::Floor(850 * $hpScale)
        MaxHP       = [math]::Floor(850 * $hpScale)
        ATK         = [math]::Floor(30 * $atkScale)
        DEF         = [math]::Floor(22 * $hpScale)
        SPD         = [math]::Floor(12 * $atkScale)
        MAG         = [math]::Floor(30 * $atkScale)
        XP          = [math]::Floor(2000 * $hpScale)
        Gold        = [math]::Floor(1000 + $lvl * 60)
        IsBoss      = $true
        IsMiniBoss  = $false
        DropsKey    = $false
        Stunned     = $false
        Loot        = (New-RandomLoot ($lvl + 4))
        Variant     = ""
        Abilities   = @(
            @{Name="Attack";          Power=0;  Type="Normal";   Cooldown=0}
            @{Name="Deprecate";       Power=26; Type="Magic";    Cooldown=3}
            @{Name="Breaking Change"; Power=34; Type="Physical"; Cooldown=4}
            @{Name="Legacy Lock";     Power=0;  Type="Buff";     Effect="ATK+10"; Cooldown=5}
            @{Name="Rollback";        Power=60; Type="Heal";     Cooldown=6}
            @{Name="Force Push";      Power=45; Type="Physical"; Cooldown=7}
        )
    }
}

function Show-MigrationFinale {
    Show-Cutscene -Title "THE FINAL MIGRATION" -Lines @(
        @{T="The floor below sixteen is SWEPT. Clean corridors.";              C="Gray"}
        @{T="Sorted tickets in perfect stacks, taller than doors.";             C="Gray"}
        @{T="";                                                              C="Gray"}
        @{T="At the heart of it, something sits a throne of filing";            C="Gray"}
        @{T="cabinets, wearing a crown of expired certificates.";               C="Gray"}
        @{T="";                                                              C="Gray"}
        @{T="'YOU ARE NOT ON THE SCHEDULE,' it says, in a voice";              C="Red"}
        @{T="like a fan spinning down. 'NOTHING IS, ANYMORE.";                 C="Red"}
        @{T="EVERYTHING MIGRATES. EVERYTHING BECOMES LEGACY.";                 C="Red"}
        @{T="EVERYTHING, FINALLY, GETS MAINTAINED — BY ME.'";                  C="Red"}
        @{T="";                                                              C="Gray"}
        @{T="You hand it the blank ticket marked LAST.";                       C="Yellow"}
        @{T="It reads the priority field. It stands.";                         C="Yellow"}
    )
    $lk = New-LichKing
    $result = Start-Combat $lk
    if($result.Result -eq "Won"){
        Set-QuestStage "lk_down" 999999
        Set-QuestStage "msq" 999
        Show-Cutscene -Title "MIGRATION CANCELLED" -Lines @(
            @{T="The crown of certificates expires all at once.";               C="Gray"}
            @{T="The stacked tickets sigh, settle — and begin, page";           C="Gray"}
            @{T="by page, to rise. Going UP. Going home.";                      C="Yellow"}
            @{T="";                                                          C="Gray"}
            @{T="Somewhere far above, a board's empty side starts";             C="Gray"}
            @{T="to fill.";                                                    C="Gray"}
            @{T="";                                                          C="Gray"}
            @{T="*** THE FINAL MIGRATION IS CANCELLED ***";                     C="Magenta"}
            @{T="*** +2 ATK / DEF / SPD / MAG — permanent ***";                 C="Yellow"}
            @{T="*** NEW GAME+ IS OPEN (town [N]) ***";                         C="Magenta"}
        )
        $p = $script:Player
        $p.ATK += 2; $p.DEF += 2; $p.SPD += 2; $p.MAG += 2
        $script:Gold += 500
        Grant-XP 1000
        Wait-Enter
    }
    elseif($result.Result -eq "Fled"){
        Write-Host ""
        Write-CL "  'RESCHEDULED,' it says behind you. 'EVERYTHING IS," "Red"
        Write-CL "   EVENTUALLY.'" "Red"
        Write-Host ""
        Wait-Enter
    }
    return $result.Result
}

# ── Phase 5: THE NEMESIS — ROOT, THE USURPED ADMIN ────────────────
# One bespoke, hand-scripted rival (locked decision). The sysadmin
# who descended before Marn and never filed a resignation. Three
# scripted encounters: ambush (floor 8+), rematch (14+, stronger,
# remembers whether you fled), final stand (16+, Core Meltdown era).
# His Name is "Root", so the intro-quip system serves its default:
# 'It does not appear in any documentation.' — working as intended.
function New-NemesisEnemy {
    param([int]$Stage)
    $lvl = [math]::Max($script:DungeonLevel, 8)
    $hpScale  = 1 + ($lvl - 1) * 0.12
    $atkScale = 1 + ($lvl - 1) * 0.10
    $mult = switch($Stage){ 1 {1.0} 2 {1.3} default {1.6} }
    $abil = @(
        @{Name="Attack";               Power=0;  Type="Normal";   Cooldown=0}
        @{Name="sudo Strike";          Power=18; Type="Physical"; Cooldown=3}
        @{Name="Privilege Escalation"; Power=0;  Type="Buff";     Effect="ATK+6"; Cooldown=4}
    )
    if($Stage -ge 2){ $abil += @{Name="kill -9";        Power=30; Type="Physical"; Cooldown=5} }
    if($Stage -ge 3){ $abil += @{Name="Restart Daemon"; Power=38; Type="Heal";     Cooldown=6} }
    @{
        Name        = "Root"
        DisplayName = if($Stage -ge 3){"*** ROOT, THE USURPED ADMIN ***"}else{"Root, the Usurped Admin"}
        HP          = [math]::Floor(200 * $hpScale * $mult)
        MaxHP       = [math]::Floor(200 * $hpScale * $mult)
        ATK         = [math]::Floor(15 * $atkScale * $mult)
        DEF         = [math]::Floor(10 * $hpScale * $mult)
        SPD         = [math]::Floor(11 * $atkScale * $mult)
        MAG         = [math]::Floor(12 * $atkScale * $mult)
        XP          = [math]::Floor(180 * $mult * $hpScale)
        Gold        = [math]::Floor(120 * $mult + $lvl * 10)
        IsBoss      = $false
        IsMiniBoss  = $true
        DropsKey    = $false
        Stunned     = $false
        Loot        = (New-RandomLoot ($lvl + 1))
        Variant     = ""
        Abilities   = $abil
    }
}

# Runs the scripted encounter for the current stage and returns the
# combat Result string ("Won" / "Fled" / "Death") to the loop hook.
function Show-NemesisEncounter {
    $stage = [int]$script:NemesisStage + 1   # which fight this is (1-3)
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkRed"
    Write-CL "  ║                          R O O T                                 ║" "Red"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkRed"
    Write-Host ""
    switch($stage){
        1 {
            Write-CL "  A figure in a tattered admin's coat steps out of the wall" "Gray"
            Write-CL "  shadow. His badge still reads GUILD OF SYSADMINS." "Gray"
            Write-CL "  His eyes read otherwise." "Gray"
            Write-Host ""
            Write-CL "  'Another fieldwalker. They keep sending you down here" "Red"
            Write-CL "   to close MY tickets.'" "Red"
            Write-CL "  'I was root here before the Depths woke up." "Red"
            Write-CL "   I am root here still.'" "Red"
        }
        2 {
            if($script:NemesisFled){
                Write-CL "  'Last time, you ran. Smart.'" "Red"
                Write-CL "  'Stopping was the mistake.'" "Red"
            } else {
                Write-CL "  'You hit hard, for a process without privileges.'" "Red"
            }
            Write-Host ""
            Write-CL "  He is faster now. Something below has been" "Gray"
            Write-CL "  feeding him cycles." "Gray"
        }
        default {
            Write-CL "  The heat parts around him. He has stopped" "Gray"
            Write-CL "  pretending to be human-shaped." "Gray"
            Write-Host ""
            Write-CL "  'This is MY production environment.'" "Red"
            Write-CL "  'You are an unauthorized change.'" "Red"
        }
    }
    Write-Host ""
    Wait-Key
    $root = New-NemesisEnemy $stage
    $result = Start-Combat $root
    if($result.Result -eq "Won"){
        clr
        Write-Host ""
        if($stage -le 2){
            # He escapes the first two defeats — the win is real (XP,
            # gold, loot all paid by the normal victory flow), but the
            # arc continues. Stage advances only on a true win.
            Write-CL "  He staggers, laughs, and dissolves into a scatter" "Gray"
            Write-CL "  of escape codes." "Gray"
            Write-Host ""
            if($stage -eq 1){
                Write-CL "  'kill -15? Cute. I ignore that signal.'" "Red"
            } else {
                Write-CL "  'Two signals ignored. There is no third —" "Red"
                Write-CL "   for one of us.'" "Red"
            }
            Write-Host ""
            Write-CL "  *** ROOT HAS ESCAPED. He will remember this. ***" "DarkRed"
            $script:NemesisStage = $stage
        } else {
            Write-CL "  ╔══════════════════════════════════════════════════╗" "Yellow"
            Write-CL "  ║        R O O T   T E R M I N A T E D             ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════╝" "Yellow"
            Write-Host ""
            Write-CL "  No escape codes this time. He unravels line by" "Gray"
            Write-CL "  line, and the last thing to go is the badge." "Gray"
            Write-Host ""
            Write-CL "  'Fine. ...Close my tickets too.'" "DarkGray"
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════╗" "Cyan"
            Write-CL "  ║           R O O T   A C C E S S                  ║" "Cyan"
            Write-CL "  ╠══════════════════════════════════════════════════╣" "Cyan"
            Write-CL "  ║   +2 ATK   +2 DEF   +2 SPD   +2 MAG   permanent  ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════╝" "Cyan"
            $p = $script:Player
            $p.ATK += 2; $p.DEF += 2; $p.SPD += 2; $p.MAG += 2
            $script:NemesisStage = 3
        }
        Write-Host ""
        Wait-Key
    }
    elseif($result.Result -eq "Fled"){
        $script:NemesisFled = $true
        Write-Host ""
        Write-CL "  'Run. I will still be here.'" "Red"
        Write-CL "  'I am ALWAYS running.'" "Red"
        Write-Host ""
        Wait-Key
    }
    return $result.Result
}

function Start-HiddenBossEncounter {
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkMagenta"
    Write-CL "  ║                                                                  ║" "DarkMagenta"
    Write-CL "  ║              A   F L I C K E R   I N   T H E   L O G S          ║" "Magenta"
    Write-CL "  ║                                                                  ║" "DarkMagenta"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkMagenta"
    Write-Host ""
    Start-Sleep -Milliseconds 600
    Write-CL "  As you turn to leave, the air goes still." "Gray"
    Write-CL "  The torches sputter once, twice, then burn cold blue." "DarkCyan"
    Write-Host ""
    Start-Sleep -Milliseconds 800
    Write-CL "  Something flickers at the edge of your awareness — a process" "Gray"
    Write-CL "  whose parent terminated long ago, but which never received" "Gray"
    Write-CL "  the signal. It has been running, alone, since before your" "Gray"
    Write-CL "  kingdom was a kingdom." "Gray"
    Write-Host ""
    Start-Sleep -Milliseconds 1200
    Write-CL "  An ORPHANED PROCESS surfaces from the depths." "Magenta"
    Write-Host ""
    Write-CL "                    ░░░░░░░" "DarkMagenta"
    Write-CL "                  ░░  ▓▓▓  ░░" "Magenta"
    Write-CL "                ░░  ▓ X X ▓  ░░" "DarkMagenta"
    Write-CL "                ░░  ▓ ▔▔▔ ▓  ░░" "Magenta"
    Write-CL "                  ░░  ▓▓▓  ░░" "DarkMagenta"
    Write-CL "                    ░░ │ ░░" "Magenta"
    Write-CL "                       │" "DarkMagenta"
    Write-CL "                    pid:????" "DarkGray"
    Write-Host ""
    Write-CL "  '...still... running... still... running...'" "DarkMagenta"
    Write-Host ""
    Write-CL "  This is a SUPER-BOSS. Far stronger than any boss." "Yellow"
    Write-Host ""
    Write-C "  Engage? [y/n]: " "Yellow"
    $eng = Read-Host
    if($eng -ne 'y' -and $eng -ne 'Y'){
        Write-CL "  You back away. The flicker fades. Some processes do not" "DarkGray"
        Write-CL "  respond to keyboard interrupts." "DarkGray"
        Wait-Key
        return
    }

    # Build the hidden boss enemy. Stats: ~3x normal boss, with unique
    # ability set themed around process/log/zombie-process flavor.
    $lvl = [math]::Max($script:DungeonLevel, 5)
    $hpScale = 1 + ($lvl - 1) * 0.30
    $atkScale = 1 + ($lvl - 1) * 0.22
    $orphan = @{
        Name        = "Orphaned Process"
        DisplayName = "*** THE ORPHANED PROCESS ***"
        HP          = [math]::Floor(700 * $hpScale)
        MaxHP       = [math]::Floor(700 * $hpScale)
        ATK         = [math]::Floor(34 * $atkScale)
        DEF         = [math]::Floor(20 * $hpScale)
        SPD         = [math]::Floor(15 * $atkScale)
        MAG         = [math]::Floor(28 * $atkScale)
        XP          = [math]::Floor(1500 * $hpScale)
        Gold        = [math]::Floor(800 + $lvl * 80)
        IsBoss      = $true
        IsMiniBoss  = $false
        DropsKey    = $false
        Stunned     = $false
        Loot        = (New-RandomLoot ($lvl + 3))
        Variant     = ""
        Abilities   = @(
            @{Name="Attack";          Power=0;  Type="Normal";    Cooldown=0}
            @{Name="Stack Overflow";  Power=22; Type="Magic";     Cooldown=2}
            @{Name="Zombie Spawn";    Power=18; Type="Physical";  Cooldown=3}
            @{Name="Memory Leak";     Power=0;  Type="Buff";      Effect="ATK+8"; Cooldown=4}
            @{Name="Force-Quit";      Power=30; Type="Physical";  Cooldown=5}
            @{Name="Garbage Collect"; Power=40; Type="Heal";                     Cooldown=6}
        )
    }
    $result = Start-Combat $orphan
    if($result.Result -eq "Won"){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "Yellow"
        Write-CL "  ║                                                                  ║" "Yellow"
        Write-CL "  ║              T H E   P R O C E S S   T E R M I N A T E S        ║" "Yellow"
        Write-CL "  ║                                                                  ║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "Yellow"
        Write-Host ""
        Write-CL "  The Orphaned Process emits one final stack trace and dissolves." "DarkGray"
        Write-CL "  A scroll falls at your feet, signed by the Guild of SysAdmins." "Gray"
        Write-Host ""
        Write-CL "  ╔═══════════════════════════════════════════════════════╗" "Cyan"
        Write-CL "  ║         GUILD OF SYSADMIN FAVOR GRANTED              ║" "Cyan"
        Write-CL "  ╠═══════════════════════════════════════════════════════╣" "Cyan"
        Write-CL "  ║   +5 ATK   +5 DEF   +5 SPD   +5 MAG                   ║" "Yellow"
        Write-CL "  ║   +25 Max HP   +15 Max MP                            ║" "Green"
        Write-CL "  ║   15% discount at all shops, permanently             ║" "Magenta"
        Write-CL "  ╚═══════════════════════════════════════════════════════╝" "Cyan"
        Write-Host ""
        $p = $script:Player
        $p.ATK    += 5
        $p.DEF    += 5
        $p.SPD    += 5
        $p.MAG    += 5
        $p.MaxHP  += 25; $p.HP += 25
        $p.MaxMP  += 15; $p.MP += 15
        if($p.HP -gt $p.MaxHP){ $p.HP = $p.MaxHP }
        if($p.MP -gt $p.MaxMP){ $p.MP = $p.MaxMP }
        $script:HiddenBossDefeated = $true
        Add-Corruption -15   # slaying the Orphaned Process cleanses much
        Write-CL "  Your Bestiary records a new entry: 'The Orphaned Process'." "DarkMagenta"
        Wait-Key
    } else {
        Write-CL "  The Process keeps running. It always was. It always will be." "DarkGray"
        Wait-Key
    }
}

# Optional risk/reward modifiers offered at dungeon entry. Player picks
# 1 of 3 random mutators or skips entirely. Each mutator amplifies a
# specific stat or behavior in exchange for bonus rewards on clear.
# Cleared on dungeon end (clear or death).
function Get-MutatorPool {
    @(
        @{ Id="GlassCannon";  Name="Glass Cannon";    Desc="+50% damage dealt and taken";        Color="Red"     ; RewardMul=1.30 }
        @{ Id="Pacifist";     Name="Pacifist's Path"; Desc="No XP from kills, 3x quest XP";       Color="Cyan"    ; RewardMul=1.20 }
        @{ Id="CursedLoot";   Name="Cursed Loot";     Desc="Gear drops at 50% durability, +50% stats"; Color="DarkMagenta"; RewardMul=1.25 }
        @{ Id="Speedrun";     Name="Speedrun";        Desc="Enemies +25% SPD"; Color="Yellow"; RewardMul=1.20 }
        @{ Id="Frugal";       Name="Frugal Run";      Desc="No potions, only 1 lockpick"; Color="DarkYellow"; RewardMul=1.40 }
        @{ Id="Hardcore";     Name="Hardcore";        Desc="Death loses 50% gold"; Color="DarkRed"  ; RewardMul=1.30 }
    )
}

# True if the active mutator has the given ID. Safe to call when no
# mutator is active.
function Has-Mutator {
    param([string]$Id)
    if(-not $script:DungeonMutator){ return $false }
    return $script:DungeonMutator.Id -eq $Id
}

# Returns the cleared-dungeon reward multiplier from the active mutator
# (or 1.0 if none). Used at the boss-defeat/exit reward step.
function Get-MutatorRewardMul {
    if(-not $script:DungeonMutator){ return 1.0 }
    return [double]$script:DungeonMutator.RewardMul
}

# Pre-dungeon screen offering 3 random mutators. Returns silently after
# the player picks (sets $script:DungeonMutator) or skips ($null).
function Show-MutatorChoice {
    # Clear any leftover mutator from a previous run defensively.
    $script:DungeonMutator = $null

    $pool = Get-MutatorPool
    # Pick 3 distinct random offers
    $offers = @($pool | Get-Random -Count 3)

    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkYellow"
    Write-CL "  ║                D U N G E O N   M U T A T O R S                  ║" "Yellow"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkYellow"
    Write-Host ""
    Write-CL "  Before you descend, a Guild SysAdmin pins three sticky notes" "Gray"
    Write-CL "  to your pack. Each is a runtime flag you can pass to today's" "Gray"
    Write-CL "  dungeon — risk/reward modifiers that change the rules and" "Gray"
    Write-CL "  amplify the gold/XP at the end if you clear it." "Gray"
    Write-Host ""
    Write-CL "  Pick one or skip." "DarkGray"
    Write-Host ""
    Write-CL "  ! WARNING: While a mutator is active, abandoning the dungeon" "DarkYellow"
    Write-CL "    forfeits ALL loot, gold, and XP earned during the run." "DarkYellow"
    Write-CL "    Mutator runs are commit-or-die." "DarkYellow"
    Write-Host ""

    for($i=0; $i -lt $offers.Count; $i++){
        $m = $offers[$i]
        $rewardPct = [int](($m.RewardMul - 1.0) * 100)
        Write-CL "    [$($i+1)] $($m.Name)" $m.Color
        Write-CL "         $($m.Desc)" "Gray"
        Write-CL "         Reward bonus on clear: +${rewardPct}% gold/XP" "DarkGray"
        Write-Host ""
    }
    Write-CL "    [0] Skip — no mutator" "DarkGray"
    Write-Host ""
    Write-C "  > " "Yellow"
    $choice = Read-Host
    if([string]::IsNullOrWhiteSpace($choice)){ return }
    $parsed = $null
    if(-not [int]::TryParse($choice.Trim(), [ref]$parsed)){ return }
    if($parsed -lt 1 -or $parsed -gt $offers.Count){ return }
    $picked = $offers[$parsed - 1]
    $script:DungeonMutator = @{
        Id        = $picked.Id
        Name      = $picked.Name
        Desc      = $picked.Desc
        Color     = $picked.Color
        RewardMul = $picked.RewardMul
    }
    Write-Host ""
    Write-CL "  Mutator activated: $($picked.Name)" $picked.Color
    Write-CL "  $($picked.Desc)" "DarkGray"
    Start-Sleep -Milliseconds 900
}

# Cleans up mutator state at dungeon end. Called from BOTH the
# clear-and-exit path and the death path so the player isn't stuck
# without their stashed gear after a Frugal run.
function Reset-MutatorOnEnd {
    # Themed raid cleanup (Phase 6): restore the Depths' floor counter.
    # This function runs on BOTH the clear path and the death path,
    # which is exactly the guarantee the raid swap needs.
    if($script:RaidTheme){
        if($null -ne $script:RaidTheme.SavedLevel){
            $script:DungeonLevel = [int]$script:RaidTheme.SavedLevel
        }
        $script:RaidTheme = $null
    }
    if(Has-Mutator "Frugal"){
        # Restore the stash WITH cap enforcement (bug fix): potions found
        # or bought during the run may already fill the belt (10) / bag
        # (5). Blindly appending let players exceed the hard caps
        # permanently. Overflow converts to gold at sell value.
        $overflowGold = 0
        if($script:FrugalStashedPotions){
            foreach($sp in $script:FrugalStashedPotions){
                if($script:Potions.Count -lt 10){
                    [void]$script:Potions.Add($sp)
                } else {
                    $gv = Get-ItemSellValue $sp
                    if(-not $gv -or $gv -le 0){ $gv = 15 }
                    $overflowGold += $gv
                }
            }
        }
        if($script:FrugalStashedThrowables){
            foreach($sp in $script:FrugalStashedThrowables){
                if($script:ThrowablePotions.Count -lt 5){
                    [void]$script:ThrowablePotions.Add($sp)
                } else {
                    $gv = Get-ItemSellValue $sp
                    if(-not $gv -or $gv -le 0){ $gv = 15 }
                    $overflowGold += $gv
                }
            }
        }
        if($overflowGold -gt 0){
            $script:Gold += $overflowGold
            Write-CL "  Your stashed potions overflow the bag — the excess sells for ${overflowGold}g." "DarkYellow"
        }
        $script:Lockpicks += [int]$script:FrugalStashedLockpicks
    }
    $script:FrugalStashedPotions    = $null
    $script:FrugalStashedThrowables = $null
    $script:FrugalStashedLockpicks  = 0
    $script:DungeonMutator          = $null
    # Revert Berserker Final Stand stat buffs so they don't compound
    # across dungeons. The deltas were stored at proc time.
    if($script:FinalStandBuffs){
        $p = $script:Player
        if($p){
            $p.ATK -= [int]$script:FinalStandBuffs.ATK
            $p.DEF -= [int]$script:FinalStandBuffs.DEF
            $p.SPD -= [int]$script:FinalStandBuffs.SPD
            $p.MAG -= [int]$script:FinalStandBuffs.MAG
            # Floor at 1 to avoid negative stats from mismatched math
            if($p.ATK -lt 1){ $p.ATK = 1 }
            if($p.DEF -lt 1){ $p.DEF = 1 }
            if($p.SPD -lt 1){ $p.SPD = 1 }
            if($p.MAG -lt 1){ $p.MAG = 1 }
        }
        $script:FinalStandBuffs = $null
    }
}

# ─── RAYCAST RENDERER (the monument) ─────────────────────────────
# Real-time DDA raycaster (donor: raycaster_v2.ps1) integrated as a
# movement/render FRONT-END. The classic master loop stays the sole
# authority: Invoke-RaycastLeg returns action tokens (Walk / Step /
# Key), the loop synthesizes a "W" keypress with an overridden target
# tile, and the ENTIRE classic tile-trigger chain runs unchanged.
# Renderer choice: Settings.Renderer = Auto/Classic/Raycast, saved as
# the 4th comma value of positional part [44]. Auto = Raycast where
# VT (ANSI) support is detected, Classic on bare conhost.

# One-time VT capability probe, cached. v1.6.1 fix: env sniffing
# ($env:WT_SESSION etc.) misses the common Windows 11 case where a
# conhost-launched script is handed off to Windows Terminal via the
# "default terminal application" setting — the window IS Windows
# Terminal but no env var says so. So: ask the console itself.
# Enabling ENABLE_VIRTUAL_TERMINAL_PROCESSING (0x4) on the stdout
# handle is both the test AND the cure — if SetConsoleMode accepts
# the flag, VT works (Win10 1511+ conhost, Windows Terminal, any
# ConPTY host), and the raycaster's escape codes now render instead
# of printing as garbage (PS 5.1 never enables the flag on its own).
# Env sniffing stays as a FALLBACK for hosts without classic console
# handles (some IDE terminals) where the P/Invoke path can't run.
$script:VTProbe = $null
function Test-VTSupport {
    if($null -ne $script:VTProbe){ return $script:VTProbe }
    $vt = $false
    # 1) Definitive probe: enable VT processing on the output handle.
    try {
        if(-not ("DOPNative.VT" -as [type])){
            $vtSig = '[DllImport("kernel32.dll", SetLastError=true)] public static extern IntPtr GetStdHandle(int nStdHandle); [DllImport("kernel32.dll", SetLastError=true)] public static extern bool GetConsoleMode(IntPtr hConsoleHandle, out uint lpMode); [DllImport("kernel32.dll", SetLastError=true)] public static extern bool SetConsoleMode(IntPtr hConsoleHandle, uint dwMode);'
            Add-Type -Namespace DOPNative -Name VT -MemberDefinition $vtSig -ErrorAction Stop
        }
        $hOut = [DOPNative.VT]::GetStdHandle(-11)   # STD_OUTPUT_HANDLE
        if($hOut -ne [IntPtr]::Zero -and $hOut -ne ([IntPtr](-1))){
            $conMode = [uint32]0
            if([DOPNative.VT]::GetConsoleMode($hOut, [ref]$conMode)){
                if(($conMode -band 0x0004) -ne 0){
                    $vt = $true    # already enabled (e.g. PS7 host)
                } elseif([DOPNative.VT]::SetConsoleMode($hOut, $conMode -bor 0x0004)){
                    $vt = $true    # flag accepted — VT is live now
                }
            }
        }
    } catch {}
    # 2) Fallback: environment advertising (ConEmu, ANSICON, VS Code,
    #    *nix-style hosts). Only consulted when the probe said no.
    if(-not $vt){
        try {
            if($env:WT_SESSION){ $vt = $true }
            elseif($env:ConEmuANSI -eq "ON"){ $vt = $true }
            elseif($env:ANSICON){ $vt = $true }
            elseif($env:TERM_PROGRAM){ $vt = $true }
            elseif($env:TERM){ $vt = $true }
        } catch {}
    }
    $script:VTProbe = $vt
    return $vt
}

# Effective renderer for THIS session: explicit choice wins (Raycast
# still needs VT), Auto follows the probe.
function Get-EffectiveRenderer {
    $pref = [string]$script:Settings.Renderer
    if($pref -eq "Classic"){ return "Classic" }
    if($pref -eq "Raycast"){ if(Test-VTSupport){ return "Raycast" } else { return "Classic" } }
    if(Test-VTSupport){ return "Raycast" }
    return "Classic"
}
# v1.6.1: the raycast frame is a fixed 100 cols x 26 rows plus ~7 HUD
# lines. In a smaller window every frame writes past the last row and
# the terminal SCROLLS — the "screen jumping" bug. Rather than
# judder, the game uses the classic view until the window can hold a
# full frame. Checked every loop turn, so resizing mid-run switches
# modes automatically (same behavior the classic buffered mode has).
function Test-RayWindowFit {
    try {
        $ws = $Host.UI.RawUI.WindowSize
        if($ws.Width -lt 118 -or $ws.Height -lt 33){
            # v1.6.2: honor the player's renderer choice instead of
            # silently dropping to classic. First try to grow the
            # window ourselves, ONCE per shrink episode (the visible
            # jump IS the resize — intentional). If the host refuses
            # (many terminals ignore SetWindowSize), fall back to
            # classic but TELL the player why and how to get 3D back.
            if(-not $script:RayFitTried){
                $script:RayFitTried = $true
                try {
                    if($env:OS -eq "Windows_NT"){
                        if([Console]::BufferWidth -lt 120){ [Console]::BufferWidth = 120 }
                        if([Console]::BufferHeight -lt 33){ [Console]::BufferHeight = 33 }
                        [Console]::SetWindowSize(120, 33)
                    }
                } catch {}
                try {
                    $ws = $Host.UI.RawUI.WindowSize
                    if($ws.Width -ge 118 -and $ws.Height -ge 33){
                        $script:StatusMsg = "Window was too small for the 3D view — resized it. That jump was intentional!"
                        return $true
                    }
                } catch {}
            }
            if(-not $script:RayFitWarned){
                $script:RayFitWarned = $true
                $script:StatusMsg = "Window too small for the 3D view (needs 100x33) — enlarge it and 3D returns automatically."
            }
            return $false
        }
    } catch {}
    $script:RayFitTried = $false
    $script:RayFitWarned = $false
    return $true
}
function Test-RaycastActive {
    if((Get-EffectiveRenderer) -ne "Raycast"){ return $false }
    return (Test-RayWindowFit)
}

# Per-zone palette as SHADE LADDERS: index = integer distance shade,
# preserving hue while darkening (the donor's grayscale-subtract trick
# only works for colors 232+, so colored zones get explicit ladders).
function Get-RayZonePalette {
    param($Zone)
    $id = ""
    if($Zone){ $id = [string]$Zone.Id }
    # v1.6.2: Zone Visuals OFF forces the baseline stone palette —
    # zone names, hazards, and variants are untouched; only paint.
    if($script:Settings.ZoneTheme -eq $false){ $id = "ServerHalls" }
    # Raid themes carry custom ids — fall back by the zone's console color.
    if($id -notin @("ServerHalls","Flooded","Archives","Core")){
        $zc = ""
        if($Zone){ $zc = [string]$Zone.Color }
        $id = switch($zc){
            "Cyan"      { "Flooded" }
            "DarkCyan"  { "Flooded" }
            "Green"     { "Archives" }
