# Ladder lookup with clamping — index by integer shade.
function Get-RayShade {
    param($Ladder, [int]$Idx)
    if($Idx -lt 0){ $Idx = 0 }
    if($Idx -ge $Ladder.Count){ $Idx = $Ladder.Count - 1 }
    return $Ladder[$Idx]
}

# ── 12x12 sprite textures (0 = transparent, else 8-bit ANSI color) ──
# Donor art (Skeleton/Wraith/Adventurer/Chest) plus six enemy types
# and three dungeon props drawn for the port. Mimic reuses the chest
# body — the disguise IS the sprite — with two red glints on the lock.
$script:RayTexCache = $null
function Get-RayTexTable {
    if($script:RayTexCache){ return $script:RayTexCache }
    $t = @{}
    $t["Skeleton"] = @(
        @(0,0,0,255,255,255,255,0,0,0,0,0),
        @(0,0,255,232,255,255,232,255,0,0,0,0),
        @(0,0,0,255,255,255,255,0,0,0,0,0),
        @(0,0,0,0,255,255,0,0,0,0,0,0),
        @(0,0,255,255,255,255,255,255,0,0,0,0),
        @(0,255,0,255,232,255,232,255,0,255,0,0),
        @(0,255,0,255,255,255,255,255,0,255,0,0),
        @(0,0,0,0,255,255,0,0,160,160,0,0),
        @(0,0,0,255,232,232,255,0,244,244,0,0),
