    # and upscaled ONCE here to 24x24 — diagonals smooth out,
    # silhouettes keep their pixel-art read, and the sampler cost is
    # identical (same lookup, bigger array). 0 stays transparent.
    $t2 = @{}
    foreach($tk in @($t.Keys)){
        $src = $t[$tk]
        $dst = New-Object "object[]" 24
        for($sy=0; $sy -lt 12; $sy++){
            $r0 = New-Object "int[]" 24
            $r1 = New-Object "int[]" 24
            $row  = $src[$sy]
            $rowU = if($sy -gt 0){ $src[$sy-1] } else { $row }
            $rowD = if($sy -lt 11){ $src[$sy+1] } else { $row }
            for($sx=0; $sx -lt 12; $sx++){
                $cP = $row[$sx]
                $cA = $rowU[$sx]
                $cD = $rowD[$sx]
                $cC = if($sx -gt 0){ $row[$sx-1] } else { $cP }
                $cB = if($sx -lt 11){ $row[$sx+1] } else { $cP }
                $e0 = $cP; $e1 = $cP; $e2 = $cP; $e3 = $cP
                if($cC -eq $cA -and $cC -ne $cD -and $cA -ne $cB){ $e0 = $cA }
                if($cA -eq $cB -and $cA -ne $cC -and $cB -ne $cD){ $e1 = $cB }
                if($cD -eq $cC -and $cD -ne $cB -and $cC -ne $cA){ $e2 = $cC }
                if($cB -eq $cD -and $cB -ne $cA -and $cD -ne $cC){ $e3 = $cB }
                $dx = $sx * 2
                $r0[$dx] = $e0; $r0[$dx+1] = $e1
                $r1[$dx] = $e2; $r1[$dx+1] = $e3
            }
            $dst[$sy*2]   = $r0
            $dst[$sy*2+1] = $r1
        }
        $t2[$tk] = $dst
    }
    $t = $t2
    $script:RayTexCache = $t
    return $t
}

# Enemy hashtable value → texture name. Group spawns render the pack
# leader; zone variants ("Corroded Goblin") map by base-name substring.
function Get-RayTexForEnemy {
    param($EnemyVal, [int]$Cell)
    if($Cell -eq 3){ return "Wraith" }
    $en = $EnemyVal
    if($EnemyVal -is [array] -and $EnemyVal.Count -gt 0){ $en = $EnemyVal[0] }
    $nm = ""
    if($en -and $en.Name){ $nm = [string]$en.Name }
    foreach($k in @("Mimic","Goblin","Zombie","Thief","Wizard","Troll","Skeleton")){
        if($nm -match $k){ return $k }
    }
    return "Skeleton"
}

# ── MAP ADAPTER ──────────────────────────────────────────────────
# Rebuilt on EVERY leg entry (441 cells — trivial) so kills, opened
# chests, and crumbled lore objects reflect instantly. Cell mapping:
#   1 wall → 1 · 4 boss (enemy alive) → 2 sliding door · else floor.
# Enemies/exit become proximity triggers; chest/rescue/altar/lore and
# the boss door become [E] interactables. Float position persists in
# $script:RayState across legs; it only re-seeds from the dungeon's
# integer PX/PY when the dungeon object itself changes (new floor).
$script:RayState = $null
function Build-RayState {
    $d = $script:Dungeon
    $fresh = $false
    if(-not $script:RayState){ $fresh = $true }
    elseif(-not [object]::ReferenceEquals($script:RayState.DunRef, $d)){ $fresh = $true }
    if($fresh){
        $script:RayState = @{
            DunRef  = $d
            Px      = [double]$d.PX + 0.5
            Py      = [double]$d.PY + 0.5
            Pa      = [double]$( switch([int]$d.PDir){ 0 { -[math]::PI/2 } 1 { 0.0 } 2 { [math]::PI/2 } default { [math]::PI } } )
            DistAcc = 0.0
            Suppress = ""
            NeedClear = $true
            Doors   = @{}
        }
    }
    $rs = $script:RayState
    $w = [int]$d.W; $h = [int]$d.H
    $map = New-Object "int[]" ($w * $h)
    $sprites = [System.Collections.ArrayList]@()
    $triggers = [System.Collections.ArrayList]@()
    $inter = @{}
    $tex = Get-RayTexTable
    for($y=0; $y -lt $h; $y++){
        for($x=0; $x -lt $w; $x++){
            $cell = $d.Grid[$y,$x]
            $mv = 0
            switch($cell){
                1 { $mv = 1 }
                2 {
                    # v1.6.1: combat starts via [E] ONLY — no proximity
                    # trigger. The tile is solid (mv=3: blocks movement,
                    # transparent to rays) so you meet the monster face
                    # to face, and choose the fight.
                    $eKey = "$x,$y"
                    if($d.Enemies.ContainsKey($eKey)){
                        $mv = 3
                        $tn = Get-RayTexForEnemy $d.Enemies[$eKey] 2
                        if(Test-MimicDisguised $d.Enemies[$eKey]){
                            # Disguised mimic (v1.6.2): chest-sized,
                            # chest-labelled, and solid — exactly like
                            # a real chest now. Tells: the red lock
                            # glint, and the Hound only smells REAL
                            # chests through fog.
                            [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex=$tn;Scale=0.45;Dist=0.0})
                            $inter[$eKey] = "Open Chest"
                        } else {
                            [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex=$tn;Scale=0.75;Dist=0.0})
                            $inter[$eKey] = "Fight"
                        }
                    }
                }
                3 {
                    $eKey = "$x,$y"
                    if($d.Enemies.ContainsKey($eKey)){
                        $mv = 3
                        [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Wraith";Scale=0.85;Dist=0.0})
                        $inter[$eKey] = "Fight the Mini-Boss"
                    }
                }
                4 {
                    # Boss door (v1.6): a locked RED sliding door on the
                    # boss room's ring. [E] with the key slides it open
                    # in-engine, then a Step token lets the classic
                    # handler commit the grid change (and the credits).
                    $eKey = "$x,$y"
                    $mv = 2
                    if(-not $rs.Doors.ContainsKey($eKey)){
                        $rs.Doors[$eKey] = @{ State="Closed"; Ratio=0.0; Boss=$true }
                    }
                    $inter[$eKey] = $(if($script:HasBossKey){"Unlock the Boss Door"}else{"Boss Door — LOCKED (mini-boss has the key)"})
                }
                10 {
                    # Regular sliding door (v1.6): brown, [E] opens,
                    # stays open forever once the classic loop commits.
                    $eKey = "$x,$y"
                    $mv = 2
                    if(-not $rs.Doors.ContainsKey($eKey)){
                        $rs.Doors[$eKey] = @{ State="Closed"; Ratio=0.0; Boss=$false }
                    }
                    $inter[$eKey] = "Open Door"
                }
                11 {
                    # The BOSS — its own tile inside the sealed room.
                    # v1.6.1: [E]-only, solid, like every other enemy.
                    $eKey = "$x,$y"
                    if($d.Enemies.ContainsKey($eKey)){
                        $mv = 3
                        [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Boss";Scale=0.95;Dist=0.0})
                        $inter[$eKey] = "Fight the BOSS"
                    }
                }
                5 {
                    # v1.6.2: the exit is [E]-only — no more descending
                    # by drifting near the portal. Solid like chests.
                    $mv = 3
                    [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Portal";Scale=0.9;Dist=0.0})
                    $inter["$x,$y"] = "Descend"
                }
                6 {
                    # v1.6.2: chests are SOLID in 3D — walking over a
                    # chest tile auto-opened it ("proximity looting").
                    # Now only [E] opens them here; classic mode keeps
                    # its walk-into flow (there is no [E] there). Also
                    # makes real chests block feet exactly like a
                    # disguised mimic. Room rectangles are >= 3x3, so
                    # one solid tile can never sever a path.
                    $mv = 3
                    [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Chest";Scale=0.45;Dist=0.0})
                    $inter["$x,$y"] = "Open Chest"
                }
                7 {
                    [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Adventurer";Scale=0.75;Dist=0.0})
                    $inter["$x,$y"] = "Rescue Survivor"
                }
                8 {
                    [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Altar";Scale=0.6;Dist=0.0})
                    $inter["$x,$y"] = "Pray at the Altar"
                }
                9 {
                    # v1.6.2: lore objects are SOLID in 3D — [E] to
                    # inspect, no more reading a terminal by walking
                    # over it. Classic walk-into unchanged; they sit
                    # in room interiors (>= 3x3) and crumble to floor
                    # once read, so blocking is safe and temporary.
                    $mv = 3
                    [void]$sprites.Add(@{X=$x+0.5;Y=$y+0.5;Tex="Lore";Scale=0.55;Dist=0.0})
                    $inter["$x,$y"] = "Inspect"
                }
            }
            $map[$y * $w + $x] = $mv
        }
    }
    # Drop door states for tiles that are no longer doors (boss slain).
    $stale = @()
    foreach($k in $rs.Doors.Keys){
        $kp = $k -split ","
        if($map[([int]$kp[1]) * $w + ([int]$kp[0])] -ne 2){ $stale += $k }
    }
    foreach($k in $stale){ $rs.Doors.Remove($k) }
    $rs.Map = $map; $rs.W = $w; $rs.H = $h
    $rs.Sprites = $sprites; $rs.Triggers = $triggers; $rs.Inter = $inter
    $rs.Palette = Get-RayZonePalette $d.Zone
    return $rs
}

# Collision test against the adapter map (door open ratio >= 0.8 walks).
function Test-RayWalkable {
    param($rs, [int]$tx, [int]$ty)
    if($tx -lt 0 -or $tx -ge $rs.W -or $ty -lt 0 -or $ty -ge $rs.H){ return $false }
    $cell = $rs.Map[$ty * $rs.W + $tx]
    if($cell -eq 0){ return $true }
    if($cell -eq 2){
        $dk = "$tx,$ty"
        if($rs.Doors.ContainsKey($dk) -and $rs.Doors[$dk].Ratio -ge 0.8){ return $true }
    }
    return $false
}

# Fog reveal around the player's tile — same radii as Render-Screen
# (3 base, 5 with the Falcon pet).
function Update-RayFog {
    param($d)
    $sightR = 3
    if($script:Pet -and $script:Pet.Type -eq "Falcon"){ $sightR = 5 }
    for($dy=-$sightR; $dy -le $sightR; $dy++){
        for($dx=-$sightR; $dx -le $sightR; $dx++){
            $mx = $d.PX + $dx; $my = $d.PY + $dy
            if($mx -ge 0 -and $mx -lt $d.W -and $my -ge 0 -and $my -lt $d.H){
                $d.Seen[$my, $mx] = $true
            }
        }
    }
}

# ── [M] DETAILED MAP ─────────────────────────────────────────────
# Full-dungeon 21x21 fogged map, double-width cells for aspect ratio.
# Replaces the classic side minimap when the raycaster owns the frame,
# and is available from the classic renderer too. Seen tiles remember
# their CURRENT contents; the Hound pet still spots chests through fog.
function Show-DetailedMap {
    $d = $script:Dungeon
    if(-not $d){ return }
    Update-RayFog $d
    $houndOwned = ($script:Pet -and $script:Pet.Type -eq "Hound")
    clr
    Write-Host ""
    Write-CL "  ── D U N G E O N   M A P — floor $($script:DungeonLevel) ──" "Yellow"
    if($d.Zone){ Write-CL "  $($d.Zone.Name)" $d.Zone.Color }
    Write-Host ""
    $dirChar = switch([int]$d.PDir){0{'^'}1{'>'}2{'v'}default{'<'}}
    # Explored % counts the FULL grid (fog-independent of the window).
    $seenCount = 0; $floorTotal = 0
    for($y=0; $y -lt $d.H; $y++){
        for($x=0; $x -lt $d.W; $x++){
            if($d.Grid[$y,$x] -ne 1){ $floorTotal++ ; if($d.Seen[$y,$x]){ $seenCount++ } }
        }
    }
    # Vertical window (v1.6): 41-tall floors don't fit a console page.
    # Show up to 25 rows centered on the player, clamped to the map.
    $winH = 25
    $winTop = 0
    if($d.H -le $winH){
        $winH = $d.H
    } else {
        $winTop = $d.PY - [math]::Floor($winH / 2)
        if($winTop -lt 0){ $winTop = 0 }
        if(($winTop + $winH) -gt $d.H){ $winTop = $d.H - $winH }
    }
    # ── Fast path (v1.6.2) ── the classic loop below is 1000+
    # Write-C calls, one console round-trip per CELL — the map
    # visibly painted line by line. On VT hosts the whole window is
    # built as one ANSI string and emitted in a single write. The
    # classic loop stays for non-VT hosts (gated, not reindented).
    $fastMap = (Test-VTSupport)
    if($fastMap){
        $mEsc = [string][char]0x1b
        $mSB = New-Object System.Text.StringBuilder 16384
        if($winTop -gt 0){ [void]$mSB.Append($mEsc).Append('[90m').Append("   ▲ more above").Append("`n") }
        for($y=$winTop; $y -lt ($winTop + $winH); $y++){
            [void]$mSB.Append('   ')
            for($x=0; $x -lt $d.W; $x++){
                if($x -eq $d.PX -and $y -eq $d.PY){
                    [void]$mSB.Append($mEsc).Append('[92m').Append("$dirChar ")
                    continue
                }
                if(-not $d.Seen[$y,$x]){
                    if($houndOwned -and $d.Grid[$y,$x] -eq 6){ [void]$mSB.Append($mEsc).Append('[93m').Append('$ ') }
                    else { [void]$mSB.Append($mEsc).Append('[90m').Append([string][char]0x00B7).Append(' ') }
                    continue
                }
                switch($d.Grid[$y,$x]){
                    1 { [void]$mSB.Append($mEsc).Append('[90m').Append(([string][char]0x2588) * 2) }
                    2 { if(Test-MimicDisguised $d.Enemies["$x,$y"]){ [void]$mSB.Append($mEsc).Append('[93m').Append('$ ') } else { [void]$mSB.Append($mEsc).Append('[91m').Append('e ') } }
                    3 { [void]$mSB.Append($mEsc).Append('[95m').Append('M ') }
                    4 { [void]$mSB.Append($mEsc).Append('[31m').Append('D ') }
                    5 { [void]$mSB.Append($mEsc).Append('[92m').Append('X ') }
                    6 { [void]$mSB.Append($mEsc).Append('[93m').Append('$ ') }
                    7 { [void]$mSB.Append($mEsc).Append('[96m').Append('@ ') }
                    8 { [void]$mSB.Append($mEsc).Append('[95m').Append('A ') }
                    9 { [void]$mSB.Append($mEsc).Append('[36m').Append('? ') }
                    10 { [void]$mSB.Append($mEsc).Append('[33m').Append('+ ') }
                    11 { [void]$mSB.Append($mEsc).Append('[91m').Append('B ') }
                    default {
                        $fxc = " "
                        foreach($r in $d.Rooms){
                            if($r.Effect -and $x -ge $r.X -and $x -lt ($r.X+$r.W) -and $y -ge $r.Y -and $y -lt ($r.Y+$r.H)){
                                $fxc = "~"
                                break
                            }
                        }
                        if($fxc -eq "~"){ [void]$mSB.Append($mEsc).Append('[36m').Append('~ ') } else { [void]$mSB.Append($mEsc).Append('[90m').Append('. ') }
                    }
                }
            }
            [void]$mSB.Append("`n")
        }
        if(($winTop + $winH) -lt $d.H){ [void]$mSB.Append($mEsc).Append('[90m').Append("   ▼ more below").Append("`n") }
        [void]$mSB.Append($mEsc).Append('[0m')
        try { [Console]::Write($mSB.ToString()) } catch { Write-Host $mSB.ToString() -NoNewline }
    }
    if($winTop -gt 0 -and -not $fastMap){ Write-CL "   ▲ more above" "DarkGray" }
    for($y=$winTop; (-not $fastMap) -and $y -lt ($winTop + $winH); $y++){
        Write-C "   " "DarkGray"
        for($x=0; $x -lt $d.W; $x++){
            if($x -eq $d.PX -and $y -eq $d.PY){
                Write-C ("$dirChar ") "Green"
                continue
            }
            if(-not $d.Seen[$y,$x]){
                if($houndOwned -and $d.Grid[$y,$x] -eq 6){
                    Write-C '$ ' "Yellow"
                } else {
                    Write-C "· " "DarkGray"
                }
                continue
            }
            switch($d.Grid[$y,$x]){
                1 { Write-C "██" "DarkGray" }
                2 { if(Test-MimicDisguised $d.Enemies["$x,$y"]){ Write-C '$ ' "Yellow" } else { Write-C "e " "Red" } }
                3 { Write-C "M " "Magenta" }
                4 { Write-C "D " "DarkRed" }
                5 { Write-C "X " "Green" }
                6 { Write-C '$ ' "Yellow" }
                7 { Write-C "@ " "Cyan" }
                8 { Write-C "A " "Magenta" }
                9 { Write-C "? " "DarkCyan" }
                10 { Write-C "+ " "DarkYellow" }
                11 { Write-C "B " "Red" }
                default {
                    # Floor — mark room-effect tiles so hazards read at a glance.
                    $fxc = " "
                    foreach($r in $d.Rooms){
                        if($r.Effect -and $x -ge $r.X -and $x -lt ($r.X+$r.W) -and $y -ge $r.Y -and $y -lt ($r.Y+$r.H)){
                            $fxc = "~"
                            break
                        }
                    }
                    if($fxc -eq "~"){ Write-C "~ " "DarkCyan" } else { Write-C ". " "DarkGray" }
                }
            }
        }
        Write-Host ""
    }
    if(($winTop + $winH) -lt $d.H -and -not $fastMap){ Write-CL "   ▼ more below" "DarkGray" }
    $pct = 0
    if($floorTotal -gt 0){ $pct = [math]::Floor(100 * $seenCount / $floorTotal) }
    Write-Host ""
    Write-C  "   >" "Green";    Write-C " you  " "DarkGray"
    Write-C  "e" "Red";         Write-C " enemy  " "DarkGray"
    Write-C  "M" "Magenta";     Write-C " mini-boss  " "DarkGray"
    Write-C  "B" "Red";         Write-C " BOSS  " "DarkGray"
    Write-C  "D" "DarkRed";     Write-CL " boss door" "DarkGray"
    Write-C  "   +" "DarkYellow"; Write-C " door  " "DarkGray"
    Write-C  "X" "Green";       Write-C " exit  " "DarkGray"
    Write-C  '$' "Yellow";      Write-C " chest  " "DarkGray"
    Write-C  "@" "Cyan";        Write-C " survivor  " "DarkGray"
    Write-C  "A" "Magenta";     Write-C " altar  " "DarkGray"
    Write-C  "?" "DarkCyan";    Write-C " lore  " "DarkGray"
    Write-C  "~" "DarkCyan";    Write-CL " hazard" "DarkGray"
    Write-Host ""
    Write-CL "   Explored: $pct%" "DarkGray"
    Wait-Key
}

# ── ENGINE STATE (LUTs and buffers, built once per session) ──────
$script:RayEngine = $null
function Init-RayEngine {
    if($script:RayEngine){ return $script:RayEngine }
    # v1.6.2 clarity pass: 118 rays (was 100) — finer wall edges
    # and rounder sprites for ~18% more per-frame ray cost.
    $sw = 118; $sh = 26
    $vh = $sh * 2
    $horizon = [int]($vh / 2)
    $fov = [math]::PI / 3
    $ceilT = New-Object "double[]" $horizon
    for($y=0; $y -lt $horizon; $y++){
        if(($horizon - $y) -ne 0){ $ceilT[$y] = $vh / (2.0 * ($horizon - $y)) } else { $ceilT[$y] = 999.0 }
    }
    # Per-row ceiling distance DELTAS (v1.6.2): how much farther row y
    # reaches than row y-1. Drives the beam anti-aliasing — the world
    # span one character row covers is this delta projected by angle.
    $ceilD = New-Object "double[]" $horizon
    for($y=1; $y -lt $horizon; $y++){ $ceilD[$y] = $ceilT[$y] - $ceilT[$y-1] }
    if($horizon -gt 1){ $ceilD[0] = $ceilD[1] }
    $floorT = New-Object "double[]" $vh
    for($y=$horizon; $y -lt $vh; $y++){
        if(($y - $horizon) -ne 0){ $floorT[$y] = $vh / (2.0 * ($y - $horizon)) } else { $floorT[$y] = 999.0 }
    }
    # ── v1.6.2 detail assets: baked ONCE so the hot loop only
    # indexes arrays ──
    # Wall pattern maps: 4 variants x 32x16 (idx = texY*32+texX),
    # value 0=brick 1=mortar 2=highlight 3=dim. Variant 0 reproduces
    # the old procedural brick EXACTLY; 1-3 layer cracks / chipped
    # bricks / a damp patch on top. Chosen per wall TILE by a cheap
    # coordinate hash, so per pixel it is one array read.
    # v1.6.2 clarity pass: 64x32 texture maps (was 32x16) — same
    # one-array-read-per-pixel cost, four times the detail up close.
    $wallMaps = New-Object "object[]" 4
    for($v=0; $v -lt 4; $v++){
        $wm = New-Object "int[]" 2048
        for($ty=0; $ty -lt 32; $ty++){
            $brickRow = $ty -shr 4
            for($tx=0; $tx -lt 64; $tx++){
                $wt = 0
                $isM = (($ty -band 15) -eq 0) -or (($brickRow % 2 -eq 0 -and ($tx -eq 0 -or $tx -eq 32)) -or ($brickRow % 2 -eq 1 -and ($tx -eq 16 -or $tx -eq 48)))
                if($isM){ $wt = 1 }
                elseif($tx -eq 2 -or $ty -eq 2 -or $ty -eq 18){ $wt = 2 }
                elseif((($tx * $ty) % 13) -eq 0 -and $tx -gt 0 -and $ty -gt 0){ $wt = 3 }
                $wm[($ty -shl 6) + $tx] = $wt
            }
        }
        $wallMaps[$v] = $wm
    }
    # v1.6.2 decals: variants 4-5 start as copies of the clean brick
    # (variant 0) and get decal pixels stamped on top — wt 4 = dried
    # blood, wt 5 = banner cloth. Rare by hash; pure paint.
    $wallMapsAll = New-Object "object[]" 6
    for($v=0; $v -lt 4; $v++){ $wallMapsAll[$v] = $wallMaps[$v] }
    for($v=4; $v -lt 6; $v++){
        $wm = New-Object "int[]" 2048
        [Array]::Copy($wallMaps[0], $wm, 2048)
        $wallMapsAll[$v] = $wm
    }
    # Blood smear: a drip cluster low on the wall, streaking down.
    $wm = $wallMapsAll[4]
    foreach($cc in @(@(40,14),@(41,14),@(42,14),@(39,15),@(40,15),@(41,15),@(42,15),@(43,15),@(40,16),@(41,16),@(42,16),@(41,17),@(42,17),@(41,18),@(41,19),@(42,20),@(41,21),@(41,22),@(41,23),@(38,16),@(38,17),@(44,16),@(44,17),@(44,18))){
        $wm[($cc[1] -shl 6) + $cc[0]] = 4
    }
    # Faction banner: a hanging pennant, pole row at the top.
    $wm = $wallMapsAll[5]
    for($tx=24; $tx -le 39; $tx++){ $wm[(3 -shl 6) + $tx] = 3 }
    for($ty=4; $ty -le 17; $ty++){
        $bw = 6 - [int](($ty - 4) / 3)
        for($tx=(32-$bw); $tx -le (31+$bw); $tx++){ $wm[($ty -shl 6) + $tx] = 5 }
    }
    $wallMaps = $wallMapsAll
    # Variant 1: a jagged crack down the right half.
    $wm = $wallMaps[1]
    foreach($cc in @(@(22,2),@(21,3),@(21,4),@(20,5),@(19,6),@(19,7),@(20,8),@(20,10),@(21,11),@(21,12),@(22,13))){
        foreach($dy in 0,1){ foreach($dx in 0,1){ $wm[((($cc[1]*2+$dy)) -shl 6) + ($cc[0]*2+$dx)] = 3 } }
    }
    # Variant 2: chipped bricks — dark pits with lit edges.
    $wm = $wallMaps[2]
    foreach($cc in @(@(5,3),@(6,3),@(5,4),@(26,11),@(27,11),@(12,12),@(13,13))){
        foreach($dy in 0,1){ foreach($dx in 0,1){ $wm[((($cc[1]*2+$dy)) -shl 6) + ($cc[0]*2+$dx)] = 3 } }
    }
    foreach($cc in @(@(4,3),@(25,11),@(11,12))){
        foreach($dy in 0,1){ foreach($dx in 0,1){ $wm[((($cc[1]*2+$dy)) -shl 6) + ($cc[0]*2+$dx)] = 2 } }
    }
    # Variant 3: damp / mossy patch low on the wall.
    $wm = $wallMaps[3]
    foreach($cc in @(@(9,12),@(10,12),@(11,12),@(8,13),@(9,13),@(10,13),@(11,13),@(12,13),@(9,14),@(10,14),@(11,14),@(12,14),@(13,14),@(10,15),@(11,15),@(12,15))){
        foreach($dy in 0,1){ foreach($dx in 0,1){ $wm[((($cc[1]*2+$dy)) -shl 6) + ($cc[0]*2+$dx)] = 3 } }
    }
    # Torch glow row factors: the old per-pixel 1-|y-horizon|/horizon.
    $glowRow = New-Object "double[]" $vh
    for($y=0; $y -lt $vh; $y++){ $glowRow[$y] = 1.0 - ([math]::Abs($y - $horizon) / $horizon) }
    # Per-row shade bases (v1.6.2): floor/ceiling distances are
    # per-ROW constants, so the [int](dist * k) the old loop paid
    # per PIXEL is baked here. Round-to-nearest, matching the
    # pre-1.6.2 look — dithering was tried and rolled back (too
    # noisy at half-block pixel scale; see handoff, do not re-add).
    $ceilSh = New-Object "int[]" $horizon
    # v1.6.2 clarity pass: gentler falloff (was 1.2 / 1.4) — the 15-
    # step ladders stretch deeper before crushing to the dark tail.
    for($y=0; $y -lt $horizon; $y++){ $ceilSh[$y] = [int]($ceilT[$y] * 1.05) }
    $floorSh = New-Object "int[]" $vh
    for($y=$horizon; $y -lt $vh; $y++){ $floorSh[$y] = [int]($floorT[$y] * 1.25) }
    # Per-row floor distance DELTAS (grout AA — mirrors CeilD).
    $floorD = New-Object "double[]" $vh
    for($y=$horizon+1; $y -lt $vh; $y++){ $floorD[$y] = $floorT[$y-1] - $floorT[$y] }
    if($vh -gt ($horizon+1)){ $floorD[$horizon] = $floorD[$horizon+1] }
    # v1.6.2: truecolor upgrade path — probed, never forced. Where
    # the terminal advertises 24-bit SGR, the 256-index ladders are
    # translated to exact RGB at emission (one LUT read per color
    # CHANGE, and changes are run-length limited). Legacy conhost
    # keeps the plain 256-color path untouched.
    $script:UseTrueColor = $false
    try {
        if($env:WT_SESSION -or ([string]$env:COLORTERM -match '24bit|truecolor')){ $script:UseTrueColor = $true }
    } catch {}
    $tcLut = @{}
    if($script:UseTrueColor){
        $std = @('0;0;0','128;0;0','0;128;0','128;128;0','0;0;128','128;0;128','0;128;128','192;192;192','128;128;128','255;0;0','0;255;0','255;255;0','0;0;255','255;0;255','0;255;255','255;255;255')
        for($ci=0; $ci -lt 16; $ci++){ $tcLut[[string]$ci] = $std[$ci] }
        $lvl = @(0,95,135,175,215,255)
        for($ci=16; $ci -lt 232; $ci++){
            $cq = $ci - 16
            $tcLut[[string]$ci] = "$($lvl[[int][math]::Floor($cq/36)]);$($lvl[[int][math]::Floor($cq/6) % 6]);$($lvl[$cq % 6])"
        }
        for($ci=232; $ci -lt 256; $ci++){
            $gv = 8 + 10 * ($ci - 232)
            $tcLut[[string]$ci] = "$gv;$gv;$gv"
        }
    }
    $angOff = New-Object "double[]" $sw
    $cosOff = New-Object "double[]" $sw
    $sinOff = New-Object "double[]" $sw
    for($col=0; $col -lt $sw; $col++){
        $a = ($col / $sw - 0.5) * $fov
        $angOff[$col] = $a
        $cosOff[$col] = [math]::Cos($a)
        $sinOff[$col] = [math]::Sin($a)
    }
    $script:RayEngine = @{
        SW=$sw; SH=$sh; VH=$vh; Horizon=$horizon; Fov=$fov; TcLut=$tcLut
        CeilT=$ceilT; CeilD=$ceilD; FloorT=$floorT; AngOff=$angOff; CosOff=$cosOff; SinOff=$sinOff
        WallMaps=$wallMaps; GlowRow=$glowRow
        CeilSh=$ceilSh; FloorSh=$floorSh; FloorD=$floorD
        Fg = New-Object "string[]" ($sw * $sh)
        Bg = New-Object "string[]" ($sw * $sh)
        Z  = New-Object "double[]" $sw
        Buf = New-Object System.Text.StringBuilder(65536)
        Resized = $false
    }
    return $script:RayEngine
}

# ── THE LEG ──────────────────────────────────────────────────────
# Runs the real-time raycast loop until something the CLASSIC loop
# must handle occurs, then returns an action token:
#   @{Kind="Walk"}          — one full tile of travel accumulated
#                             (heat / room fx / encounter rolls fire
#                             through the synthesized W step)
#   @{Kind="Step";X=;Y=}    — proximity trigger (enemy, exit) or [E]
#                             interact (chest, survivor, altar, lore,
#                             boss door) — target tile for the W case
#   @{Kind="Key";Key="P"}   — menu keys P/I/J/M/Q (ESC maps to Q)
function Invoke-RaycastLeg {
    $eng = Init-RayEngine
    $rs  = Build-RayState
    $d   = $script:Dungeon
    $tex = Get-RayTexTable
    $pal = $rs.Palette
    $ladHi = $pal.BrickHi;  $nHi = $ladHi.Count
    $ladBk = $pal.Brick;    $nBk = $ladBk.Count
    $ladDm = $pal.BrickDim; $nDm = $ladDm.Count
    $ladMo = $pal.Mortar;   $nMo = $ladMo.Count
    $ladFA = $pal.FloorA;   $nFA = $ladFA.Count
    $ladFB = $pal.FloorB;   $nFB = $ladFB.Count
    $ladBe = $pal.Beam;     $nBe = $ladBe.Count
    # v1.6.2 decal ladders (zone-independent): dried blood + banner.
    $ladBlood = @(124,88,88,52,52,52,235,235,234,234,233,233,232,232,232)
    $ladBann  = @(172,130,130,94,94,58,58,236,235,234,233,233,232,232,232)
    $sw = $eng.SW; $sh = $eng.SH; $vh = $eng.VH; $horizon = $eng.Horizon
    $tcLut = $eng.TcLut
    $fgF = $eng.Fg; $bgF = $eng.Bg; $zB = $eng.Z
    $buffer = $eng.Buf
    $esc = [char]0x1b
    $mapW = $rs.W; $mapH = $rs.H; $map = $rs.Map
    $ceilD = $eng.CeilD
    # v1.6.2 hot-loop hoists: every $eng.X[y] below was a hashtable
    # lookup per PIXEL — locals are measurably cheaper in PS 5.1.
    $ceilT = $eng.CeilT; $floorT = $eng.FloorT
    $cosOffArr = $eng.CosOff; $sinOffArr = $eng.SinOff
    $wallMaps = $eng.WallMaps; $glowRow = $eng.GlowRow
    $ceilSh = $eng.CeilSh; $floorSh = $eng.FloorSh; $floorD = $eng.FloorD
    # Boss-room wall ring (v1.6.2): torches mounted on any wall of
    # the boss room burn COLD BLUE — a landmark you can read from
    # across the floor. The ring rect is the room grown by 1 (its
    # walls); rooms never move, so once per leg entry is enough.
    $btX0 = -99; $btY0 = -99; $btX1 = -99; $btY1 = -99
    if($d.Rooms -and $d.Rooms.Count -gt 0){
        $bossRm = $d.Rooms[$d.Rooms.Count - 1]
        $btX0 = [int]$bossRm.X - 1
        $btY0 = [int]$bossRm.Y - 1
        $btX1 = [int]$bossRm.X + [int]$bossRm.W
        $btY1 = [int]$bossRm.Y + [int]$bossRm.H
    }

    # Console prep: hide cursor, one-time gentle window grow (30 rows of
    # frame+HUD need ~33; width 100 needs ~102). All guarded, all safe.
    $hasConsole = $false
    try { if([Console]::WindowHeight -gt 0){ $hasConsole = $true } } catch {}
    $cursorWas = $true
    if($hasConsole){
        try { $cursorWas = [Console]::CursorVisible; [Console]::CursorVisible = $false } catch {}
        if(-not $eng.Resized){
            $eng.Resized = $true
            try {
                if($env:OS -eq "Windows_NT"){
                    if([Console]::BufferWidth -lt 102){ [Console]::BufferWidth = 102 }
                    if([Console]::BufferHeight -lt 33){ [Console]::BufferHeight = 33 }
                    if([Console]::WindowWidth -lt 102 -or [Console]::WindowHeight -lt 33){
                        [Console]::SetWindowSize(120, 33)
                    }
                }
            } catch {}
        }
    }
    $canUseConsole = $false
    try { if(-not [Console]::IsInputRedirected){ $canUseConsole = $true } } catch {}

    # Small helper closures are too slow at frame rate — everything hot
    # stays inline below (a deliberate donor-faithful choice).
    $moveStep = 0.2133
    $rotStep  = 0.1257
    # Turn speed (v1.6): Options preset 50-150%, save-persisted.
    $rotPct = 100
    try { if($script:Settings.RotSpeed){ $rotPct = [int]$script:Settings.RotSpeed } } catch {}
    if($rotPct -lt 25 -or $rotPct -gt 300){ $rotPct = 100 }
    $rotStep = $rotStep * ($rotPct / 100.0)
    $clock = [System.Diagnostics.Stopwatch]::StartNew()
    $lastTime = $clock.ElapsedMilliseconds
    $fps = 0
    $mapChanged = $true   # force first frame
    # Status-line expiry (v1.6.2): the classic loop clears a status
    # after ONE draw; this loop redraws every frame and used to pin
    # messages ("the lock is disturbed...") forever. Track when a
    # given message first appeared and drop it after ~6 seconds.
    $statusShownMsg = ""
    $statusShownAt = 0

    # Only wipe the screen when a classic UI owned it (Step/Key returns
    # arm NeedClear; Walk returns disarm it so tile-to-tile travel never
    # flickers through a full clear).
    if($rs.NeedClear){ try { Clear-Host } catch {} }
    $rs.NeedClear = $true
    while($true){
        $currentTime = $clock.ElapsedMilliseconds
        $elapsed = $currentTime - $lastTime
        if($elapsed -lt 100){
            Start-Sleep -Milliseconds 5
            continue
        }
        $lastTime = $currentTime
        if($elapsed -gt 0){ $fps = [int](1000 / $elapsed) }
        $flicker = 1.0 + [math]::Sin($currentTime / 180.0) * 0.08 + ((Get-Random -Min 0 -Max 100) / 1000.0 - 0.05)

        # Door animation tick (boss doors) with the donor's anti-stuck.
        foreach($key in @($rs.Doors.Keys)){
            $door = $rs.Doors[$key]
            if($door.State -eq "Opening"){
                $door.Ratio += 0.2
                if($door.Ratio -ge 1.0){ $door.Ratio = 1.0; $door.State = "Open" }
            } elseif($door.State -eq "Closing"){
                $coords = $key -split ","
                $ddx = [int]$coords[0] + 0.5 - $rs.Px
                $ddy = [int]$coords[1] + 0.5 - $rs.Py
                if([math]::Sqrt($ddx*$ddx + $ddy*$ddy) -lt 0.7){
                    $door.State = "Opening"
                } else {
                    $door.Ratio -= 0.2
                    if($door.Ratio -le 0.0){ $door.Ratio = 0.0; $door.State = "Closed" }
                }
            } elseif($door.State -eq "Open"){
                # Fully open but the grid still says door: hand the
                # classic loop a Step so IT commits the open (grid->0)
                # and runs any credits (boss-room entry). Self-healing:
                # survives Walk tokens interleaving mid-animation.
                $coords = $key -split ","
                $dox = [int]$coords[0]; $doy = [int]$coords[1]
                $dgv = $d.Grid[$doy,$dox]
                if($dgv -eq 10 -or $dgv -eq 4){
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Step"; X=$dox; Y=$doy }
                }
            }
        }

        # Facing interactable (chest / survivor / altar / lore / boss door):
        # the tile ~0.9 units ahead of the nose.
        $cosPA = [math]::Cos($rs.Pa); $sinPA = [math]::Sin($rs.Pa)
        $faceX = [int][math]::Floor($rs.Px + $cosPA * 0.9)
        $faceY = [int][math]::Floor($rs.Py + $sinPA * 0.9)
        $faceKey = "$faceX,$faceY"
        $canInteract = $rs.Inter.ContainsKey($faceKey)
        if($canInteract){
            # LOS (v1.6): no more phantom [E]s through corners — march
            # 0.15-unit samples toward the target tile's center and
            # drop the prompt if a wall / closed door sits in between.
            $ldx = ($faceX + 0.5) - $rs.Px; $ldy = ($faceY + 0.5) - $rs.Py
            $llen = [math]::Sqrt($ldx*$ldx + $ldy*$ldy)
            if($llen -gt 0.05){
                $ldx = $ldx / $llen; $ldy = $ldy / $llen
                $lt = 0.0
                while($lt -lt $llen){
                    $lt += 0.15
                    if($lt -ge $llen){ break }
                    $lcx = [int][math]::Floor($rs.Px + $ldx * $lt)
                    $lcy = [int][math]::Floor($rs.Py + $ldy * $lt)
                    if($lcx -eq $faceX -and $lcy -eq $faceY){ break }
                    if($lcx -lt 0 -or $lcx -ge $mapW -or $lcy -lt 0 -or $lcy -ge $mapH){ $canInteract = $false; break }
                    $lcv = $map[$lcy * $mapW + $lcx]
                    if($lcv -eq 1){ $canInteract = $false; break }
                    if($lcv -eq 2){
                        $ldk = "$lcx,$lcy"
                        $lrr = 0.0
                        if($rs.Doors.ContainsKey($ldk)){ $lrr = $rs.Doors[$ldk].Ratio }
                        if($lrr -lt 0.8){ $canInteract = $false; break }
                    }
                }
            }
        }

        # Input: one action per frame, buffer drained after (donor).
        $keyAvailable = $false
        if($canUseConsole){
            try { if([Console]::KeyAvailable){ $keyAvailable = $true } } catch { $canUseConsole = $false }
        }
        if(-not $keyAvailable){
            try { if($Host.UI.RawUI.KeyAvailable){ $keyAvailable = $true } } catch {}
        }
        if($keyAvailable){
            $keyChar = ""
            if($canUseConsole){
                try { $keyChar = [Console]::ReadKey($true).Key.ToString() } catch {}
            } else {
                # Release-proof read (v1.6.2): KeyAvailable counted the
                # key-UP too, and a down-only ReadKey would BLOCK on it
                # — stalling the render loop on every key release on
                # RawUI-only hosts. Skip ups, take the first down.
                try {
                    while($Host.UI.RawUI.KeyAvailable){
                        $rkk = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown,IncludeKeyUp")
                        if($rkk.KeyDown){
                            $rawKey = $rkk.VirtualKeyCode
                            $keyChar = switch($rawKey){
                                38 { "W" } 40 { "S" } 37 { "A" } 39 { "D" } 27 { "Escape" }
                                default { [string][char]$rawKey }
                            }
                            break
                        }
                    }
                } catch {}
            }
            # Arrow keys arrive as names from ReadKey too
            switch($keyChar){
                "UpArrow"    { $keyChar = "W" }
                "DownArrow"  { $keyChar = "S" }
                "LeftArrow"  { $keyChar = "A" }
                "RightArrow" { $keyChar = "D" }
            }
            $moved = $false
            $oldPx = $rs.Px; $oldPy = $rs.Py
            switch($keyChar){
                "W" {
                    if(Test-Encumbered){
                        $cur = Get-CurrentCarryWeight
                        $max = Get-MaxCarryWeight $script:Player
                        $script:StatusMsg = "OVER ENCUMBERED ($cur/$max) — open inventory [I] and drop items"
                    } else {
                        $nx = $rs.Px + $cosPA * $moveStep
                        $ny = $rs.Py + $sinPA * $moveStep
                        $radius = 0.25
                        $oX = $radius; if($nx -le $rs.Px){ $oX = -$radius }
                        $oY = $radius; if($ny -le $rs.Py){ $oY = -$radius }
                        $icx = [int][math]::Floor($nx + $oX)
                        $ipy = [int][math]::Floor($rs.Py)
                        $icy = [int][math]::Floor($ny + $oY)
                        $ipx = [int][math]::Floor($rs.Px)
                        if(Test-RayWalkable $rs $icx $ipy){ $rs.Px = $nx }
                        if(Test-RayWalkable $rs $ipx $icy){ $rs.Py = $ny }
                        $moved = $true
                    }
                }
                "S" {
                    if(Test-Encumbered){
                        $cur = Get-CurrentCarryWeight
                        $max = Get-MaxCarryWeight $script:Player
                        $script:StatusMsg = "OVER ENCUMBERED ($cur/$max) — open inventory [I] and drop items"
                    } else {
                        $nx = $rs.Px - $cosPA * $moveStep
                        $ny = $rs.Py - $sinPA * $moveStep
                        $radius = 0.25
                        $oX = -$radius; if($nx -le $rs.Px){ $oX = $radius }
                        $oY = -$radius; if($ny -le $rs.Py){ $oY = $radius }
                        $icx = [int][math]::Floor($nx + $oX)
                        $ipy = [int][math]::Floor($rs.Py)
                        $icy = [int][math]::Floor($ny + $oY)
                        $ipx = [int][math]::Floor($rs.Px)
                        if(Test-RayWalkable $rs $icx $ipy){ $rs.Px = $nx }
                        if(Test-RayWalkable $rs $ipx $icy){ $rs.Py = $ny }
                        $moved = $true
                    }
                }
                "A" {
                    $rs.Pa -= $rotStep
                    if($rs.Pa -lt 0){ $rs.Pa += [math]::PI * 2 }
                }
                "D" {
                    $rs.Pa += $rotStep
                    if($rs.Pa -gt [math]::PI * 2){ $rs.Pa -= [math]::PI * 2 }
                }
                "E" {
                    if($canInteract){
                        if($rs.Doors.ContainsKey($faceKey)){
                            # Doors: slide open in-engine first. The Step
                            # is sent by the door tick once fully open.
                            $door = $rs.Doors[$faceKey]
                            if($door.Boss -and -not $script:HasBossKey){
                                # Locked: let the classic loop explain.
                                try { [Console]::CursorVisible = $cursorWas } catch {}
                                Write-Host "$esc[0m" -NoNewline
                                return @{ Kind="Step"; X=$faceX; Y=$faceY }
                            }
                            if($door.State -eq "Closed"){ $door.State = "Opening" }
                        } else {
                            $rs.Suppress = $faceKey
                            try { [Console]::CursorVisible = $cursorWas } catch {}
                            Write-Host "$esc[0m" -NoNewline
                            return @{ Kind="Step"; X=$faceX; Y=$faceY }
                        }
                    }
                }
                "M" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="M" }
                }
                "O" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="O" }
                }
                "P" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="P" }
                }
                "I" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="I" }
                }
                "J" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="J" }
                }
                "Q" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="Q" }
                }
                "Escape" {
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Key"; Key="Q" }
                }
            }
            # Drain buffered input so auto-repeat can't spin the camera.
            if($canUseConsole){
                while($true){
                    $avail = $false
                    try { if([Console]::KeyAvailable){ $avail = $true } } catch {}
                    if(-not $avail){ break }
                    try { [Console]::ReadKey($true) | Out-Null } catch {}
                }
            } else {
                while($true){
                    $avail = $false
                    try { if($Host.UI.RawUI.KeyAvailable){ $avail = $true } } catch {}
                    if(-not $avail){ break }
                    try { [void]$Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown,IncludeKeyUp") } catch {}
                }
            }

            if($moved){
                $mdx = $rs.Px - $oldPx; $mdy = $rs.Py - $oldPy
                $rs.DistAcc += [math]::Sqrt($mdx*$mdx + $mdy*$mdy)
                # Keep the dungeon's integer position, facing and fog in
                # sync with the float — minimap, quests and room effects
                # all read PX/PY.
                $ntx = [int][math]::Floor($rs.Px)
                $nty = [int][math]::Floor($rs.Py)
                if($ntx -ne $d.PX -or $nty -ne $d.PY){
                    $d.PX = $ntx; $d.PY = $nty
                    Update-RayFog $d
                    $mapChanged = $true
                }
                $absC = [math]::Abs($cosPA); $absS = [math]::Abs($sinPA)
                if($absC -gt $absS){
                    $d.PDir = if($cosPA -gt 0){1}else{3}
                } else {
                    $d.PDir = if($sinPA -gt 0){2}else{0}
                }
                if($rs.DistAcc -ge 1.0){
                    $rs.DistAcc -= 1.0
                    $rs.NeedClear = $false
                    try { [Console]::CursorVisible = $cursorWas } catch {}
                    Write-Host "$esc[0m" -NoNewline
                    return @{ Kind="Walk" }
                }
            }
        }

        # Suppression: after a Step fires, the same tile stays quiet until
        # the player backs off past 0.9 — stops the exit prompt (or a fled
        # fight) from instantly re-triggering while you stand on top of it.
        if($rs.Suppress){
            $sp = $rs.Suppress -split ","
            $sdx = [int]$sp[0] + 0.5 - $rs.Px
            $sdy = [int]$sp[1] + 0.5 - $rs.Py
            if([math]::Sqrt($sdx*$sdx + $sdy*$sdy) -gt 0.9){ $rs.Suppress = "" }
        }
        foreach($tr in $rs.Triggers){
            $tk = "$($tr.X),$($tr.Y)"
            if($tk -eq $rs.Suppress){ continue }
            $tdx = $tr.X + 0.5 - $rs.Px
            $tdy = $tr.Y + 0.5 - $rs.Py
            if([math]::Sqrt($tdx*$tdx + $tdy*$tdy) -le $tr.R){
                $rs.Suppress = $tk
                try { [Console]::CursorVisible = $cursorWas } catch {}
                Write-Host "$esc[0m" -NoNewline
                return @{ Kind="Step"; X=$tr.X; Y=$tr.Y }
            }
        }

        # Sprite depths + painter's sort (donor's manual insertion sort).
        foreach($s in $rs.Sprites){
            $s.Dist = [math]::Sqrt(($s.X - $rs.Px)*($s.X - $rs.Px) + ($s.Y - $rs.Py)*($s.Y - $rs.Py))
        }
        for($i=1; $i -lt $rs.Sprites.Count; $i++){
            $skey = $rs.Sprites[$i]
            $j = $i - 1
            while($j -ge 0 -and $rs.Sprites[$j].Dist -lt $skey.Dist){
                $rs.Sprites[$j + 1] = $rs.Sprites[$j]
                $j = $j - 1
            }
            $rs.Sprites[$j + 1] = $skey
        }

        # ── RENDER ──
        $buffer.Clear() | Out-Null
        if($hasConsole){
            try { [Console]::SetCursorPosition(0, 0) } catch { [void]$buffer.Append("$esc[H") }
        } else {
            [void]$buffer.Append("$esc[H")
        }
        $px = $rs.Px; $py = $rs.Py
        $sinP = [math]::Sin($rs.Pa); $cosP = [math]::Cos($rs.Pa)
        # Beam AA (v1.6.2): world-Y span per screen COLUMN is
        # ceilDist * |cosP| * (fov/sw) / cos^2(colAngle).
        $fpColBase = 0.010472 * [math]::Abs($cosP)
        $fpColBaseX = 0.010472 * [math]::Abs($sinP)

        for($col=0; $col -lt $sw; $col++){
            $cosO = $cosOffArr[$col]; $sinO = $sinOffArr[$col]
            $sinA = $sinP * $cosO + $cosP * $sinO
            $cosA = $cosP * $cosO - $sinP * $sinO
            # Beam AA (v1.6.2): row/column footprint factors for the
            # ceiling — world-Y per screen row is ceilD[y]*|sinA|/cosO.
            $fpRowF = [math]::Abs($sinA) / $cosO
            $fpColF = $fpColBase / ($cosO * $cosO)
            $fpRowFX = [math]::Abs($cosA) / $cosO
            $fpColFX = $fpColBaseX / ($cosO * $cosO)
            $deltaDistX = 1e30; if($cosA -ne 0){ $deltaDistX = [math]::Abs(1 / $cosA) }
            $deltaDistY = 1e30; if($sinA -ne 0){ $deltaDistY = [math]::Abs(1 / $sinA) }
            $mX = [int][math]::Floor($px); $mY = [int][math]::Floor($py)
            if($cosA -lt 0){ $stepX = -1; $sideDistX = ($px - $mX) * $deltaDistX }
            else { $stepX = 1; $sideDistX = (($mX + 1.0) - $px) * $deltaDistX }
            if($sinA -lt 0){ $stepY = -1; $sideDistY = ($py - $mY) * $deltaDistY }
            else { $stepY = 1; $sideDistY = (($mY + 1.0) - $py) * $deltaDistY }
            $hit = $false; $side = 0; $maxDepth = 24.0; $dist = 0.0; $hitType = 0; $hitBoss = $false
            while(-not $hit){
                if($sideDistX -lt $sideDistY){ $sideDistX += $deltaDistX; $mX += $stepX; $side = 0 }
                else { $sideDistY += $deltaDistY; $mY += $stepY; $side = 1 }
                if($mX -lt 0 -or $mX -ge $mapW -or $mY -lt 0 -or $mY -ge $mapH){ $dist = $maxDepth; break }
                $cellVal = $map[$mY * $mapW + $mX]
                if($cellVal -eq 1 -or $cellVal -eq 2){
                    if($cellVal -eq 2){
                        $doorKey = "$mX,$mY"
                        $ratio = 0.0
                        if($rs.Doors.ContainsKey($doorKey)){ $ratio = $rs.Doors[$doorKey].Ratio }
                        if($ratio -lt 1.0){
                            if($side -eq 0){ $wallX = $py + ($sideDistX - $deltaDistX) * $sinA }
                            else { $wallX = $px + ($sideDistY - $deltaDistY) * $cosA }
                            $wallX = $wallX % 1.0
                            if($wallX -ge $ratio){
                                $hit = $true; $hitType = 2
                                if($rs.Doors.ContainsKey($doorKey) -and $rs.Doors[$doorKey].Boss){ $hitBoss = $true }
                                if($side -eq 0){ $dist = $sideDistX - $deltaDistX } else { $dist = $sideDistY - $deltaDistY }
                            }
                        }
                    } else {
                        $hit = $true; $hitType = 1
                        if($side -eq 0){ $dist = $sideDistX - $deltaDistX } else { $dist = $sideDistY - $deltaDistY }
                    }
                }
            }
            $dist *= $cosO
            if($dist -lt 0.1){ $dist = 0.1 }
            $zB[$col] = $dist
            $wallHeight = [int]($vh / $dist)
            # v1.6.2: head-bob — walls dip one half-pixel as position
            # streams by. Stateless (derived from px/py), walls only.
            $bobPix = ([int](($px + $py) * 4)) -band 1
            $wallStart = [int](($vh - $wallHeight) / 2) + $bobPix
            $wallEnd = $wallStart + $wallHeight
            if($wallStart -lt 0){ $wallStart = 0 }
            if($wallEnd -ge $vh){ $wallEnd = $vh - 1 }
            if($side -eq 0){ $wallX = $py + $dist * $sinA } else { $wallX = $px + $dist * $cosA }
            $wallX = $wallX % 1.0
            $texX = [int]($wallX * 64)
            if($texX -lt 0){ $texX = 0 }
            if($texX -gt 63){ $texX = 63 }
            $hasTorch = ((($mX + $mY) % 2 -eq 0) -and $hitType -eq 1)
            $bossTorch = ($hasTorch -and $mX -ge $btX0 -and $mX -le $btX1 -and $mY -ge $btY0 -and $mY -le $btY1)
            # ── v1.6.2: per-COLUMN hoists (everything here used to be
            # recomputed per PIXEL) and the y loop split into ceiling /
            # wall / floor segments — each pixel skips the two range
            # tests and every branch it can never take. frameIdx and
            # the half-block toggle carry straight through because the
            # three segments are contiguous. Writes are unguarded on
            # purpose: y in [0,vh) makes frameIdx provably in-bounds.
            $whv = ($wallEnd - $wallStart)
            if($whv -le 0){ $whv = 1 }
            $texYF = 32.0 / $whv
            $sdv = $dist
            if($hitType -eq 2){ $sdv = $dist * 1.3 }
            $shadeBase = [int]$sdv
            $glowCol = 0.0
            if($hasTorch){ $glowCol = 5.0 * $flicker / [math]::Sqrt($dist) }
            $wvH = ($mX * 7 + $mY * 13)
            $wvSel = $wvH -band 3
            if(($wvH % 19) -eq 0){ $wvSel = 4 }
            elseif(($wvH % 31) -eq 7){ $wvSel = 5 }
            $wtm = $wallMaps[$wvSel]
            $frameIdx = $col
            $isBottomHalf = $false

            # ── CEILING: rows 0..wallStart-1 (always above horizon) ──
            for($y=0; $y -lt $wallStart; $y++){
                $pixelColor = 232
                $ceilDist = $ceilT[$y]
                $realCeilDist = $ceilDist / $cosO
                # Coffered beam grid (v1.6.2): rafters along world-Y AND
                # cross-beams along world-X, both footprint-widened so
                # distant/oblique beams stay SOLID instead of tearing
                # into dashes. Positive modulo — PS % keeps sign, and
                # negative coords past the map edge used to paint the
                # whole void as beam. Shade math only runs on hits.
                $bm = ($py + $realCeilDist * $sinA) % 1.5
                if($bm -lt 0){ $bm += 1.5 }
                $bd = $bm - 0.02
                if($bd -lt 0){ $bd = -$bd }
                if($bd -gt 0.75){ $bd = 1.5 - $bd }
                $bHit = $false
                if($bd -lt 0.4){
                    $fp = $fpRowF * $ceilD[$y]
                    $fpc = $fpColF * $ceilDist
                    if($fpc -gt $fp){ $fp = $fpc }
                    $bhw = 0.02 + 0.5 * $fp
                    if($bhw -gt 0.4){ $bhw = 0.4 }
                    if($bd -lt $bhw){ $bHit = $true }
                }
                if(-not $bHit){
                    $bm = ($px + $realCeilDist * $cosA) % 1.5
                    if($bm -lt 0){ $bm += 1.5 }
                    $bd = $bm - 0.02
                    if($bd -lt 0){ $bd = -$bd }
                    if($bd -gt 0.75){ $bd = 1.5 - $bd }
                    if($bd -lt 0.4){
                        $fp = $fpRowFX * $ceilD[$y]
                        $fpc = $fpColFX * $ceilDist
                        if($fpc -gt $fp){ $fp = $fpc }
                        $bhw = 0.02 + 0.5 * $fp
                        if($bhw -gt 0.4){ $bhw = 0.4 }
                        if($bd -lt $bhw){ $bHit = $true }
                    }
                }
                if($bHit){
                    $cShade = $ceilSh[$y]
                    if($hasTorch){
                        $cShade = $cShade - [int](3.0 * $flicker / ($realCeilDist + 0.5))
                        if($cShade -lt 0){ $cShade = 0 }
                    }
                    if($cShade -ge $nBe){ $cShade = $nBe - 1 }
                    $pixelColor = $ladBe[$cShade]
                }
                if($isBottomHalf){ $bgF[$frameIdx] = [string]$pixelColor; $frameIdx += $sw }
                else { $fgF[$frameIdx] = [string]$pixelColor }
                $isBottomHalf = -not $isBottomHalf
            }

            # ── WALL: rows wallStart..wallEnd ──
            for($y=$wallStart; $y -le $wallEnd; $y++){
                $texY = [int](($y - $wallStart) * $texYF)
                if($texY -gt 31){ $texY = 31 }
                if($hitType -eq 2){
                    # v1.6.2: door constants live in 64x32 texture
                    # space (scaled from the old 32x16 — unscaled,
                    # the door squashed into its top half).
                    if($texX -lt 16 -or $texX -ge 48){
                        # Stone flanks reuse the wall pattern map:
                        # mortar cell -> mortar ladder, anything else
                        # -> brick (matches the old two-tone flank).
                        $si = $shadeBase
                        if($wtm[($texY -shl 6) + $texX] -eq 1){
                            if($si -ge $nMo){ $si = $nMo - 1 }
                            $pixelColor = $ladMo[$si]
                        } else {
                            if($si -ge $nBk){ $si = $nBk - 1 }
                            $pixelColor = $ladBk[$si]
                        }
                    } else {
                        # Door panel: brown wood — or deep RED for the
                        # boss door (v1.6). Handle glint stays gold.
                        $dcFrame = 237; $dcLine = 233; $dcWood = 130
                        if($hitBoss){ $dcFrame = 124; $dcLine = 52; $dcWood = 88 }
                        if($texY -le 3 -or $texY -ge 28){ $pixelColor = $dcFrame }
                        elseif($texX -le 17 -or ($texX -ge 31 -and $texX -le 32) -or $texX -ge 46){ $pixelColor = $dcLine }
                        elseif($texX -ge 28 -and $texX -le 35 -and $texY -ge 14 -and $texY -le 19){
                            if($texY -ge 16 -and $texY -le 17 -and $texX -ge 30 -and $texX -le 33){ $pixelColor = $dcLine } else { $pixelColor = 220 }
                        } else { $pixelColor = $dcWood }
                    }
                } elseif($hasTorch -and $texX -ge 14 -and $texX -le 17 -and $texY -ge 3 -and $texY -le 7){
                    # Torch: animated flame row, ember row, then the
                    # sconce. Normal torches burn orange in wooden
                    # sconces (v1.6.2); boss-room torches burn COLD
                    # BLUE in the original grey iron holders — the
                    # room announces itself.
                    if($texY -eq 3){
                        $frame = [math]::Floor($currentTime / 150) % 3
                        if($bossTorch){
                            if($frame -eq 0){ $pixelColor = 51 }
                            elseif($frame -eq 1){ $pixelColor = 45 }
                            else { $pixelColor = 39 }
                        }
                        elseif($frame -eq 0){ $pixelColor = 226 }
                        elseif($frame -eq 1){ $pixelColor = 208 }
                        else { $pixelColor = 196 }
                    } elseif($texY -eq 4){ $pixelColor = if($bossTorch){ 33 } else { 202 } }
                    elseif($texY -le 6){ $pixelColor = if($bossTorch){ 238 } else { 130 } }
                    else { $pixelColor = if($bossTorch){ 238 } else { 94 } }
                } else {
                    $si = $shadeBase
                    if($hasTorch){
                        $si = $si - [int]($glowCol * $glowRow[$y])
                        if($si -lt 0){ $si = 0 }
                    }
                    # Side-1 walls read darker: same ladders, +2 shade.
                    if($side -eq 1){ $si = $si + 2 }
                    $wt = $wtm[($texY -shl 6) + $texX]
                    if($wt -eq 0){
                        if($si -ge $nBk){ $si = $nBk - 1 }
                        $pixelColor = $ladBk[$si]
                    } elseif($wt -eq 1){
                        if($si -ge $nMo){ $si = $nMo - 1 }
                        $pixelColor = $ladMo[$si]
                    } elseif($wt -eq 2){
                        if($si -ge $nHi){ $si = $nHi - 1 }
                        $pixelColor = $ladHi[$si]
                    } elseif($wt -eq 4){
                        if($si -ge 15){ $si = 14 }
                        $pixelColor = $ladBlood[$si]
                    } elseif($wt -eq 5){
                        if($si -ge 15){ $si = 14 }
                        $pixelColor = $ladBann[$si]
                    } else {
                        if($si -ge $nDm){ $si = $nDm - 1 }
                        $pixelColor = $ladDm[$si]
                    }
                }
                if($isBottomHalf){ $bgF[$frameIdx] = [string]$pixelColor; $frameIdx += $sw }
                else { $fgF[$frameIdx] = [string]$pixelColor }
                $isBottomHalf = -not $isBottomHalf
            }

            # ── FLOOR: rows wallEnd+1..vh-1 (at/below horizon) ──
            for($y=$wallEnd+1; $y -lt $vh; $y++){
                $floorDist = $floorT[$y]
                $realFloorDist = $floorDist / $cosO
                $floorX = $px + $realFloorDist * $cosA
                $floorY = $py + $realFloorDist * $sinA
                # Grout AA (v1.6.2): same footprint widening the beams
                # got — distance to the nearest integer grid line,
                # band widened by this pixel's world footprint, capped
                # so the far floor darkens smoothly instead of going
                # all-grout (the ladders hit black first anyway).
                # Tile centers (gd >= 0.35) skip the footprint math.
                $fxr = $floorX % 1.0
                if($fxr -lt 0){ $fxr += 1.0 }
                $fyr = $floorY % 1.0
                if($fyr -lt 0){ $fyr += 1.0 }
                $gdx = $fxr; if($gdx -gt 0.5){ $gdx = 1.0 - $gdx }
                $gdy = $fyr; if($gdy -gt 0.5){ $gdy = 1.0 - $gdy }
                $isGrout = $false
                if($gdx -lt 0.35){
                    $fp = $fpRowFX * $floorD[$y]
                    $fpc = $fpColFX * $floorDist
                    if($fpc -gt $fp){ $fp = $fpc }
                    $ghw = 0.06 + 0.5 * $fp
                    if($ghw -gt 0.35){ $ghw = 0.35 }
                    if($gdx -lt $ghw){ $isGrout = $true }
                }
                if(-not $isGrout -and $gdy -lt 0.35){
                    $fp = $fpRowF * $floorD[$y]
                    $fpc = $fpColF * $floorDist
                    if($fpc -gt $fp){ $fp = $fpc }
                    $ghw = 0.06 + 0.5 * $fp
                    if($ghw -gt 0.35){ $ghw = 0.35 }
                    if($gdy -lt $ghw){ $isGrout = $true }
                }
                if($isGrout){
                    $pixelColor = 232
                } else {
                    $fShade = $floorSh[$y]
                    if($hasTorch){
                        $fShade = $fShade - [int](3.0 * $flicker / ($realFloorDist + 0.5))
                        if($fShade -lt 0){ $fShade = 0 }
                    }
                    if((([int][math]::Floor($floorX) + [int][math]::Floor($floorY)) % 2) -eq 0){
                        if($fShade -ge $nFA){ $fShade = $nFA - 1 }
                        $pixelColor = $ladFA[$fShade]
                    } else {
                        if($fShade -ge $nFB){ $fShade = $nFB - 1 }
                        $pixelColor = $ladFB[$fShade]
                    }
                }
                if($isBottomHalf){ $bgF[$frameIdx] = [string]$pixelColor; $frameIdx += $sw }
                else { $fgF[$frameIdx] = [string]$pixelColor }
                $isBottomHalf = -not $isBottomHalf
            }
        }

        # Sprites (donor renderer, per-type textures, z-tested per stripe).
        foreach($s in $rs.Sprites){
            $spriteX = $s.X - $px
            $spriteY = $s.Y - $py
            $spriteAngle = [math]::Atan2($spriteY, $spriteX) - $rs.Pa
            while($spriteAngle -lt -[math]::PI){ $spriteAngle += [math]::PI * 2 }
            while($spriteAngle -gt [math]::PI){ $spriteAngle -= [math]::PI * 2 }
            $sDist = $s.Dist
            if($sDist -lt 0.25){ continue }
            if([math]::Cos($spriteAngle) -lt 0){ continue }
            $spriteScreenX = [int](($sw / 2) * (1 + $spriteAngle / ($eng.Fov / 2)))
            $scale = [double]$s.Scale
            $spriteSizeX = [int]($sw / $sDist * $scale)
            $spriteSizeY = [int]($vh / $sDist * $scale)
            if($spriteSizeX -le 0 -or $spriteSizeY -le 0){ continue }
            $sFloorY = [int]($vh / 2 + ($vh / (2 * $sDist)))
            $drawEndY = $sFloorY
            $drawStartY = $sFloorY - $spriteSizeY
            if($drawStartY -lt 0){ $drawStartY = 0 }
            if($drawEndY -ge $vh){ $drawEndY = $vh - 1 }
            $drawStartX = [int]($spriteScreenX - $spriteSizeX / 2)
            $drawEndX   = [int]($spriteScreenX + $spriteSizeX / 2)
            if($drawStartX -lt 0){ $drawStartX = 0 }
            if($drawEndX -ge $sw){ $drawEndX = $sw - 1 }
            $stex = $tex[$s.Tex]
            # Textures are Scale2x-upscaled to 24x24 at init (v1.6.2);
            # width/height factors are loop-invariant — hoisted.
            $texSize = 24
            $sShade = [int]($sDist * 1.5)
            $widthVal = ($drawEndX - $drawStartX)
            if($widthVal -le 0){ $widthVal = 1 }
            $stexXF = $texSize / $widthVal
            $heightVal = ($drawEndY - $drawStartY)
            if($heightVal -le 0){ $heightVal = 1 }
            $stexYF = $texSize / $heightVal
            for($stripe = $drawStartX; $stripe -le $drawEndX; $stripe++){
                if($sDist -lt $zB[$stripe]){
                    $stexX = [int](($stripe - $drawStartX) * $stexXF)
                    if($stexX -lt 0){ $stexX = 0 }
                    if($stexX -ge $texSize){ $stexX = $texSize - 1 }
                    $startCharRow = $drawStartY -shr 1
                    $frameIdx = $startCharRow * $sw + $stripe
                    $isBottomHalf = (($drawStartY -band 1) -ne 0)
                    for($y = $drawStartY; $y -le $drawEndY; $y++){
                        $stexY = [int](($y - $drawStartY) * $stexYF)
                        if($stexY -lt 0){ $stexY = 0 }
                        if($stexY -ge $texSize){ $stexY = $texSize - 1 }
                        $color = $stex[$stexY][$stexX]
                        if($color -ne 0){
                            if($color -ge 232){
                                $shadedVal = $color - $sShade
                                if($shadedVal -lt 232){ $color = 232 } else { $color = $shadedVal }
                            }
                            if($isBottomHalf){
                                if($frameIdx -ge 0 -and $frameIdx -lt $bgF.Length){ $bgF[$frameIdx] = [string]$color }
                            } else {
                                if($frameIdx -ge 0 -and $frameIdx -lt $fgF.Length){ $fgF[$frameIdx] = [string]$color }
                            }
                        }
                        if($isBottomHalf){ $frameIdx += $sw }
                        $isBottomHalf = -not $isBottomHalf
                    }
                }
            }
        }

        # String assembly with run-length color compression (donor).
        $lastFg = ""; $lastBg = ""
        for($charRow = 0; $charRow -lt $sh; $charRow++){
            $lineBuffer = New-Object System.Text.StringBuilder(1024)
            for($col = 0; $col -lt $sw; $col++){
                $frameIdx = $charRow * $sw + $col
                $fg = $fgF[$frameIdx]
                $bg = $bgF[$frameIdx]
                if($fg -ne $lastFg -or $bg -ne $lastBg){
                    $lastFg = $fg
                    $lastBg = $bg
                    if($script:UseTrueColor){
                        [void]$lineBuffer.Append("$esc[38;2;$($tcLut[[string]$fg]);48;2;$($tcLut[[string]$bg])m")
                    } else {
                        [void]$lineBuffer.Append("$esc[38;5;${fg};48;5;${bg}m")
                    }
                }
                [void]$lineBuffer.Append([char]0x2580)
            }
            $lastFg = ""; $lastBg = ""
            [void]$buffer.Append($lineBuffer.ToString()).Append("$esc[0m`n")
        }

        # ── HUD (4 lines under the frame) ──
        $p = $script:Player
        $hpPct = 0.0; if($p.MaxHP -gt 0){ $hpPct = $p.HP / $p.MaxHP }
        $hpBars = [int][math]::Max([int]($hpPct * 15), 0)
        if($hpBars -gt 15){ $hpBars = 15 }
        $hpColor = "38;5;46;48;5;46"
        if($hpPct -le 0.5){
            if($hpPct -le 0.25){ $hpColor = "38;5;196;48;5;196" } else { $hpColor = "38;5;226;48;5;226" }
        }
        $hpA = New-Object string ([char]0x2588, $hpBars)
        $hpI = New-Object string ([char]0x2588, (15 - $hpBars))
        $hpBarStr = "$esc[${hpColor}m${hpA}$esc[38;5;236;48;5;236m${hpI}$esc[0m"
        $mpPct = 0.0; if($p.MaxMP -gt 0){ $mpPct = $p.MP / $p.MaxMP }
        $mpBars = [int][math]::Max([int]($mpPct * 15), 0)
        if($mpBars -gt 15){ $mpBars = 15 }
        $mpA = New-Object string ([char]0x2588, $mpBars)
        $mpI = New-Object string ([char]0x2588, (15 - $mpBars))
        $mpBarStr = "$esc[38;5;51;48;5;51m${mpA}$esc[38;5;236;48;5;236m${mpI}$esc[0m"
        $zoneName = ""
        if($d.Zone){ $zoneName = [string]$d.Zone.Name }
        $fpsHud = ""
        if($script:Settings.ShowFPS -ne $false){
            # Interpreter-bound budget: ~9-10 is healthy, 5-8 strained,
            # 1-4 something is very wrong (window huge? host slow?).
            $fpsCol = "92"
            if($fps -le 4){ $fpsCol = "91" }
            elseif($fps -le 8){ $fpsCol = "93" }
            $fpsHud = "   FPS: $esc[${fpsCol}m$fps$esc[0m"
        }
        [void]$buffer.Append(" FLOOR $($script:DungeonLevel) — $zoneName   Lv$($script:PlayerLevel)  XP $($script:XP)/$($script:XPToNext)$fpsHud$esc[K`n")
        $bkTag = ""
        if($script:HasBossKey){ $bkTag = "  $esc[1;33m>> BOSS KEY <<$esc[0m" }
        [void]$buffer.Append(" HP [$hpBarStr] $($p.HP)/$($p.MaxHP)   MP [$mpBarStr] $($p.MP)/$($p.MaxMP)   Gold: $esc[93m$($script:Gold)g$esc[0m$bkTag$esc[K`n")
        # v1.6.2: a FRESH status message (under its 6s lifetime) beats
        # the [E] prompt — the player just acted, feedback outranks
        # affordance. Pressing [E] at the exit with the boss alive, or
        # at a chest with no picks, used to reply into a line the
        # prompt was covering. After expiry the prompt returns.
        $statusFresh = $false
        if($script:StatusMsg){
            if($script:StatusMsg -ne $statusShownMsg){
                $statusShownMsg = $script:StatusMsg
                $statusShownAt = $currentTime
            }
            if(($currentTime - $statusShownAt) -gt 3500){
                $script:StatusMsg = ""
                $statusShownMsg = ""
            } else {
                $statusFresh = $true
            }
        }
        if($statusFresh){
            [void]$buffer.Append(" $esc[1;36m$($script:StatusMsg)$esc[0m$esc[K`n")
        } else {
            [void]$buffer.Append("$esc[K`n")
        }
        # v1.6.2: the [E] prompt lives IN the controls bar — it
        # brightens and renames itself when something is in reach
        # ("[E] Open Chest"), so the prompt and the status line can
        # never mask each other again. Bar uses single spacing so the
        # longest label ("Rescue Survivor") still fits 100 cols.
        $eSeg = "[E] Interact"
        if($canInteract){
            $eLabel = [string]$rs.Inter[$faceKey]
            if(-not $eLabel -or $eLabel -eq "True"){ $eLabel = "Interact" }
            $eSeg = "$esc[1;33m[E] $eLabel$esc[0m"
        }
        [void]$buffer.Append(" [WASD] Move/Turn $eSeg [M] Map [P] Potion [I] Inv [J] Quests [O] Options [Q] Leave$esc[K")
        try { [Console]::Write($buffer.ToString()) } catch { Write-Host $buffer.ToString() -NoNewline }
    }
}
function Enter-Dungeon {
    if($script:RaidTheme){
        # Themed raid (Phase 6): the Depths' floor counter is NOT
        # advanced. A player-anchored raid level is swapped in and
        # restored by Reset-MutatorOnEnd on BOTH exit paths. No depth
        # record, no Nemesis — Root haunts the Depths, not the world.
        $script:RaidTheme.SavedLevel = [int]$script:DungeonLevel
        $script:DungeonLevel = [math]::Max([int]$script:PlayerLevel, 6)
        $script:NemesisPending = $false
    } else {
    $script:DungeonLevel++
    # Deepest-floor record (Phase 5). The flash only fires once records
    # are meaningful (old best >= 10) so early floors stay quiet.
    if($script:DungeonLevel -gt $script:DeepestFloor){
        if($script:DeepestFloor -ge 10){
            $script:StatusMsg = "NEW PERSONAL DEPTH RECORD: floor $($script:DungeonLevel)!"
        }
        $script:DeepestFloor = $script:DungeonLevel
    }
    # Nemesis (Phase 5): queue the ambush on qualifying floors. Fires
    # from the dungeon loop head so Death routes through $inDungeon.
    $script:NemesisPending = $false
    if($script:NemesisStage -eq 0 -and $script:DungeonLevel -ge 8){  $script:NemesisPending = $true }
    elseif($script:NemesisStage -eq 1 -and $script:DungeonLevel -ge 14){ $script:NemesisPending = $true }
    elseif($script:NemesisStage -eq 2 -and $script:DungeonLevel -ge 16){ $script:NemesisPending = $true }
    # Act III (Phase 6): with the LAST ticket in hand, the Lich King
    # of Legacy Code waits below sixteen. Root goes first if both queue.
    $script:MigrationPending = $false
    if((Get-QuestStage "msq") -eq 101 -and $script:DungeonLevel -ge 16){ $script:MigrationPending = $true }
    }
    $script:HasBossKey   = $false
    $script:BossDefeated = $false
    $script:Dungeon = New-Dungeon $script:DungeonLevel
    # ── Zone banner (Phase 3): announce the themed zone on entry ──
    $zoneInfo = $script:Dungeon.Zone
    if($zoneInfo){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkGray"
        $znPad = [math]::Max([math]::Floor((66 - $zoneInfo.Name.Length) / 2), 0)
        Write-C  "  ║" "DarkGray"
        Write-C ((" " * $znPad) + $zoneInfo.Name + (" " * (66 - $znPad - $zoneInfo.Name.Length))) $zoneInfo.Color
        Write-CL "║" "DarkGray"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkGray"
        Write-Host ""
        Write-CL "  $($zoneInfo.Desc1)" "Gray"
        Write-CL "  $($zoneInfo.Desc2)" "DarkGray"
        if($script:Companion -eq "rp"){
            Write-CL "  Orphan slips in behind you, staying out of the light." "DarkGray"
        } elseif($script:Companion -eq "dm"){
            Write-CL "  Cursor blinks ahead down the corridor, indexing the dark." "DarkGray"
        }
        Announce-RadiantEvent
        if($zoneInfo.Id -eq "Core"){
            Write-Host ""
            $heatWarn = if((Get-DifficultyMul) -lt 1.0){"The ambient heat gnaws at you — slowly. (Easy)"}else{"The ambient heat gnaws at you. Keep moving."}
            Write-CL "  ! $heatWarn" "Red"
        Write-Host ""
        }
        Write-Host ""
        Write-CL "  (Zone visuals can be turned off in [O] Options.)" "DarkGray"
        Write-Host ""
        Wait-Key
    }
    # v1.6.2: renderer-specific display notice, once per session.
    if(-not $script:DisplayCheckShown){
        $script:DisplayCheckShown = $true
        clr
        Show-DisplayCheck
    }
    Show-GenerationVisual
    # ── Marn's ghost (Cat 7 flourish): one scene, once ──────────────
    # Fires on the first real descent after the journal binds (raids
    # excluded — Marn died in the Depths, not a themed rerun). SF id
    # "mghost" (999999 = met); UNRELATED to syslogxing's sx_ghost quest.
    if(-not $script:RaidTheme -and $script:JournalCharm -and (Get-QuestStage "mghost") -ne 999999){
        Set-QuestStage "mghost" 999999
        clr
        Write-Host ""
        Write-CL "  The charm at your neck goes warm — then the torchlight" "Gray"
        Write-CL "  ahead bends around a shape that casts no shadow." "Gray"
        Write-Host ""
        Write-CL "  A fieldwalker, third-class, by the patches. Translucent." "DarkCyan"
        Write-CL "  He is reading a journal that is also hanging at your hip." "DarkCyan"
        Write-Host ""
        Write-CL "  'Fifteen of fifteen,' MARN says, not looking up. 'You" "Cyan"
        Write-CL "  even kept the pages in order. Do you know how rare that" "Cyan"
        Write-CL "  is? Nobody reads documentation. Nobody FINISHES it.'" "Cyan"
        Write-Host ""
        Write-CL "  He closes the ghost of the journal, and for a moment his" "Gray"
        Write-CL "  hand rests where the spine would be — where the charm was." "Gray"
        Write-Host ""
        Write-CL "  'Keep the Byte. It always worked better for other people.'" "Cyan"
        Write-CL "  He glances down the corridor, the old habit of a man who" "Gray"
        Write-CL "  swore to keep the systems up. Then, quieter:" "Gray"
        Write-Host ""
        Write-CL "  'My tickets are closed. Yours are still open. Go.'" "Yellow"
        Write-Host ""
        Write-CL "  The torchlight straightens. The corridor is just a" "DarkGray"
        Write-CL "  corridor. The charm stays warm a little longer than" "DarkGray"
        Write-CL "  it should." "DarkGray"
        Write-Host ""
        Wait-Key
    }
    # Heat tick accumulator for the Core Meltdown zone (see move handler).
    $script:HeatStepCounter = 0
    # Room-effect tracker: which effect the player last stood in, so the
    # entry announcement fires once per room visit, not every step.
    $script:LastRoomFx = $null
    $script:DisturbedChests = @{}  # fresh dungeon = fresh disturbed-chest tracking
    $script:EncountersThisDungeon = 0  # reset encounter cap counter
    $script:EncounterTiles = @{}      # reset per-tile encounter history

    # Reset per-run state — bestiary "first seen" flags clear, run stats
    # restart at zero, and the hidden-boss gating flags reset.
    $script:RunStats = @{
        DamageDealt   = 0
        DamageTaken   = 0
        GoldEarned    = 0
        XPEarned      = 0
        KillsThisRun  = 0
        CritsThisRun  = 0
        PotionsUsed   = 0
        HighestCombo  = 0
        StepsTaken    = 0
    }
    $script:UsedPotionsThisDungeon = $false
    $script:TookDamageThisDungeon  = $false
    # Per-dungeon one-shot talent flags. Reset on every dungeon entry so
    # the player gets the proc once per run.
    $script:LastStandUsed     = $false   # Knight T3_B
    $script:ResurrectionUsed  = $false   # Cleric  T3_C
    $script:FinalStandUsed    = $false   # Berserker T3_C
    $script:LayOnHandsUsed    = 0   # Cleric  T3_B

    # Ranger Trapfinder: +1 free lockpick on dungeon entry
    if(Has-Talent "Ranger_T3_C"){
        $script:Lockpicks += 1
    }
    # Cooking food buffs persist for one dungeon run only. Cleared here
    # so the buff doesn't carry into the NEXT entry.
    $script:ActiveFoodBuff = $null
    foreach($k in @($script:Bestiary.Keys)){
        if($script:Bestiary[$k].FirstSeen){ $script:Bestiary[$k].FirstSeen = $false }
    }

    # Frugal Run mutator: stash all potions, throwables, and lockpicks
    # for the run, but leave the player ONE lockpick to work with — total
    # zero picks felt punishing without any tactical option for chests.
    # Restored automatically on dungeon end (clear or death).
    if(Has-Mutator "Frugal"){
        # Frugal Run: stash potions/throwables/picks at the door. Leave
        # the player with 1 Small Health Potion + 1 Mana Potion + 1
        # lockpick — bare-bones tactical floor for the run. On dungeon
        # end, restore the stashed items in full so the player gets
        # back exactly what they came in with.
        $script:FrugalStashedPotions    = @($script:Potions.ToArray())
        $script:FrugalStashedThrowables = @($script:ThrowablePotions.ToArray())
        $script:FrugalStashedLockpicks  = [math]::Max($script:Lockpicks - 1, 0)
        $script:Potions.Clear()
        $script:ThrowablePotions.Clear()
        # Issue the bare-bones loadout. These two potions are NEW objects,
        # not pulled from the stash, so the stash restore at end-of-run
        # gives back the player's original consumables intact.
        [void]$script:Potions.Add(@{Name="Small Health Potion"; Type="Heal"; Power=30; Price=25; Desc="Restore 30 HP"; Icon="[HP+]"; Category="Potion"; Kind="Potion"; Weight=1})
        [void]$script:Potions.Add(@{Name="Mana Potion";         Type="Mana"; Power=30; Price=30; Desc="Restore 30 MP"; Icon="[MP+]"; Category="Potion"; Kind="Potion"; Weight=1})
        $script:Lockpicks = if($script:Lockpicks -ge 1){1}else{$script:Lockpicks}
    } else {
        $script:FrugalStashedPotions    = $null
        $script:FrugalStashedThrowables = $null
        $script:FrugalStashedLockpicks  = 0
    }

    # NOTE: Dungeon entry no longer auto-restores HP/MP. Players were
    # exploiting this by entering and exiting dungeons repeatedly to
    # heal for free. To recover, use potions, sleep at the Inn, or
    # rely on Cleric/Bard healing.

    # Reset frame buffer so the first dungeon render is a full paint
    Reset-FrameBuffer

    # If the terminal window is too small for buffered rendering, show a
    # one-time informational page so the player knows how to enable the
    # smoother mode. The game still plays fine at any size — small
    # windows just fall back to clear-and-redraw each frame.
    # v1.6.1: also shown when the 3D renderer is selected but the
    # window can't hold its fixed frame (raycast falls back to classic
    # below 100x33 instead of scrolling the screen every frame).
    try {
        $ws = $Host.UI.RawUI.WindowSize
        $classicSmall = ($ws.Width -lt 80 -or $ws.Height -lt 32)
        $raySmall = ((Get-EffectiveRenderer) -eq "Raycast" -and -not (Test-RayWindowFit))
        if($classicSmall -or $raySmall){
            clr
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkYellow"
            Write-CL "  ║              W I N D O W   T O O   S M A L L                     ║" "Yellow"
            Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkYellow"
            Write-Host ""
            Write-C   "  Your terminal is currently " "Gray"
            Write-C   "$($ws.Width)x$($ws.Height)" "DarkYellow"
            Write-CL  ". The dungeon will play just fine," "Gray"
            Write-CL  "  but you'll see a full screen refresh on every step." "Gray"
            Write-Host ""
            Write-C   "  Resize the window to at least " "Gray"
            Write-C   "80x32" "Cyan"
            Write-CL  " to enable " "Gray"
            Write-C   "  smooth rendering" "Cyan"
            Write-CL  " — the dungeon updates near real-time, redrawing" "Gray"
            Write-CL  "  only the parts that changed instead of repainting the whole screen" "Gray"
            Write-CL  "  each turn." "Gray"
            Write-Host ""
            Write-C   "  The simplest fix: " "White"
            Write-CL  "maximize the window." "White"
            Write-CL  "  Click the maximize button in the top-right corner of your terminal," "Gray"
            Write-C   "  or press " "Gray"
            Write-C   "Win+Up Arrow" "DarkGray"
            Write-CL  " on Windows. You can also resize at any time" "Gray"
            Write-CL  "  during play and the game will switch modes automatically." "Gray"
            if($raySmall){
                Write-Host ""
                Write-C   "  3D renderer note: " "Magenta"
                Write-CL  "the raycast view draws a fixed-size frame. In a" "Gray"
                Write-CL  "  window smaller than that frame the terminal scrolls on EVERY frame" "Gray"
                Write-CL  "  (the screen appears to jump) — this is a hard limit of console" "Gray"
                Write-C   "  rendering. The classic view is used until the window is at least " "Gray"
                Write-CL  "100x33" "Cyan"
                Write-CL  "  — resize or maximize and the 3D view returns on your next step." "Gray"
            }
            Write-Host ""
            Write-C   "  [Press Enter to continue]" "DarkGray"
            Read-Host | Out-Null
        }
    } catch {}

    # Movement throttle: after a WASD action, the player must wait at
    # least $moveCooldownMs before the next movement registers. This
    # stops keyboard auto-repeat from zooming the player across the map
    # now that the render is fast enough to make every tick count.
    $moveCooldownMs   = 130
    $lastMoveStamp    = [DateTime]::MinValue   # time of last WASD action
    # Per-dungeon-run flag — resets each time the player enters a new
    # dungeon. Used so the Heavy Pockets achievement only counts ONCE
    # per run, not every step while encumbered.
    $script:DungeonEncumberedThisRun = $false

    $inDungeon = $true
    while($inDungeon -and $script:Player.HP -gt 0){
        $d = $script:Dungeon

        # Nemesis ambush (Phase 5): fires once on entering a qualifying
        # floor. Handled INSIDE the loop so a Death exits via the same
        # $inDungeon path as every other combat.
        if($script:NemesisPending){
            $script:NemesisPending = $false
            $nmResult = Show-NemesisEncounter
            if($nmResult -eq "Death"){
                $inDungeon = $false
                continue
            }
        }
        # Act III finale: fired here so Death exits via $inDungeon,
        # exactly like every other fight in the game.
        if($script:MigrationPending){
            $script:MigrationPending = $false
            $mgResult = Show-MigrationFinale
            if($mgResult -eq "Death"){
                $inDungeon = $false
                continue
            }
        }

        # ── Raycast renderer (the monument) ────────────────────────
        # When active, a real-time engine leg replaces the classic
        # render+input turn. The leg returns an action token; Walk/Step
        # tokens synthesize a "W" keypress with an overridden target tile,
        # so the ENTIRE classic tile-trigger chain below runs unchanged.
        $script:RaycastStepTarget = $null
        if(Test-RaycastActive){
            $legTok = Invoke-RaycastLeg
            switch([string]$legTok.Kind){
                "Walk" { $key = "W"; $script:RaycastStepTarget = @([int]$d.PX, [int]$d.PY) }
                "Step" { $key = "W"; $script:RaycastStepTarget = @([int]$legTok.X, [int]$legTok.Y) }
                "Key"  { $key = [string]$legTok.Key }
                default { $key = "Q" }
            }
        } else {
        # Render everything (3D viewport, minimap, HUD, status, controls bar)
        # into the frame buffer, then Flush-Frame paints only changed cells.
        # The controls bar lives INSIDE the buffer so the cursor never has
        # to write past the buffer's last row, which would scroll the
        # terminal and invalidate our absolute cursor positions.
        Begin-Frame
        if($script:BufferedDisabled){
            # Window too short for buffered rendering — old-style clear+draw
            clr
            Render-Screen
            Write-CL "  [W] Forward  [A] Turn Left  [D] Turn Right  [S] Back" "DarkGray"
            Write-CL "  [M] Map  [P] Potion  [I] Inventory  [J] Quests  [O] Options  [Q] Quit" "DarkGray"
            Write-C "  > " "Yellow"
        } else {
            Render-Screen
            # Controls bar at the bottom of the buffer
            Write-CL "  [W] Forward  [A] Turn Left  [D] Turn Right  [S] Back" "DarkGray"
            Write-CL "  [M] Map  [P] Potion  [I] Inventory  [J] Quests  [O] Options  [Q] Quit" "DarkGray"
            Write-C "  > " "Yellow"
            # Capture where the prompt ends, so after Flush-Frame we can put
            # the cursor there for the user's keystroke to echo cleanly.
            $promptRow = $script:FrameRow
            $promptCol = $script:FrameCol
            Flush-Frame
            # Position the cursor at the end of the prompt so the keystroke
            # echo lands in the right spot. Falls through silently on hosts
            # without positioning.
            if(Test-CursorPositionOK){
                try {
                    $r = [math]::Min($promptRow, $script:FrameRows - 1)
                    $c = [math]::Min($promptCol, $script:FrameCols - 1)
                    $pos = New-Object System.Management.Automation.Host.Coordinates $c, $r
                    $Host.UI.RawUI.CursorPosition = $pos
                } catch {}
            }
        }

        # Movement throttle: enforce minimum dwell time since the last
        # WASD action before reading the next key. Non-movement keys are
        # not throttled (the cap only applies AFTER a previous move).
        $sinceMove = ([DateTime]::Now - $lastMoveStamp).TotalMilliseconds
        if($sinceMove -lt $moveCooldownMs){
            $waitMs = [int]($moveCooldownMs - $sinceMove)
            if($waitMs -gt 0){ Start-Sleep -Milliseconds $waitMs }
            # Drain any keys queued during the cooldown so auto-repeat
            # doesn't immediately register the next move.
            Drain-Keys
        }

        $key = Read-DungeonKey
        # Don't echo the key in buffered mode — it would scroll the terminal
        # if the cursor is at the last visible row. The next frame's
        # diff-paint will show the result of the action anyway.
        if($script:BufferedDisabled){
            Write-Host $key -ForegroundColor Cyan
        }
        }   # end classic render+input (raycast leg supplies $key otherwise)

        # Encumbrance gate: WASD movement blocked when over weight cap.
        # Player must open inventory (key 'I') and drop items to free up space.
        $upperKey = $key.ToUpper()
        $isMoveKey = ($upperKey -eq "W" -or $upperKey -eq "A" -or $upperKey -eq "S" -or $upperKey -eq "D")
        if($isMoveKey){
            # Stamp the move time even if the action ends up blocked — the
            # cooldown still applies so spamming W against a wall doesn't
            # fall through into hyper-speed input later.
            $lastMoveStamp = [DateTime]::Now
            $script:RunStats.StepsTaken++
            # ── Core Meltdown ambient heat (Phase 3, zone 16+) ──
            # Ticks 2-4 damage every 9 steps (Easy: 1-2 every 15). Heat
            # never kills outright — it floors at 1 HP so the zone
            # pressures the player without cheap ambient deaths.
            # (v1.6.1: cadence relaxed from 6/10 — 41x41 floors mean
            # roughly twice the walking per dive.)
            if($d.Zone -and $d.Zone.Id -eq "Core"){
                $script:HeatStepCounter++
                $heatEvery = if((Get-DifficultyMul) -lt 1.0){15}else{9}
                if($script:HeatStepCounter -ge $heatEvery){
                    $script:HeatStepCounter = 0
                    $heatDmg = if((Get-DifficultyMul) -lt 1.0){Get-Random -Min 1 -Max 3}else{Get-Random -Min 2 -Max 5}
                    if($script:Player.HP -gt 1){
                        $script:Player.HP = [math]::Max($script:Player.HP - $heatDmg, 1)
                        $script:StatusMsg = "The heat sears you for $heatDmg! (HP $($script:Player.HP)/$($script:Player.MaxHP))"
                    }
                }
            }
            # ── Room-effect entry announce + Charged MP trickle (Phase 3) ──
            $curFx = Get-ActiveRoomEffect $d
            if($curFx -ne $script:LastRoomFx){
                $script:LastRoomFx = $curFx
                if($curFx -eq "Flooded"){
                    $script:StatusMsg = "Coolant floods this room. You slog through it. (SPD -3 in combat)"
                } elseif($curFx -eq "Charged"){
                    $script:StatusMsg = "The air CRACKLES with charge. (Magic +20% both ways, +1 MP/step)"
                }
            }
            if($curFx -eq "Charged" -and $script:Player.MP -lt $script:Player.MaxMP){
                $script:Player.MP++
            }
            # Cleric Sanctuary: +3 HP per dungeon step (capped at MaxHP).
            # Quietly applied — no status message to keep the step loop
            # uncluttered.
            if(Has-Talent "Cleric_T2_C" -and $script:Player.HP -lt $script:Player.MaxHP){
                $script:Player.HP = [math]::Min($script:Player.HP + 3, $script:Player.MaxHP)
            }
        }
        if($isMoveKey -and (Test-Encumbered)){
            $cur = Get-CurrentCarryWeight
            $max = Get-MaxCarryWeight $script:Player
            $script:StatusMsg = "OVER ENCUMBERED ($cur/$max) — open inventory [I] and drop items"
            # Track this for the Heavy Pockets achievement. Flag ensures the
            # counter only bumps once per dungeon run (not every blocked step).
            if(-not $script:DungeonEncumberedThisRun){
                $script:DungeonEncumberedThisRun = $true
                $script:TotalEncumbered++
                Check-Achievements
            }
            continue
        }

        switch($upperKey){
            "W" {
                if($script:RaycastStepTarget){
                    # Raycast leg supplied the target tile (free-float
                    # approach — PDir is irrelevant to the trigger).
                    $nx = [int]$script:RaycastStepTarget[0]
                    $ny = [int]$script:RaycastStepTarget[1]
                    $script:RaycastStepTarget = $null
                } else {
                    $fwd = Get-Forward $d.PDir 1
                    $nx = $d.PX + $fwd[0]
                    $ny = $d.PY + $fwd[1]
                }
                if($nx -ge 0 -and $nx -lt $d.W -and $ny -ge 0 -and $ny -lt $d.H -and $d.Grid[$ny,$nx] -ne 1){
                    $cell = $d.Grid[$ny,$nx]

                    if($cell -eq 2 -or $cell -eq 3 -or $cell -eq 11){
                        $eKey = "$nx,$ny"
                        if($d.Enemies.ContainsKey($eKey)){
                            # Mimic ambush (v1.6.2): the "chest" springs.
                            # One-time reveal — after this the disguise
                            # is blown (sprite, prompt and maps all show
                            # the fight). Works for both entry paths:
                            # [E] in 3D and walk-into in classic.
                            if(Test-MimicDisguised $d.Enemies[$eKey]){
                                $d.Enemies[$eKey].Revealed = $true
                                clr
                                Write-Host ""
                                Write-CL "  You reach for the chest..." "DarkYellow"
                                Start-Sleep -Milliseconds 700
                                Write-CL "  The lid splits into TEETH. The chest LUNGES!" "Red"
                                Write-CL "  It's a MIMIC!" "Red"
                                Start-Sleep -Milliseconds 900
                            }
                            $result = Start-Combat $d.Enemies[$eKey]
                            if($result.Result -eq "Death"){
                                $inDungeon = $false
                            }
                            elseif($result.Result -eq "Won"){
                                $d.Enemies.Remove($eKey)
                                $d.Grid[$ny,$nx] = 0
                                $d.PX = $nx; $d.PY = $ny
                            }
                        }
                    }
                    elseif($cell -eq 4){
                        # Boss door (v1.6): opens with the key and STAYS
                        # open. The boss itself is cell 11 inside the room.
                        if($script:HasBossKey){
                            # Survivor quest: credit if HP is above 50% when entering the boss room
                            if($script:Player.HP -gt ($script:Player.MaxHP * 0.5)){
                                Update-QuestProgress "Survivor"
                            }
                            # Untouched achievement counter: 75% HP threshold (stricter)
                            if($script:Player.HP -gt ($script:Player.MaxHP * 0.75)){
                                $script:TotalUntouched++
                            }
                            $d.Grid[$ny,$nx] = 0
                            $script:StatusMsg = "The key turns. The BOSS DOOR grinds open..."
                        } else {
                            $script:StatusMsg = "The door is LOCKED. Defeat the mini-boss for the key!"
                        }
                    }
                    elseif($cell -eq 10){
                        # Sliding door (v1.6): opens on contact / [E] and
                        # stays open forever (grid mutates to floor).
                        $d.Grid[$ny,$nx] = 0
                        $script:StatusMsg = "The door slides open."
                    }
                    elseif($cell -eq 5){
                        if($script:BossDefeated){
                            $d.PX = $nx; $d.PY = $ny
                            clr
                            Write-CL "" "Green"
                            Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkYellow"
                            Write-CL "  ║                                                    ║" "DarkYellow"
                            Write-CL "  ║          D U N G E O N   C L E A R E D !           ║" "Yellow"
                            Write-CL "  ║                                                    ║" "DarkYellow"
                            Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkYellow"
                            Write-Host ""
                            Write-CL "       .     *    .   *     .    *   .    *" "DarkYellow"
                            Write-CL "    *    .      .       *      .       .   " "Yellow"
                            Write-CL "       .    *      .      *    .    *      " "DarkYellow"
                            Write-Host ""
                            Write-CL "  You emerge victorious from the dungeon!" "Green"
                            Write-Host ""

                            # In-game day advances on every dungeon clear.
                            $script:GameDay++
                            Announce-RadiantEvent
                            # Streak tracking: survived a clear
                            $script:Streak++
                            if($script:Streak -gt $script:BestStreak){
                                $script:BestStreak = $script:Streak
                            }
                            # Lifetime clears counter for achievements
                            $script:DungeonsCleared++
                            Write-CL "  Current clear streak: $($script:Streak)x" "Yellow"

                            $dailyMultiplier = if($script:DailyDungeonActive){2}else{1}
                            $bonusGold = 100 * $dailyMultiplier
                            # Mutator reward multiplier: applied on top of daily multiplier
                            $mutMul = Get-MutatorRewardMul
                            if($mutMul -gt 1.0){
                                $mutBonus = [math]::Floor($bonusGold * ($mutMul - 1.0))
                                $bonusGold += $mutBonus
                            }
                            $script:Gold += $bonusGold
                            if($dailyMultiplier -gt 1){
                                Write-CL "  + $bonusGold Gold (DAILY DUNGEON 2x BONUS!)" "Yellow"
                            } else {
                                Write-CL "  + $bonusGold Gold (Completion Bonus)" "Yellow"
                            }
                            if($mutMul -gt 1.0 -and $script:DungeonMutator){
                                $pct = [int](($mutMul - 1.0) * 100)
                                Write-CL "    (+${pct}% from mutator: $($script:DungeonMutator.Name))" $script:DungeonMutator.Color
                            }

                            Write-Host ""
                            Write-CL "  ── Treasure Haul ──" "Magenta"
                            $lootCount = 3 * $dailyMultiplier
                            for($ti=0;$ti -lt $lootCount;$ti++){
                                $treasure = Init-ItemWeight (New-RandomLoot ($script:DungeonLevel + 1)) "Loot"
                                [void]$script:Inventory.Add($treasure)
                                Write-CL "    + $($treasure.Name) (Value: $($treasure.Value)g, Wt: $($treasure.Weight))" "Magenta"
                            }
                            # If this clear loot put the player over weight, flag it
                            if(Test-Encumbered){
                                $cur = Get-CurrentCarryWeight
                                $max = Get-MaxCarryWeight $script:Player
                                Write-Host ""
                                Write-CL "  ! You're now over-encumbered ($cur/$max)." "Yellow"
                                Write-CL "    Visit the Market or Inventory before entering another dungeon." "DarkGray"
                            }

                            # ── Special items: not sold in shops, only earned here ──
                            # Daily Dungeons drop these much more frequently than normal runs.
                            # Repair Kit: 25% normal / 70% daily.
                            $kitChance = if($script:DailyDungeonActive){70}else{25}
                            if((Get-Random -Max 100) -lt $kitChance){
                                $kits = if($script:DailyDungeonActive){2}else{1}
                                $script:RepairKits += $kits
                                $kitWord = if($kits -eq 1){"Repair Kit"}else{"Repair Kits"}
                                Write-CL "    * $kits $kitWord found! (use to instantly repair all gear)" "Cyan"
                            }
                            # Extra Strong Potions: 20% normal / 65% daily.
                            # Drop is one ES potion per success, randomly chosen between
                            # Health and Mana. Goes into the regular potion bag (weight 1).
                            # If no inventory space, automatically converts to 250-400 gold.
                            $espChance = if($script:DailyDungeonActive){65}else{20}
                            if((Get-Random -Max 100) -lt $espChance){
                                $espShop = Get-PotionShop | Where-Object { $_.Category -eq "Special" }
                                $espTemplate = $espShop | Get-Random
                                # Try to add to potion bag — check carry weight first
                                $curWt = Get-CurrentCarryWeight
                                $maxWt = Get-MaxCarryWeight
                                # Bug fix: also enforce the 10-potion belt
                                # cap — weight alone let players exceed it.
                                if((($curWt + 1) -le $maxWt) -and $script:Potions.Count -lt 10){
                                    [void]$script:Potions.Add($espTemplate)
                                    Write-CL "    * 1 $($espTemplate.Name) found! ($($espTemplate.Desc))" "Magenta"
                                } else {
                                    # No space — convert to gold (250-400)
                                    $goldVal = Get-Random -Min 250 -Max 401
                                    $script:Gold += $goldVal
                                    Write-CL "    * 1 $($espTemplate.Name) found, but your bags are full." "DarkYellow"
                                    Write-CL "      You sell it on the way back to town for $goldVal gold." "Yellow"
                                }
                            }

                            # Mark daily dungeon done if applicable
                            if($script:DailyDungeonActive){
                                $script:DailyDungeonDone = $true
                                Try-UnlockAchievement "DailyDiver"
                            }

                            Check-Achievements

                            Write-Host ""
                            $totalLoot = 0
                            foreach($it in $script:Inventory){ $totalLoot += $it.Value }
                            Write-CL "  Total loot in inventory: ${totalLoot}g sell value" "DarkGray"
                            Write-CL "  Gold on hand: $($script:Gold)g" "Yellow"
                            Write-Host ""
                            Show-RunSummary -Outcome "VICTORY"

                            # ── Hidden boss check ──
                            # Spawn condition: Daily Dungeon, full HP, no potions used.
                            # Once defeated permanently (lifetime flag), no respawn.
                            # Note: while Frugal mutator is active, potions are
                            # stashed at the door — UsedPotionsThisDungeon will
                            # be false even if the player would have used them
                            # but couldn't. We accept this consistency: Frugal
                            # is a "no consumables" run anyway, so the spawn
                            # gate semantically holds.
                            $hbCondition = (
                                $script:DailyDungeonActive -and
                                $script:Player.HP -eq $script:Player.MaxHP -and
                                -not $script:UsedPotionsThisDungeon -and
                                -not $script:HiddenBossDefeated
                            )
                            if($hbCondition){
                                Wait-Key
                                # Preserve streak across the optional fight.
                                # If the player dies to the hidden boss, the
                                # combat exit handler will reset $script:Streak
                                # to 0 — but since the dungeon was already
                                # cleared, we restore the streak so the
                                # decision to engage the optional boss isn't
                                # punished by losing the clear streak.
                                $streakBeforeHidden = [int]$script:Streak
                                $bestBeforeHidden   = [int]$script:BestStreak
                                Start-HiddenBossEncounter
                                if($script:Player.HP -le 0){
                                    $script:Streak     = $streakBeforeHidden
                                    $script:BestStreak = $bestBeforeHidden
                                }
                            }

                            Wait-Key
                            Reset-MutatorOnEnd
                            $inDungeon = $false
                        } else {
                            $script:StatusMsg = "Defeat the BOSS before you can leave!"
                        }
                    }
                    elseif($cell -eq 6){
                        # ── LOCKPICKING FLOW ──
                        $chestKey = "$nx,$ny"

                        # Already disturbed (from earlier abort)? chest is jammed
                        if($script:DisturbedChests.ContainsKey($chestKey)){
                            $script:StatusMsg = "This chest is jammed from earlier tampering."
                        }
                        # Out of picks? can't attempt at all
                        elseif($script:Lockpicks -lt 1){
                            $script:StatusMsg = "You need a lockpick to open this chest."
                        }
                        else {
                            # Fixed difficulty: every chest has 5 tumblers with a
                            # single sweet spot per pin. Dungeon level no longer
                            # influences difficulty — the pure timing challenge
                            # is consistent so the player can master it.
                            $tumblers = 5

                            if(Test-HasSkeletonKey){
                                # The Skeleton Key (Backupvale quest): every
                                # lock is its lock. No picks, no minigame.
                                clr
                                Write-Host ""
                                Write-CL "  The Skeleton Key turns before the lock finishes" "Cyan"
                                Write-CL "  deciding to resist." "Cyan"
                                Start-Sleep -Milliseconds 600
                                $result = @{ Success = $true; PicksUsed = 0 }
                            } else {
                            $result = Start-Lockpicking -Tumblers $tumblers -AvailablePicks $script:Lockpicks
                            }

                            # Deduct picks used (whether success, fail, or abort)
                            $script:Lockpicks -= $result.PicksUsed
                            if($script:Lockpicks -lt 0){ $script:Lockpicks = 0 }

                            # Invalidate the dungeon partial-render cache.
                            # The lockpick screen used direct cursor writes,
                            # so the buffered frame state is now stale and
                            # the next partial-diff repaint would tear. We
                            # don't call clr here because the success path
                            # has its own clr below; we just clear the
                            # cache so the next dungeon frame is a full
                            # repaint regardless of which branch we take.
                            $script:BufferedFirstFrame = $true
                            $script:PrevFrame = $null

                            if($result.Success){
                                # ── Success: award loot, higher tumbler count = better rewards ──
                                clr
                                Write-Host ""
                                Write-CL "  The lock gives way with a satisfying CLICK!" "Yellow"
                                Write-Host ""

                                $goldMin = 10 * $tumblers
                                $goldMax = $goldMin + (20 * $tumblers) + (15 * $script:DungeonLevel)
                                $tGold = Get-Random -Min $goldMin -Max $goldMax
                                $tGold = [int]$tGold

                                # Build chest loot pile — gold goes in here too
                                $chestPile = @()
                                if($tGold -gt 0){
                                    $chestPile += @{
                                        Name     = "Gold ($tGold)"
                                        Kind     = "Gold"
                                        Quantity = $tGold
                                        Weight   = 0
                                        Value    = $tGold
                                    }
                                }
                                $chestPile += (Init-ItemWeight (New-RandomLoot ($script:DungeonLevel + $tumblers - 3)) "Loot")

                                # Small chance of rare drop
                                $rareRoll = Get-Random -Max 100
                                if($rareRoll -lt 10){
                                    # 10%: hidden potion
                                    $potShop = Get-PotionShop | Where-Object { $_.Category -eq "Potion" }
                                    $potDrop = $potShop | Get-Random
                                    $potCopy = @{}
                                    foreach($k in $potDrop.Keys){ $potCopy[$k] = $potDrop[$k] }
                                    $potCopy.Kind = "Potion"
                                    $potCopy.Weight = 1
                                    $chestPile += $potCopy
                                } elseif($rareRoll -lt 25){
                                    # 15%: bonus lockpicks (now a stackable lootable item)
                                    $bonusPicks = Get-Random -Min 1 -Max 4
                                    $pickBundle = @{
                                        Name      = "Lockpick Bundle (x$bonusPicks)"
                                        Kind      = "Lockpicks"
                                        Quantity  = $bonusPicks
                                        Weight    = $bonusPicks    # 1wt per pick
                                        Value     = $bonusPicks * 25
                                        Desc      = "$bonusPicks lockpicks. Each weighs 1."
                                    }
                                    $chestPile += $pickBundle
                                }

                                # Journal pages (Cat 7): 18% chance per opened
                                # chest to include a page of Marn's journal —
                                # always one the player hasn't collected yet,
                                # so the 15-page set is completable. Once all
                                # pages are recorded, chests stop dropping them.
                                if((Get-Random -Max 100) -lt 18){
                                    $missingPages = @()
                                    foreach($jp in (Get-JournalPages)){
                                        if(-not $script:JournalPages.ContainsKey([int]$jp.Page)){ $missingPages += $jp }
                                    }
                                    if($missingPages.Count -gt 0){
                                        $note = $missingPages | Get-Random
                                        $noteItem = @{
                                            Name      = $note.Title
                                            Kind      = "Note"
                                            IsNote    = $true
                                            Page      = [int]$note.Page
                                            Body      = $note.Body
                                            Weight    = 0
                                            Value     = 0
                                            Desc      = "A page of Marn's journal. (Recorded in the journal when taken)"
                                        }
                                        $chestPile += $noteItem
                                    }
                                }

                                Update-QuestProgress "Treasure"
                                Update-QuestProgress "Lockpicker"; $script:TotalLocksPicked++; Add-SkillXP "Lockpicking" 15
                                $d.Grid[$ny,$nx] = 0      # remove chest (taken or not)
                                $d.PX = $nx; $d.PY = $ny

                                Wait-Key
                                $taken = Show-LootScreen -Title "TREASURE INSIDE" -Items $chestPile
                                # All 15 pages in? Bind the journal (one-time).
                                Test-JournalComplete
                                if($taken.Count -gt 0){
                                    clr
                                    Write-Host ""
                                    Write-CL "  Loot stowed:" "Magenta"
                                    foreach($t in $taken){
                                        $kindTag = switch($t.Kind){"Weapon"{"[Wpn]"}"Armor"{"[Arm]"}"Ingredient"{"[Ing]"}"Note"{"[Note]"}default{""}}
                                        Write-CL "    + $($t.Name) $kindTag" "Magenta"
                                    }
                                    Write-Host ""
                                    Read-Host "  [Press Enter to continue]" | Out-Null
                                } else {
                                    Write-CL "  You leave the chest's contents behind." "DarkGray"
                                    Read-Host "  [Press Enter to continue]" | Out-Null
                                }
                            } elseif($result.Aborted){
                                # ESC = disturbed, can't retry
                                $script:DisturbedChests[$chestKey] = $true
                                $script:StatusMsg = "You walk away. The lock is disturbed — it won't yield again."
                            } else {
                                # Ran out of picks = also disturbed (consistent with abort)
                                $script:DisturbedChests[$chestKey] = $true
                                $script:StatusMsg = "All picks broke. The lock stays shut."
                            }
                        }
                    }

                    elseif($cell -eq 7){
                        # Drain held-key buffer so a held W doesn't skip through
                        Drain-Keys
                        clr
                        Write-CL "" "Yellow"
                        Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkYellow"
                        Write-CL "  ║                                                    ║" "DarkYellow"
                        Write-CL "  ║       'Thank the gods you found me!'               ║" "Yellow"
                        Write-CL "  ║       'I've been lost down here for days!'         ║" "Yellow"
                        Write-CL "  ║                                                    ║" "DarkYellow"
                        Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkYellow"
                        Write-Host ""
                        Write-CL "  The lost adventurer follows you to safety." "Green"
                        Write-Host ""
                        Update-QuestProgress "Rescue"
                        $d.Grid[$ny,$nx] = 0
                        $d.PX = $nx; $d.PY = $ny
                        Read-Host "  [Press Enter to continue]" | Out-Null
                    }
                    elseif($cell -eq 8){
                        # ── Ancient Altar (Phase 3, Cat 3.3) ──
                        Drain-Keys
                        clr
                        Write-Host ""
                        Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkYellow"
                        Write-CL "  ║              A N C I E N T   A L T A R             ║" "Yellow"
                        Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkYellow"
                        Write-Host ""
                        Write-CL "  A weathered stone altar, humming with residual power." "Gray"
                        Write-CL "  Offerings of old coins and older bones litter its base." "DarkGray"
                        Write-Host ""
                        Write-C "  Kneel and pray? (y/n): " "Yellow"
                        $altarChoice = Read-Host
                        if($altarChoice -eq 'y' -or $altarChoice -eq 'Y'){
                            Write-Host ""
                            $altarRoll = Get-Random -Max 100
                            # Phase 4: Corruption skews the altar. Calm world:
                            # blessings up to 70%, toll 10%. Corrupted world:
                            # blessings fall toward 45%, toll climbs to 35%.
                            $blessCut   = 70 - [math]::Floor($script:Corruption / 4)
                            $silenceCut = $blessCut + 20
                            if($altarRoll -lt $blessCut){
                                # Blessing — one of three boons
                                switch(Get-Random -Max 3){
                                    0 {
                                        $bHeal = [math]::Min([math]::Floor($script:Player.MaxHP * 0.30), $script:Player.MaxHP - $script:Player.HP)
                                        if($bHeal -gt 0){ $script:Player.HP += $bHeal }
                                        Write-CL "  Warm light washes over you. (+$bHeal HP)" "Green"
                                    }
                                    1 {
                                        $bMana = [math]::Min([math]::Floor($script:Player.MaxMP * 0.50), $script:Player.MaxMP - $script:Player.MP)
                                        if($bMana -gt 0){ $script:Player.MP += $bMana }
                                        Write-CL "  Your mind clears like a fresh boot. (+$bMana MP)" "Cyan"
                                    }
                                    default {
                                        $bh = [math]::Min(15, $script:Player.MaxHP - $script:Player.HP)
                                        $bm = [math]::Min(15, $script:Player.MaxMP - $script:Player.MP)
                                        $script:Player.HP += $bh; $script:Player.MP += $bm
                                        Write-CL "  A gentle mending settles into you. (+$bh HP, +$bm MP)" "Green"
                                    }
                                }
                            }
                            elseif($altarRoll -lt $silenceCut){
                                Write-CL "  The altar is silent. Perhaps it's on lunch." "DarkGray"
                            }
                            else {
                                # A toll — small HP price, decent coin
                                $tollHP  = Get-Random -Min 5 -Max 11
                                $tollGld = Get-Random -Min 40 -Max 81
                                if($script:Player.HP -gt 1){
                                    $script:Player.HP = [math]::Max($script:Player.HP - $tollHP, 1)
                                }
                                $script:Gold += $tollGld
                                Write-CL "  The altar TAKES. Pain lances up your arm... (-$tollHP HP)" "Red"
                                Write-CL "  ...but coins clatter at your feet. (+${tollGld}g)" "Yellow"
                            }
                            # One prayer per altar — it crumbles to dust.
                            $d.Grid[$ny,$nx] = 0
                            $d.PX = $nx; $d.PY = $ny
                            Write-Host ""
                            Write-CL "  The altar crumbles to dust, its purpose served." "DarkGray"
                        } else {
                            Write-Host ""
                            Write-CL "  You leave the altar undisturbed." "DarkGray"
                        }
                        Write-Host ""
                        Read-Host "  [Press Enter to continue]" | Out-Null
                    }
                    elseif($cell -eq 9){
                        # ── Interactive lore object (Phase 3, Cat 5) ──
                        Drain-Keys
                        $loreKey = "$nx,$ny"
                        $loreObj = if($d.LoreObjects -and $d.LoreObjects.ContainsKey($loreKey)){$d.LoreObjects[$loreKey]}else{@{Type="Terminal"}}
                        $loreTitle = switch($loreObj.Type){
                            "Terminal"  { "F L I C K E R I N G   T E R M I N A L" }
                            "Bookshelf" { "D U S T Y   B O O K S H E L F" }
                            "Effigy"    { "S T R A N G E   E F F I G Y" }
                            default     { "C U R I O S I T Y" }
                        }
                        $loreColor = switch($loreObj.Type){
                            "Terminal"  { "DarkCyan" }
                            "Bookshelf" { "DarkYellow" }
                            "Effigy"    { "Magenta" }
                            default     { "Gray" }
                        }
                        clr
                        Write-Host ""
                        Write-CL "  ╔════════════════════════════════════════════════════╗" $loreColor
                        $ltPad = [math]::Max([math]::Floor((52 - $loreTitle.Length) / 2), 0)
                        Write-C  "  ║" $loreColor
                        Write-C ((" " * $ltPad) + $loreTitle + (" " * (52 - $ltPad - $loreTitle.Length))) "White"
                        Write-CL "║" $loreColor
                        Write-CL "  ╚════════════════════════════════════════════════════╝" $loreColor
                        Write-Host ""
                        $loreText = Get-LoreText $loreObj.Type
                        foreach($loreLine in ($loreText -split "`n")){
                            Write-CL "  $loreLine" "Gray"
                        }
                        Write-Host ""
                        if($loreObj.Type -eq "Effigy"){
                            Write-CL "  The effigy's eyes dim. It has said what it came to say." "DarkGray"
                        } else {
                            Write-CL "  You've gleaned what you can from it." "DarkGray"
                        }
                        # Consume: crumbles to floor after one read.
                        $d.Grid[$ny,$nx] = 0
                        if($d.LoreObjects){ $d.LoreObjects.Remove($loreKey) }
                        $d.PX = $nx; $d.PY = $ny
                        Write-Host ""
                        Read-Host "  [Press Enter to continue]" | Out-Null
                    }
                    else {
                        $d.PX = $nx; $d.PY = $ny
                        # Random encounter roll on each forward step (empty floor only).
                        # Dutchman: level 15+, daily-dungeon only, not if already won.
                        # Non-Dutchman encounters: ~1.5% per step, cap of 2 per dungeon.
                        # Tiles that already triggered an encounter this dungeon don't fire again.
                        $tileKey = "$nx,$ny"
                        $tileFreshForEncounter = -not $script:EncounterTiles.ContainsKey($tileKey)
                        $roll = Get-Random -Minimum 0 -Maximum 1000
                        $dutchAllowed = (
                            $script:DailyDungeonActive -and
                            $script:PlayerLevel -ge 15 -and
                            -not $script:OwnsDutchmanBlade
                        )
                        # Repair encounter (rare metalsmith): 0.3% per step, any dungeon, any level.
                        # Only fires if there's actually damaged gear to repair.
                        $hasDamagedGear = $false
                        if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0 -and $script:EquippedWeapon.Durability -lt $script:EquippedWeapon.MaxDurability){
                            $hasDamagedGear = $true
                        }
                        if(-not $hasDamagedGear){
                            foreach($slotN in @("Helmet","Chest","Shield","Amulet","Boots")){
                                $pp = $script:EquippedArmor[$slotN]
                                if($pp -and $pp.MaxDurability -ge 0 -and $pp.Durability -lt $pp.MaxDurability){ $hasDamagedGear = $true; break }
                            }
                        }
                        if($dutchAllowed -and $roll -lt 15 -and $script:EncountersThisDungeon -lt 3){
                            $script:EncountersThisDungeon++
                            $script:EncounterTiles[$tileKey] = $true
                            Start-RandomEncounter -Type "Dutchman"
                        } elseif($hasDamagedGear -and $roll -ge 15 -and $roll -lt 20 -and $tileFreshForEncounter -and $script:EncountersThisDungeon -lt 3){
                            # 0.5% (5 in 1000) chance for free repair encounter — rare gift
                            $script:EncountersThisDungeon++
                            $script:EncounterTiles[$tileKey] = $true
                            Start-RandomEncounter -Type "RepairSmith"
                        } elseif($roll -lt 7 -and $script:EncountersThisDungeon -lt 2 -and $tileFreshForEncounter){
                            # Normal encounters: 0.7% per step (v1.6.1,
                            # was 1.0% — rebalanced for 41x41 floors).
                            # Cap at 2 normals per dungeon; Dutchman+RepairSmith
                            # share the larger 3 cap above so all-types-combined
                            # never exceeds 3 encounters per dungeon run.
                            $script:EncountersThisDungeon++
                            $script:EncounterTiles[$tileKey] = $true
                            Start-RandomEncounter
                        }
                    }

                } else {
                    $script:StatusMsg = "You bump into a wall."
                }
            }
            "S" {
                $fwd = Get-Forward $d.PDir 1
                $nx = $d.PX - $fwd[0]
                $ny = $d.PY - $fwd[1]
                if($nx -ge 0 -and $nx -lt $d.W -and $ny -ge 0 -and $ny -lt $d.H -and $d.Grid[$ny,$nx] -ne 1 -and $d.Grid[$ny,$nx] -ne 10 -and $d.Grid[$ny,$nx] -ne 4){
                    $d.PX = $nx; $d.PY = $ny
                    # Backward step: rarer (~0.8%), still cap-limited and tile-tracked
                    $tileKey = "$nx,$ny"
                    $tileFreshForEncounter = -not $script:EncounterTiles.ContainsKey($tileKey)
                    $roll = Get-Random -Minimum 0 -Maximum 1000
                    $dutchAllowed = (
                        $script:DailyDungeonActive -and
                        $script:PlayerLevel -ge 15 -and
                        -not $script:OwnsDutchmanBlade
                    )
                    if($dutchAllowed -and $roll -lt 10 -and $script:EncountersThisDungeon -lt 3){
                        $script:EncountersThisDungeon++
                        $script:EncounterTiles[$tileKey] = $true
                        Start-RandomEncounter -Type "Dutchman"
                    } elseif($roll -lt 5 -and $script:EncountersThisDungeon -lt 2 -and $tileFreshForEncounter){
                        # Backward steps trigger encounters at 0.5% (was 0.8%)
                        $script:EncountersThisDungeon++
                        $script:EncounterTiles[$tileKey] = $true
                        Start-RandomEncounter
                    }
                }
            }
            "A" { $d.PDir = ($d.PDir + 3) % 4 }
            "D" { $d.PDir = ($d.PDir + 1) % 4 }
            "P" {
                $healPotions = @($script:Potions | Where-Object { $_.Type -eq "Heal" -or $_.Type -eq "Mana" })
                if($healPotions.Count -eq 0){
                    $script:StatusMsg = "No healing or mana potions!"
                } else {
                    $p = $script:Player
                    if($p.HP -eq $p.MaxHP -and $p.MP -eq $p.MaxMP){
                        $script:StatusMsg = "HP and MP already full!"
                    } else {
                        clr
                        Write-CL "" "White"
                        Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkGreen"
                        Write-CL "  ║              U S E   P O T I O N                    ║" "Green"
                        Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkGreen"
                        Write-Host ""
                        Write-C "  HP: $($p.HP)/$($p.MaxHP)" "Green"
                        Write-CL "    MP: $($p.MP)/$($p.MaxMP)" "Cyan"
                        Write-Host ""

                        for($pi=0;$pi -lt $healPotions.Count;$pi++){
                            $pot = $healPotions[$pi]
                            $potColor = if($pot.Type -eq "Heal"){"Green"}else{"Cyan"}
                            Write-CL "  [$($pi+1)] $($pot.Name) - $($pot.Desc)" $potColor
                        }
                        Write-CL "  [0] Cancel" "DarkGray"
                        Write-Host ""
                        Write-C "  > " "Yellow"; $pc = Read-Host
                        $pidx = (ConvertTo-SafeInt -Value $pc) - 1

                        if($pidx -ge 0 -and $pidx -lt $healPotions.Count){
                            $pot = $healPotions[$pidx]
                            switch($pot.Type){
                                "Heal" {
                                    if($p.HP -eq $p.MaxHP){
                                        $script:StatusMsg = "HP already full!"
                                    } else {
                                        $power = [int]$pot.Power + [math]::Floor([int]$pot.Power * 0.04 * (Get-SkillTier "Alchemy"))
                                        if(Has-Talent "Cleric_T2_A"){
                                            $power = [math]::Floor($power * 1.30)
                                        }
                                        if(Has-Talent "Cleric_T4_A"){
                                            $power = [math]::Floor($power * 1.50)
                                        }
                                        $healed = [math]::Min($power, $p.MaxHP - $p.HP)
                                        $p.HP += $healed
                                        $script:StatusMsg = "Used $($pot.Name)! Restored $healed HP! ($($p.HP)/$($p.MaxHP))"
                                        $script:Potions.Remove($pot)
                                        $script:RunStats.PotionsUsed++; Add-SkillXP "Alchemy" 8
                                        $script:UsedPotionsThisDungeon = $true
                                    }
                                }
                                "Mana" {
                                    if($p.MP -eq $p.MaxMP){
                                        $script:StatusMsg = "MP already full!"
                                    } else {
                                        $restored = [math]::Min($pot.Power, $p.MaxMP - $p.MP)
                                        $p.MP += $restored
                                        $script:StatusMsg = "Used $($pot.Name)! Restored $restored MP! ($($p.MP)/$($p.MaxMP))"
                                        $script:Potions.Remove($pot)
                                        $script:RunStats.PotionsUsed++; Add-SkillXP "Alchemy" 8
                                        $script:UsedPotionsThisDungeon = $true
                                    }
                                }
                            }
                        }
                    }
                }
            }

            "I" {
                # Open inventory mid-dungeon. Useful for using Repair Kits or
                # dropping items when over-encumbered.
                Show-InventoryScreen
            }

            "J" {
                # Quick quest log view — see all active quests and progress
                # without leaving the dungeon.
                Show-QuestLog
            }

            "O" {
                # v1.6.2: options reachable mid-dungeon — renderer,
                # zone visuals, FPS counter, turn speed, all of it.
                Show-OptionsMenu
                Reset-FrameBuffer
            }
            "M" {
                # Detailed dungeon map (v1.5): full-floor fogged map with a
                # legend — the raycast renderer's replacement for the side
                # minimap, available from the classic renderer too.
                Show-DetailedMap
            }

            "F" {
                # Debug-only: force a random encounter of your choice.
                # Skipped silently for non-debug runs so the F key is
                # an inert no-op. Useful for play-testing because random
                # encounters are otherwise gated behind step-roll RNG
                # and per-dungeon caps.
                if($script:DebugMode){
                    clr
                    Write-Host ""
                    Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkMagenta"
                    Write-CL "  ║         D E B U G   —   F O R C E   E N C       ║" "Magenta"
                    Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkMagenta"
                    Write-Host ""
                    Write-CL "  Pick an encounter to force on this tile:" "Yellow"
                    Write-Host ""
                    Write-CL "    [1] Wandering Merchant" "Cyan"
                    Write-CL "    [2] Singing Bard       (heals HP/MP)" "Cyan"
                    Write-CL "    [3] Roving Alchemist   (potion trade)" "Cyan"
                    Write-CL "    [4] Hooded Gambler     (blackjack)" "Cyan"
                    Write-CL "    [5] Flying Dutchman    (cursed sword)" "DarkRed"
                    Write-CL "    [6] Wandering Smith    (free repair)" "DarkYellow"
                    Write-Host ""
                    Write-CL "    [0] Cancel" "DarkGray"
                    Write-Host ""
                    Write-C "  > " "Yellow"; $encPick = Read-Host
                    $encType = switch($encPick){
                        "1" { "Merchant"     }
                        "2" { "Bard"         }
                        "3" { "Alchemist"    }
                        "4" { "Gambler"      }
                        "5" { "Dutchman"     }
                        "6" { "RepairSmith"  }
                        default { $null }
                    }
                    if($encType){
                        Start-RandomEncounter -Type $encType
                    }
                    # Force a full repaint after the encounter — encounter
                    # screens use direct Write-CL calls, not the dungeon
                    # frame buffer.
                    $script:BufferedFirstFrame = $true
                    $script:PrevFrame = $null
                }
            }

            "Q" {
                # When a mutator is active, abandoning the dungeon forfeits
                # ALL gold/XP earned this run plus all loot. This is harsher
                # than the normal random-loss flee penalty and reflects the
                # mutator's risk/reward bargain: take the mutator buff for
                # bigger payouts on a clear, but if you bail, you bail
                # empty-handed.
                # v1.6.2 CRITICAL FIX: this confirm used to print at
                # the current cursor position — which, coming from the
                # 3D view, is the bottom of a full 33-row frame. The
                # question was effectively invisible: [Q] looked like
                # a freeze, Enter answered "" (= no), and the game
                # resumed — quitting was unreachable. Dedicated
                # confirmation screen now, and the key buffer is
                # drained first so a held Q can't pre-type into the
                # prompt.
                clr
                # Never-blocking drain (see Drain-Keys): a held [Q]'s
                # release event must not stall the confirm screen.
                Drain-Keys
                $hasMut = ($null -ne $script:DungeonMutator)
                $qLines = if($hasMut){ @(
                    "! WARNING: A mutator is active. Quitting forfeits ALL",
                    "  loot, gold, and XP earned this run."
                ) } else { @(
                    "Leaving early has a price: a random share of your loot",
                    "is dropped behind you on the way out."
                ) }
                Show-NoticePanel -Title "L E A V E   T H E   D U N G E O N ?" -Color "Red" -EdgeColor "DarkRed" -Lines $qLines
                Write-C "  Abandon dungeon? (y/n): " "Red"
                $confirm = Read-Host
                if($confirm -ne 'y'){
                    # User declined. The prompt was written outside the frame
                    # buffer (below the controls bar where the cursor was), so
                    # the diff-paint won't know to clear it. Force a full
                    # repaint on the next frame.
                    Reset-FrameBuffer
                }
                if($confirm -eq 'y'){
                    clr
                    Write-CL "" "Red"
                    Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkRed"
                    Write-CL "  ║                                                    ║" "DarkRed"
                    Write-CL "  ║       You fumble in fear as you flee the            ║" "Red"
                    Write-CL "  ║       dungeon, dropping loot behind you...          ║" "Red"
                    Write-CL "  ║                                                    ║" "DarkRed"
                    Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkRed"
                    Write-Host ""

                    if($hasMut){
                        # Total forfeiture branch.
                        # We void: this run's earned gold (deducted from total),
                        # this run's earned XP (deducted, with re-leveling math
                        # held), and the entire dungeon loot bag.
                        $vGold = [int]$script:RunStats.GoldEarned
                        $vXP   = [int]$script:RunStats.XPEarned
                        $script:Gold = [math]::Max($script:Gold - $vGold, 0)
                        # XP rollback: just remove run XP. We don't unlevel —
                        # if the player leveled up mid-run, they keep the
                        # level (you can't take a stat boost back cleanly),
                        # but the leftover progress within the current level
                        # is wiped to zero.
                        $script:XP = [math]::Max($script:XP - $vXP, 0)
                        $itemCount = $script:Inventory.Count
                        $script:Inventory.Clear()
                        Write-CL "  Mutator active — total forfeiture:" "DarkRed"
                        Write-CL "    Lost ${vGold}g earned this run." "Red"
                        Write-CL "    Lost ${vXP} XP earned this run." "Red"
                        Write-CL "    Lost $itemCount loot item(s)." "Red"
                    }
                    elseif($script:Inventory.Count -gt 0){
                        $lossPct = (Get-Random -Min 15 -Max 51) / 100.0
                        $loseCount = [math]::Max([math]::Ceiling($script:Inventory.Count * $lossPct), 1)

                        # Shuffle and remove random items
                        $lostItems = [System.Collections.ArrayList]@()
                        for($li=0;$li -lt $loseCount;$li++){
                            if($script:Inventory.Count -eq 0){ break }
                            $removeIdx = Get-Random -Min 0 -Max $script:Inventory.Count
                            $lostItem = $script:Inventory[$removeIdx]
                            [void]$lostItems.Add($lostItem)
                            $script:Inventory.RemoveAt($removeIdx)
                        }

                        $lostValue = 0
                        Write-CL "  Lost items:" "DarkRed"
                        foreach($lost in $lostItems){
                            Write-CL "    - $($lost.Name) ($($lost.Value)g)" "Red"
                            $lostValue += $lost.Value
                        }
                        Write-Host ""
                        $pctDisplay = [math]::Floor($lossPct * 100)
                        Write-CL "  You lost $($lostItems.Count) item(s) worth ${lostValue}g! (${pctDisplay}% of your loot)" "DarkRed"
                    } else {
                        Write-CL "  You had nothing to lose... but your dignity." "DarkGray"
                    }

                    # Non-mutator quit also takes a small percentage of gold.
                    if(-not $hasMut){
                        $goldLossPct = (Get-Random -Min 5 -Max 16) / 100.0
                        $goldLost = [math]::Floor($script:Gold * $goldLossPct)
                        if($goldLost -gt 0){
                            $script:Gold -= $goldLost
                            Write-CL "  Dropped ${goldLost}g in your panic!" "DarkYellow"
                        }
                    }

                    Write-Host ""
                    Write-CL "  Remaining Gold: $($script:Gold)g" "Yellow"
                    Write-CL "  Remaining Loot: $($script:Inventory.Count) item(s)" "DarkGray"
                    Write-Host ""
                    Wait-Key
                    Reset-MutatorOnEnd
                    $inDungeon = $false
                    $script:DungeonLevel--
                }
            

            }
        }
    }

        if($script:Player.HP -le 0){
        # Hardcore mutator: lose 50% of gold on death (instead of zero
        # under normal play — corpse-runs are not a thing in this game).
        if(Has-Mutator "Hardcore"){
            $hcLoss = [math]::Floor($script:Gold * 0.50)
            if($hcLoss -gt 0){
                $script:Gold -= $hcLoss
            }
        }
        # Mutator state cleared so the next dungeon entry starts fresh.
        Reset-MutatorOnEnd
        clr
        Write-CL "" "Red"
        Write-CL "  ╔══════════════════════════════════════════════════════╗" "DarkRed"
        Write-CL "  ║                                                      ║" "DarkRed"
        Write-CL "  ║             Y O U   H A V E   D I E D                ║" "Red"
        Write-CL "  ║                                                      ║" "DarkRed"
        Write-CL "  ╚══════════════════════════════════════════════════════╝" "DarkRed"
        Write-Host ""
        Write-CL "          _______________" "DarkGray"
        Write-CL "         /               \" "DarkGray"
        Write-CL "        |  R.I.P.         |" "DarkGray"
        Write-CL "        |                 |" "DarkGray"
        Write-CL "        |  $($script:Player.Name.PadRight(16))|" "DarkGray"
        Write-CL "        |  Level $($script:PlayerLevel.ToString().PadRight(10))|" "DarkGray"
        Write-CL "        |                 |" "DarkGray"
        Write-CL "        |  Fell in the    |" "DarkGray"
        Write-CL "        |  depths...      |" "DarkGray"
        Write-CL "        |_________________|" "DarkGray"
        Write-CL "        /                 \" "DarkGray"
        Write-CL "       /___________________\" "DarkGray"
        Write-Host ""
        Write-CL "  ── Final Stats ──" "DarkYellow"
        Write-CL "  Dungeon Level Reached: $($script:DungeonLevel)" "DarkGray"
        Write-CL "  Player Level: $($script:PlayerLevel)" "DarkGray"
        Write-CL "  Gold: $($script:Gold)" "DarkGray"
        Write-CL "  Enemies Slain: Many." "DarkGray"
        Write-CL "  $(Get-DeathQuip)" "DarkGray"
        Write-Host ""
        Add-Corruption 15   # death feeds the Depths (Phase 4)
        Show-RunSummary -Outcome "DEATH"
        Write-Host ""
        Write-CL "  ┌─────────────────────────────────────┐" "DarkGray"
        Write-CL "  │                                     │" "DarkGray"
        Write-C  "  │  " "DarkGray"; Write-C "[1]" "Green"; Write-CL " Play Again (New Character)    │" "White"
        Write-C  "  │  " "DarkGray"; Write-C "[2]" "Yellow"; Write-CL " Play Again (Same Character)   │" "White"
        Write-C  "  │  " "DarkGray"; Write-C "[3]" "Red"; Write-CL " Quit Game                     │" "White"
        Write-CL "  │                                     │" "DarkGray"
        Write-CL "  └─────────────────────────────────────┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"
        $deathChoice = Read-Host

        switch($deathChoice){
            "1" {
                # Full restart with new character
                Show-CharacterSelect
                # Reset dungeon level
                $script:DungeonLevel = 0
            }
            "2" {
                # Items lost, gold kept. Level/XP/stats reset to class
                # baseline so the player starts fresh-but-funded. Talents
                # and achievements persist (multi-life progression). The
                # potion belt gets a free Small Health Potion to start.

                # Flying Dutchman pseudo-class isn't in the regular
                # template table. If we're in Dutchman mode, just respawn
                # the player with the same Dutchman baseline rather than
                # crashing on a $null template lookup.
                if($script:DutchmanMode){
                    $script:Player = @{
                        Name      = "Flying Dutchman"
                        HP        = 200; MaxHP = 200
                        MP        = 80;  MaxMP = 80
                        ATK       = 30
                        DEF       = 18
                        SPD       = 14
                        MAG       = 16
                        Abilities = @(
                            @{Name="Phantom Strike"; Cost=12; Type="Physical"; Power=45; Effect="None";   Cooldown=2}
                            @{Name="Curse";          Cost=14; Type="Magic";    Power=30; Effect="Drain";  Cooldown=3}
                            @{Name="Maelstrom";      Cost=22; Type="Magic";    Power=60; Effect="None";   Cooldown=4}
                            @{Name="Soul Anchor";    Cost=18; Type="Heal";     Power=80; Effect="ATKBuff";Cooldown=5}
                        )
                    }
                    # Refresh the cursed weapon to full durability (the
                    # original is unique and can't be repaired the normal
                    # way, but death is its own kind of repair).
                    $script:EquippedWeapon = @{
                        Name="Dutchman's Blade"; ATK=100; Price=10000; WeaponType="Sword"
                        ClassAffinity="None"; AffinityBonus=0
                        Perk="Drain"; PerkChance=80
                        Kind="Weapon"
                        Durability=200; MaxDurability=200
                        TwoHanded=$false
                        Weight=6
                    }
                    $script:EquippedArmor = @{Helmet=$null;Chest=$null;Shield=$null;Amulet=$null;Boots=$null}
                    $script:Inventory.Clear()
                    $script:Potions.Clear()
                    $script:ThrowablePotions.Clear()
                    [void]$script:Potions.Add(@{Name="Large Health Potion";Type="Heal";Power=70;Price=60;Desc="Restore 70 HP"})
                    $script:PlayerLevel = 1
                    $script:XP          = 0
                    $script:XPToNext    = 100
                    $script:DungeonLevel = [math]::Max($script:DungeonLevel - 1, 0)
                    $script:KillCount = 0
                    $script:HasBossKey = $false
                    $script:BossDefeated = $false
                    Write-Host ""
                    Write-CL "  The Dutchman's curse drags you back to the wheel..." "Magenta"
                    Write-CL "  Gear gone. Gold remains. The Blade is yours forever." "DarkGray"
                    Wait-Key
                    continue
                }

                $tpl = (Get-ClassTemplates)[$script:PlayerClass]
                $favorBonus = if($script:HiddenBossDefeated){5}else{0}
                $favorHP    = if($script:HiddenBossDefeated){25}else{0}
                $favorMP    = if($script:HiddenBossDefeated){15}else{0}
                $script:Player = @{
                    Name      = $tpl.Name
                    HP        = $tpl.HP + $favorHP
                    MaxHP     = $tpl.MaxHP + $favorHP
                    MP        = $tpl.MP + $favorMP
                    MaxMP     = $tpl.MaxMP + $favorMP
                    ATK       = $tpl.ATK + $favorBonus
                    DEF       = $tpl.DEF + $favorBonus
                    SPD       = $tpl.SPD + $favorBonus
                    MAG       = $tpl.MAG + $favorBonus
                    Abilities = $tpl.Abilities
                }
                # Reapply training-grounds stat purchases (training is a
                # permanent investment, separate from level progression).
                $p2 = $script:Player
                $tp = $script:TrainingPoints
                if($tp){
                    $p2.ATK   += 2 * [int]$tp.ATK
                    $p2.DEF   += 2 * [int]$tp.DEF
                    $p2.SPD   += 1 * [int]$tp.SPD
                    $p2.MAG   += 2 * [int]$tp.MAG
                    $p2.MaxHP += 8 * [int]$tp.HP
                    $p2.HP     = $p2.MaxHP
                    $p2.MaxMP += 5 * [int]$tp.MP
                    $p2.MP     = $p2.MaxMP
                }
                # Reapply HP/MP-granting talents at Lv 1 baseline so the
                # level-1 player still benefits from purchased talents.
                $hpDelta = 0; $mpDelta = 0
                if(Has-Talent "Knight_T1_A")     { $hpDelta += (5 * 1) }
                if(Has-Talent "Brawler_T1_C")    { $hpDelta += (8 * 1) }
                if(Has-Talent "Cleric_T1_A")     { $hpDelta += (4 * 1); $mpDelta += (4 * 1) }
                if(Has-Talent "Berserker_T1_B")  { $hpDelta += (5 * 1) }
                if(Has-Talent "Warlock_T1_B")    { $hpDelta += (5 * 1) }
                if(Has-Talent "Mage_T1_A")          { $mpDelta += (5 * 1) }
                if(Has-Talent "Necromancer_T1_A")   { $mpDelta += (5 * 1) }
                if(Has-Talent "Necromancer_T3_A"){
                    $reduction = [math]::Floor($p2.MaxHP * 0.20)
                    $p2.MaxHP = [math]::Max($p2.MaxHP - $reduction, 30)
                }
                if($hpDelta -gt 0){
                    $p2.MaxHP += $hpDelta
                    $p2.HP     = $p2.MaxHP
                }
                if($mpDelta -gt 0){
                    $p2.MaxMP += $mpDelta
                    $p2.MP     = $p2.MaxMP
                }

                # Wipe items (gear + bag), keep gold.
                $script:EquippedWeapon = $null
                $script:EquippedArmor = @{Helmet=$null;Chest=$null;Shield=$null;Amulet=$null;Boots=$null}
                $script:Inventory.Clear()
                $script:Potions.Clear()
                $script:ThrowablePotions.Clear()
                [void]$script:Potions.Add(@{Name="Small Health Potion";Type="Heal";Power=30;Price=25;Desc="Restore 30 HP"})

                # Reset level/XP progression to baseline.
                $script:PlayerLevel = 1
                $script:XP          = 0
                $script:XPToNext    = 100

                # Per-run state cleared.
                $script:DungeonLevel = [math]::Max($script:DungeonLevel - 1, 0)
                $script:KillCount = 0
                $script:HasBossKey = $false
                $script:BossDefeated = $false

                Write-Host ""
                Write-CL "  You awaken at the town square, battered but alive..." "Yellow"
                Write-CL "  Your gear is gone. Your gold remains. Your levels are forfeit." "DarkGray"
                Write-CL "  Talents and achievements persist." "DarkGray"
                Write-CL "  Level: $($script:PlayerLevel)  |  Gold: $($script:Gold)g" "DarkGray"
                Wait-Key
            }

            "3" {
                clr
                Write-CL "" "White"
                Write-CL "  Thanks for playing DEPTHS OF POWERSHELL!" "Yellow"
                Write-CL "  Final Stats: Level $($script:PlayerLevel) $($script:Player.Name)" "Gray"
                Write-Host ""
                $script:GameRunning = $false
                return
            }
            default {
                Show-CharacterSelect
                $script:DungeonLevel = 0
            }
        }
    }
}



# ─── CHARACTER CREATOR — PAPER DOLL (Phase 1) ───────────────
# Appearance picker shown right after class select. The doll is a
# 32x48-pixel sprite drawn as 24 rows of U+2580 half-blocks (FG =
# top pixel, BG = bottom pixel) with 256-color SGR — the same
# technique as the raycast sprite grids, at portrait size. Art is
# stored as ROLE grids (one char per pixel) and colored at render
# time by palette swap, so hair/skin variants are pure data:
#   .  transparent      S/s skin base/shade    E eye     M mouth
#   H/h hair base/shade C/c tunic base/shade   T/t belt/buckle
#   P/p trouser base/shade                     B/b boot base/shade
# Layer order: body first, hair stamped over it (non-dot wins).
# Grids are string rows (48 x 32 chars) — easier to eyeball and
# hand-tune than raw int rows; they read as the same per-pixel
# data. Keep every grid EXACTLY 48 rows of 32 chars. Hair grids
# are shared between builds (both bodies use the same head box).
