# Skin tones: Base/Shade paint the S/s roles, Mouth paints M.
# Loader clamps (the AP case) hard-code these counts — update both.
function Get-DollSkinTones {
    return @(
        @{ Name = "Porcelain"; Base = 224; Shade = 217; Mouth = 174 },
        @{ Name = "Fair";      Base = 223; Shade = 180; Mouth = 174 },
        @{ Name = "Tan";       Base = 180; Shade = 137; Mouth = 131 },
        @{ Name = "Olive";     Base = 179; Shade = 136; Mouth = 131 },
        @{ Name = "Bronze";    Base = 137; Shade = 94;  Mouth = 95  },
        @{ Name = "Dark";      Base = 95;  Shade = 52;  Mouth = 88  }
    )
}

function Get-DollHairColors {
    return @(
        @{ Name = "Black";    Base = 236; Shade = 234 },
        @{ Name = "Umber";    Base = 94;  Shade = 52  },
        @{ Name = "Chestnut"; Base = 130; Shade = 94  },
        @{ Name = "Blonde";   Base = 220; Shade = 178 },
        @{ Name = "Ginger";   Base = 202; Shade = 130 },
        @{ Name = "Silver";   Base = 250; Shade = 245 },
        @{ Name = "Crimson";  Base = 160; Shade = 88  },
        @{ Name = "Violet";   Base = 97;  Shade = 54  }
    )
}

# Tunic/undergarment colors (paint the C/c roles). Index 0 is the
# original blue — the pre-outfit default, so old saves look the same.
# Loader clamps hard-code the count (see AP case) — update both.
function Get-DollOutfitColors {
    return @(
        @{ Name = "Blue";    Base = 67;  Shade = 24  },
        @{ Name = "Crimson"; Base = 131; Shade = 88  },
        @{ Name = "Forest";  Base = 71;  Shade = 22  },
        @{ Name = "Violet";  Base = 97;  Shade = 54  },
        @{ Name = "Brown";   Base = 137; Shade = 94  },
        @{ Name = "Slate";   Base = 245; Shade = 238 },
        @{ Name = "Teal";    Base = 73;  Shade = 23  },
        @{ Name = "Gold";    Base = 178; Shade = 136 }
    )
}

# Set/weight tint for armor overlays (roles A base / a shade / G
# glint). Tint comes from the item SET when it has one, else the
# weight-class default — per-ITEM art is explicitly out of scope
# (v12). Ordinal table: A/a and G are case-paired with grid roles.
function Get-DollSetPalette {
    param([string]$SetName, [string]$WeightClass, [bool]$IsRobe = $false)
    $cA = 245; $cS = 240; $cG = 252   # iron-grey heavy default
    if($IsRobe){ $cA = 97; $cS = 54; $cG = 183 }
    elseif($SetName -eq "Leather"){ $cA = 130; $cS = 94;  $cG = 178 }
    elseif($SetName -eq "Iron"){    $cA = 245; $cS = 240; $cG = 252 }
    elseif($SetName -eq "Steel"){   $cA = 252; $cS = 246; $cG = 255 }
    elseif($SetName -eq "Dragon"){  $cA = 124; $cS = 88;  $cG = 202 }
    elseif($SetName -eq "Mythril"){ $cA = 116; $cS = 73;  $cG = 195 }
    elseif($WeightClass -eq "Light"){ $cA = 130; $cS = 94; $cG = 178 }
    $t = [System.Collections.Hashtable]::new([System.StringComparer]::Ordinal)
    $t["A"] = $cA; $t["a"] = $cS; $t["G"] = $cG
    return $t
}

# Map equipped armor to overlay grids in stamp order: chest under
# boots under helm under shield. Amulets have no overlay yet (a
# chest glint is a Phase-2+ candidate). Robes are detected by NAME
# (Robe/Cloak/Vestment/Garb) — no weight class marks them.
function Get-DollEquipOverlays {
    $ovs = @()
    if(-not $script:EquippedArmor){ return ,$ovs }
    $art = Get-DollArt
    $eq = $script:EquippedArmor
    $chest = $eq["Chest"]
    if($chest){
        $setN = Get-ItemSet $chest.Name
        $wc = Get-ArmorWeightClass $chest
        $isRobe = ([string]$chest.Name -match "Robe|Cloak|Vestment|Garb")
        $grid = $art.ArmChestP
        if($isRobe){ $grid = $art.ArmChestR }
        elseif($wc -eq "Light"){ $grid = $art.ArmChestL }
        $ovs += @{ Grid = $grid; Pal = (Get-DollSetPalette $setN $wc $isRobe) }
    }
    $boots = $eq["Boots"]
    if($boots){
        $setN = Get-ItemSet $boots.Name
        $wc = Get-ArmorWeightClass $boots
        $grid = $art.ArmBootsP
        if($wc -eq "Light"){ $grid = $art.ArmBootsL }
        $ovs += @{ Grid = $grid; Pal = (Get-DollSetPalette $setN $wc $false) }
    }
    $helm = $eq["Helmet"]
    if($helm){
        $setN = Get-ItemSet $helm.Name
        $wc = Get-ArmorWeightClass $helm
        $grid = $art.ArmHelmP
        if($wc -eq "Light"){ $grid = $art.ArmHelmL }
        $ovs += @{ Grid = $grid; Pal = (Get-DollSetPalette $setN $wc $false) }
    }
    $shield = $eq["Shield"]
    if($shield){
        $setN = Get-ItemSet $shield.Name
        $wc = Get-ArmorWeightClass $shield
        $ovs += @{ Grid = $art.ArmShield; Pal = (Get-DollSetPalette $setN $wc $false) }
    }
    return ,$ovs
}

# Composite + colorize: returns 24 ANSI strings, 32 half-block
# cells wide, run-length color-compressed like the raycast frame
# assembler. Transparent cells paint 233-on-233 so the portrait
# sits on its own dark card in any terminal theme. 256-color only
# for now (the truecolor LUT lives inside the ray engine — a
# Phase-2 refactor could share it).
function Get-CharDollLines {
    param([int]$Gender = 0, [int]$Skin = 2, [int]$HairStyle = 0, [int]$HairColor = 0, [int]$Outfit = 0, $Overlays = $null)
    $art = Get-DollArt
    $body = $art.BodyM
    if($Gender -eq 1){ $body = $art.BodyF }
    if($HairStyle -lt 0 -or $HairStyle -gt 3){ $HairStyle = 0 }
    $hair = $art[("Hair" + $HairStyle)]
    $skins = Get-DollSkinTones
    $hairsT = Get-DollHairColors
    if($Skin -lt 0 -or $Skin -ge $skins.Count){ $Skin = 2 }
    if($HairColor -lt 0 -or $HairColor -ge $hairsT.Count){ $HairColor = 0 }
    $sk = $skins[$Skin]
    $hc = $hairsT[$HairColor]
    # PS 5.1 quirk: hashtable LITERAL keys are case-INsensitive —
    # "S"/"s" in one @{ } is a ParserError (DuplicateKeyInHashLiteral).
    # Build an ordinal (case-sensitive) table by assignment instead.
    $pal = [System.Collections.Hashtable]::new([System.StringComparer]::Ordinal)
    $pal["."] = 233
    $pal["S"] = [int]$sk.Base;  $pal["s"] = [int]$sk.Shade
    $pal["M"] = [int]$sk.Mouth; $pal["E"] = 232
    $pal["H"] = [int]$hc.Base;  $pal["h"] = [int]$hc.Shade
    $outfits = Get-DollOutfitColors
    if($Outfit -lt 0 -or $Outfit -ge $outfits.Count){ $Outfit = 0 }
    $of = $outfits[$Outfit]
    $pal["C"] = [int]$of.Base;  $pal["c"] = [int]$of.Shade
    $pal["T"] = 220; $pal["t"] = 136
    $pal["P"] = 240; $pal["p"] = 237
    $pal["B"] = 94;  $pal["b"] = 52
    # Per-pixel color grid: body -> hair -> equipment overlays, each
    # layer stamped where non-transparent. 0 = untouched, mapped to
    # the 233 background at emission (no palette produces 0).
    $cg = New-Object "int[]" 1536
    for($y = 0; $y -lt 48; $y++){
        $rowB = [string]$body[$y]
        $rowH = [string]$hair[$y]
        $base = $y * 32
        for($x = 0; $x -lt 32; $x++){
            $ch = $rowH[$x]
            if($ch -eq "."){ $ch = $rowB[$x] }
            if($ch -ne "."){ $cg[$base + $x] = [int]$pal[[string]$ch] }
        }
    }
    if($Overlays){
        foreach($ov in $Overlays){
            $og = $ov.Grid
            $op = $ov.Pal
            for($y = 0; $y -lt 48; $y++){
                $rowO = [string]$og[$y]
                $base = $y * 32
                for($x = 0; $x -lt 32; $x++){
                    $ch = $rowO[$x]
                    if($ch -ne "."){ $cg[$base + $x] = [int]$op[[string]$ch] }
                }
            }
        }
    }
    $esc = [char]27
    $lines = @()
    for($cy = 0; $cy -lt 24; $cy++){
        $sb = New-Object System.Text.StringBuilder 512
        $bT = $cy * 64
        $bB = $bT + 32
        $lastFg = -1; $lastBg = -1
        for($x = 0; $x -lt 32; $x++){
            $fg = $cg[$bT + $x]; if($fg -eq 0){ $fg = 233 }
            $bg = $cg[$bB + $x]; if($bg -eq 0){ $bg = 233 }
            if($fg -ne $lastFg -or $bg -ne $lastBg){
                $lastFg = $fg; $lastBg = $bg
                [void]$sb.Append("$esc[38;5;${fg};48;5;${bg}m")
            }
            [void]$sb.Append([char]0x2580)
        }
        [void]$sb.Append("$esc[0m")
        $lines += $sb.ToString()
    }
    return ,$lines
}

# The creator screen. VT hosts get the live color doll; classic
# hosts get numbered text prompts and a one-line summary (a
# 16-color doll is a Phase-2 option). Writes $script:Appearance.
function Show-CharacterCreator {
    if(-not $script:Appearance){
        $script:Appearance = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 }
    }
    $ap = $script:Appearance
    $genderNames = @("Masculine", "Feminine")
    $styleNames  = @("Short", "Long", "Ponytail", "Shaved")
    $skins = Get-DollSkinTones
    $hairsT = Get-DollHairColors
    $outfitsT = Get-DollOutfitColors
    if(-not (Test-VTSupport)){
        # ── classic text path — no ANSI, no live preview ──
        clr
        Write-Host ""
        Write-CL "  ╔═════════════════════════════════════════════════╗" "DarkCyan"
        Write-CL "  ║              A P P E A R A N C E                 ║" "Cyan"
        Write-CL "  ╚═════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""
        Write-CL "  (Color preview needs a VT-capable terminal — text picks for now.)" "DarkGray"
        Write-Host ""
        Write-CL "  Build:      [1] Masculine  [2] Feminine" "Gray"
        Write-C  "  > " "Yellow"
        $ap.Gender = [math]::Max(0, [math]::Min(1, (ConvertTo-SafeInt (Read-Host) 1) - 1))
        $stRow = @()
        for($i = 0; $i -lt $styleNames.Count; $i++){ $stRow += ("[" + ($i + 1) + "] " + $styleNames[$i]) }
        Write-CL ("  Hair Style: " + ($stRow -join "  ")) "Gray"
        Write-C  "  > " "Yellow"
        $ap.HairStyle = [math]::Max(0, [math]::Min($styleNames.Count - 1, (ConvertTo-SafeInt (Read-Host) 1) - 1))
        $hcRow = @()
        for($i = 0; $i -lt $hairsT.Count; $i++){ $hcRow += ("[" + ($i + 1) + "] " + $hairsT[$i].Name) }
        Write-CL ("  Hair Color: " + ($hcRow -join "  ")) "Gray"
        Write-C  "  > " "Yellow"
        $ap.HairColor = [math]::Max(0, [math]::Min($hairsT.Count - 1, (ConvertTo-SafeInt (Read-Host) 1) - 1))
        $skRow = @()
        for($i = 0; $i -lt $skins.Count; $i++){ $skRow += ("[" + ($i + 1) + "] " + $skins[$i].Name) }
        Write-CL ("  Skin Tone:  " + ($skRow -join "  ")) "Gray"
        Write-C  "  > " "Yellow"
        $ap.Skin = [math]::Max(0, [math]::Min($skins.Count - 1, (ConvertTo-SafeInt (Read-Host) 3) - 1))
        $ofRow = @()
        for($i = 0; $i -lt $outfitsT.Count; $i++){ $ofRow += ("[" + ($i + 1) + "] " + $outfitsT[$i].Name) }
        Write-CL ("  Outfit:     " + ($ofRow -join "  ")) "Gray"
        Write-C  "  > " "Yellow"
        $ap.Outfit = [math]::Max(0, [math]::Min($outfitsT.Count - 1, (ConvertTo-SafeInt (Read-Host) 1) - 1))
        Write-Host ""
        $sumBuild = $genderNames[$ap.Gender].ToLower()
        $sumStyle = $styleNames[$ap.HairStyle].ToLower()
        $sumHair  = $hairsT[$ap.HairColor].Name.ToLower()
        $sumSkin  = $skins[$ap.Skin].Name.ToLower()
        $sumOf    = $outfitsT[$ap.Outfit].Name.ToLower()
        Write-CL "  A $sumBuild adventurer — $sumSkin skin, $sumHair $sumStyle hair, $sumOf garb." "Green"
        return
    }
    # ── VT path: live doll, letter keys cycle, Enter accepts ──
    $esc = [char]27
    $done = $false
    while(-not $done){
        clr
        Write-Host ""
        Write-CL "  ╔═════════════════════════════════════════════════╗" "DarkCyan"
        Write-CL "  ║      C U S T O M I Z E   Y O U R   H E R O       ║" "Cyan"
        Write-CL "  ╚═════════════════════════════════════════════════╝" "DarkCyan"
        $doll = Get-CharDollLines -Gender $ap.Gender -Skin $ap.Skin -HairStyle $ap.HairStyle -HairColor $ap.HairColor -Outfit $ap.Outfit
        $gN  = $genderNames[$ap.Gender]
        $stN = $styleNames[$ap.HairStyle]
        $hcN = $hairsT[$ap.HairColor].Name
        $skN = $skins[$ap.Skin].Name
        $ofN = $outfitsT[$ap.Outfit].Name
        $panel = New-Object "string[]" 24
        for($i = 0; $i -lt 24; $i++){ $panel[$i] = "" }
        $panel[3]  = "$esc[93m[G]$esc[0m Build:       $esc[97m$gN$esc[0m"
        $panel[6]  = "$esc[93m[H]$esc[0m Hair Style:  $esc[97m$stN$esc[0m"
        $panel[9]  = "$esc[93m[C]$esc[0m Hair Color:  $esc[97m$hcN$esc[0m"
        $panel[12] = "$esc[93m[S]$esc[0m Skin Tone:   $esc[97m$skN$esc[0m"
        $panel[15] = "$esc[93m[O]$esc[0m Outfit:      $esc[97m$ofN$esc[0m"
        $panel[18] = "$esc[93m[R]$esc[0m Randomize"
        $panel[21] = "$esc[92m[ENTER]$esc[0m Begin your journey"
        for($cy = 0; $cy -lt 24; $cy++){
            Write-Host ("   " + $doll[$cy] + "   " + $panel[$cy])
        }
        Drain-Keys
        $k = $null
        try { $k = [Console]::ReadKey($true) } catch {
            # RawUI-only host (rare under VT): map to the same shape.
            $rk = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
            $k = @{ Key = ""; KeyChar = [char]$rk.Character }
        }
        if(-not $k){ continue }
        if((("" + $k.Key) -eq "Enter") -or ($k.KeyChar -eq [char]13)){ $done = $true; continue }
        $kc = ([string]$k.KeyChar).ToUpper()
        switch($kc){
            "G" { $ap.Gender = 1 - [int]$ap.Gender }
            "H" { $ap.HairStyle = ([int]$ap.HairStyle + 1) % $styleNames.Count }
            "C" { $ap.HairColor = ([int]$ap.HairColor + 1) % $hairsT.Count }
            "S" { $ap.Skin = ([int]$ap.Skin + 1) % $skins.Count }
            "O" { $ap.Outfit = ([int]$ap.Outfit + 1) % $outfitsT.Count }
            "R" {
                $ap.Gender = Get-Random -Minimum 0 -Maximum 2
                $ap.HairStyle = Get-Random -Minimum 0 -Maximum $styleNames.Count
                $ap.HairColor = Get-Random -Minimum 0 -Maximum $hairsT.Count
                $ap.Skin = Get-Random -Minimum 0 -Maximum $skins.Count
                $ap.Outfit = Get-Random -Minimum 0 -Maximum $outfitsT.Count
            }
            default { }
        }
    }
}

# ─── CHARACTER CREATION ──────────────────────────────────────────
function Show-CharacterSelect {
    $classes = Get-ClassTemplates
    $classOrder = @("Knight","Mage","Brawler","Ranger","Cleric","Necromancer","Berserker","Warlock")
    clr
    Write-CL "" "White"
    Write-CL "  ╔══════════════════════════════════════════════════════════════════════════╗" "DarkCyan"
    Write-CL "  ║                 D E P T H S   O F   P O W E R S H E L L                  ║" "Cyan"
    Write-CL "  ║                         Choose Your Class                                ║" "DarkCyan"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════════════╝" "DarkCyan"
    Write-Host ""

    # Arrange in a 3-row x 2-column grid:
    #   [1] Knight     [2] Mage
    #   [3] Brawler    [4] Ranger
    #   [5] Cleric     [6] Necromancer
    # (The requested "1 3 / 2 4" reads as columns, but in 2-wide layout
    #  odd indices go on the left, evens on the right, which is equivalent.)

    $colorMap = @{
        Knight      = "Yellow"
        Mage        = "Cyan"
        Brawler     = "Red"
        Ranger      = "Green"
        Cleric      = "White"
        Necromancer = "Magenta"
        Berserker   = "DarkRed"
        Warlock     = "DarkMagenta"
    }

    # Render each row as a two-up card (interior width 50 to fit full descriptions)
    $cardW = 50
    $bar   = "═" * $cardW

    for($row=0; $row -lt 4; $row++){
        $leftIdx  = $row * 2
        $rightIdx = $row * 2 + 1
        if($leftIdx -ge $classOrder.Count){ break }

        $lKey = $classOrder[$leftIdx]
        $rKey = if($rightIdx -lt $classOrder.Count){$classOrder[$rightIdx]}else{$null}
        $lC   = $classes[$lKey]
        $rC   = if($rKey){$classes[$rKey]}else{$null}
        $lCol = $colorMap[$lKey]
        $rCol = if($rKey){$colorMap[$rKey]}else{"Gray"}

        # Top border
        Write-C "  ╔$bar╗" "DarkGray"
        if($rC){ Write-CL "  ╔$bar╗" "DarkGray" } else { Write-Host "" }

        # Class title line
        $lTitle = "[$($leftIdx+1)] $($lC.Name)"
        Write-C "  ║ " "DarkGray"
        Write-C $lTitle $lCol
        $lPad = ($cardW - 1) - $lTitle.Length
        if($lPad -lt 0){$lPad=0}
        Write-C ("$(' ' * $lPad)║  ") "DarkGray"

        if($rC){
            $rTitle = "[$($rightIdx+1)] $($rC.Name)"
            Write-C "║ " "DarkGray"
            Write-C $rTitle $rCol
            $rPad = ($cardW - 1) - $rTitle.Length
            if($rPad -lt 0){$rPad=0}
            Write-CL ("$(' ' * $rPad)║") "DarkGray"
        } else {
            Write-Host ""
        }

        # Description line (no truncation — cards are wide enough)
        $lDesc = $lC.Desc
        Write-C "  ║ " "DarkGray"
        Write-C $lDesc "Gray"
        $lPad2 = ($cardW - 1) - $lDesc.Length
        if($lPad2 -lt 0){$lPad2=0}
        Write-C ("$(' ' * $lPad2)║  ") "DarkGray"

        if($rC){
            $rDesc = $rC.Desc
            Write-C "║ " "DarkGray"
            Write-C $rDesc "Gray"
            $rPad2 = ($cardW - 1) - $rDesc.Length
            if($rPad2 -lt 0){$rPad2=0}
            Write-CL ("$(' ' * $rPad2)║") "DarkGray"
        } else {
            Write-Host ""
        }

        # Stats line
        $lStats = "HP$($lC.MaxHP) MP$($lC.MaxMP) ATK$($lC.ATK) DEF$($lC.DEF) SPD$($lC.SPD) MAG$($lC.MAG)"
        Write-C "  ║ " "DarkGray"
        Write-C $lStats "DarkCyan"
        $lPad3 = ($cardW - 1) - $lStats.Length
        if($lPad3 -lt 0){$lPad3=0}
        Write-C ("$(' ' * $lPad3)║  ") "DarkGray"

        if($rC){
            $rStats = "HP$($rC.MaxHP) MP$($rC.MaxMP) ATK$($rC.ATK) DEF$($rC.DEF) SPD$($rC.SPD) MAG$($rC.MAG)"
            Write-C "║ " "DarkGray"
            Write-C $rStats "DarkCyan"
            $rPad3 = ($cardW - 1) - $rStats.Length
            if($rPad3 -lt 0){$rPad3=0}
            Write-CL ("$(' ' * $rPad3)║") "DarkGray"
        } else {
            Write-Host ""
        }

        # Affinity line
        $lAff = "Affinity: $($lC.Affinity)"
        Write-C "  ║ " "DarkGray"
        Write-C $lAff "DarkYellow"
        $lPad4 = ($cardW - 1) - $lAff.Length
        if($lPad4 -lt 0){$lPad4=0}
        Write-C ("$(' ' * $lPad4)║  ") "DarkGray"

        if($rC){
            $rAff = "Affinity: $($rC.Affinity)"
            Write-C "║ " "DarkGray"
            Write-C $rAff "DarkYellow"
            $rPad4 = ($cardW - 1) - $rAff.Length
            if($rPad4 -lt 0){$rPad4=0}
            Write-CL ("$(' ' * $rPad4)║") "DarkGray"
        } else {
            Write-Host ""
        }

        # Bottom border
        Write-C "  ╚$bar╝" "DarkGray"
        if($rC){ Write-CL "  ╚$bar╝" "DarkGray" } else { Write-Host "" }
    }

    Write-Host ""
    Write-CL "  TIP: Weapons matching your class grant bonus ATK." "DarkGray"
    Write-Host ""

    # Loop until the player gives a valid 1-8 selection. Empty input
    # (just hitting Enter) is rejected — previously this silently defaulted
    # to Knight, which surprised players.
    $pickIdx = -1
    while($pickIdx -lt 0 -or $pickIdx -ge $classOrder.Count){
        Write-C "  > " "Yellow"; $pick = Read-Host
        if([string]::IsNullOrWhiteSpace($pick)){
            Write-CL "  Please choose a class (1-$($classOrder.Count))." "Red"
            continue
        }
        $parsed = $null
        if(-not [int]::TryParse($pick.Trim(), [ref]$parsed)){
            Write-CL "  '$pick' is not a number. Choose 1-$($classOrder.Count)." "Red"
            continue
        }
        $cand = $parsed - 1
        if($cand -lt 0 -or $cand -ge $classOrder.Count){
            Write-CL "  Out of range. Choose 1-$($classOrder.Count)." "Red"
            continue
        }
        $pickIdx = $cand
    }
    $className = $classOrder[$pickIdx]
    $template = $classes[$className]

    $script:PlayerClass = $className
    $script:Player = @{
        Name      = $template.Name
        HP        = $template.HP
        MaxHP     = $template.MaxHP
        MP        = $template.MP
        MaxMP     = $template.MaxMP
        ATK       = $template.ATK
        DEF       = $template.DEF
        SPD       = $template.SPD
        MAG       = $template.MAG
        Abilities = $template.Abilities
    }
    $script:EquippedWeapon = $null
    $script:EquippedArmor = @{
        Helmet = $null
        Chest  = $null
        Shield = $null
        Amulet = $null
        Boots  = $null
    }
    $script:Gold = 50
    $script:Inventory.Clear()
    $script:Potions.Clear()
    $script:ThrowablePotions.Clear()
    [void]$script:Potions.Add(@{Name="Small Health Potion";Type="Heal";Power=30;Price=25;Desc="Restore 30 HP"})
    $script:DungeonLevel = 0
    $script:PlayerLevel = 1
    $script:XP = 0
    $script:XPToNext = 100
    $script:KillCount = 0
    $script:Partner = $null
    $script:Pet     = $null
    $script:Ingredients = @{}
    $script:ActiveFoodBuff = $null
    $script:Quests.Clear()
    $script:TrainingPoints = @{ ATK=0; DEF=0; SPD=0; MAG=0; HP=0; MP=0 }
    $script:Streak = 0
    $script:BestStreak = 0
    $script:Achievements = @{}
    $script:TotalKills = 0
    $script:BossesDefeated = 0
    $script:WeaponsOwned = @{}
    $script:ArmorOwned = @{}
    $script:OwnsDutchmanBlade = $false
    $script:CompletedQuests = 0
    $script:DailyDungeonActive = $false
    $script:Lockpicks = 5
    $script:RepairKits = 0
    $script:ExtraStrongPotions = 0
    $script:DisturbedChests = @{}
    $script:LuckTurnsLeft = 0; $script:LuckBonus = 0
    $script:Stance = "Balanced"
    # New v1.3 lifetime stat counters
    $script:TotalCrits = 0
    $script:TotalLocksPicked = 0
    $script:TotalBareKills = 0
    $script:TotalUntouched = 0
    $script:TotalStanceSwaps = 0
    $script:TotalRepairs = 0
    $script:TotalEncumbered = 0
    $script:DungeonsCleared = 0
    $script:NGPlusLevel = 0
    $script:HiddenBossDefeated = $false
    $script:Bestiary = @{}
    $script:Talents = @{}
    $script:LastStandUsed    = $false
    $script:ResurrectionUsed = $false
    $script:FinalStandUsed   = $false
    # Phase-1 foundations: fresh run starts at Day 1 with clean story,
    # skills, and corruption state.
    $script:GameDay    = 1
    $script:Corruption = 0
    $script:StoryFlags = @{}
    $script:SkillXP    = @{}
    foreach($__sk in (Get-SkillList)){ $script:SkillXP[$__sk] = 0 }
    $script:JournalPages = @{}
    $script:JournalCharm = $false
    $script:TownUpgrades = @{}
    $script:Companion = ""
    $script:RestedOnDay  = 0
    $script:DeepestFloor = 0
    $script:NemesisStage   = 0
    $script:NemesisFled    = $false
    $script:NemesisPending = $false
    $script:MigrationPending = $false
    $script:CurrentLocation = "helpdesk"
    $script:FishCastDay    = -1
    $script:FishCastsToday = 0
    $script:TotalFishCaught = 0
    $script:RaidTheme = $null
    $script:FactionRep = @{ RogueProcesses = 0; DataMiners = 0 }
    $script:GuildMembership = ""
    $script:Appearance = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 }
    $script:LayOnHandsUsed   = 0
    # Any normal character creation clears god-start flags — both
    # Debug Mode and Flying Dutchman Mode only persist for the run
    # they were activated in.
    $script:DebugMode    = $false
    $script:DutchmanMode = $false

    # Phase-1 creator: appearance picks with a live paper-doll preview.
    Show-CharacterCreator

    Write-Host ""
    Write-CL "  You are a $className. Your journey begins..." "Green"
    Wait-Key
}


# ─── DEBUG RUN (HIDDEN) ───────────────────────────────────────────
# Triggered by typing the dev passphrase at the splash menu prompt.
# Spins up a fully-stocked Cleric in town with 9999 gold so the
# developer can play-test deep systems without grinding to them.
# Mirrors the state initialization in Show-CharacterSelect, then
# overrides gold, then jumps directly into the main town loop.
# Not advertised anywhere; tutorial offer is suppressed too.
function Start-DebugRun {
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkMagenta"
    Write-CL "  ║              D E B U G   M O D E                 ║" "Magenta"
