    $script:TrainingPoints = @{ ATK=0; DEF=0; SPD=0; MAG=0; HP=0; MP=0 }
    $script:Streak = 0
    $script:BestStreak = 0
    $script:Achievements = @{}
    $script:TotalKills = 0
    $script:BossesDefeated = 0
    $script:WeaponsOwned = @{}
    $script:ArmorOwned = @{}
