    $script:TotalCrits = 0
    $script:TotalLocksPicked = 0
    $script:TotalBareKills = 0
    $script:TotalUntouched = 0
    $script:TotalStanceSwaps = 0
    $script:TotalRepairs = 0
    $script:TotalEncumbered = 0
    $script:DungeonsCleared = 0
    $script:NGPlusLevel = 0
    $script:HiddenBossDefeated = $false
    $script:Bestiary = @{}
    $script:Talents = @{}
    $script:LastStandUsed    = $false
    $script:ResurrectionUsed = $false
    $script:FinalStandUsed   = $false
    # Phase-1 foundations: fresh run starts at Day 1 with clean story,
    # skills, and corruption state.
    $script:GameDay    = 1
    $script:Corruption = 0
    $script:StoryFlags = @{}
    $script:SkillXP    = @{}
    foreach($__sk in (Get-SkillList)){ $script:SkillXP[$__sk] = 0 }
    $script:JournalPages = @{}
    $script:JournalCharm = $false
    $script:TownUpgrades = @{}
    $script:Companion = ""
    $script:RestedOnDay  = 0
    $script:DeepestFloor = 0
    $script:NemesisStage   = 0
