    $script:NemesisPending = $false
    $script:MigrationPending = $false
    $script:CurrentLocation = "helpdesk"
    $script:FishCastDay    = -1
    $script:FishCastsToday = 0
    $script:TotalFishCaught = 0
    $script:RaidTheme = $null
    $script:FactionRep = @{ RogueProcesses = 0; DataMiners = 0 }
    $script:GuildMembership = ""
    $script:Appearance = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 }
    $script:LayOnHandsUsed   = 0
    # Skip the tutorial offer — debug runs assume the dev knows the game.
    $script:TutorialSeen = $true
    # Debug-mode flag: enables the [Debug Mode Active] HUD banner in town
    # and disables Save Game so a debug-spawned god-start can't be turned
    # into a permanent save file. Cleared by Show-CharacterSelect (which
    # is the only path back to a clean run).
    $script:DebugMode = $true

    # Debug runs DO show the creator — it is the fastest way to
    # test appearance combos without replaying character select.
    Show-CharacterCreator

    Write-CL "  Ready. Press a key to enter town." "Green"
    Wait-Key

    # Jump into the main town loop. Show-MainMenu doesn't return until
    # the player quits the game, so this satisfies the splash-menu
    # caller, which uses `return` after invoking us.
    Show-MainMenu
}


# ── Hidden Flying Dutchman mode ──
# Activated by entering "Dutch26" at the splash menu's start prompt.
# Player runs as the Flying Dutchman pseudo-class with overpowered
# stats, the unique Dutchman's Blade equipped, 9999g, and four custom
# abilities. Like Debug Mode this run cannot be saved — it's a
# guaranteed-blast power fantasy.
function Start-FlyingDutchmanRun {
    clr
