        }
        Warlock = @{
            Name="Warlock"; MaxHP=72; HP=72; MaxMP=80; MP=80
            ATK=6; DEF=4; SPD=8; MAG=21
            Abilities=@(
                @{Name="Eldritch Blast"; Cost=10; Type="Magic";     Power=24; Effect="None";        Cooldown=2}
                @{Name="Hex";            Cost=12; Type="Magic";     Power=15; Effect="Weaken";      Cooldown=3}
                @{Name="Summon Imp";     Cost=18; Type="Magic";     Power=20; Effect="Burn";        Cooldown=3}
                @{Name="Dark Bargain";   Cost=0;  Type="Sacrifice"; Power=38; Effect="SacrificeHP"; Cooldown=5}
                @{Name="Firestorm";      Cost=22; Type="Magic";     Power=24; Effect="Burn";        Cooldown=3; AoE=$true}
            )
            Desc="Cursed caster bound by a fiendish pact."
            Affinity="Staff"
        }
    }
}

# ─── QUEST SYSTEM ─────────────────────────────────────────────────
function Get-RandomQuests {
    param([int]$DungeonLvl)
    $templates = @(
        @{Type="Kill";       DescTemplate="Slay {0} enemies in the dungeon";   TMin=3; TMax=7}
        @{Type="Kill";       DescTemplate="Defeat {0} foes to prove your worth"; TMin=5; TMax=10}
        @{Type="MiniBoss";   DescTemplate="Defeat the dungeon mini-boss";      TMin=1; TMax=1}
        @{Type="Boss";       DescTemplate="Defeat the dungeon boss";           TMin=1; TMax=1}
        @{Type="Rescue";     DescTemplate="Rescue the lost adventurer";        TMin=1; TMax=1}
        # New quest types added in v1.3:
        @{Type="Crit";       DescTemplate="Land {0} critical hits in combat";  TMin=3; TMax=8}
        @{Type="Lockpicker"; DescTemplate="Successfully pick {0} locks";       TMin=2; TMax=5}
        @{Type="LootHunter"; DescTemplate="Collect {0} loot items";            TMin=4; TMax=10}
        # Bug fix: the Treasure type had reward math and a chest-opening
        # progress trigger, but the template was missing — the quest
        # could never be offered.
        @{Type="Treasure";   DescTemplate="Find and open {0} treasure chests"; TMin=1; TMax=3}
        @{Type="Survivor";   DescTemplate="Reach the boss room above 50% HP";  TMin=1; TMax=1}
        @{Type="BareHands";  DescTemplate="Defeat {0} enemies bare-handed";    TMin=2; TMax=4}
        @{Type="Repair";     DescTemplate="Repair gear at the blacksmith {0} times"; TMin=1; TMax=3}
    )
    $picked = $templates | Get-Random -Count 5
    $result = [System.Collections.ArrayList]@()
    foreach($t in $picked){
        $count = Get-Random -Min $t.TMin -Max ($t.TMax + 1)
        $desc = if($t.DescTemplate -match '\{0\}'){$t.DescTemplate -f $count}else{$t.DescTemplate}
        $goldReward = switch($t.Type){
            "Kill"       { 40 + $DungeonLvl * 20 + $count * 5 }
            "MiniBoss"   { 80 + $DungeonLvl * 30 }
            "Boss"       { 150 + $DungeonLvl * 40 }
            "Rescue"     { 60 + $DungeonLvl * 25 }
            "Treasure"   { 50 + $DungeonLvl * 15 + $count * 5 }
            "Crit"       { 60 + $DungeonLvl * 20 + $count * 8 }
            "Lockpicker" { 70 + $DungeonLvl * 20 + $count * 10 }
            "LootHunter" { 40 + $DungeonLvl * 15 + $count * 6 }
            "Survivor"   { 90 + $DungeonLvl * 30 }
            "BareHands"  { 100 + $DungeonLvl * 35 + $count * 12 }
            "Repair"     { 50 + $DungeonLvl * 15 + $count * 10 }
            default      { 50 + $DungeonLvl * 20 }
        }
        $xpReward = switch($t.Type){
            "Kill"       { 30 + $DungeonLvl * 15 + $count * 5 }
            "MiniBoss"   { 60 + $DungeonLvl * 25 }
            "Boss"       { 100 + $DungeonLvl * 30 }
            "Rescue"     { 40 + $DungeonLvl * 20 }
            "Treasure"   { 25 + $DungeonLvl * 15 }
            "Crit"       { 35 + $DungeonLvl * 15 + $count * 4 }
            "Lockpicker" { 40 + $DungeonLvl * 15 + $count * 6 }
            "LootHunter" { 25 + $DungeonLvl * 12 + $count * 4 }
            "Survivor"   { 70 + $DungeonLvl * 25 }
            "BareHands"  { 80 + $DungeonLvl * 30 + $count * 10 }
            "Repair"     { 30 + $DungeonLvl * 12 + $count * 8 }
            default      { 30 + $DungeonLvl * 15 }
        }
        [void]$result.Add(@{
            Type=$t.Type; Desc=$desc; TargetCount=$count
            Progress=0; RewardGold=$goldReward; RewardXP=$xpReward
            Complete=$false; TurnedIn=$false
        })
    }
    return $result
}

function Update-QuestProgress {
    param([string]$Type, [int]$Amount = 1)
    foreach($q in $script:Quests){
        if($q.Type -eq $Type -and -not $q.Complete -and -not $q.TurnedIn){
            $q.Progress = [math]::Min($q.Progress + $Amount, $q.TargetCount)
            if($q.Progress -ge $q.TargetCount){
                $q.Complete = $true
                # Pacifist's Path mutator: when a quest is completed
                # while the mutator is active, bake the 3x XP bonus
                # into the stored reward right now. The turn-in screen
                # at the Quest Board reads RewardXP as-is and pays
                # whatever's stored. Doing it here (in-dungeon, mutator
                # active) is the only place Has-Mutator returns true
                # — by the time the player walks to town the mutator
                # has been cleared by Reset-MutatorOnEnd. We mark the
                # quest so the turn-in screen can label the bonus.
                # Scope note (reviewed): town-completed quests (e.g. a
                # Repair finished at the town blacksmith AFTER the run)
                # intentionally get NO Pacifist bonus — the rule is
                # "completed while the mutator is active." In-dungeon
                # repairs via the Wandering Smith encounter DO qualify.
                if(Has-Mutator "Pacifist" -and -not $q.PacifistBoosted){
                    $q.RewardXP        = [int]$q.RewardXP * 3
                    $q.PacifistBoosted = $true
                }
                $script:StatusMsg = "Quest complete: $($q.Desc)!"
            }
        }
    }
}

function Show-QuestBoard {
    $qbLoop = $true
    # Generate available quests if none exist yet
if(-not $script:AvailableQuests -or $script:AvailableQuests.Count -eq 0){
    $script:AvailableQuests = [System.Collections.ArrayList]@(Get-RandomQuests ($script:DungeonLevel + 1))
}

    while($qbLoop){
        clr
        Write-Host ""
        # 60-char banner
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkYellow"
        Write-CL "  ║                   Q U E S T   B O A R D                  ║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""
        # Notice board art
        Write-CL "          ___________________________          " "DarkGray"
        Write-CL "         |    |            |    |    |         " "DarkGray"
        Write-CL "         |HELP| ADVENTURER |GOLD|FAME|         " "DarkYellow"
        Write-CL "         | !  |  WANTED!!  | `$`$ | ** |         " "Yellow"
        Write-CL "         |____|____________|____|____|         " "DarkGray"
        Write-CL "         |         QUEST              |         " "DarkGray"
        Write-CL "         |         BOARD              |         " "DarkYellow"
        Write-CL "         |____________________________|         " "DarkGray"
        Write-Host ""
        Write-Host ""
        # ── Event notice (Cat 12): the board reacts to the calendar ──
        switch(Get-ActiveRadiantEvent){
            "GoblinHorde" { Write-CL "  !! BOUNTY: the GOBLIN WARCHIEF leads the horde below —" "Red"
                            Write-CL "     200g rides on its head. Today only." "Red" }
            "Plague"      { Write-CL "  !! NOTICE: Inn beds QUARANTINED; potion prices +50%" "Red"
                            Write-CL "     until the blight passes." "Red" }
            "BloodMoon"   { Write-CL "  !! OMEN: the moon is red. The undead walk thick — and" "Red"
                            Write-CL "     are worth DOUBLE, tonight only." "Red" }
        }
        Write-Host ""

        # ── Story/side integration (user): saved quests render INSIDE
        # the active block below; these notes frame them.
        $bMq = Get-CurrentMainQuest
        $bSt = Get-MainStage
        $sqActiveAny = $false
        foreach($sqLoc in @("backupvale","bashford","cronmarch","nullhaven","foreachfalls","cachegrove","firewallkeep","syslogxing","kernelhold","registry","terminus","sysv")){
            $sqTmp = Get-TownQuest $sqLoc
            if($sqTmp){
                $sqStT = Get-QuestStage $sqTmp.Id
                if($sqStT -ge 100000 -and $sqStT -ne 999999){ $sqActiveAny = $true; break }
            }
        }
        if($bSt -eq 0){
            Write-CL "  A trail waits — press [!] below to begin the story." "Yellow"
            Write-Host ""
        }
        if(($bSt -gt 0 -and $bMq) -or $sqActiveAny){
            Write-CL "  (! story and * side quests are saved with your character)" "DarkGray"
            Write-Host ""
        }
        # ── Active Quests (60 wide / 56 interior) ──
        $bar = "═" * 56
        Write-CL "  ╔$bar╗" "DarkCyan"
        Write-C "  ║ " "DarkCyan"; Write-C "A C T I V E   Q U E S T S" "Cyan"
        $aHdr = "A C T I V E   Q U E S T S"
        $aPad = 55 - $aHdr.Length
        Write-CL ("$(' ' * $aPad)║") "DarkCyan"
        Write-CL "  ╠$bar╣" "DarkCyan"
        $anyActiveRow = $false
        if($bMq -and $bSt -gt 0){
            $anyActiveRow = $true
            $bPhase = $bSt % 10
            if($bPhase -eq 0){
                $bWhere = if($bMq.Where -eq "town"){"Helpdesk"}else{ (Get-WorldLocation $bMq.Where).Name }
                $bRow = " ! $($bMq.Title) — the trail leads to $bWhere"
            } else {
                $bProg = Get-MainQuestProgress $bMq
                if($bProg -lt 0){ $bProg = 0 }
                if($bProg -gt $bMq.Need){ $bProg = $bMq.Need }
                # v1.6.2: story quests ADVANCE at [!], not at the board's
                # [T] turn-in — say so when one is ready instead of
                # letting the row imply a turn-in that never comes.
                $bTag = if($bProg -ge $bMq.Need){ " — READY at [!]" } else { "" }
                $bRow = " ! $($bMq.Title) — $bProg/$($bMq.Need)$bTag"
            }
            if($bRow.Length -gt 55){ $bRow = $bRow.Substring(0, 55) }
            $bPad = 55 - $bRow.Length
            Write-C "  ║" "DarkCyan"; Write-C $bRow "Red"
            Write-CL ("$(' ' * $bPad)║") "DarkCyan"
        }
        foreach($sqLoc in @("backupvale","bashford","cronmarch","nullhaven","foreachfalls","cachegrove","firewallkeep","syslogxing","kernelhold","registry","terminus","sysv")){
            $sq = Get-TownQuest $sqLoc
            if(-not $sq){ continue }
            $sqSt = Get-QuestStage $sq.Id
            if($sqSt -ge 100000 -and $sqSt -ne 999999){
                $anyActiveRow = $true
                $sqTown = (Get-WorldLocation $sqLoc).Name
                $sRow = " * $($sq.Name) ($sqTown)"
                if($sRow.Length -gt 55){ $sRow = $sRow.Substring(0, 55) }
                $sPad = 55 - $sRow.Length
                Write-C "  ║" "DarkCyan"; Write-C $sRow "Magenta"
                Write-CL ("$(' ' * $sPad)║") "DarkCyan"
            }
        }
        # v1.6.2: only claim the board is empty when NOTHING is listed
        # — an active story or side quest already fills the box.
        if($script:Quests.Count -eq 0 -and -not $anyActiveRow){
            $msg = " No quests active. Grab a bounty below!"
            $msgPad = 55 - $msg.Length
            Write-C "  ║" "DarkCyan"; Write-C $msg "DarkGray"
            Write-CL ("$(' ' * $msgPad)║") "DarkCyan"
        } elseif($script:Quests.Count -gt 0){
            for($i=0;$i -lt $script:Quests.Count;$i++){
                $q = $script:Quests[$i]
                $statusIcon = if($q.TurnedIn){"[DONE]"}elseif($q.Complete){"[READY]"}else{"[$($q.Progress)/$($q.TargetCount)]"}
                $statusColor = if($q.TurnedIn){"DarkGray"}elseif($q.Complete){"Green"}else{"Yellow"}
                $desc = $q.Desc
                # Truncate at 44 chars with ellipsis to leave room for status + padding
                $maxDesc = 44
                if($desc.Length -gt $maxDesc){ $desc = $desc.Substring(0, $maxDesc - 3) + "..." }
                $fullLine = " $statusIcon $desc"
                $qPad = 55 - $fullLine.Length
                if($qPad -lt 0){$qPad = 0}
                Write-C "  ║" "DarkCyan"
                Write-C " $statusIcon" $statusColor
                Write-C " $desc" "White"
                Write-CL ("$(' ' * $qPad)║") "DarkCyan"
            }
        }
        Write-CL "  ╚$bar╝" "DarkCyan"
        Write-Host ""

        # ── Available Quests (same 60/56 width) ──
        Write-CL "  ╔$bar╗" "DarkGreen"
        Write-C "  ║ " "DarkGreen"; Write-C "T O W N   B O U N T I E S" "Green"
        $vHdr = "T O W N   B O U N T I E S"
        $vPad = 55 - $vHdr.Length
        Write-CL ("$(' ' * $vPad)║") "DarkGreen"
        Write-CL "  ╠$bar╣" "DarkGreen"
        $avail = @($script:AvailableQuests | Where-Object { -not $_.TurnedIn })
        if($avail.Count -eq 0){
            $m1 = " No quests available. Enter a dungeon and"
            $m2 = " come back later!"
            Write-C "  ║" "DarkGreen"; Write-C $m1 "DarkGray"
            Write-CL ("$(' ' * (55 - $m1.Length))║") "DarkGreen"
            Write-C "  ║" "DarkGreen"; Write-C $m2 "DarkGray"
            Write-CL ("$(' ' * (55 - $m2.Length))║") "DarkGreen"
        } else {
            for($i=0;$i -lt $avail.Count;$i++){
                $q = $avail[$i]
                $desc = $q.Desc
                $maxD = 48
                if($desc.Length -gt $maxD){ $desc = $desc.Substring(0, $maxD - 3) + "..." }
                $line1 = " [$($i+1)] $desc"
                $p1 = 55 - $line1.Length
                if($p1 -lt 0){$p1 = 0}
                Write-C "  ║" "DarkGreen"
                Write-C " [$($i+1)] " "White"
                Write-C $desc "Green"
                Write-CL ("$(' ' * $p1)║") "DarkGreen"

                $line2 = "     Reward: $($q.RewardGold)g + $($q.RewardXP) XP"
                $p2 = 55 - $line2.Length
                if($p2 -lt 0){$p2 = 0}
                Write-C "  ║" "DarkGreen"
                Write-C $line2 "Yellow"
                Write-CL ("$(' ' * $p2)║") "DarkGreen"
            }
        }
        Write-CL "  ╚$bar╝" "DarkGreen"
        Write-Host ""

        # ── Options menu (interior 44) ──
        $obar = "─" * 44
        Write-CL "  ┌$obar┐" "DarkGray"
        $optRows = @(
            @{N="[A]"; C="Green";   L="Accept a quest"}
            @{N="[T]"; C="Yellow";  L="Turn in all completed"}
            @{N="[R]"; C="DarkCyan";L="Refresh available quests (free)"}
            @{N="[!]"; C="Red";     L="Story — view or advance the trail"}
            @{N="[*]"; C="Magenta"; L="Side quests — view details"}
            @{N="[0]"; C="White";   L="Back"}
        )
        foreach($o in $optRows){
            $full = " $($o.N) $($o.L)"
            $pp = 42 - $full.Length
            if($pp -lt 0){$pp = 0}
            Write-C "  │" "DarkGray"
            Write-C " $($o.N)" $o.C
            Write-C " $($o.L)" "White"
            Write-CL ("$(' ' * $pp) │") "DarkGray"
        }
        Write-CL "  └$obar┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $qCh = Read-Host

        switch($qCh.ToUpper()){
            "!" {
                # The story driver is the same screen the town's [!]
                # mark opens — it shows the beat, and advances the
                # quest itself when its goal is met.
                Show-StoryQuest -Context "town"
            }
            "*" {
                # (user) Detail view for active town side quests. The
                # board row only shows names; this card adds giver,
                # town, and the objective per quest Type.
                $svSides = @()
                foreach($svLoc in @("backupvale","bashford","cronmarch","nullhaven","foreachfalls","cachegrove","firewallkeep","syslogxing","kernelhold","registry","terminus","sysv")){
                    $svSq = Get-TownQuest $svLoc
                    if(-not $svSq){ continue }
                    $svSt = Get-QuestStage $svSq.Id
                    if($svSt -ge 100000 -and $svSt -ne 999999){
                        $svSides += @{ Q = $svSq; Loc = $svLoc }
                    }
                }
                clr
                Write-Host ""
                Write-CL "  ╔═════════════════════════════════════════════════╗" "DarkMagenta"
                Write-CL "  ║             S I D E   Q U E S T S                ║" "Magenta"
                Write-CL "  ╚═════════════════════════════════════════════════╝" "DarkMagenta"
                Write-Host ""
                if($svSides.Count -eq 0){
                    Write-CL "  No side quests active. Townsfolk marked [*] across the" "DarkGray"
                    Write-CL "  province have work for you." "DarkGray"
                    Write-Host ""
                } else {
                    foreach($svS in $svSides){
                        $svQ = $svS.Q
                        $svTown = (Get-WorldLocation $svS.Loc).Name
                        $svTarget = ""
                        if([string]$svQ.Type -eq "Deliver" -and $svQ.Target){
                            $svTarget = (Get-WorldLocation $svQ.Target).Name
                        }
                        $svObj = switch([string]$svQ.Type){
                            "Collect" { "Bring $($svQ.Need)x $($svQ.ItemName)." }
                            "Kill"    { "Slay $($svQ.Need) monsters in the Depths." }
                            "Clear"   { "Clear $($svQ.Need) dungeon runs." }
                            "Fish"    { "Catch $($svQ.Need) fish." }
                            "Deliver" { "Deliver a parcel to $svTarget within $($svQ.Days) days." }
                            default   { "Ask $($svQ.Giver) for the particulars." }
                        }
                        Write-C "  * " "Magenta"
                        Write-CL $svQ.Name "Yellow"
                        Write-CL "      From $($svQ.Giver) of $svTown." "Gray"
                        Write-CL "      $svObj" "White"
                        Write-CL "      Advance or turn in at the [*] in $svTown." "DarkGray"
                        Write-Host ""
                    }
                }
                Wait-Enter
            }
            "A" {
                if($script:Quests.Count -ge 5){
                    Write-CL "  You can only hold 5 quests at a time!" "Red"
                    Wait-Key
                } elseif($avail.Count -eq 0){
                    Write-CL "  No quests to accept!" "Red"
                    Wait-Key
                } else {
                    Write-C "  Accept quest #: " "Yellow"; $qPick = Read-Host
                    $qIdx = (ConvertTo-SafeInt -Value $qPick) - 1
                    if($qIdx -ge 0 -and $qIdx -lt $avail.Count){
                        $accepted = $avail[$qIdx]
                        [void]$script:Quests.Add($accepted)
                        $script:AvailableQuests.Remove($accepted)
                        Write-CL "  Quest accepted: $($accepted.Desc)" "Green"
                        Wait-Key
                    }
                }
            }
            "T" {
                $ready = @($script:Quests | Where-Object { $_.Complete -and -not $_.TurnedIn })
                if($ready.Count -eq 0){
                    Write-CL "  No completed board quests to turn in!" "Red"
                    Write-CL "  (Story quests advance at [!], not here.)" "DarkGray"
                    Read-Host "  [Press Enter to continue]" | Out-Null
                } else {
                    Write-Host ""
                    Write-CL "  ╔════════════════════════════════════════════╗" "Yellow"
                    Write-CL "  ║   TURNING IN $($ready.Count.ToString().PadRight(2)) COMPLETED QUEST(S)         ║" "Yellow"
                    Write-CL "  ╚════════════════════════════════════════════╝" "Yellow"
                    Write-Host ""

                    $totalGold = 0
                    $totalXP   = 0
                    $totalBardBonus = 0
                    $isBard = ($script:Partner -and $script:Partner.Class -eq "Bard")

                    foreach($rq in $ready){
                        $rq.TurnedIn = $true
                        $script:CompletedQuests++
                        $totalGold += $rq.RewardGold
                        $thisXP = $rq.RewardXP
                        if($isBard){
                            $bonus = [math]::Floor($rq.RewardXP * 0.25)
                            $totalBardBonus += $bonus
                            $thisXP += $bonus
                        }
                        # Pacifist's Path: if this quest was completed
                        # while Pacifist was active, RewardXP was already
                        # tripled at completion time (see Update-QuestProgress).
                        # The turn-in display just needs to label it.
                        $pacTag = if($rq.PacifistBoosted){"  (Pacifist x3)"}else{""}
                        $totalXP += $thisXP
                        Write-CL "  ✓ $($rq.Desc)" "Green"
                        Write-CL "    + $($rq.RewardGold)g, + $thisXP XP$pacTag" "DarkGray"
                        $script:Quests.Remove($rq) | Out-Null
                    }

                    if($script:CompletedQuests -ge 10){
                        Try-UnlockAchievement "QuestGiver"
                    }

                    $script:Gold += $totalGold
                    $script:XP   += $totalXP

                    Write-Host ""
                    Write-CL "  ──────────────────────────────────────────" "DarkGray"
                    Write-CL "  TOTAL: + $totalGold Gold, + $totalXP XP" "Yellow"
                    if($isBard -and $totalBardBonus -gt 0){
                        Write-CL "    ($($script:Partner.Name): +$totalBardBonus bonus XP)" "DarkCyan"
                    }

                    # Level-up check via Grant-XP (Phase 6 extraction):
                    # this path previously used a lighter clone and now
                    # gains the talent/tier notices for free.
                    Grant-XP
                    Write-Host ""
                    Read-Host "  [Press Enter to continue]" | Out-Null
                }
            }
            "R" {
                $script:AvailableQuests = [System.Collections.ArrayList]@(Get-RandomQuests ($script:DungeonLevel + 1))
                Write-CL "  New quests posted!" "Green"
                Wait-Key
            }
            "0" { $qbLoop = $false }
        }
    }
}


