# Returns all potions and throwables in a FIXED ORDER (index 0-9).
# Save/Load uses these indices to store which potions the player has.
# Index 0-6 = regular potions, index 7-9 = throwable potions.
function Get-PotionShop {
    @(
        @{Name="Small Health Potion"; Type="Heal";        Power=30; Price=25; Desc="Restore 30 HP";     Category="Potion"}
        @{Name="Large Health Potion"; Type="Heal";        Power=70; Price=60; Desc="Restore 70 HP";     Category="Potion"}
        @{Name="Mana Potion";         Type="Mana";        Power=30; Price=30; Desc="Restore 30 MP";     Category="Potion"}
        @{Name="Large Mana Potion";   Type="Mana";        Power=60; Price=55; Desc="Restore 60 MP";     Category="Potion"}
        @{Name="Strength Elixir";     Type="ATKBuff";     Power=8;  Price=75; Desc="ATK+8 in battle";   Category="Potion"}
        @{Name="Iron Skin Elixir";    Type="DEFBuff";     Power=8;  Price=75; Desc="DEF+8 in battle";   Category="Potion"}
        @{Name="Potion of Luck";      Type="Luck";        Power=20; Price=90; Desc="+20% crit, 3 turns"; Category="Potion"}
        @{Name="Acid Flask";          Type="Throw";       Power=40; Price=60; Desc="Deal 40 damage";    Category="Throwable"}
        @{Name="Poison Flask";        Type="ThrowPoison"; Power=25; Price=70; Desc="25 dmg + Poison";   Category="Throwable"}
        @{Name="Frost Bomb";          Type="ThrowSlow";   Power=20; Price=55; Desc="20 dmg + Slow";     Category="Throwable"}
        @{Name="Bomb";                Type="Throw";       Power=75; Price=140;Desc="Deal 75 damage";    Category="Throwable"}
        # ── SPECIAL: dungeon-clear drops only, never sold in shops ──
        # Filter on Category="Potion" excludes these from market/merchant
        # listings. They sit in the regular potion bag with weight 1.
        @{Name="Extra Strong Health Potion";   Type="Heal";    Power=200; Price=0; Desc="Restore 200 HP";        Category="Special"}
        @{Name="Extra Strong Mana Potion";     Type="Mana";    Power=150; Price=0; Desc="Restore 150 MP";        Category="Special"}
        @{Name="Extra Strong Strength Elixir"; Type="ATKBuff"; Power=20;  Price=0; Desc="ATK+20 in battle";      Category="Special"}
        @{Name="Extra Strong Luck Potion";     Type="Luck";    Power=50;  Price=0; Desc="+50% crit, 5 turns";    Category="Special"}
    )
}

# ─── SAVE / LOAD SYSTEM ──────────────────────────────────────────

function Save-Game {
    $p = $script:Player

    # ── Convert inventory loot to gold ──
    $lootGold = 0
    foreach($item in $script:Inventory){ $lootGold += $item.Value }
    $totalGold = $script:Gold + $lootGold

    # ── Class index (0-5) ──
    $classOrder = @("Knight","Mage","Brawler","Ranger","Cleric","Necromancer","Berserker","Warlock")
    $classIdx = 0
    for($i = 0; $i -lt $classOrder.Count; $i++){
        if($classOrder[$i] -eq $script:PlayerClass){ $classIdx = $i; break }
    }

    # ── Weapon index: 0 = none, 1-N = shop position, 999 = Dutchman's Blade ──
    $weapIdx = 0
    if($script:EquippedWeapon){
        if($script:EquippedWeapon.Name -eq "Dutchman's Blade"){
            $weapIdx = 999
        } else {
            $weapons = Get-WeaponShop
            for($i = 0; $i -lt $weapons.Count; $i++){
                if($weapons[$i].Name -eq $script:EquippedWeapon.Name){
                    $weapIdx = $i + 1
                    break
                }
            }
            # Exclusive stock (Phase 6): indices 1000+ reference the
            # append-only Get-ExclusiveStock table positions.
            if($weapIdx -eq 0){
                $exL = @(Get-ExclusiveStock)
                for($i = 0; $i -lt $exL.Count; $i++){
                    if($exL[$i].Item.Name -eq $script:EquippedWeapon.Name){ $weapIdx = 1000 + $i; break }
                }
            }
        }
    }

    # ── Armor indices ──
    $allArmor = Get-ArmorShop
    $armorSlots = @("Helmet","Chest","Shield","Amulet","Boots")
    $armorIndices = @(0, 0, 0, 0, 0)
    for($s = 0; $s -lt $armorSlots.Count; $s++){
        $piece = $script:EquippedArmor[$armorSlots[$s]]
        if($piece){
            for($i = 0; $i -lt $allArmor.Count; $i++){
                if($allArmor[$i].Name -eq $piece.Name){
                    $armorIndices[$s] = $i + 1
                    break
                }
            }
            # Exclusive stock (Phase 6): 1000+ = exclusive table position.
            if($armorIndices[$s] -eq 0){
                $exL = @(Get-ExclusiveStock)
                for($i = 0; $i -lt $exL.Count; $i++){
                    if($exL[$i].Item.Name -eq $piece.Name){ $armorIndices[$s] = 1000 + $i; break }
                }
            }
        }
    }

    # ── Potion counts (v6: 7 regular + 4 throwable + 4 special). Special
    # potions (Extra Strong) live in the regular potion bag but were
    # excluded from saves before v6, silently disappearing on save/load.
    $potShop = Get-PotionShop
    $potCounts     = @(0, 0, 0, 0, 0, 0, 0)
    $throwCounts   = @(0, 0, 0, 0)
    $specialCounts = @(0, 0, 0, 0)   # ES Health, ES Mana, ES Strength, ES Luck

    foreach($pot in $script:Potions){
        $matched = $false
        # Regular (indices 0..6)
        for($i = 0; $i -lt 7; $i++){
            if($pot.Name -eq $potShop[$i].Name){
                $potCounts[$i]++
                $matched = $true
                break
            }
        }
        # Special (indices 11..14) — same bag, distinct slot in save format
        if(-not $matched){
            for($i = 11; $i -lt 15; $i++){
                if($pot.Name -eq $potShop[$i].Name){
                    $specialCounts[$i - 11]++
                    break
                }
            }
        }
    }
    foreach($tp in $script:ThrowablePotions){
        for($i = 7; $i -lt 11; $i++){
            if($tp.Name -eq $potShop[$i].Name){
                $throwCounts[$i - 7]++
                break
            }
        }
    }

    # ── Partner: 0=none, 1=Healer, 2=Thief, 3=Bard ──
    $partnerIdx = 0
    if($script:Partner){
        switch($script:Partner.Class){
            "Healer" { $partnerIdx = 1 }
            "Thief"  { $partnerIdx = 2 }
            "Bard"   { $partnerIdx = 3 }
        }
    }

    # ── v2 additions ──
    # Achievement bitmask — iterate the list in order; '1' if unlocked, '0' otherwise
    $achList = Get-AchievementList
    $achBits = ""
    foreach($a in $achList){
        if($script:Achievements.ContainsKey($a.Id)){ $achBits += "1" } else { $achBits += "0" }
    }
    # Training points joined "ATK,DEF,SPD,MAG,HP,MP"
    $tp = $script:TrainingPoints
    $trainStr = "$($tp.ATK),$($tp.DEF),$($tp.SPD),$($tp.MAG),$($tp.HP),$($tp.MP)"
    $dutchFlag = if($script:OwnsDutchmanBlade){1}else{0}
    $dailyDone = if($script:DailyDungeonDone){1}else{0}
    $tutSeen   = if($script:TutorialSeen){1}else{0}

    # ── Build save string: version "3" = durability-aware format ──
    # Serialize durability of each equipped piece as "weapon,helmet,chest,shield,amulet,boots"
    # Each value is "cur/max", or "-1" for none-equipped, or "X" for indestructible (Dutchman's Blade).
    $durParts = @()
    if($script:EquippedWeapon){
        if($script:EquippedWeapon.MaxDurability -lt 0){
            $durParts += "X"  # indestructible
        } elseif($script:EquippedWeapon.ContainsKey("Durability")){
            $durParts += "$($script:EquippedWeapon.Durability)/$($script:EquippedWeapon.MaxDurability)"
        } else {
            $durParts += "-1"
        }
    } else {
        $durParts += "-1"
    }
    foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
        $piece = $script:EquippedArmor[$slot]
        if($piece -and $piece.ContainsKey("Durability")){
            $durParts += "$($piece.Durability)/$($piece.MaxDurability)"
        } else {
            $durParts += "-1"
        }
    }
    $durStr = $durParts -join ","

    $saveStr = @(
        "9"                          # [0]  format version (v9: adds extensible key-value field)
        $classIdx                    # [1]  class
        $script:PlayerLevel          # [2]  level
        $script:XP                   # [3]  current XP
        $script:XPToNext             # [4]  XP to next level
        $totalGold                   # [5]  gold (loot converted)
        $p.HP                        # [6]  current HP
        $p.MaxHP                     # [7]  max HP
        $p.MP                        # [8]  current MP
        $p.MaxMP                     # [9]  max MP
        $p.ATK                       # [10] ATK
        $p.DEF                       # [11] DEF
        $p.SPD                       # [12] SPD
        $p.MAG                       # [13] MAG
        $script:DungeonLevel         # [14] dungeon level
        $script:KillCount            # [15] kills (quest counter)
        $script:RoyalSuiteUses       # [16] royal suite uses
        $weapIdx                     # [17] weapon
        ($armorIndices -join ",")    # [18] armor "h,c,s,a,b"
        ($potCounts -join ",")       # [19] potion counts (7)
        ($throwCounts -join ",")     # [20] throwable counts (4)
        $partnerIdx                  # [21] partner
        # ── v2 extensions ──
        0                            # [22] streak (always saved as 0)
        $script:BestStreak           # [23]
        $script:TotalKills           # [24]
        $script:BossesDefeated       # [25]
        $achBits                     # [26] achievement bitmask
        $trainStr                    # [27] training points
        $dutchFlag                   # [28] owns Dutchman's Blade
        $script:DailyDungeonDate     # [29] daily dungeon date
        $dailyDone                   # [30] daily done flag
        $tutSeen                     # [31] tutorial seen
        $script:Lockpicks            # [32] lockpick count
        # ── v3 extension ──
        $durStr                      # [33] durability "weapon,helmet,chest,shield,amulet,boots"
        # ── v3 extension ──
        "$($script:RepairKits),$($script:ExtraStrongPotions)"  # [34] special items (legacy ESP counter)
        $script:Stance               # [35] combat stance ("Aggressive"/"Balanced"/"Defensive")
        # ── v5 extension: lifetime stat counters (drives new achievements) ──
        # Single packed field to keep the format compact: comma-separated.
        "$($script:TotalCrits),$($script:TotalLocksPicked),$($script:TotalBareKills),$($script:TotalUntouched),$($script:TotalStanceSwaps),$($script:TotalRepairs),$($script:CompletedQuests)"  # [36]
        # ── v6 extension: ES potion counts in bag (Health,Mana,Strength,Luck) ──
        ($specialCounts -join ",")   # [37]
        # ── v6 extension: more lifetime counters added in this batch ──
        "$($script:DungeonsCleared),$($script:TotalEncumbered)"  # [38]
        # ── v7 extension: pet ("Hound"/"Raven"/"Falcon" or "") ──
        $(if($script:Pet){$script:Pet.Type}else{""})  # [39]
        # ── v7 extension: NG+ level (Pass 2 feature) and hidden-boss flag ──
        "$(if($script:NGPlusLevel){$script:NGPlusLevel}else{0}),$(if($script:HiddenBossDefeated){1}else{0})"  # [40]
        # ── v7 extension: cooking ingredients "Mushroom,Herb,Meat,Bone" ──
        "$(if($script:Ingredients.Mushroom){[int]$script:Ingredients.Mushroom}else{0}),$(if($script:Ingredients.Herb){[int]$script:Ingredients.Herb}else{0}),$(if($script:Ingredients.Meat){[int]$script:Ingredients.Meat}else{0}),$(if($script:Ingredients.Bone){[int]$script:Ingredients.Bone}else{0})"  # [41]
        # ── v7 extension: bestiary, encoded as "key:count" pairs joined by ';' ──
        # ActiveFoodBuff intentionally omitted — buffs reset on dungeon
        # transitions, so saving the player in town would clear them anyway.
        $(
            $bestPairs = @()
            foreach($k in $script:Bestiary.Keys){
                $cnt = $script:Bestiary[$k].Kills
                # Strip semicolons and pipes from keys defensively (variant
                # names are clean but defense in depth never hurts).
                $cleanK = ($k -replace '[;\|:]', '_')
                $bestPairs += "${cleanK}:${cnt}"
            }
            $bestPairs -join ";"
        )  # [42]
        # ── v7 extension: talents — semicolon-joined list of purchased IDs ──
        $(
            $tIds = @()
            if($script:Talents){
                foreach($k in $script:Talents.Keys){
                    if($script:Talents[$k] -eq 1){
                        $tIds += ($k -replace '[;\|:]', '_')
                    }
                }
            }
            $tIds -join ";"
        )  # [43]
        # ── v8 extension: settings (Difficulty,AutoLoot,AutoResize) ──
        # Difficulty as "E"/"M"/"H"; bools as 1/0. Compact comma-joined.
        $(
            $diffCode = switch([string]$script:Settings.Difficulty){
                "Easy"   { "E" }
                "Hard"   { "H" }
                default  { "M" }
            }
            $alStr = if($script:Settings.AutoLoot){"1"}else{"0"}
            $arStr = if($script:Settings.AutoResize){"1"}else{"0"}
            # 4th value (v1.5): renderer choice A/C/R. Older parsers read
            # only the first three, so appending stays backward-compatible.
            $rcCode = switch([string]$script:Settings.Renderer){
                "Classic" { "C" }
                "Raycast" { "R" }
                default   { "A" }
            }
            # 5th + 6th values (v1.6): FPS counter flag and turn-speed
            # percent. Same append-only discipline — old parsers stop
            # at what they know, old saves load defaults.
            $fpsCode = if($script:Settings.ShowFPS -ne $false){"1"}else{"0"}
            $rotCode = "100"
            try { if($script:Settings.RotSpeed){ $rotCode = [string][int]$script:Settings.RotSpeed } } catch {}
            "$diffCode,$alStr,$arStr,$rcCode,$fpsCode,$rotCode"
        )  # [44]
        # ── v9 extension: extensible key-value store ──
        # Format: KEY:value pairs joined by ';'. Parsers ignore unknown
        # keys, so future systems (factions, guilds, nemesis, world
        # position, town upgrades...) add keys here WITHOUT bumping the
        # format version again. Reserved separators: '|' (top level),
        # ';' (pair), ':' (key/value), ',' (value-internal list),
        # '.' (subvalue). None may appear inside values.
        #   GD = in-game day (int)
        #   CR = corruption 0-100 (int)
        #   SF = story flags, "questId.stage" comma list (may be empty)
        #   SK = skill XP, positional comma list per Get-SkillList order
        #   JN = journal pages collected (Cat 7), comma list of page ints
        #   JC = journal charm awarded (0/1)
        #   WE = enchanter weapon perk: Perk,Chance (equipped weapon only)
        #   AS = armor sockets: Slot=Gem_Name pairs (underscores = spaces)
        #   TU = town upgrades owned, comma list of Forge/Inn
        #   RD = GameDay of the last day-advancing rest (nap-spam cap)
        #   DF = deepest dungeon floor reached (personal best)
        #   NM = nemesis: stage 0-3, fled flag (0/1)
        #   WL = current world location id
        #   FC = lifetime successful fishing hauls
        #   FR = faction rep: RogueProcesses,DataMiners (-100..100)
        #   GM = guild membership id (sysadmins/datathieves/cabal)
        #   AP = appearance: gender,skin,hairstyle,haircolor,outfit
        #        (creator; outfit is the 5th field, absent pre-outfit)
        $(
            $kv = @()
            $kv += "GD:$([int]$script:GameDay)"
            $kv += "ZT:$(if($script:Settings.ZoneTheme -ne $false){1}else{0})"
            $kv += "CR:$([int]$script:Corruption)"
            $sfPairs = @()
            if($script:StoryFlags){
                foreach($k in $script:StoryFlags.Keys){
                    $cleanId = ($k -replace '[^A-Za-z0-9_]', '')
                    if($cleanId){
                        $sfPairs += "$cleanId.$([int]$script:StoryFlags[$k])"
                    }
                }
            }
            $kv += "SF:$($sfPairs -join ',')"
            $skVals = @()
            foreach($sk in (Get-SkillList)){
                $v = 0
                if($script:SkillXP -and $script:SkillXP.ContainsKey($sk)){
                    $v = [int]$script:SkillXP[$sk]
                }
                $skVals += $v
            }
            $kv += "SK:$($skVals -join ',')"
            $jnList = @()
            if($script:JournalPages){
                foreach($jpKey in ($script:JournalPages.Keys | Sort-Object)){ $jnList += [int]$jpKey }
            }
            $kv += "JN:$($jnList -join ',')"
            $kv += "JC:$(if($script:JournalCharm){1}else{0})"
            # Enchanter (Phase 4c): only enchanter-made perks persist —
            # shop-native perks rebuild from the table by themselves.
            if($script:EquippedWeapon -and $script:EquippedWeapon.EnchantedPerk){
                $kv += "WE:$($script:EquippedWeapon.Perk),$($script:EquippedWeapon.PerkChance)"
            }
            $asList = @()
            foreach($sockSlot in @("Helmet","Chest","Shield","Amulet","Boots")){
                $sockP = $script:EquippedArmor[$sockSlot]
                if($sockP -and $sockP.SocketGem){ $asList += "$sockSlot=$($sockP.SocketGem -replace ' ','_')" }
            }
            if($asList.Count -gt 0){ $kv += "AS:$($asList -join ',')" }
            $tuList = @()
            foreach($tuKey in @("Forge","Inn")){
                if($script:TownUpgrades[$tuKey]){ $tuList += $tuKey }
            }
            if($tuList.Count -gt 0){ $kv += "TU:$($tuList -join ',')" }
            $kv += "RD:$([int]$script:RestedOnDay)"
            $kv += "DF:$([int]$script:DeepestFloor)"
            $kv += "NM:$([int]$script:NemesisStage),$(if($script:NemesisFled){1}else{0})"
            $kv += "WL:$($script:CurrentLocation)"
            $kv += "FC:$([int]$script:TotalFishCaught)"
            $kv += "FR:$([int]$script:FactionRep['RogueProcesses']),$([int]$script:FactionRep['DataMiners'])"
            if($script:Companion){ $kv += "CM:$($script:Companion)" }
            if($script:GuildMembership){ $kv += "GM:$($script:GuildMembership)" }
            if($script:Appearance){
                $apG = [int]$script:Appearance.Gender
                $apS = [int]$script:Appearance.Skin
                $apH = [int]$script:Appearance.HairStyle
                $apC = [int]$script:Appearance.HairColor
                $apO = [int]$script:Appearance.Outfit
                $kv += "AP:$apG,$apS,$apH,$apC,$apO"
            }
            $kv -join ';'
        )  # [45]
    ) -join "|"

    # ── Checksum ──
    $sum = 0
    foreach($char in $saveStr.ToCharArray()){ $sum += [int]$char }
    $checksum = $sum % 9999
    $saveStr += "|$checksum"

    # ── Base64 encode ──
    $bytes = [System.Text.Encoding]::UTF8.GetBytes($saveStr)
    $code = [Convert]::ToBase64String($bytes)

    return $code
}


function Load-Game {
    param([string]$Code)

    # ── Try to decode the Base64 string back into text ──
    # If the player typed garbage, this will fail, so we use try/catch.
    try {
        $bytes = [Convert]::FromBase64String($Code)
        $saveStr = [System.Text.Encoding]::UTF8.GetString($bytes)
    } catch {
        return @{ Success = $false; Error = "Invalid save code format." }
    }

    # ── Split into parts ──
    $parts = $saveStr -split '\|'
    $ver = $parts[0]
    # Only v4, v5, and v6 accepted. v1/v2 predate durability; v3 predates
    # the inventory weight system. v4 = inventory weight; v5 = lifetime
    # stat counters; v6 = ES potion bag entries + DungeonsCleared/TotalEncumbered.
    if($ver -eq "1" -or $ver -eq "2" -or $ver -eq "3"){
        return @{ Success = $false; Error = "This save is from an older version and can't be loaded. The inventory weight update requires a new character." }
    }
    if($ver -ne "4" -and $ver -ne "5" -and $ver -ne "6" -and $ver -ne "7" -and $ver -ne "8" -and $ver -ne "9"){
        return @{ Success = $false; Error = "Unknown save format version '$ver'." }
    }
    # Accepted lengths (parts including checksum):
    #   v4 with stance:    37  (36 data + 1 checksum)
    #   v4 without stance: 36  (legacy v4)
    #   v5:                38  (37 data + 1 checksum)
    #   v6:                40  (39 data + 1 checksum)
    #   v7:                45  (44 data + 1 checksum, includes talents)
    #   v8:                46  (45 data + 1 checksum, adds settings)
    $expectedLen = $parts.Count
    $validLen = switch($ver){
        "4" { @(36, 37) -contains $expectedLen }
        "5" { $expectedLen -eq 38 }
        "6" { $expectedLen -eq 40 }
        "7" { $expectedLen -eq 45 }
        "8" { $expectedLen -eq 46 }
        "9" { $expectedLen -eq 47 }
    }
    if(-not $validLen){
        return @{ Success = $false; Error = "Save code is corrupted (wrong length for v$ver)." }
    }

    # ── Verify checksum ──
    $dataEnd = $expectedLen - 2
    $dataStr = ($parts[0..$dataEnd]) -join "|"
    $sum = 0
    foreach($char in $dataStr.ToCharArray()){ $sum += [int]$char }
    $expectedCheck = $sum % 9999
    $actualCheck = [int]$parts[$expectedLen - 1]
    if($expectedCheck -ne $actualCheck){
        return @{ Success = $false; Error = "Checksum mismatch. Code may have a typo." }
    }

    # ── Parse core fields (shared between v1 and v2) ──
    $classIdx       = [int]$parts[1]
    $playerLevel    = [int]$parts[2]
    $xp             = [int]$parts[3]
    $xpToNext       = [int]$parts[4]
    $gold           = [int]$parts[5]
    $hp             = [int]$parts[6]
    $maxHP          = [int]$parts[7]
    $mp             = [int]$parts[8]
    $maxMP          = [int]$parts[9]
    $atk            = [int]$parts[10]
    $def            = [int]$parts[11]
    $spd            = [int]$parts[12]
    $mag            = [int]$parts[13]
    $dungeonLevel   = [int]$parts[14]
    $killCount      = [int]$parts[15]
    $royalSuiteUses = [int]$parts[16]
    $weapIdx        = [int]$parts[17]
    $armorParts     = $parts[18] -split ','
    $potParts       = $parts[19] -split ','
    $throwParts     = $parts[20] -split ','
    $partnerIdx     = [int]$parts[21]

    # ── Validate class ──
    $classOrder = @("Knight","Mage","Brawler","Ranger","Cleric","Necromancer","Berserker","Warlock")
    if($classIdx -lt 0 -or $classIdx -ge $classOrder.Count){
        return @{ Success = $false; Error = "Invalid class in save." }
    }
    $className = $classOrder[$classIdx]

    # ── Rebuild the player ──
    $classes = Get-ClassTemplates
    $template = $classes[$className]
    $script:PlayerClass = $className
    $script:Player = @{
        Name      = $template.Name
        HP        = $hp
        MaxHP     = $maxHP
        MP        = $mp
        MaxMP     = $maxMP
        ATK       = $atk
        DEF       = $def
        SPD       = $spd
        MAG       = $mag
        Abilities = $template.Abilities
    }
    $script:PlayerLevel    = $playerLevel
    $script:XP             = $xp
    $script:XPToNext       = $xpToNext
    $script:Gold           = $gold
    $script:DungeonLevel   = $dungeonLevel
    $script:KillCount      = $killCount
    $script:RoyalSuiteUses = $royalSuiteUses

    # ── Rebuild weapon ──
    # 999 = Dutchman's Blade (special handling)
    $script:EquippedWeapon = $null
    if($weapIdx -eq 999){
        $dutch = @{
            Name="Dutchman's Blade"; ATK=100; Price=10000; WeaponType="Sword"
            ClassAffinity="None"; AffinityBonus=0; Perk="Drain"; PerkChance=40
        }
        $script:EquippedWeapon = Init-ItemDurability $dutch
        $script:OwnsDutchmanBlade = $true
    } elseif($weapIdx -ge 1000){
        # Exclusive stock (Phase 6)
        $exL = @(Get-ExclusiveStock)
        if(($weapIdx - 1000) -lt $exL.Count){
            $script:EquippedWeapon = Init-ItemDurability $exL[$weapIdx - 1000].Item
        }
    } elseif($weapIdx -gt 0){
        $weapons = Get-WeaponShop
        if($weapIdx -le $weapons.Count){
            $script:EquippedWeapon = Init-ItemDurability $weapons[$weapIdx - 1]
        }
    }

    # ── Rebuild armor ──
    $script:EquippedArmor = @{
        Helmet = $null; Chest = $null; Shield = $null
        Amulet = $null; Boots = $null
    }
    $allArmor = Get-ArmorShop
    $armorSlots = @("Helmet","Chest","Shield","Amulet","Boots")
    for($s = 0; $s -lt $armorSlots.Count; $s++){
        $aIdx = [int]$armorParts[$s]
        if($aIdx -ge 1000){
            # Exclusive stock (Phase 6)
            $exL = @(Get-ExclusiveStock)
            if(($aIdx - 1000) -lt $exL.Count){
                $script:EquippedArmor[$armorSlots[$s]] = Init-ItemDurability $exL[$aIdx - 1000].Item
            }
        }
        elseif($aIdx -gt 0 -and $aIdx -le $allArmor.Count){
            $script:EquippedArmor[$armorSlots[$s]] = Init-ItemDurability $allArmor[$aIdx - 1]
        }
    }

    # ── Rebuild potions (v3: 7 regular, 3 throwables) ──
    $script:Potions = [System.Collections.ArrayList]@()
    $script:ThrowablePotions = [System.Collections.ArrayList]@()
    $potShop = Get-PotionShop

    for($i = 0; $i -lt 7; $i++){
        if($i -ge $potParts.Count){ break }
        $count = [int]$potParts[$i]
        for($c = 0; $c -lt $count; $c++){
            [void]$script:Potions.Add($potShop[$i])
        }
    }
    # Throwables: v4 saves had 3; v5 may have 4 (Bomb added). The split
    # gives whatever count the save used; iterate up to that count.
    for($i = 0; $i -lt 4; $i++){
        if($i -ge $throwParts.Count){ break }
        $count = [int]$throwParts[$i]
        for($c = 0; $c -lt $count; $c++){
            [void]$script:ThrowablePotions.Add($potShop[$i + 7])
        }
    }

    # ── Rebuild partner ──
    $script:Partner = $null
    if($partnerIdx -gt 0){
        $partnerData = @(
            @{ Name="Sister Maren";  Class="Healer"; Desc="Heals you when HP drops below 50%" }
            @{ Name="Fingers McGee"; Class="Thief";  Desc="+15% gold from enemy defeats" }
            @{ Name="Lyric the Wise"; Class="Bard";  Desc="+25% XP from all sources" }
        )
        if($partnerIdx -le $partnerData.Count){
            $script:Partner = $partnerData[$partnerIdx - 1]
        }
    }

    # ── v3 extended fields ──
    # Streak is read but discarded — always fresh on load by design
    $script:Streak         = 0
    $script:BestStreak     = [int]$parts[23]
    $script:TotalKills     = [int]$parts[24]
    $script:BossesDefeated = [int]$parts[25]

    # Achievement bitmask
    $script:Achievements = @{}
    $achBits = $parts[26]
    $achList = Get-AchievementList
    for($i = 0; $i -lt $achList.Count; $i++){
        if($i -lt $achBits.Length -and $achBits[$i] -eq '1'){
            $script:Achievements[$achList[$i].Id] = $true
        }
    }

    # Training points
    $trainStr = $parts[27]
    $trainParts = $trainStr -split ','
    if($trainParts.Count -eq 6){
        $script:TrainingPoints = @{
            ATK = [int]$trainParts[0]
            DEF = [int]$trainParts[1]
            SPD = [int]$trainParts[2]
            MAG = [int]$trainParts[3]
            HP  = [int]$trainParts[4]
            MP  = [int]$trainParts[5]
        }
    }
    if([int]$parts[28] -eq 1){ $script:OwnsDutchmanBlade = $true }
    $script:DailyDungeonDate = $parts[29]
    $script:DailyDungeonDone = ([int]$parts[30] -eq 1)
    $script:TutorialSeen     = ([int]$parts[31] -eq 1)
    $script:Lockpicks        = [int]$parts[32]
    $script:DisturbedChests  = @{}

    # Durability: "weapon,helmet,chest,shield,amulet,boots" each as "cur/max", "X", or "-1"
    $durParts = $parts[33] -split ','
    function _Apply-DurParse {
        param($Item, [string]$Raw)
        if(-not $Item){ return }
        if($Raw -eq "X"){
            # Indestructible (Dutchman's Blade)
            $Item.MaxDurability = -1
            return
        }
        if($Raw -eq "-1"){
            # No durability tracking (shouldn't happen on v3 for equipped items, but safe)
            $max = Get-MaxDurability $Item
            $Item.MaxDurability = $max
            $Item.Durability    = $max
            return
        }
        $bits = $Raw -split '/'
        if($bits.Count -eq 2){
            $Item.Durability    = [int]$bits[0]
            $Item.MaxDurability = [int]$bits[1]
        }
    }
    if($script:EquippedWeapon){
        _Apply-DurParse -Item $script:EquippedWeapon -Raw $durParts[0]
    }
    $slotOrder = @("Helmet","Chest","Shield","Amulet","Boots")
    for($si=0; $si -lt $slotOrder.Count; $si++){
        $piece = $script:EquippedArmor[$slotOrder[$si]]
        if($piece){
            _Apply-DurParse -Item $piece -Raw $durParts[$si + 1]
        }
    }

    # ── Special items (field [34]): "repairKits,extraStrongPotions" ──
    # Repair Kits remain as a counter (weightless). The legacy ESP counter
    # is migrated to bag potions: each old ES is split between Health and
    # Mana variants and added to the regular Potions bag. If they don't
    # all fit, leftovers convert to gold (200g each — same scale as the
    # new drop-overflow logic).
    $script:RepairKits = 0
    $legacyEspCount    = 0
    $specialParts = $parts[34] -split ','
    if($specialParts.Count -ge 2){
        $script:RepairKits = [int]$specialParts[0]
        $legacyEspCount    = [int]$specialParts[1]
    }
    # Migrate legacy ESPs into bag potions. Alternate Health/Mana so the
    # player gets a useful mix.
    if($legacyEspCount -gt 0){
        $espShop = Get-PotionShop | Where-Object { $_.Category -eq "Special" }
        for($em = 0; $em -lt $legacyEspCount; $em++){
            $template = $espShop[$em % $espShop.Count]
            # Bag-weight check: each potion is 1 wt
            $curWt = Get-CurrentCarryWeight
            $maxWt = Get-MaxCarryWeight
            if(($curWt + 1) -le $maxWt){
                [void]$script:Potions.Add($template)
            } else {
                # Bag full — give gold instead (200g each, slightly under drop range)
                $script:Gold += 200
            }
        }
    }
    # The old ESP counter is no longer used at runtime. Keep at 0 so any
    # stale references log nothing.
    $script:ExtraStrongPotions = 0

    # ── Stance (field [35]): "Aggressive"/"Balanced"/"Defensive" ──
    # Older v4 saves predate the stance field; default to Balanced.
    $script:Stance = "Balanced"
    if($parts.Count -ge 37){
        $loadedStance = $parts[35]
        if($loadedStance -in @("Aggressive","Balanced","Defensive")){
            $script:Stance = $loadedStance
        }
    }

    # ── Lifetime stat counters (field [36], v5+): comma-separated.
    # Older v4 saves don't have this field — counters reset to 0.
    # Order: Crits, LocksPicked, BareKills, Untouched, StanceSwaps, Repairs, CompletedQuests
    $script:TotalCrits       = 0
    $script:TotalLocksPicked = 0
    $script:TotalBareKills   = 0
    $script:TotalUntouched   = 0
    $script:TotalStanceSwaps = 0
    $script:TotalRepairs     = 0
    # CompletedQuests stays whatever was already loaded (or 0 if not set)
    if($parts.Count -ge 38){
        try {
            $countersStr = $parts[36]
            $countersArr = $countersStr -split ","
            if($countersArr.Count -ge 6){
                $script:TotalCrits       = [int]$countersArr[0]
                $script:TotalLocksPicked = [int]$countersArr[1]
                $script:TotalBareKills   = [int]$countersArr[2]
                $script:TotalUntouched   = [int]$countersArr[3]
                $script:TotalStanceSwaps = [int]$countersArr[4]
                $script:TotalRepairs     = [int]$countersArr[5]
            }
            if($countersArr.Count -ge 7){
                $script:CompletedQuests = [int]$countersArr[6]
            }
        } catch {
            # Malformed counters — leave at 0, don't fail the whole load
        }
    }

    # ── ES potion bag (field [37], v6+): "h,m,s,l" counts.
    # Order: Health, Mana, Strength, Luck. Adds the matching templates
    # to $script:Potions. v4/v5 saves don't have this field — ES potions
    # for those players come back via the legacy migration in field [34].
    if($parts.Count -ge 40 -and ($ver -eq "6" -or $ver -eq "7" -or $ver -eq "8" -or $ver -eq "9")){
        try {
            $specialStr = $parts[37]
            $specialArr = $specialStr -split ","
            if($specialArr.Count -ge 4){
                $espShop = Get-PotionShop | Where-Object { $_.Category -eq "Special" }
                # Order in PotionShop: Health(0), Mana(1), Strength(2), Luck(3)
                for($si = 0; $si -lt 4; $si++){
                    $count = [int]$specialArr[$si]
                    for($c = 0; $c -lt $count; $c++){
                        [void]$script:Potions.Add($espShop[$si])
                    }
                }
            }
        } catch {
            # Malformed — skip silently
        }
    }

    # ── Lifetime cleared / encumbered counters (field [38], v6+).
    $script:DungeonsCleared = 0
    $script:TotalEncumbered = 0
    if($parts.Count -ge 40 -and ($ver -eq "6" -or $ver -eq "7" -or $ver -eq "8" -or $ver -eq "9")){
        try {
            $extraStr = $parts[38]
            $extraArr = $extraStr -split ","
            if($extraArr.Count -ge 1){ $script:DungeonsCleared = [int]$extraArr[0] }
            if($extraArr.Count -ge 2){ $script:TotalEncumbered = [int]$extraArr[1] }
        } catch {}
    }

    # ── v7+ fields (also present in v8) ──
    $script:Pet = $null
    $script:NGPlusLevel = 0
    $script:HiddenBossDefeated = $false
    $script:Ingredients = @{}
    $script:Bestiary    = @{}
    $script:ActiveFoodBuff = $null
    if(($ver -eq "7" -or $ver -eq "8" -or $ver -eq "9") -and $parts.Count -ge 44){
        # [39] pet
        try {
            $petStr = $parts[39]
            if($petStr -in @("Hound","Raven","Falcon")){
                $petDescs = @{
                    Hound  = "Reveals chests on the minimap regardless of fog"
                    Raven  = "+5% gold from all sources"
                    Falcon = "Minimap reveal radius increased (5 -> 8)"
                }
                $script:Pet = @{ Type=$petStr; Desc=$petDescs[$petStr] }
            }
        } catch {}
        # [40] NG+ level + hidden boss flag
        try {
            $ngArr = $parts[40] -split ","
            if($ngArr.Count -ge 1){ $script:NGPlusLevel = [int]$ngArr[0] }
            if($ngArr.Count -ge 2){ $script:HiddenBossDefeated = ([int]$ngArr[1] -eq 1) }
        } catch {}
        # [41] ingredients
        try {
            $ingArr = $parts[41] -split ","
            if($ingArr.Count -ge 4){
                $script:Ingredients = @{
                    Mushroom = [int]$ingArr[0]
                    Herb     = [int]$ingArr[1]
                    Meat     = [int]$ingArr[2]
                    Bone     = [int]$ingArr[3]
                }
            }
        } catch {}
        # [42] bestiary
        try {
            $bestStr = $parts[42]
            if($bestStr){
                foreach($pair in ($bestStr -split ";")){
                    if(-not $pair){ continue }
                    $kv = $pair -split ":"
                    if($kv.Count -eq 2){
                        $script:Bestiary[$kv[0]] = @{ Kills = [int]$kv[1]; FirstSeen = $false }
                    }
                }
            }
        } catch {}
        # [43] talents — semicolon-joined list of talent IDs
        $script:Talents = @{}
        try {
            $talStr = $parts[43]
            if($talStr){
                foreach($tid in ($talStr -split ";")){
                    if($tid){ $script:Talents[$tid] = 1 }
                }
            }
        } catch {}
    }

    # ── v8 settings (Difficulty, AutoLoot, AutoResize) ──
    # Only present in v8+. Older saves leave the in-memory defaults
    # untouched so a v7 load doesn't reset them mid-session.
    if(($ver -eq "8" -or $ver -eq "9") -and $parts.Count -ge 45){
        try {
            $sStr = $parts[44]
            $sArr = $sStr -split ","
            if($sArr.Count -ge 1){
                $script:Settings.Difficulty = switch([string]$sArr[0]){
                    "E" { "Easy" }
                    "H" { "Hard" }
                    default { "Medium" }
                }
            }
            if($sArr.Count -ge 2){ $script:Settings.AutoLoot   = ($sArr[1] -eq "1") }
            if($sArr.Count -ge 3){ $script:Settings.AutoResize = ($sArr[2] -eq "1") }
            if($sArr.Count -ge 4){
                $script:Settings.Renderer = switch([string]$sArr[3]){
                    "C" { "Classic" }
                    "R" { "Raycast" }
                    default { "Auto" }
                }
            }
            if($sArr.Count -ge 5){ $script:Settings.ShowFPS = ($sArr[4] -ne "0") }
            if($sArr.Count -ge 6){
                $rotLoad = 0
                if([int]::TryParse([string]$sArr[5], [ref]$rotLoad) -and $rotLoad -ge 25 -and $rotLoad -le 300){
                    $script:Settings.RotSpeed = $rotLoad
                } else {
                    $script:Settings.RotSpeed = 100
                }
            }
            # If the player saved with auto-resize on, honor it now.
            if($script:Settings.AutoResize){ Try-AutoResizeTerminal }
        } catch {}
    }

    # ── v9 extensible key-value field ──
    # Pre-v9 saves get clean defaults (Day 1, 0 corruption, no story
    # progress, fresh skills). Unknown keys are IGNORED by design so
    # future systems can add keys without breaking older game builds.
    $script:GameDay    = 1
    $script:Corruption = 0
    $script:StoryFlags = @{}
    $script:SkillXP    = @{}
    foreach($sk in (Get-SkillList)){ $script:SkillXP[$sk] = 0 }
    $script:JournalPages = @{}
    $script:JournalCharm = $false
    $script:TownUpgrades = @{}
    $script:Companion = ""
    $script:RestedOnDay  = 0
    $script:DeepestFloor = 0
    $script:NemesisStage   = 0
    $script:NemesisFled    = $false
    $script:NemesisPending = $false
    $script:MigrationPending = $false
    $script:CurrentLocation = "helpdesk"
    $script:FishCastDay    = -1
    $script:FishCastsToday = 0
    $script:TotalFishCaught = 0
    $script:RaidTheme = $null
    $script:FactionRep = @{ RogueProcesses = 0; DataMiners = 0 }
    $script:GuildMembership = ""
    $script:Appearance = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 }
    if($ver -eq "9" -and $parts.Count -ge 46){
        try {
            $extStr = $parts[45]
            foreach($pair in ($extStr -split ';')){
                $kvSplit = $pair -split ':', 2
                if($kvSplit.Count -lt 2){ continue }
                $key = $kvSplit[0]
                $val = $kvSplit[1]
                switch($key){
                    "ZT" {
                        $script:Settings.ZoneTheme = ([string]$val -ne "0")
                    }
                    "GD" {
                        $gd = 0
                        if([int]::TryParse([string]$val, [ref]$gd) -and $gd -ge 1){
                            $script:GameDay = $gd
                        }
                    }
                    "CR" {
                        $cr = 0
                        if([int]::TryParse([string]$val, [ref]$cr)){
                            $script:Corruption = [math]::Max(0, [math]::Min(100, $cr))
                        }
                    }
                    "SF" {
                        if($val){
                            foreach($sfPair in ($val -split ',')){
                                $sfSplit = $sfPair -split '\.', 2
                                if($sfSplit.Count -eq 2){
                                    $stage = 0
                                    if([int]::TryParse([string]$sfSplit[1], [ref]$stage) -and $sfSplit[0]){
                                        $script:StoryFlags[$sfSplit[0]] = $stage
                                    }
                                }
                            }
                        }
                    }
                    "SK" {
                        $skillNames = @(Get-SkillList)
                        $skillVals  = $val -split ','
                        for($si = 0; $si -lt $skillNames.Count -and $si -lt $skillVals.Count; $si++){
                            $sxp = 0
                            if([int]::TryParse([string]$skillVals[$si], [ref]$sxp) -and $sxp -ge 0){
                                $script:SkillXP[$skillNames[$si]] = $sxp
                            }
                        }
                    }
                    "JN" {
                        if($val){
                            $jpMax = @(Get-JournalPages).Count
                            foreach($jpStr in ($val -split ',')){
                                $jpNum = 0
                                if([int]::TryParse([string]$jpStr, [ref]$jpNum) -and $jpNum -ge 1 -and $jpNum -le $jpMax){
                                    $script:JournalPages[$jpNum] = $true
                                }
                            }
                        }
                    }
                    "JC" {
                        if($val -eq "1"){ $script:JournalCharm = $true }
                    }
                    "WE" {
                        # Equipment was rebuilt (by shop index) earlier in
                        # Load-Game, so the weapon exists to re-enchant.
                        if($val -and $script:EquippedWeapon){
                            $weParts = $val -split ','
                            if($weParts.Count -ge 1 -and $weParts[0]){
                                $script:EquippedWeapon.Perk = [string]$weParts[0]
                                $weCh = 15
                                if($weParts.Count -ge 2){ [void][int]::TryParse([string]$weParts[1], [ref]$weCh) }
                                if($weCh -lt 1 -or $weCh -gt 100){ $weCh = 15 }
                                $script:EquippedWeapon.PerkChance = $weCh
                                $script:EquippedWeapon.EnchantedPerk = $true
                            }
                        }
                    }
                    "AS" {
                        if($val){
                            foreach($asPair in ($val -split ',')){
                                $asKV = $asPair -split '=',2
                                if($asKV.Count -ne 2){ continue }
                                $asGem = [string]$asKV[1] -replace '_',' '
                                if($asGem -notin @("Gem Shard","Ruby Chunk","Enchanted Dust","Shadow Gem")){ continue }
                                $asPiece = $script:EquippedArmor[[string]$asKV[0]]
                                if($asPiece){ $asPiece.SocketGem = $asGem }
                            }
                        }
                    }
                    "TU" {
                        if($val){
                            foreach($tuStr in ($val -split ',')){
                                if($tuStr -in @("Forge","Inn")){ $script:TownUpgrades[$tuStr] = $true }
                            }
                        }
                    }
                    "RD" {
                        $rdVal = 0
                        if([int]::TryParse([string]$val, [ref]$rdVal) -and $rdVal -ge 0){
                            $script:RestedOnDay = $rdVal
                        }
                    }
                    "DF" {
                        $dfVal = 0
                        if([int]::TryParse([string]$val, [ref]$dfVal) -and $dfVal -ge 0){
                            $script:DeepestFloor = $dfVal
                        }
                    }
                    "NM" {
                        if($val){
                            $nmParts = $val -split ','
                            $nmStage = 0
                            if([int]::TryParse([string]$nmParts[0], [ref]$nmStage) -and $nmStage -ge 0 -and $nmStage -le 3){
                                $script:NemesisStage = $nmStage
                            }
                            if($nmParts.Count -ge 2 -and $nmParts[1] -eq "1"){ $script:NemesisFled = $true }
                        }
                    }
                    "WL" {
                        if($val -and (Get-WorldLocation ([string]$val))){
                            $script:CurrentLocation = [string]$val
                        }
                    }
                    "FC" {
                        $fcVal = 0
                        if([int]::TryParse([string]$val, [ref]$fcVal) -and $fcVal -ge 0){
                            $script:TotalFishCaught = $fcVal
                        }
                    }
                    "CM" {
                        if($val -in @("rp","dm")){ $script:Companion = $val }
                    }
                    "FR" {
                        if($val){
                            $frParts = $val -split ','
                            $frRP = 0; $frDM = 0
                            if($frParts.Count -ge 1 -and [int]::TryParse([string]$frParts[0], [ref]$frRP)){
                                $script:FactionRep["RogueProcesses"] = [math]::Max(-100, [math]::Min(100, $frRP))
                            }
                            if($frParts.Count -ge 2 -and [int]::TryParse([string]$frParts[1], [ref]$frDM)){
                                $script:FactionRep["DataMiners"] = [math]::Max(-100, [math]::Min(100, $frDM))
                            }
                        }
                    }
                    "GM" {
                        if([string]$val -in @("sysadmins","datathieves","cabal")){
                            $script:GuildMembership = [string]$val
                        }
                    }
                    "AP" {
                        # gender 0-1, skin 0-5, style 0-3, color 0-7,
                        # outfit 0-7 (maxes mirror the creator palette
                        # tables; 4-field pre-outfit codes load fine).
                        if($val){
                            $apParts = $val -split ','
                            $apInts = @(0, 2, 0, 0, 0)
                            $apMax  = @(1, 5, 3, 7, 7)
                            for($apI = 0; $apI -lt 5 -and $apI -lt $apParts.Count; $apI++){
                                $apV = 0
                                if([int]::TryParse([string]$apParts[$apI], [ref]$apV)){
                                    $apInts[$apI] = [math]::Max(0, [math]::Min($apMax[$apI], $apV))
                                }
                            }
                            $script:Appearance = @{
                                Gender = $apInts[0]; Skin = $apInts[1]
                                HairStyle = $apInts[2]; HairColor = $apInts[3]
                                Outfit = $apInts[4]
                            }
                        }
                    }
                    default { }   # unknown key: ignore (forward compat)
                }
            }
        } catch {}
    }

    # ── Reset transient state ──
    $script:Inventory = [System.Collections.ArrayList]@()
    $script:Quests = [System.Collections.ArrayList]@()
    $script:AvailableQuests = $null
    $script:HasBossKey = $false
    $script:BossDefeated = $false
    $script:Dungeon = $null
    $script:DungeonKills = 0
    $script:DungeonTreasures = 0
    $script:RescueTarget = $null
    $script:LuckTurnsLeft = 0; $script:LuckBonus = 0
    # Loading any save clears god-start flags — Debug and Dutchman runs
    # can't save, so any save that exists is a legitimate run.
    $script:DebugMode    = $false
    $script:DutchmanMode = $false

    return @{ Success = $true; Error = "" }
}


