# ─── TRAINING GROUNDS ─────────────────────────────────────────────
function Show-TrainingGrounds {
    $loop = $true
    while($loop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════════╗" "DarkRed"
        Write-CL "  ║              T H E   T R A I N I N G   G R O U N D S                ║" "Red"
        Write-CL "  ║                    'Hone your skills — for a price.'                ║" "DarkRed"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════════╝" "DarkRed"
        Write-Host ""
        Write-CL "           _____                 ╱|  ╱|" "DarkGray"
        Write-CL "          |_____|__          ___| |_| |__" "DarkGray"
        Write-CL "         /|     |  \        /    \___/   \" "DarkYellow"
        Write-CL "        / |  X  |   \      /    <  o  >   \" "Red"
        Write-CL "       /__|_____|____\    /__________________\" "DarkGray"
        Write-CL "        ||     ||           |  DUMMY  ||WEAPON|" "DarkGray"
        Write-CL "        ||     ||           |_________||______|" "DarkGray"
        Write-Host ""

        $p = $script:Player
        # Inner box width: 66 chars between │ and │
        Write-CL "  ┌──────────────────────────────────────────────────────────────────┐" "DarkGray"
        Write-C  "  │  Gold: " "DarkGray"
        Write-C "$($script:Gold)g" "Yellow"
        $afterGold = "  Gold: $($script:Gold)g"
        $padNeeded = 66 - $afterGold.Length
        if($padNeeded -lt 0){ $padNeeded = 0 }
        Write-C ("$(' ' * $padNeeded)") "DarkGray"
        Write-CL "│" "DarkGray"
        # Description rows — each must be exactly 66 chars wide between the pipes
        $desc1 = "  Training teaches your body to bear more, hit harder, move"
        $desc2 = "  faster. Each bump costs more than the last. Max +10 per stat."
        Write-C  "  │" "DarkGray"; Write-C $desc1.PadRight(66) "DarkGray"; Write-CL "│" "DarkGray"
        Write-C  "  │" "DarkGray"; Write-C $desc2.PadRight(66) "DarkGray"; Write-CL "│" "DarkGray"
        Write-CL "  └──────────────────────────────────────────────────────────────────┘" "DarkGray"
        Write-Host ""

        $stats = @(
            @{Key="ATK"; Label="Strength (ATK)";    Gain=2; Color="Red"}
            @{Key="DEF"; Label="Toughness (DEF)";   Gain=2; Color="Cyan"}
            @{Key="SPD"; Label="Agility (SPD)";     Gain=1; Color="Green"}
            @{Key="MAG"; Label="Focus (MAG)";       Gain=2; Color="Magenta"}
            @{Key="HP";  Label="Vitality (MaxHP)";  Gain=8; Color="DarkRed"}
            @{Key="MP";  Label="Willpower (MaxMP)"; Gain=5; Color="DarkCyan"}
        )
        Write-CL "  ┌─────┬────────────────────────┬───────────┬──────────┬──────────┐" "DarkGray"
        Write-CL "  │  #  │ Stat                   │ Trained   │ Next +   │ Cost     │" "DarkGray"
        Write-CL "  ├─────┼────────────────────────┼───────────┼──────────┼──────────┤" "DarkGray"
        for($i=0; $i -lt $stats.Count; $i++){
            $s = $stats[$i]
            $current = $script:TrainingPoints[$s.Key]
            $cost = Get-TrainingCost $s.Key
            $costStr = if($cost -lt 0){"MAXED"}else{"$($cost)g"}
            $trainStr = "+$current / +10"
            $nextStr  = if($cost -lt 0){"--"}else{"+$($s.Gain)"}
            $affordable = if($cost -lt 0){"DarkGray"}elseif($script:Gold -ge $cost){"Green"}else{"DarkGray"}
            Write-C "  │ " "DarkGray"
            Write-C " $($i+1) " $affordable
            Write-C "│ " "DarkGray"
            Write-C $s.Label.PadRight(23) $s.Color
            Write-C "│ " "DarkGray"
            Write-C $trainStr.PadRight(10) "White"
            Write-C "│ " "DarkGray"
            Write-C $nextStr.PadRight(9) "Yellow"
            Write-C "│ " "DarkGray"
            Write-C $costStr.PadRight(9) $affordable
            Write-CL "│" "DarkGray"
        }
        Write-CL "  └─────┴────────────────────────┴───────────┴──────────┴──────────┘" "DarkGray"
        Write-Host ""
        Write-CL "  [0] Leave the training grounds" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $ch = Read-Host
        if($ch -eq "0"){ $loop = $false; continue }
        $idx = (ConvertTo-SafeInt -Value $ch) - 1
        if($idx -lt 0 -or $idx -ge $stats.Count){ continue }
        $s = $stats[$idx]
        $cost = Get-TrainingCost $s.Key
        if($cost -lt 0){
            Write-CL "  That stat is already maxed." "Yellow"
            Wait-Key; continue
        }
        if($script:Gold -lt $cost){
            Write-CL "  Not enough gold. The trainer crosses her arms." "Red"
            Wait-Key; continue
        }
        $script:Gold -= $cost
        $script:TrainingPoints[$s.Key]++
        switch($s.Key){
            "ATK" { $p.ATK += $s.Gain }
            "DEF" { $p.DEF += $s.Gain }
            "SPD" { $p.SPD += $s.Gain }
            "MAG" { $p.MAG += $s.Gain }
            "HP"  { $p.MaxHP += $s.Gain; $p.HP = [math]::Min($p.HP + $s.Gain, $p.MaxHP) }
            "MP"  { $p.MaxMP += $s.Gain; $p.MP = [math]::Min($p.MP + $s.Gain, $p.MaxMP) }
        }
        Write-Host ""
        Write-CL "  The trainer nods approvingly." "Yellow"
        Write-CL "  +$($s.Gain) $($s.Key) (permanent)" "Green"
        Check-Achievements
        Wait-Key
    }
}

# ─── OPTIONS / SETTINGS MENU ──────────────────────────────────────
# Settings are stored as part of the save code (v8 format). Changes
# made here apply immediately to the running session. To persist them
# across runs, generate a save from town and load that save next time.
# ── Phase 4c: THE ENCHANTER ────────────────────────────────────────
# Gem currency = existing trinket loot (locked decision): Gem Shard,
# Ruby Chunk, Shadow Gem, Enchanted Dust — matched in the bag by name
# (Kind="Loot"). Enchantments and sockets live on the equipped item
# hashtables: combat already reads .Perk/.PerkChance, and socket
# bonuses feed the live stat totals, so no combat changes were needed.
# PERSISTENCE: equipment reloads BY SHOP INDEX (fresh hashtables), so
# custom work is re-applied from save keys WE (weapon perk, only when
# .EnchantedPerk marks it enchanter-made) and AS (armor sockets,
# Slot=Gem_Name pairs, spaces underscore-encoded for KV safety).
function Get-GemCount {
    param([string]$GemName)
    $n = 0
    foreach($it in $script:Inventory){
        if($it.Kind -eq "Loot" -and $it.Name -eq $GemName){ $n++ }
    }
    return $n
}

function Remove-Gems {
    param([string]$GemName, [int]$Count)
    for($g = 0; $g -lt $Count; $g++){
        $found = $null
        foreach($it in $script:Inventory){
            if($it.Kind -eq "Loot" -and $it.Name -eq $GemName){ $found = $it; break }
        }
        if($found){ [void]$script:Inventory.Remove($found) }
    }
}

# Live socket bonuses, summed over equipped armor. Small on purpose
# (seasoning): Shard +1 DEF, Ruby +2 ATK, Dust +2 MAG, Shadow +1% crit.
function Get-SocketBonus {
    param([string]$Stat)
    $total = 0
    foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
        $piece = $script:EquippedArmor[$slot]
        if(-not $piece -or -not $piece.SocketGem){ continue }
        switch($piece.SocketGem){
            "Gem Shard"      { if($Stat -eq "DEF"){  $total += 1 } }
            "Ruby Chunk"     { if($Stat -eq "ATK"){  $total += 2 } }
            "Enchanted Dust" { if($Stat -eq "MAG"){  $total += 2 } }
            "Shadow Gem"     { if($Stat -eq "CRIT"){ $total += 1 } }
        }
    }
    return $total
}

# ── Phase 4d: ARMOR SETS ───────────────────────────────────────────
# Sets are DERIVED from item names — no Set fields in the shop tables,
# and persistence is free because equipment reloads by shop index and
# sets recompute from whatever is equipped. Thresholds stack (a 3pc
# set grants both its 2pc and 3pc lines). Bonuses feed the same live
# stat choke points as skills and sockets. Seasoning-sized on purpose.
function Get-ItemSet {
    param([string]$Name)
    switch($Name){
        "Leather Cap"     { "Leather" }
        "Leather Vest"    { "Leather" }
        "Leather Boots"   { "Leather" }
        "Iron Helm"       { "Iron" }
        "Iron Shield"     { "Iron" }
        "Iron Greaves"    { "Iron" }
        "Steel Helm"      { "Steel" }
        "Steel Greaves"   { "Steel" }
        "Steel Shield"    { "Steel" }
        "Dragon Helm"     { "Dragon" }
        "Dragon Plate"    { "Dragon" }
        "Dragon Boots"    { "Dragon" }
        "Mythril Crown"   { "Mythril" }
        "Mythril Cuirass" { "Mythril" }
        "Mythril Treads"  { "Mythril" }
        default           { "" }
    }
}

# Sums active set bonuses for one stat over the equipped armor.
#   Leather: 2pc +1 SPD, 3pc +2 more SPD (total +3)
#   Iron:    2pc +1 DEF, 3pc +2 more DEF (total +3)
#   Steel:   2pc +2 DEF, 3pc +2 more DEF (total +4)
#   Dragon:  2pc +2 ATK, 3pc also +2 DEF
#   Mythril: 2pc +1 SPD and +1% crit, 3pc +1 more of each
function Get-SetBonus {
    param([string]$Stat)
    $counts = @{}
    foreach($slot in @("Helmet","Chest","Shield","Amulet","Boots")){
        $piece = $script:EquippedArmor[$slot]
        if(-not $piece){ continue }
        $setN = Get-ItemSet $piece.Name
        if($setN){
            if($counts.ContainsKey($setN)){ $counts[$setN]++ } else { $counts[$setN] = 1 }
        }
    }
    $total = 0
    foreach($setN in $counts.Keys){
        $n = $counts[$setN]
        switch($setN){
            "Leather" {
                if($n -ge 2 -and $Stat -eq "SPD"){ $total += 1 }
                if($n -ge 3 -and $Stat -eq "SPD"){ $total += 2 }
            }
            "Iron" {
                if($n -ge 2 -and $Stat -eq "DEF"){ $total += 1 }
                if($n -ge 3 -and $Stat -eq "DEF"){ $total += 2 }
            }
            "Steel" {
                if($n -ge 2 -and $Stat -eq "DEF"){ $total += 2 }
                if($n -ge 3 -and $Stat -eq "DEF"){ $total += 2 }
            }
            "Dragon" {
                if($n -ge 2 -and $Stat -eq "ATK"){ $total += 2 }
                if($n -ge 3 -and $Stat -eq "DEF"){ $total += 2 }
            }
            "Mythril" {
                if($n -ge 2 -and $Stat -eq "SPD"){  $total += 1 }
                if($n -ge 2 -and $Stat -eq "CRIT"){ $total += 1 }
                if($n -ge 3 -and $Stat -eq "SPD"){  $total += 1 }
                if($n -ge 3 -and $Stat -eq "CRIT"){ $total += 1 }
            }
        }
    }
    return $total
}

# ── Phase 4e: TOWN UPGRADES ────────────────────────────────────────
# Purchase logic for the Reinforced Forge, shared by both Blacksmith
# paths (damaged-gear menu and the pristine-gear early exit). Inn's
# Feather Beds purchase lives inline in the Inn's rest switch.
function Buy-ForgeUpgrade {
    Write-Host ""
    if($script:TownUpgrades["Forge"]){
        Write-CL "  'Forge is already reinforced, friend.'" "DarkGray"
    } elseif((Get-GemCount "Dragon Tooth") -lt 2 -or (Get-GemCount "Demon Horn") -lt 1){
        Write-CL "  'Bring me two dragon teeth and a demon horn." "DarkGray"
        Write-CL "   Then we'll talk about upgrades.'" "DarkGray"
    } else {
        Remove-Gems "Dragon Tooth" 2
        Remove-Gems "Demon Horn" 1
        $script:TownUpgrades["Forge"] = $true
        Write-CL "  The smith sets the tooth and horn into the forge bed." "Yellow"
        Write-CL "  The flame turns white. 'Now THAT is heat.'" "Yellow"
        Write-Host ""
        Write-CL "  *** Repairs now cost 25% less, permanently! ***" "Magenta"
    }
    Write-Host ""
    Read-Host "  [Press Enter to continue]" | Out-Null
}

function Show-EnchanterScreen {
    $enchLoop = $true
    while($enchLoop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkMagenta"
        Write-CL "  ║                 T H E   E N C H A N T E R                ║" "Magenta"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkMagenta"
        Write-CL "  'Hot-patching production gear since the Second Age.'" "DarkGray"
        Write-CL '                _/\_/\_/\_' 'DarkMagenta'
        Write-CL '               /  * .  *  \ ' 'Magenta'
        Write-CL '              /   _______  \ ' 'DarkMagenta'
        Write-CL '             /   | o | o |  \ ' 'Magenta'
        Write-CL '            /____|___|___|___\ ' 'DarkMagenta'
        Write-CL '              ~ hums faintly ~' 'DarkGray'
        Write-Host ""
        $shards = Get-GemCount "Gem Shard"
        $rubies = Get-GemCount "Ruby Chunk"
        $dusts  = Get-GemCount "Enchanted Dust"
        $shadows = Get-GemCount "Shadow Gem"
        Write-C  "  Gems — " "DarkGray"
        Write-C  "Shard: $shards  " "White"
        Write-C  "Ruby: $rubies  " "Red"
        Write-C  "Dust: $dusts  " "Cyan"
        Write-CL "Shadow: $shadows" "Magenta"
        Write-Host ""
        $w = $script:EquippedWeapon
        if($w){
            $perkStr = if($w.Perk){"$($w.Perk) ($($w.PerkChance)% on hit)"}else{"none"}
            Write-CL "  Weapon: $($w.Name) — perk: $perkStr" "White"
        } else {
            Write-CL "  Weapon: bare hands (nothing to enchant)" "DarkGray"
        }
        Write-Host ""
        Write-CL "  [1] Enchant weapon  (2 Gem Shards + 1 Shadow Gem)" "Yellow"
        Write-CL "      A random perk — Bleed, Burn, Poison, Drain, or Stun" "DarkGray"
        Write-CL "      at 15% proc. Perk-less weapons only; no refunds." "DarkGray"
        Write-CL "  [2] Socket a gem into armor  (1 gem)" "Yellow"
        Write-CL "      Shard +1 DEF · Ruby +2 ATK · Dust +2 MAG · Shadow +1% crit" "DarkGray"
        Write-CL "  [0] Leave" "DarkGray"
        Write-C  "  > " "Yellow"
        $ec = Read-Host
        switch($ec){
            "1" {
                Write-Host ""
                if(-not $w){
                    Write-CL "  'Enchant WHAT, exactly? Come back armed.'" "DarkGray"
                }
                elseif($w.Perk){
                    Write-CL "  'That blade already carries a charm. Stacking" "DarkGray"
                    Write-CL "   enchantments voids the warranty — and the wielder.'" "DarkGray"
                }
                elseif($shards -lt 2 -or $shadows -lt 1){
                    Write-CL "  'Payment first. Two shards, one shadow gem." "DarkGray"
                    Write-CL "   The Depths are full of both. Go shopping.'" "DarkGray"
                }
                else {
                    Remove-Gems "Gem Shard" 2
                    Remove-Gems "Shadow Gem" 1
                    $newPerk = @("Bleed","Burn","Poison","Drain","Stun") | Get-Random
                    $w.Perk = $newPerk
                    $w.PerkChance = 15
                    $w.EnchantedPerk = $true
                    Write-CL "  The gems dissolve into the steel. Runes crawl" "Gray"
                    Write-CL "  along the edge, compile, and settle." "Gray"
                    Write-Host ""
                    Write-CL "  *** $($w.Name) gains $newPerk (15% on hit)! ***" "Magenta"
                }
                Write-Host ""
                Wait-Enter
            }
            "2" {
                Write-Host ""
                $sockSlots = @("Helmet","Chest","Shield","Amulet","Boots")
                for($si = 0; $si -lt $sockSlots.Count; $si++){
                    $sp = $script:EquippedArmor[$sockSlots[$si]]
                    if($sp){
                        $sockStr = if($sp.SocketGem){" [socket: $($sp.SocketGem)]"}else{" [empty socket]"}
                        Write-CL "    [$($si+1)] $($sockSlots[$si]): $($sp.Name)$sockStr" "White"
                    } else {
                        Write-CL "    [$($si+1)] $($sockSlots[$si]): (nothing equipped)" "DarkGray"
                    }
                }
                Write-C  "    Which piece? > " "Yellow"
                $slotPick = (ConvertTo-SafeInt -Value (Read-Host)) - 1
                if($slotPick -lt 0 -or $slotPick -ge $sockSlots.Count){ continue }
                $piece = $script:EquippedArmor[$sockSlots[$slotPick]]
                if(-not $piece){
                    Write-CL "    'I can't socket air. Equip something.'" "DarkGray"
                    Wait-Enter; continue
                }
                Write-Host ""
                Write-CL "    [1] Gem Shard (+1 DEF)       — have $shards" "White"
                Write-CL "    [2] Ruby Chunk (+2 ATK)      — have $rubies" "Red"
                Write-CL "    [3] Enchanted Dust (+2 MAG)  — have $dusts" "Cyan"
                Write-CL "    [4] Shadow Gem (+1% crit)    — have $shadows" "Magenta"
                Write-C  "    Which gem? > " "Yellow"
                $gemPick = Read-Host
                $gemName = switch($gemPick){
                    "1" { "Gem Shard" }
                    "2" { "Ruby Chunk" }
                    "3" { "Enchanted Dust" }
                    "4" { "Shadow Gem" }
                    default { $null }
                }
                if(-not $gemName){ continue }
                if((Get-GemCount $gemName) -lt 1){
                    Write-Host ""
                    Write-CL "    'You're a $gemName short. Which is to say:" "DarkGray"
                    Write-CL "     you have none.'" "DarkGray"
                    Wait-Enter; continue
                }
                if($piece.SocketGem){
                    Write-Host ""
                    Write-CL "    The old $($piece.SocketGem) is pried out and" "DarkGray"
                    Write-CL "    shatters. 'No rollbacks in this trade.'" "DarkGray"
                }
                Remove-Gems $gemName 1
                $piece.SocketGem = $gemName
                Write-Host ""
                Write-CL "    *** $gemName socketed into $($piece.Name)! ***" "Magenta"
                Write-Host ""
                Wait-Enter
            }
            "0" { $enchLoop = $false }
        }
    }
}

function Show-OptionsMenu {
    $loop = $true
    while($loop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkCyan"
        Write-CL "  ║                       O P T I O N S                              ║" "Cyan"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""

        $diff = [string]$script:Settings.Difficulty
        $alOn = [bool]$script:Settings.AutoLoot
        $arOn = [bool]$script:Settings.AutoResize
        $fpsOn = ($script:Settings.ShowFPS -ne $false)
        $rotP  = 100
        try { if($script:Settings.RotSpeed){ $rotP = [int]$script:Settings.RotSpeed } } catch {}
        if($rotP -lt 25 -or $rotP -gt 300){ $rotP = 100 }

        # Difficulty row
        $diffColor = switch($diff){"Easy"{"Green"} "Hard"{"Red"} default{"Yellow"}}
        Write-C "  [1] Difficulty:  " "White"; Write-C $diff $diffColor
        $diffDesc = switch($diff){
            "Easy"   { "  (enemies -25% HP/ATK)" }
            "Hard"   { "  (enemies +25% HP/ATK)" }
            default  { "  (baseline — the game as designed)" }
        }
        Write-CL $diffDesc "DarkGray"

        # Auto-loot row
        $alStr = if($alOn){"ON "}else{"OFF"}
        $alColor = if($alOn){"Green"}else{"DarkGray"}
        Write-C "  [2] Auto-Loot:   " "White"; Write-C $alStr $alColor
        Write-CL "  (loot screen auto-takes everything that fits)" "DarkGray"

        # Terminal resize row
        $arStr = if($arOn){"ON "}else{"OFF"}
        $arColor = if($arOn){"Green"}else{"DarkGray"}
        Write-C "  [3] Auto-Resize: " "White"; Write-C $arStr $arColor
        Write-CL "  (Experimental: resize terminal to ~100x40 on game launch, may crash some terminals)" "DarkGray"

        # Renderer row (v1.5): Auto / Classic / Raycast. Auto resolves to
        # Raycast where VT (ANSI) support is detected, Classic on conhost.
        $rcPref = [string]$script:Settings.Renderer
        if(-not $rcPref){ $rcPref = "Auto" }
        $rcEff  = Get-EffectiveRenderer
        $rcColor = if($rcEff -eq "Raycast"){"Magenta"}else{"White"}
        Write-C "  [4] Renderer:    " "White"; Write-C $rcPref $rcColor
        if($rcPref -eq "Raycast" -and $rcEff -eq "Classic"){
            Write-CL "  (no VT/ANSI console support found — Classic is used)" "DarkGray"
        } elseif($rcPref -eq "Auto"){
            Write-CL "  (auto-detected: $rcEff)" "DarkGray"
        } else {
            Write-CL "  (dungeon view: classic panels or real-time 3D)" "DarkGray"
        }

        # FPS counter row (v1.6): 3D HUD frame counter, ON by default.
        $fpsStr = if($fpsOn){"ON "}else{"OFF"}
        $fpsColor = if($fpsOn){"Green"}else{"DarkGray"}
        Write-C "  [5] FPS Counter: " "White"; Write-C $fpsStr $fpsColor
        Write-CL "  (frame counter in the 3D dungeon HUD)" "DarkGray"

        # Turn speed row (v1.6): raycast camera rotation, preset cycle.
        Write-C "  [6] Turn Speed:  " "White"; Write-C "$rotP%" "Cyan"
        Write-CL "  (3D camera rotation — cycles 50/75/100/125/150%)" "DarkGray"
        # Zone visuals row (v1.6.2): themed dungeon paint on/off.
        $ztOn = ($script:Settings.ZoneTheme -ne $false)
        $ztStr = if($ztOn){"ON "}else{"OFF"}
        $ztColor = if($ztOn){"Green"}else{"DarkGray"}
        Write-C "  [7] Zone Visuals:" "White"; Write-C " $ztStr" $ztColor
        Write-CL "  (OFF = plain stone texture on every floor)" "DarkGray"
        Write-Host ""
        Write-CL "  [0] Back" "DarkGray"
        Write-Host ""
        Write-CL "  Settings are saved as part of your save code." "DarkGray"
        Write-CL "  Generate a new save from the town menu [S] to persist them." "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $optChoice = Read-Host

        switch($optChoice){
            "1" {
                # Cycle Easy -> Medium -> Hard -> Easy
                $script:Settings.Difficulty = switch($diff){
                    "Easy"   { "Medium" }
                    "Medium" { "Hard"   }
                    "Hard"   { "Easy"   }
                    default  { "Medium" }
                }
            }
            "2" {
                $script:Settings.AutoLoot = -not $alOn
            }
            "3" {
                $script:Settings.AutoResize = -not $arOn
                if($script:Settings.AutoResize){
                    Try-AutoResizeTerminal
                }
            }
            "4" {
                $script:Settings.Renderer = switch([string]$script:Settings.Renderer){
                    "Classic" { "Raycast" }
                    "Raycast" { "Auto"    }
                    default   { "Classic" }
                }
            }
            "5" {
                $script:Settings.ShowFPS = -not $fpsOn
            }
            "6" {
                $script:Settings.RotSpeed = switch($rotP){
                    50  { 75  }
                    75  { 100 }
                    100 { 125 }
                    125 { 150 }
                    default { 50 }
                }
            }
            "7" {
                $script:Settings.ZoneTheme = -not ($script:Settings.ZoneTheme -ne $false)
            }
            "0" {
                $loop = $false
            }
            default { }
        }
    }
}

# ─── ACHIEVEMENTS MENU ────────────────────────────────────────────
function Show-AchievementsMenu {
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════════╗" "DarkMagenta"
    Write-CL "  ║                      A C H I E V E M E N T S                         ║" "Magenta"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════════╝" "DarkMagenta"
    Write-Host ""
    $list = Get-AchievementList
    $unlocked = $script:Achievements.Count
    $total = $list.Count
    Write-CL "  Progress: $unlocked / $total  ($([math]::Floor($unlocked * 100 / $total))%)" "Yellow"
    Write-Host ""
    foreach($ach in $list){
        $isDone = $script:Achievements.ContainsKey($ach.Id)
        $marker = if($isDone){"[✓]"}else{"[ ]"}
        $color  = if($isDone){"Green"}else{"DarkGray"}
        $nameCol = if($isDone){"Yellow"}else{"DarkGray"}
        Write-C "  $marker " $color
        Write-C $ach.Name.PadRight(24) $nameCol
        Write-C " — " $color
        Write-C $ach.Desc.PadRight(40) $color
        Write-CL " (+$($ach.Gold)g, +$($ach.XP)xp)" "DarkCyan"
    }
    Write-Host ""
    Write-CL "  Some achievements unlock from specific events — keep exploring!" "DarkGray"
    Wait-Key
}


# ─── MAIN MENU / GAME LOOP ──────────────────────────────────────
# ── Phase 6: THE PROVINCE OF PRODUCTION ────────────────────────────
# Arena-style overworld (per the user's TES Arena reference images):
# a sea-framed landmass dense with named places. Three tiers of
# settlement plus wilderness POIs (locked decisions): Cities get full
# services (chunk 2 wires remote services; for now services on the
# road are camps' rest fires and the hub), Towns carry a unique side
# quest + exclusive stock (chunk 2), Camps are a fire and a flat
# patch, and POIs are statues that trade offerings for blessings,
# ponds (fishing arrives later), and ruins. Travel takes in-game
# days — the radiant-event calendar applies on the road.
# ── Phase 6: FISHING (Cat 14) ──────────────────────────────────────
# Reaction minigame on the lockpick's RawUI pattern: wait for the
# STRIKE, hit a key inside the window. Window widens and rare odds
# improve with the Fishing skill tier. Rare gear is real, equippable,
# and save-safe (see the __fishing exclusive-stock entries). 3 casts
# per game-day. Hosts without RawUI degrade to an always-hit cast.
# ── Phase 6: FACTIONS (canonical: Rogue Processes / Data Miners) ───
# Rep moves through choices, mostly on the road. Standing bands:
#   -100..-20 HUNTED · -19..-1 Wary · +1..+24 Friendly · +25.. HONORED
# HUNTED sends assassins after you (travel ambush injection). HONORED
# perks: Data Miners buy your loot at +10%; Rogue Processes taught
# you how to leave a room (+5 flee chance). Vendors, companions, and
# faction questlines are the next wave.
function Get-FactionRep {
    param([string]$Faction)
    if($script:FactionRep -and $script:FactionRep.ContainsKey($Faction)){ return [int]$script:FactionRep[$Faction] }
    return 0
}

function Get-FactionLabel {
    param([string]$Faction)
    if($Faction -eq "RogueProcesses"){ "the Rogue Processes" } else { "the Data Miners" }
}

function Get-FactionStanding {
    param([string]$Faction)
    $r = Get-FactionRep $Faction
    if($r -le -20){ return "HUNTED" }
    if($r -lt 0){  return "Wary" }
    if($r -ge 25){ return "HONORED" }
    if($r -gt 0){  return "Friendly" }
    return "Unknown"
}

function Add-FactionRep {
    param([string]$Faction, [int]$Amount)
    $before = Get-FactionStanding $Faction
    $script:FactionRep[$Faction] = [math]::Max(-100, [math]::Min(100, (Get-FactionRep $Faction) + $Amount))
    $after = Get-FactionStanding $Faction
    $fl = Get-FactionLabel $Faction
    if($Amount -gt 0){ Write-CL "  (Reputation with $fl +$Amount)" "Green" }
    else             { Write-CL "  (Reputation with $fl $Amount)" "Red" }
    if($after -ne $before){
        $col = switch($after){ "HUNTED" {"Red"} "HONORED" {"Magenta"} "Wary" {"DarkYellow"} default {"Cyan"} }
        Write-CL "  *** You are now $after by $fl ***" $col
    }
}

# Honored Rogue Processes: +5 flee chance (they taught you exits).
function Get-FactionFleeBonus {
    if((Get-FactionRep "RogueProcesses") -ge 25){ return 5 }
    return 0
}

# ── Phase 6: FACTION CONTACTS (wave 2) ─────────────────────────────
# One broker per faction: the Data Miners keep Indexa in the old
# capital (everything is readable; here it is also for sale); the
# Rogue Processes keep Sig Kill at Terminus — the port of endings is
# exactly where the processes that refused to end hide out. Below
# HONORED they talk but do not deal. Vendor stock lives on pseudo-loc
# "__rp"/"__dm" ExclusiveStock rows (append-only; the 1000+ name scan
# persists purchases like any exclusive).
function Get-FactionContactHere {
    param([string]$LocId)
    switch($LocId){
        "registry" { @{ Faction="DataMiners";     Who="Indexa";   Title="broker of the Data Miners"; StockLoc="__dm"; Color="DarkCyan" } }
        "terminus" { @{ Faction="RogueProcesses"; Who="Sig Kill"; Title="of the Rogue Processes";    StockLoc="__rp"; Color="Red" } }
        default { $null }
    }
}

function Show-FactionContact {
    param($C)
    $fcLoop = $true
    while($fcLoop){
        clr
        Write-Host ""
        $fl = Get-FactionLabel $C.Faction
        $standing = Get-FactionStanding $C.Faction
        $rep = Get-FactionRep $C.Faction
        Write-CL "  ── $($C.Who), $($C.Title) ──" $C.Color
        Write-Host ""
        $sCol = switch($standing){ "HUNTED"{"Red"} "HONORED"{"Magenta"} "Wary"{"DarkYellow"} "Friendly"{"Cyan"} default{"DarkGray"} }
        Write-C  "  Standing: " "DarkGray"; Write-CL "$standing ($rep)" $sCol
        Write-Host ""
        if($rep -lt 25){
            if($C.Faction -eq "DataMiners"){
                Write-CL "  Indexa looks you up in a ledger you cannot see." "Gray"
                Write-CL "  'You are not indexed yet. Do the roads right — make the" "Yellow"
                Write-CL "   right calls at the crossroads — and we will have a record.'" "Yellow"
            } else {
                Write-CL "  Sig leans on a bollard, watching the water not end." "Gray"
                Write-CL "  'We only deal with people the province cannot schedule." "Yellow"
                Write-CL "   Prove it on the roads. Then we talk.'" "Yellow"
            }
            Write-Host ""
            Write-CL "  (Reach HONORED (+25) with $fl to trade.)" "DarkGray"
            Write-Host ""
            Wait-Enter
            return
        }
        if($C.Faction -eq "DataMiners"){
            Write-CL "  'You index well. Ask.'" "Gray"
        } else {
            Write-CL "  'Still running, I see. Good.'" "Gray"
        }
        Write-Host ""
        Write-CL "  [1] Browse goods" "Cyan"
        Write-CL "  [2] Faction work (questline)" "Cyan"
        Write-CL "  [3] Odd jobs (repeatable)" "Cyan"
        Write-CL "  [0] Leave" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"
        switch(Read-Host){
            "1" { Show-FactionGoods $C }
            "2" { Show-FactionQuestline $C }
            "3" { Show-FactionOddJob $C }
            "0" { $fcLoop = $false }
        }
    }
}

function Show-FactionGoods {
    param($C)
    $fgLoop = $true
    while($fgLoop){
        clr
        Write-Host ""
        Write-CL "  ── $($C.Who) lays the goods out, unhurried ──" $C.Color
        Write-Host ""
        Write-C "  Gold: " "DarkGray"; Write-CL "$($script:Gold)g" "Yellow"
        Write-Host ""
        $rows = @()
        foreach($ex in (Get-ExclusiveStock)){ if($ex.Loc -eq $C.StockLoc){ $rows += ,$ex.Item } }
        $n = 0
        foreach($it in $rows){
            $n++
            if($it.WeaponType){
                $perk = if($it.Perk){"$($it.Perk) $($it.PerkChance)%"}else{"---"}
                Write-CL "  [$n] $($it.Name)†  (ATK+$($it.ATK), $($it.WeaponType), $perk)  $($it.Price)g" "Cyan"
            } else {
                Write-CL "  [$n] $($it.Name)†  ($($it.Slot), DEF+$($it.DEF)$(Get-ArmorClassTag $it))  $($it.Price)g" "Cyan"
            }
        }
        Write-Host ""
        Write-CL "  († marked goods exist nowhere else in the province.)" "DarkGray"
        Write-CL "  [0] Back" "DarkGray"
        Write-Host ""
        Write-C "  Buy #: " "Yellow"
        $pick = Read-Host
        if($pick -eq "0"){ $fgLoop = $false; continue }
        $bIdx = 0
        [int]::TryParse([string]$pick, [ref]$bIdx) | Out-Null
        if($bIdx -ge 1 -and $bIdx -le $rows.Count){
            $it = $rows[$bIdx-1]
            if($script:Gold -ge $it.Price){
                $script:Gold -= $it.Price
                $copy = @{}
                foreach($k in $it.Keys){ $copy[$k] = $it[$k] }
                $copy.Exclusive = $true
                $newIt = Init-ItemDurability $copy
                if($newIt.WeaponType){
                    if(-not $newIt.Kind){ $newIt.Kind = "Weapon" }
                    $script:WeaponsOwned[$it.Name] = $true
                    Invoke-GearAcquired -Item $newIt -Kind "Weapon"
                } else {
                    if(-not $newIt.Kind){ $newIt.Kind = "Armor" }
                    $script:ArmorOwned[$it.Name] = $true
                    Invoke-GearAcquired -Item $newIt -Kind "Armor"
                }
                Check-Achievements
            } else { Write-CL "  Not enough gold!" "Red" }
            Wait-Key
        }
    }
}

# Faction questlines (wave 2): 3 sequential stages each on the guild
# SF encoding (per-stage ids), objectives on lifetime counters. The
# finale grants a "__faction" signature (via Invoke-GearAcquired so
# it can be equipped on the spot — bag items liquidate on save),
# +15 rep and 250 XP. Stages 1-2 pay +5 rep on turn-in.
function Get-FactionQuestline {
    param([string]$Faction)
    if($Faction -eq "RogueProcesses"){
        @(
            @{ Sid="fq_rp1"; Label="Outsourced terminations"; Type="Kill";    Need=10; Text="'Ten processes the province wants gone. We are rogue, not sentimental.'" }
            @{ Sid="fq_rp2"; Label="Old currencies";          Type="Collect"; ItemName="Demon Horn"; Need=2; Text="'Two Demon Horns. Exit brokers do not take gold. Gold is TRACKED.'" }
            @{ Sid="fq_rp3"; Label="Leave one ended";         Type="Clear";   Need=1;  Text="'Take a dungeon to its end and walk OUT. Endings are our whole business.'" }
        )
    } else {
        @(
            @{ Sid="fq_dm1"; Label="Data wants opening";      Type="Locks";   Need=3;  Text="'Three locks, opened. Every lock is just data that says no.'" }
            @{ Sid="fq_dm2"; Label="Raw strata";              Type="Collect"; ItemName="Ruby Chunk"; Need=2; Text="'Two Ruby Chunks, uncut. The impurities ARE the data.'" }
            @{ Sid="fq_dm3"; Label="The deep index";          Type="Depth";   Need=12; Text="'Floor twelve. The index has a gap where twelve should be. Fill it.'" }
        )
    }
}

# One infinitely repeatable job per faction: stage returns to 0 on
# payout instead of 999999. Flat +6 rep; the 100 clamp is the cap.
function Get-FactionRepeatable {
    param([string]$Faction)
    if($Faction -eq "RogueProcesses"){
        @{ Sid="fq_rp_r"; Label="Overdue terminations"; Type="Kill"; Need=8; Gold=150; Rep=6; Text="'Always more overdue terminations. The province never stops scheduling.'" }
    } else {
        @{ Sid="fq_dm_r"; Label="Raw ore"; Type="Collect"; ItemName="Gem Shard"; Need=2; Gold=150; Rep=6; Text="'Shards. Always shards. Small data compounds.'" }
    }
}

# Shared progress math (guild pattern + Depth).
function Get-FactionObjectiveProgress {
    param($Stage, [int]$Aux)
    $prog = switch($Stage.Type){
        "Kill"    { [int]$script:TotalKills - $Aux }
        "Locks"   { [int]$script:TotalLocksPicked - $Aux }
        "Clear"   { [int]$script:DungeonsCleared - $Aux }
        "Boss"    { [int]$script:BossesDefeated - $Aux }
        "Corrupt" { [int]$script:Corruption }
        "Depth"   { [int]$script:DeepestFloor }
        "Collect" { Get-NamedItemCount $Stage.ItemName }
        default   { 0 }
    }
    if($prog -lt 0){ $prog = 0 }
    return $prog
}
function Get-FactionObjectiveBaseline {
    param($Stage)
    switch($Stage.Type){
        "Kill"    { [int]$script:TotalKills }
        "Locks"   { [int]$script:TotalLocksPicked }
        "Clear"   { [int]$script:DungeonsCleared }
        "Boss"    { [int]$script:BossesDefeated }
        default   { 0 }
    }
}

function Show-FactionQuestline {
    param($C)
    $fqLoop = $true
    while($fqLoop){
        clr
        Write-Host ""
        $stages = Get-FactionQuestline $C.Faction
        Write-CL "  ── Faction work — $(Get-FactionLabel $C.Faction) ──" $C.Color
        Write-Host ""
        # Find the current (first non-done) stage.
        $curStage = $null; $stageNum = 0
        for($qi=0; $qi -lt $stages.Count; $qi++){
            if((Get-QuestStage $stages[$qi].Sid) -ne 999999){ $curStage = $stages[$qi]; $stageNum = $qi + 1; break }
        }
        for($qi=0; $qi -lt $stages.Count; $qi++){
            $sg = $stages[$qi]
            $sgSt = Get-QuestStage $sg.Sid
            $mark = if($sgSt -eq 999999){"[x]"} elseif($sgSt -ge 100000){"[>]"} else {"[ ]"}
            $mCol = if($sgSt -eq 999999){"DarkGray"} elseif($sgSt -ge 100000){"Yellow"} else {"White"}
            Write-CL "  $mark Stage $($qi+1): $($sg.Label)" $mCol
        }
        Write-Host ""
        if(-not $curStage){
            $myComp = if($C.Faction -eq "DataMiners"){"dm"}else{"rp"}
            $compName = if($myComp -eq "dm"){"Cursor"}else{"Orphan"}
            $compDesc = if($myComp -eq "dm"){"a query sprite (+2% crit)"}else{"a small zombie process (+1 SPD)"}
            if($C.Faction -eq "DataMiners"){
                Write-CL "  'The index remembers what you filled. So do I.'" "Gray"
            } else {
                Write-CL "  'You ended things properly. Around here, that is family.'" "Gray"
            }
            Write-Host ""
            if($script:Companion -eq $myComp){
                Write-CL "  $compName is with you — $compDesc." "DarkCyan"
                Write-Host ""
                Write-CL "  [1] Part ways with $compName   [0] Back" "White"
            } else {
                Write-CL "  $compName — $compDesc — could travel with you." "DarkCyan"
                if($script:Companion){ Write-CL "  (Your current companion would head home.)" "DarkGray" }
                Write-Host ""
                Write-CL "  [1] Take $compName along   [0] Back" "White"
            }
            Write-C "  > " "Yellow"
            switch(Read-Host){
                "1" {
                    if($script:Companion -eq $myComp){
                        $script:Companion = ""
                        Write-CL "  $compName drifts off into the stonework. No hard feelings." "DarkGray"
                    } else {
                        $script:Companion = $myComp
                        Write-CL "  *** $compName now travels with you. ***" "Magenta"
                    }
                    Write-Host ""; Wait-Enter
                }
                "0" { $fqLoop = $false }
            }
            continue
        }
        $st = Get-QuestStage $curStage.Sid
        if($st -eq 0){
            Write-CL "  $($curStage.Text)" "Yellow"
            Write-Host ""
            Write-CL "  [1] Accept   [0] Back" "White"
        } else {
            $aux = $st - 100000
            $prog = Get-FactionObjectiveProgress $curStage $aux
            Write-CL "  Progress: $prog / $($curStage.Need)" "White"
            if($prog -ge $curStage.Need){
                Write-CL "  READY TO TURN IN." "Green"
                Write-Host ""
                Write-CL "  [1] Turn in   [0] Back" "White"
            } else {
                Write-Host ""
                Write-CL "  [0] Back" "DarkGray"
            }
        }
        Write-C  "  > " "Yellow"
        switch(Read-Host){
            "1" {
                $st = Get-QuestStage $curStage.Sid
                if($st -eq 0){
                    Set-QuestStage $curStage.Sid (100000 + (Get-FactionObjectiveBaseline $curStage))
                    Write-Host ""
                    Write-CL "  *** Stage accepted: $($curStage.Label) ***" $C.Color
                    Write-Host ""; Wait-Enter
                } elseif($st -ge 100000){
                    $aux = $st - 100000
                    $prog = Get-FactionObjectiveProgress $curStage $aux
                    if($prog -ge $curStage.Need){
                        if($curStage.Type -eq "Collect"){ Remove-Gems $curStage.ItemName $curStage.Need }
                        Set-QuestStage $curStage.Sid 999999
                        Write-Host ""
                        Write-CL "  *** Stage complete: $($curStage.Label) ***" $C.Color
                        if($stageNum -eq 3){
                            Write-Host ""
                            if($C.Faction -eq "DataMiners"){
                                Write-CL "  Indexa closes the ledger. For a moment the whole" "Gray"
                                Write-CL "  Registry seems to have finished reading." "Gray"
                                $sigName = "Prospector's Charm"
                            } else {
                                Write-CL "  Sig looks at you the way processes look at an exit" "Gray"
                                Write-CL "  that nobody is watching." "Gray"
                                $sigName = "Runaway's Signet"
                            }
                            foreach($ex in (Get-ExclusiveStock)){
                                if($ex.Loc -eq "__faction" -and $ex.Item.Name -eq $sigName){
                                    $fItem = @{}
                                    foreach($k in $ex.Item.Keys){ $fItem[$k] = $ex.Item[$k] }
                                    $fItem.Kind = "Armor"
                                    $fItem = Init-ItemDurability $fItem
                                    Invoke-GearAcquired -Item $fItem -Kind "Armor"
                                    break
                                }
                            }
                            Write-CL "  *** You receive the $($sigName.ToUpper()) (amulet, DEF+6)! ***" "Magenta"
                            Add-FactionRep $C.Faction 15
                            Grant-XP 250
                        } else {
                            Add-FactionRep $C.Faction 5
                        }
                        Write-Host ""; Wait-Enter
                    }
                }
            }
            "0" { $fqLoop = $false }
        }
    }
}

function Show-FactionOddJob {
    param($C)
    $ojLoop = $true
    while($ojLoop){
        clr
        Write-Host ""
        $job = Get-FactionRepeatable $C.Faction
        Write-CL "  ── Odd jobs — $($job.Label) ──" $C.Color
        Write-Host ""
        $st = Get-QuestStage $job.Sid
        if($st -eq 0){
            Write-CL "  $($job.Text)" "Yellow"
            $objLine = if($job.Type -eq "Collect"){"Bring $($job.Need) $($job.ItemName)s."}else{"Slay $($job.Need) enemies."}
            Write-CL "  ($objLine Reward: $($job.Gold)g, +$($job.Rep) rep. Repeatable.)" "DarkGray"
            Write-Host ""
            Write-CL "  [1] Take the job   [0] Back" "White"
        } else {
            $aux = $st - 100000
            $prog = Get-FactionObjectiveProgress $job $aux
            Write-CL "  Progress: $prog / $($job.Need)" "White"
            if($prog -ge $job.Need){
                Write-CL "  READY TO TURN IN." "Green"
                Write-Host ""
                Write-CL "  [1] Turn in   [0] Back" "White"
            } else {
                Write-Host ""
                Write-CL "  [0] Back" "DarkGray"
            }
        }
        Write-C  "  > " "Yellow"
        switch(Read-Host){
            "1" {
                $st = Get-QuestStage $job.Sid
                if($st -eq 0){
                    Set-QuestStage $job.Sid (100000 + (Get-FactionObjectiveBaseline $job))
                    Write-Host ""
                    Write-CL "  *** Job taken: $($job.Label) ***" $C.Color
                    Write-Host ""; Wait-Enter
                } elseif($st -ge 100000){
                    $aux = $st - 100000
                    $prog = Get-FactionObjectiveProgress $job $aux
                    if($prog -ge $job.Need){
                        if($job.Type -eq "Collect"){ Remove-Gems $job.ItemName $job.Need }
                        $script:Gold += $job.Gold
                        Write-Host ""
                        Write-CL "  *** Job done. (+$($job.Gold)g) ***" "Magenta"
                        Add-FactionRep $C.Faction $job.Rep
                        Set-QuestStage $job.Sid 0
                        Write-CL "  'Another one is already queued. There is always another.'" "DarkGray"
                        Write-Host ""; Wait-Enter
                    }
                }
            }
            "0" { $ojLoop = $false }
        }
    }
}

# ── Phase 6: THEMED RAIDS ──────────────────────────────────────────
# Original-doc locations get their own dungeons: Frostfang ice caves,
# Sys-V patrol vaults, the Whispering Woods undergrowth. Raids reuse
# the full Depths machinery (Daily Dungeon precedent) at a player-
# anchored level; the Depths' own floor counter is saved and restored.
function Get-RaidThemes {
    @{
        "frostfang"    = @{ Id="Frost"; DName="THE ICE CAVES";     Label="Enter the Ice Caves";     Color="Cyan";
                            Types=@("Frost Troll","Frost Troll","Skeleton","Wizard","Frost Troll");
                            Boss="the Frost Matriarch";
                            Desc1="Breath hangs. The walls tick as they freeze a little deeper.";
                            Desc2="Something below is answering pings." }
        "sysv"         = @{ Id="Golem"; DName="THE PATROL VAULTS"; Label="Enter the Patrol Vaults"; Color="DarkGray";
                            Types=@("Golem","Golem","Skeleton","Wizard","Golem");
                            Boss="Warden Prime";
                            Desc1="Servos older than the province grind somewhere in the dark.";
                            Desc2="The patrols never received the shutdown order." }
        "whisperwoods" = @{ Id="Spore"; DName="THE UNDERGROWTH";   Label="Enter the Undergrowth";   Color="Green";
                            Types=@("Spore Beast","Spore Beast","Zombie","Troll","Spore Beast");
                            Boss="the Sporefather";
                            Desc1="The roots repeat your footsteps, half a beat late.";
                            Desc2="Do not breathe deeply." }
    }
}

# ── Phase 6: TOWN SIDE QUESTS (Cat 13.2) ───────────────────────────
# One hand-made quest per town (first wave: 5), persisted through the
# SF story-flag key. Stage encoding: 0 = unmet; 100000 + aux = active,
# where aux carries the objective baseline (TotalKills / deadline day /
# TotalFishCaught); 999999 = done. These are SEPARATE from the
# ephemeral Town Board quests (locked decision) and survive save/load.
# Rewards: gold/items/skill-XP, and (since the Grant-XP extraction
# from Start-Combat) real player XP — the city-wave quests use it.
function Get-TownQuest {
    param([string]$LocId)
    switch($LocId){
        "backupvale" { @{ Id="bkv_key"; Name="The Skeleton Key"; Giver="Old Tumbler Wren"; Type="Collect"; ItemName="Ancient Rune"; Need=3 } }
        "bashford"   {
            if((Get-QuestStage "bash_edge") -eq 999999){
                @{ Id="bash_edge2"; Name="Diplomacy, Continued"; Giver="Bruska the Smith"; Type="Kill"; Need=20 }
            } else {
                @{ Id="bash_edge"; Name="One-Liner Diplomacy"; Giver="Bruska the Smith"; Type="Kill"; Need=12 }
            }
        }
        "cronmarch"  { @{ Id="cron_parcel"; Name="On Schedule"; Giver="the Scheduler"; Type="Deliver"; Target="syslogxing"; Days=4 } }
        "nullhaven"  {
            # Sequel: once existence is proven, it must be FILED.
            if((Get-QuestStage "null_proof") -eq 999999){
                @{ Id="null_persist"; Name="Proof of Persistence"; Giver="the Registrar of Nullhaven"; Type="Deliver"; Target="registry"; Days=5 }
            } else {
                @{ Id="null_proof"; Name="Proof of Existence"; Giver="the Registrar of Nullhaven"; Type="Collect"; ItemName="Shadow Gem"; Need=1 }
            }
        }
        "foreachfalls" {
            if((Get-QuestStage "falls_fish") -eq 999999){
                @{ Id="falls_fish2"; Name="The Pipeline Runs Deep"; Giver="Weir the ferryman"; Type="Fish"; Need=6 }
            } else {
                @{ Id="falls_fish"; Name="One at a Time"; Giver="Weir the ferryman"; Type="Fish"; Need=3 }
            }
        }
        "cachegrove"   {
            if((Get-QuestStage "cg_bread") -eq 999999){
                @{ Id="cg_bread2"; Name="A Warm Batch"; Giver="Loaf-warden Prue"; Type="Collect"; ItemName="Ruby Chunk"; Need=2 }
            } else {
                @{ Id="cg_bread"; Name="Stale Bread, Fresh Scales"; Giver="Loaf-warden Prue"; Type="Collect"; ItemName="Wyvern Scale"; Need=2 }
            }
        }
        "firewallkeep" {
            if((Get-QuestStage "fk_deny") -eq 999999){
                @{ Id="fk_deny2"; Name="Allow-List of One"; Giver="Gate-captain Rules"; Type="Clear"; Need=4 }
            } else {
                @{ Id="fk_deny"; Name="Deny by Default"; Giver="Gate-captain Rules"; Type="Clear"; Need=2 }
            }
        }
        "syslogxing"   { @{ Id="sx_ghost"; Name="The Unwritten Traveler"; Giver="the log-keeper"; Type="Depth"; Need=10 } }
        "kernelhold"   {
            if((Get-QuestStage "kh_audit") -eq 999999){
                @{ Id="kh_audit2"; Name="The Second Audit"; Giver="Auditor Primm"; Type="Kill"; Need=25 }
            } else {
                @{ Id="kh_audit"; Name="A Capital Request"; Giver="Auditor Primm"; Type="Kill"; Need=15 }
            }
        }
        "registry"     {
            # 3-chapter arc: each chapter appears once the last is done.
            if((Get-QuestStage "reg_ink2") -eq 999999){
                @{ Id="reg_ink3"; Name="The Reader in the Stacks"; Giver="the Under-Archivist"; Type="Clear"; Need=1 }
            } elseif((Get-QuestStage "reg_ink") -eq 999999){
                @{ Id="reg_ink2"; Name="The Redacted Name"; Giver="the Under-Archivist"; Type="Collect"; ItemName="Shadow Gem"; Need=1 }
            } else {
                @{ Id="reg_ink"; Name="Ink That Remembers"; Giver="the Under-Archivist"; Type="Collect"; ItemName="Enchanted Dust"; Need=3 }
            }
        }
        "terminus"     { @{ Id="term_line"; Name="End of Line"; Giver="Harbormaster Quay"; Type="Fish"; Need=5 } }
        "sysv"         { @{ Id="sysv_quiet"; Name="Quiet Streets"; Giver="Salvage-foreman Grep"; Type="Kill"; Need=18 } }
        default { $null }
    }
}

function Get-QuestStage {
    param([string]$Qid)
    if($script:StoryFlags -and $script:StoryFlags.ContainsKey($Qid)){ return [int]$script:StoryFlags[$Qid] }
    return 0
}
function Set-QuestStage {
    param([string]$Qid, [int]$Stage)
    if(-not $script:StoryFlags){ $script:StoryFlags = @{} }
    $script:StoryFlags[$Qid] = $Stage
}
# The Skeleton Key: Backupvale's quest reward. Every lock is its lock.
function Test-HasSkeletonKey {
    return ((Get-QuestStage "bkv_key") -eq 999999)
}

# Counts inventory items by name (any Kind) for Collect objectives.
function Get-NamedItemCount {
    param([string]$Name)
    $n = 0
    foreach($it in $script:Inventory){ if($it.Name -eq $Name){ $n++ } }
    return $n
}

# Called on arriving at any location: completes active Deliver quests
# targeting this place (or scolds and resets them if the deadline has
# passed — retryable at the giver).
function Check-QuestArrival {
    foreach($srcLoc in @("cronmarch","nullhaven")){
        $dq = Get-TownQuest $srcLoc
        if(-not $dq -or $dq.Type -ne "Deliver"){ continue }
        $st = Get-QuestStage $dq.Id
        if($st -lt 100000 -or $st -eq 999999){ continue }
        $deadline = $st - 100000
        if($script:CurrentLocation -eq $dq.Target){
            Write-Host ""
            if($script:GameDay -le $deadline){
                if($dq.Id -eq "null_persist"){
                    Write-CL "  You file Nullhaven's proof at the capital. The clerk" "Gray"
                    Write-CL "  reads it twice, stamps it once, and frowns at the" "Gray"
                    Write-CL "  implications of both actions." "Gray"
                    Write-CL "  'Nullhaven now exists. Provisionally. Congratulations?'" "Yellow"
                    $script:Gold += 400
                    Grant-XP 200
                    Write-CL "  *** Quest complete: Proof of Persistence! (+400g) ***" "Magenta"
                } else {
                    Write-CL "  You hand over the sealed parcel from Cronmarch." "Gray"
                    Write-CL "  The clerk checks the seal, the date, and — twice — you." "Gray"
                    Write-CL "  'On schedule. Remarkable. Payment as agreed.'" "Yellow"
                    $script:Gold += 350
                    Write-CL "  *** Quest complete: On Schedule! (+350g) ***" "Magenta"
                }
                Set-QuestStage $dq.Id 999999
            } else {
                Write-CL "  The clerk eyes the date on the parcel and sighs the" "Gray"
                Write-CL "  sigh of a person adding you to a report." "Gray"
                if($dq.Id -eq "null_persist"){
                    Write-CL "  'Expired. Nullhaven will have to prove itself again." "Red"
                    Write-CL "   It is, I suspect, used to that.'" "Red"
                } else {
                    Write-CL "  'Late. The Scheduler will want to re-run this job.'" "Red"
                }
                Set-QuestStage $dq.Id 0
            }
            Write-Host ""
            Wait-Enter
        }
        elseif($script:GameDay -gt $deadline -and $script:CurrentLocation -eq $srcLoc){
            # Wandered home past the deadline: reset quietly at the giver.
            Set-QuestStage $dq.Id 0
        }
    }
}

function Show-TownQuest {
    param($Loc, $Q)
    $st = Get-QuestStage $Q.Id
    clr
    Write-Host ""
    Write-CL "  ── $($Q.Name) — $($Q.Giver) ──" "Magenta"
    Write-Host ""
    if($st -eq 999999){
        switch($Q.Id){
            "bkv_key"    { Write-CL "  Wren nods at your belt. 'Treat her kindly. She opens" "Gray"
                           Write-CL "  everything, and forgives nothing.'" "Gray" }
            "bash_edge"  { Write-CL "  Bruska grunts. In Bashford, that is a parade." "Gray" }
            "cron_parcel"{ Write-CL "  'Next job runs when it runs,' says the Scheduler." "Gray" }
            "null_proof" { Write-CL "  The Registrar is not here. The stamp on your paperwork is." "Gray" }
            "reg_ink"    { Write-CL "  The restored shelves hum faintly, like rereading." "Gray" }
            "term_line"  { Write-CL "  Quay tips his cap. The harbor smells of dinner and departures." "Gray" }
            "sysv_quiet" { Write-CL "  Grep's crews work in the open now. In Sys-V, that IS thanks." "Gray" }
            "reg_ink3"   { Write-CL "  In the deep stacks there is a chair that is always warm now." "Gray"
                           Write-CL "  The Under-Archivist dusts around it, and leaves it be." "Gray" }
            "null_persist" { Write-CL "  A framed certificate hangs in Nullhaven: EXISTS (PROVISIONAL)." "Gray" }
            default      { Write-CL "  Weir waves from the water. The falls keep falling, one at a time." "Gray" }
        }
        Write-Host ""; Wait-Enter; return
    }
    if($st -eq 0){
        # ── Offer ──
        switch($Q.Id){
            "bkv_key" {
                Write-CL "  Old Tumbler Wren turns a blank key over arthritic fingers." "Gray"
                Write-CL "  'My grandmother cut a key that opens every lock ever made." "Yellow"
                Write-CL "   Then she hid the cutting pattern in THREE Ancient Runes," "Yellow"
                Write-CL "   because she did not trust anyone. Including me. Bring the" "Yellow"
                Write-CL "   runes, and I will cut you the last Skeleton Key.'" "Yellow"
                Write-CL "  (Bring 3 Ancient Runes — dungeon trinket drops.)" "DarkGray"
            }
            "bash_edge" {
                Write-CL "  Bruska doesn't look up from the anvil." "Gray"
                Write-CL "  'Twelve of whatever's crawling the Depths. Dead. That's the" "Yellow"
                Write-CL "   whole request. Bashford doesn't do subclauses.'" "Yellow"
                Write-CL "  (Slay 12 enemies, then return. Reward: 250g + 2 Gem Shards.)" "DarkGray"
            }
            "cron_parcel" {
                Write-CL "  The Scheduler holds out a parcel sealed in wax and dread." "Gray"
                Write-CL "  'Syslog Crossing. Four days. Not five. The Crossing writes" "Yellow"
                Write-CL "   down late arrivals, and I do not appear in logs.'" "Yellow"
                Write-CL "  (Deliver to Syslog Crossing within 4 days. Reward: 350g.)" "DarkGray"
            }
            "null_proof" {
                Write-CL "  The Registrar of Nullhaven may or may not lean forward." "Gray"
                Write-CL "  'Bring me a Shadow Gem. If darkness can persist, then so —" "Yellow"
                Write-CL "   in principle — can we. It would mean a great deal. Maybe.'" "Yellow"
                Write-CL "  (Bring 1 Shadow Gem. Reward: 180g + 2 Enchanted Dust.)" "DarkGray"
            }
            "cg_bread" {
                Write-CL "  Loaf-warden Prue thumps a loaf. It thumps back." "Gray"
                Write-CL "  'The damp gets in the flour stores. Wyvern scales keep" "Yellow"
                Write-CL "   it out — two good ones and the bread stops fighting.'" "Yellow"
                Write-CL "  (Bring 2 Wyvern Scales. Reward: 220g + preserved rations.)" "DarkGray"
            }
            "fk_deny" {
                Write-CL "  Gate-captain Rules does not blink. Possibly ever." "Gray"
                Write-CL "  'The Keep holds because the Depths are thinned. Take two" "Yellow"
                Write-CL "   dungeons to their end. Boss down. Exit reached. Twice.'" "Yellow"
                Write-CL "  (Clear 2 dungeons. Reward: 300g + confiscated contraband.)" "DarkGray"
            }
            "sx_ghost" {
                Write-CL "  The log-keeper opens the ledger to a blank line that" "Gray"
                Write-CL "  should not be blank." "Gray"
                Write-CL "  'Someone crossed unwritten. Unlisted travelers go DOWN." "Yellow"
                Write-CL "   Reach floor ten. Tell me what the dark is keeping.'" "Yellow"
                Write-CL "  (Reach dungeon floor 10. Reward: 250g + 2 Gem Shards.)" "DarkGray"
            }
            "kh_audit" {
                Write-CL "  Auditor Primm produces a form with your name pre-filled," "Gray"
                Write-CL "  which is somehow the most frightening thing in the city." "Gray"
                Write-CL "  'The capital audits the Depths quarterly. Fifteen line" "Yellow"
                Write-CL "   items, terminated and receipted. Sign here.'" "Yellow"
                Write-CL "  (Slay 15 enemies. Reward: 400g + 1 Ancient Rune.)" "DarkGray"
            }
            "reg_ink" {
                Write-CL "  The Under-Archivist holds a page up to the light. The" "Gray"
                Write-CL "  words on it are leaving." "Gray"
                Write-CL "  'The old ink forgets. Ground Enchanted Dust remembers FOR" "Yellow"
                Write-CL "   it. Three measures, and the capital keeps its names.'" "Yellow"
                Write-CL "  (Bring 3 Enchanted Dust. Reward: 280g + 1 Shadow Gem.)" "DarkGray"
            }
            "term_line" {
                Write-CL "  Harbormaster Quay reads a manifest of departures that" "Gray"
                Write-CL "  never lists arrivals." "Gray"
                Write-CL "  'Every session ends here, and they all end HUNGRY. Five" "Yellow"
                Write-CL "   fish off the pond for the galley, and you eat free too.'" "Yellow"
                Write-CL "  (Catch 5 fish. Reward: 300g + 1 Dragon Tooth.)" "DarkGray"
            }
            "sysv_quiet" {
                Write-CL "  Salvage-foreman Grep watches a patrol grind past a street" "Gray"
                Write-CL "  his crew should be stripping." "Gray"
                Write-CL "  'Eighteen of anything that bites, out of the Depths. The" "Yellow"
                Write-CL "   patrols reroute to count corpses. My crews work. Deal?'" "Yellow"
                Write-CL "  (Slay 18 enemies. Reward: 380g + 2 Gem Shards.)" "DarkGray"
            }
            "reg_ink2" {
                Write-CL "  The Under-Archivist shows you a restored page. Every" "Gray"
                Write-CL "  name on it holds firm — except one, still fading." "Gray"
                Write-CL "  'I have re-inked this name FOUR times. It will not stay" "Yellow"
                Write-CL "   written. Someone erased themselves. To write what is" "Yellow"
                Write-CL "   not there, I need ink of shadow. One Shadow Gem.'" "Yellow"
                Write-CL "  (Bring 1 Shadow Gem. Reward: 300g.)" "DarkGray"
            }
            "reg_ink3" {
                Write-CL "  The shadow-ink held for one line. Long enough to read a" "Gray"
                Write-CL "  title: UNDER-ARCHIVIST. The name was her predecessor's." "Gray"
                Write-CL "  'He did not die. He went DOWN, where erased things settle." "Yellow"
                Write-CL "   And something has been reading with his eyes ever since." "Yellow"
                Write-CL "   Close a dungeon, end to end. If you meet a reader down" "Yellow"
                Write-CL "   there, tell him the shelves are restored.'" "Yellow"
                Write-CL "  (Clear 1 dungeon. Reward: 450g + 1 Ancient Rune.)" "DarkGray"
            }
            "null_persist" {
                Write-CL "  The Registrar holds your filed proof like a newborn." "Gray"
                Write-CL "  'Existence, it turns out, EXPIRES. Unless it is filed with" "Yellow"
                Write-CL "   the capital within five days, Nullhaven goes back to" "Yellow"
                Write-CL "   being a rumor. We would rather not. Probably.'" "Yellow"
                Write-CL "  (Deliver to the Registry within 5 days. Reward: 400g.)" "DarkGray"
            }
            default {
                Write-CL "  Weir the ferryman watches the falls sort the river." "Gray"
                Write-CL "  'Three fish. Not four at once, not a net. One. At. A. Time." "Yellow"
                Write-CL "   The falls will know if you cheat.'" "Yellow"
                Write-CL "  (Catch 3 fish. Reward: 200g, a Ruby Chunk, and technique.)" "DarkGray"
            }
        }
        Write-Host ""
        Write-CL "  [1] Accept   [0] Not now" "Yellow"
        Write-C  "  > " "Yellow"
        if((Read-Host) -eq "1"){
            $aux = switch($Q.Type){
                "Kill"    { [int]$script:TotalKills }
                "Fish"    { [int]$script:TotalFishCaught }
                "Deliver" { [int]$script:GameDay + [int]$Q.Days }
                "Clear"   { [int]$script:DungeonsCleared }
                default   { 0 }
            }
            Set-QuestStage $Q.Id (100000 + $aux)
            Write-Host ""
            Write-CL "  *** Quest accepted: $($Q.Name) ***" "Magenta"
            Write-Host ""
            Wait-Enter
        }
        return
    }
    # ── Active: progress / turn-in ──
    $aux = $st - 100000
    switch($Q.Type){
        "Collect" {
            $have = Get-NamedItemCount $Q.ItemName
            Write-CL "  $($Q.ItemName): $have / $($Q.Need)" "Cyan"
            if($have -ge $Q.Need){
                Write-Host ""
                Write-CL "  [1] Hand them over   [0] Not yet" "Yellow"
                Write-C  "  > " "Yellow"
                if((Read-Host) -eq "1"){
                    Remove-Gems $Q.ItemName $Q.Need
                    Write-Host ""
                    if($Q.Id -eq "bkv_key"){
                        Write-CL "  Wren reads the runes like sheet music, clamps a blank," "Gray"
                        Write-CL "  and files in silence for a long time." "Gray"
                        Write-Host ""
                        Write-CL "  ╔══════════════════════════════════════════╗" "Cyan"
                        Write-CL "  ║      T H E   S K E L E T O N   K E Y     ║" "Cyan"
                        Write-CL "  ╚══════════════════════════════════════════╝" "Cyan"
                        Write-CL "  Every lock in the Depths is now YOUR lock." "Yellow"
                        Write-CL "  Chests open at a touch — no picks, no minigame." "Yellow"
                        $script:Gold += 50
                        Write-CL "  (+50g for the runes' silver settings)" "DarkGray"
                    } elseif($Q.Id -eq "cg_bread"){
                        Write-CL "  Prue wedges the scales into the store-room seams. The" "Gray"
                        Write-CL "  flour sighs. 'Tomorrow's loaves will be LEGAL.'" "Yellow"
                        $script:Gold += 220
                        if(-not $script:Ingredients){ $script:Ingredients = @{} }
                        if(-not $script:Ingredients.ContainsKey("Meat")){ $script:Ingredients["Meat"] = 0 }
                        $script:Ingredients["Meat"] += 3
                        Write-CL "  *** Quest complete! (+220g, +3 Meat rations) ***" "Magenta"
                    } elseif($Q.Id -eq "reg_ink2"){
                        Write-CL "  She grinds the gem to shadow-ink and writes the fading" "Gray"
                        Write-CL "  name. For one line, it HOLDS — long enough to read." "Gray"
                        Write-CL "  Her hand stops. '...That is the man who trained me.'" "Yellow"
                        $script:Gold += 300
                        Grant-XP 200
                        Write-CL "  *** Quest complete! (+300g) ***" "Magenta"
                        Write-CL "  (The Under-Archivist has more to ask of you.)" "DarkGray"
                    } elseif($Q.Id -eq "reg_ink"){
                        Write-CL "  The Under-Archivist grinds the dust into ink that" "Gray"
                        Write-CL "  gleams wet on centuries-dry pages. Names resurface." "Gray"
                        Write-CL "  'The capital forgets nothing now. Well. Less.'" "Yellow"
                        $script:Gold += 280
                        [void]$script:Inventory.Add(@{Name="Shadow Gem"; Value=75; Tier=3; Kind="Loot"; Weight=1})
                        Grant-XP 150
                        Write-CL "  *** Quest complete! (+280g, +1 Shadow Gem) ***" "Magenta"
                    } else {
                        Write-CL "  'Huh. It's real. Or real enough.' The Registrar files it" "Gray"
                        Write-CL "  somewhere that may exist." "Gray"
                        $script:Gold += 180
                        foreach($dz in 1..2){
                            [void]$script:Inventory.Add(@{Name="Enchanted Dust"; Value=30; Tier=1; Kind="Loot"; Weight=1})
                        }
                        Write-CL "  *** Quest complete! (+180g, +2 Enchanted Dust) ***" "Magenta"
                    }
                    Set-QuestStage $Q.Id 999999
                }
            } else {
                Write-CL "  Not enough yet. The Depths drop them in chests and pockets." "DarkGray"
            }
        }
        "Kill" {
            $progress = [int]$script:TotalKills - $aux
            if($progress -lt 0){ $progress = 0 }
            Write-CL "  Slain since the handshake: $progress / $($Q.Need)" "Cyan"
            if($progress -ge $Q.Need){
                Write-Host ""
                if($Q.Id -eq "kh_audit"){
                    Write-CL "  Primm checks fifteen boxes without looking up, then" "Gray"
                    Write-CL "  stamps the audit CLEAN. 'The capital thanks you in" "Yellow"
                    Write-CL "   the enclosed, non-negotiable amount.'" "Yellow"
                    $script:Gold += 400
                    [void]$script:Inventory.Add(@{Name="Ancient Rune"; Value=60; Tier=3; Kind="Loot"; Weight=1})
                    Write-CL "  *** Quest complete! (+400g, +1 Ancient Rune) ***" "Magenta"
                } elseif($Q.Id -eq "sysv_quiet"){
                    Write-CL "  Grep counts eighteen tallies scratched on a girder and" "Gray"
                    Write-CL "  whistles once. Salvage crews move out behind the sound." "Gray"
                    Write-CL "  'A week of quiet streets. Best pay I ever gave.'" "Yellow"
                    $script:Gold += 380
                    foreach($dz in 1..2){
                        [void]$script:Inventory.Add(@{Name="Gem Shard"; Value=25; Tier=1; Kind="Loot"; Weight=1})
                    }
                    Grant-XP 200
                    Write-CL "  *** Quest complete! (+380g, +2 Gem Shards) ***" "Magenta"
                } else {
                    Write-CL "  Bruska counts on scarred fingers, nods once." "Gray"
                    Write-CL "  'Payment. And Bashford's thanks, which is this nod.'" "Yellow"
                    $script:Gold += 250
                    foreach($dz in 1..2){
                        [void]$script:Inventory.Add(@{Name="Gem Shard"; Value=25; Tier=1; Kind="Loot"; Weight=1})
                    }
                    Write-CL "  *** Quest complete! (+250g, +2 Gem Shards) ***" "Magenta"
                }
                Set-QuestStage $Q.Id 999999
            }
        }
        "Deliver" {
            $daysLeft = $aux - [int]$script:GameDay
            if($daysLeft -ge 0){
                Write-CL "  The parcel waits in your pack. $daysLeft day(s) to reach" "Cyan"
                Write-CL "  $((Get-WorldLocation $Q.Target).Name)." "Cyan"
            } else {
                if($Q.Id -eq "null_persist"){
                    Write-CL "  The paperwork has expired. Nullhaven remains, officially," "Red"
                    Write-CL "  a rumor. The Registrar re-drafts, uncomplaining." "Red"
                } else {
                    Write-CL "  The deadline is gone. The Scheduler pretends not to see you" "Red"
                    Write-CL "  and re-queues the job." "Red"
                }
                Set-QuestStage $Q.Id 0
            }
        }
        "Clear" {
            $progress = [int]$script:DungeonsCleared - $aux
            if($progress -lt 0){ $progress = 0 }
            Write-CL "  Dungeons closed since the order: $progress / $($Q.Need)" "Cyan"
            if($progress -ge $Q.Need){
                Write-Host ""
                if($Q.Id -eq "reg_ink3"){
                    Write-CL "  You closed it, end to end. In the deepest room there was" "Gray"
                    Write-CL "  a chair, a lamp, and a book still warm at the spine." "Gray"
                    Write-CL "  You said the shelves were restored. Nothing answered —" "Gray"
                    Write-CL "  but the lamp went out politely, like a reader done for" "Gray"
                    Write-CL "  the night. Back home, the re-inked name stays written." "Yellow"
                    $script:Gold += 450
                    [void]$script:Inventory.Add(@{Name="Ancient Rune"; Value=60; Tier=3; Kind="Loot"; Weight=1})
                    Grant-XP 300
                    Write-CL "  *** Questline complete! (+450g, +1 Ancient Rune) ***" "Magenta"
                } else {
                    Write-CL "  Rules initials two lines on a wall-ledger of thousands." "Gray"
                    Write-CL "  'The wall stands because somebody thins the other side." "Yellow"
                    Write-CL "   Today, somebody was you.' A crate slides across." "Yellow"
                    $script:Gold += 300
                    [void]$script:Inventory.Add(@{Name="Demon Horn"; Value=70; Tier=3; Kind="Loot"; Weight=2})
                    Write-CL "  *** Quest complete! (+300g, +1 Demon Horn) ***" "Magenta"
                }
                Set-QuestStage $Q.Id 999999
            }
        }
        "Depth" {
            Write-CL "  Deepest floor reached: $($script:DeepestFloor) / $($Q.Need)" "Cyan"
            if([int]$script:DeepestFloor -ge $Q.Need){
                Write-Host ""
                Write-CL "  You describe floor ten. The log-keeper writes it in the" "Gray"
                Write-CL "  blank line, backwards, so it reads only in a mirror." "Gray"
                Write-CL "  'Now the ledger balances. Thank you.'" "Yellow"
                $script:Gold += 250
                foreach($dz in 1..2){
                    [void]$script:Inventory.Add(@{Name="Gem Shard"; Value=25; Tier=1; Kind="Loot"; Weight=1})
                }
                Write-CL "  *** Quest complete! (+250g, +2 Gem Shards) ***" "Magenta"
                Set-QuestStage $Q.Id 999999
            }
        }
        "Fish" {
            $progress = [int]$script:TotalFishCaught - $aux
            if($progress -lt 0){ $progress = 0 }
            Write-CL "  Hauls since the promise: $progress / $($Q.Need)" "Cyan"
            if($progress -ge $Q.Need){
                Write-Host ""
                if($Q.Id -eq "term_line"){
                    Write-CL "  Quay weighs the haul on dockside scales older than the" "Gray"
                    Write-CL "  province and stamps the manifest PROVISIONED." "Gray"
                    Write-CL "  'Five good fish. Tonight's departures eat like arrivals.'" "Yellow"
                    $script:Gold += 300
                    [void]$script:Inventory.Add(@{Name="Dragon Tooth"; Value=65; Tier=3; Kind="Loot"; Weight=3})
                    Add-SkillXP "Fishing" 150
                    Grant-XP 150
                    Write-CL "  *** Quest complete! (+300g, +1 Dragon Tooth, technique) ***" "Magenta"
                } else {
                    Write-CL "  Weir inspects your hands like they are the catch." "Gray"
                    Write-CL "  'One at a time. You understand the falls now.'" "Yellow"
                    $script:Gold += 200
                    [void]$script:Inventory.Add(@{Name="Ruby Chunk"; Value=40; Tier=2; Kind="Loot"; Weight=2})
                    Add-SkillXP "Fishing" 150
                    Write-CL "  *** Quest complete! (+200g, +1 Ruby Chunk, technique) ***" "Magenta"
                }
                Set-QuestStage $Q.Id 999999
            }
        }
    }
    Write-Host ""
    Wait-Enter
}

# ── Phase 6: FISHING (Cat 14, v2) ──────────────────────────────────
# Real-time minigame on the LOCKPICK's proven conventions:
#   * [Console]::KeyAvailable first (reports KEY-DOWNS only — never
#     blocks); RawUI fallback reads with IncludeKeyDown,IncludeKeyUp
#     so ReadKey can never stall on a stale key-up (the v1 hang).
#   * Cursor-home frame redraws (no Clear-Host flicker), hidden
#     cursor during animation, fixed-width padded lines.
# Flow: cast → animated wait (2-4.8s) → STRIKE splash → reaction
# window (500ms + 50ms per Fishing LEVEL). Early press snaps the line.
# 3 casts per game-day; rare gear via the __fishing exclusive rows.
function Show-FishingMinigame {
    if($script:FishCastDay -ne $script:GameDay){
        $script:FishCastDay = $script:GameDay
        $script:FishCastsToday = 0
    }
    $LINE_W = 72
    function fish-Pad([string]$s){
        if($s.Length -ge $LINE_W){ return $s.Substring(0, $LINE_W) }
        return $s + (' ' * ($LINE_W - $s.Length))
    }
    function fish-Home {
        try {
            $z = New-Object System.Management.Automation.Host.Coordinates(0,0)
            $Host.UI.RawUI.CursorPosition = $z
        } catch {
            try { [Console]::SetCursorPosition(0,0) } catch { Clear-Host }
        }
    }
    # TRUE when a fresh KEY-DOWN was consumed. Never blocks: Console
    # KeyAvailable only sees key-downs; the RawUI fallback includes
    # key-ups in the read filter so ReadKey always has something to
    # return, and we count only .KeyDown records as presses.
    function fish-GetKey {
        try {
            if([Console]::KeyAvailable){ $null = [Console]::ReadKey($true); return $true }
        } catch {}
        try {
            if($Host.UI.RawUI.KeyAvailable){
                $rk = $Host.UI.RawUI.ReadKey('NoEcho,IncludeKeyDown,IncludeKeyUp')
                if($rk.KeyDown){ return $true }
            }
        } catch {}
        return $false
    }
    # Consume EVERYTHING queued (downs and ups), hard-capped so it can
    # never spin — this replaces the v1 drain that could block.
    function fish-Drain {
        for($dz = 0; $dz -lt 60; $dz++){
            $any = $false
            try { if([Console]::KeyAvailable){ $null = [Console]::ReadKey($true); $any = $true } } catch {}
            if(-not $any){
                try {
                    if($Host.UI.RawUI.KeyAvailable){
                        $null = $Host.UI.RawUI.ReadKey('NoEcho,IncludeKeyDown,IncludeKeyUp')
                        $any = $true
                    }
                } catch {}
            }
            if(-not $any){ break }
        }
    }
    $waveBase = '~ ~~~ ~~ ~ ~~ ~~~~ ~ ~~ ~~~ ~~ ~~~~ ~ ~~ ~~ ~~~ ~ ~~~~ ~~ ~ ~~ ~~~ ~~ ~ ~~ ~~~ ~~ ~'
    function fish-SetChar([string]$s, [int]$x, [string]$c){
        if($x -lt 0 -or $x -ge $s.Length){ return $s }
        return $s.Substring(0, $x) + $c + $s.Substring($x + $c.Length)
    }
    # One animation frame. State: 'wait' (bobbing), 'strike' (splash),
    # 'hit' (hauling), 'snap' (early), 'lost' (missed window).
    function fish-Frame([int]$ph, [string]$state, [int]$tier, [int]$castsLeft){
        fish-Home
        $bobX = 34
        Write-Host (fish-Pad "  ── F I S H I N G ──   Lv$(Get-SkillLevel 'Fishing')   casts left: $castsLeft") -ForegroundColor Cyan
        Write-Host (fish-Pad '') 
        # v1.6.2 art pass: sky, a pier to stand on, deeper water.
        Write-Host (fish-Pad '      .-~~-.              .--~~--.                       .-~~~-.') -ForegroundColor DarkGray
        $sky1 = ' ' * $LINE_W
        $sky2 = ' ' * $LINE_W
        $rodTip = '\_'
        $sky1 = fish-SetChar $sky1 ($bobX + 14) '__'
        $sky1 = fish-SetChar $sky1 ($bobX + 16) $rodTip
        $sky2 = fish-SetChar $sky2 ($bobX + 12) '_/'
        switch($state){
            'strike' {
                $sky1 = fish-SetChar $sky1 ($bobX - 1) '!'
                $sky2 = fish-SetChar $sky2 ($bobX - 3) '! ! !'
            }
            'hit' {
                $sky2 = fish-SetChar $sky2 ($bobX - 2) '><(('
            }
            default {
                $sky2 = fish-SetChar $sky2 $bobX '|'
            }
        }
        Write-Host (fish-Pad $sky1) -ForegroundColor DarkYellow
        Write-Host (fish-Pad $sky2) -ForegroundColor DarkYellow
        Write-Host (fish-Pad ('  ' + [string][char]0x2550 * 12 + [string][char]0x2566 + [string][char]0x2550 * 6 + [string][char]0x2566 + [string][char]0x2550 * 4)) -ForegroundColor DarkYellow
        # Three water rows, phase-shifted for motion
        $w1 = $waveBase.Substring(($ph) % 8,        $LINE_W)
        $w2 = $waveBase.Substring(($ph + 3) % 8,    $LINE_W)
        $w3 = $waveBase.Substring(($ph + 6) % 8,    $LINE_W)
        switch($state){
            'wait'   {
                if(($ph % 4) -lt 2){ $w1 = fish-SetChar $w1 $bobX 'o' }
                else               { $w2 = fish-SetChar $w2 $bobX 'O' }
            }
            'strike' { $w1 = fish-SetChar $w1 ($bobX - 1) '\O/' }
            'hit'    { $w1 = fish-SetChar $w1 ($bobX - 1) '\o>' }
            'snap'   { $w1 = fish-SetChar $w1 ($bobX - 1) '-x-' }
            'lost'   { $w2 = fish-SetChar $w2 $bobX '.' }
        }
        Write-Host (fish-Pad $w1) -ForegroundColor Cyan
        Write-Host (fish-Pad $w2) -ForegroundColor DarkCyan
        Write-Host (fish-Pad $w3) -ForegroundColor DarkBlue
        $w4 = $waveBase.Substring(($ph + 1) % 8, $LINE_W)
        $w4 = fish-SetChar $w4 2 ')('
        $w4 = fish-SetChar $w4 ($LINE_W - 6) ')('
        Write-Host (fish-Pad $w4) -ForegroundColor DarkBlue
        $msg = switch($state){
            'wait'   { '  Line settled. When it STRIKES, press [SPACE] to reel in!' }
            'strike' { '  !!! S T R I K E !!!  [SPACE] NOW!' }
            'hit'    { '  Hooked! Hauling it in...' }
            'snap'   { '  Too early — the line snaps back, empty.' }
            'lost'   { '  It spits the hook. The pond ripples, smug.' }
        }
        $msgCol = switch($state){
            'strike' { 'Yellow' } 'hit' { 'Green' } 'wait' { 'Gray' } default { 'DarkGray' }
        }
        Write-Host (fish-Pad $msg) -ForegroundColor $msgCol
    }
    $fishLoop = $true
    while($fishLoop){
        clr
        Write-Host ""
        Write-CL "  ── F I S H I N G ──" "Cyan"
        $tier = Get-SkillTier "Fishing"
        $castsLeft = 3 - $script:FishCastsToday
        Write-CL "  Fishing Lv$(Get-SkillLevel 'Fishing')   Casts left today: $castsLeft" "DarkGray"
        Write-Host ""
        if($castsLeft -le 0){
            Write-CL "  The water has had enough of you for one day." "DarkGray"
            Write-Host ""
            Wait-Enter
            return
        }
        Write-CL "  When the bobber STRIKES, press [SPACE] to reel in." "DarkGray"
        Write-CL "  (Any key works — but pressing early snaps the line!)" "DarkGray"
        Write-Host ""
        Write-CL "  [1] Cast a line   [0] Leave" "Yellow"
        Write-C  "  > " "Yellow"
        $fc = Read-Host
        if($fc -ne "1"){ return }
        $script:FishCastsToday++
        $castsLeft = 3 - $script:FishCastsToday
        # ── Animated cast ──
        try { $fishCursorWas = [Console]::CursorVisible } catch { $fishCursorWas = $true }
        try { [Console]::CursorVisible = $false } catch {}
        Clear-Host
        fish-Drain
        $dur = Get-Random -Min 2000 -Max 4801
        $sw = [System.Diagnostics.Stopwatch]::StartNew()
        $ph = 0
        $outcome = ''
        while($sw.ElapsedMilliseconds -lt $dur){
            fish-Frame $ph 'wait' $tier $castsLeft
            if(fish-GetKey){ $outcome = 'snap'; break }
            Start-Sleep -Milliseconds 110
            $ph++
        }
        if($outcome -eq ''){
            # ── STRIKE: reaction window, splash pulsing while we poll ──
            fish-Drain
            # User tuning: 500ms base + 50ms per Fishing LEVEL (not
            # tier) — novices need reflexes; Lv50 anglers get ~3s.
            $window = 500 + (50 * (Get-SkillLevel "Fishing"))
            $sw.Restart()
            $hit = $false
            while($sw.ElapsedMilliseconds -lt $window){
                fish-Frame $ph 'strike' $tier $castsLeft
                if(fish-GetKey){ $hit = $true; break }
                Start-Sleep -Milliseconds 90
                $ph++
            }
            $outcome = if($hit){'hit'}else{'lost'}
        }
        # Result flourish: a few frames of the outcome state
        for($fz = 0; $fz -lt 5; $fz++){
            fish-Frame $ph $outcome $tier $castsLeft
            Start-Sleep -Milliseconds 130
            $ph++
        }
        try { [Console]::CursorVisible = $fishCursorWas } catch {}
        clr
        Write-Host ""
        if($outcome -eq 'snap'){
            Write-CL "  You strike at nothing. The line snaps back, empty." "DarkGray"
            Add-SkillXP "Fishing" 2
        }
        elseif($outcome -eq 'lost'){
            Write-CL "  It spits the hook and is gone. The pond ripples, smug." "DarkGray"
            Add-SkillXP "Fishing" 3
        }
        else {
            # ── The catch (odds/rewards unchanged from v1) ──
            $script:TotalFishCaught++
            $roll = Get-Random -Max 100
            if($roll -lt (8 + $tier)){
                $rares = @()
                foreach($ex in (Get-ExclusiveStock)){ if($ex.Loc -eq "__fishing" -or ($ex.Loc -eq "__fishing50" -and (Get-SkillLevel "Fishing") -ge 50)){ $rares += $ex } }
                $pick = ($rares | Get-Random).Item
                $caught = @{}
                foreach($k in $pick.Keys){ $caught[$k] = $pick[$k] }
                $caught.Kind = if($caught.WeaponType){"Weapon"}else{"Armor"}
                $caught = Init-ItemDurability $caught
                [void]$script:Inventory.Add($caught)
                Write-CL "  The water heaves — and yields IRON." "Cyan"
                Write-CL "  *** You haul up the $($caught.Name)! ***" "Magenta"
                Add-SkillXP "Fishing" 15
            }
            elseif($roll -lt 40){
                if(-not $script:Ingredients){ $script:Ingredients = @{} }
                if(-not $script:Ingredients.ContainsKey("Meat")){ $script:Ingredients["Meat"] = 0 }
                $script:Ingredients["Meat"]++
                Write-CL "  A fat pond fish. The cooking pot will approve. (+1 Meat)" "Green"
                Add-SkillXP "Fishing" 10
            }
            elseif($roll -lt 70){
                $g = Get-Random -Min 15 -Max 41
                $script:Gold += $g
                Write-CL "  A snagged coin purse, still knotted. (+${g}g)" "Yellow"
                Add-SkillXP "Fishing" 8
            }
            else {
                $script:Gold += 3
                Write-CL "  A boot. A single, ancient boot. You sell it to the" "DarkGray"
                Write-CL "  concept of boots for 3g." "DarkGray"
                Add-SkillXP "Fishing" 5
            }
        }
        Write-Host ""
        Wait-Enter
    }
}

