function Draw-LocationArt {
    param([string]$Id)
    $artL = @(Get-LocationArt $Id)
    if($artL.Count -eq 0){ return }
    Write-Host ""
    foreach($ln in $artL){ Write-CL "        $($ln.T)" $ln.C }
    Write-Host ""
}

