# ── Phase 6 chunk 2: EXCLUSIVE STOCK ───────────────────────────────
# Location-only items (locked decision: travel incentive). This table
# is ***APPEND-ONLY***: save indices 1000+ reference positions here,
# exactly like shop positions — reordering or deleting entries
# corrupts existing saves. Weapons/armor only (market potions are an
# inline table and the bag liquidates on save anyway).
function Get-ExclusiveStock {
    @(
        @{ Loc="kernelhold"; Item=@{Name="Kernel Blade";      ATK=16; Price=1400; WeaponType="Sword";  ClassAffinity="Knight"; AffinityBonus=3; Perk="Stun";  PerkChance=10} }
        @{ Loc="bashford";   Item=@{Name="One-Liner";         ATK=12; Price=700;  WeaponType="Dagger"; ClassAffinity="Thief";  AffinityBonus=3; Perk="Bleed"; PerkChance=15} }
        @{ Loc="registry";   Item=@{Name="Archivist's Ward";  Slot="Shield"; DEF=13; Price=950}  }
        @{ Loc="sysv";       Item=@{Name="Golem-Core Plate";  Slot="Chest";  DEF=16; Price=1500} }
        @{ Loc="terminus";   Item=@{Name="Longshore Greaves"; Slot="Boots";  DEF=9;  Price=600}  }
        @{ Loc="cachegrove"; Item=@{Name="Cachewoven Cap";    Slot="Helmet"; DEF=8;  Price=500}  }
        # Fishing rares (Phase 6): pseudo-location "__fishing" never
        # matches a real shop, but the 1000+ save-index scan finds
        # these by name — caught gear survives save/load for free.
        @{ Loc="__fishing";  Item=@{Name="Drowned Blade";     ATK=14; Price=900; WeaponType="Sword"; ClassAffinity="None"; AffinityBonus=0; Perk="Drain"; PerkChance=12} }
        @{ Loc="__fishing";  Item=@{Name="Barnacled Ward";    Slot="Shield"; DEF=12; Price=800} }
        # Guild questline rewards (Phase 6): pseudo-loc "__guild" —
        # never sold; the 1000+ index scan persists them once granted.
        @{ Loc="__guild";    Item=@{Name="Firewall Plate";           Slot="Chest";  DEF=17; Price=1600} }
        @{ Loc="__guild";    Item=@{Name="Whisperstep Boots";        Slot="Boots";  DEF=8;  Price=700}  }
        @{ Loc="__guild";    Item=@{Name="Grimoire of Forgotten Code"; Slot="Amulet"; DEF=6; Price=900}  }
        # Faction vendors (wave 2): pseudo-locs "__rp"/"__dm" — sold only
        # by faction contacts at HONORED standing; the 1000+ name scan
        # persists purchases like any exclusive. APPEND-ONLY still applies.
        @{ Loc="__rp";       Item=@{Name="Sigkill";         ATK=15; Price=1200; WeaponType="Dagger"; ClassAffinity="Thief"; AffinityBonus=3; Perk="Stun";  PerkChance=12} }
        @{ Loc="__rp";       Item=@{Name="Orphan's Cloak";  Slot="Chest";  DEF=13; Price=1000} }
        @{ Loc="__dm";       Item=@{Name="Deep Query Rod";  ATK=11; Price=1100; WeaponType="Staff";  ClassAffinity="Mage";  AffinityBonus=3; Perk="Drain"; PerkChance=12; MAGBonus=11} }
        @{ Loc="__dm";       Item=@{Name="Indexer's Visor"; Slot="Helmet"; DEF=9;  Price=800}  }
        # Faction questline signatures: pseudo-loc "__faction" — never
        # sold; granted at the questline finale, persisted by name scan.
        @{ Loc="__faction";  Item=@{Name="Runaway's Signet";   Slot="Amulet"; DEF=6; Price=900} }
        @{ Loc="__faction";  Item=@{Name="Prospector's Charm"; Slot="Amulet"; DEF=6; Price=900} }
        # Master Crafting (Cat 11): pseudo-loc "__craft" — forged in the
        # Blacksmith's back room at Blacksmithing 50, never sold. The 1000+
        # name scan persists them once equipped. APPEND-ONLY still applies.
        # (Nullforged Bulwark is deliberately NOT in the weight-class map
        # — a smith-forged shield defaults Heavy, as intended.)
        @{ Loc="__craft";    Item=@{Name="Hotpatch";           ATK=17; Price=1500; WeaponType="Sword"; ClassAffinity="None"; AffinityBonus=0; Perk="Burn"; PerkChance=12} }
        @{ Loc="__craft";    Item=@{Name="Nullforged Bulwark"; Slot="Shield"; DEF=14; Price=1000} }
        # Fishing 50 milestone (Cat 11): pseudo-loc "__fishing50" joins the
        # rare-catch pool only at Fishing Lv50 (amulet — weight-exempt).
        @{ Loc="__fishing50"; Item=@{Name="Leviathan-Scale Charm"; Slot="Amulet"; DEF=7; Price=1000} }
    )
}

# Location-aware shop lists — used ONLY by Show-Market's browse and
# purchase flow. Save/load and loot tables stay on the base tables.
function Get-WeaponShopHere {
    $list = @(Get-WeaponShop)
    foreach($ex in (Get-ExclusiveStock)){
        if($ex.Loc -eq $script:CurrentLocation -and $ex.Item.WeaponType){
            $it = @{}
            foreach($k in $ex.Item.Keys){ $it[$k] = $ex.Item[$k] }
            $it.Exclusive = $true
            $list += $it
        }
    }
    return $list
}
function Get-ArmorShopHere {
    $list = @(Get-ArmorShop)
    foreach($ex in (Get-ExclusiveStock)){
        if($ex.Loc -eq $script:CurrentLocation -and $ex.Item.Slot){
            $it = @{}
            foreach($k in $ex.Item.Keys){ $it[$k] = $ex.Item[$k] }
            $it.Exclusive = $true
            $list += $it
        }
    }
    return $list
}

function Get-WorldLocation {
    param([string]$Id)
    foreach($wl in (Get-WorldLocations)){ if($wl.Id -eq $Id){ return $wl } }
    return $null
}

