function Get-TierGlyph {
    param([string]$Tier)
    switch($Tier){
        "City" { "◆" }
        "Hub"  { "◆" }
        "Town" { "■" }
        "Camp" { "▲" }
        default { "†" }
    }
}
function Get-TierColor {
    param([string]$Tier)
    switch($Tier){
        "City" { "Yellow" }
        "Hub"  { "Green" }
        "Town" { "White" }
        "Camp" { "DarkYellow" }
        default { "Magenta" }
    }
}

# Renders the province map with the location list baked over terrain.
# $SelectedId gets a Cyan highlight and > < brackets around its name.
function Draw-WorldMap {
    param([string]$SelectedId)
    $art = Get-WorldMapArt
    $locs = Get-WorldLocations
    $W = 78
    # Build char + color grids
    $chars = @(); $cols = @()
    foreach($row in $art){
        $rowC = $row.PadRight($W).Substring(0, $W).ToCharArray()
        $rowK = New-Object string[] $W
        for($x = 0; $x -lt $W; $x++){
            $rowK[$x] = switch([string]$rowC[$x]){
                '~' { "DarkBlue" }
                '*' { "DarkGreen" }
                '.' { "DarkGray" }
                '^' { "Gray" }
                default { "DarkGray" }
            }
        }
        $chars += ,$rowC
        $cols  += ,$rowK
    }
    # Bake locations: glyph + name (name goes left of glyph near the
    # right edge so nothing clips off the map)
    foreach($wl in $locs){
        $sel = ($wl.Id -eq $SelectedId)
        $gCol = if($sel){"Cyan"}else{ Get-TierColor $wl.Tier }
        $y = [int]$wl.Y; $x = [int]$wl.X
        if($y -lt 0 -or $y -ge $chars.Count){ continue }
        $chars[$y][$x] = [char](Get-TierGlyph $wl.Tier)
        $cols[$y][$x] = $gCol
        $label = if($sel){">$($wl.Name)<"}else{$wl.Name}
        $nCol = if($sel){"Cyan"}else{ Get-TierColor $wl.Tier }
        if($x -gt 56){
            $start = $x - 1 - $label.Length
        } else {
            $start = $x + 2
        }
        for($i = 0; $i -lt $label.Length; $i++){
            $px = $start + $i
            if($px -ge 0 -and $px -lt $W){
                $chars[$y][$px] = $label[$i]
                $cols[$y][$px] = $nCol
            }
        }
    }
    # Render rows as color runs
    for($y = 0; $y -lt $chars.Count; $y++){
        Write-C "  " "DarkGray"
        $runStart = 0
        for($x = 1; $x -le $W; $x++){
            if($x -eq $W -or $cols[$y][$x] -ne $cols[$y][$runStart]){
                $seg = -join $chars[$y][$runStart..($x-1)]
                Write-C $seg $cols[$y][$runStart]
                $runStart = $x
            }
        }
        Write-Host ""
    }
}

# Travel time: straight-line distance over the map grid, ~1-3 days.
function Get-TravelDays {
    param($FromLoc, $ToLoc)
    $dx = [double]($FromLoc.X - $ToLoc.X)
    $dy = [double]($FromLoc.Y - $ToLoc.Y) * 2.2   # rows are taller than cols
    $dist = [math]::Sqrt($dx*$dx + $dy*$dy)
    return [math]::Max(1, [int][math]::Round($dist / 22.0))
}

# One travel day on the road: the day turns, the calendar applies,
# and the road rolls an encounter — hostile, kind, or just miles.
# Returns $true to keep traveling, $false if the trip was cut short
# (player death-rescue). Locked decision (flagged to user): road
# defeat is SOFTER than dungeon death — a passing caravan drags you
# back to your origin at 1 HP, -15% gold, +5 Corruption. The Depths
# remain the place that takes things from you properly.
function Invoke-TravelDay {
    param($FromLoc)
    $script:GameDay++
    Write-Host ""
    Write-CL "  Day $($script:GameDay) on the road..." "DarkYellow"
    Announce-RadiantEvent
    $roll = Get-Random -Max 100
    if($roll -lt 25){
        # ── Hostile ambush: 1-2 road enemies, event-biased ──
        Write-Host ""
        Write-CL "  Movement in the treeline — an AMBUSH!" "Red"
        Start-Sleep -Milliseconds 600
        $pool = @("Goblin","Thief","Skeleton","Zombie","Troll")
        $spawnLvl = Get-ScaledEnemyLevel -PlayerLevel $script:PlayerLevel -Role "Regular"
        # Faction assassins (Phase 6): HUNTED standing means the road
        # itself is hostile — 40% of ambushes are hired knives.
        $assassinFaction = ""
        foreach($fk in @("RogueProcesses","DataMiners")){
            if((Get-FactionRep $fk) -le -20 -and (Get-Random -Max 100) -lt 40){ $assassinFaction = $fk; break }
        }
        if($assassinFaction){
            $fShort = if($assassinFaction -eq "RogueProcesses"){"Rogue Process"}else{"Data Miner"}
            Write-CL "  Not bandits — hired knives. The $fShort kind." "Red"
            Write-CL "  You were warned. They do not send letters." "DarkGray"
            $foes = @()
            $nAssassins = if((Get-Random -Max 100) -lt 35){2}else{1}
            for($ai = 0; $ai -lt $nAssassins; $ai++){
                $assn = New-Enemy "Thief" $spawnLvl
                $assn.Name = "$fShort Assassin"
                $assn.ATK  = [math]::Floor($assn.ATK * 1.2)
                $assn.SPD  = $assn.SPD + 2
                $assn.XP   = [math]::Floor($assn.XP * 1.3)
                $foes += $assn
            }
        } else {
        $foes = @( (New-Enemy (Get-EventBiasedType $pool) $spawnLvl) )
        if((Get-Random -Max 100) -lt 35){
            $foes += (New-Enemy (Get-EventBiasedType $pool) $spawnLvl)
        }
        }
        $result = Start-Combat $foes
        if($result.Result -eq "Death"){
            clr
            Write-Host ""
            Write-CL "  ── Darkness. Then wheel-creak. ──" "DarkGray"
            Write-Host ""
            Write-CL "  A passing caravan finds you face-down at the milestone" "Gray"
            Write-CL "  and hauls you back to $($FromLoc.Name). Their fee comes" "Gray"
            Write-CL "  out of your purse. Their silence comes free." "Gray"
            $fee = [math]::Floor($script:Gold * 0.15)
            $script:Gold = [math]::Max(0, $script:Gold - $fee)
            $script:Player.HP = 1
            Add-Corruption 5
            Write-Host ""
            Write-CL "  (-${fee}g. You live. The road remembers.)" "Red"
            $script:CurrentLocation = $FromLoc.Id
            Write-Host ""
            Wait-Enter
            return $false
        }
        return $true
    }
    elseif($roll -lt 40){
        # ── Kindness on the road ──
        Write-Host ""
        switch(Get-Random -Max 5){
            0 {
                $heal = [math]::Floor($script:Player.MaxHP * 0.25)
                $mana = [math]::Floor($script:Player.MaxMP * 0.25)
                $script:Player.HP = [math]::Min($script:Player.HP + $heal, $script:Player.MaxHP)
                $script:Player.MP = [math]::Min($script:Player.MP + $mana, $script:Player.MaxMP)
                Write-CL "  A pilgrim shares her fire and a blessing over your" "Gray"
                Write-CL "  wounds. (+$heal HP, +$mana MP)" "Green"
            }
            1 {
                $found = Get-Random -Min 20 -Max 61
                $script:Gold += $found
                Write-CL "  A collapsed courier satchel by the road. No owner in" "Gray"
                Write-CL "  sight — and ${found}g inside. (+${found}g)" "Yellow"
            }
            2 {
                $pot = Get-PotionShop | Where-Object { $_.Category -ne "Special" } | Get-Random
                $price = [math]::Floor($pot.Price * 0.6)
                Write-CL "  A wandering trader flags you down: '$($pot.Name)," "Gray"
                Write-CL "  road price — ${price}g. Everything's cheaper when" "Gray"
                Write-CL "  you're the one carrying it.'" "Gray"
                Write-C  "  Buy? (y/n) > " "Yellow"
                $buy = Read-Host
                # v1.6.2: every outcome answers — a yes that failed on
                # gold or belt space used to read as him just leaving.
                if(($buy -eq "y" -or $buy -eq "Y") -and $script:Gold -lt $price){
                    Write-CL "  'Come back richer, friend.' (you need ${price}g)" "DarkYellow"
                } elseif(($buy -eq "y" -or $buy -eq "Y") -and $script:Potions.Count -ge 10){
                    Write-CL "  'Your belt's full, friend.' (potion belt 10/10)" "DarkYellow"
                } elseif(($buy -eq "y" -or $buy -eq "Y") -and $script:Gold -ge $price -and $script:Potions.Count -lt 10){
                    $script:Gold -= $price
                    # Clone with bag fields — shop templates lack Kind/Weight.
                    $potItem = @{}
                    foreach($pk in $pot.Keys){ $potItem[$pk] = $pot[$pk] }
                    $potItem.Kind = "Potion"; $potItem.Weight = 1
                    [void]$script:Potions.Add($potItem)
                    Write-CL "  Deal struck. ($($pot.Name), -${price}g)" "Green"
                } else {
                    Write-CL "  He shrugs and walks on, whistling." "DarkGray"
                }
            }
            3 {
                # ── Road quest-giver (recovered doc): a traveler can hand
                # you an unstarted town quest right here on the highway.
                $openQ = @()
                foreach($rqLoc in @("backupvale","bashford","cronmarch","nullhaven","foreachfalls","cachegrove","firewallkeep","syslogxing","kernelhold","registry","terminus","sysv")){
                    $rq = Get-TownQuest $rqLoc
                    if($rq -and (Get-QuestStage $rq.Id) -eq 0){ $openQ += @{Loc=$rqLoc; Q=$rq} }
                }
                if($openQ.Count -eq 0){
                    Write-CL "  A tinker nods as she passes. Nothing needs saying." "Gray"
                } else {
                    $pickQ = $openQ | Get-Random
                    $rqTown = (Get-WorldLocation $pickQ.Loc).Name
                    Write-CL "  A traveler shares your milestone for a rest, and gossip:" "Gray"
                    Write-CL "  '$($pickQ.Q.Giver) over in $rqTown is paying for help —" "Yellow"
                    Write-CL "   the job's called $($pickQ.Q.Name), I hear.'" "Yellow"
                    Write-CL "  [1] Take the job here and now   [Enter] Just gossip" "Cyan"
                    Write-C  "  > " "Yellow"
                    if((Read-Host) -eq "1"){
                        $rqAux = switch($pickQ.Q.Type){
                            "Kill"    { [int]$script:TotalKills }
                            "Fish"    { [int]$script:TotalFishCaught }
                            "Deliver" { [int]$script:GameDay + [int]$pickQ.Q.Days }
                            "Clear"   { [int]$script:DungeonsCleared }
                            default   { 0 }
                        }
                        Set-QuestStage $pickQ.Q.Id (100000 + $rqAux)
                        Write-CL "  *** Quest accepted on the road: $($pickQ.Q.Name) ***" "Magenta"
                        Write-CL "  (Turn in with $($pickQ.Q.Giver) in $rqTown.)" "DarkGray"
                    } else {
                        Write-CL "  Gossip it stays. The traveler moves on." "DarkGray"
                    }
                }
            }
            default {
                Write-CL "  Good weather, dry boots, and no tickets filed against" "Gray"
                Write-CL "  you anywhere in the world. It won't last. Enjoy it." "DarkGray"
            }
        }
        Start-Sleep -Milliseconds 400
        return $true
    }
    elseif($roll -lt 50){
        # ── Faction crossroads (Phase 6): the road makes you pick sides ──
        Write-Host ""
        if((Get-Random -Max 2) -eq 0){
            Write-CL "  A ragged process flags you down, clutching a satchel of" "Gray"
            Write-CL "  scheduling tokens — Data Miner claim-tags still on them." "Gray"
            Write-CL "  'They were MINE first. Look away. Please.'" "Yellow"
            Write-CL "  [1] Let it run   [2] Flag it for the Miners bounty post   [Enter] Walk on" "Cyan"
            Write-C  "  > " "Yellow"
            $fchoice = Read-Host
            if($fchoice -eq "1"){
                Write-CL "  It vanishes into the hedgerow, tokens and all." "Gray"
                Add-FactionRep "RogueProcesses" 8
                Add-FactionRep "DataMiners" -4
            } elseif($fchoice -eq "2"){
                Write-CL "  You note its heading on a claim slip. The bounty post" "Gray"
                Write-CL "  pays finders on the spot. (+40g)" "Gray"
                $script:Gold += 40
                Add-FactionRep "DataMiners" 8
                Add-FactionRep "RogueProcesses" -4
            } else {
                Write-CL "  Not your dispute. The road goes on." "DarkGray"
            }
        } else {
            Write-CL "  A Data Miner rig sits axle-deep in mud, core samples" "Gray"
            Write-CL "  spilling across the road — unindexed memories. Somebody's." "Gray"
            Write-CL "  The prospector waves: 'A hand? Or at least not a boot?'" "Yellow"
            Write-CL "  [1] Help re-rack the samples   [2] Discreetly free a few   [Enter] Walk on" "Cyan"
            Write-C  "  > " "Yellow"
            $fchoice = Read-Host
            if($fchoice -eq "1"){
                Write-CL "  An hour of careful lifting. The prospector logs your name" "Gray"
                Write-CL "  under ASSETS, which is apparently a compliment." "Gray"
                Add-FactionRep "DataMiners" 8
                Add-FactionRep "RogueProcesses" -4
            } elseif($fchoice -eq "2"){
                Write-CL "  A few samples roll free into the ditchwater and dissolve," "Gray"
                Write-CL "  looking, somehow, relieved." "Gray"
                Add-FactionRep "RogueProcesses" 8
                Add-FactionRep "DataMiners" -4
            } else {
                Write-CL "  Not your dispute. The road goes on." "DarkGray"
            }
        }
        Write-Host ""
        Wait-Enter
        return $true
    }
    else {
        $flavor = @(
            "Milestones drift past. The road hums its one long note."
            "A crow paces you for a mile, then loses interest."
            "You pass a shrine to some forgotten protocol. You nod anyway."
            "Cart tracks, boot prints, and one set of prints that stop mid-road."
            "Distant hills. Distant weather. Distant everything."
            "The road forks, reconsiders, and merges with itself again."
        ) | Get-Random
        Write-CL "  $flavor" "DarkGray"
        Start-Sleep -Milliseconds 400
        return $true
    }
}

function Travel-To {
    param([string]$DestId)
    $from = Get-WorldLocation $script:CurrentLocation
    $dest = Get-WorldLocation $DestId
    if(-not $from -or -not $dest){ return }
    $days = Get-TravelDays $from $dest
    clr
    Write-Host ""
    Write-CL "  ── The road to $($dest.Name) — $days day(s) ──" "Yellow"
    for($td = 1; $td -le $days; $td++){
        if(-not (Invoke-TravelDay $from)){ return }   # rescued home
    }
    $script:CurrentLocation = $dest.Id
    Write-Host ""
    Write-CL "  You arrive at $($dest.Name)." "Green"
    Write-CL "  $($dest.Blurb)" "DarkGray"
    Write-Host ""
    Wait-Enter
}

function Show-WorldMap {
    $locs = @(Get-WorldLocations | Sort-Object { [int]$_.X })
    # Start selection on the current location
    $sel = 0
    for($i = 0; $i -lt $locs.Count; $i++){
        if($locs[$i].Id -eq $script:CurrentLocation){ $sel = $i; break }
    }
    $mapLoop = $true
    while($mapLoop){
        clr
        Write-CL "  ╔══════════════════════════════════════════════════════════════════════════════╗" "DarkYellow"
        Write-CL "  ║                 P R O V I N C E   O F   P R O D U C T I O N                  ║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════════════════╝" "DarkYellow"
        Draw-WorldMap -SelectedId $locs[$sel].Id
        $cur = $locs[$sel]
        $here = if($cur.Id -eq $script:CurrentLocation){" (you are here)"}else{""}
        Write-C  "  ◆ " (Get-TierColor $cur.Tier)
        Write-C  "$($cur.Name)" "Cyan"
        Write-CL " — $($cur.Tier)$here" "DarkGray"
        Write-CL "  $($cur.Blurb)" "Gray"
        if($cur.Id -ne $script:CurrentLocation){
            $fromLoc = Get-WorldLocation $script:CurrentLocation
            $dTrip = Get-TravelDays $fromLoc $cur
            Write-CL "  Travel time: $dTrip day(s)" "DarkYellow"
        }
        Write-Host ""
        Write-CL "  [A]/[D] browse · type a name to find it · [T] travel · [0] back" "DarkGray"
        Write-C  "  > " "Yellow"
        $mk = Read-Host
        switch($mk.ToUpper()){
            "A" { $sel = ($sel - 1 + $locs.Count) % $locs.Count }
            "D" { $sel = ($sel + 1) % $locs.Count }
            "T" {
                if($locs[$sel].Id -ne $script:CurrentLocation){
                    Travel-To $locs[$sel].Id
                    $mapLoop = $false
                }
            }
            "0" { $mapLoop = $false }
            default {
                # Type-to-select (user request): case-insensitive name
                # match, exact first, then prefix, then substring — so
                # "frost" finds Frostfang Mts and "sys" finds Sys-V
                # before Syslog Crossing only if typed exactly. Two-char
                # minimum keeps stray keys from jumping the cursor.
                # (Mouse clicks: recorded as an optional experiment —
                # needs Win32 ReadConsoleInput via Add-Type, fragile
                # across terminals; A/D + typing cover selection.)
                if($mk -and $mk.Trim().Length -ge 2){
                    $q = $mk.Trim().ToLower()
                    $found = -1
                    for($i = 0; $i -lt $locs.Count; $i++){
                        if($locs[$i].Name.ToLower() -eq $q){ $found = $i; break }
                    }
                    if($found -lt 0){
                        for($i = 0; $i -lt $locs.Count; $i++){
                            if($locs[$i].Name.ToLower().StartsWith($q)){ $found = $i; break }
                        }
                    }
                    if($found -lt 0){
                        for($i = 0; $i -lt $locs.Count; $i++){
                            if($locs[$i].Name.ToLower().Contains($q)){ $found = $i; break }
                        }
                    }
                    if($found -ge 0){ $sel = $found }
                }
            }
        }
    }
}

# One menu round at a non-hub location. The MainMenu loop re-enters
# this every iteration while CurrentLocation != helpdesk; traveling
# (or arriving home) changes CurrentLocation and the loop re-routes.
function Show-LocationVisit {
    $loc = Get-WorldLocation $script:CurrentLocation
    if(-not $loc){ $script:CurrentLocation = "helpdesk"; return }
    $p = $script:Player
    $svcMap = @()
    Check-QuestArrival
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════════════════╗" "DarkYellow"
    $lnPad = [math]::Max([math]::Floor((78 - $loc.Name.Length) / 2), 0)
    Write-C  "  ║" "DarkYellow"
    Write-C ((" " * $lnPad) + $loc.Name + (" " * (78 - $lnPad - $loc.Name.Length))) (Get-TierColor $loc.Tier)
    Write-CL "║" "DarkYellow"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════════════════╝" "DarkYellow"
    Write-CL "  $($loc.Blurb)" "Gray"
    Draw-LocationArt $loc.Id
    Write-C  "  Day $($script:GameDay)   HP $($p.HP)/$($p.MaxHP)   MP $($p.MP)/$($p.MaxMP)   Gold $($script:Gold)g" "DarkGray"
    $hdrCrCol = if($script:Corruption -ge 60){"Red"}elseif($script:Corruption -ge 25){"DarkYellow"}else{"DarkGray"}
    Write-CL "   Corruption $($script:Corruption)" $hdrCrCol
    Announce-RadiantEvent
    Write-Host ""
    if($loc.Kind -eq "Statue"){
        Write-CL "  [1] Make an offering (50g or 1 gem) — blessing for your next dive" "Magenta"
    }
    elseif($loc.Kind -eq "Pond"){
        Write-CL "  [1] Cast a line (3 casts a day — rare gear is down there)" "Cyan"
    }
    elseif($loc.Kind -eq "Ruin"){
        Write-CL "  [1] Study the carvings" "DarkGray"
    }
    else {
        Write-CL "  [1] Rest by the fire (free — heals half, the day may turn)" "Green"
        # Services (Phase 6 chunk 2): not every location has every
        # service (locked decision) — the list comes from the data.
        if($loc.Services){
            $svcN = 2
            foreach($svc in $loc.Services){
                $svcLabel = switch($svc){
                    "Market"    { "Visit the market" }
                    "Inn"       { "The inn — paid rest & cooking" }
                    "Smith"     { "The blacksmith" }
                    "Enchanter" { "The enchanter" }
                    "Pond"      { if($loc.Id -eq "terminus"){"Fish off the docks"}else{"Fish below the falls"} }
                }
                Write-CL "  [$svcN] $svcLabel" "Cyan"
                $svcMap += $svc
                $svcN++
            }
        }
    }
    $raidCfg = (Get-RaidThemes)[$loc.Id]
    if($raidCfg){
        Write-CL "  [D] $($raidCfg.Label)" "Red"
    }
    # Story trail marker (Phase 6): the [!] appears where the trail IS.
    $mqHere = Get-CurrentMainQuest
    $mqSt = Get-MainStage
    if($mqHere -and ($mqSt % 10) -eq 0 -and $mqSt -gt 0 -and $mqHere.Where -eq $loc.Id){
        Write-CL "  [!] STORY: the trail is HERE." "Red"
    }
    $tq = Get-TownQuest $loc.Id
    if($tq){
        $tqStage = Get-QuestStage $tq.Id
        if($tqStage -eq 0){
            Write-CL "  [Q] $($tq.Giver) wants a word..." "Magenta"
        } elseif($tqStage -lt 999999){
            Write-CL "  [Q] Quest: $($tq.Name) (in progress)" "Magenta"
        }
    }
    $fc = Get-FactionContactHere $loc.Id
    if($fc){
        Write-CL "  [F] $($fc.Who) — $($fc.Title)" $fc.Color
    }
    Write-CL "  [W] World map / travel" "Yellow"
    Write-CL "  [H] Head home to Helpdesk" "DarkYellow"
    Write-C  "  > " "Yellow"
    $lk = Read-Host
    switch($lk.ToUpper()){
        "1" {
            Write-Host ""
            if($loc.Kind -eq "Statue"){
                $gemNames = @("Gem Shard","Ruby Chunk","Enchanted Dust","Shadow Gem")
                $haveGem = $null
                foreach($gn in $gemNames){ if((Get-GemCount $gn) -ge 1){ $haveGem = $gn; break } }
                if($script:ActiveFoodBuff){
                    Write-CL "  A blessing already clings to you ($($script:ActiveFoodBuff.Name))." "DarkGray"
                    Write-CL "  Offer anyway and replace it? (y/n)" "Yellow"
                    Write-C "  > " "Yellow"
                    if((Read-Host) -notmatch '^[Yy]$'){ return }
                }
                if($script:Gold -ge 50){
                    $script:Gold -= 50
                    Write-CL "  You leave 50g at the base. The stone is warmer than it should be." "Gray"
                }
                elseif($haveGem){
                    Remove-Gems $haveGem 1
                    Write-CL "  You leave your $haveGem at the base. It sinks in slightly." "Gray"
                }
                else {
                    Write-CL "  You have nothing worthy to offer. The statue does not judge." "DarkGray"
                    Write-CL "  (It absolutely judges.)" "DarkGray"
                    Wait-Enter
                    return
                }
                $script:ActiveFoodBuff = @{Name="Blessing of $($loc.Name)"; Effect=$loc.Buff; Value=[int]$loc.BuffVal}
                Write-Host ""
                Write-CL "  *** Blessing of $($loc.Name) received! ***" "Magenta"
                Write-CL "  (It carries into your next dungeon dive.)" "DarkGray"
            }
            elseif($loc.Kind -eq "Pond"){
                Show-FishingMinigame
            }
            elseif($loc.Kind -eq "Ruin"){
                Write-CL "  You copy a fragment of the carvings into your notes. It" "Gray"
                Write-CL "  almost parses. Almost." "DarkGray"
            }
            else {
                $heal = [math]::Floor($p.MaxHP * 0.5)
                $mana = [math]::Floor($p.MaxMP * 0.5)
                $p.HP = [math]::Min($p.HP + $heal, $p.MaxHP)
                $p.MP = [math]::Min($p.MP + $mana, $p.MaxMP)
                Write-CL "  You rest by the fire. (+$heal HP, +$mana MP)" "Green"
                if($script:RestedOnDay -ne $script:GameDay){
                    $script:GameDay++
                    $script:RestedOnDay = $script:GameDay
                    Write-CL "  A new day dawns. (Day $($script:GameDay))" "DarkGray"
                    Announce-RadiantEvent
                }
            }
            Write-Host ""
            Wait-Enter
        }
        "D" {
            if($raidCfg){
                # Clone the config so SavedLevel never sticks to the
                # static theme table.
                $script:RaidTheme = @{}
                foreach($rk in $raidCfg.Keys){ $script:RaidTheme[$rk] = $raidCfg[$rk] }
                Enter-Dungeon
            }
        }
        "!" { Show-StoryQuest -Context $loc.Id }
        "Q" { if($tq){ Show-TownQuest $loc $tq } }
        "F" { if($fc){ Show-FactionContact $fc } }
        "W" { Show-WorldMap }
        "H" { Travel-To "helpdesk" }
        default {
            $svcPick = 0
            if([int]::TryParse($lk, [ref]$svcPick) -and $svcPick -ge 2 -and ($svcPick - 2) -lt $svcMap.Count){
                switch($svcMap[$svcPick - 2]){
                    "Market"    { Show-Market }
                    "Inn"       { Show-Inn }
                    "Smith"     { Show-Blacksmith }
                    "Enchanter" { Show-EnchanterScreen }
                    "Pond"      { Show-FishingMinigame }
                }
            }
        }
    }
}

# ── Phase 6 chunk 2: THE INN, extracted verbatim from the town
# switch so remote settlements can offer it too.
# IMPORTANT: bare 'continue' statements inside this body rely on
# PowerShell's DYNAMICALLY-SCOPED continue — they bubble up to the
# CALLER's loop (the town loop, or the MainMenu loop when visiting a
# remote location), preserving the original one-action-then-back
# flow in both contexts. Do not wrap this body in its own loop
# without auditing every continue.
function Show-Inn {
    $p = $script:Player
                clr
                Write-Host ""
                # 52-char-wide banner
                Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
                Write-CL "  ║          T H E   W E A R Y   L A N T E R N      ║" "Yellow"
                Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
                Write-Host ""
                # Hanging lantern (original art from v1.2)
                Write-CL "              _.._" "DarkYellow"
                Write-CL "            .' .-'``." "Yellow"
                Write-CL "           /  /      \" "Yellow"
                Write-CL "           |  |  0  ||" "DarkYellow"
                Write-CL "           \  \     /" "Yellow"
                Write-CL "            '._'-._'" "DarkYellow"
                Write-CL "               |  |" "DarkGray"
                Write-CL "             __|__|__" "DarkGray"
                Write-CL "            |________|" "DarkGray"
                Write-Host ""

                $p = $script:Player
                $hpMissing = $p.MaxHP - $p.HP
                $mpMissing = $p.MaxMP - $p.MP

                # Stats box (interior 44 chars)
                $sBar = "─" * 44
                Write-CL "  ┌$sBar┐" "DarkGray"
                $line1 = "Current HP: $($p.HP)/$($p.MaxHP)"
                $pad1 = 42 - $line1.Length
                if($pad1 -lt 0){$pad1=0}
                Write-C  "  │ " "DarkGray"; Write-C $line1 "Green"; Write-CL ("$(' ' * $pad1) │") "DarkGray"
                $line2 = "Current MP: $($p.MP)/$($p.MaxMP)"
                $pad2 = 42 - $line2.Length
                if($pad2 -lt 0){$pad2=0}
                Write-C  "  │ " "DarkGray"; Write-C $line2 "Cyan"; Write-CL ("$(' ' * $pad2) │") "DarkGray"
                $line3 = "Gold: $($script:Gold)g"
                $pad3 = 42 - $line3.Length
                if($pad3 -lt 0){$pad3=0}
                Write-C  "  │ " "DarkGray"; Write-C $line3 "Yellow"; Write-CL ("$(' ' * $pad3) │") "DarkGray"
                Write-CL "  └$sBar┘" "DarkGray"
                Write-Host ""

                if($p.HP -eq $p.MaxHP -and $p.MP -eq $p.MaxMP){
                    # Player is fully rested. Greet them about that, but
                    # still let them use the cooking pot — cooking is
                    # independent of rest. Rest options will fast-fail
                    # with a friendly "you look rested" line.
                    Write-CL "  The innkeeper looks at you:" "DarkGray"
                    Write-CL "  'You look well rested already, friend!'" "Yellow"
                    Write-CL "  '...but the cooking pot is always available, if you've brought ingredients.'" "DarkGray"
                } else {
                    Write-CL "  The innkeeper greets you warmly:" "DarkGray"
                    Write-CL "  'Welcome, weary traveler! What'll it be?'" "Yellow"
                }
                Write-Host ""
                # Menu box (interior 54 chars). Each line: " [N] Label<pad>-  DetailText<pad-end> │"
                $mBar = "─" * 54
                $options = @(
                    @{N="[1]"; Label="Quick Nap";    Color="Green";    Detail="15g  (50% HP/MP)"}
                    @{N="[2]"; Label="Full Rest";    Color="Cyan";     Detail="30g  (100% HP/MP)"}
                    @{N="[3]"; Label="Royal Suite";  Color="Magenta";  Detail="60g  (Full + ATK/DEF)"}
                    @{N="[C]"; Label="Cooking Pot";  Color="Yellow";   Detail="Cook ingredients into food"}
                )
                # Town upgrade (Phase 4e): sold here until owned.
                if(-not $script:TownUpgrades["Inn"]){
                    $options += @{N="[U]"; Label="Feather Beds"; Color="Magenta"; Detail="2 Rune+1 Horn (+2 DEF rests)"}
                }
                $options += @{N="[0]"; Label="Leave"; Color="DarkGray"; Detail=""}
                Write-CL "  ┌$mBar┐" "DarkGray"
                foreach($opt in $options){
                    $head    = " $($opt.N) $($opt.Label)"
                    $headPad = 22 - $head.Length
                    if($headPad -lt 1){$headPad = 1}
                    $det = [string]$opt.Detail
                    $midSep  = if($det){"-  "}else{"   "}
                    $midLen  = 3
                    $tailLen = 54 - $head.Length - $headPad - $midLen - $det.Length - 1
                    if($tailLen -lt 0){
                        # v1.6.2: an over-long detail used to push the
                        # right border out and break the box (Cooking
                        # Pot, Feather Beds). Truncate to fit instead.
                        $det = $det.Substring(0, $det.Length + $tailLen)
                        $tailLen = 0
                    }

                    Write-C "  │" "DarkGray"
                    Write-C " $($opt.N)" "White"
                    Write-C " $($opt.Label)" $opt.Color
                    Write-C (" " * $headPad) "Black"
                    if($det){
                        Write-C $midSep "DarkGray"
                        Write-C $det "White"
                    } else {
                        Write-C (" " * $midLen) "Black"
                    }
                    Write-C (" " * $tailLen) "Black"
                    Write-CL " │" "DarkGray"
                }
                Write-CL "  └$mBar┘" "DarkGray"
                Write-Host ""
                Write-C "  > " "Yellow"; $restChoice = Read-Host

                # If the player is at full HP/MP, the three rest options
                # are no-ops. Bail out early with a flavor line so they
                # don't waste gold on a heal that does nothing. The
                # cooking pot ([C]) and leave ([0]) bypass this check.
                $playerFull = ($p.HP -eq $p.MaxHP -and $p.MP -eq $p.MaxMP)
                # Blighted Plague (Cat 12): the beds are quarantined.
                # Cooking ([C]) and the upgrade ([U]) stay available.
                if((Get-ActiveRadiantEvent) -eq "Plague" -and ($restChoice -eq "1" -or $restChoice -eq "2" -or $restChoice -eq "3")){
                    Write-Host ""
                    Write-CL "  A notice is nailed over the stairs: QUARANTINE BY" "Red"
                    Write-CL "  ORDER OF THE PLAGUE WARDEN. The innkeeper shrugs:" "Red"
                    Write-CL "  'Beds are closed till the blight passes. Pot's on, though.'" "Yellow"
                    Wait-Key
                    continue
                }
                if($playerFull -and ($restChoice -eq "1" -or $restChoice -eq "2" -or $restChoice -eq "3")){
                    Write-Host ""
                    Write-CL "  'You're already in fighting shape, friend.'" "Yellow"
                    Write-CL "  '(Try the cooking pot if you've got ingredients.)'" "DarkGray"
                    Wait-Key
                    continue
                }

                switch($restChoice){
                        "U" {
                            Write-Host ""
                            if($script:TownUpgrades["Inn"]){
                                Write-CL "  'Beds are already feathered, friend.'" "DarkGray"
                            } elseif((Get-GemCount "Ancient Rune") -lt 2 -or (Get-GemCount "Demon Horn") -lt 1){
                                Write-CL "  'Two ancient runes and a demon horn. The runes" "DarkGray"
                                Write-CL "   go in the frames; the horn... trade secret.'" "DarkGray"
                            } else {
                                Remove-Gems "Ancient Rune" 2
                                Remove-Gems "Demon Horn" 1
                                $script:TownUpgrades["Inn"] = $true
                                Write-CL "  The innkeeper stuffs the mattresses with something" "Yellow"
                                Write-CL "  that shimmers. 'Best sleep this side of the Depths.'" "Yellow"
                                Write-Host ""
                                Write-CL "  *** Paid rests now leave you Well Rested (+2 DEF)! ***" "Magenta"
                            }
                            Wait-Key
                        }
                        "1" {
                            $cost = [int][math]::Ceiling(15 * (Get-ShopDiscount))
                            if($script:Gold -ge $cost){
                                $script:Gold -= $cost
                                $healAmt = [math]::Floor($p.MaxHP * 0.5)
                                $manaAmt = [math]::Floor($p.MaxMP * 0.5)
                                $p.HP = [math]::Min($p.HP + $healAmt, $p.MaxHP)
                                $p.MP = [math]::Min($p.MP + $manaAmt, $p.MaxMP)
                                Write-Host ""
                                Write-CL "  You take a quick nap on a straw bed..." "DarkGray"
                                Write-CL "  zzz..." "DarkCyan"
                                Start-Sleep -Milliseconds 800
                                Write-CL "  zzzZZZ..." "Cyan"
                                Start-Sleep -Milliseconds 800
                                Write-Host ""
                                Write-CL "  Recovered $healAmt HP and $manaAmt MP! (${cost}g)" "Green"
                                Write-CL "  HP: $($p.HP)/$($p.MaxHP)  MP: $($p.MP)/$($p.MaxMP)" "White"
                                if($script:RestedOnDay -ne $script:GameDay){
                                    $script:GameDay++
                                    $script:RestedOnDay = $script:GameDay
                                    Write-CL "  A new day dawns. (Day $($script:GameDay))" "DarkGray"
                                    Announce-RadiantEvent
                                } else {
                                    Write-CL "  (The day is still young — resting again won't pass time.)" "DarkGray"
                                }
                                # Feather Beds (Phase 4e): grant Well Rested unless
                                # a cooked meal is active (never clobber real food).
                                if($script:TownUpgrades["Inn"] -and -not $script:ActiveFoodBuff){
                                    $script:ActiveFoodBuff = @{Name="Well Rested"; Effect="DEFBoost"; Value=2}
                                    Write-CL "  The feather bed leaves you Well Rested. (+2 DEF)" "Green"
                                }
                            } else {
                                Write-CL "  'Sorry friend, no coin, no pillow.'" "Red"
                            }
                            Wait-Key
                        }
                        "2" {
                            $cost = [int][math]::Ceiling(30 * (Get-ShopDiscount))
                            if($script:Gold -ge $cost){
                                $script:Gold -= $cost
                                $p.HP = $p.MaxHP
                                $p.MP = $p.MaxMP
                                Write-Host ""
                                Write-CL "  You settle into a comfortable bed... (${cost}g)" "DarkGray"
                                Write-CL "  zzz..." "DarkCyan"
                                Start-Sleep -Milliseconds 600
                                Write-CL "  zzzZZZ..." "Cyan"
                                Start-Sleep -Milliseconds 600
                                Write-CL "  ZZZZZZ..." "White"
                                Start-Sleep -Milliseconds 600
                                Write-Host ""
                                Write-CL "  Fully restored! HP: $($p.MaxHP)/$($p.MaxHP)  MP: $($p.MaxMP)/$($p.MaxMP)" "Green"
                                if($script:RestedOnDay -ne $script:GameDay){
                                    $script:GameDay++
                                    $script:RestedOnDay = $script:GameDay
                                    Write-CL "  A new day dawns. (Day $($script:GameDay))" "DarkGray"
                                    Announce-RadiantEvent
                                } else {
                                    Write-CL "  (The day is still young — resting again won't pass time.)" "DarkGray"
                                }
                                # Feather Beds (Phase 4e): grant Well Rested unless
                                # a cooked meal is active (never clobber real food).
                                if($script:TownUpgrades["Inn"] -and -not $script:ActiveFoodBuff){
                                    $script:ActiveFoodBuff = @{Name="Well Rested"; Effect="DEFBoost"; Value=2}
                                    Write-CL "  The feather bed leaves you Well Rested. (+2 DEF)" "Green"
                                }
                            } else {
                                Write-CL "  'Sorry friend, no coin, no pillow.'" "Red"
                            }
                            Wait-Key
                        }
                        "3" {
                            $cost = [int][math]::Ceiling(60 * (Get-ShopDiscount))
                            if($script:RoyalSuiteUses -ge 3){
                                Write-CL "  'You've enjoyed our finest rooms before...'" "DarkGray"
                                Write-CL "  'The enchantments no longer affect you, friend.'" "DarkGray"
                                Write-CL "  (Royal Suite stat boost capped at 3 uses)" "DarkYellow"
                                # No Wait-Key here — the outer one at the end
                                # of case "3" handles the prompt. Two Wait-Keys
                                # in a row was producing a doubled "press any
                                # key" prompt for the maxed-out player.
                            }
                            elseif($script:Gold -ge $cost){
                                $script:Gold -= $cost
                                $p.HP = $p.MaxHP
                                $p.MP = $p.MaxMP
                                Write-Host ""
                                Write-CL "  You sink into a luxurious feather bed... (${cost}g)" "DarkGray"
                                Write-CL "  A warm bath, fine wine, enchanted candles..." "DarkMagenta"
                                Start-Sleep -Milliseconds 600
                                Write-CL "  zzz..." "DarkCyan"
                                Start-Sleep -Milliseconds 600
                                Write-CL "  zzzZZZ..." "Cyan"
                                Start-Sleep -Milliseconds 600
                                Write-CL "  ZZZZZZ..." "White"
                                Start-Sleep -Milliseconds 800
                                Write-Host ""
                                Write-CL "  You awaken feeling POWERFUL!" "Yellow"
                                if($script:RestedOnDay -ne $script:GameDay){
                                    $script:GameDay++
                                    $script:RestedOnDay = $script:GameDay
                                    Write-CL "  A new day dawns. (Day $($script:GameDay))" "DarkGray"
                                    Announce-RadiantEvent
                                } else {
                                    Write-CL "  (The day is still young — resting again won't pass time.)" "DarkGray"
                                }
                                # Feather Beds (Phase 4e): grant Well Rested unless
                                # a cooked meal is active (never clobber real food).
                                if($script:TownUpgrades["Inn"] -and -not $script:ActiveFoodBuff){
                                    $script:ActiveFoodBuff = @{Name="Well Rested"; Effect="DEFBoost"; Value=2}
                                    Write-CL "  The feather bed leaves you Well Rested. (+2 DEF)" "Green"
                                }
                                Write-Host ""

                                $p.ATK += 3
                                $p.DEF += 3
                                $script:RoyalSuiteUses++
                                Write-CL "  Fully restored! HP: $($p.MaxHP)/$($p.MaxHP)  MP: $($p.MaxMP)/$($p.MaxMP)" "Green"
                                Write-CL "  ATK +3 and DEF +3 from the enchanted rest!" "Magenta"
                                Write-CL "  (Permanent stat boost!)" "DarkMagenta"
                            } else {
                                Write-CL "  'The royal suite requires deeper pockets, friend.'" "Red"
                            }
                            Wait-Key
                        }
                        {$_ -in @("C","c")} { Show-CookingStation }
                        "0" { }
                        default { }
                    }
}

function Show-MainMenu {
    while($script:GameRunning){
        # World map (Phase 6): away from the hub, the town screen is
        # replaced by the location visit. Travel changes CurrentLocation
        # and this branch re-routes on the next iteration.
        if($script:CurrentLocation -ne "helpdesk"){
            Show-LocationVisit
            continue
        }
        # ── Reset daily dungeon flag if the day changed ──
        $today = (Get-Date).ToString("yyyy-MM-dd")
        if($script:DailyDungeonDate -ne $today){
            $script:DailyDungeonDate = $today
            $script:DailyDungeonDone = $false
        }
        clr
        $p = $script:Player
        Write-Host ""
        # ── Town banner (aligned 83-char box, matching action grid width) ──
        Write-CL "  ╔═════════════════════════════════════════════════════════════════════════════════╗" "DarkYellow"
        Write-CL "  ║                              T O W N   S Q U A R E                              ║" "Yellow"
        Write-CL "  ║            The settlement of Helpdesk — last stop before the Depths             ║" "DarkYellow"
        Write-CL "  ╚═════════════════════════════════════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""
        # ASCII skyline of the town (user-provided)
        Write-CL '                                         .                                       ' "DarkGray"
        Write-CL '                                        /|\                                      ' "DarkGray"
        Write-CL '                                       / | \                                     ' "DarkGray"
        Write-CL '                   .                  /  |  \            .                       ' "DarkGray"
        Write-CL '                  /|\        _       /___|___\          /|\                      ' "DarkGray"
        Write-CL '                 / | \      |~|      |  |_|  |         / | \                     ' "DarkGray"
        Write-CL '                /  |  \     |.|   _  | |   | |    _   /  |  \                    ' "DarkGray"
        Write-CL '     .    *    /___|___\   /| |\  |~|| |___| |   |~| /___|___\                   ' "DarkGray"
        Write-CL '    /|\  /|\  |  _   _ |  |   | |.|||_______||   |.||  _   _ |                   ' "DarkGray"
        Write-CL '   / | \/ | \ | |_| |_||  |___|_|  ||   |   ||  /| || |_| |_||                   ' "DarkGray"
        Write-CL '  /__|_/__|__\| |       | |       | ||   |   || |   || |     ||                  ' "DarkGray"
        Write-CL ' |    |    |  | |  ___  | |  ___  | ||  _|_  || |___|| | ___ ||    /\            ' "DarkGray"
        Write-CL ' |____|____|__| | |   | | | |   | | || |   | ||_____|| ||   |||   /  \           ' "DarkGray"
        Write-CL ' |  |    |  | | | |___| | | |___| | || |___| ||  |  || ||___|||  / /\ \          ' "DarkGray"
        Write-CL ' |  | [] |  | | |_______| |_______| ||_______||  |  || |_____|| / /  \ \         ' "DarkGray"
        Write-CL ' |  |    |  | |_|  |||  |_|  |||  |_||  |||  ||  |  ||_|  |  ||/ / [] \ \        ' "DarkGray"
        Write-CL ' |__|____|__| |  |_|||__|  |_|||__|  ||__|||__||__|__||  |_|__||_/______\_\      ' "DarkGray"
        Write-CL ' |  |    |  | |    |||  |    |||  |  ||  |||  ||  |  ||   |   ||    ||   |      ' "DarkGray"
        Write-CL '_|__|____|__|_|____|||||_|____|||||__|_|__||||_||__|__|_|__|___|_|__||___|_     ' "DarkGray"
        Write-CL '   ~      ~    ^^  ~~ ~  ~~ ^^ ~~  ~  ^^  ~~   ~~  ^^ ~    ~~    ^^   ~~        ' "DarkBlue"
        Write-Host ""

        # ── Debug-mode banner ──
        # Only renders when the run was started via the splash-menu dev
        # passphrase. Bright green so it can't be missed; the wording
        # also explains why Save Game is disabled.
        if($script:DebugMode){
            Write-CL "                          [Debug Mode Active — Save Disabled]                       " "Green"
            Write-Host ""
        }
        if($script:DutchmanMode){
            Write-CL "                       [Flying Dutchman Mode — Save Disabled]                       " "Magenta"
            Write-Host ""
        }

        # ── Player status block (83-char width matching banner/grid) ──
        $hpPct = $p.HP / $p.MaxHP
        $hpColor = if($hpPct -gt 0.5){"Green"}elseif($hpPct -gt 0.25){"Yellow"}else{"Red"}
        Write-CL "  ╔═════════════════════════════════════════════════════════════════════════════════╗" "DarkCyan"
        Write-C  "  ║  " "DarkCyan"
        Write-C "$($p.Name)" "Green"
        Write-C "  Lv$($script:PlayerLevel)" "Yellow"
        Write-C "  Day $($script:GameDay)" "DarkYellow"
        # Corruption counter (v1.6.1): ALWAYS visible — 0 is information
        # too (a calm world trades kindly; see Get-PriceMul).
        $crTag = "  Corruption $($script:Corruption)"
        $crCol = if($script:Corruption -ge 60){"Red"}elseif($script:Corruption -ge 25){"DarkYellow"}else{"DarkGray"}
        Write-C $crTag $crCol
        $evInfo = Get-RadiantEventInfo
        $evTag = ""
        if($evInfo){
            $evTag = "  $($evInfo.Name)"
            Write-C $evTag $evInfo.Color
        }
        $topLine = "$($p.Name)  Lv$($script:PlayerLevel)  Day $($script:GameDay)$crTag$evTag"
        $pad1 = 79 - $topLine.Length
        if($pad1 -lt 0){$pad1=0}
        Write-CL ("$(' ' * $pad1)║") "DarkCyan"

        Write-C  "  ║  " "DarkCyan"
        Write-C "HP: " "White"
        Write-C "$($p.HP)/$($p.MaxHP)" $hpColor
        Write-C "   MP: " "White"
        Write-C "$($p.MP)/$($p.MaxMP)" "Cyan"
        Write-C "   Gold: " "White"
        Write-C "$($script:Gold)g" "Yellow"
        Write-C "   XP: " "White"
        Write-C "$($script:XP)/$($script:XPToNext)" "DarkCyan"
        $statLine = "HP: $($p.HP)/$($p.MaxHP)   MP: $($p.MP)/$($p.MaxMP)   Gold: $($script:Gold)g   XP: $($script:XP)/$($script:XPToNext)"
        $pad2 = 79 - $statLine.Length
        if($pad2 -lt 0){$pad2=0}
        Write-CL ("$(' ' * $pad2)║") "DarkCyan"

        $streakTxt = if($script:Streak -gt 0){"Streak: $($script:Streak)x"}else{""}
        Write-C  "  ║  " "DarkCyan"
        Write-C "Dungeons Cleared: $($script:DungeonLevel)" "DarkGray"
        $dungLine = "Dungeons Cleared: $($script:DungeonLevel)"
        if($streakTxt){
            Write-C "   " "DarkCyan"
            Write-C $streakTxt "Yellow"
            $dungLine += "   $streakTxt"
        }
        $achCount = $script:Achievements.Count
        $totalAch = (Get-AchievementList).Count
        Write-C "   Achievements: " "DarkGray"
        Write-C "$achCount/$totalAch" "Magenta"
        $dungLine += "   Achievements: $achCount/$totalAch"
        $pad3 = 79 - $dungLine.Length
        if($pad3 -lt 0){$pad3=0}
        Write-CL ("$(' ' * $pad3)║") "DarkCyan"
        Write-CL "  ╚═════════════════════════════════════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""

        # ── Action grid: fixed 2-column layout, each column 40 chars wide ──
        # Total box width = 2 + 40 + 1 + 40 = 83 chars
        $colW = 40
        $hbar = "═" * $colW
        Write-CL "  ╔$hbar╦$hbar╗" "DarkGray"

        # First row: Enter Dungeon / Daily Dungeon
        $leftCell  = " [1] Enter Dungeon"
        $dtxt = if($script:DailyDungeonDone){" (DONE)"}else{" (2x rewards!)"}
        $rightCell = " [2] Daily Dungeon$dtxt"
        $lPad = $colW - $leftCell.Length
        if($lPad -lt 0){$lPad=0}
        $rPad = $colW - $rightCell.Length
        if($rPad -lt 0){$rPad=0}
        Write-C "  ║" "DarkGray"
        Write-C " [1]" "Green"; Write-C " Enter Dungeon" "White"
        Write-C ("$(' ' * $lPad)║") "DarkGray"
        Write-C " [2]" "Green"; Write-C " Daily Dungeon" "White"
        $dtxtColor = if($script:DailyDungeonDone){"DarkGray"}else{"Yellow"}
        Write-C $dtxt $dtxtColor
        Write-CL ("$(' ' * $rPad)║") "DarkGray"

        Write-CL "  ╠$hbar╬$hbar╣" "DarkGray"

        # New Game+ row content shifts by readiness. Before 25 clears the
        # row reads as a progress nudge; once eligible it becomes a clear
        # call-to-action so the player can't miss it.
        # NOTE: Descriptions must fit a 40-char column with ~22 chars
        # reserved for "[N] Label". That leaves ~17 chars for the desc.
        # v1.6.2: the [N] handler has gated on STORY COMPLETION since
        # the Final Migration shipped — this row still advertised the
        # dead 25-clears rule and lied to anyone who finished early.
        $ngReady = ((Get-QuestStage "msq") -ge 999)
        $ngLabel = if($ngReady){"New Game+ READY!"}else{"New Game+"}
        $ngDesc  = if($ngReady){"Ascend the Depths"}else{"Finish the story"}
        $ngColor = if($ngReady){"Magenta"}else{"DarkMagenta"}

        $rows = @(
            @( @{N="[3]";L="Visit the Market";   C="Cyan";       Desc="Buy & sell gear"},
               @{N="[4]";L="View Inventory";     C="Magenta";    Desc="Manage loot & gear"} ),
            @( @{N="[5]";L="Weary Lantern Inn";  C="Yellow";     Desc="Recover/Cook"},
               @{N="[6]";L="Training Grounds";   C="Red";        Desc="Hone your skills"} ),
            @( @{N="[7]";L="Quest Board";        C="DarkYellow"; Desc="Accept bounties"},
               @{N="[8]";L="Guild Hall";         C="Green";      Desc="Hire companions"} ),
            @( @{N="[9]";L="View Stats";         C="White";      Desc="Abilities & gear"},
               @{N="[A]";L="Achievements";       C="DarkMagenta";Desc="Review milestones"} ),
            @( @{N="[B]";L="Bestiary";           C="DarkRed";    Desc="Creatures defeated"},
               @{N="[S]";L="Save Game";          C="DarkGreen";  Desc="Export save code"} ),
            @( @{N="[N]";L=$ngLabel;             C=$ngColor;     Desc=$ngDesc},
               @{N="[O]";L="Options";            C="Cyan";       Desc="Game settings"} ),
            # v1.6.2: the story moved to the Quest Board's [!] — one
            # home for all quests. The town's "!" hotkey still works
            # as a hidden shortcut (the switch case remains).
            @( @{N="[W]";L="World Map";          C="Yellow";     Desc="Travel the land"},
               @{N="[T]";L="Tutorial";           C="DarkCyan";   Desc="Replay the basics"} ),
            @( @{N="[Q]";L="Quit";               C="DarkRed";    Desc="Leave the town"},
               @{N=""   ;L="";                   C="DarkGray";   Desc=""} )
        )
        # Cell layout inside each column:
        #   " [N] Label" + spaces_to_labelW + "Desc" + padding_to_colW
        $labelW = 22  # width reserved for "[N] Label" part including leading space
        foreach($r in $rows){
            $l = $r[0]; $rg = $r[1]

            $lLabel = " $($l.N) $($l.L)"           # e.g. " [3] Visit the Market"
            $lDesc  = $l.Desc
            $lSpace = $labelW - $lLabel.Length
            if($lSpace -lt 1){$lSpace = 1}
            $lUsed  = $lLabel.Length + $lSpace + $lDesc.Length
            $lTail  = $colW - $lUsed
            if($lTail -lt 0){$lTail = 0}

            $rLabel = " $($rg.N) $($rg.L)"
            $rDesc  = $rg.Desc
            $rSpace = $labelW - $rLabel.Length
            if($rSpace -lt 1){$rSpace = 1}
            $rUsed  = $rLabel.Length + $rSpace + $rDesc.Length
            $rTail  = $colW - $rUsed
            if($rTail -lt 0){$rTail = 0}

            Write-C "  ║" "DarkGray"
            Write-C " $($r[0].N)" $r[0].C
            Write-C " $($r[0].L)" "White"
            Write-C (" " * $lSpace) "Black"
            Write-C $lDesc "DarkGray"
            Write-C (" " * $lTail) "Black"
            Write-C "║" "DarkGray"

            Write-C " $($r[1].N)" $r[1].C
            Write-C " $($r[1].L)" "White"
            Write-C (" " * $rSpace) "Black"
            Write-C $rDesc "DarkGray"
            Write-C (" " * $rTail) "Black"
            Write-CL "║" "DarkGray"
        }
        Write-CL "  ╚$hbar╩$hbar╝" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $ch = Read-Host

        # Re-map choices to match old indices where logic is already correct
        # Old: 1=Dungeon 2=Market 3=Inventory 4=Rest 5=Stats 6=Quest 7=Guild 8=Quit 9=Save
        # New:
        #   1 => Dungeon           (was 1)
        #   2 => Daily Dungeon     (new)
        #   3 => Market            (was 2)
        #   4 => Inventory         (was 3)
        #   5 => Rest/Inn          (was 4)
        #   6 => Training Grounds  (new)
        #   7 => Quest Board       (was 6)
        #   8 => Guild Hall        (was 7)
        #   9 => Stats             (was 5)
        #   A => Achievements      (new)
        #   S => Save              (was 9)
        #   Q => Quit              (was 8)
        # PowerShell hash literals are case-insensitive, so we only need one entry per key.
        # Normalize single-letter inputs to upper-case before lookup.
        $map = @{
            "1" = "1"; "2" = "D"; "3" = "2"; "4" = "3"; "5" = "4"
            "6" = "T"; "7" = "6"; "8" = "7"; "9" = "5"
            "A" = "A"
            "S" = "9"
            "Q" = "8"
            # v1.6.2: letter T = replay the tutorial. The INTERNAL
            # code "T" (Training Grounds, reached by digit 6) is
            # unaffected — map lookup happens before passthrough.
            "T" = "TUT"
        }
        $chKey = if($ch){$ch.ToUpper()}else{""}
        $routed = if($map.ContainsKey($chKey)){$map[$chKey]}else{$ch}

        switch($routed){
            "TUT" {
                Show-Tutorial
            }
            "1" {
                if(Test-Encumbered){
                    $cur = Get-CurrentCarryWeight
                    $max = Get-MaxCarryWeight $script:Player
                    clr
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
                    Write-CL "  ║              T O O   E N C U M B E R E D                ║" "Red"
                    Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
                    Write-Host ""
                    Write-CL "  You're carrying $cur weight (max $max)." "Yellow"
                    Write-CL "  Sell loot at the Market or visit Inventory to drop items." "Gray"
                    Write-Host ""
                    Wait-Key
                } else {
                    Show-MutatorChoice
                    Enter-Dungeon
                }
            }
            "D" {
                # Daily dungeon: Enter-Dungeon with double rewards flag
                if(Test-Encumbered){
                    $cur = Get-CurrentCarryWeight
                    $max = Get-MaxCarryWeight $script:Player
                    clr
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkRed"
                    Write-CL "  ║              T O O   E N C U M B E R E D                ║" "Red"
                    Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkRed"
                    Write-Host ""
                    Write-CL "  You're carrying $cur weight (max $max)." "Yellow"
                    Write-CL "  The Daily herald frowns at your overloaded pack." "DarkGray"
                    Write-Host ""
                    Wait-Key
                    continue
                }
                $today = (Get-Date).ToString("yyyy-MM-dd")
                if($script:DailyDungeonDate -ne $today){
                    # Reset daily for new day
                    $script:DailyDungeonDate = $today
                    $script:DailyDungeonDone = $false
                }
                if($script:DailyDungeonDone){
                    clr
                    Write-CL "  The herald nods." "Gray"
                    Write-CL "  'You've already braved the Daily Dungeon today. Return tomorrow.'" "Yellow"
                    Wait-Key
                } else {
                    Show-MutatorChoice
                    $script:DailyDungeonActive = $true
                    Enter-Dungeon
                    $script:DailyDungeonActive = $false
                }
            }
            "2" { Show-Market }
            "3" { Show-InventoryScreen }



            "4" { Show-Inn }

            "5" {
                clr
                $p2 = $script:Player
                $wAtk = Get-TotalWeaponATK
                $aDef = Get-TotalArmorDEF
                $mBonus = Get-WeaponMAGBonus
                $cb = Get-WeaponClassBonus

                Write-CL "  ╔══════════════════════════════════════════════════╗" "Cyan"
                Write-CL "  ║  $($p2.Name) - Level $($script:PlayerLevel)" "Cyan"
                Write-CL "  ╚══════════════════════════════════════════════════╝" "Cyan"
                Write-Host ""

                # ── Core Stats ──
                Write-CL "  ── STATS ──" "Yellow"
                Write-C "  HP:  $($p2.HP) / $($p2.MaxHP)" "Green"
                Write-CL "     MP:  $($p2.MP) / $($p2.MaxMP)" "Cyan"
                Write-Host ""

                $atkTotal = $p2.ATK + $wAtk
                $defTotal = $p2.DEF + $aDef
                $magTotal = $p2.MAG + $mBonus

                # Training-derived bonuses (already baked into $p2.STAT, but show breakdown)
                # Per Show-TrainingGrounds: ATK +2, DEF +2, SPD +1, MAG +2, HP +10, MP +5 per pt
                $tp = $script:TrainingPoints
                $trnATK = if($tp){$tp.ATK * 2}else{0}
                $trnDEF = if($tp){$tp.DEF * 2}else{0}
                $trnSPD = if($tp){$tp.SPD * 1}else{0}
                $trnMAG = if($tp){$tp.MAG * 2}else{0}

                Write-C "  ATK: $($p2.ATK)" "White"
                if($trnATK -gt 0){ Write-C " (+$trnATK trn)" "Magenta" }
                if($wAtk -gt 0){
                    Write-C " + $wAtk wpn" "DarkCyan"
                    if($cb -gt 0){ Write-C " ($cb class)" "Green" }
                }
                Write-CL "  = $atkTotal total" "Yellow"

                Write-C "  DEF: $($p2.DEF)" "White"
                if($trnDEF -gt 0){ Write-C " (+$trnDEF trn)" "Magenta" }
                if($aDef -gt 0){ Write-C " + $aDef armor" "DarkCyan" }
                Write-CL "  = $defTotal total" "Yellow"

                # v1.6.1: SPD breakdown matches ATK/DEF — LightArmor
                # skill, set bonus, and companion are real initiative
                # speed, so the sheet now shows the same effective
                # number combat uses (minus room effects).
                $spdGear = (Get-ArmorSkillSPD) + (Get-SetBonus "SPD")
                if($script:Companion -eq "rp"){ $spdGear += 1 }
                $spdTotal = $p2.SPD + $spdGear
                Write-C "  SPD: $($p2.SPD)" "White"
                if($trnSPD -gt 0){ Write-C " (+$trnSPD trn)" "Magenta" }
                if($spdGear -gt 0){ Write-C " + $spdGear gear" "DarkCyan" }
                Write-CL "  = $spdTotal total" "Yellow"

                Write-C "  MAG: $($p2.MAG)" "White"
                if($trnMAG -gt 0){ Write-C " (+$trnMAG trn)" "Magenta" }
                if($mBonus -gt 0){ Write-C " + $mBonus staff" "DarkCyan" }
                Write-CL "  = $magTotal total" "Yellow"

                Write-Host ""
                Write-CL "  XP:  $($script:XP) / $($script:XPToNext)" "DarkCyan"
                Write-CL "  Kills: $($script:KillCount) (total: $($script:TotalKills))" "DarkGray"
                Write-C  "  Lockpicks: " "DarkGray"; Write-CL "$($script:Lockpicks)" "Cyan"
                Write-C  "  Dungeon Streak: " "DarkGray"
                $curStreakColor = if($script:Streak -ge 3){"Yellow"}elseif($script:Streak -ge 1){"White"}else{"DarkGray"}
                Write-C  "$($script:Streak)" $curStreakColor
                Write-C  "   Best: " "DarkGray"
                $bestColor = if($script:BestStreak -ge 5){"Magenta"}elseif($script:BestStreak -ge 3){"Yellow"}else{"White"}
                Write-CL "$($script:BestStreak)" $bestColor
                Write-CL "  Bosses Defeated: $($script:BossesDefeated)" "DarkGray"
                $dfCol = if($script:DeepestFloor -ge 16){"Red"}elseif($script:DeepestFloor -ge 11){"Green"}elseif($script:DeepestFloor -ge 6){"Cyan"}else{"DarkGray"}
                Write-CL "  Deepest Floor: $($script:DeepestFloor)" $dfCol
                foreach($fk in @("RogueProcesses","DataMiners")){
                    $frV = Get-FactionRep $fk
                    if($frV -ne 0){
                        $frS = Get-FactionStanding $fk
                        $frC = switch($frS){ "HUNTED" {"Red"} "HONORED" {"Magenta"} "Wary" {"DarkYellow"} default {"Cyan"} }
                        Write-CL "  $(Get-FactionLabel $fk): $frS ($frV)" $frC
                    }
                }
                if($script:Companion -eq "rp"){ Write-CL "  Companion: Orphan (a small zombie process) — +1 SPD" "DarkCyan" }
                if($script:Companion -eq "dm"){ Write-CL "  Companion: Cursor (a query sprite) — +2% crit" "DarkCyan" }
                Write-Host ""
                # ── Skills (Phase 4) ──
                # All nine skills, two columns, ALWAYS visible (Lv0 rows
                # render DarkGray). Fixed: previously hidden until first
                # XP, which read as a missing section on a fresh character.
                Write-CL "  ── SKILLS ──" "Yellow"
                $skAll = @(Get-SkillList)
                for($si = 0; $si -lt $skAll.Count; $si += 2){
                    $sk1 = $skAll[$si]
                    $lv1 = Get-SkillLevel $sk1
                    $c1 = if($lv1 -ge 10){"Cyan"}elseif($lv1 -gt 0){"White"}else{"DarkGray"}
                    Write-C ("  " + "$sk1 Lv$lv1".PadRight(24)) $c1
                    if(($si + 1) -lt $skAll.Count){
                        $sk2 = $skAll[$si + 1]
                        $lv2 = Get-SkillLevel $sk2
                        $c2 = if($lv2 -ge 10){"Cyan"}elseif($lv2 -gt 0){"White"}else{"DarkGray"}
                        Write-C ("$sk2 Lv$lv2") $c2
                    }
                    Write-Host ""
                }
                Write-Host ""

                # ── Active Sets (Phase 4d) ──
                $setLine = @()
                foreach($setN in @("Leather","Iron","Steel","Dragon","Mythril")){
                    $setPc = 0
                    foreach($setSlot in @("Helmet","Chest","Shield","Amulet","Boots")){
                        $setPiece = $script:EquippedArmor[$setSlot]
                        if($setPiece -and (Get-ItemSet $setPiece.Name) -eq $setN){ $setPc++ }
                    }
                    if($setPc -ge 2){ $setLine += "$setN ($setPc pc)" }
                }
                if($setLine.Count -gt 0){
                    Write-CL "  Active Sets: $($setLine -join ', ')" "Green"
                    Write-Host ""
                }

                # ── Weapon Affinity Tip ──
                Write-CL "  ┌──────────────────────────────────────────────────┐" "DarkGray"
                Write-CL "  │  Your class affinity: $($script:PlayerClass)" "DarkGray"
                Write-CL "  │  Weapons matching your class give bonus ATK.     │" "DarkGray"
                Write-CL "  └──────────────────────────────────────────────────┘" "DarkGray"
                Write-Host ""

                # ── Abilities ──
                $abilTier = Get-AbilityTier $script:PlayerLevel
                $tierLabel = if($abilTier -gt 0){" (Tier $abilTier)"}else{""}
                Write-CL "  ── ABILITIES$tierLabel ──" "Yellow"
                foreach($abBase in $p2.Abilities){
                    $ab = Get-ScaledAbility $abBase $script:PlayerLevel
                    $costStr = if($ab.Type -eq "Sacrifice"){"HP:15%"}else{"MP:$($ab.Cost)"}
                    $effStr = if($ab.Effect -and $ab.Effect -ne "None" -and $ab.Effect -ne "SacrificeHP"){" [$($ab.Effect)]"}else{""}
                    Write-CL "    $($ab.Name)  |  $costStr  |  $($ab.Type)  |  Pwr:$($ab.Power)$effStr" "Cyan"
                }
                if($abilTier -lt 3){
                    $nextLevel = if($abilTier -eq 0){5}elseif($abilTier -eq 1){10}else{15}
                    Write-CL "    (Next ability upgrade at level $nextLevel)" "DarkGray"
                }
                Write-Host ""
                # Talent points summary + jump to talent tree screen.
                $availTalents = Get-AvailableTalentPoints
                Write-CL "  ── TALENTS ──" "Yellow"
                Write-C  "  Available talent points: " "DarkGray"
                $tpCol = if($availTalents -gt 0){"Green"}else{"DarkGray"}
                Write-CL "$availTalents" $tpCol
                $spent = if($script:Talents){$script:Talents.Count}else{0}
                Write-C  "  Talents purchased: " "DarkGray"
                Write-CL "$spent" "Cyan"
                Write-Host ""
                Write-CL "  [T] Open Talent Tree    [Enter] Back" "White"
                Write-C  "  > " "Yellow"
                $statsKey = Read-Host
                if($statsKey -eq "T" -or $statsKey -eq "t"){
                    Show-TalentTree
                }
            }

            "6" { Show-QuestBoard }
            "7" { Show-GuildHall }

            "T" { Show-TrainingGrounds }
            "A" { Show-AchievementsMenu }
            "B" { Show-Bestiary }
            "O" { Show-OptionsMenu }
            # [E] row removed — the Enchanter is market [8] now — but
            # the key stays as a silent shortcut for muscle memory.
            "E" { Show-EnchanterScreen }
            "W" { Show-WorldMap }
            "!" { Show-StoryQuest -Context "town" }
            "N" {
                # New Game Plus: gated on STORY COMPLETION (locked
                # decision — swapped from the old 25-clears gate when
                # the Final Migration shipped).
                # Keeps gold, achievements, training, bestiary, talents,
                # NGPlus level (incremented), and HiddenBoss favor. Resets
                # player level/XP/gear and DungeonsCleared. Enemies scale
                # +20% per NG+ level via the existing combat hook.
                if((Get-QuestStage "msq") -lt 999){
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkGray"
                    Write-CL "  ║              N E W   G A M E   +                ║" "DarkGray"
                    Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkGray"
                    Write-Host ""
                    Write-CL "  Ascension is for those who ENDED something." "DarkGray"
                    Write-CL "  Finish THE FINAL MIGRATION first — the story" "DarkGray"
                    Write-CL "  waits at the Quest Board's [!] mark." "Yellow"
                    Write-Host ""
                    Wait-Key
                } else {
                    clr
                    Write-Host ""
                    Write-CL "  ╔══════════════════════════════════════════════════════════════╗" "Magenta"
                    Write-CL "  ║                  A S C E N D   T H E   D E P T H S          ║" "Yellow"
                    Write-CL "  ╚══════════════════════════════════════════════════════════════╝" "Magenta"
                    Write-Host ""
                    Write-CL "  You have proven yourself worthy. The Guild offers ascension:" "Gray"
                    Write-Host ""
                    Write-CL "  KEPT:    gold, achievements, training, bestiary, talents," "Yellow"
                    Write-CL "           SysAdmin Favor, pet, ingredients" "Yellow"
                    Write-CL "  RESET:   player level, XP, gear, dungeon level, clears counter" "Red"
                    Write-CL "  GAINED:  NG+ tier increments to $($script:NGPlusLevel + 1)" "Cyan"
                    Write-CL "           Enemies +20% HP and ATK per NG+ tier" "Cyan"
                    Write-CL "           20% chance for boss/mini drops to be ASCENDED gear" "Magenta"
                    Write-Host ""
                    Write-C "  Ascend now? [y/n]: " "Yellow"
                    $asc = Read-Host
                    if($asc -eq 'y' -or $asc -eq 'Y'){
                        # Perform ascension
                        $script:NGPlusLevel++
                        $script:DungeonLevel = 0
                        $script:DungeonsCleared = 0
                        $script:PlayerLevel = 1
                        $script:XP = 0
                        $script:XPToNext = 100
                        $script:EquippedWeapon = $null
                        $script:EquippedArmor = @{Helmet=$null;Chest=$null;Shield=$null;Amulet=$null;Boots=$null}
                        $script:Inventory.Clear()
                        # Talents persist on ascend by spec — they're a
                        # multi-run progression layer, not a per-life buff.
                        # We do NOT reset $script:Talents here.
                        # Reset player to fresh class template (preserve permanent SysAdmin Favor bonus)
                        $tpl = (Get-ClassTemplates)[$script:PlayerClass]
                        $favorBonus = if($script:HiddenBossDefeated){5}else{0}
                        $favorHP    = if($script:HiddenBossDefeated){25}else{0}
                        $favorMP    = if($script:HiddenBossDefeated){15}else{0}
                        $script:Player = @{
                            Name      = $tpl.Name
                            HP        = $tpl.HP + $favorHP
                            MaxHP     = $tpl.MaxHP + $favorHP
                            MP        = $tpl.MP + $favorMP
                            MaxMP     = $tpl.MaxMP + $favorMP
                            ATK       = $tpl.ATK + $favorBonus
                            DEF       = $tpl.DEF + $favorBonus
                            SPD       = $tpl.SPD + $favorBonus
                            MAG       = $tpl.MAG + $favorBonus
                            Abilities = $tpl.Abilities
                        }

                        # Reapply training-grounds stat purchases. The
                        # Player object was just rebuilt from template,
                        # which wiped the per-purchase deltas, so we walk
                        # $TrainingPoints and credit each point. Per-point
                        # gains MUST match the values in Show-TrainingGrounds.
                        $p2 = $script:Player
                        $tp = $script:TrainingPoints
                        if($tp){
                            $p2.ATK   += 2 * [int]$tp.ATK
                            $p2.DEF   += 2 * [int]$tp.DEF
                            $p2.SPD   += 1 * [int]$tp.SPD
                            $p2.MAG   += 2 * [int]$tp.MAG
                            $p2.MaxHP += 8 * [int]$tp.HP
                            $p2.HP     = $p2.MaxHP
                            $p2.MaxMP += 5 * [int]$tp.MP
                            $p2.MP     = $p2.MaxMP
                        }

                        # Reapply HP/MP-granting talents at Lv 1. As the
                        # player levels up again post-ascension, the per-
                        # level bonuses don't auto-grow — that matches the
                        # talent's behavior on first purchase (one-shot
                        # delta tied to player level at purchase time).
                        $hpDelta = 0; $mpDelta = 0
                        if(Has-Talent "Knight_T1_A")     { $hpDelta += (5 * 1) }
                        if(Has-Talent "Brawler_T1_C")    { $hpDelta += (8 * 1) }
                        if(Has-Talent "Cleric_T1_A")     { $hpDelta += (4 * 1); $mpDelta += (4 * 1) }
                        if(Has-Talent "Berserker_T1_B")  { $hpDelta += (5 * 1) }
                        if(Has-Talent "Warlock_T1_B")    { $hpDelta += (5 * 1) }
                        if(Has-Talent "Mage_T1_A")          { $mpDelta += (5 * 1) }
                        if(Has-Talent "Necromancer_T1_A")   { $mpDelta += (5 * 1) }
                        if(Has-Talent "Necromancer_T3_A"){
                            # Lich's Pact: -20% MaxHP at acquire time.
                            $reduction = [math]::Floor($p2.MaxHP * 0.20)
                            $p2.MaxHP = [math]::Max($p2.MaxHP - $reduction, 30)
                        }
                        if($hpDelta -gt 0){
                            $p2.MaxHP += $hpDelta
                            $p2.HP     = $p2.MaxHP
                        }
                        if($mpDelta -gt 0){
                            $p2.MaxMP += $mpDelta
                            $p2.MP     = $p2.MaxMP
                        }

                        Write-Host ""
                        Write-CL "  ╔══════════════════════════════════════════════════════════════╗" "Yellow"
                        Write-CL "  ║                A S C E N D E D                              ║" "Yellow"
                        Write-CL "  ╚══════════════════════════════════════════════════════════════╝" "Yellow"
                        Write-CL "  You are now NG+$($script:NGPlusLevel)." "Cyan"
                        Write-CL "  The Depths await — harder, richer, and stranger than before." "DarkGray"
                        Write-Host ""
                        Wait-Key
                    }
                }
            }

            "8" {
                Write-C "  Really quit? (y/n): " "Red"; $confirm = Read-Host
                if($confirm -eq 'y'){
                    $script:GameRunning = $false
                    clr
                    Write-CL "" "White"
                    Write-CL "  Thanks for playing DEPTHS OF POWERSHELL!" "Yellow"
                    Write-CL "  Final Stats: Level $($script:PlayerLevel) $($p.Name) | Gold: $($script:Gold) | Dungeons: $($script:DungeonLevel)" "Gray"
                    Write-Host ""
                }
            }

            "9" {
                # Debug mode and Flying Dutchman mode both lock out Save.
                # Either one is a god-start session that can't be turned
                # into a permanent save file.
                if($script:DebugMode -or $script:DutchmanMode){
                    $modeLabel = if($script:DutchmanMode){"Flying Dutchman Mode"}else{"Debug Mode"}
                    clr
                    Write-Host ""
                    Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkRed"
                    Write-CL "  ║          S A V E   D I S A B L E D                 ║" "Red"
                    Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkRed"
                    Write-Host ""
                    Write-CL "  Save is unavailable in $modeLabel." "Yellow"
                    Write-CL "  Start a regular run from the splash menu to save progress." "DarkGray"
                    Write-Host ""
                    Wait-Key
                    continue
                }
                clr
                Write-CL "" "White"
                Write-CL "  ╔════════════════════════════════════════════════════╗" "DarkYellow"
                Write-CL "  ║            S A V E   G A M E                       ║" "Yellow"
                Write-CL "  ╚════════════════════════════════════════════════════╝" "DarkYellow"
                Write-Host ""
                Write-CL "  Preparing save code..." "DarkGray"
                Write-Host ""

                # Convert loot to gold and tell the player
                $lootVal = 0
                foreach($item in $script:Inventory){ $lootVal += $item.Value }
                if($lootVal -gt 0){
                    Write-CL "  Loot inventory converted to gold: +${lootVal}g" "Yellow"
                }
                if($script:Quests.Count -gt 0){
                    Write-CL "  Active quests will not be saved." "DarkGray"
                }
                Write-Host ""

                $code = Save-Game
                Write-CL "  ┌──────────────────────────────────────────────────────┐" "Green"
                Write-CL "  │  YOUR SAVE CODE (copy this entire string):           │" "Green"
                Write-CL "  └──────────────────────────────────────────────────────┘" "Green"
                Write-Host ""
                Write-CL "  $code" "Cyan"
                Write-Host ""
                # ── Try to auto-copy to clipboard (Windows PS 5.1 has Set-Clipboard) ──
                $clipboardOk = $false
                try {
                    Set-Clipboard -Value $code -ErrorAction Stop
                    $clipboardOk = $true
                } catch {
                    $clipboardOk = $false
                }
                if($clipboardOk){
                    Write-CL "  ✔ Save code copied to your clipboard automatically!" "Green"
                } else {
                    Write-CL "  (Clipboard copy unavailable — select the text manually.)" "DarkGray"
                }
                Write-Host ""
                Write-CL "  ┌──── HOW TO SAVE ──────────────────────────────────────┐" "Cyan"
                Write-CL "  │ 1. Open a Notepad text file on your computer.         │" "White"
                Write-CL "  │ 2. Paste the save code (Ctrl+V) into the file.        │" "White"
                Write-CL "  │ 3. Save the file somewhere you'll remember it.        │" "White"
                Write-CL "  │                                                       │" "Cyan"
                Write-CL "  │ TO LOAD: from the splash screen pick [2] Load Save    │" "White"
                Write-CL "  │  Code, then press Ctrl+V to paste your code in.       │" "White"
                Write-CL "  └───────────────────────────────────────────────────────┘" "Cyan"
                Write-Host ""
                Write-CL "  NOTE: Loot was converted to gold. Quests were reset." "DarkYellow"
                Write-Host ""
                Read-Host "  Press Enter to continue"
            }
        }
    }
}



# ─── CHANGELOG ───────────────────────────────────────────────────
# Paginated release notes. Grouped into three categories. Shown from the
# launch menu, returns back to the launch menu when dismissed.
function Show-Changelog {
    $pages = @(
        @{Title="v1.6.0 — THE DEEP HALLS"; Color="Red"; Lines=@(
            "  DUNGEONS, QUADRUPLED"
            "    * Floors are now 41x41 — four times the ground — with"
            "      more rooms, looping corridors, and sliding doors"
            "      between areas. Press [E] to open one; it stays open."
            ""
            "  THE BOSS ROOM IS SEALED"
            "    * Every way into the final room is barred by a RED"
            "      boss door. Take the key from the mini-boss, watch"
            "      the seal slide open, and face what waits inside."
            ""
            "  A SHARPER [E]"
            "    * Contextual prompts — Open Door, Fight, Rescue the"
            "      Adventurer — with a line-of-sight check, so the"
            "      game stops offering doors you cannot see."
            ""
            "  OPTIONS"
            "    * FPS counter toggle (on by default) and adjustable"
            "      3D turn speed (50-150%), both saved in your code."
            ""
            "  RENDERER DETECTION FIXED"
            "    * The game now asks the console itself for VT/ANSI"
            "      support instead of sniffing env vars — Windows 11"
            "      default-terminal handoffs get the 3D view too."
            ""
            "  POLISH (v1.6.1)"
            "    * Fights start on YOUR terms: [E] to engage — enemies"
            "      no longer lunge when you merely walk near them."
            "    * Doors are now GATES: a few per floor, each sealing a"
            "      room that holds something worth sealing. No more"
            "      doors to nowhere."
            "    * Corruption counter always visible (town + sheet)."
            "    * Armor shows its weight class: [H] heavy / [L] light."
            "    * Small windows fall back to classic instead of the 3D"
            "      view scrolling the screen; heat + encounter pacing"
            "      retuned for the bigger floors; fishing prompt fits."
            "    * Combat now shows your EFFECTIVE speed (skills, sets,"
            "      Flooded rooms) and openers state both speeds — no"
            "      more ‘faster’ enemies that look slower. Map: you are"
            "      the green arrow (now in the legend)."
            ""
            "  PATCH (v1.6.2)"
            "    * MIMICS NOW AMBUSH. In the dungeon they look like a"
            "      chest — sprite, prompt, minimap, everything — until"
            "      you reach for the lid. Two tells for the wary: a"
            "      red glint on the lock, and chests do not usually"
            "      block your feet. Once sprung, the con is blown."
            "    * Boss seals no longer generate picket lines of red"
            "      doors where a corridor hugged the boss room — each"
            "      line collapses to one door, walls fill the rest."
            "    * Ceiling beams render solid at range instead of"
            "      tearing into dashes (and a bug that painted the"
            "      void past the map edge as one giant beam is gone)."
            "    * Renderer detail pass: coffered ceilings (cross"
            "      beams), per-tile wall variety (cracks, chips,"
            "      damp patches), 2x-smoothed sprites, floor grout"
            "      lines that stay crisp into the distance, and"
            "      torches in wooden sconces — all baked at"
            "      startup, with the frame loop trimmed to pay"
            "      for it."
            "    * Turn order fix: initiative was effectively"
            "      random on Windows PowerShell (a hashtable"
            "      sorting gotcha) — the opener could claim a"
            "      SLOWER enemy was faster. Speed now decides,"
            "      ties favor you, and the opening-rush message"
            "      shows the real numbers, the rush chance, and"
            "      the coolant slow when a Flooded room applies."
            "    * Same gotcha fixed in the shops (weapon and"
            "      armor lists now truly sort by price), boss"
            "      telegraphs (they charge their actual strongest"
            "      move), and the world map (west to east)."
            "    * Lockpicking runs smoothly from the first frame"
            "      — the minigame draws with one buffered write"
            "      instead of ~100 console calls."
            "    * [T] in town replays the tutorial any time."
            "    * The armor shop explains its [H] / [L] tags."
            "    * Status messages in the 3D view fade after a few"
            "      seconds instead of sticking around forever."
            "    * Chests in the 3D view open with [E] only — no"
            "      more looting by walking over them."
            "    * Dungeon gen: every floor is verified walkable"
            "      (spawn can always reach the mini-boss and a"
            "      boss door — no more sealed-in starts), and"
            "      gate doors that led nowhere or stood mid-room"
            "      are swept away."
            "    * Too-small window? The game resizes it for the"
            "      3D view (that jump is intentional!) or, if the"
            "      terminal refuses, explains why it fell back to"
            "      classic and how to get 3D back."
            "    * The 3D view now actually SHOWS replies to your"
            "      actions — trying the exit with the boss alive, or"
            "      a chest with no picks, answers on the spot (the"
            "      [E] prompt used to cover the message)."
            "    * The dungeon map opens instantly — one buffered"
            "      write instead of a thousand per-cell prints."
            "    * Quest board: story quests advance at [!] — the"
            "      board now has that mark, tags a finished story"
            "      step READY, and says where to take it."
            "    * Inn menu box no longer breaks on the Cooking Pot"
            "      and Feather Beds rows."
            "    * Boss-room torches burn COLD BLUE in grey iron"
            "      holders — you can read the room from across the"
            "      floor."
            "    * New armor: Steel Shield (220g) and Mythril"
            "      Treads (800g) — every armor set can now be"
            "      completed to 3 pieces, with new 3pc bonuses"
            "      (Steel +2 more DEF; Mythril +1 SPD, +1% crit)."
            "    * Fishing finally SAYS the button: press [SPACE]"
            "      when it strikes (any key works)."
            "    * The Quest Board is the home of ALL quests now:"
            "      the story's [!] mark lives there, the posting"
            "      list is titled TOWN BOUNTIES, and the board only"
            "      claims to be empty when it actually is. [T] in"
            "      town moved up beside the World Map."
            "    * The [E] prompt joined the controls bar — it"
            "      brightens and names its target, like [E] Open"
            "      Chest, so it never fights the status line again,"
            "      and status messages fade faster to compensate."
            "    * New Game+ row now tells the truth: it unlocks by"
            "      FINISHING THE STORY, not 25 clears — matching"
            "      what [N] actually checked all along."
            "    * The splash screen finally admits what version it"
            "      is (1.6.2, not 1.4.1b), and the tutorial learned"
            "      about [E], [M], and the real New Game+ rule."
            "    * Lore terminals in 3D are [E]-only — no more"
            "      speed-reading by walking over them. The HUD's"
            "      gold count went gold, and the FPS readout now"
            "      grades itself green / yellow / red."
            "    * The tutorial grew two pages — SKILLS (what"
            "      trains what, and what each tier pays) and"
            "      CORRUPTION & WORLD EVENTS — and now covers the"
            "      three quest kinds, [V] target switching, and"
            "      the World Map — plus a GUILDS & FACTIONS page."
            "    * Shop receipts now name their discount honestly:"
            "      fresh characters get 'calm world' prices (low"
            "      Corruption), not a Guild SysAdmin favor they"
            "      never earned."
            "    * CRITICAL: [Q] Leave works from the 3D view — the"
            "      abandon prompt used to print below a full-screen"
            "      frame where nobody could see it, so Enter quietly"
            "      answered no. It gets its own screen now — and a"
            "      whole family of input drains that could hang for"
            "      one extra keypress on a key RELEASE were made"
            "      release-proof (the [Q] black screen, plus pauses"
            "      at altars, lore, encounters, and loot screens)."
            "    * Pack fights retuned: fewer ambushes at low"
            "      Corruption, and packs of FOUR only in a deeply"
            "      corrupted world (70+)."
            "    * The road trader answers every outcome — no more"
            "      silent shrug when you said yes but lacked gold"
            "      or belt space. His speech is no longer blue."
            "    * The dungeon exit is [E]-only in the 3D view."
            "    * Mixed armor finally trains: no majority class"
            "      now trains each worn class at half rate. And"
            "      MATCHING sets (3+ pieces, one class) pay +2 DEF"
            "      (Heavy) or +2 SPD (Light) on top of skill tiers."
            "    * World events announce their endings, so a Blood"
            "      Moon rolling into a Goblin Horde overnight no"
            "      longer looks like a broken banner."
            "    * [O] Options works INSIDE the dungeon — and a new"
            "      [7] Zone Visuals toggle paints every floor plain"
            "      stone if the themed looks aren't for you (saved"
            "      with your game)."
            "    * The HUD shows your level, XP, and a >> BOSS KEY <<"
            "      tag the moment you hold it."
            "    * Items an active Collect quest still needs can't be"
            "      sold out from under the quest."
            "    * A loading bar at launch, a floor-generation visual"
            "      on every descent, per-renderer display checks, a"
            "      proper send-off screen on [Q], a wider fishing"
            "      pier — and five new side quests for towns that"
            "      finish their first."
            "    * 3D clarity pass: 118 rays wide (was 100) and a"
            "      gentler distance falloff — deep corridors keep"
            "      their shape instead of crushing to black. Wall"
            "      textures are 64x32 (4x the detail up close), a"
            "      subtle head-bob rides your stride, and terminals"
            "      that speak 24-bit color get exact-RGB shading"
            "      automatically. And keep an eye on the walls:"
            "      some carry dried blood, some carry banners."
        )}
        @{Title="v1.5.0 — THE PROVINCE SWEEP"; Color="Magenta"; Lines=@(
            "  CITY SIDE QUESTS"
            "    * The three cities finally post work of their own:"
            "      Registry's INK THAT REMEMBERS, Terminus's END OF"
            "      LINE, and Sys-V's QUIET STREETS. First side quests"
            "      to pay out player XP alongside gold and gems."
            ""
            "  TOWN QUESTLINES — STORIES NOW CHAIN"
            "    * Some town quests continue after turn-in. Registry"
            "      runs a three-chapter arc (the fading name has an"
            "      owner), and Nullhaven's notary wants his proof"
            "      DELIVERED — five days, one road, no excuses."
            ""
            "  FACTIONS — CONTACTS, GOODS, AND WORK"
            "    * The Rogue Processes and Data Miners now keep"
            "      contacts in the cities. Earn their respect (rep 25)"
            "      and they'll deal: exclusive gear sold nowhere else."
            "    * Each faction runs a 3-stage questline ending in a"
            "      signature amulet — plus one infinitely repeatable"
            "      odd job for grinding rep and gold."
            ""
            "  COMPANIONS"
            "    * Finish a faction's questline and someone starts"
            "      walking with you. Orphan (+1 SPD) or Cursor"
            "      (+2% crit) — passive followers, one at a time,"
            "      with opinions about your dungeon choices."
            ""
            "  SKILL MILESTONES (Lv 50)"
            "    * Skills finally spend their levels, not just their"
            "      tiers. BLACKSMITHING 50 opens the forge's back room:"
            "      two one-time master recipes (gems + gold in, gear"
            "      that exists nowhere else out)."
            "    * ALCHEMY 50 unlocks the Master's Still at the potion"
            "      stall — distill a gem into an Extra Strong potion,"
            "      repeatable, no more waiting on boss luck."
            "    * FISHING 50 adds a third rare to the pond: the"
            "      Leviathan-Scale Charm bites for masters only."
            ""
            "  THE DEPTHS IN 3D — RAYCAST RENDERER"
            "    * The dungeon can render as a real-time textured 3D"
            "      view: free-float movement, animated torchlight,"
            "      per-zone palettes, sliding boss doors, and every"
            "      enemy type as its own sprite. Walk with W/S, turn"
            "      with A/D, [E] to interact with what you face."
            "    * Auto-enabled on VT terminals (Windows Terminal,"
            "      ConEmu, VS Code); bare conhost keeps the classic"
            "      renderer. Override either way in Options [4]."
            "    * New [M] detailed map in BOTH renderers: the full"
            "      floor with fog of war, legend, hazard rooms, and"
            "      an explored percentage."
            ""
            "  THE JOURNAL REMEMBERS BACK"
            "    * Bind all fifteen pages, then descend. Someone has"
            "      been waiting to see the finished documentation."
        )}
        @{Title="v1.4.1b — BUG FIXES"; Color="Green"; Lines=@(
            "  LETHAL-SAVE TALENTS NO LONGER EXIT COMBAT"
            "    * Bug: Knight Last Stand, Cleric Resurrection, and"
            "      Berserker Final Stand ended the fight when they"
            "      triggered — the player was silently returned to the"
            "      dungeon, away from the enemy. Every revive doubled"
            "      as a free escape, so a careful player could avoid"
            "      dying entirely (revive, retreat, repeat next run)."
            "    * Fix: the revive now happens IN PLACE and the fight"
            "      continues. The enemy that dropped you is still"
            "      standing there at its current HP, and it's your"
            "      turn. Still once per dungeon — a second lethal"
            "      blow in the same dungeon is final."
            ""
            "  POISON NO LONGER TICKS ON FLEE ATTEMPTS"
            "    * Bug: throwing a poison potion and then spamming the"
            "      Flee action ticked poison damage on every attempt,"
            "      letting players melt enemies with minimal risk."
            "    * Fix: flee attempts (successful or failed) no longer"
            "      tick poison. A flee rejected outright (boss and"
            "      mini-boss fights) still follows normal turn rules."
        )}
        @{Title="v1.4.1a — HOTFIX"; Color="Cyan"; Lines=@(
            "  PACIFIST MUTATOR — QUEST XP BONUS RESTORED"
            "    * Bug: Pacifist's Path was supposed to trade kill XP for"
            "      tripled quest XP, but the bonus check fired at the"
            "      Quest Board (in town) AFTER the mutator had been"
            "      cleared by dungeon end. Result: the 3x bonus never"
            "      applied — Pacifist was a strict downside."
            "    * Fix: the 3x bonus now bakes into the quest's stored"
            "      reward at the moment of completion (in-dungeon, while"
            "      the mutator is still active). The Quest Board pays"
            "      out the boosted reward as-is and labels the line"
            "      with '(Pacifist x3)' so you can see the bonus."
            "    * Edge case: a quest that was already complete from a"
            "      previous non-Pacifist run will NOT get the bonus on"
            "      turn-in — only quests completed during a Pacifist"
            "      run earn it."
            ""
            "  BOSS DOOR SPRITE"
            "    * The dungeon boss-room cell now renders as a heavy"
            "      iron-banded LOCKED DOOR with a keyhole, instead of"
            "      a generic 'BOSS!!!' creature face. Reads correctly"
            "      with the mini-boss-drops-the-key narrative: see the"
            "      locked door, find the mini-boss, come back and"
            "      unlock it."
        )}
        @{Title="v1.4.1 — POLISH & PROGRESSION"; Color="Yellow"; Lines=@(
            "  TIER 4 TALENT CAPSTONES (Lv 15)"
            "    * Each class gets ONE ULT-tier talent unlocked at Lv 15."
            "    * Knight Avatar of Light:    -25% damage taken, +15% dealt"
            "    * Mage Archmage Ascendant:   abilities cost 50% MP, +40% magic"
            "    * Brawler Iron Avalanche:    +50% damage below 50% HP"
            "    * Ranger Volley:             Multishot 50% chance, full damage"
            "    * Cleric Holy Fury:          all healing +50%, Lay on Hands x2"
            "    * Necromancer Lord of the Dead: Reaper at 40% HP, kills heal 15"
            "    * Berserker Eternal Rage:    Rampage cap 6 (was 3)"
            "    * Warlock Bound to Eternity: Soul Drain heals 60%, Soul Tap free"
            "    * After all 10 talents are owned, level-up no longer grants"
            "      points — there's nothing left to buy."
            ""
            "  RANGER BUFF"
            "    * Base SPD raised from 15 to 16."
            "    * Rangers wielding any Bow weapon get +1 ATK on top of"
            "      their normal affinity bonus."
            "    * Multishot proc rate increased from 20% to 25%."
            ""
            "  NEW GAME PLUS — NOW VISIBLE"
            "    * The town menu shows [N] New Game+ with progress (X/25)."
            "    * Once you've cleared 25 dungeons, the row turns magenta"
            "      and reads NEW GAME+ READY! so it can't be missed."
            "    * NG+ trigger logic was already correct (DungeonsCleared,"
            "      not player level) — only the UI was hiding it."
            ""
            "  OPTIONS / SETTINGS [O]"
            "    * Difficulty: Easy (-25% enemy HP/ATK), Medium (default),"
            "      Hard (+25%). Applies to all enemies multiplicatively"
            "      on top of NG+ scaling."
            "    * Auto-Loot: when ON, the loot screen takes everything"
            "      that fits in your bag automatically."
            "    * Auto-Resize: optional terminal resize on game start."
            "    * Settings travel inside your save code — generate and"
            "      load a save to carry them across runs."
            ""
            "  MUTATOR REWORK"
            "    * Reward bonuses now apply ONLY at end-of-dungeon clear"
            "      (the +20-40% multiplier on the final gold/XP haul)."
            "      Per-kill bonuses from Speedrun/Frugal/Hardcore removed."
            "    * Quitting [Q] mid-dungeon while a mutator is active now"
            "      forfeits ALL run gold, XP, AND loot. Without a mutator,"
            "      [Q] still uses the older random flee penalty."
            "    * Frugal Run: now leaves you with 1 Small Health Potion +"
            "      1 Mana Potion + 1 lockpick at entry (was 0 of everything)."
            ""
            "  DEATH HANDLING"
            "    * Play Again (Same Character): items lost, gold KEPT,"
            "      level/XP reset to 1/0/100, stats rebuilt from class"
            "      template + reapplied training. The XP-to-next bug"
            "      (level showed 1 but next-level cost stayed high) is fixed."
            ""
            "  WANDERING MERCHANT — GEAR COMPARISON"
            "    * Each offer now shows a comparison vs your current gear:"
            "      green ▲ for upgrade, red ▼ for downgrade, = for same."
            "    * Weapons compare ATK + class affinity bonus; armor"
            "      compares DEF for the same slot."
            ""
            "  LORE NOTES — NOW READABLE"
            "    * 18% of opened chests drop a NOTE (15 entries total)."
            "    * Inventory now has [V] Read Notes when at least one is"
            "      in your bag. Notes weigh nothing."
            ""
            "  COMBAT & SHOP POLISH"
            "    * Boss base stats +10% (HP 210 -> 231, ATK 20 -> 22)."
            "    * Two-handed weapons split into a separate section in the"
            "      shop with a banner divider. 7 new 2H weapons added (12"
            "      total, 2 per non-Brawler class)."
            "    * 'Death Scythe' (2H) renamed to 'Soulshear' to avoid"
            "      visual clash with the existing 1H 'Death's Scythe'."
            "    * Armor and potion shops sorted by ascending price."
            "    * Sell Loot screen loops on each sale (was kicking you"
            "      back to the market root after every transaction)."
            "    * New [L] Sell All Loot button: liquidates the bag while"
            "      KEEPING weapons, armor, potions, throwables, notes,"
            "      and ingredients — sells the rest in one go."
            "    * Confirmation prompt before selling Dutchman's Blade"
            "      (it's unique and can't be re-acquired)."
            "    * Inventory now shows weight on equipped weapon and armor."
            "    * Loot screen now WARNS instead of blocking when you'd"
            "      go over the carry cap — confirm with y/n to take"
            "      anyway and accept the encumbered penalty."
            ""
            "  EXTRA STRONG POTIONS"
            "    * Removed from normal kill drop pool (was a bug)."
            "    * Bosses now roll a separate 35% chance for an Extra"
            "      Strong potion drop, in addition to normal loot."
            "    * End-of-dungeon Extra Strong roll unchanged."
            ""
            "  TOWN & UI POLISH"
            "    * Inn now always shows the menu — [C] Cooking Pot is"
            "      available even at full HP/MP. Rest options 1-3 give"
            "      a flavor line if you're already topped up."
            "    * Royal Suite maxed-out path no longer double-prompts"
            "      'press any key' (was showing two prompts in a row)."
            "    * Quest Log renamed to QUEST JOURNAL on the title bar."
            "    * Save screen now explains step-by-step how to save"
            "      (open Notepad, paste with Ctrl+V, save the file)"
            "      and how to load (paste from clipboard at the prompt)."
            "    * Tutorial page 6 corrected: equipped gear now listed"
            "      under WEIGHTED ITEMS (was incorrectly weight-free)."
            ""
            "  BUG FIXES"
            "    * Lockpick screen tearing fixed: returning from the"
            "      lockpicking minigame now invalidates the dungeon"
            "      partial-render cache so the next frame is a clean"
            "      full repaint."
            "    * Broken-lock final screen now waits for Enter instead"
            "      of flashing past in 1 second."
            "    * Blackjack BUST screen now waits for Enter instead of"
            "      auto-advancing in 1.2 seconds."
            "    * Notes are now weight 0 (was 1)."
            ""
            "  Have fun, sysadmin."
        )}
        @{Title="v1.5.0 — MARN'S JOURNAL"; Color="Yellow"; Lines=@(
            "  FOUND NOTES ARE NOW ONE JOURNAL"
            "    * The 15 lore notes have been rewritten as pages of a"
            "      single journal — Marn, Guild fieldwalker, sent into"
            "      the Depths to close tickets. Pages drop out of order;"
            "      the story assembles as you collect."
            "    * No duplicate drops: chests only ever contain pages"
            "      you are missing, so the set is completable."
            "    * Collection is PERMANENT per character — recorded the"
            "      moment you take a page. Selling or losing the paper"
            "      scrap does not lose the page."
            "    * Inventory [V] is now the Journal: pages listed in"
            "      order, gaps visible, progress shown as X / 15."
            ""
            "  COMPLETION REWARD"
            "    * Recover all 15 pages and the journal binds itself."
            "      Something is sewn into the spine."
            ""
            "  SYSADMIN VOICE PASS (LIGHT TOUCH)"
            "    * New one-line quips at four moments: fight start"
            "      (per enemy type), victory, player death, and boss"
            "      defeat. No existing text was rewritten."
            ""
            "  SKILLS NOW LIVE (PHASE 4)"
            "    * The nine skills finally accrue XP from play:"
            "      Swords/Bows (weapon hits), Destruction (attack"
            "      spells), Restoration (heals), Heavy/LightArmor"
            "      (taking hits in majority gear), Lockpicking,"
            "      Blacksmithing (repairs), Alchemy (potions)."
            "    * Bonuses are deliberately small — +1 effect step"
            "      per 10 levels, capped at skill Lv50. Seasoning,"
            "      overpower the game. Highlights: +dmg on your weapon"
            "      class, +DEF in heavy gear, +SPD in light gear,"
            "      cheaper repairs, stronger potions, and a wider"
            "      lockpick sweet-spot at Lockpicking 15+."
            ""
            "  ENDGAME PREP (PHASE 5)"
            "    * Inn rests always heal, but only the first paid"
            "      rest per day now passes time — future world"
            "      events can no longer be slept past."
            "    * Your deepest floor is now a personal record —"
            "      tracked per character, shown on the Stats"
            "      screen (colored by zone), saved in your code."
            "    * RADIANT EVENTS now stir on the day counter:"
            "      the GOBLIN HORDE floods spawns with goblins,"
            "      the BLIGHTED PLAGUE raises the walking dead,"
            "      and every 13th day the BLOOD MOON makes the"
            "      Depths crueler — and kills worth +25% XP."
            "      Watch the town header; plan your descents."
            "    * A NEMESIS stalks the deep floors. He was Guild"
            "      once. He kept the badge. Bring him down three"
            "      times — he only stays down the last one, and"
            "      what he is holding becomes yours."
            ""
            "  THE PROVINCE OF PRODUCTION (PHASE 6)"
            "    * The world above the Depths: a full province map"
            "      with 22 locations — cities, towns, rest camps,"
            "      offering statues, a too-still pond, and ruins."
            "    * Travel takes in-game days; the road rolls its"
            "      own encounters, kind and unkind — and radiant"
            "      events follow the calendar out there too."
            "    * Statue blessings carry into your next dive."
            "    * Town [W] opens the map. Cities and towns now"
            "      open their doors: markets, inns, smiths, and"
            "      enchanters — but not every place has every"
            "      service. Six locations carry EXCLUSIVE stock"
            "      (marked † in shop listings) found nowhere else."
            "    * Every location now has its own look — unique"
            "      art for all 24 places, and the Enchanter got"
            "      a proper tent."
            "    * FISHING is in: cast at the Still Pond or below"
            "      Foreach Falls — 3 casts a day, a new Fishing"
            "      skill, pond fish for the cooking pot, snagged"
            "      purses, one very old boot, and RARE GEAR that"
            "      is fully real, equippable, and save-safe."
            "    * COMBAT: faster enemies no longer auto-win the"
            "      opening strike — they must win a speed-gated"
            "      dice roll (30% + 4% per SPD point, max 75%),"
            "      or you react first. Turn order afterward is"
            "      still pure speed, ties in your favor."
            "    * TOWN SIDE QUESTS (first five): Old Tumbler Wren"
            "      of Backupvale will cut you THE SKELETON KEY —"
            "      every lock, no picks, no minigame — for three"
            "      Ancient Runes. Bashford wants twelve dead"
            "      things, Cronmarch needs a parcel run ON TIME,"
            "      Nullhaven wants proof anything persists, and"
            "      the ferryman at Foreach Falls will teach you"
            "      patience, one fish at a time."
            "    * Fishing tuning: Terminus now fishes off its"
            "      docks, and the strike window is 500ms + 50ms"
            "      per Fishing level — train the skill, buy time."
            "    * THEMED RAIDS: Frostfang hides the Ice Caves and"
            "      the Frost Matriarch; Sys-V, the Patrol Vaults"
            "      and Warden Prime; the Whispering Woods, the"
            "      Undergrowth and the Sporefather. Full dungeons"
            "      at your level with native enemies — and your"
            "      Depths progress stays exactly where you left it."
            "    * Map: type a location name (any case, partial"
            "      works) to jump the cursor straight to it."
            ""
            "  FACTIONS (PHASE 6)"
            "    * The ROGUE PROCESSES and the DATA MINERS now"
            "      notice you. The road will make you pick sides;"
            "      standings show on your Stats. Get HONORED and"
            "      the Miners pay +10% for loot, or the Processes"
            "      teach you how to leave a room (+5 flee). Get"
            "      HUNTED and the ambushes stop being random."
            "    * GUILD CHARTERS at the Guild Hall [G]: sign with"
            "      the SysAdmins, the Data-Thieves, or the Cabal"
            "      of Forgotten Code. Each runs a three-stage"
            "      questline ending in a signature reward — the"
            "      Firewall Plate, the Whisperstep Boots, or the"
            "      Grimoire. Defecting costs your dues and your"
            "      progress. Choose like it matters."
            ""
            "  THE MAIN STORY BEGINS (PHASE 6)"
            "    * THE FINAL MIGRATION: the ticket board's UP side"
            "      has been empty for nineteen days. Town [!]"
            "      starts the trail — cutscenes, story rewards,"
            "      and real XP through one unified leveling path."
            "      Act I opens; the trail deepens next update."
            "    * The QUEST BOARD is now the ledger of it all:"
            "      the MAIN STORY in red (one quest at a time, in"
            "      order) and your saved SIDE QUESTS in magenta,"
            "      above the day's postings. Story beat III sends"
            "      you to Syslog Crossing — the trail now moves"
            "      across the map. Watch for the [!]."
            "    * ACT I CONCLUDES: the badge gets a name, the"
            "      Guild gets a report, and a file gets the most"
            "      optimistic stamp they own."
            "    * WORLD EVENTS grew teeth: the Goblin Horde is"
            "      led by a WARCHIEF (200g bounty); the Plague"
            "      quarantines Inn beds and spikes potion prices;"
            "      the Blood Moon is an undead night — they swarm,"
            "      and they are worth double."
            "    * FOUR MORE SIDE QUESTS: Cachegrove's bread wars,"
            "      Firewall Keep's standing orders, the Crossing's"
            "      unwritten traveler, and the capital's audit —"
            "      the first CITY quest. And travelers on the road"
            "      now carry job offers: quests can find YOU."
            "    * ACT II: the Registry unseals a file nobody"
            "      wanted open, Sys-V's rehearsal finally ends,"
            "      the Cabal grinds you a lens, and Cronmarch's"
            "      Scheduler reads the date out loud: the Final"
            "      Migration runs on a BLOOD MOON."
            "    * ACT III — THE END: the Guild says the name out"
            "      loud, the sweeper gets severed for good, and"
            "      below floor sixteen something on a throne of"
            "      filing cabinets reads a ticket marked LAST."
            "    * NEW GAME+ is now earned by FINISHING the story,"
            "      not by counting clears. End something first."
            ""
            "  TOWN UPGRADES (PHASE 4)"
            "    * Permanent, per-character town improvements paid"
            "      in high-tier trinkets: Reinforce the Forge at"
            "      the Blacksmith (2 Dragon Tooth + 1 Demon Horn,"
            "      repairs -25%) and Feather Beds at the Inn"
            "      (2 Ancient Rune + 1 Demon Horn, paid rests"
            "      grant Well Rested +2 DEF)."
            ""
            "  ARMOR SETS (PHASE 4)"
            "    * Matching pieces now grant set bonuses: Leather"
            "      (SPD), Iron and Steel (DEF), Dragon (ATK, then"
            "      DEF at 3pc), Mythril (SPD + crit). Set pieces"
            "      are marked * in the armor shop; active sets"
            "      show on the Stats screen."
            ""
            "  THE ENCHANTER OPENS SHOP (PHASE 4)"
            "    * New town service [E]: your trinket gems finally"
            "      have a purpose beyond vendor gold."
            "    * Enchant a perk-less weapon (2 Shards + 1 Shadow"
            "      Gem): random Bleed/Burn/Poison/Drain/Stun, 15%."
            "    * Socket gems into armor (1 gem): Shard +1 DEF,"
            "      Ruby +2 ATK, Dust +2 MAG, Shadow +1% crit."
            "    * Enchantments and sockets on EQUIPPED gear survive"
            "      save/load. Gear in the bag still liquidates."
            ""
            "  CORRUPTION AWAKENS (PHASE 4)"
            "    * The Depths now remember. Dying (+15) and fleeing"
            "      (+3) feed the Corruption meter; slaying bosses"
            "      pushes it back (dungeon boss -10, miniboss -4,"
            "      the hidden boss -15)."
            "    * High Corruption changes WHO you meet, never raw"
            "      stats: more zone variants, more packs, more"
            "      support specialists - and at 60+, the lost"
            "      merchant stops wandering. Something else does."
            "    * A calm world is kind: below 25 Corruption, shops"
            "      take 5% off and altars bless far more often."
            "    * Your current Corruption shows in the town status"
            "      bar once it is above zero."
        )}
    )

    foreach($page in $pages){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkMagenta"
        Write-CL "  ║                  C H A N G E L O G   -   v1.6.2                  ║" "Magenta"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkMagenta"
        Write-Host ""
        Write-CL "  >>> $($page.Title)" $page.Color
        Write-CL ("  " + ("-" * 60)) "DarkGray"
        Write-Host ""
        foreach($line in $page.Lines){
            Write-CL $line "Gray"
        }
        Write-Host ""
        Read-Host "  [Press Enter to continue]" | Out-Null
    }
}



# ─── ENTRY POINT ─────────────────────────────────────────────────
function Start-Game {
    # v1.6.2: a little theater — thick blue loading bar before the
    # splash. Entirely fake; PowerShell parsed everything pages ago.
    try {
        clr
        $spin = @('/','-','\','|')
        for($lb = 0; $lb -le 26; $lb++){
            try { [Console]::SetCursorPosition(0,2) } catch {}
            Write-C "     L O A D I N G  " "White"
            Write-CL $spin[$lb % 4] "Cyan"
            Write-Host ""
            Write-C "     " "DarkBlue"
            Write-C ("█" * $lb) "Blue"
            Write-C ("░" * (26 - $lb)) "DarkGray"
            Write-CL "  $([int](($lb / 26) * 100))%  " "DarkBlue"
            Start-Sleep -Milliseconds (Get-Random -Min 25 -Max 80)
        }
        Start-Sleep -Milliseconds 250
    } catch {}
    $script:GameRunning = $true
    # Settings are now part of the save code, not a separate file.
    # Try the optional terminal resize using the current in-memory
    # settings (defaults until a save is loaded). Loading a save will
    # call Try-AutoResizeTerminal again with the saved value if
    # AutoResize is on.
    Try-AutoResizeTerminal
    clr

    # Title screen
    Write-Host ""
    Write-Host ""
    Write-CL "    ██████╗  ███████╗ ██████╗  ████████╗ ██╗  ██╗ ███████╗" "DarkCyan"
    Write-CL "    ██╔══██╗ ██╔════╝ ██╔══██╗ ╚══██╔══╝ ██║  ██║ ██╔════╝" "Cyan"
    Write-CL "    ██║  ██║ █████╗   ██████╔╝    ██║    ███████║ ███████╗" "Cyan"
    Write-CL "    ██║  ██║ ██╔══╝   ██╔═══╝     ██║    ██╔══██║ ╚════██║" "Cyan"
    Write-CL "    ██████╔╝ ███████╗ ██║         ██║    ██║  ██║ ███████║" "DarkCyan"
    Write-CL "    ╚═════╝  ╚══════╝ ╚═╝         ╚═╝    ╚═╝  ╚═╝ ╚══════╝" "DarkCyan"
    Write-Host ""
    Write-CL "             O   F     P O W E R S H E L L" "DarkYellow"
    Write-Host ""
    Write-CL "                       Version 1.6.2" "DarkGray"
    Write-Host ""
    Write-CL "         A first-person dungeon crawler" "DarkGray"
    Write-CL "         with turn-based RPG combat" "DarkGray"
    Write-Host ""
    Write-Host ""
    Wait-Key

    # ═══════════════════════════════════════════════════
    #  NEW / LOAD / CHANGELOG PROMPT
    # ═══════════════════════════════════════════════════
    $menuLoop = $true
    while($menuLoop){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkYellow"
        Write-CL "  ║               DEPTHS OF POWERSHELL               ║" "Yellow"
        Write-CL "  ║                   Version 1.6.2                  ║" "DarkGray"
        Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkYellow"
        Write-Host ""
        Write-CL "  ┌─────────────────────────────────────────┐" "DarkGray"
        Write-C  "  │  " "DarkGray"; Write-C "[1]" "Green";  Write-CL " New Game                          │" "White"
        Write-C  "  │  " "DarkGray"; Write-C "[2]" "Cyan";   Write-CL " Load Save Code                    │" "White"
        Write-C  "  │  " "DarkGray"; Write-C "[3]" "Magenta";Write-CL " View Changelog                    │" "White"
        Write-CL "  └─────────────────────────────────────────┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $startChoice = Read-Host

        if($startChoice -eq "3"){
            Show-Changelog
            continue  # back to menu
        }
        # ── Hidden debug mode ──
        # Typing the dev passphrase at the splash prompt skips character
        # select entirely and drops the player in town as a fully-stocked
        # Cleric with 9999 gold. Useful for play-testing late-game systems
        # (talents, NG+, bestiary, mutators) without grinding to them.
        # Not advertised anywhere in the UI.
        if($startChoice -eq "80085noob"){
            Start-DebugRun
            return  # Start-DebugRun jumps straight into the town loop and
                    # eventually returns control to the OS via Start-Game's
                    # normal exit path; nothing more to do at this level.
        }
        # ── Hidden Flying Dutchman mode ──
        # Same pattern as the debug passphrase: not in any UI, no save.
        # Starts the player as the Flying Dutchman pseudo-class with 4
        # custom abilities, the Dutchman's Blade equipped, and 9999g.
        if($startChoice -eq "Dutch26"){
            Start-FlyingDutchmanRun
            return
        }
        $menuLoop = $false  # fall through to handling [1] or [2]
    }

    if($startChoice -eq "2"){
        # ── LOAD PATH ──
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkCyan"
        Write-CL "  ║         L O A D   G A M E                        ║" "Cyan"
        Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""
        Write-CL "  Paste or type your save code below." "DarkGray"
        Write-CL "  (It's the Base64 string you copied last time)" "DarkGray"
        Write-Host ""
        Write-C "  Code: " "Yellow"
        $code = Read-Host

        # Trim whitespace in case they accidentally copied spaces
        $code = $code.Trim()

        $result = Load-Game $code

        if($result.Success){
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════╗" "Green"
            Write-CL "  ║       SAVE LOADED SUCCESSFULLY!       ║" "Green"
            Write-CL "  ╚══════════════════════════════════════╝" "Green"
            Write-Host ""
            $p = $script:Player
            Write-CL "  Welcome back, $($p.Name)!" "Yellow"
            Write-CL "  Class: $($script:PlayerClass)  Level: $($script:PlayerLevel)" "DarkGray"
            Write-CL "  HP: $($p.HP)/$($p.MaxHP)  MP: $($p.MP)/$($p.MaxMP)" "DarkGray"
            Write-CL "  Gold: $($script:Gold)g" "Yellow"
            Write-CL "  Dungeon Level: $($script:DungeonLevel)" "DarkGray"
            if($script:EquippedWeapon){
                Write-CL "  Weapon: $($script:EquippedWeapon.Name)" "Cyan"
            }
            if($script:Partner){
                Write-CL "  Ally: $($script:Partner.Name) ($($script:Partner.Class))" "Green"
            }
            Write-Host ""
            Write-CL "  Your loot was converted to gold." "DarkYellow"
            Write-CL "  Quests have been reset - visit the Quest Board!" "DarkYellow"
            Write-Host ""
            Wait-Key
            # Skip lore and character select, go straight to town
            Show-MainMenu
            return
        } else {
            # Load failed — tell them why and fall through to new game
            Write-Host ""
            Write-CL "  ╔══════════════════════════════════════╗" "Red"
            Write-CL "  ║         LOAD FAILED                   ║" "Red"
            Write-CL "  ╚══════════════════════════════════════╝" "Red"
            Write-CL "  $($result.Error)" "DarkRed"
            Write-Host ""
            Write-CL "  Starting a new game instead..." "DarkGray"
            Wait-Key
        }
    }

    # ── NEW GAME PATH (lore + character select, same as before) ──

    # ── Story Intro ──
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkCyan"
    Write-CL "  ║                 T H E   L O R E                          ║" "Cyan"
    Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkCyan"
    Write-Host ""
    Write-CL "  In the age before automation, the realm was at peace." "Gray"
    Write-CL "  Scripts ran on time. Logs were clean. Cron jobs never failed." "Gray"
    Write-Host ""
    Start-Sleep -Milliseconds 1200
    Write-CL "  Then came the Great Deprecated Update." "DarkYellow"
    Write-Host ""
    Start-Sleep -Milliseconds 1200
    Write-CL "  A careless wizard cast an untested script upon the kingdom's" "Gray"
    Write-CL "  core infrastructure. No -WhatIf. No -Confirm. Just..." "Gray"
    Write-Host ""
    Start-Sleep -Milliseconds 800
    Write-CL "    Invoke-Catastrophe -Force -NoRollback" "Red"
    Write-Host ""
    Start-Sleep -Milliseconds 1500
    Write-CL "  The earth split open. Beneath the Server Halls of the old" "Gray"
    Write-CL "  kingdom, a vast dungeon materialized — twisting corridors" "Gray"
    Write-CL "  of corrupted memory, haunted by rogue processes and daemon" "Gray"
    Write-CL "  threads that refused to terminate." "Gray"
    Write-Host ""
    Start-Sleep -Milliseconds 1200
    Write-CL "  They call it... the Depths of PowerShell." "Cyan"
    Write-Host ""
    Start-Sleep -Milliseconds 1500
    Wait-Key
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkCyan"
    Write-CL "  ║                 T H E   L O R E                          ║" "Cyan"
    Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkCyan"
    Write-Host ""
    Write-CL "  The Guild of SysAdmins posted a bounty:" "DarkYellow"
    Write-Host ""
    Write-CL "  ┌──────────────────────────────────────────────────────┐" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-CL "  │   WANTED: Brave soul to descend into the Depths.     │" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-CL "  │   Objective: Reach the bottom. Find the root shell.  │" "Yellow"
    Write-CL "  │   Terminate the runaway process known only as...     │" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-C  "  │           " "Yellow"
    Write-C "the Lich King of Legacy Code" "Red"
    Write-CL "             │" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-CL "  │   WARNING: This task cannot be run as a background   │" "Yellow"
    Write-CL "  │   job. You must go in person.                        │" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-CL "  │   Payment: All the gold your pipeline can carry.     │" "Yellow"
    Write-CL "  │                                                      │" "Yellow"
    Write-CL "  └──────────────────────────────────────────────────────┘" "Yellow"
    Write-Host ""
    Start-Sleep -Milliseconds 1000
    Write-CL "  You step forward. You have no -ErrorAction SilentlyContinue." "Gray"
    Write-CL "  If you fail, the exception will not be caught." "Gray"
    Write-Host ""
    Start-Sleep -Milliseconds 1200
    Write-CL "  There is only one way out: through." "White"
    Write-Host ""
    Wait-Key

    Show-CharacterSelect

    # ── Tutorial offer (new game only) ──
    if(-not $script:TutorialSeen){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════╗" "DarkGreen"
        Write-CL "  ║             W E L C O M E ,   A D V E N T U R E R      ║" "Green"
        Write-CL "  ╚══════════════════════════════════════════════════════════╝" "DarkGreen"
        Write-Host ""
        Write-CL "  This is your first time in the Depths." "White"
        Write-Host ""
        Write-C "  Would you like a quick tutorial? (y/n): " "Yellow"
        $tut = Read-Host
        if($tut -eq 'y' -or $tut -eq 'Y'){
            Show-Tutorial
        }
        $script:TutorialSeen = $true
    }

    Show-MainMenu
}

# ─── INVENTORY SCREEN ─────────────────────────────────────────────
# Extracted so it can be called from both Town Square ([3]) and from
# inside a dungeon ([I] key). Same UI, same options.
# ─── QUEST LOG ────────────────────────────────────────────────────
# Quick view of all active quests with progress bars. Called from the
# dungeon's [J] key and the town square's quest board for at-a-glance
# tracking. Read-only — accept/turn-in still happens at the board.
# ─── BESTIARY ─────────────────────────────────────────────────────
# Read-only screen listing every enemy type the player has defeated, with
# per-variant kill counts. Sorted into Normal / Mini-Boss / Boss sections.
# Accessible from the town square; no gameplay effect.
function Show-Bestiary {
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkRed"
    Write-CL "  ║                       B E S T I A R Y                           ║" "Red"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkRed"
    Write-Host ""

    if(-not $script:Bestiary -or $script:Bestiary.Count -eq 0){
        Write-CL "  No creatures defeated yet. Venture into the dungeons!" "DarkGray"
        Write-Host ""
        Wait-Key
        return
    }

    # Group entries by category from the key prefix. Keys use ~ as the
    # internal delimiter so they round-trip through save/load cleanly.
    $normals = @()
    $minis   = @()
    $bosses  = @()
    foreach($k in $script:Bestiary.Keys){
        $entry = @{ Key=$k; Count=$script:Bestiary[$k].Kills }
        if($k.StartsWith("Boss~"))         { $bosses += $entry }
        elseif($k.StartsWith("MiniBoss~")) { $minis  += $entry }
        else                                { $normals += $entry }
    }

    # ── Normal enemies ──
    if($normals.Count -gt 0){
        Write-CL "  ── Normal Enemies ──" "Yellow"
        $sorted = $normals | Sort-Object { $_.Key }
        foreach($e in $sorted){
            $parts = $e.Key -split '~'
            $type = $parts[0]
            $variant = if($parts.Count -gt 1){$parts[1]}else{""}
            $name = if($variant){"$variant $type"}else{$type}
            $colVar = switch($variant){
                "Frenzied" { "Red" }
                "Armored"  { "DarkGray" }
                "Hulking"  { "DarkYellow" }
                "Swift"    { "Cyan" }
                "Sickly"   { "DarkGreen" }
                "Brutal"   { "Magenta" }
                default    { "White" }
            }
            $padName = $name.PadRight(28)
            Write-C "    " "Black"
            Write-C $padName $colVar
            Write-C "  Slain: " "DarkGray"
            Write-CL "$($e.Count)" "Yellow"
        }
        Write-Host ""
    }

    # ── Mini-bosses ──
    if($minis.Count -gt 0){
        Write-CL "  ── Mini-Bosses ──" "Yellow"
        foreach($e in $minis){
            $parts = $e.Key -split '~'
            $name  = $parts[1]
            $padName = $name.PadRight(28)
            Write-C "    " "Black"
            Write-C $padName "Magenta"
            Write-C "  Slain: " "DarkGray"
            Write-CL "$($e.Count)" "Yellow"
        }
        Write-Host ""
    }

    # ── Bosses ──
    if($bosses.Count -gt 0){
        Write-CL "  ── Bosses ──" "Yellow"
        foreach($e in $bosses){
            $parts = $e.Key -split '~'
            $name  = $parts[1]
            $padName = $name.PadRight(28)
            Write-C "    " "Black"
            Write-C $padName "Red"
            Write-C "  Slain: " "DarkGray"
            Write-CL "$($e.Count)" "Yellow"
        }
        Write-Host ""
    }

    # Hidden boss flag, shown only if the player has actually beaten them
    if($script:HiddenBossDefeated){
        Write-CL "  ── ??? ──" "DarkMagenta"
        Write-CL "    The Orphaned Process              Slain: 1" "Magenta"
        Write-Host ""
    }

    $totalSpecies = $script:Bestiary.Count
    Write-CL "  $totalSpecies distinct creatures recorded." "DarkGray"
    Write-Host ""
    Wait-Key
}

# ─── RUN SUMMARY ──────────────────────────────────────────────────
# Quick stats screen shown at the end of a dungeon run (clear OR death).
# Pure read-only display from $script:RunStats.
function Show-RunSummary {
    param([string]$Outcome = "Run Complete")
    Write-Host ""
    Write-CL "  ┌──────────────────────────────────────────────────────────────────┐" "DarkCyan"
    $tit = "  R U N   S U M M A R Y"
    $padT = 66 - $tit.Length
    if($padT -lt 0){ $padT = 0 }
    Write-C  "  │" "DarkCyan"; Write-C $tit "Cyan"; Write-CL "$(' ' * $padT)│" "DarkCyan"
    Write-CL "  ├──────────────────────────────────────────────────────────────────┤" "DarkCyan"
    $rs = $script:RunStats
    $rows = @(
        @{L="Outcome";        V=$Outcome}
        @{L="Kills";          V="$($rs.KillsThisRun)"}
        @{L="Critical Hits";  V="$($rs.CritsThisRun)"}
        @{L="Damage Dealt";   V="$($rs.DamageDealt)"}
        @{L="Damage Taken";   V="$($rs.DamageTaken)"}
        @{L="Gold Earned";    V="$($rs.GoldEarned)g"}
        @{L="XP Earned";      V="$($rs.XPEarned)"}
        @{L="Potions Used";   V="$($rs.PotionsUsed)"}
        @{L="Steps Taken";    V="$($rs.StepsTaken)"}
    )
    foreach($r in $rows){
        $line = "  $($r.L.PadRight(20))$($r.V)"
        $pad = 66 - $line.Length
        if($pad -lt 0){ $pad = 0 }
        Write-C "  │" "DarkCyan"
        Write-C $line "White"
        Write-CL "$(' ' * $pad)│" "DarkCyan"
    }
    Write-CL "  └──────────────────────────────────────────────────────────────────┘" "DarkCyan"
    Write-Host ""
}

function Show-QuestLog {
    clr
    Write-Host ""
    Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkYellow"
    Write-CL "  ║                   Q U E S T   J O U R N A L                      ║" "Yellow"
    Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkYellow"
    Write-Host ""

    # (user fix) The log previously listed ONLY board bounties — the
    # ! story quest and * town side quests were invisible outside
    # town. All three sections render here now.
    $qlMq = Get-CurrentMainQuest
    $qlSt = Get-MainStage
    $qlStory = ($qlMq -and $qlSt -gt 0)
    $qlSides = @()
    foreach($qlLoc in @("backupvale","bashford","cronmarch","nullhaven","foreachfalls","cachegrove","firewallkeep","syslogxing","kernelhold","registry","terminus","sysv")){
        $qlSq = Get-TownQuest $qlLoc
        if(-not $qlSq){ continue }
        $qlStg = Get-QuestStage $qlSq.Id
        if($qlStg -ge 100000 -and $qlStg -ne 999999){
            $qlSides += @{ Q = $qlSq; Loc = $qlLoc }
        }
    }
    $active = @()
    if($script:Quests){ $active = @($script:Quests | Where-Object { -not $_.TurnedIn }) }
    if(-not $qlStory -and $qlSides.Count -eq 0 -and $active.Count -eq 0){
        Write-CL "  No active quests. Visit the Quest Board in town to accept some." "DarkGray"
        Write-Host ""
        Wait-Enter
        return
    }
    if($qlStory){
        $qlPhase = $qlSt % 10
        if($qlPhase -eq 0){
            $qlWhere = "Helpdesk"
            if($qlMq.Where -ne "town"){ $qlWhere = (Get-WorldLocation $qlMq.Where).Name }
            $qlRow = "the trail leads to $qlWhere"
        } else {
            $qlProg = Get-MainQuestProgress $qlMq
            if($qlProg -lt 0){ $qlProg = 0 }
            if($qlProg -gt $qlMq.Need){ $qlProg = $qlMq.Need }
            $qlRow = "$qlProg/$($qlMq.Need)"
            if($qlProg -ge $qlMq.Need){ $qlRow = $qlRow + " - READY at the town [!]" }
        }
        Write-C "  [!] " "Red"
        Write-C $qlMq.Title "White"
        Write-C "  " "DarkGray"
        Write-CL $qlRow "Red"
        Write-Host ""
    }
    foreach($qlS in $qlSides){
        $qlTown = (Get-WorldLocation $qlS.Loc).Name
        Write-C "  [*] " "Magenta"
        Write-C $qlS.Q.Name "White"
        Write-CL "  ($qlTown - advance at its [*])" "DarkGray"
    }
    if($qlSides.Count -gt 0){ Write-Host "" }
    if($active.Count -eq 0){
        Write-CL "  No board bounties held. Grab some at the Quest Board in town." "DarkGray"
        Write-Host ""
        Wait-Enter
        return
    }

    $i = 1
    foreach($q in $active){
        $statusTag = if($q.Complete){"[READY TO TURN IN]"}else{"[$($q.Progress)/$($q.TargetCount)]"}
        $statusColor = if($q.Complete){"Green"}else{"Yellow"}
        Write-C "  [$i] " "DarkGray"
        Write-C $q.Desc "White"
        Write-C "  " "DarkGray"
        Write-CL $statusTag $statusColor

        # Progress bar (10 cells)
        if(-not $q.Complete -and $q.TargetCount -gt 0){
            $pct = $q.Progress / $q.TargetCount
            $filled = [math]::Floor($pct * 20)
            if($filled -lt 0){$filled = 0}; if($filled -gt 20){$filled = 20}
            $empty = 20 - $filled
            Write-C "      [" "DarkGray"
            Write-C ('=' * $filled) "Green"
            Write-C ('-' * $empty) "DarkGray"
            Write-C "]" "DarkGray"
            Write-CL "  Reward: $($q.RewardGold)g + $($q.RewardXP) XP" "DarkYellow"
        } else {
            Write-CL "      Reward: $($q.RewardGold)g + $($q.RewardXP) XP" "DarkYellow"
        }
        Write-Host ""
        $i++
    }

    Write-CL "  Turn in completed quests at the Quest Board in town." "DarkGray"
    Write-Host ""
    Wait-Enter
}

# ─── NOTE READER ──────────────────────────────────────────────────
# Lists every Note item currently in the bag, lets the player pick
# one by number to read in full. Pure flavor — no mechanics, no
# stat changes, just a way to revisit picked-up lore at any time.
function Show-NoteReader {
    # Marn's Journal (Cat 7): flag-driven page viewer. Pages are
    # listed in journal order with gaps visible, so the player can
    # see exactly which pages are still missing. The bag is NOT
    # consulted — items liquidate on save, the flags never do.
    $pool = @(Get-JournalPages)
    if(-not $script:JournalPages -or $script:JournalPages.Count -eq 0){
        clr
        Write-Host ""
        Write-CL "  You haven't recovered any journal pages yet." "DarkGray"
        Write-Host ""
        Wait-Enter
        return
    }
    $readerLoop = $true
    while($readerLoop){
        clr
        Write-Host ""
        Write-CL "  ╔════════════════════════════════════════════════════════════╗" "DarkMagenta"
        Write-CL "  ║                M A R N ' S   J O U R N A L                 ║" "Magenta"
        Write-CL "  ╚════════════════════════════════════════════════════════════╝" "DarkMagenta"
        Write-Host ""
        $found = 0
        foreach($jp in $pool){
            if($script:JournalPages.ContainsKey([int]$jp.Page)){ $found++ }
        }
        Write-CL "  Pages recovered: $found / $($pool.Count)" "DarkYellow"
        if($script:JournalCharm){
            Write-CL "  [Charm] Marn's Lucky Byte — +2% crit, always." "Green"
        }
        Write-Host ""
        foreach($jp in $pool){
            $pn = [int]$jp.Page
            if($script:JournalPages.ContainsKey($pn)){
                $numTag = "[$pn]".PadRight(5)
                Write-C "  $numTag " "DarkGray"
                Write-CL $jp.Title "Magenta"
            } else {
                $numTag = "[$pn]".PadRight(5)
                Write-CL "  $numTag (page missing)" "DarkGray"
            }
        }
        Write-Host ""
        Write-CL "  [0] Back" "DarkGray"
        Write-Host ""
        Write-C "  Read which page? > " "Yellow"
        $pick = Read-Host
        if($pick -eq "0" -or [string]::IsNullOrWhiteSpace($pick)){
            $readerLoop = $false
            continue
        }
        $idx = 0
        if(-not [int]::TryParse($pick, [ref]$idx)){ continue }
        if($idx -lt 1 -or $idx -gt $pool.Count){ continue }
        # Unrecovered pages can't be read — the gap is the point.
        if(-not $script:JournalPages.ContainsKey($idx)){ continue }

        # Display the page. Word-wrap the body text at ~62 chars per
        # line so it fits the screen without breaking words awkwardly.
        $note = $pool[$idx - 1]
        clr
        Write-Host ""
        Write-CL "  ╔════════════════════════════════════════════════════════════╗" "DarkMagenta"
        $title = $note.Title
        if($title.Length -gt 56){ $title = $title.Substring(0, 56) }
        $titleLine = "  ║  " + $title.PadRight(56) + "  ║"
        Write-CL $titleLine "Magenta"
        Write-CL "  ╚════════════════════════════════════════════════════════════╝" "DarkMagenta"
        Write-Host ""

        $body = if($note.Body){[string]$note.Body}else{"(this page is blank)"}
        # Wrap body at ~62 chars without breaking mid-word. Newlines
        # in the source text are preserved as paragraph breaks.
        $wrapWidth = 62
        foreach($paragraph in ($body -split "`n")){
            if($paragraph.Trim().Length -eq 0){
                Write-Host ""
                continue
            }
            $words = $paragraph.Trim() -split '\s+'
            $line = ""
            foreach($w in $words){
                if(($line.Length + $w.Length + 1) -le $wrapWidth){
                    if($line.Length -gt 0){ $line += " " }
                    $line += $w
                } else {
                    Write-CL ("  " + $line) "Gray"
                    $line = $w
                }
            }
            if($line.Length -gt 0){
                Write-CL ("  " + $line) "Gray"
            }
        }
        Write-Host ""
        Wait-Enter
    }
}

function Show-InventoryScreen {
    $invLoop = $true
    while($invLoop){
        clr
        Write-Host ""
        # ── Consistent 60-char-wide boxes with interior 58 ──
        # Pattern: "  ║" + content(58 chars exactly) + "║"
        # Where content starts with a space and ends with space padding
        $BoxW = 58              # interior width
        $barH = "═" * $BoxW     # horizontal bar
        # Helper: pad a visible-length string to exactly $BoxW chars
        function Pad-Box {
            param([string]$s,[int]$width=$BoxW)
            if($s.Length -ge $width){
                return $s.Substring(0,$width)
            }
            return $s + (" " * ($width - $s.Length))
        }

        # 60-char banner
        Write-CL ("  ╔" + $barH + "╗") "DarkCyan"
        $title = " I N V E N T O R Y "
        $tSpace = [math]::Floor(($BoxW - $title.Length) / 2)
        $tLine  = (" " * $tSpace) + $title
        Write-C "  ║" "DarkCyan"
        Write-C (Pad-Box $tLine) "Cyan"
        Write-CL "║" "DarkCyan"
        Write-CL ("  ╚" + $barH + "╝") "DarkCyan"
        Write-Host ""

        # ── Character summary line (class shown ONCE: $p.Name IS the class name) ──
        $p = $script:Player
        $wepATK = Get-TotalWeaponATK
        $armorDEF = Get-TotalArmorDEF
        $magBonus = Get-WeaponMAGBonus

        Write-C "  $($p.Name)" "Green"
        $curW = Get-CurrentCarryWeight
        $maxW = Get-MaxCarryWeight $script:Player
        $weightColor = if($curW -gt $maxW){"Red"}elseif($curW -gt ($maxW * 0.85)){"Yellow"}else{"Green"}
        Write-CL "   Lv$($script:PlayerLevel)  |  Gold: $($script:Gold)g  |  Lockpicks: $($script:Lockpicks) ($($script:Lockpicks)wt)" "DarkGray"
        Write-C  "   Carry: " "DarkGray"
        Write-CL "$curW / $maxW" $weightColor
        if($script:RepairKits -gt 0){
            Write-C  "   Special items: " "DarkGray"
            Write-C "Repair Kits x$($script:RepairKits)" "Cyan"
            Write-Host ""
        }
        Write-Host ""

        # ── Equipped gear (Phase 2): paper-doll pane on VT hosts, the
        # classic weapon/armor boxes elsewhere. The invLoop redraw
        # means equip/unequip updates the doll immediately. (v12
        # sketched a cursor-addressed pane; composed in-flow lines
        # were chosen instead because this screen can scroll —
        # absolute addressing would smear the doll mid-list.) ──
        $dollPane = $false
        try { if(Test-VTSupport){ $dollPane = $true } } catch {}
        if($dollPane){
            $dEsc = [char]27
            $dAp = $script:Appearance
            if(-not $dAp){ $dAp = @{ Gender = 0; Skin = 2; HairStyle = 0; HairColor = 0; Outfit = 0 } }
            $dLines = Get-CharDollLines -Gender $dAp.Gender -Skin $dAp.Skin -HairStyle $dAp.HairStyle -HairColor $dAp.HairColor -Outfit $dAp.Outfit -Overlays (Get-DollEquipOverlays)
            $rl = @()
            $rl += @{ T = ""; C = "0" }
            $rl += @{ T = "WEAPON"; C = "93" }
            if($script:EquippedWeapon){
                $wpn = $script:EquippedWeapon
                $wDur = Format-Durability $wpn
                $wTxt = "  " + $wpn.Name + "  ATK+" + $wpn.ATK + "  " + $wDur
                $rl += @{ T = $wTxt; C = "36" }
            } else {
                $rl += @{ T = "  Bare Hands"; C = "90" }
            }
            $rl += @{ T = ""; C = "0" }
            $rl += @{ T = ("ARMOR   DEF +" + $armorDEF); C = "93" }
            foreach($dSlot in @("Helmet","Chest","Shield","Amulet","Boots")){
                $dPiece = $script:EquippedArmor[$dSlot]
                $dLbl = ($dSlot + ":").PadRight(9)
                if($dPiece){
                    $dTag = Get-ArmorClassTag $dPiece
                    $dDur = Format-Durability $dPiece
                    $dTxt = "  " + $dLbl + $dPiece.Name + " (DEF+" + $dPiece.DEF + ")" + $dTag + " " + $dDur
                    $rl += @{ T = $dTxt; C = "36" }
                } else {
                    $rl += @{ T = ("  " + $dLbl + "(empty)"); C = "90" }
                }
            }
            $rtMax = 62
            try { $rtMax = [int]$Host.UI.RawUI.WindowSize.Width - 38 } catch {}
            if($rtMax -lt 12){ $rtMax = 12 }
            for($dY = 0; $dY -lt 24; $dY++){
                $rt = ""
                if($dY -lt $rl.Count){
                    $dT = [string]$rl[$dY].T
                    if($dT.Length -gt $rtMax){ $dT = $dT.Substring(0, $rtMax) }
                    $dC = [string]$rl[$dY].C
                    if($dT.Length -gt 0){ $rt = "$dEsc[${dC}m$dT$dEsc[0m" }
                }
                Write-Host ("  " + $dLines[$dY] + "  " + $rt)
            }
            Write-Host ""
        } else {
        # ── Equipped Weapon ──
        Write-CL ("  ╔" + $barH + "╗") "DarkYellow"
        # Header row
        Write-C "  ║" "DarkYellow"
        Write-C (Pad-Box " W E A P O N") "Yellow"
        Write-CL "║" "DarkYellow"
        Write-CL ("  ╠" + $barH + "╣") "DarkYellow"
        # Body row
        if($script:EquippedWeapon){
            $w = $script:EquippedWeapon
            $cb = Get-WeaponClassBonus
            $cbStr   = if($cb -gt 0){" [+$cb class bonus]"}else{""}
            $perkStr = if($w.Perk){" [$($w.Perk) $($w.PerkChance)%]"}else{""}
            $magStr  = if($w.MAGBonus){" [MAG+$($w.MAGBonus)]"}else{""}
            $durStr  = " " + (Format-Durability $w)  # leading space separator
            $durColr = Get-DurabilityColor $w
            $wepWt   = Get-ItemWeight $w
            $wtStr   = " ${wepWt}wt"
            # Render colored segments inline, then compute remaining pad
            $emitted = 0
            Write-C "  ║" "DarkYellow"
            Write-C " $($w.Name)" "Cyan";     $emitted += 1 + $w.Name.Length
            Write-C "  ATK+$($w.ATK)" "White"; $emitted += 6 + "$($w.ATK)".Length
            if($cbStr){   Write-C $cbStr "Green";     $emitted += $cbStr.Length }
            if($perkStr){ Write-C $perkStr "DarkRed"; $emitted += $perkStr.Length }
            if($magStr){  Write-C $magStr "Magenta";  $emitted += $magStr.Length }
            if($durStr.Trim()){ Write-C $durStr $durColr; $emitted += $durStr.Length }
            Write-C $wtStr "DarkGray"; $emitted += $wtStr.Length
            $remaining = $BoxW - $emitted
            if($remaining -lt 0){ $remaining = 0 }
            Write-C (" " * $remaining) "Black"
            Write-CL "║" "DarkYellow"
        } else {
            Write-C "  ║" "DarkYellow"
            Write-C (Pad-Box " Bare Hands") "DarkGray"
            Write-CL "║" "DarkYellow"
        }
        Write-CL ("  ╚" + $barH + "╝") "DarkYellow"
        Write-Host ""

        # ── Equipped Armor ──
        Write-CL ("  ╔" + $barH + "╗") "DarkCyan"
        # Header with right-aligned DEF total
        $armorHdr = "A R M O R"
        $armorDefStr = "DEF: +$armorDEF "
        $midLen = $BoxW - 1 - $armorHdr.Length - $armorDefStr.Length  # 1 leading space
        if($midLen -lt 1){$midLen = 1}
        Write-C "  ║" "DarkCyan"
        Write-C " $armorHdr" "Cyan"
        Write-C (" " * $midLen) "Black"
        Write-C $armorDefStr "White"
        Write-CL "║" "DarkCyan"
        Write-CL ("  ╠" + $barH + "╣") "DarkCyan"
        $slots = @("Helmet","Chest","Shield","Amulet","Boots")
        foreach($slot in $slots){
            $piece = $script:EquippedArmor[$slot]
            $slotLabel = "$($slot):".PadRight(10)
            Write-C "  ║" "DarkCyan"
            Write-C " $slotLabel" "White"
            if($piece){
                $pText = "$($piece.Name) (DEF+$($piece.DEF))$(Get-ArmorClassTag $piece)"
                Write-C $pText "Cyan"
                $dStr = " " + (Format-Durability $piece)
                $dClr = Get-DurabilityColor $piece
                Write-C $dStr $dClr
                $aWt = Get-ItemWeight $piece
                $aWtStr = " ${aWt}wt"
                Write-C $aWtStr "DarkGray"
                $used = 1 + 10 + $pText.Length + $dStr.Length + $aWtStr.Length
            } else {
                Write-C "(empty)" "DarkGray"
                $used = 1 + 10 + 7
            }
            $pad = $BoxW - $used
            if($pad -lt 0){$pad = 0}
            Write-C (" " * $pad) "Black"
            Write-CL "║" "DarkCyan"
        }
        Write-CL ("  ╚" + $barH + "╝") "DarkCyan"
        Write-Host ""
        }

        # ── Loot / Items ──
        Write-CL ("  ╔" + $barH + "╗") "DarkMagenta"
        $lootHdr = " L O O T  ($($script:Inventory.Count) items)"
        Write-C "  ║" "DarkMagenta"
        Write-C (Pad-Box $lootHdr) "Magenta"
        Write-CL "║" "DarkMagenta"
        Write-CL ("  ╠" + $barH + "╣") "DarkMagenta"
        if($script:Inventory.Count -eq 0){
            Write-C "  ║" "DarkMagenta"
            Write-C (Pad-Box " (empty)") "DarkGray"
            Write-CL "║" "DarkMagenta"
        } else {
            $totalVal = 0
            $totalWt  = 0
            for($i=0;$i -lt $script:Inventory.Count;$i++){
                $it=$script:Inventory[$i]
                $sv = Get-ItemSellValue $it
                $totalVal += $sv
                $iWt = Get-ItemWeight $it
                $totalWt += $iWt
                $kindTag = switch($it.Kind){
                    "Weapon" { "[Wpn]" }
                    "Armor"  { "[Arm]" }
                    "Potion" { "[Pot]" }
                    "Note"   { "[Note]" }
                    default  { "[Loot]" }
                }
                $iName = "$($i+1). $($it.Name) $kindTag"
                $iVal  = "${sv}g"
                $iWtStr = "${iWt}wt"
                $namePad = 36
                if($iName.Length -gt $namePad){ $iName = $iName.Substring(0, $namePad - 3) + "..." }
                Write-C "  ║" "DarkMagenta"
                Write-C " " "Black"
                Write-C $iName.PadRight($namePad) "Magenta"
                Write-C " " "Black"
                Write-C $iWtStr.PadLeft(5) "DarkGray"
                Write-C " " "Black"
                Write-C $iVal.PadLeft(8) "Yellow"
                $used = 1 + $namePad + 1 + 5 + 1 + 8
                $pad = $BoxW - $used
                if($pad -lt 0){$pad = 0}
                Write-C (" " * $pad) "Black"
                Write-CL "║" "DarkMagenta"
            }
            Write-CL ("  ╠" + $barH + "╣") "DarkMagenta"
            Write-C "  ║" "DarkMagenta"
            Write-C " Total: " "White"
            Write-C "${totalVal}g" "Yellow"
            Write-C " | " "DarkGray"
            Write-C "${totalWt}wt" "DarkGray"
            $used = 1 + 8 + "${totalVal}g".Length + 3 + "${totalWt}wt".Length
            $pad = $BoxW - $used
            if($pad -lt 0){$pad = 0}
            Write-C (" " * $pad) "Black"
            Write-CL "║" "DarkMagenta"
        }
        Write-CL ("  ╚" + $barH + "╝") "DarkMagenta"
        Write-Host ""

        # ── Potions / Throwables ──
        $potCount = $script:Potions.Count
        $thrCount = $script:ThrowablePotions.Count
        if($potCount -gt 0 -or $thrCount -gt 0){
            Write-CL ("  ╔" + $barH + "╗") "DarkGreen"
            $consHdr = " P O T I O N S  ($potCount)  +  T H R O W A B L E S  ($thrCount)"
            Write-C "  ║" "DarkGreen"
            Write-C (Pad-Box $consHdr) "Green"
            Write-CL "║" "DarkGreen"
            Write-CL ("  ╠" + $barH + "╣") "DarkGreen"
            $idx = 0
            for($pi=0; $pi -lt $potCount; $pi++){
                $idx++
                $pot = $script:Potions[$pi]
                $iName = "$idx. $($pot.Name) [Pot]"
                $iVal  = if($pot.Price){"$($pot.Price)g"}else{"---"}
                if($iName.Length -gt 36){ $iName = $iName.Substring(0,33) + "..." }
                Write-C "  ║" "DarkGreen"
                Write-C " " "Black"
                Write-C $iName.PadRight(36) "Green"
                Write-C " " "Black"
                Write-C "1wt".PadLeft(5) "DarkGray"
                Write-C " " "Black"
                Write-C $iVal.PadLeft(8) "Yellow"
                $used = 1 + 36 + 1 + 5 + 1 + 8
                $pad = $BoxW - $used
                if($pad -lt 0){$pad = 0}
                Write-C (" " * $pad) "Black"
                Write-CL "║" "DarkGreen"
            }
            for($ti=0; $ti -lt $thrCount; $ti++){
                $idx++
                $thr = $script:ThrowablePotions[$ti]
                $iName = "$idx. $($thr.Name) [Thr]"
                $iVal  = if($thr.Price){"$($thr.Price)g"}else{"---"}
                if($iName.Length -gt 36){ $iName = $iName.Substring(0,33) + "..." }
                Write-C "  ║" "DarkGreen"
                Write-C " " "Black"
                Write-C $iName.PadRight(36) "DarkYellow"
                Write-C " " "Black"
                Write-C "1wt".PadLeft(5) "DarkGray"
                Write-C " " "Black"
                Write-C $iVal.PadLeft(8) "Yellow"
                $used = 1 + 36 + 1 + 5 + 1 + 8
                $pad = $BoxW - $used
                if($pad -lt 0){$pad = 0}
                Write-C (" " * $pad) "Black"
                Write-CL "║" "DarkGreen"
            }
            # Lockpicks no longer get their own row here — they're shown
            # at the top of the inventory screen with their total weight,
            # so duplicating them inside the potions box is just visual noise.
            Write-CL ("  ╚" + $barH + "╝") "DarkGreen"
            Write-Host ""
        }
        # Note: the lockpick count is shown at the top of the inventory
        # screen alongside its weight; we no longer render a standalone
        # lockpicks-only box here.

        # ── Cooking ingredients section ──
        # Each ingredient weighs 1; rolled up into one box.
        if($script:Ingredients){
            $ingTotal = 0
            foreach($k in $script:Ingredients.Keys){
                $ingTotal += [int]$script:Ingredients[$k]
            }
            if($ingTotal -gt 0){
                Write-CL ("  ╔" + $barH + "╗") "DarkRed"
                $iHdr = " I N G R E D I E N T S  ($ingTotal)"
                Write-C "  ║" "DarkRed"
                Write-C (Pad-Box $iHdr) "Yellow"
                Write-CL "║" "DarkRed"
                Write-CL ("  ╠" + $barH + "╣") "DarkRed"
                foreach($ing in @("Mushroom","Herb","Meat","Bone")){
                    $ct = if($script:Ingredients.ContainsKey($ing)){[int]$script:Ingredients[$ing]}else{0}
                    if($ct -le 0){ continue }
                    $iName = "  $ing x$ct"
                    $iWt   = "${ct}wt"
                    Write-C "  ║" "DarkRed"
                    Write-C " " "Black"
                    Write-C $iName.PadRight(36) "Yellow"
                    Write-C " " "Black"
                    Write-C $iWt.PadLeft(5) "DarkGray"
                    Write-C " " "Black"
                    Write-C "---".PadLeft(8) "DarkGray"
                    $used = 1 + 36 + 1 + 5 + 1 + 8
                    $pad = $BoxW - $used
                    if($pad -lt 0){$pad = 0}
                    Write-C (" " * $pad) "Black"
                    Write-CL "║" "DarkRed"
                }
                Write-CL ("  ╚" + $barH + "╝") "DarkRed"
                Write-Host ""
            }
        }


        # ── Options (interior 44) ──
        $oBar = "─" * 44
        Write-CL "  ┌$oBar┐" "DarkGray"
        $row1 = " [U] Unequip Gear (move to bag)"
        $pad1 = 42 - $row1.Length
        if($pad1 -lt 0){$pad1 = 0}
        Write-C "  │" "DarkGray"; Write-C " [U]" "Red"; Write-C " Unequip Gear (move to bag)" "White"
        Write-CL ("$(' ' * $pad1) │") "DarkGray"
        $eRow = " [E] Equip from Bag"
        $ePad = 42 - $eRow.Length
        if($ePad -lt 0){$ePad = 0}
        Write-C "  │" "DarkGray"; Write-C " [E]" "Green"; Write-C " Equip from Bag" "White"
        Write-CL ("$(' ' * $ePad) │") "DarkGray"
        $kRow = " [K] Use Repair Kit (x$($script:RepairKits))"
        $kPad = 42 - $kRow.Length
        if($kPad -lt 0){$kPad = 0}
        Write-C "  │" "DarkGray"; Write-C " [K]" "Cyan"; Write-C " Use Repair Kit (x$($script:RepairKits))" "White"
        Write-CL ("$(' ' * $kPad) │") "DarkGray"
        $dRow = " [D] Drop Items (destroy)"
        $dPad = 42 - $dRow.Length
        if($dPad -lt 0){$dPad = 0}
        Write-C "  │" "DarkGray"; Write-C " [D]" "DarkRed"; Write-C " Drop Items (destroy)" "White"
        Write-CL ("$(' ' * $dPad) │") "DarkGray"
        # Show [V] Journal once at least one page has ever been
        # collected (Cat 7). The collection is flag-based and
        # permanent, so the row stays even when the paper items
        # are long gone (the bag liquidates on save anyway).
        $hasNotes = ($script:JournalPages -and $script:JournalPages.Count -gt 0)
        if($hasNotes){
            $vRow = " [V] Journal"
            $vPad = 42 - $vRow.Length
            if($vPad -lt 0){$vPad = 0}
            Write-C "  │" "DarkGray"; Write-C " [V]" "Magenta"; Write-C " Journal" "White"
            Write-CL ("$(' ' * $vPad) │") "DarkGray"
        }
        $row2 = " [0] Back"
        $pad2 = 42 - $row2.Length
        if($pad2 -lt 0){$pad2 = 0}
        Write-C "  │" "DarkGray"; Write-C " [0]" "White"; Write-C " Back" "White"
        Write-CL ("$(' ' * $pad2) │") "DarkGray"
        Write-CL "  └$oBar┘" "DarkGray"
        Write-Host ""
        Write-C "  > " "Yellow"; $invCh = Read-Host

        switch($invCh.ToUpper()){
            "D" {
                Show-DropScreen
            }
            "V" {
                # Marn's Journal (Cat 7): flag-driven page collection
                # viewer — pages in order, gaps visible, read any
                # recovered page in full.
                Show-NoteReader
            }
            "K" {
                if($script:RepairKits -le 0){
                    Write-CL "  You don't have any Repair Kits." "Red"
                    Wait-Key
                    continue
                }
                # Check if anything actually needs repair
                $needsRepair = $false
                if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0 -and $script:EquippedWeapon.Durability -lt $script:EquippedWeapon.MaxDurability){
                    $needsRepair = $true
                }
                if(-not $needsRepair){
                    foreach($slotN in @("Helmet","Chest","Shield","Amulet","Boots")){
                        $piece = $script:EquippedArmor[$slotN]
                        if($piece -and $piece.MaxDurability -ge 0 -and $piece.Durability -lt $piece.MaxDurability){
                            $needsRepair = $true; break
                        }
                    }
                }
                if(-not $needsRepair){
                    Write-CL "  All your gear is already at full durability." "DarkGray"
                    Wait-Key
                    continue
                }
                # Repair everything
                $script:RepairKits--
                Write-Host ""
                Write-CL "  *POP* You crack open the Repair Kit." "Cyan"
                if($script:EquippedWeapon -and $script:EquippedWeapon.MaxDurability -ge 0){
                    $script:EquippedWeapon.Durability = $script:EquippedWeapon.MaxDurability
                    Write-CL "    ✓ $($script:EquippedWeapon.Name) restored" "Green"
                }
                foreach($slotN in @("Helmet","Chest","Shield","Amulet","Boots")){
                    $piece = $script:EquippedArmor[$slotN]
                    if($piece -and $piece.MaxDurability -ge 0){
                        $piece.Durability = $piece.MaxDurability
                        Write-CL "    ✓ $($piece.Name) restored" "Green"
                    }
                }
                Write-CL "  All gear repaired! ($($script:RepairKits) kit(s) remaining)" "Cyan"
                Wait-Key
            }
            "U" {
                clr
                Write-CL "  ── Unequip Gear ──" "Red"
                Write-CL "  Items go back to your inventory bag (no refund)." "DarkGray"
                Write-Host ""
                $unequipOptions = [System.Collections.ArrayList]@()
                if($script:EquippedWeapon){
                    [void]$unequipOptions.Add(@{Label="Weapon: $($script:EquippedWeapon.Name)";Slot="Weapon"})
                }
                foreach($slot in $slots){
                    if($script:EquippedArmor[$slot]){
                        [void]$unequipOptions.Add(@{Label="$($slot): $($script:EquippedArmor[$slot].Name)";Slot=$slot})
                    }
                }
                if($unequipOptions.Count -eq 0){
                    Write-CL "  Nothing equipped to remove." "DarkGray"
                    Wait-Key
                } else {
                    for($ui=0;$ui -lt $unequipOptions.Count;$ui++){
                        Write-CL "  [$($ui+1)] $($unequipOptions[$ui].Label)" "White"
                    }
                    Write-CL "  [0] Cancel" "DarkGray"
                    Write-Host ""
                    Write-C "  > " "Yellow"; $uPick = Read-Host
                    $uIdx = (ConvertTo-SafeInt -Value $uPick) - 1
                    if($uIdx -ge 0 -and $uIdx -lt $unequipOptions.Count){
                        $uSlot = $unequipOptions[$uIdx].Slot
                        if($uSlot -eq "Weapon"){
                            # Special warning for Dutchman's Blade — even though
                            # it now goes to the bag (and could be re-equipped),
                            # players might not realize it's irreplaceable.
                            if($script:EquippedWeapon.Name -eq "Dutchman's Blade"){
                                Write-Host ""
                                Write-CL "  ╔══════════════════════════════════════════════════╗" "DarkRed"
                                Write-CL "  ║         N O T E                                  ║" "Red"
                                Write-CL "  ╚══════════════════════════════════════════════════╝" "DarkRed"
                                Write-CL "  The Dutchman's Blade is one of a kind." "Yellow"
                                Write-CL "  It will go to your bag — be careful not to drop it." "Yellow"
                                Write-Host ""
                                Write-C "  Continue? (y/N): " "Red"
                                $confirm = Read-Host
                                if($confirm -ne "y" -and $confirm -ne "Y"){
                                    Write-CL "  The Blade remains at your side." "Green"
                                    Read-Host "  [Press Enter to continue]" | Out-Null
                                    continue
                                }
                            }
                            $oldWep = $script:EquippedWeapon
                            if(-not $oldWep.Kind){ $oldWep.Kind = "Weapon" }
                            [void]$script:Inventory.Add($oldWep)
                            $script:EquippedWeapon = $null
                            Write-CL "  Unequipped $($oldWep.Name) — moved to bag." "Yellow"
                            if(Test-Encumbered){
                                Write-CL "  -- OVER ENCUMBERED -- you cannot move on the dungeon grid." "Red"
                            }
                        } else {
                            $piece = $script:EquippedArmor[$uSlot]
                            if(-not $piece.Kind){ $piece.Kind = "Armor" }
                            [void]$script:Inventory.Add($piece)
                            $script:EquippedArmor[$uSlot] = $null
                            Write-CL "  Unequipped $($piece.Name) — moved to bag." "Yellow"
                            if(Test-Encumbered){
                                Write-CL "  -- OVER ENCUMBERED -- you cannot move on the dungeon grid." "Red"
                            }
                        }
                        Wait-Key
                    }
                }
            }
            "E" {
                clr
                Write-CL "  ── Equip from Bag ──" "Green"
                Write-CL "  Pick a weapon or armor in your inventory to equip." "DarkGray"
                Write-CL "  Currently equipped item (if any) goes to the bag." "DarkGray"
                Write-Host ""
                # Find equippable items in inventory
                $equipOptions = [System.Collections.ArrayList]@()
                for($ei=0; $ei -lt $script:Inventory.Count; $ei++){
                    $it = $script:Inventory[$ei]
                    if($it.Kind -eq "Weapon" -or $it.WeaponType){
                        [void]$equipOptions.Add(@{Index=$ei; Label="Weapon: $($it.Name) (ATK+$($it.ATK))"; Item=$it})
                    } elseif($it.Kind -eq "Armor" -or $it.Slot){
                        $defStr = if($it.DEF){"DEF+$($it.DEF)"}else{""}
                        [void]$equipOptions.Add(@{Index=$ei; Label="$($it.Slot): $($it.Name) ($defStr)$(Get-ArmorClassTag $it)"; Item=$it})
                    }
                }
                if($equipOptions.Count -eq 0){
                    Write-CL "  No equippable items in your bag." "DarkGray"
                    Wait-Key
                } else {
                    for($oi=0; $oi -lt $equipOptions.Count; $oi++){
                        Write-CL "  [$($oi+1)] $($equipOptions[$oi].Label)" "White"
                    }
                    Write-CL "  [0] Cancel" "DarkGray"
                    Write-Host ""
                    Write-C "  > " "Yellow"; $ePick = Read-Host
                    $eIdx = (ConvertTo-SafeInt -Value $ePick) - 1
                    if($eIdx -ge 0 -and $eIdx -lt $equipOptions.Count){
                        $invIdx = $equipOptions[$eIdx].Index
                        Invoke-EquipFromInventory -InvIndex $invIdx | Out-Null
                        Wait-Key
                    }
                }
            }
            "0" { $invLoop = $false }
            default { $invLoop = $false }
        }
    }
}

function Show-Tutorial {
    $pages = @(
        @{Title="1. THE TOWN SQUARE"; Lines=@(
            "  The TOWN SQUARE is your hub between dungeon runs."
            ""
            "  From here you can:"
            "   * Enter a dungeon (gain XP, gold, loot)"
            "   * Run the DAILY DUNGEON — once per day, double rewards"
            "   * Visit the Market to buy gear, armor, potions, lockpicks"
            "   * Repair damaged equipment at the Blacksmith"
            "   * Rest at the Weary Lantern Inn — and use the Cooking Pot"
            "     to combine ingredients into run-long buff foods"
            "   * Train at the Training Grounds (boost stats for gold)"
            "   * Accept quests for bonus rewards (up to 5 active)"
            "   * Travel the WORLD MAP ([W]) — towns, camps, side"
            "     quests, and location-exclusive shop stock"
            "   * Hire companions and adopt PETS at the Guild Hall"
            "   * Manage gear and inventory"
            "   * View Stats — and spend TALENT POINTS in the Talent Tree"
            "   * Browse the BESTIARY of every enemy variant defeated"
            "   * Finish the main story: ASCEND for New Game Plus"
            ""
            "  You select actions by typing their number or letter."
        )}
        @{Title="2. DUNGEON MOVEMENT"; Lines=@(
            "  Inside a dungeon, movement is REAL-TIME. Just press keys —"
            "  no Enter needed."
            ""
            "  Controls:"
            "    W — walk forward         S — step back"
            "    A — turn left            D — turn right"
            "    P — use a healing potion I — open inventory"
            "    J — view quest journal   Q — quit the dungeon"
            "    E — interact (3D view)   M — full dungeon map"
            "    (arrow keys also work for movement)"
            ""
            "  Movement is gently throttled to about 7 steps per second so"
            "  holding a key doesn't zoom you across the map."
            ""
            "  KEY-PRESS QUIRK (PowerShell limitation):"
            "    Because PowerShell reads keys through a console buffer"
            "    rather than a true keyboard event loop, you may need to"
            "    HOLD a key briefly (about a quarter second) for it to"
            "    register reliably. This applies to movement (W/A/S/D),"
            "    [P]otion, [Q]uit, and [I]nventory inside the dungeon."
            "    Tap-and-it-doesn't-respond is a buffer-read race, not a"
            "    bug — a slightly longer press fixes it. There's no way"
            "    to bypass this from within PowerShell itself."
            ""
            "  PERFORMANCE TIP: For the smoothest rendering, resize your"
            "  terminal to at least 80x32 (or maximize it). The game will"
            "  use partial-redraw mode and only repaint the parts of the"
            "  screen that change. Smaller windows fall back to full"
            "  refreshes, which still works but flickers."
            ""
            "  A 3D view shows the corridor ahead; a minimap is on the right."
            "  Look for:  ! enemies   M mini-boss   B boss"
            "             $ treasure  > exit        ? lost adventurer"
        )}
        @{Title="3. COMBAT BASICS"; Lines=@(
            "  Combat is turn-based. Options each round:"
            ""
            "    [1] Attack   — basic weapon strike"
            "    [2] Ability  — class spells/skills (costs MP, has cooldown)"
            "    [3] Potion   — drink from your potion bag"
            "    [4] Throw    — hurl flasks and bombs"
            "    [5] Defend   — double DEF this turn (great vs. boss charges)"
            "    [6] Flee     — try to run (bosses can't be fled from)"
            "    [T] Stance   — switch stance (free action, no turn cost)"
            "    [V] Target   — switch enemy in group fights (free action;"
            "                   your target also auto-advances on a kill)"
            ""
            "  HIT & CRIT:"
            "    Hit chance caps at 90%. Slow/Stun effects drop enemy accuracy."
            "    Both you AND enemies can crit for 2x damage."
            "    Bosses sometimes CHARGE a big attack — DEFEND when you see it!"
            ""
            "  ABILITY COOLDOWNS:"
            "    Each ability has its own cooldown after use, shown in the"
            "    ability menu. Manage them — you can't spam your strongest"
            "    spell every turn. Different abilities have different CDs."
        )}
        @{Title="4. ENEMY ABILITIES & AI"; Lines=@(
            "  Enemies aren't just punching bags. They have abilities too:"
            ""
            "    * DAMAGE abilities    (Power Strike, Dark Wave, Inferno...)"
            "    * SELF-BUFFS         (ATK or DEF up for 3 turns)"
            "    * HEALING             (recover their own HP)"
            ""
            "  ENEMY AI is throttled — they won't spam abilities every turn."
            "  Roughly 35% of turns will use a damage ability if one is off"
            "  cooldown, otherwise they basic-attack. Buffs and heals are"
            "  used sparingly so combat feels fair, not frustrating."
            ""
            "  TRIGGERS YOU CAN PLAN AROUND:"
            "    * Below 30% HP, enemies with a heal will use it"
            "    * Without a buff active, they may self-buff (~30% chance)"
            "    * Bosses telegraph their biggest attacks — defend that turn"
            ""
            "  Mini-bosses and bosses have wider ability sets including"
            "  heals and buffs. Higher-level normal enemies (troll, skeleton,"
            "  zombie, wizard, thief) gain extra abilities at deeper floors."
        )}
        @{Title="5. GEAR & DURABILITY"; Lines=@(
            "  Every class has a weapon AFFINITY. Matching weapon type = bonus ATK."
            ""
            "    Knight → Sword    Mage → Staff    Brawler → Fist"
            "    Ranger → Bow      Cleric → Mace   Necromancer → Scythe"
            "    Berserker → Sword   Warlock → Staff"
            ""
            "  Weapon perks like Bleed, Burn, Poison trigger on attack."
            "  Armor covers 5 slots: Helmet, Chest, Shield, Amulet, Boots."
            ""
            "  DURABILITY: Every weapon and armor piece has a durability pool."
            "   * Weapons lose 1 point per successful hit you land."
            "   * Armor has a 50% chance to lose 1 point when you take damage."
            "   * A BROKEN item (0 durability) gives 0 stat bonus until repaired."
            ""
            "  Visit the BLACKSMITH in the market to repair gear. Cost scales"
            "  with the damage done. Repair All gives a 10% bulk discount."
            ""
            "  EQUIPPING & UNEQUIPPING:"
            "    Buying or finding new gear with a slot already occupied"
            "    will prompt you: equip now (old goes to bag) or stow new."
            "    No more sell-on-replace — your gear stays with you."
            "    Use [E] Equip from Bag in the inventory screen to swap."
            "    Use [U] Unequip Gear to move equipped pieces back to bag."
            ""
            "  Rare encounters in dungeons include the Healing Bard, Lost"
            "  Merchant, Wandering Alchemist — and the Flying Dutchman, who"
            "  offers a legendary blade on a coin toss."
        )}
        @{Title="6. INVENTORY & WEIGHT"; Lines=@(
            "  Every item you carry has weight. Your bag has a HARD CAP of 90."
            "  This cap doesn't grow with your stats — it's the same at every"
            "  level, so inventory choices stay meaningful from start to end."
            ""
            "  WEIGHT-FREE ITEMS:"
            "    * Gold, Lore Notes, and Repair Kits"
            ""
            "  WEIGHTED ITEMS (count toward your cap):"
            "    * Equipped weapon and armor — every piece you wear adds"
            "      its own weight (helmet 3, chest 5, shield 4, amulet 1,"
            "      boots 2, weapons 4-9 by type)"
            "    * Loot items — gems, scales, idols, etc. (varies by item;"
            "      includes a +2 weight surcharge that makes the 90 cap bite)"
            "    * Spare weapons and armor in your bag (boss/miniboss drops)"
            "    * Potions and throwables — 1 weight each"
            "    * Extra Strong potions (Health/Mana/Strength/Luck) — 1 weight"
            "      each, found as rare end-of-dungeon drops; convert to gold"
            "      if bag is full"
            "    * Cooking ingredients — 1 weight each"
            "    * Lockpicks — 1 weight each"
            ""
            "  WHEN YOU'RE OVER ENCUMBERED:"
            "    * In a dungeon, WASD movement is BLOCKED. Open inventory [I]"
            "      and use [D] Drop Items to destroy unwanted items."
            "    * In town, you can't enter another dungeon. Sell at the"
            "      Market or drop items via the Inventory."
            ""
            "  THROWABLES (combat option [4]):"
            "    Acid Flask — 40 dmg     Poison Flask — 25 dmg + Poison"
            "    Frost Bomb — 20 dmg + Slow     Bomb — 75 dmg (premium)"
            ""
            "  LOOT SCREEN (chest contents, enemy drops):"
            "    Up/Down — move cursor   Space — toggle take/leave"
            "    A — take all that fit   V — view item details"
            "    Enter — confirm         Esc — take nothing"
            ""
            "  Gold also flows through the loot screen for visual consistency,"
            "  but it has 0 weight and is always safe to take."
        )}
        @{Title="7. COMBAT STANCES"; Lines=@(
            "  In combat, press [T] to switch your STANCE. This is a"
            "  FREE ACTION — it doesn't cost your turn."
            ""
            "  THREE STANCES:"
            "    AGGRESSIVE  ATK +30%  /  DEF -30%   (deal more, take more)"
            "    BALANCED    no change              (neutral default)"
            "    DEFENSIVE   ATK -30%  /  DEF +30%  (deal less, take less)"
            ""
            "  Stance affects BOTH basic attacks and abilities, including"
            "  magic damage. It also persists between fights — you'll keep"
            "  the same stance across the dungeon until you switch again."
            ""
            "  TACTICAL TIPS:"
            "    * Use Aggressive to finish off a low-HP enemy quickly"
            "    * Use Defensive against bosses with charged-attack telegraphs"
            "    * Combine Defensive with [5] Defend for huge damage reduction"
            "    * Stance is shown in the combat HUD with a color tag"
        )}
        @{Title="8. QUESTS"; Lines=@(
            "  ALL quests live at the QUEST BOARD in town — three kinds:"
            ""
            "  ! STORY (main quest): one chapter at a time. Press [!]"
            "    at the board to watch the beat, then advance it there"
            "    once its goal reads READY. Finishing the whole story"
            "    unlocks NEW GAME PLUS."
            "  * SIDE quests: one per town — travel the World Map ([W])"
            "    and talk to the locals. Accepted ones stay listed in"
            "    the board's ACTIVE box until done."
            "  TOWN BOUNTIES: 5 random postings, hold up to 5 at once,"
            "    and turn finished ones in with [T] for gold and XP."
            ""
            "  BOUNTY TYPES:"
            "    * Kill X enemies           * Defeat the dungeon mini-boss"
            "    * Defeat the boss          * Rescue the lost adventurer"
            "    * Land X critical hits     * Pick X locks"
            "    * Collect X loot items     * Reach boss room above 50% HP"
            "    * X kills bare-handed      * Repair gear at the Blacksmith"
            ""
            "  Press [J] in the dungeon to view the QUEST JOURNAL with progress"
            "  bars. Quests don't auto-complete — return to the board to"
            "  turn in finished quests for gold and XP."
            ""
            "  Rewards scale with dungeon level and target count, so deeper"
            "  dungeons offer more lucrative bounties."
        )}
        @{Title="9. DUNGEON MUTATORS"; Lines=@(
            "  Before you descend, a Guild SysAdmin offers three random"
            "  MUTATORS — risk/reward modifiers that change the rules of"
            "  the run. Pick one or skip with [0]."
            ""
            "  THE SIX MUTATORS:"
            "    Glass Cannon    — +50% damage dealt and taken"
            "    Pacifist's Path — 0 XP from kills, 3x quest XP"
            "    Cursed Loot     — gear drops at 50% durability, +50% stats"
            "    Speedrun        — enemies +25% SPD"
            "    Frugal Run      — 1 HP pot, 1 MP pot, 1 lockpick (rest stashed)"
            "    Hardcore        — lose 50% gold on death"
            ""
            "  Each mutator adds a +20-40% bonus to the gold/XP haul on"
            "  dungeon CLEAR (boss defeated + reach the exit). Bonuses"
            "  do NOT apply per-kill — only at the end of a successful"
            "  run. Mutators clear automatically on dungeon end."
            ""
            "  ! WARNING: With a mutator active, abandoning the dungeon"
            "  via [Q] forfeits ALL loot, gold, and XP earned this run."
            "  Mutator runs are commit-or-die. Without a mutator, [Q]"
            "  has the usual flee penalty (random loot/gold loss)."
            ""
            "  TIP: Frugal Run stashes your potions and most lockpicks at"
            "  the door (you keep one HP pot, one MP pot, and one pick)"
            "  and returns everything when the dungeon ends — clear or die."
        )}
        @{Title="10. PETS & COOKING"; Lines=@(
            "  THE KENNEL (Guild Hall, [P]):"
            "    Three pets, each with one passive perk:"
            "      Hound  (500g) — chests visible on minimap through fog"
            "      Raven  (650g) — +5% gold from all sources"
            "      Falcon (600g) — fog-of-war reveal radius increased"
            "    You can own one pet at a time. Release for 50% refund."
            ""
            "  COOKING POT (Weary Lantern Inn, [C]):"
            "    Enemies drop INGREDIENTS — Mushroom, Herb, Meat, Bone."
            "    12% drop chance per kill, guaranteed on bosses. Each"
            "    weighs 1, so don't hoard. Combine at the pot:"
            "      Hearty Stew     - +5 ATK for the run"
            "      Bone Broth      - +3 DEF for the run"
            "      Forager's Plate - +10% gold for the run"
            "      Hunter's Skewer - +15% XP for the run"
            "    Only one food buff active at a time. Wears off on"
            "    dungeon end (clear or death)."
        )}
        @{Title="11. THE TALENT TREE"; Lines=@(
            "  Every level grants 1 TALENT POINT. Spend points at the"
            "  Stats page (press [T] from the stats screen)."
            ""
            "  Each class has 10 talents across 4 tiers:"
            "    Tier 1 — unlocks at Lv 1   (entry-level passive boosts)"
            "    Tier 2 — unlocks at Lv 5   (combat triggers and modifiers)"
            "    Tier 3 — unlocks at Lv 10  (class-defining specialties)"
            "    Tier 4 — unlocks at Lv 15  (ULT capstone, one per class)"
            ""
            "  When you've purchased all 10 talents for your class, no"
            "  more points are granted on level-up — there's nothing"
            "  left to buy. Save the surplus levels for raw stat gain."
            ""
            "  EXAMPLES — vary by class:"
            "    Knight Crusader:    +25% damage to bosses"
            "    Knight Avatar (T4): -25% damage taken, +15% damage dealt"
            "    Ranger Multishot:   25% chance for a second arrow"
            "    Ranger Volley (T4): Multishot 50% chance, full damage"
            "    Cleric Holy Fury (T4): all healing +50%, Lay on Hands x2"
            ""
            "  NEW COMBAT ACTIONS unlocked by talents:"
            "    [L] Lay on Hands — Cleric T3, full heal once per dungeon"
            "    [O] Soul Tap     — Warlock T2, spend 5 HP for +10 damage"
            ""
            "  Talents persist across save/load AND through New Game"
            "  Plus ascensions — they're a long-term progression layer."
        )}
        @{Title="12. HIDDEN BOSS & NEW GAME +"; Lines=@(
            "  THE ORPHANED PROCESS (hidden boss):"
            "    A secret super-boss spawns when you clear a DAILY"
            "    DUNGEON at full HP with ZERO potions used. Tough but"
            "    rewarding — defeat it for the GUILD OF SYSADMIN FAVOR:"
            "      +5 to all stats permanent"
            "      +25 Max HP, +15 Max MP"
            "      15% discount at all shops, forever"
            "    Lifetime achievement — once defeated, the favor sticks."
            ""
            "  NEW GAME PLUS:"
            "    Finish THE FINAL MIGRATION story to unlock [N] in town."
            "    On ascension you KEEP: gold, achievements, training,"
            "    bestiary, talents, pet, ingredients, and SysAdmin Favor."
            "    You RESET: player level, XP, gear, dungeon level, and"
            "    the dungeons-cleared counter."
            ""
            "    Each NG+ tier scales enemies +20% HP and +20% ATK."
            "    20% of boss/mini drops in NG+ become ASCENDED gear:"
            "    +30% to base stats, marked with the Ascended prefix."
            ""
            "  Ascending is permanent — no going back to your old level."
        )}
        @{Title="13. SAVING YOUR PROGRESS"; Lines=@(
            "  From the Town Square, press [S] to generate a SAVE CODE."
            ""
            "  The code is a long Base64 string — copy it somewhere safe!"
            "  When you relaunch the game, choose LOAD SAVE CODE and paste it."
            ""
            "  Notes:"
            "   * Loot items are converted to gold on save."
            "   * Active quests are reset on save (visit the board again)."
            "   * Achievements, training, and best-streak record persist."
            "   * Your CURRENT dungeon streak does NOT persist — each load"
            "     starts fresh. Your best-ever streak is preserved though."
            ""
        )}
        @{Title="14. OPTIONS, NOTES & QUALITY-OF-LIFE"; Lines=@(
            "  OPTIONS (town menu, [O]):"
            "   * Difficulty: Easy / Medium / Hard. Easy makes enemies"
            "     -25% HP/ATK; Hard +25%. Medium is the default."
            "   * Auto-Loot: when ON, the loot screen auto-takes every"
            "     item that fits within your carry weight. OFF leaves"
            "     you to mark items manually with SPACE."
            "   * Auto-Resize: tries to resize your terminal to ~100x40"
            "     on game start. Some terminals refuse this; that's fine."
            "   Settings are saved as part of your save code — generate a"
            "   save from town to keep them, then load it next session."
            ""
            "  NOTES & LORE:"
            "   * 18% of opened chests drop a NOTE — a journal scrap from"
            "     a previous adventurer. Pure flavor, weight 0."
            "   * From the inventory, press [V] to read your notes any time."
            ""
            "  WANDERING MERCHANT:"
            "   * Random encounter offering one item at 60% off. The screen"
            "     now shows a comparison vs your current gear: green ▲ for"
            "     a clear upgrade, red ▼ for a downgrade, = for the same."
            ""
            "  DUTCHMAN'S BLADE WARNING:"
            "   * If you try to sell the Dutchman's Blade in the Sell Loot"
            "     screen, you'll get a confirmation prompt — it's unique"
            "     and can't be re-acquired in a normal run."
        )}
        @{Title="15. SKILLS"; Lines=@(
            "  Ten skills level 0-50 by DOING. Watch them at the Training"
            "  Grounds ([6] in town). Every 10 levels is one TIER, and"
            "  tiers feed small, steady bonuses that add up over a long run."
            ""
            "  SKILL            TRAINS BY              EACH TIER GIVES"
            "    Swords / Bows    landed weapon hits     +1 weapon damage"
            "    Destruction      attack spells cast     +1 spell damage"
            "    Restoration      healing spells cast    +2 healing"
            "    Heavy Armor      taking hits in [H]     +1 DEF"
            "    Light Armor      taking hits in [L]     +1 SPD"
            "    Lockpicking      successful picks       (Lv15: wider zone)"
            "    Blacksmithing    repairs & crafting     -3% repair cost"
            "    Alchemy          drinking & brewing     +4% potion power"
            "    Fishing          casts & catches        longer strike window"
            ""
            "  The armor bonuses read your MAJORITY class — wear three"
            "  of five slots in Heavy gear and you train and pay as Heavy"
            "  (the shop's [H]/[L] tags show each piece's class)."
            "  Level N needs N x 100 more XP, so growth slows at the top."
        )}
        @{Title="16. CORRUPTION & WORLD EVENTS"; Lines=@(
            "  CORRUPTION (0-100) is the world reacting to you. The count"
            "  sits on the town banner — grey is calm, red is not."
            ""
            "  It RISES when the Depths win:   die +15, flee a fight +3,"
            "                                  fall on the world map +5"
            "  It FALLS when you win:          mini-boss -4, boss -10,"
            "                                  the hidden boss -15"
            ""
            "  A corrupted world bites back: more variant enemies, more"
            "  group ambushes with support casters guarding them, altars"
            "  that bless less and toll more — and at 60+ the kindly"
            "  wandering Merchant stops appearing. Something else does."
            "  A CALM world (under 25) trades kindly: 5% off in shops."
            ""
            "  WORLD EVENTS: every dungeon clear advances the day, and"
            "  certain days wake an event (named on the town banner):"
            "    BLOOD MOON      — everything below is bolder, undead"
            "                      hit harder, kills are worth more XP"
            "    GOBLIN HORDE    — goblins everywhere; their Warchief"
            "                      takes the mini-boss floor (200g bounty)"
            "    BLIGHTED PLAGUE — the dead walk in numbers and the"
            "                      Inn's beds are quarantined"
        )}
        @{Title="17. GUILDS & FACTIONS"; Lines=@(
            "  GUILDS — three formal orders inside the Guild Hall ([8]):"
            "    The SysAdmins' Guild         — FIREWALL PLATE + 100g"
            "    The Data-Thieves' Collective — WHISPERSTEP BOOTS + picks"
            "    The Cabal of Forgotten Code  — GRIMOIRE + permanent +2 MAG"
            "  Each runs a 3-stage questline (kills, locks, tributes —"
            "  the Cabal even wants the world's Corruption raised to 40)."
            "  Turn stages in at the Hall. Defecting costs 100g and all"
            "  your progress with that guild."
            ""
            "  FACTIONS — two rival networks out on the World Map: the"
            "  DATA MINERS and the ROGUE PROCESSES. World-map choices"
            "  and their brokers' jobs move REPUTATION (-100 to 100):"
            "    -20 HUNTED    <0 Wary    >0 Friendly    25+ HONORED"
            "  Siding with one usually costs standing with the other."
            ""
            "  HONORED pays: the Data Miners buy your loot at +10% and"
            "  their broker Indexa (the Registry) opens her stock; the"
            "  Rogue Processes teach you exits (+5% flee chance) and"
            "  Sig Kill (Terminus) finally deals."
            ""
            "  (Shop receipts name their discounts — 'calm world' is"
            "  low Corruption; 'SysAdmin favor' is earned much deeper.)"
            ""
            "  Good luck, adventurer. The Depths await."
        )}
    )

    foreach($page in $pages){
        clr
        Write-Host ""
        Write-CL "  ╔══════════════════════════════════════════════════════════════════╗" "DarkCyan"
        Write-CL "  ║                    T U T O R I A L                               ║" "Cyan"
        Write-CL "  ║  $($page.Title.PadRight(64))║" "Yellow"
        Write-CL "  ╚══════════════════════════════════════════════════════════════════╝" "DarkCyan"
        Write-Host ""
        foreach($line in $page.Lines){
            Write-CL $line "Gray"
        }
        Write-Host ""
        Wait-Key
    }
    clr
    Write-CL "  Tutorial complete! May your gold pile high." "Green"
    Wait-Key
}

# Launch the game
Start-Game
